window.HADITH_CACHE["ahmad_2"] = {"1001":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنِي شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ قَالَ سَمِعْتُ مُطَرِّفَ بْنَ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ يُحَدِّثُ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَنْتَ سَيِّدُ قُرَيْشٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّيِّدُ اللَّهُ قَالَ أَنْتَ أَفْضَلُهَا فِيهَا قَوْلًا وَأَعْظَمُهَا فِيهَا طَوْلًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَقُلْ أَحَدُكُمْ بِقَوْلِهِ وَلَا يَسْتَجِرُّهُ الشَّيْطَانُ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepadaku [Syu'bah] berkata, saya telah mendengar [Qatadah] berkata, saya telah mendengar [Mutharrif bin Abdullah bin Asy-Syikhir] menceritakan dari [Bapaknya] berkata, Datang seorang laki-laki kepada Nabi Shallallahu'alaihiwasallam lalu berkata 'Engkaulah tuan Quraisy, Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya hakekat Tuan adalah Allah\" lalu laki-laki tersebut berkata, \"engkau adalah oang yang paling utama perkataannya di antara mereka dan yang paling agung kemampuannya\" Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Hendaklah kalian hati-hati dalam perkataannya (berkata sewajarnya dengan tidak berlebihan), jangan sampai disesatkan oleh setan.\""},"1002":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسُئِلَ عَنْ رَجُلٍ يَصُومُ الدَّهْرَ قَالَ لَا صَامَ وَلَا أَفْطَرَ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Mutharrif bin Abdullah bin Asy-Syikhir] dari [Bapaknya] telah mendengar Nabi Shallallahu'alaihiwasallam tentang seorang laki-laki yang berpuasa Dahr, maka beliau bersabda: \"Orang itu tidak dianggap puasa juga tidak dianggap berbuka.\""},"1003":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْهِ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Sa'id Al Jurairi] dari [Abu Al 'Ala` bin Abdullah bin Asy-Syikhir] dari [bapaknya] berkata, Aku melihat Rasulullahi Shallallahu'alaihiwasallam shalat dengan menggunakan kedua sandalnya.\""},"1004":{"ar":"قَالَ حَدَّثَنَا سُوَيْدُ بْنُ عَمْرٍو وَعَبْدُ الصَّمَدِ قَالَا حَدَّثَنَا مَهْدِيٌّ حَدَّثَنَا غَيْلَانُ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِأَنَّهُ وَفَدَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ بَنِي عَامِرٍ قَالَ فَأَتَيْنَاهُ فَسَلَّمْنَا عَلَيْهِ فَقُلْنَا أَنْتَ وَلِيُّنَا وَأَنْتَ سَيِّدُنَا وَأَنْتَ أَطْوَلُ عَلَيْنَا قَالَ يُونُسُ وَأَنْتَ أَطْوَلُ عَلَيْنَا طَوْلًا وَأَنْتَ أَفْضَلُنَا عَلَيْنَا فَضْلًا وَأَنْتَ الْجَفْنَةُ الْغَرَّاءُ فَقَالَ قُولُوا قَوْلَكُمْ وَلَا يَسْتَجِرَّنَّكُمْ الشَّيْطَانُ قَالَ وَرُبَّمَا قَالَ وَلَا يَسْتَهْوِيَنَّكُمْ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Suwaid bin 'Amr] dan [Abdushshamad] berkata, telah menceritakan kepada kami [Mahdi] telah menceritakan kepada kami [Ghailan] dari [Mutharrif bin Abdullah bin Asy-Syikhir] dari [bapaknya] dia menjadi seorang utusan untuk menemui Nabi Shallallahu'alaihiwasallam dalam sebuah rombongan dari Bani 'Amir. (Abdullah bin Asy-Syikhir) berkata, lalu kami menemuinya dan kami mengucapkan salam kepada beliau, lalu kami berkata 'Anda adalah wali kami, tuan kami dan anda adalah yang paling kaya dan paling mampu di antara kami.' Yunus berkata, anda adalah orang yang paling mampu dan kaya di antara kami, anda adalah orang yang paling utama di antara kami, anda bagaikan piring besar yang putih wajahnya. (Rasulullahi Shallallahu'alaihiwasallam) bersabda: \"Katakanlah yang wajar-wajar saja dan janganlah setan menyesatkan kalian.\" (Abdullah bin Asy-Syikhir) berkata, barangkali beliau bersabda: \"Janganlah sampai (setan) menjadikan kalian tersesat.\""},"1005":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي صَدْرِهِ أَزِيزٌ كَأَزِيزِ الْمِرْجَلِ مِنْ الْبُكَاءِقَالَ عَبْد اللَّهِ لَمْ يَقُلْ مِنْ الْبُكَاءِ إِلَّا يَزِيدُ بْنُ هَارُونَ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Yazid] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit Al Bunani] dari [Mutharrif bin Abdullah] dari [bapaknya] berkata, Aku melihat Rasulullah Shallallahu'alaihiwasallam yang ketika itu dalam dadanya terdengar rintihan suara tangisan sebagaimana suara air yang bergolak ketika dimasak dalam periuk karena menangis.\" Abdullah berkata, tidak ada yang mengatakan dengan redaksi karena menangis kecuali Yazid bin Harun."},"1006":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حُمَيْدٌ يَعْنِي الطَّوِيلَ حَدَّثَنَا الْحَسَنُ عَنْ مُطَرِّفٍ عَنْ أَبِيهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ هَوَامَّ الْإِبِلِ نُصِيبُهَا قَالَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Humaid] yaitu Ath-Thawil, telah menceritakan kepada kami [Al Hasan] dari [Mutharrif] dari [Bapaknya] ada seorang laki-laki berkata, Wahai Rasulullah, jika ada unta yang telah tertidur, apakah kami bisa mengambilnya?. Beliau bersabda: \"Barang yang hilang dari seorang muslim adalah api neraka yang membakar.\""},"1007":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَ��َّمَ مَنْ صَامَ الدَّهْرَ لَا صَامَ وَلَا أَفْطَرَ وَمَا صَامَ وَلَا أَفْطَرَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Mutharrif] dari [Bapaknya] berkata, Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa berpuasa sepanjang puasa, maka dia tidak dianggap puasa dan berbuka.\""},"1008":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ وَقَالَ ابْنُ جَعْفَرٍ سَمِعْتُ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ قَالَ حَجَّاجٌ فِي حَدِيثِهِ قَالَ سَمِعْتُ مُطَرِّفًا عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَنْتَ سَيِّدُ قُرَيْشٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّيِّدُ اللَّهُ فَقَالَ أَنْتَ أَفْضَلُهَا فِيهَا قَوْلًا وَأَعْظَمُهَا فِيهَا طَوْلًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَقُلْ أَحَدُكُمْ بِقَوْلِهِ وَلَا يَسْتَجِرَّنَّهُ الشَّيْطَانُ أَوْ الشَّيَاطِينُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dan [Hajjaj] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dan [Ibnu Ja'far] berkata, saya mendengar [Qatadah] dari [Mutharrif bin Abdullah] [Hajjaj] berkata, dalam hadisnya, berkata, saya mendengar [Mutharrif] dari [Bapaknya] berkata, seorang laki-laki datang kepada Nabi Shallallahu'alaihiwasallam lalu berkata 'Anda adalah tuan Quraisy.' Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Tuan itu adalah Allah\", lalu dia berkata, anda adalah orang yang paling utama dan paling kaya dan paling mampu. Lalu Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Hendaklah kalian berkata secara wajar dan jangan sampai setan menyesatkan kalian.\""},"1009":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ يَعْنِي ابْنَ عُرْوَةَ قَالَ حَدَّثَنِي أَبِي عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ وَوَكِيعٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ قَالَ وَكِيعٌ فِي بَيْتِ أُمِّ سَلَمَةَ فِي ثَوْبٍ قَدْ أَلْقَى طَرَفَيْهِ عَلَى عَاتِقِهِ فِي بَيْتِ أُمِّ سَلَمَةَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] yaitu Ibnu 'Urwah berkata, telah menceritakan kepadaku [bapakku] dari ['Umar bin Abu Salamah] Dan [Waki'] berkata, telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari ['Umar bin Abu Salamah] berkata, Aku melihat Rasulullahi Shallallahu'alaihiwasallam shalat dengan memakai satu baju. Waki' berkata, pada waktu di rumah Ummu Salamah dengan kedua sisinya terjurai ke pundak beliau."},"1010":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ وَإِبْرَاهِيمُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي وَجْزَةَ السَّعْدِيِّ عَنْ رَجُلٍ مِنْ مُزَيْنَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِطَعَامٍ فَقَالَ يَا عُمَرُ قَالَ هِشَامٌ يَا بُنَيَّ سَمِّ اللَّهَ عَزَّ وَجَلَّ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَقَالَ فَمَا زَالَتْ أُكْلَتِي بَعْدُ","id":"Telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Hisyam bin 'Urwah] dan [Ibrahim bin Isma'il] dari [Abu Wajzah As Sa'di] dari [seseorang dari Muzainah] dari ['Umar bin Abu Salamah] Nabi Shallallahu'alaihiwasallam diberi makanan, lalu beliau bersabda: \"Wahai 'Umar\". Hisyam berkata, Wahai anakku, Sebutlah nama Allah AzzaWaJalla, makanlah dengan tangan kananmu dan makanlah makanan yang terdekat olehmu. ('Umar bin Abu Salamah) berkata, Maka sejak itu aku makan dengan cara itu (cara yang diajarkan oleh Rasulullahi Shallallahu'alaihiwasallam)."},"1011":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِي وَجْزَةَ رَجُلٍ مِنْ بَنِي سَعْدٍ عَنْ رَجُلٍ مِنْ بَنِي مُزَيْنَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بُنَيَّ إِذَا أَكَلْتَ فَسَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَقَالَ فَمَا زَالَتْ أُكْلَتِي بَعْدُ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Abu Wajzah, seorang laki-laki dari Bani Sa'ad] dari [seorang laki-laki dari Bani Muzainah] dari ['Umar bin Abu Salamah] berkata, Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Wahai anakku, jika kau makan maka sebutlah nama Allah, makanlah dengan tangan kananmu, makanlah pada yang terdekat denganmu\". ('Umar bin Abu Salamah) berkata, Maka sejak itu aku makan dengan cara itu (cara yang diajarkan oleh Rasulullahi Shallallahu'alaihiwasallam)."},"1012":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا غُلَامُ سَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَفَلَمْ تَزَلْ تِلْكَ طُعْمَتِي بَعْدُ وَكَانَتْ يَدِي تَطِيشُ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Al Walid bin Katsir] dari [Wahb bin Kaisan] dari ['Umar bin Abu Salamah] berkata, Nabi Shallallahu'alaihiwasallam bersabda kepadaku, wahai pemuda, sebutlah nama Allah, makanlah dengan tangan kananmu, makanlah yang terdekat, maka sejak saat itu cara makanku seperti itu, padahal sebelumnya tanganku bergerak-gerak."},"1013":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي بَيْتِ أُمِّ سَلَمَةَ فِي ثَوْبٍ وَاحِدٍ مُشْتَمِلًا بِهِ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Bapaknya] dari ['Umar bin Abu Salamah] berkata, saya melihat Rasulullahi Shallallahu'alaihiwasallam shalat di rumah Umu Salamah dengan memakai satu kain dengan menyelendangkannya."},"1014":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Umar bin Abu Salamah] berkata, Rasulullahi Shallallahu'alaihiwasallam bersabdaku, \"sebutlah nama Allah, makanlah dengan tangan kananmu dan makanlah yang terdekat."},"1015":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَبِي إِسْحَاقَ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ قَدْ خَالَفَ بَيْنَ طَرَفَيْهِ جَعَلَ طَرَفَيْهِ عَلَى عَاتِقَيْهِ","id":"Telah menceritakan kepada kami [Yahya bin Abu Ishaq] berkata, telah menceritakan kepada kami [Al Laits bin Sa'ad] dari [Yahya bin Sa'id] dari [Abu Umamah bin Sahal] dari ['Umar bin Abu Salamah] berkata, saya melihat Rasulullahi Shallallahu'alaihiwasallam shalat dengan memakai satu pakaian dengan menyelempangkan pada kedua ujungnya pada kedua pundaknya."},"1016":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَاقَ قَالَ وَذَكَرَ يَحْيَى بْنُ سَعِيدِ بْنِ قَيْسٍ الْأَنْصَارِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ مُتَوَشِّحًا بِهِ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata, dan [Yahya bin Sa'id bin Qais Al Anshari] menyebutkan dari [Abu Umamah bin Sahal] dari ['Umar bin Abu Salamah] berkata, sungguh saya melihat Rasulullah Shallallahu'alaihiwasallam shalat dengan satu kain dengan menyarungkannya (melingkarkannya)."},"1017":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ قَرَأْتُ عَلَى أَبِي مُوسَى بْنُ دَاوُدَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ أَبِي وَجْزَةَ السَّعْدِيِّ قَالَ أَخْبَرَنِي عُمَرُ بْنُ أَبِي سَلَمَةَ قَالَدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ يَأْكُلُهُ فَقَالَ ادْنُ فَسَمِّ اللَّهَ عَزَّ وَجَلَّ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَ","id":"Telah menceritakan kepada kami Abdullah berkata, saya telah membaca di hadapan [Abu Musa bin Daud], berkata, telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Abu Wajzah As Sa'di] berkata, telah mengabarkan kepadaku ['Umar bin Abu Salamah] berkata, Rasulullahi Shallallahu'alaihiwasallam memanggilku untuk makan yang beliau sedang memakannya, lalu bersabda: \"Mendekatlah, lalu sebutlah nama Allah, makanlah dengan tangan kananmu dan yang terdekat darimu.\""},"1018":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ قَرَأْتُ عَلَى أَبِي : مَنْصُورُ بْنُ سَلَمَةَ الْخُزَاعِيُّ قَالَ أَخْبَرَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَنِي أَوْ أَخْبَرَنِي أَبُو وَجْزَةَ السَّعْدِيُّ أَنَّهُ سَمِعَ عُمَرَ بْنَ أَبِي سَلَمَةَ رَبِيبَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ادْنُ يَا بُنَيَّ فَسَمِّ وَكُلْ مِمَّا يَلِيكَحَدَّثَنَا لُوَيْنٌ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ أَبِي وَجْزَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami Abdullah berkata, saya telah membaca di hadapan bapakku: [Manshur bin Salamah Al Khuza'i], berkata, telah menceritakan kepada kami [Sulaiman bin Bilal] berkata, telah menceritakan kepadaku atau telah mengabarkan kepadaku [Abu Wajzah As Sa'idi] telah mendengar ['Umar bin Abu Salamah, anak tiri Nabi Shallallahu'alaihiwasallam] berkata, Rasulullahi Shallallahu'alaihiwasallam memanggilku lalu bersabda: \"Mendekatlah wahai anakku, sebutlah nama Allah dan makanlah yang terdekat denganmu\". Telah menceritakan kepada kami [Luwain] berkata, telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Abu Wajzah] dari ['Umar bin Abu Salamah] dari Nabi Shallallahu'alaihiwasallam sama dengan yang di atasnya."},"1019":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي أُمَيَّةَ الْمَخْزُومِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي بَيْتِ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَوْبٍ وَاحِدٍ مُتَوَشِّحًا مَا عَلَيْهِ غَيْرُهُ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepadaku [bapakku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Hisyam bin 'Urwah] dari [Bapaknya] dari [Abdullah bin Abdullah bin Abu Umayyah Al Makhzumy] berkata, Aku melihat Rasulullahi Shallallahu'alaihiwasallam shalat di rumah Ummu Salamah istri beliau, dengan memakai satu baju yang tertutup yang bagian atasnya tidak terdapat apapun selainnya."},"1020":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي بَيْتِ أُمِّ سَلَمَةَ فِي ثَوْبٍ مُلْتَحِفًا بِهِ مُخَالِفًا بَيْنَ طَرَفَيْهِ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] berkata, telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [Bapaknya] dari ['Urwah bin Az Zubair] dia berkata, telah mengabarkan kepadaku [Abdullah bin Abdullah bin Abu Umayyah] dia melihat Rasulullahi Shallallahu'alaihiwasallam shalat di rumah Umu Salamah dengan memakai satu kain, yang beliau selimutkan dan kedua ujungnya diselendangkan."},"1021":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ قَالَ حَدَّثَنِي ابْنُ عُمَرَ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَ أَنَّ أَبَا سَلَمَةَ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَصَابَتْ أَحَدَكُمْ مُصِيبَةٌ فَلْيَقُلْ{ إِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ }اللَّهُمَّ عِنْدَكَ أَحْتَسِبُ مُصِيبَتِي فَأْجُرْنِي فِيهَا وَأَبْدِلْنِي بِهَا خَيْرًا مِنْهَافَلَمَّا قُبِضَ أَبُو سَلَمَةَ خَلَفَنِي اللَّهُ عَزَّ وَجَلَّ فِي أَهْلِي خَيْرًا مِنْهُ","id":"Telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] berkata, telah menceritakan kepadaku [Ibnu 'Umar] dari [Bapaknya] dari [Ummu Salamah] bahwa [Abu Salamah] menceritakan kepada mereka Rasulullahi Shallallahu'alaihiwasallam bersabda: Jika diantara kalian yang terkena suatu musibah maka hendaklah berkata, \"INNA LILLAHI WAINNA ILAIHI ROJI'UN ALLAHUMMA 'INDAKA AHTASIBU MUSIBATI FA'JURNI FIIHA WABDILNI BIHA KHAIRAN MINHA\" (Segala sesuatu milik Allah dan hanya kepada Allah-lah kita kembali. Ya Allah Disisi-Mu aku mengharapkan pahala atas musibah yang menimpaku, dan berikanlah kepadaku balasan dan gantilah itu dengan sesuatu yang lebih baik). Ketika Abu Salamah meninggal, Allah AzzaWaJalla menggantinya dengan orang yang lebih baik (yaitu Rasulullahi Shallallahu'alaihiwasallam, pent) "},"1022":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ عَنْ عَمْرٍو يَعْنِي ابْنَ أَبِي عَمْرٍو عَنْ الْمُطَّلِبِ عَنْ أُمِّ سَلَمَةَ قَالَتْأَتَانِي أَبُو سَلَمَةَ يَوْمًا مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَقَدْ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْلًا فَسُرِرْتُ بِهِ قَالَ لَا تُصِيبُ أَحَدًا مِنْ الْمُسْلِمِينَ مُصِيبَةٌ فَيَسْتَرْجِعَ عِنْدَ مُصِيبَتِهِ ثُمَّ يَقُولُ اللَّهُمَّ أْجُرْنِي فِي مُصِيبَتِي وَاخْلُفْ لِي خَيْرًا مِنْهَا إِلَّا فُعِلَ ذَلِكَ بِهِ قَالَتْ أُمُّ سَلَمَةَ فَحَفِظْتُ ذَلِكَ مِنْهُ فَلَمَّا تُوُفِّيَ أَبُو سَلَمَةَ اسْتَرْجَعْتُ وَقُلْتُ اللَّهُمَّ أْجُرْنِي فِي مُصِيبَتِي وَاخْلُفْنِي خَيْرًا مِنْهُ ثُمَّ رَجَعْتُ إِلَى نَفْسِي قُلْتُ مِنْ أَيْنَ لِي خَيْرٌ مِنْ أَبِي سَلَمَةَ فَلَمَّا انْقَضَتْ عِدَّتِي اسْتَأْذَنَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَدْبُغُ إِهَابًا لِي فَغَسَلْتُ يَدَيَّ مِنْ الْقَرَظِ وَأَذِنْتُ لَهُ فَوَضَعْتُ لَهُ وِسَادَةَ أَدَمٍ حَشْوُهَا لِيفٌ فَقَعَدَ عَلَيْهَا فَخَطَبَنِي إِلَى نَفْسِي فَلَمَّا فَرَغَ مِنْ مَقَالَتِهِ قُلْتُ يَا رَسُولَ اللَّهِ مَا بِي أَنْ لَا تَكُونَ بِكَ الرَّغْبَةُ فِيَّ وَلَكِنِّي امْرَأَةٌ فِيَّ غَيْرَةٌ شَدِيدَةٌ فَأَخَافُ أَنْ تَرَى مِنِّي شَيْئًا يُعَذِّبُنِي اللَّهُ بِهِ وَأَنَا امْرَأَةٌ دَخَلْتُ فِي السِّنِّ وَأَنَا ذَاتُ عِيَالٍ فَقَالَ أَمَّا مَا ذَكَرْتِ مِنْ الْغَيْرَةِ فَسَوْفَ يُذْهِبُهَا اللَّهُ عَزَّ وَجَلَّ مِنْكِ وَأَمَّا مَا ذَكَرْتِ مِنْ السِّنِّ فَقَدْ أَصَابَنِي مِثْلُ الَّذِي أَصَابَكِ وَأَمَّا مَا ذَكَرْتِ مِنْ الْعِيَالِ فَإِنَّمَا عِيَالُكِ عِيَالِي قَالَتْ فَقَدْ سَلَّمْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَزَوَّجَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَفَقَالَتْ أُمُّ سَلَمَةَ فَقَدْ أَبْدَلَنِي اللَّهُ بِأَبِي سَلَمَةَ خَيْرًا مِنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yunus] berkata, telah menceritakan kepada kami [Laits] yaitu Ibnu Sa'ad dari [Yazid bin Abdullah bin Usamah bin Al Had] dari ['Amr] yaitu Ibnu Abu 'Amr, dari [Al Muthallib] dari [Umu Salamah] berkata, [Abu Salamah] datang kepadaku pada suatu hari dari sisi Rasulullahi Shallallahu'alaihiwasallam lalu berkata, saya mendengar dari Rasulullahi Shallallahu'alaihiwasallam suatu perkataan lalu saya merasa sangat senang dengannya. Beliau bersabda: \"Tidaklah seorang muslimpun yang terkena musibah lalu dia mengucapkan kalimat istirja' (ucapan INNA LILLAHI WA INNA ILAIHI RAJI'UN) ketika tertimpanya lalu membaca, 'Ya Allah, berilah pahala pada musibahku ini dan gantilah dengan yang lebih baik darinya' kecuali hal itu pasti akan terjadi.\" Umu Salamah berkata, lalu saya menghapal hal itu darinya. Tatkala Abu Salamah meninggal, saya mengucapkan kalimat istirja' dan saya membaca Ya Allah, berilah pahala pada musibahku dan gantilah dengan yang lebih baik darinya, lalu saya kembalikan kepada diriku, dan saya bertanya bagaimana ada yang lebih bagiku daripada Abu Salamah. Setelah iddahku habis, Rasulullahi Shallallahu'alaihiwasallam meminta ijin kepadaku, waktu itu saya sedang membersihkan kulit yang hendak disamak milikku, lalu saya mencuci tanganku dengan daun suatu pohon yang biasa dijadikan sebagai campuran dalam menyamak, lalu saya mengijinkan beliau. Saya meletakkan kepada beliau bantal dari kulit yang pinggirnya ada lipantannya, lalu kujadikan tempat duduk, lalu beliau melamarku. Tatkala beliau selesai berbicara, saya berkata, Wahai Rasulullah, bagaimana saya, saya tidak menyangka jika anda ada rasa cinta kepadaku, sayang, saya adalah wanita yang sangat cemburu, lalu saya takut jika anda melihat dariku suatu hal yang Allah menyiksaku karenanya, selain saya adalah wanita yang telah berumur, saya mempunyai banyak tanggungan. Lalu beliau bersabda: \"Apa yang kamu sebutkan berupa rasa cemburu niscaya Allah AzzaWaJalla akan menghilangkannya darimu. Hal lain yang kamu sebutkan dari umurmu maka saya juga mengalami apa yang kau alami, sedangkan apa yang kau sebutkan mengenai tanggungan maka tanggunganmu adalah tanggunganku. Lalu (Umu Salamah berkata, maka saya menerima Rasulullahi Shallallahu'alaihiwasallam. Lalu Rasulullahi Shallallahu'alaihiwasallam menikahinya. Lalu Umu Salamah berkata, sungguh Allah telah mengganti Abu Salamah dengan yang lebih baik darinya yaitu Rasulullahi Shallallahu'alaihiwasallam."},"1023":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا حَجَّاجٌ وَابْنُ أَبِي زَائِدَةَ قَالَ أَخْبَرَنَا حَجَّاجٌ عَنِ الْحَسَنِ بْنِ سَعْدٍ عَنِ ابْنِ عَبَّاسٍ قَالَ أَخْبَرَنِي أَبُو طَلْحَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ بَيْنَ الْحَجِّ وَالْعُمْرَةِ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Hajjaj] dan [Ibnu Abu Za`idah] berkata, telah mengabarkan kepada kami [Hajjaj] dari [Al Hasan bin Sa'id] dari [Ibnu 'Abbas] berkata, telah menceritakan kepadaku [Abu Thalhah] Rasulullahi Shallallahu'alaihiwasallam pernah menghimpun antara pelaksanaan Haji dan Umrah."},"1024":{"ar":"و قَالَ عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُ سَمِعْتُ أَبَا طَلْحَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةُ تَمَاثِيلَ","id":"dan [Abdurrazzaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] telah mendengar [Ibnu 'Abbas] berkata, saya mendengar [Abu Thalhah] berkata, saya mendengar Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Malaikat tidak akan masuk rumah yang terdapat anjing dan gambar.\""},"1025":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي طَلْحَةَ قَالَلَمَّا صَبَّحَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ وَقَدْ أَخَذُوا مَسَاحِيَهُمْ وَغَدَوْا إِلَى حُرُوثِهِمْ وَأَرْضِهِمْ فَلَمَّا رَأَوْا نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُ الْجَيْشُ رَكَضُوا مُدْبِرِينَ فَقَالَ نَبِيُّ اللَّهِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas bin Malik] dari [Abu Thalhah] berkata, Tatkala Nabiyyullah Shallallahu'alaihiwasallam datang pada waktu pagi ke Khaibar, penduduknya telah mondar mandir dan berangkat ke ladang-ladang dan kebun mereka. Ketika mereka melihat Nabiyullah Shallallahu'alaihiwasallam bersama para pasukannya, mereka lari terbirit-birit hingga beliau bersabda: Allahu Akbar Allahu Akbar, kita jika telah memasuki bumi sebuah kaum, maka alangkah buruklah pagi harinya (keadaan) orang-orang yang mendapatkan peringatan itu.\""},"1026":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ حَفْصٍ عَنِ الْأَغَرِّ عَنْ رَجُلٍ آخَرَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَوَضَّئُوا مِمَّا غَيَّرَتْ النَّارُو قَالَ أَبُو بَكْرٍ يَعْنِي ابْنَ حَفْصٍ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ ابْنِ أَبِي طَلْحَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ فَقَالَ وَثَنَا شُعْبَةُ عَنِ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Abdushshamad] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Abu Bakar bin Hafsh] dari [Al A'ghar] dari [orang lain] dari [Abu Hurairah] Nabi Shallallahu'alaihiwasallam bersabda: \"Berwudlulah dari segala hal yang tersentuh api\". Dan [Abu Bakar] yaitu Ibnu Al Hafs, berkata, telah menceritakan kepada kami [Az Zuhri] dari [Ibnu Abu Thalhah] dari [Bapaknya] dari Nabi Shallallahu'alaihiwasallam sama dengan yang di atas. Lalu berkata, dan telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi Shallallahu'alaihiwasallam sama dengan yang di atas."},"1027":{"ar":"حَدَّثَنَا حُسَيْنٌ فِي تَفْسِيرِ شَيْبَانَ عَنْ قَتَادَةَ قَالَ حَدَّثَ أَنَسُ بْنُ مَالِكٍ عَنْ أَبِي طَلْحَةَ قَالَصَبَّحَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ وَقَدْ أَخَذُوا مَسَاحِيَهُمْ وَغَدَوْا إِلَى حُرُوثِهِمْ فَلَمَّا رَأَوْا نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُ الْجَيْشُ نَكَصُوا مُدْبِرِينَ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ قَالَحَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ قَوْلَهُ عَزَّ وَجَلَّ{ فَإِذَا نَزَلَ بِسَاحَتِهِمْ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }قَالَ حَدَّثَ أَنَسُ بْنُ مَالِكٍ عَنْ أَبِي طَلْحَةَ قَالَ صَبَّحَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Husain] dalam tafsir [Syaiban], dari [Qatadah] berkata, [Anas bin Malik] menceritakan dari [Abu Thalhah] berkata, Nabiyullah Shallallahu'alaihiwasallam datang pada waktu pagi di Khaibar, para penduduknya telah berangkat ke ladang-ladang dan kebun mereka. Ketika mereka melihat Nabiyullah Shallallahu'alaihiwasallam bersama para pasukannya, mereka lari terbirit-birit hingga beliau bersabda: Allahu Akbar Allahu Akbar, telah tumbang Khaibar, kami jika memasuki sebuah halaman kaum, maka alangkah buruklah pagi harinya (keadaan) orang-orang yang mendapatkan peringatan itu.\" (Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Yunus] berkata, telah menceritakan kepada kami [Syaiban] dari [Qatadah] pada firman-Nya AzzaWaJalla, 'Maka apabila siksaan itu turun dihalaman mereka, Maka amat buruklah pagi hari yang dialami oleh orang-orang yang diperingatkan itu' Dia berkata, [Anas bin Malik] menceritakan dari [Abu Thalhah] berkata, Nabiyullah Shallallahu'alaihiwasallam datang pada saat masih pagi, ke Khaibar, seperti pada hadis di atas."},"1028":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنْ أَبِي طَلْحَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ صُورَةٌ وَلَا كَلْبٌ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah] dari [Ibnu 'Abbas] dari [Abu Thalhah] sampai padanya dari Nabi Shallallahu'alaihiwasallam bersabda: \"Malaikat tidak akan masuk rumah yang terdapat gambar dan anjing\"."},"1029":{"ar":"حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ قَالَ أَخْبَرَنَا حَجَّاجٌ عَنِ الْحَسَنِ بْنِ سَعْدٍ عَنِ ابْنِ عَبَّاسٍ قَالَ أَنْبَأَنِي أَبُو طَلْحَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ بَيْنَ حَجَّةٍ وَعُمْرَةٍ","id":"Telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Za`idah] berkata, telah mengabarkan kepada kami [Hajjaj] dari [Al Hasan bin Sa'id] dari [Ibnu 'Abbas] berkata, telah memberitakan kepada kami [Abu Thalhah] Rasulullahi Shallallahu'alaihiwasallam pernah mnghimpun antara haji dan umrah."},"1030":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي طَلْحَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا غَلَبَ قَوْمًا أَحَبَّ أَنْ يُقِيمَ بِعَرْصَتِهِمْ ثَلَاثًا","id":"Telah menceritakan kepada kami [Mu'adz bin Mu'adz] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas bin Malik] dari [Abu Thalhah] Rasulullahi Shallallahu'alaihiwasallam jika telah mengalahkan suatu kaum, maka beliau senang untuk tetap bermukim di daerah tersebut selama tiga hari."},"1031":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا شَيْبَانُ وَحُسَيْنٌ فِي تَفْسِيرِ شَيْبَانَ عَنْ قَتَادَةَ قَالَ وَحَدَّثَنَا أَنَسُ بْنُ مَالِكٍ أَنَّ أَبَا طَلْحَةَ قَالَغَشِيَنَا النُّعَاسُ وَنَحْنُ فِي مَصَافِّنَا يَوْمَ بَدْرٍ قَالَ أَبُو طَلْحَةَ وَكُنْتُ فِيمَنْ غَشِيَهُ النُّعَاسُ يَوْمَئِذٍ فَجَعَلَ سَيْفِي يَسْقُطُ مِنْ يَدِي وَآخُذُهُ وَيَسْقُطُ وَآخُذُهُ","id":"Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Syaiban] dan [Husain] dalam Tafsir [Syaiban], dari [Qatadah] berkata, dan telah menceritakan kepada kami [Anas bin Malik] [Abu Thalhah] berkata, kami mendapati rasa kantuk yang sangat pada waktu kita dalam barisan perang Badar, lalu Abu Thalhah berkata, saya termasuk yang mengalami rasa kantuk yang sangat pada hari itu sehingga pedangku terjatuh dari tanganku, lalu aku mengambilnya, lalu jatuh kembali dan kembali aku mengambilnya."},"1032":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي طَلْحَةَ قَالَلَمَّا صَبَّحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ وَقَدْ أَخَذُوا مَسَاحِيَهُمْ وَغَدَوْا إِلَى حُرُوثِهِمْ وَأَرْضِيهِمْ فَلَمَّا رَأَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُ الْجَيْشُ نَكَصُوا مُدْبِرِينَ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }","id":"Telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas bin Malik] dari [Abu Thalhah] berkata, Tatkala Rasulullahi Shallallahu'alaihiwasallam datang pada waktu pagi ke Khaibar, penduduknya telah mondar mandir dan berangkat ke ladang-ladang dan kebun mereka. Ketika mereka melihat Nabi Shallallahu'alaihiwasallam bersama para pasukannya, mereka lari terbirit-birit hingga Nabiyullah Shallallahu'alaihiwasallam bersabda: Allahu Akbar, Allahu Akbar, jika kami telah memasuki halaman sebuah kaum, maka alangkah buruklah pagi harinya (keadaan) orang-orang yang mendapatkan peringatan itu.\""},"1033":{"ar":"حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ قَالَ أَخْبَرَنَا زَكَرِيَّا بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ وَكَانَتْ لَهُ صُحْبَةٌ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُحْسِنْ إِلَى جَارِهِ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Rauh bin 'Ubadah] berkata, telah mengabarkan kepada kami [Zakariya bin Ishaq] berkata, telah menceritakan kepada kami ['Amr bin Dinar] dari [Nafi' bin Jubair bin Muth'im] dari [Abu Syuraih Al Khuza'i], dia berkata, Aku mendengar Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang beriman kepada Allah dan Hari Akhir, hendaklah dia memuliakan tamunya. Barangsiapa yang beriman kepada Allah dan Hari Akhir hendaklah ia berbuat baik kepada tetangganya, dan barangsiapa yang beriman kepada Allah dan Hari Akhir, hendaklah ia berkata baik atau diam.\""},"1034":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ وَجَائِزَتُهُ يَوْمٌ وَلَيْلَةٌ وَلَا يَحِلُّ لِلرَّجُلِ أَنْ يُقِيمَ عِنْدَ أَحَدٍ حَتَّى يُؤْثِمَهُ قَالُوا يَا رَسُولَ اللَّهِ فَكَيْفَ يُؤْثِمُهُ قَالَ يُقِيمُ عِنْدَهُ وَلَيْسَ لَهُ شَيْءٌ يَقْرِيهِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Syuraih Al Khuza'i] berkata, Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Hak jamuan bertamu itu selama tiga hari, sedang yang wajar adalah sehari semalam, dan tidak halal bagi seseorang untuk tinggal pada seseorang sampai dia menjadikan dia berdosa\". Mereka bertanya, Wahai Rasulullah, bagaimana dia membuat dosa terhadapnya?. Beliau bersabda: \"Dia tinggal bersama seseorang dan seseorang itu tidak memiliki apapun untuk menjamunya.\""},"1035":{"ar":"حَدَّثَنَا حَجَّاجٌ وَرَوْحٌ قَالَا حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْكَعْبِيِّ وَقَالَ رَوْحٌ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَاللَّهِ لَا يُؤْمِنُ وَاللَّهِ لَا يُؤْمِنُ وَاللَّهِ لَا يُؤْمِنُ قَالَهَا ثَلَاثَ مَرَّاتٍ قَالُوا وَمَا ذَاكَ يَا رَسُولَ اللَّهِ قَالَ الْجَارُ لَا يَأْمَنُ الْجَارُ بَوَائِقَهُ قَالُوا وَمَا بَوَائِقُهُ قَالَ شَرُّهُ","id":"Telah menceritakan kepada kami [Hajjaj] dan [Rauh] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Sa'id Al Maqburi] dari [Abu Syuraih Al Ka'b'i] dan [Rauh] berkata, dari [Abu Hurairah] Nabi Shallallahu'alaihiwasallam bersabda: \"Demi Allah tidaklah beriman seseorang, Demi Allah tidaklah beriman seseorang, Demi Allah tidaklah beriman seseorang\" beliau mengulanginya tiga kali. Mereka bertanya, \"Apakah hal tersebut wahai Rasulullah?\" (Rasulullahi Shallallahu'alaihiwasallam) menjawab, \"Yaitu seorang tetangga yang tidak merasa nyaman dengan tetangganya karena cobaan yang dia terima\", lalu mereka berkata, Apakah cobaan tersebut? Beliau bersabda: \"Keburukannya\"."},"1036":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي سَعِيدٌ يَعْنِي الْمَقْبُرِيَّ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّأَنَّهُ قَالَ لِعَمْرِو بْنِ سَعِيدٍ وَهُوَ يَبْعَثُ الْبُعُوثَ إِلَى مَكَّةَ ائْذَنْ لِي أَيُّهَا الْأَمِيرُ أُحَدِّثْكَ قَوْلًا قَامَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغَدَ مِنْ يَوْمِ الْفَتْحِ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي وَأَبْصَرَتْهُ عَيْنَايَ حِينَ تَكَلَّمَ بِهِ أَنْ حَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ مَكَّةَ حَرَّمَهَا اللَّهُ وَلَمْ يُحَرِّمْهَا النَّاسُ فَلَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْفِكَ بِهَا دَمًا وَلَا يَعْضِدَ بِهَا شَجَرَةً فَإِنْ أَحَدٌ تَرَخَّصَ لِقِتَالِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا فَقُولُوا إِنَّ اللَّهَ عَزَّ وَجَلَّ أَذِنَ لِرَسُولِهِ وَلَمْ يَأْذَنْ لَكُمْ إِنَّمَا أَذِنَ لِي فِيهَا سَاعَةً مِنْ نَهَارٍ وَقَدْ عَادَتْ حُرْمَتُهَا الْيَوْمَ كَحُرْمَتِهَا بِالْأَمْسِ وَلْيُبَلِّغْ الشَّاهِدُ الْغَائِبَ","id":"Telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Laits] berkata, telah menceritakan kepadaku [Sa'id yaitu Al Maqburi] dari [Abu Syuraih Al 'Adawi] dia berkata, kepada 'Amr bin Sa'id yang mengutus utusan ke Makkah, Wahai Amir (pemimpin, pent) ijinkanlah diriku untuk menceritakan kepadamu sebuah sabda Rasulullahi Shallallahu'alaihiwasallam yang beliau sampaikan ketika beliau berdiri pada satu hari setelah Penaklukan Makkah, yang aku mendengar hadits tersebut dengan kedua telingaku, dan aku memperhatikanya dengan segenap hatiku serta melihatnya dengan kedua bola mataku ketika beliau bersabda: yang beliau memuji Allah dan memujanya, lalu beliau bersabda: \"Sesungguhnya Allah-lah yang telah mengharamkan Makkah, maka tidak diperbolehkan barangsiapa yang beriman kepada Allah dan hari akhir untuk menumpahkan darah di tanah Makah dan menebang pohonnya, maka barangsiapa yang merasa bolehnya untuk berperang di tanah Makkah karena perang yang di lakukan Rasulullahi Shallallahu'alaihiwasallamdi atasnya, maka katakanlah kepadanya bahwasanya Allah mengizinkan Rasul-Nya dan bukan kepada kalian. Sesungguhnya Allah AzzaWaJalla mengizinkan hanya sementara waktu pada waktu siang, dan keharamannya (Makkah, pent) telah kembali hari ini sebagaimana keharamannya pada hari kemarin. Bagi yang menyaksikan, tolong sampaikanlah hal ini kepada yang tidak hadir\""},"1037":{"ar":"حَدَّثَنَا حَجَّاجٌ وَأَبُو كَامِلٍ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّ أَنَّهُ قَالَسَمِعَتْ أُذُنَايَ وَأَبْصَرَتْ عَيْنَايَ حِينَ تَكَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ جَائِزَتَهُ قَالُوا وَمَا جَائِزَتُهُ يَا رَسُولَ اللَّهِ قَالَ يَوْمٌ وَلَيْلَةٌ وَالضِّيَافَةُ ثَلَاثٌ فَمَا كَانَ وَرَاءَ ذَلِكَ فَهُوَ صَدَقَةٌ عَلَيْهِ وَقَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ وَقَالَ أَبُو كَامِلٍ وَلَا يَثْوِي عِنْدَهُ حَتَّى يُحْرِجَهُ","id":"Telah menceritakan kepada kami [Hajjaj] dan [Abu Kamil] telah menceritakan kepada kami [Laits] yaitu Ibnu Sa'ad berkata, telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari [Abu Syuraih Al 'Adawi] dia berkata, saya mendengar dengan kedua telingaku dan saya melihat dengan kedua mataku, ketika Rasulullahi Shallallahu'alaihiwasallam berbicara, yaitu sabdanya, \"Barangsiapa yang beriman kepada Allah dan Hari Akhir, hendaklah memuliakan tetangganya, barangsiapa yang beriman kepada Allah dan Hari Akhir, hendaklah memuliakan tamunya agar ia memperoleh haknya \". Mereka bertanya, apakah hak tamu Wahai Rasulullah?. Beliau bersabda: \" Haknya adalah jamuan satu hari satu malam, dan bertamu itu paling lama adalah tiga hari, adapun setelah waktu itu adalah sedekah atasnya\". Dan beliau bersabda: \"Barangsiapa yang beriman kepada Allah dan Hari Akhir, hendaklah mengucapkan perkataan yang baik atau diam\". Abu Kamil berkata, janganlah tinggal bersamanya sampai dia merepotkannya.\""},"1038":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْحَرَّانِيُّ عَنِ ابْنِ إِسْحَاقَ وَيَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنِ الْحَارِثِ بْنِ فُضَيْلٍ عَنْ سُفْيَانَ بْنِ أَبِي الْعَوْجَاءِ قَالَ يَزِيدُ السُّلَمِيِّ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ يَزِيدُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أُصِيبَ بِدَمٍ أَوْ خَبْلٍ الْخَبْلُ الْجِرَاحُ فَهُوَ بِالْخِيَارِ بَيْنَ إِحْدَى ثَلَاثٍ إِمَّا أَنْ يَقْتَصَّ أَوْ يَأْخُذَ الْعَقْلَ أَوْ يَعْفُوَ فَإِنْ أَرَادَ رَابِعَةً فَخُذُوا عَلَى يَدَيْهِ فَإِنْ فَعَلَ شَيْئًا مِنْ ذَلِكَ ثُمَّ عَدَا بَعْدُ فَقَتَلَ فَلَهُ النَّارُ خَالِدًا فِيهَا مُخَلَّدًا","id":"Telah menceritakan kepada kami [Muhammad bin Salamah Al Harani] dari [Ibnu Ishaq] dan [Yazid bin Harun] berkata, telah memberitakan kepada kami [Muhammad bin Ishaq] dari [Al Harits bin Fudlail] dari [Sufyan bin Abu Al 'Auja`] [Yazid bin As Sulamy] berkata, dari [Abu Syuraih Al Khuza'i] berkata, Rasulullahi Shallallahu'alaihiwasallam bersabda. Yazid berkata, Aku mendengar Rasulullahi Shallallahu'alaihiwasallam berkata, \"Barangsiapa yang terkena darah (terbunuh) ataupun terluka, maka baginya untuk memilih di antara salah satu dari tiga pilihan: Meminta qishas ataupun meminta diyah (ganti materi) ataupun memaafkan. Barangsiapa yang memilih yang keempat (selain dari tiga pilihan, pent) maka cegahlah dia, dan apabila dia telah memilih di antara tiga hal tersebut kemudian dia masih membunuh maka baginya balasan api neraka yang kekal di dalamnya.\""},"1039":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ يُونُسَ يُحَدِّثُ عَنِ الزُّهْرِيِّ عَنْ مُسْلِمِ بْنِ يَزِيدَ أَحَدِ بَنِي سَعْدِ بْنِ بَكْرٍ أَنَّهُ سَمِعَ أَبَا شُرَيْحٍ الْخُزَاعِيَّ ثُمَّ الْكَعْبِيَّ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُأَذِنَ لَنَا رَسُولُ اللَّهِ يَوْمَ الْفَتْحِ فِي قِتَالِ بَنِي بَكْرٍ حَتَّى أَصَبْنَا مِنْهُمْ ثَأْرَنَا وَهُوَ بِمَكَّةَ ثُمَّ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَفْعِ السَّيْفِ فَلَقِيَ رَهْطٌ مِنَّا الْغَدَ رَجُلًا مِنْ هُذَيْلٍ فِي الْحَرَمِ يَؤُمُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُسْلِمَ وَكَانَ قَدْ وَتَرَهُمْ فِي الْجَاهِلِيَّةِ وَكَانُوا يَطْلُبُونَهُ فَقَتَلُوهُ وَبَادَرُوا أَنْ يَخْلُصَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَأْمَنَ فَلَمَّا بَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَضِبَ غَضَبًا شَدِيدًا وَاللَّهِ مَا رَأَيْتُهُ غَضِبَ غَضَبًا أَشَدَّ مِنْهُ فَسَعَيْنَا إِلَى أَبِي بَكْرٍ وَعُمَرَ وَعَلِيٍّ رَضِيَ اللَّهُ عَنْهُمْ نَسْتَشْفِعُهُمْ وَخَشِينَا أَنْ نَكُونَ قَدْ هَلَكْنَا فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَأَثْنَى عَلَى اللَّهِ عَزَّ وَجَلَّ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ هُوَ حَرَّمَ مَكَّةَ وَلَمْ يُحَرِّمْهَا النَّاسُ وَإِنَّمَا أَحَلَّهَا لِي سَاعَةً مِنْ النَّهَارِ أَمْسِ وَهِيَ الْيَوْمَ حَرَامٌ كَمَا حَرَّمَهَا اللَّهُ عَزَّ وَجَلَّ أَوَّلَ مَرَّةٍ وَإِنَّ أَعْتَى النَّاسِ عَلَى اللَّهِ عَزَّ وَجَلَّ ثَلَاثَةٌ رَجُلٌ قَتَلَ فِيهَا وَرَجُلٌ قَتَلَ غَيْرَ قَاتِلِهِ وَرَجُلٌ طَلَبَ بِذَحْلٍ فِي الْجَاهِلِيَّةِ وَإِنِّي وَاللَّهِ لَأَدِيَنَّ هَذَا الرَّجُلَ الَّذِي قَتَلْتُمْ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepadaku [bapakku] berkata, saya telah mendengar [Yunus] menceritakan dari [Az Zuhri] dari [Muslim bin Yazid] salah satu Bani Sa'ad bin Bakr, telah mendengar [Abu Syuraih Al Khuza'i, Al Ka'bi] dia adalah salah seorang sahabat Rasulullahi Shallallahu'alaihiwasallam berkata, Rasulullahi Shallallahu'alaihiwasallam mengijinkan kepada kami pada Fathu Makkah untuk memerangi Bani Bakr sampai kami bisa menuntut balas pada mereka dan beliau berada di Makah. Lalu beliau menyuruh agar kami mengangkat pedang, lalu sebagain orang dari kami mendapati seorang laki-laki dari Hudzail di Tanah Haram yang menuju Rasulullahi Shallallahu'alaihiwasallam untuk masuk Islam dan dia telah merampas harta dan keluarga mereka pada Masa Jahiliyah. Lalu mereka memintanya kembali, dan membunuhnya, lalu mereka bersegera sebelum dia bertemu pada Rasulullahi Shallallahu'alaihiwasallam hingga menjadi aman. Tatkala kabar itu sampai pada Rasulullahi Shallallahu'alaihiwasallam, beliau sangat marah besar, demi Allah saya tidak pernah melihat beliau semarah itu. Lalu kami menuju Abu Bakar, 'Umar dan 'Ali RAm, kami meminta tolong pada mereka, dan kami takut jika kami binasa. Tatkala Rasulullahi Shallallahu'alaihiwasallam shalat lalu beliau berdiri dan memuji Allah 'azza wajalla sesuai dengan yang patut bagi-Nya, lalu bersabda: \"Amma ba'du, Allah 'azza wajalla telah mengharamkan Makkah sedangkan orang-orang tidak mengharamkannya. Hanyasanya pernah dihalalkan bagiku, suatu waktu dari sebagian siang kemarin. Pada hari ini Makah adalah haram sebagaimana Allah 'azza wajalla telah mengharamkannya sejak pertama kali. Sesungguhnya orang yang paling sombong atas Allah 'azza wajalla ada tiga kelompok yaitu: Laki-laki yang membunuh di dalamnya, laki-laki yang membunuh orang yang tidak membunuhnya dan laki-laki yang meminta kembali uang tebusan pada Jaman Jahiliyah. Sesungguhnya saya, demi Allah, sunguh saya akan mengganti diyat orang yang telah kalian bunuh\", lalu Rasulullahi Shallallahu'alaihiwasallam membayar diyatnya."},"1040":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَلَمَّا بَعَثَ عَمْرُو بْنُ سَعِيدٍ إِلَى مَكَّةَ بَعْثَهُ يَغْزُو ابْنَ الزُّبَيْرِ أَتَاهُ أَبُو شُرَيْحٍ فَكَلَّمَهُ وَأَخْبَرَهُ بِمَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ خَرَجَ إِلَى نَادِي قَوْمِهِ فَجَلَسَ فِيهِ فَقُمْتُ إِلَيْهِ فَجَلَسْتُ مَعَهُ فَحَدَّثَ قَوْمَهُ كَمَا حَدَّثَ عَمْرَو بْنَ سَعِيدٍ مَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَمَّا قَالَ لَهُ عَمْرُو بْنُ سَعِيدٍ قَالَ قُلْتُ هَذَا إِنَّا كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ افْتَتَحَ مَكَّةَ فَلَمَّا كَانَ الْغَدُ مِنْ يَوْمِ الْفَتْحِ عَدَتْ خُزَاعَةُ عَلَى رَجُلٍ مِنْ هُذَيْلٍ فَقَتَلُوهُ وَهُوَ مُشْرِكٌ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِينَا خَطِيبًا فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ اللَّهَ عَزَّ وَجَلَّ حَرَّمَ مَكَّةَ يَوْمَ خَلَقَ السَّمَاوَاتِ وَالْأَرْضَ فَهِيَ حَرَامٌ مِنْ حَرَامِ اللَّهِ تَعَالَى إِلَى يَوْمِ الْقِيَامَةِ لَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْفِكَ فِيهَا دَمًا وَلَا يَعْضِدَ بِهَا شَجَرًا لَمْ تَحْلِلْ لِأَحَدٍ كَانَ قَبْلِي وَلَا تَحِلُّ لِأَحَدٍ يَكُونُ بَعْدِي وَلَمْ تَحْلِلْ لِي إِلَّا هَذِهِ السَّاعَةَ غَضَبًا عَلَى أَهْلِهَا أَلَا ثُمَّ قَدْ رَجَعَتْ كَحُرْمَتِهَا بِالْأَمْسِ أَلَا فَلْيُبَلِّغْ الشَّاهِدُ مِنْكُمْ الْغَائِبَ فَمَنْ قَالَ لَكُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَاتَلَ بِهَا فَقُولُوا إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ أَحَلَّهَا لِرَسُولِهِ وَلَمْ يُحْلِلْهَا لَكُمْ يَا مَعْشَرَ خُزَاعَةَ وَارْفَعُوا أَيْدِيَكُمْ عَنْ الْقَتْلِ فَقَدْ كَثُرَ أَنْ يَقَعَ لَئِنْ قَتَلْتُمْ قَتِيلًا لَأَدِيَنَّهُ فَمَنْ قُتِلَ بَعْدَ مَقَامِي هَذَا فَأَهْلُهُ بِخَيْرِ النَّظَرَيْنِ إِنْ شَاءُوا فَدَمُ قَاتِلِهِ وَإِنْ شَاءُوا فَعَقْلُهُ ثُمَّ وَدَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلَ الَّذِي قَتَلَتْهُ خُزَاعَةُ فَقَالَ عَمْرُو بْنُ سَعِيدٍ لِأَبِي شُرَيْحٍ انْصَرِفْ أَيُّهَا الشَّيْخُ فَنَحْنُ أَعْلَمُ بِحُرْمَتِهَا مِنْكَ إِنَّهَا لَا تَمْنَعُ سَافِكَ دَمٍ وَلَا خَالِعَ طَاعَةٍ وَلَا مَانِعَ جِزْيَةٍ قَالَ فَقُلْتُ قَدْ كُنْتُ شَاهِدًا وَكُنْتَ غَائِبًا وَقَدْ بَلَّغْتُ وَقَدْ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبَلِّغَ شَاهِدُنَا غَائِبَنَا وَقَدْ بَلَّغْتُكَ فَأَنْتَ وَشَأْنُكَ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Sa'id bin Sa'id Al Maqrubi] dari [Abu Syuraih Al Khuza'i] berkata, tatkala 'Amr bin Sa'id mengutus ke Makkah, yang bertujuan menyerang Ibnu Az Zubair. Abu Syuraih mendatanginya lalu mengajaknya bicara dan menghabarinya dengan apa yang telah dia dengar dari Rasulullahi Shallallahu'alaihiwasallam lalu dia keluar menuju tempat pertemuan kaumnya dan duduk di dalamya. Lalu saya berdiri mendatanginya, saya duduk bersamanya. Lalu dia menyampaikan kepada kaumnya sebagaimana dia menyampaikan kepada 'Amr bin Sa'id apa yang telah dia dengar dari Rasulullahi Shallallahu'alaihiwasallam dan apa yang telah dikatakan 'Amr bin Sa'id kepadanya. (Abu Syuraih Al Khuza'i RA) berkata, ini, kami bersama Rasulullahi Shallallahu'alaihiwasallam ketika terjadi Fathu Makah, maka pada esok harinya Khuza'ah menganggu seorang laki-laki dari Hudzail lalu mereka membunuhnya. Dia dalam keadaan musrik. Lalu Rasulullahi Shallallahu'alaihiwasallam berdiri kepada kami dan berkutbah, beliau bersabda: \"Wahai manusia, Allah 'azza wajalla telah mengharamkan Makkah pada saat diciptakannya langit dan bumi. Maka Makkah adalah haram sejak Allah Ta'ala mengharamkannya sampai Hari Kiamat. Tidak halal bagi seorangpun yang beriman kepada Allah dan Hari Akhir, menumpahkan darah di dalamnya, tidak boleh menebang pohon di dalamnya. Tidak halal bagi seorangpun sebelumku juga kepada setelahku. Bahkan tidak halal bagiku kecuali pada saat ini saja, karena sebagai kemarahan kepada para penduduknya. Ketahuilah, kemudian saya telah mengembalikan keharamannya sebagaimana kemarin. Ketahuilah, hendaknya orang yang datang dari kalian memberitahukan orang yang tidak datang. Barangsiapa yang berkata kepada kalian Rasulullahi Shallallahu'alaihiwasallam telah berperang di dalamnya maka katakanlah Allah 'azza wajalla telah menghalalkannya kepada Rasul-Nya dan Dia tidak menghalalkannya kepada kalian. Wahai orang-orang Khuza'ah angkatlah tangan-tangan kalian dari membunuh, karena hal itu telah banyak terjadi. Jika kalian telah membunuh, maka saya akan membayar diyatnya. Siapa yang dibunuh setelah saya di sini, maka keluarganya berhak memilih antara dua pilihan. Jika mereka menghendaki, maka dia mendapatkan darah orang yang melakukannya, jika mereka mau maka dia akan mendapatkan harta sebagai ganti rugi. Lalu Rasulullahi Shallallahu'alaihiwasallam membayar diyat seorang laki-laki yang telah dibunuh oleh Khuza'ah. Lalu 'Amr bin Sa'id berkata kepada Abu Syuraih, pergilah Wahai syaikh, kami lebih tahu tentang keharamannya daripada kamu, hal itu tidak menghalangi orang yang menumpahkan darah atau orang yang melepaskan ketaatan atau orang yang enggan membayar jizyah. (Abu Syuraih Al Khuza'i RA) berkata, lalu saya berkata, saya telah menyaksikan dan terkadang saya tidak datang, dan terkadang saya sampaikan padahal Rasulullahi Shallallahu'alaihiwasallam telah memerintahkan kepada kami sebagai orang yang hadir kepada orang yang tidak hadir, maka hal itu saya sampaikan kepadamu, maka terserah kepadamu."},"1041":{"ar":"قَالَ عَبْد اللَّهِ وَجَدْتُ فِي كِتَابِ أَبِي بِخَطِّ يَدِهِ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ وَأَكْبَرُ عِلْمِي أَنَّ أَبِي حَدَّثَنَا قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ أَعْتَى النَّاسِ عَلَى اللَّهِ عَزَّ وَجَلَّ مَنْ قَتَلَ غَيْرَ قَاتِلِهِ أَوْ طَلَبَ بِدَمِ الْجَاهِلِيَّةِ مِنْ أَهْلِ الْإِسْلَامِ أَوْ بَصَّرَ عَيْنَيْهِ فِي النَّوْمِ مَا لَمْ تُبْصِرَا","id":"Abdullah berkata, saya telah mendapatkan dalam kitab bapakku dengan tulisan dia sendiri, telah menceritakan kepada kami ['Ali bin Abdullah] menurut pengetahuanku bapakku, telah menceritakan kepada kami berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Abdurrahman bin Ishaq] berkata, telah menceritakan kepada kami [Az Zuhri] dari ['Atha` bin Yazid Al Laitsi] dari [Abu Syuraih Al Khuza'i] Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Termasuk orang yang paling sombong terhadap Allah AzzaWaJalla adalah seseorang membunuh orang yang tidak membunuhnya atau menuntut darah pada Masa Jahiliyyah pada saat sudah Islam atau dia mengaku bermimpi padahal tidak.\""},"1042":{"ar":"حَدَّثَنَا فَيَّاضُ بْنُ مُحَمَّدٍ الرَّقِّيُّ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ ثَابِتِ بْنِ الْحَجَّاجِ الْكِلَابِيِّ عَنْ عَبْدِ اللَّهِ الْهَمْدَانِيِّ عَنِ الْوَلِيدِ بْنِ عُقْبَةَ قَالَلَمَّا فَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ جَعَلَ أَهْلُ مَكَّةَ يَأْتُونَهُ بِصِبْيَانِهِمْ فَيَمْسَحُ عَلَى رُءُوسِهِمْ وَيَدْعُو لَهُمْ فَجِيءَ بِي إِلَيْهِ وَإِنِّي مُطَيَّبٌ بِالْخَلُوقِ وَلَمْ يَمْسَحْ عَلَى رَأْسِي وَلَمْ يَمْنَعْهُ مِنْ ذَلِكَ إِلَّا أَنَّ أُمِّي خَلَّقَتْنِي بِالْخَلُوقِ فَلَمْ يَمَسَّنِي مِنْ أَجْلِ الْخَلُوقِ","id":"Telah menceritakan kepada kami [Fayyad bin Muhammad Ar-Riqi] dari [Ja'far bin Burqan] dari [Tsabit bin Al Hajjaj, Al Kilabi] dari [Abdullah Al Hamdani] dari [Walid bin 'Uqbah] berkata, Ketika Rasulullahi Shallallahu'alaihiwasallam menaklukkan Makkah, penduduk Makkah berdatangan dengan membawa bayi-bayi mereka, lalu (Rasulullahi Shallallahu'alaihiwasallam) membasuh kepala mereka dan berdoa untuk mereka. Saya juga termasuk yang didatangkan ke hadapan beliau, saya dalam keadaan memakai pengharum wangi-wangian (yang berwarna kuning), beliau tidak mengusap kepalaku tapi juga tidak melarangnya, kecuali hanya ibukulah yang memberiku wangi-wangian tersebut, dan beliau tidak mengusapku karena minyak tersebut."},"1043":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي هَاشِمٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبِرَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَنْشَقْتَ فَبَالِغْ إِلَّا أَنْ تَكُونَ صَائِمًا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abu Hisyam] dari ['Ashim bin Laqit bin Shabirah] dari [bapaknya] berkata, Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Jika kalian melakukan istinsyaq (menghirup air ke dalam hidung waktu berwudlu) maka perbanyaklah kecuali kalian dalam keadaan berpuasa.\""},"1044":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي هَاشِمٍ إِسْمَاعِيلَ بْنِ كَثِيرٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبِرَةَ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِذَا تَوَضَّأْتَ فَخَلِّلْ الْأَصَابِعَ","id":"Telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Hasyim, Isma'il bin Katsir] dari ['Ashim bin Laqit bin Shabirah] dari [bapaknya] berkata, saya telah menemui Nabi Shallallahu'alaihiwasallam lalu beliau bersabda: \"Jika kamu berwudlu maka silangilah jari-jari.\""},"1045":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي هَاشِمٍ إِسْمَاعِيلَ بْنِ كَثِيرٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبِرَةَ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَبَحَ لَنَا شَاةً وَقَالَ لَا تَحْسَبَنَّ وَلَمْ يَقُلْ لَا يَحْسَبَنَّ إِنَّا إِنَّمَا ذَبَحْنَاهَا لَكَ وَلَكِنْ لَنَا غَنَمٌ فَإِذَا بَلَغَتْ مِائَةً ذَبَحْنَا شَاةً","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abu Hasyim, Isma'il bin Katsir] dari ['Ashim bin Laqith bin Shabirah] dari [bapaknya] berkata, saya menemui Nabi Shallallahu'alaihiwasallam lalu menyembelih kambing untuk kami dan bersabda: \"Nggak usah kamu hitung-hitung\" dan tidak bersabda: \"Nggak usah diantara kalian menghitung.' Sesungguhnya kami menyembelihnya memang untuk kalian, tapi kami memiliki kambing jika jumlahnya sudah mencapai seratus maka kami menyembelihnya satu.\""},"1046":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ إِسْمَاعِيلَ بْنِ كَثِيرٍ أَبِي هَاشِمٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبِرَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَأَبْلِغْ فِي الِاسْتِنْشَاقِ مَا لَمْ تَكُنْ صَائِمًا","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Isma'il bin katsir, Abu Hasyim] dari ['Ashim bin Laqith bin Shabirah] dari [bapaknya] dari Nabi Shallallahu'alaihiwasallam 'Jika kamu melakukan wudlu maka perbanyaklah dalam memasukkan air ke dalam hidung selama kalian tidak berpuasa.'"},"1047":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ كَثِيرٍ أَبُو هَاشِمٍ الْمَكِّيُّ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبِرَةَ عَنْ أَبِيهِ وَافِدِ بَنِي الْمُنْتَفِقِ قَالَانْطَلَقْتُ أَنَا وَصَاحِبٌ لِي حَتَّى انْتَهَيْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ نَجِدْهُ فَأَطْعَمَتْنَا عَائِشَةُ تَمْرًا وَعَصَدَتْ لَنَا عَصِيدَةً إِذْ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَقَلَّعُ فَقَالَ هَلْ أُطْعِمْتُمْ مِنْ شَيْءٍ قُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ فَبَيْنَا نَحْنُ كَذَلِكَ دَفَعَ رَاعِي الْغَنَمِ فِي الْمُرَاحِ عَلَى يَدِهِ سَخْلَةٌ قَالَ هَلْ وَلَدَتْ قَالَ نَعَمْ قَالَ فَاذْبَحْ لَنَا شَاةً ثُمَّ أَقْبِلْ عَلَيْنَا فَقَالَ لَا تَحْسَبَنَّ وَلَمْ يَقُلْ لَا يَحْسَبَنَّ إِنَّا ذَبَحْنَا الشَّاةَ مِنْ أَجْلِكُمَا لَنَا غَنَمٌ مِائَةٌ لَا نُرِيدُ أَنْ تَزِيدَ عَلَيْهَا فَإِذَا وَلَّدَ الرَّاعِي بَهْمَةً أَمَرْنَاهُ بِذَبْحِ شَاةٍ فَقَالَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي عَنْ الْوُضُوءِ قَالَ إِذَا تَوَضَّأْتَ فَأَسْبِغْ وَخَلِّلْ الْأَصَابِعَ وَإِذَا اسْتَنْثَرْتَ فَأَبْلِغْ إِلَّا أَنْ تَكُونَ صَائِمًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي امْرَأَةً فَذَكَرَ مِنْ طُولِ لِسَانِهَا وَإِيذَائِهَا فَقَالَ طَلِّقْهَا قَالَ يَا رَسُولَ اللَّهِ إِنَّهَا ذَاتُ صُحْبَةٍ وَوَلَدٍ قَالَ فَأَمْسِكْهَا وَأْمُرْهَا فَإِنْ يَكُ فِيهَا خَيْرٌ فَسَتَفْعَلْ وَلَا تَضْرِبْ ظَعِينَتَكَ ضَرْبَكَ أَمَتَكَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah menceritakan kepada kami [Isma'il bin Katsir Abu Hasyim Al Maki] dari ['Ashim bin Laqit bin Shabirah] dari [bapaknya, utusan Bani Al Muntafiq] berkata, saya dan salah seorang sahabatku berangkat sampai kami temui Rasulullah Shallallahu'alaihiwasallam, hanya kami tidak mendapati beliau. Lalu 'Aisyah menyuguhi kami dengan kurma dan makanan yang terbuat dari gandum dan lemak. Tiba-tiba Nabi Shallallahu'alaihiwasallam datang dengan mengibAs ngibaskan kakinya namun tidak sampai menyentuh tanah. Lalu beliau bertanya, apakah kalian telah disuguhi sesuatu? Maka kami menjawab, Ya Wahai Rasulullah. Pada saat demikian itu tiba-tiba pengembala kambing mulai berjalan menuju kandang dengan membawa anak unta dengan tangannya. Beliau bertanya, apakah ternaknya telah beranak?. Dia menjawab, Ya. Beliau bersabda: \"Kalau begitu, sembelihlah satu ekor kambing untuk kita, dan tolong bawalah kemari!. Lalu beliau bersabda: \"Janganlah kamu menghitung-hitungnya\" dan tidak berkata, \"Janganlah seseorang menghitung-hitung, kami menyembelih kambing karena kalian berdua, kami memiliki seratus kambing, kami tidak suka jika jumlah itu bertambah\". Adalah kebiasaan beliau jika ada unta yang melahirkan anaknya, maka memerintahkan kami untuk menyembelih kambing. Lalu dia berkata, Wahai Rasulullah, berilah kabar kepadaku tentang wudlu!. Beliau bersabda: \"Jika kalian melakukan wudlu, maka ratakanlah dan silangilah jari-jarinya. Jika kamu memasukkan ke dalam hidungmu maka penuhilah, kecuali jika kau dalam keadaan puasa.\" (Laqit bin Shabirah) berkata, Wahai Rasulullah, saya memiliki istri, lalu dia menyebutkan tentang panjang lidahnya dan gangguannya. Lalu beliau bersabda: \"Ceraikanlah dia.\" (Laqit bin Shabirah) berkata, Wahai Rasulullah, tapi dia sangat pandai bergaul dan sudah punya anak. Lalu beliau bersabda: \"Tahanlah dia, dan perintahkan dia. Jika dia menjadi baik maka terimalah dan jangan kamu pukul istrimu sebagaimana kamu memukul budakmu.\""},"1048":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هِشَامٌ وَيَزِيدُ قَالَ أَخْبَرَنَا هِشَامٌ قَالَ حَدَّثَنِي يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعْنُ الْمُؤْمِنِ كَقَتْلِهِ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ فِي الدُّنْيَا عُذِّبَ بِهِ فِي الْآخِرَةِ وَلَيْسَ عَلَى رَجُلٍ مُسْلِمٍ نَذْرٌ فِيمَا لَا يَمْلِكُ وَمَنْ رَمَى مُؤْمِنًا بِكُفْرٍ فَهُوَ كَقَتْلِهِ وَمَنْ حَلَفَ بِمِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Hisyam] dan [Yazid] berkata, telah mengabarkan kepada kami [Hisyam] berkata, telah menceritakan kepadaku [Yahya] dari [Abu Qilabah] dari [Tsabit bin Dlahhak] Nabi Shallallahu'alaihiwasallam bersabda: \"Melaknat orang mukmin bagaikan membunuhnya, barangsiapa bunuh diri dengan sesuatu di dunia, maka dia akan disiksa di akhirat dengan sesuatu yang digunakannya untuk bunuh diri. Tidak boleh seorang laki-laki muslim bernadzar dengan sesuatu yang tidak dia miliki. Barangsiapa menuduh orang muslim lainnya dengan kata kafir maka bagaikan membunuhnya. Barangsiapa bersumpah dengan agama selain Islam sekalipun dusta, maka dia bagaikan apa yang dia katakan.\""},"1049":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا سُفْيَانُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ بِمِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا مُتَعَمِّدًا فَهُوَ كَمَا قَالَ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Sufyan] dari [Khalid bin Al Hadza`] dari [Abu Qilabah] dari [Tsabit bin Dlahhak Al Anshori] berkata, Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa bersumpah dengan agama selain Islam secara sengaja sekalipun ia dusta, maka ia bagaikan apa yang dikatakannya.\""},"1050":{"ar":"وَقَالَ مَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عَذَّبَهُ اللَّهُ بِهِ فِي نَارِ جَهَنَّمَ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Tsabit bin Adh Dhahhak]; dan beliau bersabda: \"Barangsiapa yang membunuh dirinya dengan sesuatu, niscaya Allah menyiksanya di neraka Jahannam dengan benda yang digunakannya untuk bunuh diri.\""},"1051":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَرْبٌ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنِي أَبُو قِلَابَةَ قَالَ حَدَّثَنِي ثَابِتُ بْنُ الضَّحَّاكِ الْأَنْصَارِيِّ وَكَانَ مِمَّنْ بَايَعَ تَحْتَ الشَّجَرَةِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ بِمِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ وَلَيْسَ عَلَى رَجُلٍ نَذْرٌ فِيمَا لَا يَمْلِكُ","id":"(Ahmad bin Hanbal RH) berkata, telah menceritakan kepada kami [Abdushshamad] telah menceritakan kepada kami [Harb] telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepadaku [Abu Qilabah] berkata, telah menceritakan kepadaku [Tsabit bin Dlahhak Al Anshari] dia adalah termasuk orang yang ikut dalam Peristiwa bai'ah dibawah Pohon, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa bersumpah atas suatu sumpah dengan agama selain Islam secara dusta, maka dia bagaikan apa yang dikatakannya. Dan barangsiapa yang bunuh dirinya dengan sesuatu, dia akan disiksa dengan sesuatu yang dipergunakannya unutk bunuh diri pada hari Hari Kiamat dan tidak boleh ada seorang laki-laki yang bernadzar dengan suatu yang tidak dimilikinya.\""},"1052":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا سُلَيْمَانُ الشَّيْبَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ السَّائِبِ قَالَ سَأَلْتُ عَبْدَ اللَّهِ بْنَ مَعْقِلٍ عَنْ الْمُزَارَعَةِ فَقَالَ حَدَّثَنَا ثَابِتُ بْنُ الضَّحَّاكِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَارَعَةِ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Abdu Wahid bin Zinad] telah menceritakan kepada kami [Sulaiman Asy-Syaibani] telah menceritakan kepada kami [Abdullah bin As Sa`ib] berkata, Aku bertanya [Abdullah bin Ma'qil] tentang Muzaroah (sistem bagi hasil dalam penggarapan tanah, yang pekerjanya mendapatkan sebagian dari hasil panen, pent) maka dia menjawab, telah menceritakan kepada kami [Tsabit bin Dlahhak] Rasulullahi Shallallahu'alaihiwasallam melarang Muzara'ah."},"1053":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى مِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا قَالَ وَلَيْسَ عَلَى رَجُلٍ نَذْرٌ فِيمَا لَا يَمْلِكُ وَمَنْ قَتَلَ نَفْسَ��ُ بِشَيْءٍ فِي الدُّنْيَا عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Aban] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Qilabah] dari [Tsabit bin Dlahhak Al Anshari] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa bersumpah dengan agama selain Islam secara dusta maka dia seperti yang dikatakannya. Tidak boleh ada seorang laki-laki yang bernadzar dengan yang tidak dia miliki. Barangsiapa yang bunuh dirinya dengan sesuatu di dunia, dia akan disiksa dengan sesuatu yang dipergunakannya untuk bunuh diri pada hari Hari Kiamat.\""},"1054":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ وَكَانَ مِنْ أَصْحَابِ الشَّجَرَةِ ثُمَّ قَالَ بَعْدُ أَوْ عَنْ رَجُلٍ عَنْ ثَابِتِ بْنِ الضَّحَّاكِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ حَلَفَ بِمِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا مُتَعَمِّدًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ أَوْ ذَبَحَ ذَبَحَهُ اللَّهُ بِهِ فِي نَارِ جَهَنَّمَ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Khalid] [Abu Qilabah] dari [Tsabit bin Dlahhak] dia adalah salah satu dari orang yang ikut dalam Peristiwa baiat dibawah Pohon, selanjutnya ia berkata, atau dari [seseorang] dari [Tsabit bin Dlahhak] dari Nabi Shallallahu'alaihiwasallam beliau bersabda: \"Barangsiapa bersumpah dengan agama selain Islam secara dusta dengan sengaja maka dia seperti yang dikatakannya. Barangsiapa yang bunuh diri dengan sesuatu atau menyembelih dirinya, niscaya Allah akan menyembelihnya dengan sesuatu yang dipergunakannya untuk menyembelih dirinya di Neraka Jahannam.\""},"1055":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِرَفَعَ الْحَدِيثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عُذِّبَ بِهِ وَمَنْ شَهِدَ عَلَى مُسْلِمٍ أَوْ قَالَ مُؤْمِنٍ بِكُفْرٍ فَهُوَ كَقَتْلِهِ وَمَنْ لَعَنَهُ فَهُوَ كَقَتْلِهِ وَمَنْ حَلَفَ عَلَى مِلَّةٍ غَيْرِ الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا حَلَفَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Abu Qilabah] dari [Tsabit bin Dlahhak] dia memarfukkan hadis sampai pada Nabi Shallallahu'alaihiwasallam, bersabda: \"Barangsiapa bunuh diri dengan sesuatu, dia akan disiksa dengan sesuatu yang dipergunakannya untuk bunuh diri. Barangsiapa yang bersaksi atas seorang muslim atau mukmin dengan kekufuran maka itu seperti membunuhnya. Barangsiapa yang melaknatnya maka itu seperti membunuhnya. Barangsiapa yang bersumpah atas agama selain Islam dalam secara dusta maka dia seperti yang disumpahkan.\""},"1056":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ بِمِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا مُتَعَمِّدًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عَذَّبَهُ اللَّهُ فِي نَارِ جَهَنَّمَ","id":"Telah menceritakan kepada kami ['Ali bin 'Ashim] dari [Khalid] dari [Abu Qilabah] dari [Tsabit bin Dlahhak] berkata, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa bersumpah dengan agama selain Islam secara dusta dengan sengaja maka dia bagaikan apa yang dikatakannya. Barangsiapa bunuh diri dengan sesuatu niscaya Allah akan menyiksanya di Neraka Jahannam.\""},"1057":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ بُسْرِ بْنِ مِحْجَنٍ عَنْ أَبِيهِ وَعَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ بُسْرِ بْنِ مِحْجَنٍ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُقِيمَتْ الصَّلَاةُ فَجَلَسْتُ فَلَمَّا صَلَّى قَالَ لِي أَلَسْتَ بِمُسْلِمٍ قُلْتُ بَلَى قَالَ فَمَا مَنَعَكَ أَنْ تُصَلِّيَ مَعَ النَّاسِ قَالَ قُلْتُ صَلَّيْتُ فِي أَهْلِي قَالَ فَصَلِّ مَعَ النَّاسِ وَلَوْ كُنْتَ قَدْ صَلَّيْتَ فِي أَهْلِكَقَالَ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ بُسْرِ بْنِ مِحْجَنٍ الدِّيلِيِّ عَنْ أَبِيهِ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ صَلَّيْتُ فِي أَهْلِي فَأُقِيمَتْ الصَّلَاةُ فَذَكَرَ مَعْنَى حَدِيثِ عَبْدِ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Zaid bin Aslam] dari [Busr bin Mihjan] dari [Bapaknya] dan [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari [Busr bin Mihjan] dari [Bapaknya] berkata; Aku mendatangi Nabi Shallallahu'alaihiwasallam ketika shalat sedang didirikan, sehingga aku cuma duduk. Selesai shalat, beliau bersabda kepadaku, \"Bukankah kamu seorang muslim?\" Aku menjawab 'Ya.' Lalu beliau bersabda: \"Apa yang mencegahmu untuk ikut serta shalat bersama orang-orang\", (Mihjan) berkata, saya menjawab, Aku telah shalat bersama dengan kelauargaku. Beliau bersabda: \"Shalatlah bersama orang-orang walaupun kamu telah shalat bersama dengan keluargamu.\" (Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] dari [Busr bin Mihjan Ad-Dilly] dari [bapaknya] berkata, Aku mendatangi Nabi Shallallahu'alaihiwasallam dan saya telah melaksanakan shalat di keluargaku, lalu didirikanlah shalat, maka dia menyebutkan makna hadis Abdurrahman."},"1058":{"ar":"قَالَ قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ رَجُلٍ مِنْ بَنِي الدِّيلِ يُقَالُ لَهُ بُسْرُ بْنُ مِحْجَنٍ عَنْ أَبِيهِ مِحْجَنٍأَنَّهُ كَانَ فِي مَجْلِسٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُذِّنَ بِالصَّلَاةِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى ثُمَّ رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمِحْجَنٌ فِي مَجْلِسِهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَنَعَكَ أَنْ تُصَلِّيَ مَعَ النَّاسِ أَلَسْتَ بِرَجُلٍ مُسْلِمٍ قَالَ بَلَى يَا رَسُولَ اللَّهِ وَلَكِنِّي كُنْتُ قَدْ صَلَّيْتُ فِي أَهْلِي فَقَالَ لَهُ إِذَا جِئْتَ فَصَلِّ مَعَ النَّاسِ وَإِنْ كُنْتَ قَدْ صَلَّيْتَ","id":"(Abdullah bin Ahmad bin Hanbal) berkata, (Ahmad bin Hanbal) berkata, saya telah membaca pada [Abdurrahman]: [Malik] dari [Zaid bin Aslam] dari seorang laki-laki dari Bani Ad-Dil yang bernama [Busr bin Mihjan Ad-Dilly] dari [bapaknya, Mihjan] bahwa dia berada pada suatu majlis bersama Rasulullahi Shallallahu'alaihiwasallam lalu dikumandangkan adzan untuk shalat. Rasulullah Shallallahu'alaihiwasallam bangkit lalu melaksanakan shalat. Lalu Rasulullah Shallallahu'alaihiwasallam kembali dan Mihjan masih dalam duduknya. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya 'Apa yang menghalangimu untuk shalat bersama orang-orang?. Bukankah kamu adalah seorang muslim?. Dia menjawab, ya Wahai Rasulullah, tapi saya telah shalat dalam keluargaku. Lalu beliau bersabda kepadanya 'Jika kamu datang, shalatlah bersama manusia walau kamu telah melaksanakan shalat."},"1059":{"ar":"قَالَ حَدَّثَنَا يُونُسُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ رَجُلٍ مِنْ أَهْلِ الْمَدِينَةِ أَنَّهُصَلَّى خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَهُ يَقْرَأُ فِي صَلَاةِ الْفَجْرِ ق وَالْقُرْآنِ الْمَجِيدِ وَيس وَالْقُرْآنِ الْحَكِيمِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Abu 'Awanah] dari [Simak bin Harb] dari [seorang laki-laki penduduk Madinah] dia shalat di belakang Nabi Shallallahu'alaihiwasallam lalu dia mendengar beliau membaca surat Qof dan surat Yasin dalam shalat fajar."},"1060":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ يُحَدِّثُ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ قَالَ ثَلَاثٌ حَقٌّ عَلَى كُلِّ مُسْلِمٍ الْغُسْلُ يَوْمَ الْجُمُعَةِ وَالسِّوَاكُ وَيَمَسُّ مِنْ طِيبٍ إِنْ وَجَدَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Sa'ad bin Ibrahim] berkata; saya telah mendengar [Muhammad bin Abdurrahman bin Tsauban] menceritakan dari [seorang laki-laki dari Anshar] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam] beliau bersabda: \"Tiga hal yang menjadi kewajiban bagi seorang muslim adalah: Mandi pada Hari Jumat, bersiwak dan memakai wangi-wangian jika ada\""},"1061":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَقٌّ عَلَى كُلِّ مُسْلِمٍ يَغْتَسِلُ يَوْمَ الْجُمُعَةِ يَتَسَوَّكُ وَيَمَسُّ مِنْ طِيبٍ إِنْ كَانَ لِأَهْلِهِ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Sa'ad bin Ibrahim] dari [Muhammad bin Abdurrahman bin Tsauban] dari [seorang laki-laki] dari Anshar, salah seorang sahabat Nabi Shallallahu'alaihiwasallam, dari Nabi Shallallahu'alaihiwasallam bersabda: \"Kewajiban bagi setiap muslim adalah: Mandi pada Hari Jumat, bersiwak dan memakai wangi-wangian jika keluarganya memilikinya\""},"1062":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ حَدَّثَتْنِي أُمُّ كُلْثُومٍ ابْنَةُ عَلِيٍّ قَالَ أَتَيْتُهَا بِصَدَقَةٍ كَانَ أُمِرَ بِهَا قَالَتْ أَحَدُ رَبَائِبِنَا فَإِنَّ مَيْمُونَ أَوْ مِهْرَانَ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَنِي أَنَّهُمَرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ يَا مَيْمُونُ أَوْ يَا مِهْرَانُ إِنَّا أَهْلُ بَيْتٍ نُهِينَا عَنْ الصَّدَقَةِ وَإِنَّ مَوَالِيَنَا مِنْ أَنْفُسِنَا وَلَا نَأْكُلُ الصَّدَقَةَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Sufyan] dari ['Atha` bin As-Sa`ib] berkata; telah menceritakan kepadaku [Umu Kultsum, anak perempuan 'Ali] berkata; saya memberinya sedekah yang telah disuruh kepadanya. Salah satu anak tiri berkata; [Maimun] atau Mihran budak Nabi Shallallahu'alaihiwasallam mengabariku dia melewati Nabi Shallallahu'alaihiwasallam lalu beliau bersabda kepadanya, Wahai Maimun atau Mihran, kami sebagai Ahli Bait, kami dilarang mengambil sedekah, dan orang-orang yang menjadi budak kami juga termasuk bagian dari kami. Kami tidak makan harta sedekah."},"1063":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ عَبْدِ اللَّهِ بْنِ أَرْقَمَ أَنَّهُخَرَجَ مِنْ مَكَّةَ وَكَانَ يَؤُمُّهُمْ وَيُؤَذِّنُ وَيُقِيمُ فَأَقَامَ يَوْمًا الصَّلَاةَ فَقَالَ لِيُصَلِّ بِكُمْ رَجُلٌ مِنْكُمْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَرَادَ أَحَدُكُمْ أَنْ يَذْهَبَ إِلَى الْخَلَاءِ وَأُقِيمَتْ الصَّلَاةُ فَلْيَذْهَبْ إِلَى الْخَلَاءِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] berkata; telah menceritakan kepadaku [bapakku] dari [Abdullah bin Arqam] dia keluar dengannya dari Makkah. Dia mengimami mereka, mengumandangkan adzan dan beriqamah. Pada suatu hari didirikan shalat, lalu dia berkata; hendaklah di antara kalian ada yang menjadi imam dalam shalat kalian, saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian hendak pergi ke kamar kecil dan didirikan shalat, dahulukanlah ke kamar kecil."},"1064":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَقْرَمَ قَالَ حَدَّثَنِي ��َبِي أَنَّهُكَانَ مَعَ أَبِيهِ بِالْقَاعِ مِنْ نَمِرَةَ فَمَرَّ بِنَا رَكْبٌ فَقَالَ أَبِي يَا بُنَيَّ كُنْ فِي بَهْمِكَ حَتَّى آتِيَ هَؤُلَاءِ الْقَوْمَ فَأُسَائِلَهُمْ فَدَنَا وَدَنَوْتُ فَكُنْتُ أَنْظُرُ إِلَى عُفْرَتَيْ إِبْطَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ سَاجِدٌ","id":"Telah menceritakan kepada kami [Abdurrahman bin mahdi] berkata; telah menceritakan kepada kami [Daud bin Qais] dari ['Ubaidullah bin Abdullah bin Aqram] berkata; telah menceritakan kepadaku [bapakku] dia dulu bersama bapaknya di Qa' dari Namirah, maka lewatlah rombongan musafir. Bapakku berkata; Wahai anakku, tetaplah bersama dengan binatang ternakmu sampai aku mendatangi mereka dan menanyakan kepada mereka. Lalu bapakku mendekat, begitu juga denganku, lalu saya melihat putih ketiak Rasulullah Shallallahu'alaihiwasallam ketika beliau bersujud."},"1065":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَقْرَمَ الْخُزَاعِيِّ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ أَبِي أَقْرَمَ بِالْقَاعِ قَالَ فَمَرَّ بِنَا رَكْبٌ فَأَنَاخُوا بِنَاحِيَةِ الطَّرِيقِ فَقَالَ لِي أَبِي أَيْ بُنَيَّ كُنْ فِي بَهْمِكَ حَتَّى آتِيَ هَؤُلَاءِ الْقَوْمَ وَأُسَائِلَهُمْ قَالَ فَخَرَجَ وَخَرَجْتُ فِي أَثَرِهِ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَحَضَرَتْ الصَّلَاةُ فَصَلَّيْتُ مَعَهُ فَكُنْتُ أَنْظُرُ إِلَى عُفْرَتَيْ إِبْطَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّمَا سَجَدَ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Daud bin Qais] dari ['Ubaidullah bin Abdullah bin Aqram Al Khuza'i] dari [Bapaknya] berkata; saya bersama Abu Al Aqra' di Qa'. (Abdullah bin Aqram Al Khuza'i Radliyallahu'anhu) berkata; lalu lewatlah rombongan yang berkendaraan lalu mereka menepi ke samping jalan. Lalu bapakku berkata kepadaku, 'Wahai anakku, tetaplah bersama dengan binatang ternakmu sampai aku mendatangi mereka dan menanyakan kepada mereka.' Lalu bapakku keluar, dan saya juga mengikutinya, ternyata ada Rasulullah Shallallahu'alaihiwasallam. lalu datanglah waktu shalat, lalu saya shalat bersama beliau, lalu saya melihat kedua ketiak putih Rasulullah Shallallahu'alaihiwasallam setiap beliau bersujud."},"1066":{"ar":"قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا دَاوُدُ يَعْنِي ابْنَ قَيْسٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أَقْرَمَ الْخُزَاعِيُّ قَالَ حَدَّثَنِي أَبِيأَنَّهُ كَانَ مَعَ أَبِيهِ بِالْقَاعِ مِنْ نَمِرَةَ قَالَ فَمَرَّ بِنَا رَكْبٌ فَأَنَاخُوا بِنَاحِيَةِ الطَّرِيقِ فَقَالَ أَبِي أَيْ بُنَيَّ كُنْ فِي بَهْمِكَ حَتَّى آتِيَ هَؤُلَاءِ الرَّكْبَ فَأُسَائِلَهُمْ قَالَ دَنَا مِنْهُمْ وَدَنَوْتُ مِنْهُ وَأُقِيمَتْ الصَّلَاةُ فَإِذَا فِيهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّيْتُ مَعَهُمْ وَكَأَنِّي أَنْظُرُ إِلَى عُفْرَتَيْ إِبْطَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nua'im] telah menceritakan kepada kami [Daud] yaitu Ibnu Qais, berkata; telah menceritakan kepadaku ['Ubaidullah bin Abdullah bin Aqram Al Khuza'i] berkata; telah menceritakan kepadaku [bapakku] dia bersama dengan bapaknya di Al Qa' di Namirah. Lalu lewatlah di hadapan kami rombongan yang berkendaraan dan mereka menepi ke samping jalan. Lalu bapakku berkata; Wahai anakku, tetaplah bersama dengan binatang ternakmu sampai aku mendatangi mereka dan menanyakan kepada mereka. (Abdullah bin Aqram Al Khuza'i Radliyallahu'anhu) berkata; Lalu (bapakku) mendekatinya, dan saya juga mengikutinya, dan didirikan shalat, ternyata di dalamnya ada Rasulullah Shallallahu'alaihiwasallam, lalu saya shalat bersama mereka, seolah-olah saya melihat kedua ketiak putih Rasulullah Shallallahu'alaihiwasallam jika beliau bersujud."},"1067":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي الْهَيْثَمِ الْعَطَّارُ قَالَ سَمِعْتُ يُوسُفَ بْنَ عَبْدِ اللَّهِ بْنِ سَلَامٍ وَقَالَ مَرَّةً سَمِعَهُ مِنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَسَمَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوسُفَ وَمَسَحَ عَلَى رَأْسِي","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Yahya bin Abu Al Haitsam Al 'Athar] berkata; saya telah mendengar dari [Yusuf bin Abdullah Salam] berkata; Rasulullah Shallallahu'alaihiwasallam menamakanku dengan nama Yusuf kemudian beliau mengusap kepalaku."},"1068":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ عَنْ نَضْرِ بْنِ قَيْسٍ قَالَ سَمِعْتُ يُوسُفَ بْنَ عَبْدِ اللَّهِ بْنِ سَلَامٍ يَقُولُسَمَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوسُفَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Mis'ar] dari [Nadlr bin Qais] berkata; saya telah mendengar [Yusuf bin Abdullah bin Salam] berkata; Rasulullah Shallallahu'alaihiwasallam memberiku nama dengan Yusuf."},"1069":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا ابْنُ الْمُنْكَدِرِ قَالَ سَمِعْتُ يُوسُفَ بْنَ عَبْدِ اللَّهِ بْنِ سَلَامٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مِنْ الْأَنْصَارِ وَامْرَأَتِهِ اعْتَمِرَا فِي رَمَضَانَ فَإِنَّ عُمْرَةً فِي رَمَضَانَ لَكُمَا كَحَجَّةٍ وَقَالَ سُفْيَانُ مَرَّةً وَلَمْ يَقُلْ حَدَّثَنِي يَعْنِي ابْنَ الْمُنْكَدِرِ فَإِنَّ عُمْرَةً فِيهِ كَحَجَّةٍ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] berkata; telah menceritakan kepada kami [Ibnu Al Munkadir] berkata; Aku mendengar [Yusuf bin Abdullah bin Salam] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda kepada seorang laki-laki dan istrinya dari Anshar yang berumrah pada waktu Ramadlan. \"Umrah kalian di Bulan Ramadlan sebagaimana kalian melaksanakan haji\" Sufyan berkata; dia tidak berkata; telah menceritakan kepadaku yaitu Ibnu Al Munkadir, Umrah di bulan itu sebagaimana Haji."},"1070":{"ar":"قَالَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي الْهَيْثَمِ قَالَ سَمِعْتُ يُوسُفَ بْنَ عَبْدِ اللَّهِ بْنِ سَلَامٍ يَقُولُأَجْلَسَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجْرِهِ وَمَسَحَ عَلَى رَأْسِي وَسَمَّانِي يُوسُفَقَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا سَلَّامُ بْنُ عَبْدِ اللَّهِ بْنِ مِسْكِينٍ قَالَ حَدَّثَنَا شَهْرُ بْنُ حَوْشَبٍ عَنْ مُحَمَّدِ بْنِ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ وَذَكَرَ الْحَدِيثَ الْمَارَّ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Yahya bin Abu Al Haitsam] berkata; saya telah mendengar [Yusuf bin Abdullah bin Salam] berkata; Rasulullah Shallallahu'alaihiwasallam mendudukkanku dalam kamarnya, beliau membasuh kepalaku dan memberiku namaku dengan Yusuf. (Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Salam bin Abdullah bin Miskin] berkata; telah menceritakan kepada kami [Syahr bin Husyab] dari [Muhammad bin Yusuf bin Abdullah bin Salam] lalu menyebutkan hadis tentang orang yang lewat."},"1071":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ يَعْنِي ابْنَ عُبَيْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي حَجَّةِ الْوَدَاعِ أَرِقَّاءَكُمْ أَرِقَّاءَكُمْ أَرِقَّاءَكُمْ أَطْعِمُوهُمْ مِمَّا تَأْكُلُونَ وَاكْسُوهُمْ مِمَّا تَلْبَسُونَ فَإِنْ جَاءُوا بِذَنْبٍ لَا تُرِيدُونَ أَنْ تَغْفِرُوهُ فَبِيعُوا عِبَادَ اللَّهِ وَلَا تُعَذِّبُوهُمْ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrahman] berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashim] yaitu Ibnu 'Ubaidullah, dari [Abdurrahman bin Yazid] dari [bapaknya] Rasulullah Shallallahu'alaihiwasallam berkata pada waktu Haji Wada', \"Budak kalian, budak kalian, budak kalian…berilah mereka makan sebagaimana makanan yang kalian makan, dan berilah mereka pakaian sebagaimana pakaian yang kalian pakai, jika mereka melakukan kesalahan yang kalian tidak berkeinginan untuk memaafkan mereka, maka juallah mereka, wahai hamba Allah dan janganlah kalian menyiksa mereka.\""},"1072":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ الْمَخْزُومِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْلَفَ مِنْهُ حِينَ غَزَا حُنَيْنًا ثَلَاثِينَ أَوْ أَرْبَعِينَ أَلْفًا فَلَمَّا انْصَرَفَ قَضَاهَا إِيَّاهُ ثُمَّ قَالَ بَارَكَ اللَّهُ لَكَ فِي أَهْلِكَ وَمَالِكَ إِنَّمَا جَزَاءُ السَّلَفِ الْوَفَاءُ وَالْحَمْدُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Isma'il bin Ibrahim bin Abdullah bin Abu Rabi'ah Al Makhzumi] dari [Bapaknya] dari [kakeknya] Nabi Shallallahu'alaihiwasallam meminjam uang kepadanya pada waktu Perang Hunain sebanyak tiga puluh atau empat puluh ribu, ketika selesai perang, beliau melunasi hutangnya dan berdoa, \"BARAKALLAHU LAKA FII AHLIIKA WA MALIKA WA INNAMA JAZAAUS SALAF AL WAFA' WAL HAMDU (Semoga Allah memberimu berkah untuk keluargamu dan hartamu dan balasan dari hutang adalah melunasi dan pujian).\""},"1073":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ بَنِي أَسَدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ وَلَهُ أُوقِيَّةٌ أَوْ عَدْلُهَا فَقَدْ سَأَلَ إِلْحَافًا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [seorang laki-laki Bani Asad] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa minta sedangkan dia mempunyai uang sebanyak satu Uqiyah (empat puluh Dirham dari perak) maka dia bagaikan orang yang sering minta-minta.\""},"1074":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْضَلُ الْكَلَامِ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [sebagian sahabat Nabi] Shallallahu'alaihiwasallam bersabda: \"Sebaik-baik perkataan adalah SUBHANALLAH WAL HAMDULILAH LA ILAHA ILLALLAHU ALLAHU AKBAR, (Maha Suci Allah, Segala puji bagi Allah, Tidak ada ilah selain Allah dan Allah maha besar) \""},"1075":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ وَقَالَ غُنْدَرٌ عَبْدُ رَبِّهِ بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ قَالَ أَخْبَرَنِي مَنْرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ أَحْجَارِ الزَّيْتِ يَدْعُو بِكَفَّيْهِقَالَ حَجَّاجٌ وَرَفَعَ شُعْبَةُ كَفَّيْهِ وَبَسَطَهُمَا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Sufyan] dan [Hajjaj] berkata; telah mengabarkan kepada kami [Syu'bah] dari [Abdu Rabbihi bin Sa'id] dan [Ghundar] berkata; [Abdu Rabbihi bin Sa'id] dari [Muhammad bin Ibrahim] berkata; telah mengabarkan kepadaku, [orang yang melihat] Nabi Shallallahu'alaihiwasallam di sisi Batu Zaitun berdoa dengan kedua telapak tangannya. [Hajjaj] berkata; lalu Syu'bah mengangkat telapak tangannya dan membentangkannya."},"1076":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَتِيكٍ أَحَدِ بَنِي سَلِمَةَ عَنْ أَبِيهِ عَبْدِ اللَّهِ بْنِ عَتِيكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ خَرَجَ مِنْ بَيْ��ِهِ مُجَاهِدًا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ ثُمَّ قَالَ بِأَصَابِعِهِ هَؤُلَاءِ الثَّلَاثِ الْوُسْطَى وَالسَّبَّابَةِ وَالْإِبْهَامِ فَجَمَعَهُنَّ وَقَالَ وَأَيْنَ الْمُجَاهِدُونَ فَخَرَّ عَنْ دَابَّتِهِ فَمَاتَ فَقَدْ وَقَعَ أَجْرُهُ عَلَى اللَّهِ تَعَالَى أَوْ لَدَغَتْهُ دَابَّةٌ فَمَاتَ فَقَدْ وَقَعَ أَجْرُهُ عَلَى اللَّهِ أَوْ مَاتَ حَتْفَ أَنْفِهِ فَقَدْ وَقَعَ أَجْرُهُ عَلَى اللَّهِ عَزَّ وَجَلَّ وَاللَّهِ إِنَّهَا لَكَلِمَةٌ مَا سَمِعْتُهَا مِنْ أَحَدٍ مِنْ الْعَرَبِ قَبْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَاتَ فَقَدْ وَقَعَ أَجْرُهُ عَلَى اللَّهِ تَعَالَى وَمَنْ مَاتَ قَعْصًا فَقَدْ اسْتَوْجَبَ الْمَآبَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim bin Al Harits] dari [Muhammad bin Abdullah bin 'Atik] yaitu dari Bani Salamah, dari [Bapaknya, Abdullah bin 'Atik] berkata; Aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa siapa yang keluar dari rumahnya dalam keadaan berjihad di jalan Allah Azzawajalla\" kemudian beliau bersabda dengan tiga jarinya, jari tunjuk, tengah dan jempolnya lalu menggabungkan ketiganya. Lalu beliau bersabda: \"Di mana saja orang yang berjihad, lalu terjatuh dari kendaraannya lalu dia meninggal, sungguh pahalanya telah tetap di sisi Allah Ta'ala, atau dia disengat oleh tunggangannya lalu dia meninggal maka Allahlah akan memberinya pahala, atau jika dia meninggal di atas tempat tidurnya maka dia mendapatkan pahala dari Allah Azzawajalla. Demi Allah, itu adalah kalimat yang saya tidak pernah mendengarnya dari seluruh orang Arab sebelum Rasulullah Shallallahu'alaihiwasallam, maka pahalanya telah tetap dari Allah Ta'ala. Barangsiapa yang meninggal dengan tiba-tiba maka wajib baginya mendapatkan tempat kembali yang bagus.\""},"1077":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ عَلِيِّ بْنِ بِلَالٍ عَنْ نَاسٍ مِنْ الْأَنْصَارِ قَالُواكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَغْرِبَ ثُمَّ نَنْصَرِفُ فَنَتَرَامَى حَتَّى نَأْتِيَ دِيَارَنَا فَمَا يَخْفَى عَلَيْنَا مَوَاقِعُ سِهَامِنَا","id":"Telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari ['Ali bin Bilal] dari [orang-orang Anshar] mereka berkata; kami shalat maghrib bersama Rasulullah Shallallahu'alaihiwasallam kemudian kami bubar. Lalu kami saling melempar anak panah hingga tiba ke rumah kami dan dengan tempat anak panah itu kami masih bisa melihatnya."},"1078":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا أَبُو بِشْرٍ عَنْ عَلِيِّ بْنِ بِلَالٍ اللَّيْثِيِّ قَالَصَلَّيْتُ مَعَ نَفَرٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثُونِي أَنَّهُمْ كَانُوا يُصَلُّونَ الْمَغْرِبَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَنْطَلِقُونَ يَتَرَامَوْنَ لَا يَخْفَى عَلَيْهِمْ مَوَاقِعُ سِهَامِهِمْ حَتَّى يَأْتُونَ دِيَارَهُمْ فِي أَقْصَى الْمَدِينَةِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Abu 'Awanah] berkata; telah menceritakan kepada kami [Abu Bisyr] dari ['Ali bin Bilal Al Laits] berkata; saya shalat bersama [beberapa sahabat] Rasulullah Shallallahu'alaihiwasallam lalu mereka menceritakan kepadaku, mereka shalat Maghrib bersama Rasulullah Shallallahu'alaihiwasallam lalu mereka pulang dan saling memanah. Tempat anak panah tersebut masih terlihat sampai mereka di rumah-rumah mereka di ujung Madinah."},"1079":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيْدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ رِجَالٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْرَكَهُمْ يَذْكُرُونَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ ظَهَرَ عَلَى خَيْبَرَ وَصَارَتْ خَيْبَرُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمِينَ ضَعُفُوا عَنْ عَمَلِهَا فَدَفَعُوهَا إِلَى الْيَهُودِ يَقُومُونَ عَلَيْهَا وَيُنْفِقُونَ عَلَيْهَا عَلَى أَنَّ لَهُمْ نِصْفَ مَا يَخْرُجُ مِنْهَا فَقَسَمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سِتَّةٍ وَثَلَاثِينَ سَهْمًا جَمَعَ كُلُّ سَهْمٍ مِائَةَ سَهْمٍ فَجَعَلَ نِصْفَ ذَلِكَ كُلِّهِ لِلْمُسْلِمِينَ وَكَانَ فِي ذَلِكَ النِّصْفِ سِهَامُ الْمُسْلِمِينَ وَسَهْمُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهَا وَجَعَلَ النِّصْفَ الْآخَرَ لِمَنْ يَنْزِلُ بِهِ مِنْ الْوُفُودِ وَالْأُمُورِ وَنَوَائِبِ النَّاسِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [beberapa sahabat Nabi Shallallahu'alaihiwasallam], yang beliau mengenal mereka, mereka menyebutkan Rasulullah Shallallahu'alaihiwasallam ketika mengalahkan Khaibar dan Khaibar menjadi milik beliau dan kaum muslimin, mereka tidak mampu menggarapnya lalu mereka menyerahkan kepada orang Yahudi, yang akan mengarapnya. Dan (orang-orang muslim) menginfakkan kepada mereka dengan cara mereka akan mendapatkan setengah hasil panennya, lalu Rasulullah Shallallahu'alaihiwasallam membaginya menjadi tiga puluh enam bagian. Dan setiap bagian dibagi lagi menjadi seratus bagian, setengahnya untuk kaum muslimin. Bagian untuk kaum muslimin adalah setengah dari itu dan jatah untuk Rasulullah Shallallahu'alaihiwasallam digarap oleh orang Yahudi. Setengah yang lainnya diberikan kepada orang yang tinggal dari para utusan dan para wakil serta para tamu dari masyarakat."},"1080":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ أَرْطَاةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ حَفِظْنَا عَنْ ثَلَاثِينَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ قَالَ مَنْ أَعْتَقَ شِقْصًا لَهُ فِي مَمْلُوكٍ ضَمِنَ بَقِيَّتَهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah menceritakan kepada kami [Hajjaj bin Arthah] dari ['Amr bin Syua'ib] dari [Sa'id bin Musayyab] berkata; kami telah menghafal dari [tiga puluh sahabat Nabi Shallallahu'alaihiwasallam] beliau bersabda: \"Barangsiapa yang membebaskan bagiannya dari hamba sahaya yang dimiliki secara kolektif maka dia harus menjamin bagian yang tersisa.\""},"1081":{"ar":"قَالَ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ الْمُلَائِيُّ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي فَرْوَةَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ سَلَمَةَ بْنِ صَخْرٍ الزُّرَقِيِّ قَالَتَظَاهَرْتُ مِنْ امْرَأَتِي ثُمَّ وَقَعْتُ بِهَا قَبْلَ أَنْ أُكَفِّرَ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَفْتَانِي بِالْكَفَّارَةِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdussalam bin Harb Al Mula`i] dari [Ishaq bin Abdullah bin Abu Farwah] dari [Bukair bin Abdullah bin Al Asyaj] dari [Sulaiman bin Yasar] dari [Salamah bin Shakhr Az Zuraqy] berkata; Aku mendzihar (mengatakan isteri seperti ibu kandung sang suami) dari istriku, kemudian aku mencampurinya sebelum aku menebus kaffarah (denda). Lalu saya bertanya kepada Nabi Shallallahu'alaihiwasallam, lalu beliau memberiku fatwa untuk membayar kaffarahnya."},"1082":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ سَلَمَةَ بْنِ صَخْرٍ الزُّرَقِيِّ قَالَتَظَاهَرْتُ مِنْ امْرَأَتِي ثُمَّ وَقَعْتُ بِهَا قَبْلَ أَنْ أُكَفِّرَ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَفْتَانِي بِالْكَفَّارَةِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin 'Amr bin 'Atha`] dari [Sulaiman bin Yasar] dari [Salamah bin Shakhr Az Zuraqy] berkata; Aku mendzihar (mengatakan isteri seperti ibu kandung sang suami) pada istriku kemudian aku mencampurinya sebelum aku menebus, Lalu saya bertanya kepada Nabi Shallallahu'alaihiwasallam, lalu beliau memberiku fatwa kepadaku untuk membayar kafarahnya."},"1083":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ سَلَمَةَ بْنِ صَخْرٍ الْأَنْصَارِيِّ قَالَكُنْتُ امْرَأً قَدْ أُوتِيتُ مِنْ جِمَاعِ النِّسَاءِ مَا لَمْ يُؤْتَ غَيْرِي فَلَمَّا دَخَلَ رَمَضَانُ تَظَاهَرْتُ مِنْ امْرَأَتِي حَتَّى يَنْسَلِخَ رَمَضَانُ فَرَقًا مِنْ أَنْ أُصِيبَ فِي لَيْلَتِي شَيْئًا فَأَتَتَابَعُ فِي ذَلِكَ إِلَى أَنْ يُدْرِكَنِي النَّهَارُ وَأَنَا لَا أَقْدِرُ عَلَى أَنْ أَنْزِعَ فَبَيْنَا هِيَ تَخْدُمُنِي إِذْ تَكَشَّفَ لِي مِنْهَا شَيْءٌ فَوَثَبْتُ عَلَيْهَا فَلَمَّا أَصْبَحْتُ غَدَوْتُ عَلَى قَوْمِي فَأَخْبَرْتُهُمْ خَبَرِي وَقُلْتُ لَهُمْ انْطَلِقُوا مَعِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُخْبِرُهُ بِأَمْرِي فَقَالُوا لَا وَاللَّهِ لَا نَفْعَلُ نَتَخَوَّفُ أَنْ يَنْزِلَ فِينَا قُرْآنٌ أَوْ يَقُولَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَالَةً يَبْقَى عَلَيْنَا عَارُهَا وَلَكِنْ اذْهَبْ أَنْتَ فَاصْنَعْ مَا بَدَا لَكَ قَالَ فَخَرَجْتُ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ خَبَرِي فَقَالَ لِي أَنْتَ بِذَاكَ فَقُلْتُ أَنَا بِذَاكَ فَقَالَ أَنْتَ بِذَاكَ فَقُلْتُ أَنَا بِذَاكَ قَالَ أَنْتَ بِذَاكَ قُلْتُ نَعَمْ هَا أَنَا ذَا فَأَمْضِ فِيَّ حُكْمَ اللَّهِ عَزَّ وَجَلَّ فَإِنِّي صَابِرٌ لَهُ قَالَ أَعْتِقْ رَقَبَةً قَالَ فَضَرَبْتُ صَفْحَةَ رَقَبَتِي بِيَدِي وَقُلْتُ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَصْبَحْتُ أَمْلِكُ غَيْرَهَا قَالَ فَصُمْ شَهْرَيْنِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ وَهَلْ أَصَابَنِي مَا أَصَابَنِي إِلَّا فِي الصِّيَامِ قَالَ فَتَصَدَّقْ قَالَ فَقُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ بِتْنَا لَيْلَتَنَا هَذِهِ وَحْشَاءَ مَا لَنَا عَشَاءٌ قَالَ اذْهَبْ إِلَى صَاحِبِ صَدَقَةِ بَنِي زُرَيْقٍ فَقُلْ لَهُ فَلْيَدْفَعْهَا إِلَيْكَ فَأَطْعِمْ عَنْكَ مِنْهَا وَسْقًا مِنْ تَمْرٍ سِتِّينَ مِسْكِينًا ثُمَّ اسْتَعِنْ بِسَائِرِهِ عَلَيْكِ وَعَلَى عِيَالِكَ قَالَ فَرَجَعْتُ إِلَى قَوْمِي فَقُلْتُ وَجَدْتُ عِنْدَكُمْ الضِّيقَ وَسُوءَ الرَّأْيِ وَوَجَدْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّعَةَ وَالْبَرَكَةَ قَدْ أَمَرَ لِي بِصَدَقَتِكُمْ فَادْفَعُوهَا لِي قَالَ فَدَفَعُوهَا إِلَيَّ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin 'Amr bin 'Atha`] dari [Sulaiman bin Yasar] dari [Salamah bin Shakhr Al Anshari] berkata; aku adalah seseorang yang hasrat seksual yang besar untuk mengumpuli wanita yang tidak sebagaimana lazimnya orang-orang.Tatkala masuk Ramadlan, saya menzhihar (mengatakan isteri seperti ibu kandung sang suami) istriku sampai bulan Ramadlan selesai. Aku zhihar isteriku sampai selesai Ramadhan dengan pertimbangan saya khawatir jangan-jangan pada suatu malam saya akan mengumpuli istriku. Saya bisa menahan nafsuku secara berturut-turut hingga suatu siang saya tidak mampu lagi menahan nafsuku. Ketika isteriku melayaniku, tiba-tiba sebagian tubuhnya yang gemulai tersingkap hingga aku melihatnya. Pada pagi harinya, saya menemui kaumku, saya kabarkan kepada mereka perihal kasusku. Saya katakan kepada mereka 'Maaf ya, tolong kalian berangkat bersamaku untuk menemui Nabi Shallallahu'alaihiwasallam, dengan tujuan saya akan memberitahukan kepada beliau tentang kasus rahasiaku.' Mereka berkata; 'Maaf, kami nggak bisa, demi Allah, kami tak mau melakukannya, kami khawatir jangan-jangan akan turun ayat Al qur'an yang mengekspos keadaan kami, atau jangan-jangan Rasulullah Shallallahu'alaihiwasallam berkomentar suatu hal tentang kami sehingga borok kami akan abadi. Sana pergilah kamu sendiri, dan lakukanlah yang menurutmu ideal!. (Salamah bin Shakhr Al Anshari Radliyallahu'anhu) berkata; saya pun pergi dan menemui Nabi Shallallahu'alaihiwasallam, saya laporkan kepada beliau tentang kasusku. Lalu beliau bersabda kepadaku 'Kamu telah melakukan hal itu?. saya jawab 'Cenar, saya melakukannya.' Beliau bertanya lagi, \"Apakah benar kamu telah melakukan hal itu?\", saya jawab 'Benar, saya betul-betul telah melakukan hal itu.' Beliau bertanya lagi 'Apakah kau betul-betul melakukan hal itu?, saya jawab 'Iya, saya benar-benar telah melakukannya, tolong perlakukan hukum Allah Azzawajalla atas diriku, saya akan bersabar menerimanya.' Beliau bersabda: \"Bebaskanlah satu budak!\" (Salamah bin Shakhr Al Anshari Radliyallahu'anhu) berkata 'Lalu saya memukul samping pundak budakku dengan tanganku dan saya katakan, demi yang telah mengutus anda dengan kebenaran, Maaf yang ini saya tidak bisa melakukannya, karena saya tidak memiliki selainnya.' Beliau bersabda: \"okelah, kalau begitu berpuasalah selama dua bulan\". (Salamah bin Shakhr Al Anshari Radliyallahu'anhu) berkata; saya berkata 'Wahai Rasulullah, bukankah saya bisa kuat menanggung sekian banyak hukuman selain puasa? ' Rasulullah bersabda: \"Kalau begitu, bayarlah sedekah.\" (Salamah bin Shakhr Al Anshari Radliyallahu'anhu) berkata; saya berkata; 'Demi yang mengutus anda dengan kebenaran, kami bermalam pada malam itu dalam keadaan lapar yang sangat karena kami tidak memiliki makan malam.' Beliau bersabda: \"Okelah, kalau begitu pergilah kamu ke orang yang biasa bersedekah dari Bani Zuraiq, dan katakan kepadanya agar dia memberi kurmanya untukmu, dan berilah makan enam puluh orang miskin dengan satu wasaq kurmamu, dan sisanya silahkan kau pergunakan untuk makan dan juga untuk keluarga yang menjadi tanggunganmu.\" (Salamah bin Shakhr Al Anshari Radliyallahu'anhu) berkata; lalu saya pulang ke kaumku dan berujar 'Kudapatkan pada kalian kesusahan dan pendapat-pendapat yang sangat jelek, sebaliknya saya dapatkan dari Rasulullah Shallallahu'alaihiwasallam kelonggaran dan barakah, beliau menyuruhku agar kalian memberikan sedekah untukku, maka tolong bayarkanlah untukku (Salamah bin Shakhr Al Anshari Radliyallahu'anhu) berkata; lalu mereka membayarkannya untukku."},"1084":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ قَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِالْأَبْوَاءِ أَوْ بِوَدَّانَ فَأَهْدَيْتُ لَهُ مِنْ لَحْمِ حِمَارِ وَحْشٍ وَهُوَ مُحْرِمٌ فَرَدَّهُ عَلَيَّ فَلَمَّا رَأَى فِي وَجْهِي الْكَرَاهَةَ قَالَ إِنَّهُ لَيْسَ بِنَا رَدٌّ عَلَيْكَ وَلَكِنَّا حُرُمٌ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dengan ['Ubaidullah bin Abdullah] dari [Ibnu 'Abbas] dari [Ash Sha'b bin Jatsamah] berkata; Rasulullah Shallallahu'alaihiwasallam melewatiku, saya waktu itu sedang berada di Abwa`, atau di Wadan, lalu saya hadiahkan daging keledai kepada beliau yang sedang melakukan ihram, dan beliau menolak pemberianku. Tatkala beliau membaca ekspresi ketidaksukaan di wajahku, beliau bersabda: \"Bukannya kami menolak pemberianmu, hanya kami sedang di Tanah Haram.\""},"1085":{"ar":"وَسَمِعْتُهُ يَقُولُ لَا حِمَى إِلَّا لِلَّهِ وَلِرَسُولِهِ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Sho'bi bin Jatstsamah]; dan saya telah mendengarnya bersabda: \"Tidak ada hima (larangan-larangan yang tidak boleh bagi seorang muslim melanggarnya) kecuali hima yang ditetapkan Allah dan Rasul-Nya.\""},"1086":{"ar":"وَسُئِلَ عَنْ أَهْلِ الدَّارِ مِنْ الْمُشْرِكِينَ يُبَيَّتُونَ فَيُصَابُ مِنْ نِسَائِهِمْ وَذَرَارِيِّهِمْ فَقَالَ هُمْ مِنْهُمْ ثُمَّ يَقُولُ الزُّهْرِيُّ ثُمَّ نَهَى عَنْ ذَلِكَ بَعْدُ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Sha'bi bin Jatstsamah]; pernah nabi ditanya tentang perkampungan orang-orang musyrik yang diserang pada malam hari, sehingga serangan tersebut mengenai kaum wanita mereka dan anak-anak mereka. Beliau bersabda: \"Mereka adalah bagian dari orang-orang musyrik itu\". Az Zuhri berkata; Di kemudian hari beliau melarang hal itu."},"1087":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ : مَالِكُ بْنُ أَنَسٍ عَنِ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ اللَّيْثِيِّأَنَّهُ أَهْدَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِالْأَبْوَاءِ أَوْ بِوَدَّانَ حِمَارًا وَحْشِيًّا فَرَدَّهُ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَى مَا فِي وَجْهِي قَالَ إِنَّا لَمْ نَرُدَّ عَلَيْكَ إِلَّا أَنَّا حُرُمٌ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; saya telah membaca di hadapan [Abdurrahman bin Mahdi]: [Malik bin Anas] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu 'Abbas] dari [Ash Sha'b bin Jatsamah Al Laits] dia menghadiahkan daging keledai kepada Rasulullah Shallallahu'alaihiwasallam ketika beliau sedang berada di Abwa`, atau di Wadan,. Lalu Rasulullah Shallallahu'alaihiwasallam menolak pemberianku. Tatkala beliau melihat sesuatu pada wajahku beliau bersabda: \"Kami tidak menolak pemberianmu, hanya karena kami sedang di Tanah Haram.\""},"1088":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لَهُ لَوْ أَنَّ خَيْلًا أَغَارَتْ مِنْ اللَّيْلِ فَأَصَابَتْ مِنْ أَبْنَاءِ الْمُشْرِكِينَ قَالَ هُمْ مِنْ آبَائِهِمْ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku ['Amr bin Dinar] [Ibnu Syihab] mengabarinya, dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu 'Abbas] dari [Ash Sha'b bin Jatsamah] Rasulullah Shallallahu'alaihiwasallam, ditanyakan kepada beliau; Bagaimana seandainya terdapat pasukan berkuda muslimin menyerang musuh pada waktu malam buta sehingga mengenai anak-anak kaum musyrikin?, maka beliau bersabda: \"Mereka itu (anak-anak) termasuk bagian dari bapak-bapaknya.\""},"1089":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا حِمَى إِلَّا لِلَّهِ وَلِرَسُولِهِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abdullah bin Abdullah bin 'Utbah] dari [Ibnu 'Abbas] dari [Ash Sha'b bin Jatsamah] berkata; Aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada hima (larangan-larangan yang tidak boleh bagi seorang muslim melangarnya) kecuali hiuma yang ditetapkan Allah dan Rasul-Nya.\""},"1090":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ قَالَقُلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا نُصِيبُ فِي الْبَيَاتِ مِنْ ذَرَارِيِّ الْمُشْرِكِينَ قَالَ هُمْ مِنْهُمْ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu 'Abbas] dari [Ash Sha'b bin Jatsamah] berkata; saya berkata kepada Rasulullah Shallallahu'alaihiwasallam 'Saat penyerangan malam hari, serangan kami mengenai kaum wanita dan anak-anak kaum musyrikin. beliau bersabda: \"Mereka adalah bagian dari mereka\"."},"1091":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ قَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِالْأَبْوَاءِ فَأَهْدَيْتُ لَهُ حِمَارَ وَحْشٍ فَرَدَّهُ عَلَيَّ فَلَمَّا رَأَى الْكَرَاهِيَةَ فِي وَجْهِي قَالَ إِنَّهُ لَيْسَ بِنَا رَدٌّ عَلَيْكَ وَلَكِنَّا حُرُمٌ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu 'Abbas] dari [Ash Sha'b bin Jatsamah] berkata; Rasulullah Shallallahu'alaihiwasallam melewatiku yang ketika itu saya berada di Abwa`. Lantas saya memberi hadiah beliau berupa daging keledai. Beliau menolak pemberianku. Tatkala beliau melihat ketidaksukaan pada wajahku beliau bersabda: \"Kami bukannya menolak pemberianmu, hanya karena kami sedang di Tanah Haram.\""},"1092":{"ar":"قَالَ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنِ صَعْبِ بْنِ جَثَّامَةَ أَنَّهُ قَالَمَرَّ بِي وَأَنَا بِالْأَبْوَاءِ أَوْ بِوَدَّانَ فَأَهْدَيْتُ لَهُ حِمَارَ وَحْشٍ فَرَدَّهُ عَلَيَّ فَلَمَّا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَرَاهِيَةَ فِي وَجْهِي قَالَ إِنَّهُ لَيْسَ بِنَا رَدٌّ عَلَيْكَ وَلَكِنَّا حُرُمٌقُلْتُ لِابْنِ شِهَابٍ الْحِمَارُ عَقِيرٌ قَالَ لَا أَدْرِي حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ أَنَّهُ أَهْدَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِمَارَ وَحْشٍ وَهُوَ مُحْرِمٌ فَذَكَرَهُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Bakr] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abdullah bin 'Abbas] dari [Ash Sha'b bin Jatsamah] dia berkata; (Rasulullah Shallallahu'alaihiwasallam) melewatiku, saya waktu itu sedang berada di Abwa`, atau di Wadan, lalu saya hadiahkan daging keledai kepada beliau. Beliau menolaknya, tatkala Rasulullah Shallallahu'alaihiwasallam melihat ekspresi kebencian di wajahku beliau bersabda: \"Bukannya kami menolak pemberianmu, hanya kami sedang di Tanah Haram.\" Saya bertanya kepada Ibnu Syihab, apakah keledai itu disembelih?. Dia menjawab, saya tidak tahu. Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Ibnu Abu Dzi`berkata;] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu 'Abbas] dari [Ash Sha'b bin Jatsamah] dia memberi hadiah kepada Rasulullah Shallallahu'alaihiwasallam berupa keledai dalam keadaan ihram, lalu menyebutkan secara lengkap."},"1093":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا مَالِكٌ عَنِ الزُّهْرِيِّ وَعَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَبْدُ الرَّزَّاقِ فِي حَدِيثِهِ فِي الْمَسْجِدِ وَاضِعًا إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَى","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata; telah menceritakan kepada kami [Malik] dari [Az Zuhri] dan [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [pamannya] berkata; Aku melihat Nabi Shallallahu'alaihiwasallam -- [Abdurrazzaq] berkata dalam hadisnya-- Di masjid, meletakkan salah satu kakinya di atas yang lain.\""},"1094":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ : مَالِكُ بْنُ أَنَسٍ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِأَنَّ جَدَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَاصِمٍ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تَسْتَطِيعُ أَنْ تُرِيَنِي كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ قَالَ عَبْدُ اللَّهِ بْنُ زَيْدٍ نَعَمْ فَدَعَا بِوَضُوءٍ فَأَفْرَغَ عَلَى يَدَيْهِ فَغَسَلَ يَدَهُ مَرَّتَيْنِ ثُمَّ تَمَضْمَضَ وَاسْتَنْثَرَ ثَلَاثًا ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَيْهِ مَرَّتَيْنِ إِلَى الْمِرْفَقَيْنِ ثُمَّ مَسَحَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ بَدَأَ بِمُقَدَّمِ رَأْسِهِ ثُمَّ ذَهَبَ بِهِمَا إِلَى قَفَاهُ ثُمَّ رَدَّهُمَا حَتَّى رَجَعَ إِلَى الْمَكَانِ الَّذِي بَدَأَ مِنْهُ ثُمَّ غَسَلَ رِجْلَيْهِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; saya membaca di hadapan [Abdurrahman bin Mahdi]: [Malik bin Anas] dari ['Amr bin Yahya Al Mazinny] dari [bapaknya] berkata kepada [Abdullah bin Zaid bin 'Ashim] dia termasuk salah seorang sahabat Rasulullah Shallallahu'alaihiwasallam, Apakah kamu dapat menunjukkan kepadaku bagaimana Rasulullah Shallallahu'alaihiwasallam berwudlu? Abdullah bin Zaid berkata; Ya. lalu (Abdullah bin Zaid Radliyallahu'anhu) meminta air wudlu dan menuangkannya ke tangan, lalu dia membasuh tangannya sebanyak dua kali, kemudian berkumur dan mengeluarkan air dari hidungnya sebanyak tiga kali, kemudian membasuh wajahnya tiga kali. Lalu mencuci kedua tangannya sampai ke pergelangan tangan tiga kali, lalu mengusap kepalanya dengan kedua tangannya dengan memulainya dari depan hingga ke belakang kepala, kemudian mengembalikan ke posisi pertama ketika memulai lalu beliau membasuh kakinya.\""},"1095":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَيْنَ بَيْتِي وَمِنْبَرِي رَوْضَةٌ مِنْ رِيَاضِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Abu Bakr] dari ['Abbad bin Tamim] dari [pamannya, Abdullah Bin Zaid] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Antara rumahku dan mimbarku terdapat taman dari taman-taman surga.\""},"1096":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْقَى وَحَوَّلَ رِدَاءَهُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrahman] berkata; telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Bakar] dari ['Abbad bin Tamim] dari [pamannya] Nabi Shallallahu'alaihiwasallam meminta hujan dan memindah posisi selendangnya."},"1097":{"ar":"قَالَ قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ عَنِ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ أَنَّهُ سَمِعَ عَبَّادَ بْنَ تَمِيمٍ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ زَيْدٍ الْمَازِنِيَّ يَقُولُخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُصَلَّى فَاسْتَسْقَى وَحَوَّلَ رِدَاءَهُ حِينَ اسْتَقْبَلَ الْقِبْلَةَ","id":"(Abdullah bin Ahmad bin Hanbal Radliyallahu'anhu) berkata; (Ahmad bin Hanbal Radliyallahu'anhu) berkata; saya membaca di hadapan [Abdurrahman]: [Malik] dari [Abdullah bin Abu Bakar] telah mendengar ['Abbad bin Tamim] berkata; saya telah mendengar [Abdullah bin Zaid Al Mazini] berkata; Rasulullah Shallallahu'alaihiwasallam keluar kepada tempat shalat lalu meminta hujan dan merubah posisi selendangnya ketika menghadap kiblat."},"1098":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ يَسْتَسْقِي فَصَلَّى بِهِمْ رَكْعَتَيْنِ وَجَهَرَ بِالْقِرَاءَةِ فِيهَا وَحَوَّلَ رِدَاءَهُ وَدَعَا وَاسْتَقْبَلَ الْقِبْلَةَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [pamannya] berkata; Rasulullah Shallallahu'alaihiwasallam keluar menemui orang-orang untuk meminta hujan, shalat memimpin mereka shalat dua rekaat dengan mengeraskan bacaannya, memindah posisi selendangnya, berdo'a dan menghadap kiblat."},"1099":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ وَبَدَأَ بِمُقَدَّمِ رَأْسِهِ ثُمَّ ذَهَبَ بِهِمَا إِلَى قَفَاهُ ثُمَّ رَدَّهُمَا حَتَّى رَجَعَ إِلَى الْمَكَانِ الَّذِي بَدَأَ مِنْهُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Malik] dari ['Amr bin Yahya] dari [Bapaknya] dari [Abdullah bin Zaid] Nabi Shallallahu'alaihiwasallam mengusap kepalanya dengan kedua tangannya, dari depannya lalu bagian belakangnya, dimulai dari depan kepalanya sampai pada belakangnya dan mengulanginya dari awal lagi."},"1100":{"ar":"قَالَ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ حَبَّانَ بْنِ وَاسِعٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَاصِمٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ يَوْمًا فَمَسَحَ رَأْسَهُ بِمَاءٍ غَيْرِ فَضْلِ يَدَيْهِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Musa bin Daud] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Habban bin Wasi'] dari [Bapaknya] dari [Abdullah bin Yazid bin 'Ashim] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam melakukan wudlu pada suatu hari, beliau mengusap kepalanya dengan air yang bukan sisa dari kedua tangannya."},"1101":{"ar":"قَالَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ زَيْدٍ سَمِعَ عَبَّادَ بْنَ تَمِيمٍ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَجَعَلَ يَقُولُ هَكَذَا يَدْلُكُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Daud Ath-Thayalisi] berkata; telah menceritakan kepada kami [Syu'bah] dari [Habib bin Zaid] telah mendengar ['Abbad bin Tamim] dari [pamannya, Abdullah bin Zaid] Nabi Shallallahu'alaihiwasallam berwudlu dan kemudian berkata; \"Beginilah menggosok.\""},"1102":{"ar":"قَالَ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَفْصَةَ قَالَ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ وَعَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا وُضُوءَ إِلَّا فِيمَا وَجَدْتَ الرِّيحَ أَوْ سَمِعْتَ الصَّوْتَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Rouh bin 'Ubadah] berkata; telah menceritakan kepada kami [Muhammad bin Abu Hafshah] berkata; telah menceritakan kepada kami [Ibnu Syihab] dari [Sa'id bin Musayyab] dan ['Abbad bin Tamim] dari [pamannya] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada wudlu kecuali kamu mendapatkan bau atau mendengar suara.\""},"1103":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا أَبَانُ هُوَ الْعَطَّارُ قَالَ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ ب��نِ زَيْدٍ أَنَّ أَبَاهُ حَدَّثَهُأَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمَنْحَرِ وَرَجُلًا مِنْ قُرَيْشٍ وَهُوَ يَقْسِمُ أَضَاحِيَّ فَلَمْ يُصِبْهُ مِنْهَا شَيْءٌ وَلَا صَاحِبَهُ فَحَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ فِي ثَوْبِهِ فَأَعْطَاهُ فَقَسَمَ مِنْهُ عَلَى رِجَالٍ وَقَلَّمَ أَظْفَارَهُ فَأَعْطَاهُ صَاحِبَهُ قَالَ فَإِنَّهُ لَعِنْدَنَا مَخْضُوبٌ بِالْحِنَّاءِ وَالْكَتَمِ يَعْنِي شَعْرَهُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdushshomad bin Abdul Warits] berkata; telah menceritakan kepada kami [Aban] Al 'Aththar, berkata; telah menceritakan kepada kami [Yahya] yaitu Ibnu Abu Katsir, dari [Abu Salamah] dari [Muhammad bin Abdullah bin Zaid] [bapaknya] menceritakannya, dia melihat Rasulullah Shallallahu'alaihiwasallam di atas tempat penyembelihan dan seorang laki-laki dari Quraisy yang membagikan daging sembelihan sedangkan dia tidak mendapatkan bagian dari daging sembelihan tersebut. Begitu juga orang yang berkurban. Lalu Rasulullah Shallallahu'alaihiwasallam memotong kepala daging hewan sembelihan tersebut dan memberikannya kepada laki-laki Quraisy yang tadi membagi-bagikan daging, lalu beliau juga memotong kuku hewan sembelihan tersebut dan memberikannya kepada orang yang berkurban. lalu beliau bersabda: \"Kami mendapatkan dari bagian hewan kurban itu yang terwarnai oleh pohon pacar yaitu rambutnya.\""},"1104":{"ar":"قَالَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ حَدَّثَنَا أَبَانُ الْعَطَّارُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ أَنَّ مُحَمَّدَ بْنَ عَبْدِ اللَّهِ بْنِ زَيْدٍ أَخْبَرَهُ عَنْ أَبِيهِأَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ الْمَنْحَرِ هُوَ وَرَجُلٌ مِنْ الْأَنْصَارِ فَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحَايَا فَلَمْ يُصِبْهُ وَلَا صَاحِبَهُ شَيْءٌ فَحَلَقَ رَأْسَهُ فِي ثَوْبِهِ فَأَعْطَاهُ وَقَسَمَ مِنْهُ عَلَى رِجَالٍ وَقَلَّمَ أَظْفَارَهُ فَأَعْطَاهُ صَاحِبَهُ فَإِنَّ شَعْرَهُ عِنْدَنَا مَخْضُوبٌ بِالْحِنَّاءِ وَالْكَتَمِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Daud Ath-Thayalisi] berkata; telah menceritakan kepada kami [Aban Al 'Athar] dari [Yahya bin Abu Katsir] [Abu Salamah] menceritakannya, [Muhammad bin Abdullah bin Zaid] mengabarinya dari [Bapaknya] dia menyaksikan Nabi Shallallahu'alaihiwasallam di tempat penyembelihan dan seorang laki-laki dari Anshar. Lalu Rasulullah Shallallahu'alaihiwasallam membagikan daging sembelihan, sedangkan (orang Anshar) tidak mendapatkan bagian juga orang yang berkurban sedikitpun. Lalu (Rasulullah Shallallahu'alaihiwasallam) memotong kepala daging hewan sembelihan tersebut lalu memberikannya kepadanya dan dia membagi-bagikan darinya kepada beberapa orang, lalu beliau juga memotong kuku hewan sembelihan tersebut dan memberikannya kepada orang yang berkurban. Kami mendapatkan dari bagian hewan kurban itu yang terwarnai oleh pohon pacar."},"1105":{"ar":"قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ أَبُو الْحُسَيْنِ الْعُكْلِيُّ قَالَ أَخْبَرَنِي أَبُو سَهْلٍ مُحَمَّدُ بْنُ عَمْرٍو قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ زَيْدٍ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ زَيْدٍ أَنَّهُ أُرِيَ الْأَذَانَ قَالَفَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ أَلْقِهِ عَلَى بِلَالٍ فَأَلْقَيْتُهُ فَأَذَّنَ قَالَ فَأَرَادَ أَنْ يُقِيمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنَا رَأَيْتُ أُرِيدُ أَنْ أُقِيمَ قَالَ فَأَقِمْ أَنْتَ فَأَقَامَ هُوَ وَأَذَّنَ بِلَالٌ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Zaid Al Habhab Abu Al Husain Al 'Ukli] berkata; telah mengabarkan kepadaku [Abu Sahl, Muhammad bin 'Amr] berkata; telah mengabarkan kepadaku [Abdullah bin Muhammad bin Zaid] dari [pamannya. Abdullah bin Zaid] dia diperlihatkan adzan. Lalu (Abdullah bin Zaid Radliyallahu'anhu) berkata; Maka aku datang kepada Rasulullah Shallallahu'alaihiwasallam dan memberitahukan perihal hal tersebut, maka beliau bersabda: \"Beritahukanlah kepada Bilal\" Maka aku memberitahukannya, lalu Bilal pun mengumandangkan adzan. (Abdullah bin Zaid Radliyallahu'anhu) berkata; dia hendak mengumandangkan Iqamah, maka aku bertanya, \"Wahai Rasulullah, aku ingin mengumandangkan iqamah\" maka beliau bersabda: \"Kumandangkanlah iqamah\", dia pun mengumandangkan iqamah dan Bilal mengumandangkan adzan."},"1106":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ أَخْبَرَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ وَذَكَرَ مُحَمَّدُ بْنُ مُسْلِمٍ الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَبْدِ رَبِّهِ قَالَلَمَّا أَجْمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَضْرِبَ بِالنَّاقُوسِ يَجْمَعُ لِلصَّلَاةِ النَّاسَ وَهُوَ لَهُ كَارِهٌ لِمُوَافَقَتِهِ النَّصَارَى طَافَ بِي مِنْ اللَّيْلِ طَائِفٌ وَأَنَا نَائِمٌ رَجُلٌ عَلَيْهِ ثَوْبَانِ أَخْضَرَانِ وَفِي يَدِهِ نَاقُوسٌ يَحْمِلُهُ قَالَ فَقُ��ْتُ لَهُ يَا عَبْدَ اللَّهِ أَتَبِيعُ النَّاقُوسَ قَالَ وَمَا تَصْنَعُ بِهِ قُلْتُ نَدْعُو بِهِ إِلَى الصَّلَاةِ قَالَ أَفَلَا أَدُلُّكَ عَلَى خَيْرٍ مِنْ ذَلِكَ قَالَ فَقُلْتُ بَلَى قَالَ تَقُولُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ قَالَ ثُمَّ اسْتَأْخَرْتُ غَيْرَ بَعِيدٍ قَالَ ثُمَّ تَقُولُ إِذَا أَقَمْتَ الصَّلَاةَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ قَدْ قَامَتْ الصَّلَاةُ قَدْ قَامَتْ الصَّلَاةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ قَالَ فَلَمَّا أَصْبَحْتُ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِمَا رَأَيْتُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذِهِ لَرُؤْيَا حَقٌّ إِنْ شَاءَ اللَّهُ ثُمَّ أَمَرَ بِالتَّأْذِينِ فَكَانَ بِلَالٌ مَوْلَى أَبِي بَكْرٍ يُؤَذِّنُ بِذَلِكَ وَيَدْعُو رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصَّلَاةِ قَالَ فَجَاءَهُ فَدَعَاهُ ذَاتَ غَدَاةٍ إِلَى الْفَجْرِ فَقِيلَ لَهُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَائِمٌ قَالَ فَصَرَخَ بِلَالٌ بِأَعْلَى صَوْتِهِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِقَالَ سَعِيدُ بْنُ الْمُسَيَّبِ فَأُدْخِلَتْ هَذِهِ الْكَلِمَةُ فِي التَّأْذِينِ إِلَى صَلَاةِ الْفَجْرِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Ya'qub] berkata; telah mengabarkan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; [Muhammad bin Muslim Az Zuhri] menyebutkan dari [Sa'id bin Musayyab] dari [Abdullah bin Zaid bin Abdu Rabbihi] berkata; tatkala Rasulullah Shallallahu'alaihiwasallam hendak memukul lonceng sebagai tanda mengumpulkan manusia untuk shalat, beliau membencinya karena menyamai dengan orang Nasrani. Lalu ada seorang yang mengelilingiku pada malam hari tepatnya pada waktu tertidur yaitu seorang yang memakai dua pakaian yang berwarna hijau dan pada salah satu tangannya ada lonceng yang dibawanya. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; saya bertanya kepadanya, Wahai Abdullah, apakah kamu menjual lonceng? Dia berkata; akan kau pergunakan untuk apa lonceng itu? saya menjawab, akan saya pergunakan untuk memanggil shalat. Dia berkata 'Maukah saya tunjukkan sesuatu yang lebih baik daripada itu?. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; saya menjawab, Ya. Dia berkata; bacalah: ALLAHU AKBAR ALLAHU AKBAR, ALLAHU AKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU ANNA MUHAMMADAR Radliyallahu'anhuSULULLAH, ASYHADU ANNA MUHAMMADAR Radliyallahu'anhuSULULLAH, HAYYA 'ALAS SHALAAH, HAYYA 'ALAS SHOLAAH, HAYYA 'ALAL FALAAH HAYYA 'ALAL FALAAH, ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLA ALLAH. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; lalu saya menunggu dalam waktu yang tidak lama. Dia berkata; lalu kamu baca, jika kamu hendak mendirikan shalat: ALLAHU AKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU ANNA MUHAMMADAR Radliyallahu'anhuSULULLAH, HAYYA 'ALAS SHALAAH, HAYYA 'ALAL FALAAH QAD QAMATIS SHALAH, QAD QAMATIS SHALAH ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLA ALLAH. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; tatkala pada pagi hari, saya menemui Rasulullah Shallallahu'alaihiwasallam, lalu saya mengabarkan kepada beliau dengan apa yang saya alami. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \" Itu mimpi yang haq, jika Allah menghendaki\". Lalu beliau memerintahkan untuk mengumandangkan adzan. Bilal, budak Abu Bakar mengumandangkan hal itu dan memanggil Rasulullah Shallallahu'alaihiwasallam untuk melakukan shalat. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; lalu (Bilal Radliyallahu'anhu) datang dan memanggilnya pada suatu pagi, lalu diberitahukan kepadanya, Rasulullah Shallallahu'alaihiwasallam sedang tidur. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; lalu Bilal berteriak dengan suaranya yang paling keras, ASH SHALATU KHAIRUN MINANNAUM Sa'id bin Musayyab berkata; kemudian kalimat itu dimasukkan dalam kalimat adzan pada shalat fajar."},"1107":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيُّ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَبْدِ رَبِّهِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ زَيْدٍ قَالَلَمَّا أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاقُوسِ لِيُضْرَبَ بِهِ لِلنَّاسِ فِي الْجَمْعِ لِلصَّلَاةِ طَافَ بِي وَأَنَا نَائِمٌ رَجُلٌ يَحْمِلُ نَاقُوسًا فِي يَدِهِ فَقُلْتُ لَهُ يَا عَبْدَ اللَّهِ أَتَبِيعُ النَّاقُوسَ قَالَ مَا تَصْنَعُ بِهِ قَالَ فَقُلْتُ نَدْعُو بِهِ إِلَى الصَّلَاةِ قَالَ أَفَلَا أَدُلُّكَ عَلَى مَا هُوَ خَيْرٌ مِنْ ذَلِكَ قَالَ فَقُلْتُ لَهُ بَلَى قَالَ تَقُولُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ ثُمَّ اسْتَأْخَرَ غَيْرَ بَعِيدٍ ثُمَّ قَالَ تَقُولُ إِذَا أُقِيمَتْ الصَّلَاةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ قَدْ قَامَتْ الصَّلَاةُ قَدْ قَامَتْ الصَّلَاةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ فَلَمَّا أَصْبَحْتُ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِمَا رَأَيْتُ فَقَالَ إِنَّهَا لَرُؤْيَا حَقٌّ إِنْ شَاءَ اللَّهُ فَقُمْ مَعَ بِلَالٍ فَأَلْقِ عَلَيْهِ مَا رَأَيْتَ فَلْيُؤَذِّنْ بِهِ فَإِنَّهُ أَنْدَى صَوْتًا مِنْكَ قَالَ فَقُمْتُ مَعَ بِلَالٍ فَجَعَلْتُ أُلْقِيهِ عَلَيْهِ وَيُؤَذِّنُ بِهِ قَالَ فَسَمِعَ بِذَلِكَ عُمَرُ بْنُ الْخَطَّابِ وَهُوَ فِي بَيْتِهِ فَخَرَجَ يَجُرُّ رِدَاءَهُ يَقُولُ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ رَأَيْتُ مِثْلَ الَّذِي أُرِيَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلِلَّهِ الْحَمْدُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepadaku [bapakku] dari [Muhammad bin Ishaq] berkata; telah menceritakan kepadaku [Muhammad bin Ibrahim bin Al Harits At-Taimi] dari [Muhammad bin Abdullah bin Zaid bin Abdu Rabbihi] berkata; telah menceritakan kepadaku [Abdullah bin Zaid] berkata; tatkala Rasulullah Shallallahu'alaihiwasallam menyuruh lonceng dipukul untuk mengumpulkan orang shalat, ada seorang yang mengelilingiku pada malam hari pada waktu saya tertidur, yaitu seorang yang membawa lonceng di tangannya. Saya bertanya kepadanya, Wahai Abdullah, apakah kamu menjual lonceng? Dia berkata; untuk apakau pergunakan? saya menjawab, kami pergunakan untuk memanggil shalat. Dia berkata; maukah saya tunjukkan sesuatu yang lebih baik daripada itu?. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; saya menjawab, Ya. Dia berkata; bacalah: ALLAHU AKBAR ALLAHU AKBAR, ALLAHU AKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU ANNA MUHAMMADAR Radliyallahu'anhuSULULLAH, ASYHADU ANNA MUHAMMADAR Radliyallahu'anhuSULULLAH, HAYYA 'ALAS SHALAAH, HAYYA 'ALAS SHOLAAH, HAYYA 'ALAL FALAAH HAYYA 'ALAL FALAAH, ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLA ALLAH. lalu dia menunggu dalam waktu yang tidak lama, lalu dia berkata; dan jika kamu hendak mendirikan shalat bacalah: ALLAHU AKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU ANNA MUHAMMADAR Radliyallahu'anhuSULULLAH, HAYYA 'ALAS SHALAAH, HAYYA 'ALAL FALAAH QAD QAMATIS SHALAH, QAD QAMATIS SHALAH ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLA ALLAH. Tatkala pagi hari, saya menemui Rasulullah Shallallahu'alaihiwasallam, saya mengabarkan beliau dengan apa yang saya lihat dalam mimpi. Lalu (Rasulullah Shallallahu'alaihiwasallam) bersabda: \" Itu adalah mimpi yang haq, jika Allah menghendaki\". Lalu berdirilah bersama Bilal, lalu saya sampaikan kepadanya dan dia pergunakan untuk mengumandangkan adzan. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; lalu 'Umar bin Al Khattab mendengarnya, pada saat dia sedang berada di rumahnya, lalu beliau keluar dan menyeret selendangnya dan berkata; demi yang mengutus anda dengan Al Haq, sungguh saya telah bermimpi sebagaimana yang saya lihat. (Abdullah bin Zaid bin Abdu Rabbihi Radliyallahu'anhu) berkata; lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bagi Allah segala puji.\""},"1108":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا ابْنُ مُبَارَكٍ عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ رَبِيعٍ عَنْ عِتْبَانَ بْنِ مَالِكٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضُحًى وَسَلَّمْنَا حِينَ سَلَّمَ وَأَنَّهُ يَعْنِي صَلَّى بِهِمْ فِي مَسْجِدٍ عِنْدَهُمْ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Ibnu Mubarak] dari [Ma'mar] dari [Az Zuhri] dari [Mahmud bin Rabi'] dari ['Itban bin Malik] berkata; Rasulullah Shallallahu'alaihiwasallam shalat dluha, lalu mengucapkan salam ketika beliau membaca salam. beliau shalat bersama mereka di masjid mereka."},"1109":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ فَسُئِلَ سُفْيَانُ عَمَّنْ قَالَ هُوَ مَحْمُودٌ إِنْ شَاءَ اللَّهُأَنَّ عِتْبَانَ بْنَ مَالِكٍ كَانَ رَجُلًا مَحْجُوبَ الْبَصَرِ وَأَنَّهُ ذَكَرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّخَلُّفَ عَنْ الصَّلَاةِ قَالَ هَلْ تَسْمَعُ النِّدَاءَ قَالَ نَعَمْ قَالَ فَلَمْ يُرَخِّصْ لَهُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] Sufyan ditanya dari siapa, dia menjawab, dari [Mahmud] jika Allah menghendaki, 'Itban bin Malik adalah seorang yang penglihatannya buta, dia menyebutkan kepada Nabi Shallallahu'alaihiwasallam tentang orang yang meninggalkan shalat. (SufyanRadliyallahu'anhu) bertanya, apakah kau mendengarkan panggilan? Dia menjawab, Ya. (Sufyan) Radliyallahu'anhu) berkata; maka beliau tidak memberikan keringanan baginya."},"1110":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنِ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ أَوْ الرَّبِيعِ بْنِ مَحْمُودٍ شَكَّ يَزِيدُ عَنْ عِتْبَانَ بْنِ مَالِكٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي رَجُلٌ ضَرِيرُ الْبَصَرِ وَبَيْنِي وَبَيْنَكَ هَذَا الْوَادِي وَالظُّلْمَةُ وَسَأَلْتُهُ أَنْ يَأْتِيَ فَيُصَلِّيَ فِي بَيْتِي فَأَتَّخِذَ مُصَلَّاهُ مُصَلًّى فَوَعَدَنِي أَنْ يَفْعَلَ فَجَاءَ هُوَ وَأَبُو بَكْرٍ وَعُمَرُ فَتَسَامَعَتْ بِهِ الْأَنْصَارُ فَأَتَوْهُ وَتَخَلَّفَ رَجُلٌ مِنْهُمْ يُقَالُ لَهُ مَالِكُ بْنُ الدُّخْشُنِ وَكَانَ يُزَنُّ بِالنِّفَاقِ فَاحْتَبَسُوا عَلَى طَعَامٍ فَتَذَاكَرُوا بَيْنَهُمْ فَقَالُوا مَا تَخَلَّفَ عَنَّا وَقَدْ عَلِمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَارَنَا إِلَّا لِنِفَاقِهِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَلَمَّا انْصَرَفَ قَالَ وَيْحَهُ أَمَا شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ بِهَا مُخْلِصًا فَإِنَّ اللَّهَ عَزَّ وَجَلَّ حَرَّمَ النَّارَ عَلَى مَنْ شَهِدَ بِهَا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Sufyan bin Husain] dari [Az Zuhri] dari [Mahmud bin Ar-Rabi' atau Ar-Rabi' bin Mahmud] Yazid ragu, dari ['Itban bin Malik] berkata; saya mendatangi Rasulullah Shallallahu'alaihiwasallam lalu saya menyampaikan uneg-unegku 'Saya orang buta, antara anda dan aku dipisahkan sebuah bukit dan keadaannya gelap gulita.' Selanjutnya saya meminta beliau untuk datang dan shalat di rumahku, dengan niyat saya akan menjadikan tempat shalatnya sebagai suraunya. Beruntunglah, Beliau menjanjikanku untuk merealisasikannya. Selanjutnya beliau, Abu Bakar dan 'Umar datang. Orang-orang Anshar mendengar kedatangan beliau dari mulut ke mulut, hingga mereka datangi beliau. Rupanya seorang laki-laki dari mereka ada yang sengaja tidak ikut hadir, namanya Malik bin Dukhsyun, dia adalah orang yang dicap sebagai orang munafik. Para sahabat sedemikian serius menyantap makanan lalu mereka saling mengingat-ingat nama sesama mereka. Lalu mereka berkata 'Si Malik bin duhsyun sengaja tidak ikut bersama kita karena sifat munafiknya, sebab ia pun tahu bahwa Rasulullah Shallallahu'alaihiwasallam mengunjungi kita sekarang ini.' Para sahabat mengucapkan demikian ketika Rasulullah Shallallahu'alaihiwasallam sedang shalat. Selesai shalat, beliau bersabda: \"Huss jangan begitu, Bukankah dia bersaksi bahwa tidak ada sesembahan yang hak selain Allah dengan ikhlas? dan Allah Azzawajalla mengharamkan neraka bagi siapa yang bersaksi dengan kalimat itu?.\""},"1111":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عِتْبَانَ بْنِ مَالِكٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنَّ السُّيُولَ تَحُولُ بَيْنِي وَبَيْنَ مَسْجِدِ قَوْمِي فَأُحِبُّ أَنْ تَأْتِيَنِي فَتُصَلِّيَ فِي مَكَانٍ فِي بَيْتِي أَتَّخِذُهُ مَسْجِدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَنَفْعَلُ قَالَ فَلَمَّا أَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَا عَلَى أَبِي بَكْرٍ فَاسْتَتْبَعَهُ فَلَمَّا دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيْنَ تُرِيدُ فَأَشَرْتُ لَهُ إِلَى نَاحِيَةٍ مِنْ الْبَيْتِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصُفِفْنَا خَلْفَهُ فَصَلَّى بِنَا رَكْعَتَيْنِ وَحَبَسْنَاهُ عَلَى خَزِيرٍ صَنَعْنَاهُ فَسَمِعَ أَهْلُ الدَّارِ يَعْنِي أَهْلَ الْقَرْيَةِ فَجَعَلُوا يَثُوبُونَ فَامْتَلَأَ الْبَيْتُ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَيْنَ مَالِكُ بْنُ الدُّخْشُمِ فَقَالَ رَجُلٌ ذَاكَ مِنْ الْمُنَافِقِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُهُ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِهَا وَجْهَ اللَّهِ قَالَ أَمَّا نَحْنُ فَنَرَى وَجْهَهُ وَحَدِيثَهُ إِلَى الْمُنَافِقِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُهُ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ بَلَى يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَئِنْ وَافَى عَبْدٌ يَوْمَ الْقِيَامَةِ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ إِلَّا حُرِّمَ عَلَى النَّارِفَقَالَ مَحْمُودٌ فَحَدَّثْتُ بِذَلِكَ قَوْمًا فِيهِمْ أَبُو أَيُّوبَ قَالَ مَا أَظُنُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذَا قَالَ فَقُلْتُ لَئِنْ رَجَعْتُ وَعِتْبَانُ حَيٌّ لَأَسْأَلَنَّهُ فَقَدِمْتُ وَهُوَ أَعْمَى وَهُوَ إِمَامُ قَوْمِهِ فَسَأَلْتُهُ فَحَدَّثَنِي كَمَا حَدَّثَنِي أَوَّلَ مَرَّةٍ وَكَانَ عِتْبَانُ بَدْرِيًّا قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عِتْبَانَ بْنِ مَالِكٍ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي قَدْ أَنْكَرْتُ بَصَرِي فَذَكَرَ مَعْنَاهُ إِلَّا أَنَّهُ قَالَ مَالِكُ بْنُ الدُّخْشُنِ وَرُبَّمَا قَالَ الدُّخَيْشِنِ وَقَالَ حُرِّمَ عَلَى النَّارِ وَلَمْ يَقُلْ كَانَ بَدْرِيًّا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Mahmud bin Rabi'] dari ['Itban bin Malik] dia berkata; \"Wahai Rasulullah, Sesungguhnya ada aliran air dari tempatku dan masjid kaum-ku, maka aku senang jika anda datang kepadaku dan shalat di rumahku yang akan kujadikan salah satu ruangannya sebagai masjid. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Baiklah\". ('Itban bin Malik Radliyallahu'anhu) berkata; ketika agak siang beliau mengajak Abu Bakar untuk mengikuti beliau. Ketika Rasulullah Shallallahu'alaihiwasallam masuk beliau bertanya, \"Dimana tempat yang kamu inginkan?\" lalu saya menunjukkan kepada beliau salah satu ruangan di rumahku. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda dan kami meluruskan shaf di belakang beliau, lalu beliau menjadi imam kami dan shalat dua rekaat. Lalu kami menahan beliau untuk tidak segera pergi dengan menyajikan hidangan khazir (makanan dari sedikit daging yang dicampur dengan banyak kuah dan ditaburi tepung) yang kami buat, maka penduduk desa mendengarnya dan merekapun mendatanginya sehingga rumah kamipun menjadi sesak. Lalu ada salah seorang laki-laki yang berkata; Dimana Malik bin Dukhsyum? Ada seseorang yang menjawab, dia adalah salah seorang dari kaum munafiqin. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah kamu mengatakan seperti itu, dia bersyahadat untuk mencari keridlaan wajah Allah\". (laki-laki tersebut) menimpali dengan berkata; Tapi kami melihat wajah dan pembicaraannya kepada kaum munafiqin. Lalu bersabda: \"Janganlah kamu mengatakan seperti itu, dia bersyahadat untuk mencari keridlaan wajah Allah.\" Lalu salah seorang dari mereka berkata; \"Ya. Wahai Rasulullah.\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika telah datang hisab pada Hari Kiamat terhadap seseorang yang bersyahadat mengharap ridla Allah kecuali diharamkan baginya neraka.\" Mahmud berkata; lalu saya ceritakan hadis tersebut kepada suatu kaum yang di dalamnya terdapat Abu Ayyub, maka dia berkata; Aku tidak menduga Rasulullah Shallallahu'alaihiwasallam mengatakan hal seperti itu. (Mahmud Radliyallahu'anhu) berkata; \"Nanti kalaulah aku pulang dan mendapati 'Itban masih hidup maka aku akan menanyakan hadis tersebut\" Lalu saya menemuinya, dia dalam kedaan buta dan menjadi imam bagi kaumnya, lalu saya menanyakannya, dan dia pun menceritakan kepada ku sebagaimana dulu dia bercerita pertama kali, 'Itban adalah termasuk orang yang ikut Perang Badar. (Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrozaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Mahmud bin Rabi'] dari ['Itban bin Malik] berkata; Aku mendatangi Nabi Shallallahu'alaihiwasallam, lalu aku berkata; \"Sesungguhnya penglihatanku telah memburuk\", lalu dia menyebutkan hadis secara makna, kecuali dia berkata; Apakah Malik bin Dukhsyun ataukah bin Dukhaisyn, dan perkataan, \"Diharamkan neraka\" dan dia tidak mengatakan bahwa dia adalah seorang yang ikut Perang Badar."},"1112":{"ar":"قَالَ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَنَسِ بْنِ مَالِكٍ قَالَقَدِمَ أَبِي مِنْ الشَّامِ وَافِدًا وَأَنَا مَعَهُ فَلَقِينَا مَحْمُودَ بْنَ الرَّبِيعِ فَحَدَّثَ أَبِي حَدِيثًا عَنْ عِتْبَانَ بْنِ مَالِكٍ قَالَ أَبِي أَيْ بُنَيَّ احْفَظْ هَذَا الْحَدِيثَ فَإِنَّهُ مِنْ كُنُوزِ الْحَدِيثِ فَلَمَّا قَفَلْنَا انْصَرَفْنَا إِلَى الْمَدِينَةِ فَسَأَلْنَا عَنْهُ فَإِذَا هُوَ حَيٌّ وَإِذَا شَيْخٌ أَعْمَى قَالَ فَسَأَلْنَاهُ عَنْ الْحَدِيثِ فَقَالَ نَعَمْ ذَهَبَ بَصَرِي عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ ذَهَبَ بَصَرِي وَلَا أَسْتَطِيعُ الصَّلَاةَ خَلْفَكَ فَلَوْ بَوَّأْتَ فِي دَارِي مَسْجِدًا فَصَلَّيْتُ فِيهِ فَأَتَّخِذُهُ مُصَلًّى قَالَ نَعَمْ فَإِنِّي غَادٍ عَلَيْكَ غَدًا قَالَ فَلَمَّا صَلَّى مِنْ الْغَدِ الْتَفَتَ إِلَيْهِ فَقَامَ حَتَّى أَتَاهُ فَقَالَ يَا عِتْبَانُ أَيْنَ تُحِبُّ أَنْ أُبَوِّئَ لَكَ فَوَصَفَ لَهُ مَكَانًا فَبَوَّأَ لَهُ وَصَلَّى فِيهِ ثُمَّ حَبَسَ أَوْ جَلَسَ وَبَلَغَ مَنْ حَوْلَنَا مِنْ الْأَنْصَارِ فَجَاءُوا حَتَّى مُلِئَتْ عَلَيْنَا الدَّارُ فَذَكَرُوا الْمُنَافِقِينَ وَمَا يَلْقُونَ مِنْ أَذَاهُمْ وَشَرِّهِمْ حَتَّى صَيَّرُوا أَمْرَهُمْ إِلَى رَجُلٍ مِنْهُمْ يُقَالُ لَهُ مَالِكُ بْنُ الدُّخْشُمِ وَقَالُوا مِنْ حَالِهِ وَمِنْ حَالِهِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاكِتٌ فَلَمَّا أَكْثَرُوا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَلَمَّا كَانَ فِي الثَّالِثَةِ قَالُوا إِنَّهُ لَيَقُولُهُ قَالَ وَالَّذِي بَعَثَنِي بِالْحَقِّ لَئِنْ قَالَهَا صَادِقًا مِنْ قَلْبِهِ لَا تَأْكُلُهُ النَّارُ أَبَدًا قَالُوا فَمَا فَرِحُوا بِشَيْءٍ قَطُّ كَفَرَحِهِمْ بِمَا قَالَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Husain bin Muhammad] berkata; telah menceritakan kepada kami [Jarir] yaitu Ibnu Hazm dari ['Ali bin Zaid bin Jud'an] berkata; telah menceritakan kepadaku [Abu Bakar bin Anas bin Malik] berkata; bapakku datang dari Syam sebagai utusan dan saya bersamanya lalu kami bertemu dengan [Mahmud bin Rabi'], lalu dia menceritakan kepada bapakku suatu hadis dari ['Itban bin Malik] bapakku berkata; Wahai anakku hafalkanlah hadis ini, karena termasuk dari hadis yang sangat berharga. Tatkala kami telah berangkat menuju Madinah, lalu kami menanyakan tentangnya, ternyata dia berada di desa dan umurnya telah tua dan buta. (Malik Radliyallahu'anhu) berkata; lalu kami bertanya kepadanya tentang hadis tersebut, lalu dia menjawab, mataku telah buta pada masa Rasulullah Shallallahu'alaihiwasallam lalu saya berkata; Wahai Rasulullah, mataku telah buta dan saya tidak mampu lagi shalat di belakang anda, kalau saja anda mau datang ke rumahku lalu saya jadikan sebagai masjid. Lalu saya shalat di dalamnya. Beliau menjawab, Ya. Sesungguhnya saya besok akan datang ('Itban bin Malik Radliyallahu'anhu) berkata; pada besoknya beliau shalat, beliau menoleh kepadanya, lalu beliau berdiri dan mendatanginya lalu bersabda: \"Wahai 'itban, dimana tempat yang kau sukai untuk dijadikan tempat shalat?\" Dia dia menunjukkan tempat yang dia kehendaki dan beliau shalat di tempat tersebut, lalu beliau tertahan atau duduk dan hal itu sampai pada orang-orang di sekitar kami dari kalangan Anshar, lalu mereka mendatangi beliau sampai tempat itu menjadi penuh. Lalu mereka menyebutkan tentang orang-orang munafik dan apa yang telah mereka lakukan dari berbagai macam gangguan dan kejahatan mereka sampai mereka mengakhiri urusan tersebut pada salah seorang dari mereka yangbernama Malik bin Dukhsyum. Dan mereka berkata; dia begini dan begini. Sedangkan Rasulullah Shallallahu'alaihiwasallam dalam keadaan diam. Tatkala mereka bertambah banyak dalam menyebutkannya, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidakkah dia bersaksi bahwa tidak ada tuhan selain Allah\". Pada saat ketiga kalinya mereka berkata; dia memang mengatakan hal itu. Beliau bersabda: \"Demi dzat yang telah mengutusku dengan Al Haq, jika dia telah mengatakannya secara jujur dari hatinya, maka neraka tidak akan memakannya selamanya.\" Mereka berkata dan mereka tidaklah merasa senang dengan sesuatu sebelumnya sebagaimana kesenangan mereka terhadap apa yang beliau sabdakan."},"1113":{"ar":"قَالَ حَدَّثَنَا حَجَّاجٌ وحُجَيْنٌ قَالَا حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنِ الْبَرَاءِ عَنْ خَالِهِ أَبِي بُرْدَةَ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنَّا عَجَّلْنَا شَاةَ لَحْمٍ لَنَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَبْلَ الصَّلَاةِ قُلْتُ نَعَمْ قَالَ تِلْكَ شَاةُ لَحْمٍ قَالَ يَا رَسُولَ اللَّهِ إِنَّ عِنْدَنَا عَنَاقًا جَذَعَةً هِيَ أَحَبُّ إِلَيَّ مِنْ مُسِنَّةٍ قَالَ تُجْزِئُ عَنْهُ وَلَا تُجْزِئُ عَنْ أَحَدٍ بَعْدَهُ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hajjaj] dan [Hujain] berkata; telah menceritakan kepada kami [Isra'il] dari [Ibnu Ishaq] dari [Al Bara`] dari [pamannya, Abu Burdah] dia berkata; Wahai Rasulullah, kami telah menyembelih kambing milik kami. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apakah sebelum shalat (idul adha)?.\" saya menjawab, Ya. Beliau bersabda: \"Itu sudah terhitung kambing sembelihan.\" Dia berkata; Wahai Rasulullah, kami memiliki unta yang baru berumur enam bulan lebih yang lebih saya sukai daripada yang berumur satu tahun, beliau bersabda: \"Itu boleh baginya dan tidak boleh bagi orang selainnya.\""},"1114":{"ar":"قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَا يُجْلَدُ فَوْقَ عَشْرِ جَلَدَاتٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepada kami [Laits] yaitu Ibnu Sa'ad, berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Bukair bin Abdullah bin Al Asyaj] dari [Sulaiman bin Yasar] dari [Abdurrahman bin Jabir bin Abdullah] dari [Abu Burdah] Rasulullah Shallallahu'alaihiwasallam pernah bersabda: \"Tidak boleh seseorang dicambuk melebihi sepuluh kali kecuali dalam hukum yang telah menjadi hukum-hukum Allah Azzawajalla.\""},"1115":{"ar":"قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرٍو أَنَّ بُكَيْرًا حَدَّثَهُ قَالَ بَيْنَمَا أَنَا جَالِسٌ عِنْدَ سُلَيْمَانَ بْنِ يَسَارٍ إِذْ جَاءَ عَبْدُ الرَّحْمَنِ يُحَدِّثُ سُلَيْمَانَ ثُمَّ أَقْبَلَ عَلَيْنَا سُلَيْمَانُ فَقَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جَابِرٍ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا بُرْدَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَجْلِدُوا فَوْقَ عَشَرَةَ أَسْوَاطٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّكَذَا قَالَ لَنَا فِيهِ قَالَ أَبِي وَأَنَا أَذْهَبُ إِلَيْهِ يَعْنِي الْحَدِيثَ يَعْنِي حَدِيثَ أَبِي بُرْدَةَ بْنِ نِيَارٍ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Mu'awiyah bin 'Amr] berkata; telah menceritakan kepada kami [Abdullah bin Wahb] dari ['Amr] [Bukair] menceritakannya, berkata; tatkala saya sedang duduk bersama [Sulaiman bin Yasar], datanglah Abdurrahman menceritakan kepada Sulaiman, lalu Sulaiman datang menemui kami, lalu berkata; telah menceritakan kepadaku [Abdurrahman bin Jabir] [Bapaknya] menceritakannya dia telah mendengar [Abu Burdah] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah kalian mencambuk melebihi sepuluh kali cambukan kecuali dalam hukum yang telah menjadi hukum-hukum Allah Azzawajalla.\" Demikian dia mengatakan kepada kami. bapakku berkata; dan saya menemuinya yaitu mendatangi hadis Abu Burdah bin Niyar."},"1116":{"ar":"قَالَ حَدَّثَنَا سُرَيْجٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا بُرْدَةَ بْنَ نِيَارٍ الْأَنْصَارِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَجْلِدُوا فَوْقَ عَشَرَةَ أَسْوَاطٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Suraij] berkata; telah menceritakan kepada kami [Abdullah bin Wahab] dari ['Amr bin Al Harits] dari [Bukair] dari [Sulaiman bin Yasar] berkata; telah menceritakan kepadaku [Abdurrahman bin Jabir bin Abdullah] [Bapaknya] menceritakannya telah mendengar [Abu Burdah bin Niyar Al Anshari] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah kalian mencambuk melebihi sepuluh kali cambukan kecuali dalam hukum yang telah menjadi hukum Allah Azzawajalla.\""},"1117":{"ar":"قَالَ حَدَّثَنَا سُوَيْدُ بْنُ عَمْرٍو الْكَلْبِيُّ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ جُمَيْعٍ أَوْ أَبِي جُمَيْعٍ عَنْ خَالِهِ أَبِي بُرْدَةَ بْنِ نِيَارٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى طَعَامًا فَأَدْخَلَ يَدَهُ فِيهِ فَرَأَى غَيْرَ ذَلِكَ فَقَالَ لَيْسَ مِنَّا مَنْ غَشَّنَا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Suwaid bin 'Amr Al Kalbi] berkata; telah menceritakan kepada kami [Syarik] dari [Abdullah bin 'Isa] dari [Jumai'] atau Abu Jumai' dari [pamannya, Abu Burdah bin Niyar] Nabi Shallallahu'alaihiwasallam melihat makanan lalu beliau memasukkan tangannya ke dalamnya, seketika itu pula beliau melihat yang di dalamnya berbeda dengan yang di atas, lalu beliau bersabda: \"Bukan termasuk golongan kami orang yang berbuat curang.\""},"1118":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنِي بُشَيْرُ بْنُ يَسَارٍ مَوْلَى بَنِي حَارِثَةَ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍ قَالَشَهِدْتُ الْعِيدَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَخَالَفَتْ امْرَأَتِي حَيْثُ غَدَوْتُ إِلَى الصَّلَاةِ إِلَى أُضْحِيَّتِي فَذَبَحَتْهَا وَصَنَعَتْ مِنْهَا طَعَامًا قَالَ فَلَمَّا صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْصَرَفْتُ إِلَيْهَا جَاءَتْنِي بِطَعَامٍ قَدْ فُرِغَ مِنْهُ فَقُلْتُ أَنَّى هَذَا قَالَتْ أُضْحِيَّتُكَ ذَبَحْنَاهَا وَصَنَعْنَا لَكَ مِنْهَا طَعَامًا لِتَغَدَّى إِذَا جِئْتَ قَالَ فَقُلْتُ لَهَا وَاللَّهِ لَقَدْ خَشِيتُ أَنْ يَكُونَ هَذَا لَا يَنْبَغِي قَالَ فَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ لَيْسَتْ بِشَيْءٍ مَنْ ذَبَحَ قَبْلَ أَنْ نَفْرُغَ مِنْ نُسُكِنَا فَلَيْسَ بِشَيْءٍ فَضَحِّ قَالَ فَالْتَمَسْتُ مُسِنَّةً فَلَمْ أَجِدْهَا قَالَ فَجِئْتُهُ فَقُلْتُ وَاللَّهِ يَا رَسُولَ اللَّهِ لَقَدْ الْتَمَسْتُ مُسِنَّةً فَمَا وَجَدْتُهَا قَالَ فَالْتَمِسْ جَذَعًا مِنْ الضَّأْنِ فَضَحِّ بِهِ قَالَ فَرَخَّصَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَذَعِ مِنْ الضَّأْنِ فَضَحَّى بِهِ حَيْثُ لَمْ يَجِدْ الْمُسِنَّةَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata; telah menceritakan kepada kami [bapakku] dari [Muhammad bin Ishaq] berkata; telah menceritakan kepadaku [Busyair bin Yasar] budak Bani Haritsah, dari [Abu Burdah bin Niyar] berkata; saya menyaksikan Hari Raya bersama Rasulullah Shallallahu'alaihiwasallam. (Abu Burdah bin Niyar Radliyallahu'anhu) berkata; maka istriku menyelisihiku tatkala saya sedang pergi menuju shalat, dia menuju ke sembelihanku, lalu dia menyembelihnya dan dijadikan makanan. (Abu Burdah bin Niyar Radliyallahu'anhu) berkata; tatkala Rasulullah Shallallahu'alaihiwasallam shalat bersama kami, dan saya menuju pada istriku, dia memberikan kepadaku membawa makanan yang telah siap lalu saya bertanya dari mana ini? Dia menjawab, hewan kurbanmu sudah saya sembelih dan sudah saya masak agar bisa dijadikan sarapan pagi jika kamu datang. Saya berkata kepadanya, demi Allah saya takut kalau hal itu tidak diperbolehkan. (Abu Burdah bin Niyar Radliyallahu'anhu) berkata; saya pun mendatangi Rasulullah Shallallahu'alaihiwasallam lalu saya sampaikan hal itu, maka beliau bersabda: \"Tidak dianggap kurban yang disembelih sebelum selesai dari ibadah (shalat ied) kami, tidak ada gunanya, tolong lakukan sembelihan lagi\". (Abu Burdah bin Niyar Radliyallahu'anhu) berkata; maka saya mencari kambing lagi yang telah berumur setahun namun tidak saya dapatkan. (Abu Burdah bin Niyar Radliyallahu'anhu) berkata; lalu saya mendatangi beliau dan saya katakan 'Wahai Rasulullah, saya telah mencari kambing yang telah berumur satu tahun namun saya tidak mendapatkannya.' Beliau bersabda: \"Carilah yang berumur enam bulan lebih dan sembelihlah.\" (Busyair bin YasarRadliyallahu'anhu) berkata; lalu Rasulullah Shallallahu'alaihiwasallam memberi keringanan dalam menyembelih yang baru berumur enam bulan, lalu dia menyembelihnya karena tidak mendapatkan yang berumur satu tahun."},"1119":{"ar":"قَالَ حَدَّثَنَا عَبْدُ اللَّهِ الْمُقْرِئُ قَالَ أَخْبَرَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُجْلَدُ فَوْقَ عَشَرَةِ أَسْوَاطٍ فِيمَا دُونَ حَدٍّ مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّكَذَا قَالَ لَنَا لَمْ يَقُلْ عَنْ أَبِيهِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdullah Al Muqri'] berkata; telah mengabarkan kepada kami [Sa'id bin Abu Ayyub] berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Bukair bin Abdullah bin Al Asyaj] dari [Sulaiman bin Yasar] dari [Abdurrahman bin Jabir bin Abdullah] dari [Abu Burdah bin Niyar] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Seseorang tidak boleh dicambuk melebihi sepuluh kali selain dalam hukum yang telah menjadi hukum-hukum Allah Azzawajalla.\" Demikian dia mengatakan kepada kami dan tidak mengatakan dari bapaknya."},"1120":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا أَبُو عُمَيْسٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِ قَالَبَارَزْتُ رَجُلًا فَقَتَلْتُهُ فَنَفَّلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَبَهُ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Abu 'Umais] dari [Iyyas bin Salamah] dari [bapaknya] berkata; Pernah aku perang tanding dengan seseorang lalu aku berhasil membunuhnya, maka Rasulullah Shallallahu'alaihiwasallam memberiku nafl. "},"1121":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَأْكُلُ بِشِمَالِهِ فَقَالَ كُلْ بِيَمِينِكَ فَقَالَ لَا أَسْتَطِيعُ فَقَالَ لَا اسْتَطَعْتَ قَالَ فَمَا رَجَعَتْ إِلَيْهِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami ['Ikrimah bin 'Ammar] dari [Iyas bin Salamah bin Al Akwa'] dari [bapaknya] Nabi Shallallahu'alaihiwasallam melihat seseorang makan dengan tangan kirinya, lalu beliau bersabda: \"Makanlah dengan tangan kananmu\", orang tersebut berkata; Aku tidak bisa. Maka beliau bersabda: \"Kamu tidak akan bisa\". Kontan orang tersebut tidak bisa lagi menggunakan tangan kanannya saat makan."},"1122":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِ قَالَكَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُلَامٌ يُسَمَّى رَبَاحًا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami ['Ikrimah bin 'Ammar] dari [Iyas bin Salamah] dari [bapaknya] berkata; Nabi Shallallahu'alaihiwasallam memiliki seorang budak yang bernama Rabah."},"1123":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا يَعْلَى بْنُ الْحَارِثِ قَالَ سَمِعْتُ إِيَاسَ بْنَ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ نَرْجِعُ فَلَا نَجِدُ لِلْحِيطَانِ فَيْئًا يُسْتَظَلُّ فِيهِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata; telah menceritakan kepada kami [Ya'la bin Al Harits] berkata; saya telah mendengar [Iyyas bin Salamah bin Al Akwa'] dari [bapaknya] berkata; kami shalat Jumat bersama Rasulullah Shallallahu'alaihiwasallam, kemudian kami kembali, maka kami tidak mendapati dinding-dinding suatu bayangan yang bisa kami gunakan untuk berteduh."},"1124":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَكَانَ شِعَارُنَا لَيْلَةَ بَيَّتْنَا فِي هَوَازِنَ مَعَ أَبِي بَكْرٍ الصِّدِّيقِ وَأَمَّرَهُ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمِتْ أَمِتْ وَقَتَّلْتُ بِيَدَيَّ لَيْلَتَئِذٍ سَبْعَةً أَهْلَ أَبْيَاتٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami ['Ikrimah bin 'Ammar] dari [Iyyas bin Salamah bin Al Akwa'] dari [bapaknya] berkata; kode rahasia kami ketika kami melakukan penyerangan malam-malam terhadap kabilah Hawazin bersama Abu Bakar Ash-Shidiq, yang Rasulullah Shallallahu'alaihiwasallam mengangkatnya sebagaii pemimpin kami adalah 'Amit-Amit' ('bunuhlah- bunuhlah), selanjutnya saya di malam itu berhasil membunuh tujuh penghuni rumah."},"1125":{"ar":"قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ الْيَمَامِيُّ قَالَ حَدَّثَنَا إِيَاسُ بْنُ سَلَمَةَ بْنِ الْأَكْوَعِ أَنَّ أَبَاهُ حَدَّثَهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِرَجُلٍ يُقَالُ لَهُ بُسْرُ ابْنُ رَاعِي الْعِيرِ أَبْصَرَهُ يَأْكُلُ بِشِمَالِهِ فَقَالَ كُلْ بِيَمِينِكَ فَقَالَ لَا أَسْتَطِيعُ فَقَالَ لَا اسْتَطَعْتَ قَالَ فَمَا وَصَلَتْ يَمِينُهُ إِلَى فَمِهِ بَعْدُو قَالَ أَبُو النَّضْرِ فِي حَدِيثِهِ ابْنُ رَاعِي الْعِيرِ مِنْ أَشْجَعَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami ['Ikrimah bin 'Ammar Al Yamami] berkata; telah menceritakan kepada kami [Iyyas bin Salamah bin Al Akwa'] sesungguhnya [bapaknya] menceritakannya, berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda kepada seorang laki-laki yang bernama Busr bin Ra'il 'ir, beliau melihatnya makan dengan menggunakan tangan kiri. Lalu beliau bersabda: \"Makanlah dengan tangan kananmu\". Dia menjawab, 'Saya tidak bisa.' Beliau bersabda: \"Kalau begitu kamu tidak akan bisa.\" (Salamah bin Al Akwa' Radliyallahu'anhuma) berkata; semenjak itu tangan kanannya tidak bisa sampai ke mulutnya. Dan Abu Nadlr berkata dalam haditsnya 'Ibnu Ra'il ir adalah dari Asyja'."},"1126":{"ar":"قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَلَّ عَلَيْنَا السَّيْفَ فَلَيْسَ مِنَّا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami ['Ikrimah bin 'Ammar] dari [Iyyas bin Salamah] dari [bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menghunuskan pedangnya terhadap kami maka dia bukanlah termasuk dari kami.\""},"1127":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا إِيَاسُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبِي قَالَخَرَجْنَا مَعَ أَبِي بَكْرِ بْنِ أَبِي قُحَافَةَ وَأَمَّرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا قَالَ غَزَوْنَا فَزَارَةَ فَلَمَّا دَنَوْنَا مِنْ الْمَاءِ أَمَرَنَا أَبُو بَكْرٍ فَعَرَّسْنَا قَالَ فَلَمَّا صَلَّيْنَا الصُّبْحَ أَمَرَنَا أَبُو بَكْرٍ فَشَنَنَّا الْغَارَةَ فَقَتَلْنَا عَلَى الْمَاءِ مَنْ قَتَلْنَا قَالَ سَلَمَةُ ثُمَّ نَظَرْتُ إِلَى عُنُقٍ مِنْ النَّاسِ فِيهِ الذُّرِّيَّةُ وَالنِّسَاءُ نَحْوَ الْجَبَلِ وَأَنَا أَعْدُو فِي آثَارِهِمْ فَخَشِيتُ أَنْ يَسْبِقُونِي إِلَى الْجَبَلِ فَرَمَيْتُ بِسَهْمٍ فَوَقَعَ بَيْنَهُمْ وَبَيْنَ الْجَبَلِ قَالَ فَجِئْتُ بِهِمْ أَسُوقُهُمْ إِلَى أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ حَتَّى أَتَيْتُهُ عَلَى الْمَاءِ وَفِيهِمْ امْرَأَةٌ مِنْ فَزَارَةَ عَلَيْهَا قَشْعٌ مِنْ أَدَمٍ وَمَعَهَا ابْنَةٌ لَهَا مِنْ أَحْسَنِ الْعَرَبِ قَالَ فَنَفَّلَنِي أَبُو بَكْرٍ ابْنَتَهَا قَالَ فَمَا كَشَفْتُ لَهَا ثَوْبًا حَتَّى قَدِمْتُ الْمَدِينَةَ ثُمَّ بِتُّ فَلَمْ أَكْشِفْ لَهَا ثَوْبًا قَالَ فَلَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السُّوقِ فَقَالَ لِي يَا سَلَمَةُ هَبْ لِي الْمَرْأَةَ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ لَقَدْ أَعْجَبَتْنِي وَمَا كَشَفْتُ لَهَا ثَوْبًا قَالَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَرَكَنِي حَتَّى إِذَا كَانَ مِنْ الْغَدِ لَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السُّوقِ فَقَالَ يَا سَلَمَةُ هَبْ لِي الْمَرْأَةَ لِلَّهِ أَبُوكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ أَعْجَبَتْنِي مَا كَشَفْتُ لَهَا ثَوْبًا وَهِيَ لَكَ يَا رَسُولَ اللَّهِ قَالَ فَبَعَثَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَهْلِ مَكَّةَ وَفِي أَيْدِيهِمْ أُسَارَى مِنْ الْمُسْلِمِينَ فَفَدَاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتِلْكَ الْمَرْأَةِ","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami ['Ikrimah bin 'Ammar] telah menceritakan kepada kami [Iyyas bin Salamah] berkata; telah menceritakan kepada kami [bapakku] berkata; kami keluar bersama Abu Bakar bin Abu Quhafah dan Rasulullah Shallallahu'alaihiwasallam mengangkat Abu Bakar sebagai pemimpin kami. (Salamah bin Al Akwa' Radliyallahu'anhu) berkata; kami memerangi kaum Fazarah, ketika kami mendekati sumber air, Abu Bakar menyuruh kami untuk istirahat pada akhir malam. (Salamah bin Al Akwa' Radliyallahu'anhu) berkata; ketika kami shalat subuh, Abu Bakar menyuruh kami untuk menyerang musuh dari segala penjuru sehingga terjadilah perang yang sengit, sehingga kami berhasil membunuh beberapa orang di atas mata air. Lalu saya melihat rombongan manusia yang di dalamnya terdapat anak-anak kecil dan perempuan sedang mendaki gunung. Aku bersegera mengikuti jejak mereka, aku khawatir apabila mereka mendahuluiku ke atas gunung, saya pun melempari anak panah hingga terjatuh menghalangi antara rombongan dan gunung. Lalu aku mendatangi mereka dan menggiring mereka kepada Abu Bakar Radliyallahu'anhu, hingga aku menemuinya di mata air dan di antara mereka terdapat seorang perempuan dari kaum Fazarah yang membawa kulit disamak dengan membawa anak perempuannya yang tercantik di Arab. (Salamah bin Al Akwa' Radliyallahu'anhu) berkata; lalu Abu Bakar memberiku anak prempuan itu dalam pembagian harta rampasan perang. (Salamah bin Al Akwa' Radliyallahu'anhu) berkata; dan aku tidak pernah menyingkap bajunya sampai kami kembali ke Madinah. (ketika di Madinah) aku belum juga menyingkap bajunya. lalu Rasulullah Shallallahu'alaihiwasallam menemuiku di pasar dan bersabda kepadaku, \"Wahai Salamah, berikanlah perempuan itu kepadaku\", saya menjawab, \"Wahai Rasulullah, demi Allah saya sangat menyukainya namun saya belum pernah membuka bajunya\". Rasulullah Shallallahu'alaihiwasallam terdiam lalu meninggalkanku sampai kemudian esok harinya beliau menemuiku kembali di pasar dan kembali bersabda: \"Wahai Salamah, berikanlah perempuan itu kepadaku karena Allah, \" lalu saya berkata; Wahai Rasulullah, demi Allah, saya sangat menyukainya dan aku tidak pernah menyingkap bajunya dan sekarang dia milikmu wahai Rasulullah. Lalu Rasulullah Shallallahu'alaihiwasallam mengirim perempuan itu ke penduduk Makkah yang menahan beberapa tawanan kaum muslimin, dan beliau menebus mereka dengan perempuan itu."},"1128":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ الْأَنْصَارِيُّ أَنَّ سَلَمَةَ بْنَ الْأَكْوَعِ قَالَلَمَّا كَانَ يَوْمُ خَيْبَرَ قَاتَلَ أَخِي قِتَالًا شَدِيدًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَارْتَدَّ عَلَيْهِ سَيْفُهُ فَقَتَلَهُ فَقَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ وَشَكُّوا فِيهِ رَجُلٌ مَاتَ بِسِلَاحِهِ شَكُّوا فِي بَعْضِ أَمْرِهِ قَالَ سَلَمَةُ فَقَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَيْبَرَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَأْذَنُ لِي أَنْ أَرْجُزَ بِكَ فَأَذِنَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ عُمَرُ اعْلَمْ مَا تَقُولُ قَالَ فَقُلْتُ وَاللَّهِ لَوْلَا اللَّهُ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقْتَ فَأَنْزِلَنْ سَكِينَةً عَلَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاوَالْمُشْرِكُونَ قَدْ بَغَوْا عَلَيْنَافَلَمَّا قَضَيْتُ رَجَزِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ هَذَا قُلْتُ أَخِي قَالَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُهُ اللَّهُ فَقُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ إِنَّ نَاسًا لَيَهَابُونَ أَنْ يُصَلُّوا عَلَيْهِ وَيَقُولُونَ رَجُلٌ مَاتَ بِسِلَاحِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَ جَاهِدًا مُجَاهِدًاقَالَ ابْنُ شِهَابٍ ثُمَّ سَأَلْتُ ابْنَ سَلَمَةَ بْنِ الْأَكْوَعِ فَحَدَّثَنِي عَنْ أَبِيهِ مِثْلَ الَّذِي حَدَّثَنِي عَنْهُ عَبْدُ الرَّحْمَنِ غَيْرَ أَنَّ ابْنَ سَلَمَةَ قَالَ قَالَ مَعَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَهَابُونَ الصَّلَاةَ عَلَيْهِ كَذَبُوا مَاتَ جَاهِدًا مُجَاهِدًا فَلَهُ أَجْرُهُ مَرَّتَيْنِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِصْبَعَيْهِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abdurrahman bin Abdullah bin Ka'ab bin Malik Al Anshari] sesungguhnya [Salamah bin Al Akwa'] berkata; Ketika terjadi perang Khaibar, saudaraku berperang dengan sengitnya bersama Rasulullah Shallallahu'alaihiwasallam sehingga karena sengitnya pertempuran, pedangnya berbalik kepadanya dan akhirnya terbunuh oleh pedangnya sendiri. Para sahabat Rasulullah Shallallahu'alaihiwasallam terus memperbincangkan hal itu dan menyebarkan ghosip bahwa ia mati karena senjatanya sendiri serta beberapa hal yang berkaitan dengannya. Kemudian Rasulullah Shallallahu'alaihiwasallam pulang dari Khaibar, lalu aku berkata kepada beliau, 'Wahai Rasulullah, ijinkanlah aku untuk mendendangkan syair', maka beliau pun mengijinkannya, lalu 'Umar berkata kepadaku, 'Perhatikanlah apa yang kamu ucapkan.' Lalu aku pun berkata: Demi Allah, kalaulah bukan karena Allah, kami tidaklah mendapat petunjuk, kami tidak akan pernah shalat serta bersedekah. Lalu Rasulullah Shallallahu'alaihiwasallam menimpalinya: kamu benar, turunkanlah ketenangan kepada kami, teguhkanlah kaki-kaki kami ketika kami saling bertemu, ketika kaum musrikin telah berbuat sewenang-wenang terhadap kami.' Setelah saya menyelesaikan syairku Rasulullah Shallallahu'alaihiwasallam bersabda: \"Siapakah yang telah mengucapkan syair ini\"? maka aku berkata; \"Saudaraku\", maka beliau bersabda: \"Semoga Allah merahmatinya\", maka aku berkata kepada beliau, Demi Allah, orang-orang takut untuk menshalatinya dan mereka berkata; dia mati oleh senjatanya sendiri. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya dia mati dalam keadaan jihad dan sebagai mujahid\". [Ibnu Syihab] berkata; lalu saya bertanya kepada [Ibnu Salamah bin Al Akwa'], lalu dia menceritakan kepadaku dari [Bapaknya] sebagaimana yang telah saya dapatkan darinya oleh Abdurrahman hanya yang beda adalah Ibnu Salamah berkata; ada keterangan, manusia takut untuk menshalatinya, maka Rasulullah Shallallahu'alaihiwasallam bersabda: \"Mereka telah berbohong, dia adalah mati dalam keadaan jihad dan sebagai seorang mujahid dan kelak dia akan mendapati dua pahala dua kali\" Rasulullah Shallallahu'alaihiwasallam bersabda mengatakan dengan kedua jarinya."},"1129":{"ar":"قَالَ حَدَّثَنَا قُرَّانُ بْنُ تَمَّامٍ عَنْ عِكْرِمَةَ الْيَمَامِيِّ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِ قَالَخَرَجْتُ مَعَ أَبِي بَكْرٍ فِي غَزَاةِ هَوَازِنَ فَنَفَّلَنِي جَارِيَةً فَاسْتَوْهَبَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ بِهَا إِلَى مَكَّةَ فَفَدَى بِهَا أُنَاسًا مِنْ الْمُسْلِمِينَ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Qurran bin Tammam] dari ['Ikrimah Al Yamami] dari ['Iyas bin Salamah] dari [Bapaknya] berkata; saya pernah bepergian bersama Abu Bakar dalam perang melawan Hawazin lalu saya mendapatkan rampasan berupa seorang wanita, lalu Rasulullah Shallallahu'alaihiwasallam memintanya dan beliau mengirimkannya ke Makkah dan digunakan untuk menebus beberapa tawanan muslimin."},"1130":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ قَالَ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّ رَجُلًا عَطَسَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ النَّب��يُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُكَ اللَّهُ ثُمَّ عَطَسَ الثَّانِيَةَ أَوْ الثَّالِثَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ مَزْكُومٌ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ikrimah bin 'Ammar] berkata; telah menceritakan kepadaku [Iyas bin Salamah bin Al Akwa'] sesungguhnya [bapaknya] mengabarinya sesungguhnya ada seorang laki-laki yang bersin di sisi Nabi Shallallahu'alaihiwasallam. lalu Nabi Shallallahu'alaihiwasallam bersabda kepadanya, \"YARHAMUKA ALLAHU (Semoga Allah merahmatimu\", kemudian bersin untuk kedua, atau ketiga kalinya. Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Ohh, dia terserang pilek.\""},"1131":{"ar":"قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ قَالَ حَدَّثَنَا أَبُو عُمَيْسٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَجَاءَ عَيْنٌ لِلْمُشْرِكِينَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا طَعِمَ انْسَلَّ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الرَّجُلِ اقْتُلُوا قَالَ فَابْتَدَرَ الْقَوْمُ قَالَ وَكَانَ أَبِي يَسْبِقُ الْفَرَسَ شَدًّا قَالَ فَسَبَقَهُمْ إِلَيْهِ قَالَ فَأَخَذَ بِزِمَامِ نَاقَتِهِ أَوْ بِخِطَامِهَا قَالَ ثُمَّ قَتَلَهُ قَالَ فَنَفَّلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَبَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Ja'far bin 'Aun] berkata; telah menceritakan kepada kami [Abu 'Umais] dari [Iyas bin Salamah bin Al Akwa'] dari [Bapaknya] berkata; seorang mata-mata orang musrik datang kepada Rasulullah Shallallahu'alaihiwasallam. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; tatkala beliau makan, mata-mata itu kabur dengan sembunyi-sembunyi. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; Rasulullah Shallallahu'alaihiwasallam bersabda mengenai orang tersebut, 'Bunuhlah olehmu sekalian.' (Salamah bin Al Akwa' radliyallahu'anhu) berkata; lalu orang-orang bersegera memburu mata-mata tadi, dan bapakku adalah orang selalu menang dalam memacu kuda. Dia pun lebih dahulu daripada sahabat lain. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; lalu ayahku mengambil tali unta tersebut atau ujung hidungnya, lalu membunuh orangnya. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; lalu Rasulullah Shallallahu'alaihiwasallam memberi ghanimah yang ada pada musuh tersebut."},"1132":{"ar":"قَالَ حَدَّثَنَا صَفْوَانُ قَالَ حَدَّثَنَا ابْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَغْرِبَ سَاعَةَ تَغْرُبُ الشَّمْسُ إِذَا غَابَ حَاجِبُهَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Shafwan] berkata; telah menceritakan kepada kami [Ibnu Abu 'Ubaid] dari [Salamah bin Al Akwa'] berkata; Rasulullah Shallallahu'alaihiwasallam shalat magrib pada waktu tenggelamnya Matahari, ketika telah bagian tepinya telah tenggelam\""},"1133":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ الْحَسَنَ بْنَ مُحَمَّدٍ يُحَدِّثُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَسَلَمَةَ بْنِ الْأَكْوَعِ قَالَاخَرَجَ عَلَيْنَا مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَى إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَذِنَ لَكُمْ فَاسْتَمْتِعُوا يَعْنِي مُتْعَةَ النِّسَاءِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Dinar] berkata; saya telah mendengar [Al Hasan bin Muhammad] menceritakan dari [Jabir bin Abdullah] dan [Salamah bin Al Akwa'] berkata; ada seorang penyeru Rasulullah Shallallahu'alaihiwasallam datang menemui kami, lalu dia mengucapkan: Rasulullah Shallallahu'alaihiwasallam telah mengijinkan untuk kalian maka berbuatlah mut'ah maksudnya nikah mut'ah."},"1134":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ زُهَيْرٍ وَحَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ قَالَ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَكُنْتُ أُسَافِرُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا رَأَيْتُهُ صَلَّى بَعْدَ الْعَصْرِ وَلَا بَعْدَ الصُّبْحِ قَطُّ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; [Abdurrahman bin Mahdi] dari [Zuhair] dan telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata; telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Yazid bin Khushoifah] dari [Salamah Bin Al Akwa'] berkata; saya bepergian bersama Rasulullah Shallallahu'alaihiwasallam maka saya tidak pernah mendapati beliau shalat setelah ashar dan setelah subuh sama sekali."},"1135":{"ar":"قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا إِيَاسُ بْنُ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَوَازِنَ وَغَطَفَانَ فَبَيْنَمَا نَحْنُ كَذَلِكَ إِذْ جَاءَ رَجُلٌ عَلَى جَمَلٍ أَحْمَرَ فَانْتَزَعَ شَيْئًا مِنْ حَقَبِ الْبَعِيرِ فَقَيَّدَ بِهِ الْبَعِيرَ ثُمَّ جَاءَ يَمْشِي حَتَّى قَعَدَ مَعَنَا يَتَغَدَّى قَالَ فَنَظَرَ فِي الْقَوْمِ فَإِذَا ظَهْرُهُمْ فِيهِ قِلَّةٌ وَأَكْثَرُهُمْ مُشَاةٌ فَلَمَّا نَظَرَ إِلَى الْقَوْمِ خَرَجَ يَعْدُو قَالَ فَأَتَى بَعِيرَهُ فَقَعَدَ عَلَيْهِ قَالَ فَخَرَجَ يَرْكُضُهُ وَهُوَ طَلِيعَةٌ لِلْكُفَّارِ فَاتَّبَعَهُ رَجُلٌ مِنَّا مِنْ أَسْلَمَ عَلَى نَاقَةٍ لَهُ وَرْقَاءَ قَالَ إِيَاسٌ قَالَ أَبِي فَاتَّبَعْتُهُ أَعْدُو عَلَى رِجْلَيَّ قَالَ وَرَأْسُ النَّاقَةِ عِنْدَ وَرِكِ الْجَمَلِ قَالَ وَلَحِقْتُهُ فَكُنْتُ عِنْدَ وَرِكِ النَّاقَةِ وَتَقَدَّمْتُ حَتَّى كُنْتُ عِنْدَ وَرِكِ الْجَمَلِ ثُمَّ تَقَدَّمْتُ حَتَّى أَخَذْتُ بِخِطَامِ الْجَمَلِ فَقُلْتُ لَهُ إِخْ فَلَمَّا وَضْعَ الْجَمَلُ رُكْبَتَهُ إِلَى الْأَرْضِ اخْتَرَطْتُ سَيْفِي فَضَرَبْتُ رَأْسَهُ فَنَدَرَ ثُمَّ جِئْتُ بِرَاحِلَتِهِ أَقُودُهَا فَاسْتَقْبَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ النَّاسِ قَالَ مَنْ قَتَلَ هَذَا الرَّجُلَ قَالُوا ابْنُ الْأَكْوَعِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ سَلَبُهُ أَجْمَعُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Bahz bin Asad] berkata; telah menceritakan kepada kami [Ikrimah bin 'Ammar] berkata; telah menceritakan kepada kami [Iyas bin Salamah bin Al Akwa'] dari [Bapaknya] berkata; kami berperang bersama Rasulullah Shallallahu'alaihiwasallam melawan kaum Hawazin dan Ghathafan. Tatkala kami sedang menyerang mereka, tiba-tiba datanglah seorang laki-laki dengan mengendarai unta jantan berwarna merah. Lalu dia mengambil sesuatu dari tasnya, lalu dia mengikat unta betinanya dengan tali itu, lalu dia datang dengan berjalan sampai dia duduk bersama kami dan makan siang. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; ternyata kendaraan mereka ada di dalamnya sedikit, dan kebanyakan mereka berjalan. Tatkala dia melihat ke arah kaum, dia keluar dan berlari. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; lalu dia mendatangi untanya dan duduk di atasnya, lalu dia keluar dengan memacunya. Dia adalah salah intelejen orang kafir. Seorang dari kami dari kabilah Aslam membuntutinya dengan berkendaraan unta miliknya yaitu warqa (yang warna hitamnya bercampur dengan warna putih). Iyas berkata; bapakku berkata; lalu saya mengikutinya dengan berlari dengan mengunakan kedua kakiku. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; hingga kepala unta betinaku berada dalam paha unta jantan. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; saya menyusulnya sampai saya berada pada paha unta betina, lalu saya maju sampai saya berada pada paha untuk jantan musuh, lalu saya maju lagi sampai di tempat hidung unta jantan musuh, lalu saya katakan, ih. Tatkala unta jantan itu meletakkkan lututnya ke tanah, saya menghunuskan pedangku, lalu saya tebas kepala (laki-laki tersebut), maka dia terjatuh, lalu saya bawa kendaraannya dan segala yang ada di atasnya. Saya giring, lalu Rasulullah Shallallahu'alaihiwasallam mendapatiku. Beliau sedang bersama orang-orang, beliau bertanya, siapakah orang yang telah membunuh orang ini? Mereka menjawab, Ibnu Al Akwa'. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: semua rampasan menjadi miliknya. "},"1136":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا عِكْرِمَةُ قَالَ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنِي أَبِي قَالَبَارَزَ عَمِّي يَوْمَ خَيْبَرَ مَرْحَبٌ الْيَهُودِيُّ فَقَالَ مَرْحَبٌ قَدْ عَلِمَتْ خَيْبَرُ أَنِّي مَرْحَبُشَاكِي السِّلَاحِ بَطَلٌ مُجَرَّبُإِذَا الْحُرُوبُ أَقْبَلَتْ تَلَهَّبُفَقَالَ عَمِّي عَامِرٌ قَدْ عَلِمَتْ خَيْبَرُ أَنِّي عَامِرُشَاكِي السِّلَاحِ بَطَلٌ مُغَامِرُفَاخْتَلَفَا ضَرْبَتَيْنِ فَوَقَعَ سَيْفُ مَرْحَبٍ فِي تُرْسِ عَامِرٍ وَذَهَبَ يَسْفُلُ لَهُ فَرَجَعَ السَّيْفُ عَلَى سَاقِهِ قَطَعَ أَكْحَلَهُ فَكَانَتْ فِيهَا نَفْسُهُ قَالَ سَلَمَةُ بْنُ الْأَكْوَعِ لَقِيتُ نَاسًا مِنْ صَحَابَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا بَطَلَ عَمَلُ عَامِرٍ قَتَلَ نَفْسَهُ قَالَ سَلَمَةُ فَجِئْتُ إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْكِي قُلْتُ يَا رَسُولَ اللَّهِ بَطَلَ عَمَلُ عَامِرٍ قَالَ مَنْ قَالَ ذَاكَ قُلْتُ نَاسٌ مِنْ أَصْحَابِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبَ مَنْ قَالَ ذَاكَ بَلْ لَهُ أَجْرُهُ مَرَّتَيْنِ إِنَّهُ حِينَ خَرَجَ إِلَى خَيْبَرَ جَعَلَ يَرْجُزُ بِأَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِيهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسُوقُ الرِّكَابَ وَهُوَ يَقُولُ تَالَلَّهِ لَوْلَا اللَّهُ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَاإِنَّ الَّذِينَ قَدْ بَغَوْا عَلَيْنَاإِذَا أَرَادُوا فِتْنَةً أَبَيْنَاوَنَحْنُ عَنْ فَضْلِكَ مَا اسْتَغْنَيْنَافَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاوَأَنْزِلَنْ سَكِينَةً عَلَيْنَافَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذَا قَالَ عَامِرٌ يَا رَسُولَ اللَّهِ قَالَ غَفَرَ لَكَ رَبُّكَ قَالَ وَمَا اسْتَغْفَرَ لِإِنْسَانٍ قَطُّ يَخُصُّهُ إِلَّا اسْتُشْهِدَ فَلَمَّا سَمِعَ ذَلِكَ عُمَرُ بْنُ الْخَطَّابِ قَالَ يَا رَسُولَ اللَّهِ لَوْ مَتَّعْتَنَا بِعَامِرٍ فَقَدِمَ فَاسْتُشْهِدَ قَالَ سَلَمَةُ ثُمَّ إِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَنِي إِلَى عَلِيٍّ فَقَالَ لَأُعْطِيَنَّ الرَّايَةَ الْيَوْمَ رَجُلًا يُحِبُّ اللَّهَ وَرَسُولَهُ أَوْ يُحِبُّهُ اللَّهُ وَرَسُولُهُ قَالَ فَجِئْتُ بِهِ أَقُودُهُ أَرْمَدَ فَبَصَقَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عَيْنِهِ ثُمَّ أَعْطَاهُ الرَّايَةَ فَخَرَجَ مَرْحَبٌ يَخْطِرُ بِسَيْفِهِ فَقَالَ قَدْ عَلِمَتْ خَيْبَرُ أَنِّي مَرْحَبُشَاكِي السِّلَاحِ بَطَلٌ مُجَرَّبُإِذَا الْحُرُوبُ أَقْبَلَتْ تَلَهَّبُفَقَالَ عَلِيُّ بْنُ أَبِي طَالِبٍ كَرَّمَ اللَّهُ وَجْهَهُ أَنَا الَّذِي سَمَّتْنِي أُمِّي حَيْدَرَهْكَلَيْثِ غَابَاتٍ كَرِيهِ الْمَنْظَرَهْأُوفِيهِمُ بِالصَّاعِ كَيْلَ السَّنْدَرَهْفَفَلَقَ رَأْسَ مَرْحَبٍ بِالسَّيْفِ وَكَانَ الْفَتْحُ عَلَى يَدَيْهِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Ikrimah] berkata; telah menceritakan kepadaku [Iyas bin Salamah bin Al Akwa'] berkata; telah mengabarkan kepadaku [bapakku] berkata; Marhab bertanding pada Perang Khaibar dengan pamanku. Marhab sambil mendendangkan bait-bait syair 'Khaibar telah tahu sesungguhnya aku Marhab, orang yang sangat piawai memainkan senjata, seorang pahlawan pemberani, kala peperangan datang berkecamuk dan menyala-nyala. Lalu pamanku 'Amir melawan dengan bait-bait syair, 'Khaibar telah tahu sesungguhnya aku 'Amir, orang yang sangat pandai dalam memainkan senjata, seorang pahlawan pengacau dalam peperangan. Lalu keduanya saling bergantian dalam memukul, lalu pedang Marhab mengenai tameng 'Amir. Pedang Marhab terjepit tamengnya hingga bengkok, dan berbalik mengenai lengannya dan memotong uratnya hingga menjadikan Amir gugur karenanya. Salamah bin Al Akwa' berkata; lantas saya menjumpai beberapa orang dari sahabat Nabi Shallallahu'alaihiwasallam. Sayang, mereka malah berkata; sia-sialah amalan 'Amir, dia mati bunuh diri. Salamah berkata; saya pun datang menemui Nabiyullah Shallallahu'alaihiwasallam dengan keadaan menangis, saya berkata; Wahai Rasulullah, telah sia-sia amalan 'Amir. Beliau bertanya siapa yang mengatakan hal itu? Saya menjawab, 'Beberapa orang dari sahabat anda.' Rasulullah Shallallahu'alaihiwasallam bersabda: \"Dusta orang yang mengatakan hal itu, bahkan baginya pahala dua kali. Saat dia berangkat menuju Khaibar, dia melantunkan bait-bait syair bersama para sahabat Rasulullah Shallallahu'alaihiwasallam yang diantaranya adalah Nabi Shallallahu'alaihiwasallam selaku pemimpin rombongan. Amir melantunkan bait-bait syair: # Demi Allah, kalaulah bukan karena Allah, kami tidaklah mendapat petunjuk, # kami tidak akan pernah shalat serta bersedekah. # Sesungguhnya musuh telah melampui batas terhadap kami # jika mereka menghendaki fitnah kami akan menolaknya # Kami selalu membutuhkan kurnia-Mu # teguhkanlah kaki-kaki kami ketika kami saling bertemu # dan turunkanlah ketenangan kepada kami # Rasulullah Shallallahu'alaihiwasallam bersabda: \"Siapakah orang itu?\" Dia menjawab, 'Amir Wahai Rasulullah. Beliau bersabda: \"Semoga Rabmu mengampunimu.\" (Salamah bin Al Akwa' radliyallahu'anhu) berkata; tidaklah Rasulullah Shallallahu'alaihiwasallam memintakan ampun yang beliau tujukan untuk seseorang tertentu, kecuali orang itu akan mendapatkan kesyahidan. Tatkala 'Umar bin Al Khattab mendengar hal itu, ia berkata; 'Wahai Rasulullah, Aduhai sendaianya anda menangguhkan doa anda kepada 'Amir, tentu kita bisa bersahabat lebih lama dengannya. Lalu Amir maju ke medan laga dan memperoleh kesyahidan. Salamah berkata; 'Lantas Nabiyullah Shallallahu'alaihiwasallam mengutusku untuk menemui 'Ali, beliau bersabda: \"Sungguh pada hari saya akan memberikan bendera kepada orang mencintai Allah dan Rasul-Nya atau dengan redaksi 'kepada seseorang yang Allah dan Rasul-Nya mencintainya--. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; lalu saya datang membawa dia ('Ali Radliyallahu'anhu) dalam keadaan sakit matanya. Lantas Nabiyullah meludahinya pada matanya, dan beliau berikan bendera kepadanya. Marhab lantas keluar dengan senjatannya dan mendendangkan bait-bait syair '# Khaibar telah tahu sesungguhnya aku Marhab # orang yang sangat pandai memainkan senjata # seorang pahlawan pemberani # Ketika peperangan datang dan menyala-nyala. 'Ali bin Abu Thalib karamahullahu wajhah lantas membalas bait-bait syairnya dengan mengatakan 'Sayalah orang yang diberi nama oleh ibuku Haidarah (salah satu nama singa) # layaknya singa hutan yang sangat menakutkan # akan saya penuhi mereka dengan sha' ukuran yang sangat besar #. Lalu Ali bin Abi Thalib karramahullahu wajhah berhasil membelah kepala Marhab dengan pedangnya dan kemenangan berhasil diraih dengan tangannya."},"1137":{"ar":"قَالَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا إِيَاسُ بْنُ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَقَدِمْنَا الْمَدِينَةَ زَمَنَ الْحُدَيْبِيَةِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجْنَا أَنَا وَرَبَاحٌ غُلَامُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَرَجْتُ بِفَرَسٍ لِطَلْحَةَ بْنِ عُبَيْدِ اللَّهِ كُنْتُ أُرِيدُ أَنْ أُبْدِيَهُ مَعَ الْإِبِلِ فَلَمَّا كَانَ بِغَلَسٍ غَارَ عَبْدُ الرَّحْمَنِ بْنُ عُيَيْنَةَ عَلَى إِبِلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَتَلَ رَاعِيَهَا وَخَرَجَ يَطْرُدُهَا هُوَ وَأُنَاسٌ مَعَهُ فِي خَيْلٍ فَقُلْتُ يَا رَبَاحُ اقْعُدْ عَلَى هَذَا الْفَرَسِ فَأَلْحِقْهُ بِطَلْحَةَ وَأَخْبِرْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَدْ أُغِيرَ عَلَى سَرْحِهِ قَالَ وَقُمْتُ عَلَى تَلٍّ فَجَعَلْتُ وَجْهِي مِنْ قِبَلِ الْمَدِينَةِ ثُمَّ نَادَيْتُ ثَلَاثَ مَرَّاتٍ يَا صَبَاحَاهْ ثُمَّ اتَّبَعْتُ الْقَوْمَ مَعِي سَيْفِي وَنَبْلِي فَجَعَلْتُ أَرْمِيهِمْ وَأَعْقِرُ بِهِمْ وَذَلِكَ حِينَ يَكْثُرُ الشَّجَرُ فَإِذَا رَجَعَ إِلَيَّ فَارِسٌ جَلَسْتُ لَهُ فِي أَصْلِ شَجَرَةٍ ثُمَّ رَمَيْتُ فَلَا يُقْبِلُ عَلَيَّ فَارِسٌ إِلَّا عَقَرْتُ بِهِ فَجَعَلْتُ أَرْمِيهِمْ وَأَنَا أَقُولُ أَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِفَأَلْحَقُ بِرَجُلٍ مِنْهُمْ فَأَرْمِيهِ وَهُوَ عَلَى رَاحِلَتِهِ فَيَقَعُ سَهْمِي فِي الرَّحْلِ حَتَّى انْتَظَمْتُ كَتِفَهُ فَقُلْتُ خُذْهَا وَأَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِفَإِذَا كُنْتُ فِي الشَّجَرِ أَحْرَقْتُهُمْ بِالنَّبْلِ فَإِذَا تَضَايَقَتْ الثَّنَايَا عَلَوْتُ الْجَبَلَ فَرَدَيْتُهُمْ بِالْحِجَارَةِ فَمَا زَالَ ذَاكَ شَأْنِي وَشَأْنَهُمْ أَتْبَعُهُمْ فَأَرْتَجِزُ حَتَّى مَا خَلَقَ اللَّهُ شَيْئًا مِنْ ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا خَلَّفْتُهُ وَرَاءَ ظَهْرِي فَاسْتَنْقَذْتُهُ مِنْ أَيْدِيهِمْ ثُمَّ لَمْ أَزَلْ أَرْمِيهِمْ حَتَّى أَلْقَوْا أَكْثَرَ مِنْ ثَلَاثِينَ رُمْحًا وَأَكْثَرَ مِنْ ثَلَاثِينَ بُرْدَةً يَسْتَخِفُّونَ مِنْهَا وَلَا يُلْقُونَ مِنْ ذَلِكَ شَيْئًا إِلَّا جَعَلْتُ عَلَيْهِ حِجَارَةً وَجَمَعْتُ عَلَى طَرِيقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا امْتَدَّ الضُّحَى أَتَاهُمْ عُيَيْنَةُ بْنُ ��َدْرٍ الْفَزَارِيُّ مَدَدًا لَهُمْ وَهُمْ فِي ثَنِيَّةٍ ضَيِّقَةٍ ثُمَّ عَلَوْتُ الْجَبَلَ فَأَنَا فَوْقَهُمْ فَقَالَ عُيَيْنَةُ مَا هَذَا الَّذِي أَرَى قَالُوا لَقِينَا مِنْ هَذَا الْبَرْحَ مَا فَارَقَنَا بِسَحَرٍ حَتَّى الْآنَ وَأَخَذَ كُلَّ شَيْءٍ فِي أَيْدِينَا وَجَعَلَهُ وَرَاءَ ظَهْرِهِ قَالَ عُيَيْنَةُ لَوْلَا أَنَّ هَذَا يَرَى أَنَّ وَرَاءَهُ طَلَبًا لَقَدْ تَرَكَكُمْ لِيَقُمْ إِلَيْهِ نَفَرٌ مِنْكُمْ فَقَامَ إِلَيْهِ مِنْهُمْ أَرْبَعَةٌ فَصَعِدُوا فِي الْجَبَلِ فَلَمَّا أَسْمَعْتُهُمْ الصَّوْتَ قُلْتُ أَتَعْرِفُونِي قَالُوا وَمَنْ أَنْتَ قُلْتُ أَنَا ابْنُ الْأَكْوَعِ وَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَطْلُبُنِي مِنْكُمْ رَجُلٌ فَيُدْرِكُنِي وَلَا أَطْلُبُهُ فَيَفُوتُنِي قَالَ رَجُلٌ مِنْهُمْ إِنْ أَظُنُّ قَالَ فَمَا بَرِحْتُ مَقْعَدِي ذَلِكَ حَتَّى نَظَرْتُ إِلَى فَوَارِسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُونَ الشَّجَرَ وَإِذَا أَوَّلُهُمْ الْأَخْرَمُ الْأَسَدِيُّ وَعَلَى أَثَرِهِ أَبُو قَتَادَةَ فَارِسُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى أَثَرِ أَبِي قَتَادَةَ الْمِقْدَادُ الْكِنْدِيُّ فَوَلَّى الْمُشْرِكُونَ مُدْبِرِينَ وَأَنْزِلُ مِنْ الْجَبَلِ فَأَعْرِضُ لِلْأَخْرَمِ فَآخُذُ بِعِنَانِ فَرَسِهِ فَقُلْتُ يَا أَخْرَمُ ائْذَنْ الْقَوْمَ يَعْنِي احْذَرْهُمْ فَإِنِّي لَا آمَنُ أَنْ يَقْطَعُوكَ فَاتَّئِدْ حَتَّى يَلْحَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ قَالَ يَا سَلَمَةُ إِنْ كُنْتَ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَتَعْلَمُ أَنَّ الْجَنَّةَ حَقٌّ وَالنَّارَ حَقٌّ فَلَا تَحُلْ بَيْنِي وَبَيْنَ الشَّهَادَةِ قَالَ فَخَلَّيْتُ عِنَانَ فَرَسِهِ فَيَلْحَقُ بِعَبْدِ الرَّحْمَنِ بْنِ عُيَيْنَةَ وَيَعْطِفُ عَلَيْهِ عَبْدُ الرَّحْمَنِ فَاخْتَلَفَا طَعْنَتَيْنِ فَعَقَرَ الْأَخْرَمُ بِعَبْدِ الرَّحْمَنِ وَطَعَنَهُ عَبْدُ الرَّحْمَنِ فَقَتَلَهُ فَتَحَوَّلَ عَبْدُ الرَّحْمَنِ عَنْ فَرَسِ الْأَخْرَمِ فَيَلْحَقُ أَبُو قَتَادَةَ بِعَبْدِ الرَّحْمَنِ فَاخْتَلَفَا طَعْنَتَيْنِ فَعَقَرَ بِأَبِي قَتَادَةَ وَقَتَلَهُ أَبُو قَتَادَةَ وَتَحَوَّلَ أَبُو قَتَادَةَ عَلَى فَرَسِ الْأَخْرَمِ ثُمَّ إِنِّي خَرَجْتُ أَعْدُو فِي أَثَرِ الْقَوْمِ حَتَّى مَا أَرَى مِنْ غُبَارِ صَحَابَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا وَيُعْرِضُونَ قَبْلَ غَيْبُوبَةِ الشَّمْسِ إِلَى شِعْبٍ فِيهِ مَاءٌ يُقَالُ لَهُ ذُو قَرَدٍ فَأَرَادُوا أَنْ يَشْرَبُوا مِنْهُ فَأَبْصَرُونِي أَعْدُو وَرَاءَهُمْ فَعَطَفُوا عَنْهُ وَاشْتَدُّوا فِي الثَّنِيَّةِ ثَنِيَّةِ ذِي بِئْرٍ وَغَرَبَتْ الشَّمْسُ فَأَلْحَقُ رَجُلًا فَأَرْمِيهِ فَقُلْتُ خُذْهَا وَأَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِقَالَ فَقَالَ يَا ثُكْلَ أُمِّ أَكْوَعَ بَكْرَةً قُلْتُ نَعَمْ أَيْ عَدُوَّ نَفْسِهِ وَكَانَ الَّذِي رَمَيْتُهُ بَكْرَةً فَأَتْبَعْتُهُ سَهْمًا آخَرَ فَعَلِقَ بِهِ سَهْمَانِ وَيَخْلُفُونَ فَرَسَيْنِ فَجِئْتُ بِهِمَا أَسُوقُهُمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمَاءِ الَّذِي جَلَّيْتُهُمْ عَنْهُ ذُوْ قَرَدٍ فَإِذَا بِنَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَمْسِ مِائَةٍ وَإِذَا بِلَالٌ قَدْ نَحَرَ جَزُورًا مِمَّا خَلَّفْتُ فَهُوَ يَشْوِي لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ كَبِدِهَا وَسَنَامِهَا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ خَلِّنِي فَأَنْتَخِبَ مِنْ أَصْحَابِكَ مِائَةً فَآخُذَ عَلَى الْكُفَّارِ عَشْوَةً فَلَا يَبْقَى مِنْهُمْ مُخْبِرٌ إِلَّا قَتَلْتُهُ قَالَ أَكُنْتَ فَاعِلًا ذَلِكَ يَا سَلَمَةُ قَالَ نَعَمْ وَالَّذِي أَكْرَمَكَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى رَأَيْتُ نَوَاجِذَهُ فِي ضُوءِ النَّارِ ثُمَّ قَالَ إِنَّهُمْ يُقْرَوْنَ الْآنَ بِأَرْضِ غَطَفَانَ فَجَاءَ رَجُلٌ مِنْ غَطَفَانَ فَقَالَ مَرُّوا عَلَى فُلَانٍ الْغَطَفَانِيِّ فَنَحَرَ لَهُمْ جَزُورًا قَالَ فَلَمَّا أَخَذُوا يَكْشِطُونَ جِلْدَهَا رَأَوْا غَبَرَةً فَتَرَكُوهَا وَخَرَجُوا هَرَبًا فَلَمَّا أَصْبَحْنَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ فُرْسَانِنَا الْيَوْمَ أَبُو قَتَادَةَ وَخَيْرُ رَجَّالَتِنَا سَلَمَةُ فَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَهْمَ الرَّاجِلِ وَالْفَارِسِ جَمِيعًا ثُمَّ أَرْدَفَنِي وَرَاءَهُ عَلَى الْعَضْبَاءِ رَاجِعِينَ إِلَى الْمَدِينَةِ فَلَمَّا كَانَ بَيْنَنَا وَبَيْنَهَا قَرِيبًا مِنْ ضَحْوَةٍ وَفِي الْقَوْمِ رَجُلٌ مِنْ الْأَنْصَارِ كَانَ لَا يُسْبَقُ جَعَلَ يُنَادِي هَلْ مِنْ مُسَابِقٍ أَلَا رَجُلٌ يُسَابِقُ إِلَى الْمَدِينَةِ فَأَعَادَ ذَلِكَ مِرَارًا وَأَنَا وَرَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْدِفِي قُلْتُ لَهُ أَمَا تُكْرِمُ كَرِيمًا وَلَا تَهَابُ شَرِيفًا قَالَ لَا إِلَّا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي خَلِّنِي فَلَأُسَابِقُ الرَّجُلَ قَالَ إِنْ شِئْتَ قُلْتُ أَذْهَبُ إِلَيْكَ فَطَفَرَ عَنْ رَاحِلَتِهِ وَثَنَيْتُ رِجْلَيَّ فَطَفَرْتُ عَنْ النَّاقَةِ ثُمَّ إِنِّي رَبَطْتُ عَلَيْهَا شَرَفًا أَوْ شَرَفَيْنِ يَعْنِي اسْتَبْقَيْتُ نَفْسِي ثُمَّ إِنِّي عَدَوْتُ حَتَّى أَلْحَقَهُ فَأَصُكَّ بَيْنَ كَتِفَيْهِ بِيَدَيَّ قُلْتُ سَبَقْتُكَ وَاللَّهِ أَوْ كَلِمَةً نَحْوَهَا قَالَ فَضَحِكَ وَقَالَ إِنْ أَظُنُّ حَتَّى قَدِمْنَا الْمَدِينَةَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Ikirimah bin 'Ammar] berkata; telah menceritakan kepada kami [Iyas bin Salamah bin Al Akwa'] dari [Bapaknya] berkata; kami datang ke Madinah pada masa Hudaibiyah bersama Rasulullah Shallallahu'alaihiwasallam, saya berangkat bersama Rabah, budak Rasulullah Shallallahu'alaihiwasallam dengan kendaraan Rasulullah Shallallahu'alaihiwasallam. Saya berangkat dengan membawa kuda milik Abu Thalhah bin 'Ubaidullah. Ketika itu saya hendak mengembalakan kudaku dan sekawanan untaku ke padang gembalaan. Sialnya ketika menjelang malam, Abdurrahman bin 'Uyainah menyerang unta-unta Rasulullah Shallallahu'alaihiwasallam dan dia membunuh penggembalanya, lantas dia menggiring unta-unta itu bersama beberapa orang kawannya dengan membawa kuda. Saya berkata; 'Wahai Rabah, duduklah pada kuda ini dan susullah Thalhah, beritahukanlah Rasulullah Shallallahu'alaihiwasallam bahwa unta ternaknya telah diserang.' (Salamah bin Al Akwa' radliyallahu'anhu) berkata; 'Saya berdiri pada anak bukit. Lalu saya arahkan wajahku ke arah Madinah lalu saya memangggil tiga kali: 'Tolonglah aku di pagi hari ini, tolonglah aku di pagi hari ini! '. Lalu saya membuntuti para perampok itu dengan membawa pedangku dan panahku. Tiada henti saya memanahi mereka untuk membunuh mereka, dan peristiwa itu kebetulan saat pepohonan bersemi. Ternyata lantas ada seorang penunggang kuda yang kembali mencari-cariku, dan saya hanya duduk menunggunya di pangkal pohon, lalu saya memanahinya. Rupanya dia tidak mau menyerahkan kudaku, kecuali saya harus membunuhnya. Saya pun memanah mereka lagi seraya melantunkan bait-bait syair: # Saya adalah Ibnu Al Akwa', # sekarang adalah hari hari kehinaan # Lantas saya berpapasan dengan salah seorang diantara mereka, saya lempari panah, dia tetap berada pada kendaraannya. Lalu panahku mengenai kendaraannya sampai saya bisa merusak pundaknya lalu saya melantunkan bait-bait syair # Ambillah! saya adalah Ibnu Al Akwa' # sekarang adalah hari kehinaan # Lalu saya bersembunyi pada sebuah pohon, dan saya membakar mereka ketapel untuk melemparkan api. Tatkala jalan yang ada pada bukit itu telah sempit, saya naik ke gunung, saya lempari mereka dengan batu, saya tetap melakukan hal itu. Keadaan mereka juga tetap seperti itu, saya terus membuntuti mereka sambil melantunkan bait-bait syair, tidaklah Allah menciptakan unta tunggangan Rasulullah Shallallahu'alaihiwasallam kecuali saya saya salip dengan kendaraanku. Lalu saya selamatkan unta-unta kendaraan itu dari tangan-tangan mereka, dan saya tetap memanah mereka, sampai musuh harus melepaskan panah lebih dari tiga puluh lemparan dan lebih dari tiga puluh pakaian dengan harapan mereka membawa beban lebih ringan. Dan tidaklah mereka melemparkan sebuah benda kecuali saya tindih dengan batu dan saya kumpulkan pada jalan Rasulullah Shallallahu'alaihiwasallam. Hingga saat waktu dluha datang, 'Uyainah bin Badar Al Fazari datang dalam rangka menolong mereka, mereka sedang berada di bukit yang sempit, lalu saya naik ke gunung, namun saya berada di gunung yang jauh diatas mereka. 'Uyainah berkata; apa sebenarnya yang saya lihat sekarang ini? Mereka menjawab, kami sedang menghindar dari keadaan yang sangat payah, yang tidak pernah membiarkan kami semenjak waktu sahur sampai sekarang dan dia mengambil setiap sesuatu yang ada pada tangan kami, dan diletakkannya di belakang untanya. 'Uyainah berkata; kalaulah dia tidak melihat di belakangnya ada pasukan pembantu yang mencari musuh, niscaya telah meninggalkan kalian. Hendaklah ada empat orang diantara kalian meladeni orang itu!. Lalu empat orang berdiri untuk memburu kediaman Al akwa', mereka naik ke gunung. Tatkala saya berteriak dan saya yakin mereka bisa mendengar suaraku, mereka bertanya 'Apakah kalian mengenaliku?. Mereka bertanya siapakah kamu?, saya menjawab, saya adalah Ibnu Al Akwa', demi Dzat yang telah memuliakan wajah Muhammad Shallallahu'alaihiwasallam, tidak mungkin ada seorang dari kalian yang memburuku lalu bisa menangkapku atau saya memburunya lalu dia selamat dari tangkapanku. Ada salah seorang dari mereka yang berkata; 'Saya kira begitu.' (Salamah bin Al Akwa' radliyallahu'anhu) berkata; maka saya tidak meninggalkan tempat dudukku sampai saya dapat melihat penunggang-penunggang kuda terbaik Rasulullah Shallallahu'alaihiwasallam yang menyelinap diantara pepohonan, yang pertama adalah Al Ahram Al Asadi dan setelahnya adalah Abu Qatadah, pasukan penunggang kuda Rasulullah Shallallahu'alaihiwasallam, dan setelahnya adalah Abu Qatadah Al Miqdad Al Kindi, lalu orang-orang musryrik lari meninggalkan dan turun dari gunung. Kontan saya menghadapi Ahram, lalu saya mengambil tali kudanya, saya katakan, 'Wahai Akhram, hati-hatilah terhadap kaum, sesungguhnya saya tidak percaya, mereka bisa menghalangi langkahmu dan pelanlah sampai Rasulullah Shallallahu'alaihiwasallam dan para sahabatnya datang. Akhram Al asady berkata; 'Wahai Salamah jika kamu beriman kepada Allah dan Hari Akhir, dan kamu tahu bahwa syurga itu benar, dan neraka adalah benar, janganlah kamu halangi antara aku dan kesyahidan. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; lalu saya lepaskan tali kuda (Ahram) lalu dia menyusul Abdurrahman bin 'Uyainah. Abdurrahman lantas berusaha menjauhinya. Keduanya saling bergantian menebas dengan pedangnya, lalu Ahram menyerang Abdurrahman dan Abdurrahman menebasnya sampai dapat membunuhnya. Lalu Abdurrahman berpindah ke kuda Al Ahram, lantas Abu Qatadah menyusul Abdurrahman, lalu mereka berdua saling menyerang, lalu dia dapat menyerang Abu Qatadah, namun akhir peperangan tanding ini Abu Qatadah dapat membunuhnya, lalu Abu Qatadah perpindah ke kuda Ahram. Lalu saya berlari membututi jejak kaum sampai saya tidak dapat melihat debu para sahabat Nabi Shallallahu'alaihiwasallam sedikit pun dan mereka (musuh) kembali menjelang terbenamnya matahari menuju jalan yang terletak antara bukit yang ada mata airnya yang bernama Dzu Qarad. Mereka hendak meminum airnya namun mereka melihatku, yang waktu itu saya berlari mengejar mereka dari belakang, lalu mereka menghindar darinya. Rupanya mereka merasa keberatan berada di bukit, yaitu bukit yang ada sumurnya dan matahari telah tenggelam. Lalu saya mengejar seorang laki-laki, saya serang dia dengan panah, lalu saya katakan kepadanya, # ambillah panahku, saya adalah Ibnu Al Akwa', # sekarang adalah hari kehinaan.# (Salamah bin Al Akwa' radliyallahu'anhu) berkata; lalu dia menjawab, 'Celaka, Inikah Al Akwa' yang pagi-pagi tadi mendatangkan kesialan bagiku? '. Saya menjawab, Ya, akulah Al akwa'. Musuh itulah yang saya lempari dengan anak panah pada pagi hari, lantas saya cecar dengan panah yang lain. Dua panahku berhasil mengenainya dan mereka meninggalkan dua kuda, lalu kedua kuda tersebut saya giring menuju Rasulullah Shallallahu'alaihiwasallam, saat itu beliau sedang berada di mata air yang sebelumnya kuusir musuh dari tempat itu, yaitu Dzu Qarad, ternyata Nabi Shallallahu'alaihiwasallam bersama limaratus orang sahabatnya dan Bilal telah menyembelih unta yang saya tinggalkan. Dia sedang membakarnya untuk Rasulullah Shallallahu'alaihiwasallam, Bilal membakar hati dan daging punggung. Lalu saya mendatangi Rasulullah Shallallahu'alaihiwasallam, lalu saya katakan: Wahai Rasulullah, Berilah aku kebebasan sehingga saya bisa memilih seratus orang diantara sahabat-sahabatmu. Lantas saya menyerang orang-orang kafir pada malam hari dan tidaklah tersisa dari mereka kecuali saya bantai. Beliau bertanya, apa kamu yang telah melakukan hal itu Wahai Salamah?, maka saya menjawab, ya demi yang telah memuliakanmu. Lalu Rasulullah Shallallahu'alaihiwasallam tertawa sampai saya bisa melihat gigi gerahamnya karena sinar api, lalu beliau bersabda: \"Sesungguhnya mereka sekarang sedang berada di Ghathafan\", lalu datanglah seorang laki-laki dari Ghathafan, lalu dia berkata; lewatilah pada seorang dari Ghathafan, lalu dia menyembelih untuk mereka unta sembelihan. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; tatkala mereka mulai meletkan kulitnya, lalu mereka melihat debu, lalu mereka meninggalkannya. Mereka kabur. Pada pagi harinya Rasulullah Shallallahu'alaihiwasallam bersabda: {\"Penunggang kuda terbaik pada hari ini adalah Abu Qatadah, sedangkan pejalan kaki terbaik adalah Salamah\" Lalu Rasulullah Shallallahu'alaihiwasallam memberikan kepadaku bagian bagi pejalan kaki dan bagian untuk penunggang kuda semuanya, lalu beliau memboncengkanku di belakang untanya Al 'Adlba` pulang ke Madinah. Tatkala jarak antara kami dengan Madinah itu mendekati waktu dluha, ada seorang laki-laki dari anggota kaum dari Anshar, dia tidak ada yang bisa mendahului, dia memanggil: adakah orang yang bisa mendahului, ketahuilah adakah seorang yang bisa mendahului sampai Madinah. Lalu dia mengulangi hal itu berkali-kali, sedangkan saya berada di belakang Rasulullah Shallallahu'alaihiwasallam, karena membonceng beliau. Saya berkata kepadanya, kenapa kamu tidak memuliakan orang yang mulia dan memberi pada orang yang utama. Dia menjawab, tidak kecuali Rasulullah Shallallahu'alaihiwasallam. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; saya berkata; Wahai Rasulullah, demi bapak dan ibu, biarkanlah saya akan saya dahului dia. Beliau bersabda: \"Jika kau mau\" Lalu saya berkata; saya akan menyusulmu, lalu dia melompat dari kendaraan (Rasulullah Shallallahu'alaihiwasallam) dan saya mengecualikan kedua kakiku, saya melompat dari unta, lalu saya mengikatnya ikat atau dua ikat, yaitu membiarkan diriku, lalu saya berlari sampai saya bisa menyusulnya, lalu saya pukul antara kedua pundaknya dengan kedua tanganku, lalu saya katakan kepadanya, saya bisa mendahuluimu demi Allah, atau kalimat yang semisalnya. (Salamah bin Al Akwa' radliyallahu'anhu) berkata; lalu dia tertawa dan berkata; saya kira harus sampai Madinah."},"1138":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ عُتْبَةَ قَالَ حَدَّثَنَا إِيَاسُ بْنُ سَلَمَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَلَّ عَلَيْنَا السَّيْفَ فَلَيْسَ مِنَّا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Ayyub bin 'Utbah] berkata; telah menceritakan kepada kami [Iyas bin Salamah] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menghunuskan pedang kepada kami maka dia bukan termasuk golongan kami.\""},"1139":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ يَزِيدَ عَنْ سَلَمَةَ أَنَّهُكَانَ يَتَحَرَّى مَوْضِعَ الْمُصْحَفِ وَذَكَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَحَرَّى ذَلِكَ الْمَكَانَوَكَانَ بَيْنَ الْمِنْبَرِ وَالْقِبْلَةِ مَمَرُّ شَاةٍ","id":"Telah menceritakan kepada kami [Hammad bin Mas'adah] dari [Yazid] dari [Salamah] sesungguhnya dia sangat memperhatikan tempat kitab alquran dan dia menyebutkan bahwa Rasulullah Shallallahu'alaihiwasallam sangat memperhatikan tempat itu dan antara mimbar dan kiblat seukuran tempat lewat kambing."},"1140":{"ar":"قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي السَّلِيلِ عَنْ عَجُوزٍ مِنْ بَنِي نُمَيْرٍأَنَّهَا رَمَقَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي بِالْأَبْطَحِ تُجَاهَ الْبَيْتِ قَبْلَ الْهِجْرَةِ قَالَ فَسَمِعَتْهُ يَقُولُ اللَّهُمَّ اغْفِرْ لِي ذَنْبِي خَطَئِي وَجَهْلِي","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hajjaj] berkata; telah mengabarkan kepada kami [Syu'bah] dari [Sa'id Al Jurairi] dari [Abu As Salil] dari [orang yang sudah tua bani Numair] sesungguhnya dia memperhatikan gerak-gerik Rasulullah Shallallahu'alaihiwasallam ketika shalat di Abthah menghadap Kiblat sebelum Hijrah. Saya mendengar beliau bersabda: \"ALLHUMMA IGHFIRLY DZANBY, KHATAI, WA JAHLI (Wahai Rabku, ampunilah dosaku, kesalahanku dan kebodohanku) \""},"1141":{"ar":"قَالَ حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا عُمَرُ بْنُ فَرُّوخَ قَالَ حَدَّثَنَا مُصْعَبُ بْنُ نُوحٍ الْأَنْصَارِيُّ قَالَأَدْرَكْتُ عَجُوزًا لَنَا كَانَتْ فِيمَنْ بَايَعْنَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَتَيْنَاهُ يَوْمًا فَأَخَذَ عَلَيْنَا أَنْ لَا تَنُحْنَ قَالَتْ الْعَجُوزُ يَا رَسُولَ اللَّهِ إِنَّ نَاسًا كَانُوا قَدْ أَسْعَدُونِي عَلَى مُصِيبَةٍ أَصَابَتْنِي وَإِنَّهُمْ أَصَابَتْهُمْ مُصِيبَةٌ وَأَنَا أُرِيدُ أَنْ أُسْعِدَهُمْ ثُمَّ إِنَّهَا أَتَتْهُ فَبَايَعَتْهُ وَقَالَتْ هُوَ الْمَعْرُوفُ الَّذِي قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا يَعْصِينَكَ فِي مَعْرُوفٍ }","id":"Telah menceritakan kepada kami [Abu Sa'id] telah menceritakan kepada kami ['Umar bin Farruh] berkata; telah menceritakan kepada kami [Mus'ab bin Nuh Al Anshary] berkata; Aku menjumpai [salah seorang wanita tua yang pernah berbaiat kepada Nabi Shallallahu'alaihiwasallam], berkata; kami mendatangi beliau pada suatu hari, lalu beliau menyuruh kami untuk tidak meratapi mayit. wanita tua tersebut berkata; \"Wahai Rasulullah, sesungguhnya orang-orang dulunya telah menghiburku ketika aku tertimpa musibah, maka ketika mereka mendapat musibah, akupun ingin menghibur mereka\". Kemudian wanita tua tersebut mendatangi beliau lalu dia berbaiat kepada beliau dalam perkara Maruf sebagaimana yang dikatakan Allah Azzawajalla, \"Janganlah kalian berbuat maksiat dalam perkara ma'ruf.\""},"1142":{"ar":"قَالَ أَنَسُ بْنُ عِيَاضٍ اللَّيْثِيُّ أَبُو ضَمْرَةَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ خُصَيْفَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنِ السَّائِبِ بْنِ خَلَّادٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَخَافَ أَهْلَ الْمَدِينَةِ ظُلْمًا أَخَافَهُ اللَّهُ وَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يَقْبَلُ اللَّهُ مِنْهُ يَوْمَ الْقِيَامَةِ صَرْفًا وَلَا عَدْلًا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Anas bin Iyadl Al Laitsi Abu Dlamrah] berkata; telah menceritakan kepadaku [Yazid bin Khusaifah] dari [Abdullah bin Abdurrahman bin Abu Sha'sha'ah] dari ['Atha` bin Yasar] dari [As Sa`ib bin Khallad] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menakut-nakuti penduduk Madinah secara aniaya, niscaya Allah menjadikannya takut dan dia mendapatkan laknat Allah, Malaikat dan manusia semuanya. Allah tidak menerima taubat ataupun tebusan darinya pada Hari Kiamat nanti.\""},"1143":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنِ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ عَنْ خَلَّادِ بْنِ السَّائِبِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ زَرَعَ زَرْعًا فَأَكَلَ مِنْهُ الطَّيْرُ أَوْ الْعَافِيَةُ كَانَ لَهُ بِهِ صَدَقَةٌ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Usamah bin Zaid] dari [Al Muthallib bin Abdullah bin Hanthab] dari [Khallad bin As Sa`ib] dari [bapaknya] berkata Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menanam tanaman kemudian tanaman tersebut dimakan oleh burung atau binatang buas maka kesemua tadi terhitung sedekah baginya\""},"1144":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ قَالَ حَدَّثَنَا رِشْدِينُ قَالَ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ يَعْنِي ابْنَ الْهَادِ عَنْ أَبِي بَكْرِ بْنِ الْمُنْكَدِرِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنِ السَّائِبِ بْنِ خَلَّادٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا مِنْ شَيْءٍ يُصِيبُ الْمُؤْمِنَ حَتَّى الشَّوْكَةِ تُصِيبُهُ إِلَّا كَتَبَ اللَّهُ لَهُ بِهَا حَسَنَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Ghailan] berkata; telah menceritakan kepada kami [Risydin] berkata; telah menceritakan kepadaku [Yazid bin Abdullah] yaitu Ibnu Al Hadi dari [Abu Bakar bin Al Munkadir] dari ['Atha` bin Yasar] dari [As Sa'ib bin Khallad] dari Rasulullah Shallallahu'alaihiwasallam sesungguhnya beliau bersabda: \"Segala sesuatu yang mengenai seorang mukmin hingga duri yang melukainya kecuali Allah mencatat kebaikan baginya dan menghapuskan kesalahannya.\""},"1145":{"ar":"قَالَ حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بَكْرِ بْنِ سَوَادَةَ الْجُذَامِيِّ عَنْ صَالِحِ بْنِ خَيْوَانَ عَنْ أَبِي سَهْلَةَ السَّائِبِ بْنِ خَلَّادٍأَنَّ رَجُلًا أَمَّ قَوْمًا فَبَصَقَ فِي الْقِبْلَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ فَرَغَ لَا يُصَلِّ لَكُمْ فَأَرَادَ بَعْدَ ذَلِكَ أَنْ يُصَلِّيَ لَهُمْ فَمَنَعُوهُ وَأَخْبَرُوهُ بِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ نَعَمْ وَحَسِبْتُ أَنَّهُ قَالَ آذَيْتَ اللَّهَ عَزَّ وَجَلَّ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Suraij bin an-Nu'man] berkata; telah menceritakan kepada kami [Abdullah bin Wahab] dari ['Amr bin Al Harits] dari [Bakar bin Sawadah Al Judzami] dari [Shalih bin Khaiwah] dari [Abu Sahlah, As Saib bin Khallad] Pernah seorang laki-laki menjadi imam bagi suatu kaum lalu dia berludah di arah kiblah dan Rasulullah Shallallahu'alaihiwasallam melihatnya. Selesai shalat, Rasulullah Shallallahu'alaihiwasallam bersabda 'Jangan sesekali dia menjadi (imam) shalat kalian lagi', kemudian hari orang itu ingin mengulangi shalat bersama mereka, lalu para jamaah melarangnya dan memberitahukan kepadanya perkataan Rasulullah Shallallahu'alaihiwasallam, kemudian hal tersebut dilaporkan kepada Rasulullah Shallallahu'alaihiwasallam, yang beliau kira-kira bersabda: \"Engkau telah melukai Allah Azzawajalla \""},"1146":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُسْلِمِ بْنِ أَبِي مَرْيَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنِ السَّائِبِ بْنِ خَلَّادٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَخَافَ الْمَدِينَةَ أَخَافَهُ اللَّهُ عَزَّ وَجَلَّ وَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يَقْبَلُ اللَّهُ مِنْهُ صَرْفًا وَلَا عَدْلًا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdushshomad] berkata; telah menceritakan kepadaku [bapakku] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muslim bin Abu Maryam] dari ['Atha` bin Yasar] dari [As Sa'ib bin Khallad] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menakut-nakuti Madinah niscaya Allah Azzawajalla menjadikannya takut dan dia mendapatkan laknat Allah, para Malaikat dan manusia semuanya. Allah tidak menerima taubat atau pun tebusan darinya.\""},"1147":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ حَبَّانَ بْنِ وَاسِعٍ عَنْ خَلَّادِ بْنِ السَّائِبِ الْأَنْصَارِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَأَلَ جَعَلَ بَاطِنَ كَفَّيْهِ إِلَيْهِ وَإِذَا اسْتَعَاذَ جَعَلَ ظَاهِرَهُمَا إِلَيْهِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Ishaq] telah mengabarkan kepada kami [Ibnu Lahi'ah] dari [Habban bin Wasi'] dari [Khallad bin As Sa`ib Al Anshary] sesungguhnya Nabi Shallallahu'alaihiwasallam apabila meminta (dalam berdoa) menjadikan kedua telapak tangannya menghadap ke wajahnya dan jika meminta perlindungan beliau membaliknya."},"1148":{"ar":"قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ قَالَ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي يَزِيدُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ الْأَنْصَارِيِّ أَنَّ عَطَاءَ بْنَ يَسَارٍ أَخْبَرَهُ أَنَّ السَّائِبَ بْنَ خَلَّادٍ أَخَا بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَخَافَ أَهْلَ الْمَدِينَةِ ظَالِمًا أَخَافَهُ اللَّهُ وَكَانَتْ عَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ عَدْلٌ وَلَا صَرْفٌ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Sulaiman bin Daud Al Hasyimi] berkata; telah menceritakan kepada kami [Isma'il bin Ja'far] berkata; telah mengabarkan kepadaku [Yazid] dari [Abdurrahman bin Abu Sha'sha'ah Al Anshari] sesungguhnya ['Atha` bin Yasar] mengabarinya, sesungguhnya [As Sa'ib bin Khallad] dari Bani Al Harits bin Al Khazraj mengabarinya sesungguhnya Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa menakut-nakuti penduduk Madinah secara aniaya, Allah menjadikannya takut dan dia mendapatkan laknat Allah, para Malaikat dan manusia semuanya. tidak akan diterima taubat ataupun tebusan darinya.\""},"1149":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ حَدَّثَنَا مَالِكٌ وحَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا مَالِكٌ يَعْنِي ابْنَ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ خَلَّادِ بْنِ السَّائِبِ الْأَنْصَارِيِّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ أَنْ آمُرَ أَصْحَابِي أَوْ مَنْ مَعِي أَنْ يَرْفَعُوا أَصْوَاتَهُمْ بِالتَّلْبِيَةِ أَوْ بِالْإِهْلَالِ يُرِيدُ أَحَدَهُمَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; saya membaca di hadapan [Abdurrahman bin Mahdi]: telah menceritakan kepada kami [Malik] dan telah menceritakan kepada kami [Rauh] berkata; telah menceritakan kepada kami [Malik] yaitu Ibnu Anas dari [Abdullah bin Abu Bakar bin Muhammad bin 'Amr bin Hazam] dari [Abdul Malik bin Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] dari [Khallad bin As Sa'ib Al Anshari] dari [Bapaknya] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Malaikat Jibril 'Alaihissalam mendatangiku lalu berkata; 'Agar saya memerintahkanlah kepada para sahabatku atau siapa yang bersamaku untuk mengangkat suara mereka pada waktu talbiyah atau Ihlal (melafadkan niat dan mengucapkan talbiyah dalam Haji) \". Yang beliau maksudkan salah satunya."},"1150":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ وَرَوْحٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ كَتَبَ إِلَيَّ عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ يَقُولُ حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ أَبِي بَكْرِ بْنِ الْحَارِثِ أَنَّهُ حَدَّثَهُ خَلَّادُ بْنُ السَّائِبِ بْنِ سُوَيْدٍ الْأَنْصَارِيُّ عَنْ أَبِيهِ السَّائِبِ بْنِ خَلَّادٍ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تَأْمُرَ أَصْحَابَكَ أَنْ يَرْفَعُوا أَصْوَاتَهُمْ بِالتَّلْبِيَةِ وَالْإِهْلَالِ وَقَالَ رَوْحٌ بِالتَّلْبِيَةِ أَوْ بِالْإِهْلَالِ قَالَ وَلَا أَدْرِي أَيُّنَا وَهِلَ أَنَا وَعَبْدُ اللَّهِ أَوْ خَلَّادٌ فِي الْإِهْلَالِ أَوْ التَّلْبِيَةِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Bakar] berkata; telah mengabarkan kepada kami [Ibnu Juraij] dan [Rouh] berkata; telah menceritakan kepada kami [Ibnu Juraij] berkata; [Abdullah bin Abu Bakar bin Muhammad bin 'Amr bin Hazam] menulis kepadaku, berkata; telah menceritakan kepadaku [Abdul Malik bin Abu Bakar bin Al Harits] sesungguhnya dia menceritakannya, dari [Khallad bin As Sa'ib bin Suwaid Al Anshari] dari [Bapaknya, As Sa'ib bin Khallad] sesungguhnya dia telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Malaikat Jibril 'Alaihissalam telah mendatangiku lalu berkata; Allah telah memerintahkan kepadamu agar kamu menyuruh para sahabatmu untuk mengangkat suara mereka pada waktu talbiyah dan Ihlal (melafadkan niat dan mengucapkan talbiyah dalam Haji) \". [Rauh] berkata; talbiyah atau ihlal, dia berkata; saya tidak tahu siapa yang lupa saya atau Abdullah atau Khallad dalam ihlal atau talbiyah."},"1151":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرِ بْنِ الْحَارِثِ عَنْ خَلَّادِ بْنِ السَّائِبِ بْنِ خَلَّادٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام وَقَالَ مُرْ أَصْحَابَكَ فَلْيَرْفَعُوا أَصْوَاتَهُمْ بِالْإِهْلَالِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Abu Bakar] dari [Abdul Malik bin Abu Bakar bin Al Harits] dari [Khallad bin As Sa'ib bin Al Khallad] dari [Bapaknya] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Malaikat Jibril 'Alaihissalam telah mendatangiku lalu berkata; perintahkan para sahabatmu untuk mengangkat suara mereka pada waktu Ihlal (melafadzkan niat dan mengucapkan talbiyah dalam Haji) \"."},"1152":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ حَنْظَلَةَ بْنِ عَلِيٍّ الْأَسْلَمِيِّ عَنْ خُفَافِ بْنِ إِيمَاءِ بْنِ رَحَضَةَ الْغِفَارِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ وَنَحْنُ مَعَهُ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ الْآخِرَةِ قَالَ لَعَنَ اللَّهُ لِحْيَانًا وَرِعْلًا وَذَكْوَانَ وَعُصَيَّةَ عَصَتْ اللَّهَ وَرَسُولَهُ أَسْلَمُ سَالَمَهَا اللَّهُ وَغِفَارٌ غَفَرَ اللَّهُ لَهَا ثُمَّ وَقَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاجِدًا فَلَمَّا انْصَرَفَ قَرَأَ عَلَى النَّاسِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنِّي أَنَا لَسْتُ قُلْتُهُ وَلَكِنَّ اللَّهَ عَزَّ وَجَلَّ قَالَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Imran bin Abu Anas] dari [Hanzhalah bin 'Ali Al Aslami] dari [Khufaf bin Ima`i bin Rahadlah Al Ghiffary] berkata; Rasulullah Shallallahu'alaihiwasallam shalat subuh bersama kami. Tatkala beliau mengangkat kepala beliau dari ruku pada rekaat terakhir membaca, \"Semoga Allah melaknat kaum Lihyan, Ri'il, Dzakwan dan 'Ushayyah, mereka telah bermaksiat kepada Allah dan Rasul-Nya, Aslam semoga Allah menyelamatkannya. Ghifar, semoga Allah mengampuninya\". Lalu Rasulullah Shallallahu'alaihiwasallam ke turun bersujud. Tatkala selesai shalat, beliau berkata; \"Wahai orang-orang, bukanlah aku yang berkata tadi dalam shalat tapi Allah-lah yang berkata\""},"1153":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ بْنِ حَرْمَلَةَ عَنِ الْحَارِثِ بْنِ خُفَافٍ عَنْ أَبِيهِ خُفَافِ بْنِ إِيمَاءِ بْنِ رَحَضَةَ الْغِفَارِيِّ قَالَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ غِفَارٌ غَفَرَ اللَّهُ لَهَا وَأَسْلَمُ سَالَمَهَا اللَّهُ وَعُصَيَّةُ عَصَتْ اللَّهَ وَرَسُولَهُ اللَّهُمَّ الْعَنْ بَنِي لَحْيَانَ اللَّهُمَّ الْعَنْ رِعْلًا وَذَكْوَانَ ثُمَّ كَبَّرَ وَوَقَعَ سَاجِدًاقَالَ خُفَافٌ فَجُعِلَتْ لَعْنَةُ الْكَفَرَةِ مِنْ أَجْلِ ذَلِكَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Khalid bin Abdullah bin Harmalah] dari [Al Harits bin Khufaf] dari Bapaknya [Khufaf bin Ima`i bin Rahadlah Al Ghiffary] berkata; Rasulullah Shallallahu'alaihiwasallam rukuk dalam shalatnya lalu mengangkat kepalanya lalu membaca, \"Ghifar, semoga Allah mengampuninya dan Aslam, semoga Allah menyelamatkannya. 'Ushayyah, mereka telah bermaksiat kepada Allah dan Rasul-Nya. Ya Allah, laknatlah Bani Lihyan, Ya Allah, laknatlah Ri'il dan Dzakwan\" lalu beliau membaca takbir dan bersujud. Khufaf berkata; lalu dijadikan laknat pada orang kafir karena hal itu."},"1154":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثْنِي عَنْ افْتِرَاشِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخِذَهُ الْيُسْرَى فِي وَسَطِ الصَّلَاةِ وَفِي آخِرِهَا وَقُعُودِهِ عَلَى وَرِكِهِ الْيُسْرَى وَوَضْعِهِ يَدَهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى وَنَصْبِهِ قَدَمَهُ الْيُمْنَى وَوَضْعِهِ يَدَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى وَنَصْبِهِ أُصْبُعَهُ السَّبَّابَةَ يُوَحِّدُ بِهَا رَبَّهُ عَزَّ وَجَلَّ عِمْرَانُ بْنُ أَبِي أَنَسٍ أَخُو بَنِي عَامِرِ بْنِ لُؤَيٍّ وَكَانَ ثِقَةً عَنْ أَبِي الْقَاسِمِ مِقْسَمٍ مَوْلَى عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ قَالَ حَدَّثَنِي رَجُلٌ مِنْ أَهْلِ الْمَدِينَةِ قَالَصَلَّيْتُ فِي مَسْجِدِ بَنِي غِفَارٍ فَلَمَّا جَلَسْتُ فِي صَلَاتِي افْتَرَشْتُ فَخِذِي الْيُسْرَى وَنَصَبْتُ السَّبَّابَةَ قَالَ فَرَآنِي خُفَافُ بْنُ إِيمَاءِ بْنِ رَحَضَةَ الْغِفَارِيُّ وَكَانَ لَهُ صُحْبَةٌ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَصْنَعُ ذَلِكَ قَالَ فَلَمَّا انْصَرَفْتُ مِنْ صَلَاتِي قَالَ لِي أَيْ بُنَيَّ لِمَ نَصَبْتَ إِصْبَعَكَ هَكَذَا قَالَ وَمَا تُنْكِرُ رَأَيْتُ النَّاسَ يَصْنَعُونَ ذَلِكَ قَالَ فَإِنَّكَ أَصَبْتَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى يَصْنَعُ ذَلِكَ فَكَانَ الْمُشْرِكُونَ يَقُولُونَ إِنَّمَا يَصْنَعُ هَذَا مُحَمَّدٌ بِإِصْبَعِهِ يَسْحَرُهَا وَكَذَبُوا إِنَّمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ ذَلِكَ يُوَحِّدُ بِهَا رَبَّهُ عَزَّ وَجَلَّ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata; telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] berkata; dia telah menceritakan kepadaku tentang membentangkannya Rasulullah Shallallahu'alaihiwasallam pada lutut kirinya di tengah-tengah shalat dan pada akhirnya. dan duduknya beliau pada pangkal paha yang kiri. Dan meletakkan tangan kirinya pada lututnya yang kiri dengan menegakkan kaki kanannya.Lalu dia meletakkan tangan kanannya pada lutut kanannya dan meluruskan jari telunjuknya sebagai isyarat mengesakan Rabnya 'Azzawajalla. ['Imran bin Abu Anas], adalah dari Bani 'Ami bin Lu'ay, dia tsiqqah dari [Abu Al Qasim Miqsam] budak Abdullah bin Al Harits bin Naufal, berkata; telah menceritakan kepadaku [salah seorang penduduk Madinah], berkata; saya telah shalat di masjid Bani Ghifar. Tatkala saya duduk dalam shalatku, lalu saya membentangkan lutut kiriku dan saya menegakkan jari telunjukku. (seorang dari Bani Ghifar Radliyallahu'anhum) berkata; [Khufaf bin Ima`i bin Rahadlah Al Ghiffary] melihatku, dia adalah salah seorang sahabat Rasulullah Shallallahu'alaihiwasallam, saya melakukan hal itu. (seorang dari Bani Ghifar Radliyallahu'anhum) berkata; tatkala saya telah selesai dari shalatku, dia berkata kepadaku, Wahai anakku, kenapa kamu meluruskan jarimu demikian. Kenapa kamu mengingkari, saya telah melihat orang-orang melakukan hal itu. Dia berkata; sesungguhnya kamu benar, sesungguhnya Rasulullah Shallallahu'alaihiwasallam jika beliau shalat melakukan hal itu, namun orang-orang musyrik mengatakan Muhammad melakukan itu dengan jarinya untuk menyihirnya dan mereka mendustakannya. Rasulullah Shallallahu'alaihiwasallam melakukan hal itu dalam rangka mengesakan Rabnya 'Azzawajalla."},"1155":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنِ الْوَلِيدِ بْنِ الْوَلِيدِ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنِّي أَجِدُ وَحْشَةً قَالَ إِذَا أَخَذْتَ مَضْجَعَكَ فَقُلْ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ غَضَبِهِ وَعِقَابِهِ وَشَرِّ عِبَادِهِ وَمِنْ هَمَزَاتِ الشَّيَاطِينِ وَأَنْ يَحْضُرُونِ فَإِنَّهُ لَا يُضَرُّ وَبِالْحَرِيِّ أَنْ لَا يَقْرَبَكَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Al Walid bin Al Walid] sesungguhnya dia berkata; Wahai Rasulullah, aku bermimpi buruk, maka beliau bersabda: \"Jika kamu ingin tidur maka bacalah, 'AUUDZU BIKALIMATILLAAHI ATTAAMMAH MIN GHADZABIHI WA IQAABIHI WA SYARRI 'IBAADIHI WA MIN HAMAZAATIS SYAYAATHIINA (Aku berlindung diri dengan kalimah Allah yang sempurna dari amarah-Nya, hukuman-Nya, dan sesuatu yang buruk dari hamba-Nya serta dari hembusan setan) ' (jika kamu membaca doa ini) tak bakalan mereka mendatangkan keburukan bagimu, apalagi mendekatimu\""},"1156":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ رَبِيعَةَ بْنِ كَعْبٍ الْأَسْلَمِيِّ قَالَكُنْتُ أَنَامُ فِي حُجْرَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ أَسْمَعُهُ إِذَا قَامَ مِنْ اللَّيْلِ ي��صَلِّي يَقُولُ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ الْهَوِيَّ قَالَ ثُمَّ يَقُولُ سُبْحَانَ اللَّهِ الْعَظِيمِ وَبِحَمْدِهِ الْهَوِيَّ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Rabi'ah bin Kaab bin Al Aslamy] berkata; saya tidur di kamar Nabi Shallallahu'alaihiwasallam. Saya dapat mendengar beliau ketika shalat malam berdoa, 'ALHAMDULILLAH RABBIL ALAMIN AL HAWIY (Segala puji bagi Allah Rabb sekalian alam, Dzat yang hidup dalam masa yang panjang), kemudian berdoa, \"SUBHANALLAH AL AZDIM WA BIHAMDIH AL HAWY (Segala puji bagi Allah Yang Maha Agung dan dengan pujian kepada-Nya, Dzat yang hidup dalam masa Yang Panjang) "},"1157":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ حَدَّثَنِي رَبِيعَةُ بْنُ كَعْبٍ الْأَسْلَمِيُّ قَالَكُنْتُ أَبِيتُ عِنْدَ بَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُعْطِيهِ وَضُوءَهُ فَأَسْمَعُهُ بَعْدَ هَوِيٍّ مِنْ اللَّيْلِ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَأَسْمَعُهُ بَعْدَ هَوِيٍّ مِنْ اللَّيْلِ يَقُولُ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdul Malik bin 'Amir] berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah] berkata; telah menceritakan kepadaku [Rabi'ah bin Kaab bin Al Aslamy] berkata; saya menginap di rumah Rasulullah Shallallahu'alaihiwasallam. Saya hendak memberikan air wudlunya, saya mendengarnya setelah berlangsung waktu yang lama pada malam itu, beliau membaca, \"SAMI'A ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar siapa saja yang memujinya), dan pada malam harinya yang sudah sangat malam, membaca: ALHAMDU LILLAHI RABBIL 'ALAMIN (segala puji bagi Allah Rabb semesta alam) \""},"1158":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ رَبِيعَةَ بْنِ كَعْبٍ الْأَسْلَمِيِّ قَالَكُنْتُ أَبِيتُ عِنْدَ بَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُعْطِيهِ وَضُوءَهُ فَأَسْمَعُهُ بَعْدَ هَوِيٍّ مِنْ اللَّيْلِ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَالْهَوِيِّ مِنْ اللَّيْلِ يَقُولُ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Hisyam Ad-Dastuwan`i] berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Rabi'ah bin Kaab Al Aslami] berkata; saya menginap pada rumah Rasulullah Shallallahu'alaihiwasallam dan saya memberikan air wudlu kepada beliau, lalu saya mendengarnya pada malam harinya membaca \"SAMI'A ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar siapa yang memuji-Nya), dan pada malam harinya yang sudah sangat malam, membaca: ALHAMDU LILLAHI RABBIL 'ALAMIN (segala puji bagi Allah Rabb semesta alam) \""},"1159":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا الْمُبَارَكُ يَعْنِي ابْنَ فَضَالَةَ قَالَ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ رَبِيعَةَ الْأَسْلَمِيِّ قَالَكُنْتُ أَخْدُمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَبِيعَةُ أَلَا تَزَوَّجُ قَالَ قُلْتُ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا أُرِيدُ أَنْ أَتَزَوَّجَ مَا عِنْدِي مَا يُقِيمُ الْمَرْأَةَ وَمَا أُحِبُّ أَنْ يَشْغَلَنِي عَنْكَ شَيْءٌ فَأَعْرَضَ عَنِّي فَخَدَمْتُهُ مَا خَدَمْتُهُ ثُمَّ قَالَ لِي الثَّانِيَةَ يَا رَبِيعَةُ أَلَا تَزَوَّجُ فَقُلْتُ مَا أُرِيدُ أَنْ أَتَزَوَّجَ مَا عِنْدِي مَا يُقِيمُ الْمَرْأَةَ وَمَا أُحِبُّ أَنْ يَشْغَلَنِي عَنْكَ شَيْءٌ فَأَعْرَضَ عَنِّي ثُمَّ رَجَعْتُ إِلَى نَفْسِي فَقُلْتُ وَاللَّهِ لَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا يُصْلِحُنِي فِي الدُّنْيَا وَالْآخِرَةِ أَعْلَمُ مِنِّي وَاللَّهِ لَئِنْ قَالَ تَزَوَّجْ لَأَقُولَنَّ نَعَمْ يَا رَسُولَ اللَّهِ مُرْنِي بِمَا شِئْتَ قَالَ فَقَالَ يَا رَبِيعَةُ أَلَا تَزَوَّجُ فَقُلْتُ بَلَى مُرْنِي بِمَا شِئْتَ قَالَ انْطَلِقْ إِلَى آلِ فُلَانٍ حَيٍّ مِنْ الْأَنْصَارِ وَكَانَ فِيهِمْ تَرَاخٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْ لَهُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَنِي إِلَيْكُمْ يَأْمُرُكُمْ أَنْ تُزَوِّجُونِي فُلَانَةَ لِامْرَأَةٍ مِنْهُمْ فَذَهَبْتُ فَقُلْتُ لَهُمْ إِنَّ رَسُولَ اللَّهِ أَرْسَلَنِي إِلَيْكُمْ يَأْمُرُكُمْ أَنْ تُزَوِّجُونِي فُلَانَةَ فَقَالُوا مَرْحَبًا بِرَسُولِ اللَّهِ وَبِرَسُولِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ لَا يَرْجِعُ رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا بِحَاجَتِهِ فَزَوَّجُونِي وَأَلْطَفُونِي وَمَا سَأَلُونِي الْبَيِّنَةَ فَرَجَعْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَزِينًا فَقَالَ لِي مَا لَكَ يَا رَبِيعَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَيْتُ قَوْمًا كِرَامًا فَزَوَّجُونِي وَأَكْرَمُونِي وَأَلْطَفُونِي وَمَا سَأَلُونِي بَيِّنَةً وَلَيْسَ عِنْدِي صَدَاقٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بُرَيْدَةُ الْأَسْلَمِيُّ اجْمَعُوا لَهُ وَزْنَ نَوَاةٍ مِنْ ذَهَبٍ قَالَ فَجَمَعُوا لِي وَزْنَ نَوَاةٍ مِنْ ذَهَبٍ فَأَخَذْتُ مَا جَمَعُوا لِي فَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اذْهَبْ بِهَذَا إِلَيْهِمْ فَقُلْ هَذَا صَدَاقُهَا فَأَتَيْتُهُمْ فَقُلْتُ هَذَا صَدَاقُهَا فَرَضُوهُ وَقَبِلُوهُ وَقَالُوا كَثِيرٌ طَيِّبٌ قَالَ ثُمَّ رَجَعْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَزِينًا فَقَالَ يَا رَبِيعَةُ مَا لَكَ حَزِينٌ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا رَأَيْتُ قَوْمًا أَكْرَمَ مِنْهُمْ رَضُوا بِمَا آتَيْتُهُمْ وَأَحْسَنُوا وَقَالُوا كَثِيرًا طَيِّبًا وَلَيْسَ عِنْدِي مَا أُولِمُ قَالَ يَا بُرَيْدَةُ اجْمَعُوا لَهُ شَاةً قَالَ فَجَمَعُوا لِي كَبْشًا عَظِيمًا سَمِينًا فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ إِلَى عَائِشَةَ فَقُلْ لَهَا فَلْتَبْعَثْ بِالْمِكْتَلِ الَّذِي فِيهِ الطَّعَامُ قَالَ فَأَتَيْتُهَا فَقُلْتُ لَهَا مَا أَمَرَنِي بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ هَذَا الْمِكْتَلُ فِيهِ تِسْعُ آصُعِ شَعِيرٍ لَا وَاللَّهِ إِنْ أَصْبَحَ لَنَا طَعَامٌ غَيْرُهُ خُذْهُ فَأَخَذْتُهُ فَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْبَرْتُهُ مَا قَالَتْ عَائِشَةُ فَقَالَ اذْهَبْ بِهَذَا إِلَيْهِمْ فَقُلْ لِيُصْبِحْ هَذَا عِنْدَكُمْ خُبْزًا فَذَهَبْتُ إِلَيْهِمْ وَذَهَبْتُ بِالْكَبْشِ وَمَعِي أُنَاسٌ مِنْ أَسْلَمَ فَقَالَ لِيُصْبِحْ هَذَا عِنْدَكُمْ خُبْزًا وَهَذَا طَبِيخًا فَقَالُوا أَمَّا الْخُبْزُ فَسَنَكْفِيكُمُوهُ وَأَمَّا الْكَبْشُ فَاكْفُونَا أَنْتُمْ فَأَخَذْنَا الْكَبْشَ أَنَا وَأُنَاسٌ مِنْ أَسْلَمَ فَذَبَحْنَاهُ وَسَلَخْنَاهُ وَطَبَخْنَاهُ فَأَصْبَحَ عِنْدَنَا خُبْزٌ وَلَحْمٌ فَأَوْلَمْتُ وَدَعَوْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَانِي أَرْضًا وَأَعْطَانِي أَبُو بَكْرٍ أَرْضًا وَجَاءَتْ الدُّنْيَا فَاخْتَلَفْنَا فِي عِذْقِ نَخْلَةٍ فَقُلْتُ أَنَا هِيَ فِي حَدِّي وَقَالَ أَبُو بَكْرٍ هِيَ فِي حَدِّي فَكَانَ بَيْنِي وَبَيْنَ أَبِي بَكْرٍ كَلَامٌ فَقَالَ أَبُو بَكْرٍ كَلِمَةً كَرِهَهَا وَنَدِمَ فَقَالَ لِي يَا رَبِيعَةُ رُدَّ عَلَيَّ مِثْلَهَا حَتَّى تَكُونَ قِصَاصًا قَالَ قُلْتُ لَا أَفْعَلُ فَقَالَ أَبُو بَكْرٍ لَتَقُولَنَّ أَوْ لَأَسْتَعْدِيَنَّ عَلَيْكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مَا أَنَا بِفَاعِلٍ قَالَ وَرَفَضَ الْأَرْضَ وَانْطَلَقَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْطَلَقْتُ أَتْلُوهُ فَجَاءَ نَاسٌ مِنْ أَسْلَمَ فَقَالُوا لِي رَحِمَ اللَّهُ أَبَا بَكْرٍ فِي أَيِّ شَيْءٍ يَسْتَعْدِي عَلَيْكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَالَ لَكَ مَا قَالَ فَقُلْتُ أَتَدْرُونَ مَا هَذَا هَذَا أَبُو بَكْرٍ الصِّدِّيقُ هَذَا ثَانِيَ اثْنَيْنِ وَهَذَا ذُو شَيْبَةِ الْمُسْلِمِينَ إِيَّاكُمْ لَا يَلْتَفِتُ فَيَرَاكُمْ تَنْصُرُونِي عَلَيْهِ فَيَغْضَبَ فَيَأْتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَغْضَبَ لِغَضَبِهِ فَيَغْضَبَ اللَّهُ عَزَّ وَجَلَّ لِغَضَبِهِمَا فَيُهْلِكَ رَبِيعَةَ قَالُوا مَا تَأْمُرُنَا قَالَ ارْجِعُوا قَالَ فَانْطَلَقَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَبِعْتُهُ وَحْدِي حَتَّى أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثَهُ الْحَدِيثَ كَمَا كَانَ فَرَفَعَ إِلَيَّ رَأْسَهُ فَقَالَ يَا رَبِيعَةُ مَا لَكَ وَلِلصِّدِّيقِ قُلْتُ يَا رَسُولَ اللَّهِ كَانَ كَذَا كَانَ كَذَا قَالَ لِي كَلِمَةً كَرِهَهَا فَقَالَ لِي قُلْ كَمَا قُلْتُ حَتَّى يَكُونَ قِصَاصًا فَأَبَيْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَلْ فَلَا تَرُدَّ عَلَيْهِ وَلَكِنْ قُلْ غَفَرَ اللَّهُ لَكَ يَا أَبَا بَكْرٍ فَقُلْتُ غَفَرَ اللَّهُ لَكَ يَا أَبَا بَكْرٍقَالَ الْحَسَنُ فَوَلَّى أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ وَهُوَ يَبْكِي","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr Hasyim bin Al Qasim] berkata; telah menceritakan kepada kami [Al Mubarak] yaitu Ibnu Fadlalah berkata; telah menceritakan kepada kami [Abu 'Imran Al Jauni] dari [Rabi'ah Al Aslami] berkata; saya melayani Rasulullah Shallallahu'alaihiwasallam lalu beliau bersabda: \"Wahai Rabi'ah, kenapa kamu tidak menikah?\" (Rabi'ah Al Aslami radliyallahu'anhu) berkata; \"Demi Allah, Wahai Rasulullah, saya tidak mau menikah, saya tidak mempunyai sesuatu unuk menanggung beban-beban pernikahan, saya juga tidak mau jika isteriku menyibukkanku sehingga kurang perhatian ketika melayani anda\", lalu beliau memalingkan dariku, lalu saya melayaninya dan tetap melayaninya. Selanjutnya beliau bersabda yang kedua kalinya, \"Wahai Rabi'ah, kenapa kamu tidak menikah?\", lalu saya menjawab, \"Demi Allah, Wahai Rasulullah, saya tidak mau menikah, saya tidak mempunyai sesuatu untuk menanggung beban-beban kerumahtanggaan, saya juga tidak mau jika isteriku menyibukkanku sehingga kurang perhatian ketika melayani anda, lalu beliau berpaling dariku.\" Lalu saya merenung diri dan berkata; \"Demi Allah, Rasulullah Shallallahu'alaihiwasallam pasti lebih tahu terhadap segala yang hal yang mendatangkan kemaslahatan dunia dan akheratku daripada aku sendiri. Demi Allah, Seandainya beliau mengatakan menikahlah, tentu saya menjawab, 'Ya Wahai Rasulullah, perintahkan terserah anda. (Rabi'ah Al Aslami radliyallahu'anhu) berkata; lalu beliau bersabda: \"Wahai Rabi'ah, kenapa kamu tidak menikah?\" lalu saya menjawab 'Perintahlah aku sekehendak anda\". Beliau bersabda: \"Pergilah kepada keluarga si 'A' salah satu perkampungan dari Anshar, yang karena tinggal disana lantas ia bermalAs malasan melayani Nabi Shallallahu'alaihiwasallam, dan katakan kepada mereka bahwa Rasulullah Shallallahu'alaihiwasallam mengutusku kepada kalian, bahwa nabi menyuruh kalian agar kalian menikahkanku dengan fulanah salah seorang wanita dari mereka\". Lalu saya pergi dan saya katakan kepada mereka, \"Sesungguhnya Rasulullah Shallallahu'alaihiwasallam telah mengutusku kepada kalian agar kalian menikahkanku dengan fulanah\", lalu mereka berkata; 'Selamat datang Rasulullah Shallallahu'alaihiwasallam dan selamat datang utusan Rasulullah Shallallahu'alaihiwasallam, demi Allah, tidaklah utusan Rasulullah Shallallahu'alaihiwasallam kembali kecuali keperluannya telah terpenuhi. Mereka menikahkanku, mereka berbuat baik kepadaku. Mereka tidak memintaku bukti, lalu saya pulang kepada Rasulullah Shallallahu'alaihiwasallam dalam keadaan sedih. Beliau bertanya, \"Kenapa kamu Wahai Rabi'ah?\" saya menjawab, \"Wahai Rasulullah, saya telah mendatangi suatu kaum yang sangat mulia, mereka menikahkanku, memuliakanku dan berlemah lembut terhadapku. Mereka tidak meminta bukti sedikitpun, hanya sayang saya tidak memiliki mas kawin.\" Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wahai Buraidah Al Aslami, kumpulkanlah untuknya sebiji emas\". (Rabi'ah Al Aslami radliyallahu'anhu) berkata; lalu mereka mengumpulkan sebiji emas untukku, saya mengambilnya, lalu saya bawa kepada Nabi Shallallahu'alaihiwasallam. Lalu beliau bersabda: \"Bawalah ini kepada mereka dan katakan kepada mereka ini adalah maskawinnya',. Mereka pun menyetujuinya dan menerimanya dan berkata 'Mas kawin seperti ini sudah sangat banyak dan baik sekali. (Rabi'ah Al Aslami radliyallahu'anhu) berkata; lalu saya pulang menemui Nabi Shallallahu'alaihiwasallam dalam keadaan sedih, lalu beliau bertanya Wahai Rabi'ah kenapa kamu bersedih? Saya menjawab, Wahai Rasulullah, saya tidak pernah melihat kaum yang lebih mulia dari mereka, mereka rela dengan apa yang saya berikan dan mereka berbuat sangat baik dan berkata; ini adalah sangat banyak dan bagus. Hanya sayang saya tidak punya sesuatu apa yang saya gunakan untuk mengadakan walimah. Beliau bersabda: \"Wahai Buraidah, tolong kumpulkan kambing untuknya\". (Rabi'ah Al Aslami radliyallahu'anhu) berkata; lalu mereka mengumpulkan kambing yang banyak dan gemuk, lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku 'Pergilah dan temuilah 'Aisyah dan katakan kepadanya agar dia mengirim beberapa keranjang berisi makanan', lalu saya mendatanginya dan aku katakan kepadanya segala yang Rasulullah Shallallahu'alaihiwasallam perintahkan kepadaku. Lalu dia berkata; 'Ini keranjang berisi sembilan Sha' gandum, demi Allah, dan jika ada makanan lain besok hari maka ambillah.' Lalu saya mengambilnya dan saya bawa kepada Nabi Shallallahu'alaihiwasallam dan saya kabarkan kepada beliau apa yang dikatakan 'Aisyah, lalu beliau bersabda: \"Bawalah barang-barang ini ke sana, dan katakan kepada mereka agar mereka pergunakan untuk membuat roti\". Lalu saya berangkat ke sana, saya membawa kambing dan saya berangkat bersama beberapa orang dari Aslam, lalu seorang dari Aslam berkata 'Tolong besok barang-barang ini telah diolah menjadi roti '. Maka saya datangi mereka dan saya juga membawa kambing bersama beberapa orang Aslam, lantas salah seorang dari Aslam mengatakan 'tolong besok gandum ini besok sudah diolah menjadi roti, dan kambing ini telah dimasak'. Mereka menjawan 'Untuk membuat roti maka cukuplah kami saja, namun untuk menyembelih kambing, kalianlah yang mengerjakan'. Kontan kami mengambil kambing yang ada, saya bersama dengan beberapa orang Aslam. Kami menyembelihnya lalu kami bersihkan. Kami memasaknya dan sudah siaplah pada kami segala daging dan roti, saya mengadakan walimah dengan mengundang Rasulullah Shallallahu'alaihiwasallam. lalu (Rabi'ah Al Aslami radliyallahu'anhu) berkata; Rasulullah Shallallahu'alaihiwasallam telah memberi tanah kepadaku dan juga kepada Abu Bakar, rupanya dunia telah datang, lalu kami kami saling berselisih dalam masalah pelepah kurma, saya katakan mayang itu dalam batasanku sedang Abu Bakar berkata 'mayang itu dalam batas tanahnya sehingga terjadilah cekcok antara saya dan Abu Bakar. Lalu Abu Bakar berkata dengan perkataan yang tak sepantasnya sehingga ia menyesalinya dan merasa bersalah, ia pun berkata kepadaku 'Wahai Rabi'ah balaslah ucapkanku yang tak sepantasnya kepadaku sehingga menjadi pembalasan yang sebanding\". Saya menjawab 'Tidak sudi, saya tidak bakalan melakukannya', Abu Bakar berkata; 'Baiklah, sekarang kamu katakan atau aku yang akan meminta pertolongan Rasulullah Shallallahu'alaihiwasallam untuk mengalahkanmu. Saya tetap berkata; 'Saya tidak sudi melakukannya.' Lantas Abu Bakar menolak tanah itu sebagai milikku sehingga ia temui Nabi Shallallahu'alaihiwasallam dan saya mengikutinya, lalu datanglah beberapa orang dari Aslam sembari menyumpah serapahiku 'Semoga Allah merahmati Abu Bakar, ada masalah apa hingga dia meminta Rasulullah Shallallahu'alaihiwasallam untuk mengalahkanmu dan dia mengatakan kepadamu sampai begini-begini? Saya jawab, apakah kalian tidak tahu siapa dia, dia adalah satu-satunya sahabat nabi yang menemaninya dalam gua ketika hanya berdua, dia adalah orang yang memiliki kedudukan tinggi di kalangan kaum muslimin, salahnya dia tidak menoleh kemana-mana lantas memandang kalian menolongku untuk mengalahkannya, maka dia pun marah. Lantas Abu Bakar pun mendatangi Rasulullah Shallallahu'alaihiwasallam dengan harapan nabi pun marah kerena kemarahannya, lantas Allah marah karena kemarahan keduanya, sehingga Rabi'ah akan celaka. Mereka berkata 'Apa yang kau perintakan kepada kami.' Pulanglah saja kalian, kata rabiah. Lalu Abu Bakar radliyallahu'anhu pulang menuju Rasulullah Shallallahu'alaihiwasallam, saya ikuti sendirian sampai kepada Nabi Shallallahu'alaihiwasallam. Saya sampaikan segala hal ihwal kejadian tersebut sampai beliau mengangkat kepalanya kepadaku dan berkata; Wahai Rabi'ah apa yang terjadi antara kamu dengan As Shididiq?, saya menjawab 'Wahai Rasulullah, telah terjadi begini dan begitu.' Dia mengatakan kepadaku suatu kalimat yang sebenarnya dia pun muak terhadap ucapan itu, lalu dia mengatakan kepada ku; 'Katakanlah sebagaimana yang aku katakan sehingga hal itu menjadi qishah', namun saya menolaknya. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Benar, janganlah kau balas kepadanya tapi katakanlah 'Semoga Allah mengampuni kamu Wahai Abu Bakar', lalu saya berkata 'Semoga Allah mengampunimu Wahai Abu Bakar\". Al Hasan berkata; lalu Abu Bakar radliyallahu'anhu pulang dengan keadaan menangis."},"1160":{"ar":"قَالَ حَدَّثَنَا أَبُو الْيَمَانِ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ نُعَيْمٍ الْمُجْمِرِ عَنْ رَبِيعَةَ بْنِ كَعْبٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلْنِي أُعْطِكَ قُلْتُ يَا رَسُولَ اللَّهِ أَنْظِرْنِي أَنْظُرْ فِي أَمْرِي قَالَ فَانْظُرْ فِي أَمْرِكَ قَالَ فَنَظَرْتُ فَقُلْتُ إِنَّ أَمْرَ الدُّنْيَا يَنْقَطِعُ فَلَا أَرَى شَيْئًا خَيْرًا مِنْ شَيْءٍ آخُذُهُ لِنَفْسِي لِآخِرَتِي فَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا حَاجَتُكَ فَقُلْتُ يَا رَسُولَ اللَّهِ اشْفَعْ لِي إِلَى رَبِّكَ عَزَّ وَجَلَّ فَلْيُعْتِقْنِي مِنْ النَّارِ فَقَالَ مَنْ أَمَرَكَ بِهَذَا فَقُلْتُ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ مَا أَمَرَنِي بِهِ أَحَدٌ وَلَكِنِّي نَظَرْتُ فِي أَمْرِي فَرَأَيْتُ أَنَّ الدُّنْيَا زَائِلَةٌ مِنْ أَهْلِهَا فَأَحْبَبْتُ أَنْ آخُذَ لِآخِرَتِي قَالَ فَأَعِنِّي عَلَى نَفْسِكَ بِكَثْرَةِ السُّجُودِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Al Yaman] berkata; telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Muhammad bin Ishaq] dari [Muhammad bin 'Amr bin 'Atha`] dari [Nu'aim Al Mujmir] dari [Rabi'ah bin Kaab] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku, \"Mintalah kepadaku, niscaya saya beri\". Saya berkata; \"Wahai Rasulullah, tunggulah sampai aku melihat kebutuhanku\" Beliau bersabda: \"Lihatlah urusanmu terlebih dahulu\" Lalu saya melihat bahwa urusan dunia adalah hakekatnya terputus dan aku tidak melihat kebaikan apapun apabila aku mengambil tawaran dalam perkara akhiratku. Lalu saya menemui Nabi Shallallahu'alaihiwasallam lalu beliau bertanya, \"Apa kebutuhanmu?\" saya menjawab, \"Wahai Rasulullah, berilah syafaat kepadaku dari Rabbmu Azzawajalla sehingga membebaskan aku dari api neraka\". Beliau bertanya, \"Siapa yang menyuruhmu berkata demikian\"? maka aku berkata; \"Demi Allah, Wahai Rasulullah, Tidak ada seorangpun yang menyuruhku, tapi hal itu muncul setelah aku memperhatikan urusanku, dan menyimpulkan bahwa dunia adalah tidak kekal dari para pemiliknya, maka aku lebih senang untuk mengambil tawaran tuanku untuk perkara kebaikan akheratku\", beliau bersabda: \"Tolonglah dirimu dengan memperbanyak sujud.\""},"1161":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ عَنْ نُعَيْمٍ الْمُجْمِرِ عَنْ رَبِيعَةَ بْنِ كَعْبٍ قَالَكُنْتُ أَخْدُمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَقُومُ لَهُ فِي حَوَائِجِهِ نَهَارِي أَجْمَعَ حَتَّى يُصَلِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ الْآخِرَةَ فَأَجْلِسَ بِبَابِهِ إِذَا دَخَلَ بَيْتَهُ أَقُولُ لَعَلَّهَا أَنْ تَحْدُثَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجَةٌ فَمَا أَزَالُ أَسْمَعُهُ يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَانَ اللَّهِ سُبْحَانَ اللَّهِ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ حَتَّى أَمَلَّ فَأَرْجِعَ أَوْ تَغْلِبَنِي عَيْنِي فَأَرْقُدَ قَالَ فَقَالَ لِي يَوْمًا لِمَا يَرَى مِنْ خِفَّتِي لَهُ وَخِدْمَتِي إِيَّاهُ سَلْنِي يَا رَبِيعَةُ أُعْطِكَ قَالَ فَقُلْتُ أَنْظُرُ فِي أَمْرِي يَا رَسُولَ اللَّهِ ثُمَّ أُعْلِمُكَ ذَلِكَ قَالَ فَفَكَّرْتُ فِي نَفْسِي فَعَرَفْتُ أَنَّ الدُّنْيَا مُنْقَطِعَةٌ زَائِلَةٌ وَأَنَّ لِي فِيهَا رِزْقًا سَيَكْفِينِي وَيَأْتِينِي قَالَ فَقُلْتُ أَسْأَلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِآخِرَتِي فَإِنَّهُ مِنْ اللَّهِ عَزَّ وَجَلَّ بِالْمَنْزِلِ الَّذِي هُوَ بِهِ قَالَ فَجِئْتُ فَقَالَ مَا فَعَلْتَ يَا رَبِيعَةُ قَالَ فَقُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ أَسْأَلُكَ أَنْ تَشْفَعَ لِي إِلَى رَبِّكَ فَيُعْتِقَنِي مِنْ النَّارِ قَالَ فَقَالَ مَنْ أَمَرَكَ بِهَذَا يَا رَبِيعَةُ قَالَ فَقُلْتُ لَا وَاللَّهِ الَّذِي بَعَثَكِ بِالْحَقِّ مَا أَمَرَنِي بِهِ أَحَدٌ وَلَكِنَّكَ لَمَّا قُلْتَ سَلْنِي أُعْطِكَ وَكُنْتَ مِنْ اللَّهِ بِالْمَنْزِلِ الَّذِي أَنْتَ بِهِ نَظَرْتُ فِي أَمْرِي وَعَرَفْتُ أَنَّ الدُّنْيَا مُنْقَطِعَةٌ وَزَائِلَةٌ وَأَنَّ لِي فِيهَا رِزْقًا سَيَأْتِينِي فَقُلْتُ أَسْأَلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِآخِرَتِي قَالَ فَصَمَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَوِيلًا ثُمَّ قَالَ لِي إِنِّي فَاعِلٌ فَأَعِنِّي عَلَى نَفْسِكَ بِكَثْرَةِ السُّجُودِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Muhammad bin 'Amr bin 'Atha`] dari [Nua'im Al Mujmir] dari [Rabi'ah bin Kaab] berkata; saya melayani Rasulullah Shallallahu'alaihiwasallam, saya memenuhi keperluannya pada siang hari semuanya sampai Rasulullah Shallallahu'alaihiwasallam shalat isya' pada akhir malam, lalu saya duduk di depan pintunya, jika beliau masuk, saya katakan semoga ada keperluan Rasulullah Shallallahu'alaihiwasallam, sehingga saya tetap bisa mendengarnya Rasulullah Shallallahu'alaihiwasallam membaca, SUBHANALLAHU, SUBHANALLAHU, SUBHANALLAHU, WABIHAMDIHI (Maha Suci Allah, Maha Suci Allah, Maha Suci Allah, dengan puji-Nya) \" sehingga saya bosan lalu saya pulang atau sampai mataku kalah, lalu saya tidur. (Rabiah bin Kaab radliyallahu'anhu) berkata; pada suatu hari beliau bersabda karena beliau melihat seringnya saya kepadanya dan pelayanan saya kepada beliau, \"Mintalah kepadaku Wahai Rabi'ah, saya akan memberikannya\" (Rabiah bin Kaab radliyallahu'anhu) berkata; \"Saya akan melihat kebutuhanku dulu Wahai Rasulullah, nanti akan saya beritahukan kepada anda\" (Rabiah bin Kaab radliyallahu'anhu) berkata; lalu saya berpikir dalam diriku, saya tahu sesungguhnya dunia adalah akan terputus dan akan hilang, dan saya telah memiliki rizqi yang cukup bagiku dan akan mendatangiku. (Rabiah bin Kaab radliyallahu'anhu) berkata; lalu saya katakan saya akan meminta kepada Rasulullah Shallallahu'alaihiwasallam untuk akhiratku karena hal itu dari Allah Azzawajalla dengan kedudukan beliau. (Rabiah bin Kaab radliyallahu'anhu) berkata; lalu saya mendatanginya, lalu beliau bertanya, apa yang telah kau lakukan Wahai Rabi'ah? (Rabiah bin Kaab radliyallahu'anhu) berkata; Ya Wahai Rasulullah, saya meminta kepada anda aagr anda memberi syafaat kepadaku dari Rabmu sehingga membebaskan aku dari api neraka\". (Rabiah bin Kaab radliyallahu'anhu) berkata; beliau bertanya, \"Siapa yang menyuruhmu berkata demikian Wahai Rabi'ah\"? maka aku berkata; \"Tidak, Demi Allah, yang mengutus anda dengan Al Haq, Tidak ada seorangpun yang menyuruhku, tapi ketika anda bersabda mintalah kepadaku, maka saya akan memberikannya, dan anda di hadapan Allah mempunyai kedudukan, setelah aku memperhatikan urusanku, dan menyimpulkan bahwa dunia adalah tidak kekal dari para pemiliknya, maka aku lebih senang untuk mengambil tawaran tuanku untuk perkara kebaikan akheratku\". (Rabiah bin Kaab radliyallahu'anhu) berkata; lalu Rasulullah Shallallahu'alaihiwasallam terdiam dalam waktu yang lama lalu beliau bersabda kepadaku, \"Sesungguhnya saya akan melakukannya, maka tolonglah dirimu dengan memperbanyak sujud.\""},"1162":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا الثَّوْرِيُّ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أَبِي عَيَّاشٍ الزُّرَقِيِّ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُسْفَانَ فَاسْتَقْبَلَنَا الْمُشْرِكُونَ عَلَيْهِمْ خَالِدُ بْنُ الْوَلِيدِ وَهُمْ بَيْنَنَا وَبَيْنَ الْقِبْلَةِ فَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَقَالُوا قَدْ كَانُوا عَلَى حَالٍ لَوْ أَصَبْنَا غِرَّتَهُمْ ثُمَّ قَالُوا تَأْتِي عَلَيْهِمْ الْآنَ صَلَاةٌ هِيَ أَحَبُّ إِلَيْهِمْ مِنْ أَبْنَائِهِمْ وَأَنْفُسِهِمْ قَالَ فَنَزَلَ جِبْرِيلُ عَلَيْهِ السَّلَام بِهَذِهِ الْآيَاتِ بَيْنَ الظُّهْرِ وَالْعَصْرِ{ وَإِذَا كُنْتَ فِيهِمْ فَأَقَمْتَ ��َهُمْ الصَّلَاةَ }قَالَ فَحَضَرَتْ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذُوا السِّلَاحَ قَالَ فَصَفَفْنَا خَلْفَهُ صَفَّيْنِ قَالَ ثُمَّ رَكَعَ فَرَكَعْنَا جَمِيعًا ثُمَّ رَفَعَ فَرَفَعْنَا جَمِيعًا ثُمَّ سَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّفِّ الَّذِي يَلِيهِ وَالْآخَرُونَ قِيَامٌ يَحْرُسُونَهُمْ فَلَمَّا سَجَدُوا وَقَامُوا جَلَسَ الْآخَرُونَ فَسَجَدُوا فِي مَكَانِهِمْ ثُمَّ تَقَدَّمَ هَؤُلَاءِ إِلَى مَصَافِّ هَؤُلَاءِ وَجَاءَ هَؤُلَاءِ إِلَى مَصَافِّ هَؤُلَاءِ قَالَ ثُمَّ رَكَعَ فَرَكَعُوا جَمِيعًا ثُمَّ رَفَعَ فَرَفَعُوا جَمِيعًا ثُمَّ سَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّفُّ الَّذِي يَلِيهِ وَالْآخَرُونَ قِيَامٌ يَحْرُسُونَهُمْ فَلَمَّا جَلَسَ جَلَسَ الْآخَرُونَ فَسَجَدُوا فَسَلَّمَ عَلَيْهِمْ ثُمَّ انْصَرَفَ قَالَ فَصَلَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّتَيْنِ مَرَّةً بِعُسْفَانَ وَمَرَّةً بِأَرْضِ بَنِي سُلَيْمٍ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ats-Tsauri] dari [Manshur] dari [Mujahid] dari [Abu 'Ayyasy Az-Zuraqi] berkata; kami bersama Rasulullah Shallallahu'alaihiwasallam di 'Utsfan lalu kami menghadap orang-orang musrik yang di dalamnya ada Khalid bin Al Walid, mereka berada di antara kami dengan kiblat, lalu Rasulullah Shallallahu'alaihiwasallam memimpin shalat dluhur kepada bersama kami. (orang-orang musyrik) berkata; \"Sesungguhnya mereka dalam keadaan lengah jika kita menyerang pertama\", lalu mereka berkata; \"Telah datang kepada mereka, sekarang waktu shalat yang lebih mereka sukai daripada anak-anak mereka dan diri mereka sendiri.\" (Abu 'Ayyasy Az-Zuraqi Radliyallahu'anhu) berkata; maka turunlah Jibril 'Alaihissalam dengan ayat ini antara waktu zhuhur sampai waktu ashar, Dan apabila kamu berada di tengah-tengah mereka (sahabatmu) lalu kamu hendak mendirikan shalat bersama-sama mereka, (Abu 'Ayyasy Az-Zuraqi Radliyallahu'anhu) berkata; lalu Rasulullah Shallallahu'alaihiwasallam menyuruh mereka, lalu mereka mengambil senjatanya. (Abu 'Ayyasy Az-Zuraqi Radliyallahu'anhu) berkata; lalu kami berbaris di belakang beliau dua barisan. lalu beliau rukuk dan kami juga semuanya lalu beliau mengangkat kepalanya dan kami juga mengangkatnya, lalu Nabi Shallallahu'alaihiwasallam sujud dengan shaf yang di belakangnya sedang yang lainnya berdiri untuk menjaga mereka. Tatkala mereka bersujud dan berdiri maka yang lainnya duduk lalu bersujud pada tempat mereka, lalu mereka maju ke barisan yang pertama dan yang di depan tadi mundur. (Abu 'Ayyasy Az-Zuraqi Radliyallahu'anhu) berkata; lalu beliau rukuk dan mereka pun rukuk semuanya, lalu mereka mengangkat semuanya, kemudian Nabi Shallallahu'alaihiwasallam sujud bersama dengan shaf di belakangnya sedang yang lainnya dalam keadaan berdiri menjaga mereka. Tatkala beliau duduk, yang belakang ikut duduk, lalu besujud, lalu beliau bersalam kepada mereka lalu mereka bubar. (Abu 'Ayyasy Az-Zuraqi Radliyallahu'anhu) berkata; Rasulullah Shallallahu'alaihiwasallam shalat dua kali, sekali di 'Usfan dan sekali di Bani Sulaim."},"1163":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ مُجَاهِدًا يُحَدِّثُ عَنْ أَبِي عَيَّاشٍ الزُّرَقِيِّ قَالَ قَالَ شُعْبَةُ كَتَبَ بِهِ إِلَيَّ وَقَرَأْتُهُ عَلَيْهِ وَسَمِعْتُهُ مِنْهُ يُحَدِّثُ بِهِ وَلَكِنِّي حَفِظْتُهُ مِنْ الْكِتَابِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي مَصَافِّ الْعَدُوِّ بِعُسْفَانَ وَعَلَى الْمُشْرِكِينَ خَالِدُ بْنُ الْوَلِيدِ فَصَلَّى بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ ثُمَّ قَالَ الْمُشْرِكُونَ إِنَّ لَهُمْ صَلَاةً بَعْدَ هَذِهِ هِيَ أَحَبُّ إِلَيْهِمْ مِنْ أَبْنَائِهِمْ وَأَمْوَالِهِمْ فَصَلَّى بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ فَصَفَّهُمْ صَفَّيْنِ خَلْفَهُ قَالَ فَرَكَعَ بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمِيعًا فَلَمَّا رَفَعُوا رُءُوسَهُمْ سَجَدَ الصَّفُّ الَّذِي يَلِيهِ وَقَامَ الْآخَرُونَ فَلَمَّا رَفَعُوا رُءُوسَهُمْ سَجَدَ الصَّفُّ الْمُؤَخَّرُ لِرُكُوعِهِمْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثُمَّ تَأَخَّرَ الصَّفُّ الْمُقَدَّمُ وَتَقَدَّمَ الصَّفُّ الْمُؤَخَّرُ فَقَامَ كُلُّ وَاحِدٍ مِنْهُمْ فِي مَقَامِ صَاحِبِهِ ثُمَّ رَكَعَ بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمِيعًا فَلَمَّا رَفَعُوا رُءُوسَهُمْ مِنْ الرُّكُوعِ سَجَدَ الصَّفُّ الَّذِي يَلِيهِ وَقَامَ الْآخَرُونَ ثُمَّ سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] berkata; saya telah mendengar [Mujahid] menceritakan dari [Abu 'Ayyasy Az-Zuraqi] berkata; Syu'bah berkata; dia telah menulisnya untukku dan saya membaca di hadapannya dan saya juga telah mendengarnya darinya dia menceritakannya, tapi saya saya menghapalnya dari kitab, Nabi Shallallahu'alaihiwasallam berada pada shaf yang menghadapi musuh di 'Usfan yang dalam pasukan orang-orang musyrik terdapat Khalid bin Al Walid, lalu Nabi Shallallahu'alaihiwasallam shalat zhuhur bersama mereka kemudian orang-orang musyrik mengatakan, \"Sesungguhnya mereka memiliki shalat setelah ini yang mereka lebih cintai daripada anak-anak dan harta-harta mereka\" Lalu Rasulullah Shallallahu'alaihiwasallam shalat ashar bersama mereka, lalu mereka membariskan mereka dua shaf di belakang beliau. (Abu 'Ayyasy Az-Zuraqi Radliyallahu'anhu) berkata; lalu Rasulullah Shallallahu'alaihiwasallam rukuk bersama mereka semuanya. Tatkala mereka mengangkat kepala mereka, maka shaf yang berada di belakang beliau bersujud sedang yang di belakangnya tetap berdiri. Tatkala mereka telah mengangkat kepala mereka, maka shaf yang di belakangnya bersujud untuk rukuk bersama Rasulullah Shallallahu'alaihiwasallam. (Abu 'Ayyasy Az-Zuraqi Radliyallahu'anhu) berkata; lalu shaf yang di depan tersebut mundur dan shaf yang berada di belakangnya maju, lalu masing-masing menempati tempat temannya, lalu Rasulullah Shallallahu'alaihiwasallam memimpin rukuk bersama mereka semuanya. Tatkala mereka mengangkat kepalanya dari rukuk, maka shaf yang berada di belakangnya dan yang lainnya tetap berdiri, lalu Rasulullah Shallallahu'alaihiwasallam mengucapkan salam kepada mereka."},"1164":{"ar":"قَالَ حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أَبِي عَيَّاشٍ الزُّرَقِيِّ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ وَالْمُشْرِكُونَ بَيْنَهُمْ وَبَيْنَ الْقِبْلَةِ مَرَّتَيْنِ مَرَّةً بِأَرْضِ بَنِي سُلَيْمٍ وَمَرَّةً بِعُسْفَانَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Mu`ammal] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari [Abu 'Ayyasy Az-Zuraqi] berkata; Rasulullah Shallallahu'alaihiwasallam shalat khauf sedang kaum musyrikin berada di antara mereka dan arah kiblat selama dua kali, sekali di Bani Sulaim dan sekali di 'Usman."},"1165":{"ar":"قَالَ حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي عَيَّاشٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ حِينَ أَصْبَحَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ كَانَ لَهُ كَعَدْلِ رَقَبَةٍ مِنْ وَلَدِ إِسْمَاعِيلَ وَكُتِبَ لَهُ بِهَا عَشْرُ حَسَنَاتٍ وَحُطَّ عَنْهُ بِهَا عَشْرُ سَيِّئَاتٍ وَرُفِعَتْ لَهُ بِهَا عَشْرُ دَرَجَاتٍ وَكَانَ فِي حِرْزٍ مِنْ الشَّيْطَانِ حَتَّى يُمْسِيَ وَإِذَا أَمْسَى مِثْلُ ذَلِكَ حَتَّى يُصْبِحَ قَالَ فَرَأَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا يَرَى النَّائِمُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أَبَا عَيَّاشٍ يَرْوِي عَنْكَ كَذَا وَكَذَا قَالَ صَدَقَ أَبُو عَيَّاشٍ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu 'Ayyasy] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang pada waktu paginya membaca, 'LAA ILAAHA ILLALLAAH WAHDAHU LAA SYARIIKA LAHU LAHUL MULKU WALAHUL HAMDU WAHUWA 'ALA KULLI SYAI'IN QADIIR, (tidak ada tuhan selain Allah, Yang Maha Esa, tidak ada sekutu bagi-Mu, baginya kerajaan dan pujian dan baginya pujian dan dia Maha Menentukan atas segala sesuatu) ' maka baginya bagaikan membebaskan budak dari anak Isma'il dan dicatat baginya sepuluh kebaikan dan dihapusknnya sepuluh keburukan dan diangkat dengan sepuluh derajat dan dia terbentengi dari setan sampai waktu sorenya dan apabila pada waktu sorenya dia kembali berdoa seperti waktu paginya maka akan mendapatkan sebagaimana waktu paginya sehingga datang waktu pagi\". (Abu 'Ayyasy Az-Zuraqi Radliyallahu'anhu) berkata; maka ada seorang laki-laki yang melihat Rasulullah Shallallahu'alaihiwasallam sebagaimana orang tidur lalu berkata; \"Wahai Rasulullah, sesungguhnya Abu 'Ayyasy telah meriwayatkan darimu hal ini dan itu (sebagaimana dalam hadits) maka dia berkata; \"Benarlah Abu 'Ayyasy.\""},"1166":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ عَمْرِو بْنِ الْقَارِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِ عَمْرِو بْنِ الْقَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِمَ فَخَلَّفَ سَعْدًا مَرِيضًا حَيْثُ خَرَجَ إِلَى حُنَيْنٍ فَلَمَّا قَدِمَ مِنْ جِعِرَّانَةَ مُعْتَمِرًا دَخَلَ عَلَيْهِ وَهُوَ وَجِعٌ مَغْلُوبٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي مَالًا وَإِنِّي أُورَثُ كَلَالَةً أَفَأُوصِي بِمَالِي كُلِّهِ أَوْ أَتَصَدَّقُ بِهِ قَالَ لَا قَالَ أَفَأُوصِي بِثُلُثَيْهِ قَالَ لَا قَالَ أَفَأُوصِي بِشَطْرِهِ قَالَ لَا قَالَ أَفَأُوصِي بِثُلُثِهِ قَالَ نَعَمْ وَذَاكَ كَثِيرٌ قَالَ أَيْ رَسُولَ اللَّهِ أَمُوتُ بِالدَّارِ الَّتِي خَرَجْتُ مِنْهَا مُهَاجِرًا قَالَ إِنِّي لَأَرْجُو أَنْ يَرْفَعَكَ اللَّهُ فَيَنْكَأَ بِكَ أَقْوَامًا وَيَنْفَعَ بِكَ آخَرِينَ يَا عَمْرُو بْنَ الْقَارِيِّ إِنْ مَاتَ سَعْدٌ بَعْدِي فَهَا هُنَا فَادْفِنْهُ نَحْوَ طَرِيقِ الْمَدِينَةِ وَأَشَارَ بِيَدِهِ هَكَذَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin 'Utsman bin Khutsaim] dari ['Amr bin Al Qary] dari [Bapaknya] dari [kakeknya, 'Amr bin Al Qary] sesungguhnya Rasulullah Shallallahu'alaihiwasallam pergi dan meninggalkan Saad karena sakit, ketika keluar menuju Hunain. Tatkala sampai dari Ji'ranah karena umrah, dia menemuinya dalam keadaan sakit yang akut, lalu dia berkata; Wahai Rasulullah, sesungguhnya saya mempunyai harta dan saya dalam keadaan kalalah (mayat yang tidak mempunyai orang tua maupun anak) apakah harus meninggalkan warisan dengan hartaku semuanya atau saya sedekahkan saja. Beliau bersabda: \"Tidak\". Dia berkata; apakah saya berwasiat dengan dua pertiga? Beliau bersabda: \"Tidak\". Dia berkata; apakah saya berwasiat dengan setengahnya? Beliau bersabda: \"Tidak\". Dia berkata; apakah saya berwasiat dengan sepertiganya? Beliau bersabda: \"Ya, dan itu sudah banyak\". Dia berkata; 'Wahai Rasulullah, saya meninggal dalam rumah yang saya telah keluar darinya saat berhijrah.' Beliau bersabda: \"Sesungguhnya saya sangat mengharap semoga Allah mengangkat kamu lalu dia melukai suatu kaum dan orang yang lain bisa mengambil manfaat darimu, Wahai 'Amr bin Al Qari, jika Saad meninggal setelahku maka kuburkanlah di sini menuju jalan ke Madinah\" dan beliau memberi isyarat dengan tangannya begini.'"},"1167":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّازَّقِ قَالَ أَخْبَرَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرٍو الْقُرَشِيِّ قَالَ حَدَّثَنِي مَنْ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَأَمَرَ بِرَجْمِ رَجُلٍ بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَلَمَّا أَصَابَتْهُ الْحِجَارَةُ فَرَّ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَهَلَّا تَرَكْتُمُوهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Isra'il] dari [Simak] dari [Abdul Aziz bin Abdullah bin 'Amr Al Qurasyi] berkata; telah menceritakan kepadaku [orang yang menyaksikan] bahwa Nabi Shallallahu'alaihiwasallam menyuruh untuk merajam seseorang di antara Makkah dan Madinah. Tatkala laki-laki tersebut terkena batu kemudian dia kabur, ketika disampaikan hal tersebut kepada Nabi Shallallahu'alaihiwasallam, maka beliau bersabda: \"Mengapa kalian tidak membiarkan dia\"? "},"1168":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّازَّقِ أَخْبَرَنَا دَاوُدُ بْنُ قَيْسٍ الصَّنْعَانِيُّ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ أَبِيهِ قَالَ حَدَّثَنِي فَنَّجُ قَالَكُنْتُ أَعْمَلُ فِي الدَّيْنَبَاذِ وَأُعَالِجُ فِيهِ فَقَدِمَ يَعْلَي بْنُ أُمَيَّةَ أَمِيرًا عَلَى الْيَمَنِ وَجَاءَ مَعَهُ رِجَالٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَنِي رَجُلٌ مِمَّنْ قَدِمَ مَعَهُ وَأَنَا فِي الزَّرْعِ أَصْرِفُ الْمَاءَ فِي الزَّرْعِ وَمَعَهُ فِي كُمِّهِ جَوْزٌ فَجَلَسَ عَلَى سَاقِيَةٍ مِنْ الْمَاءِ وَهُوَ يَكْسِرُ مِنْ ذَلِكَ الْجَوْزِ وَيَأْكُلُ ثُمَّ أَشَارَ إِلَى فَنَّجَ فَقَالَ يَا فَارِسِيُّ هَلُمَّ قَالَ فَدَنَوْتُ مِنْهُ فَقَالَ الرَّجُلُ لِفَنَّجَ أَتَضْمَنُ لِي غَرْسَ هَذَا الْجَوْزِ عَلَى الْمَاءِ فَقَالَ لَهُ فَنَّجُ مَا يَنْفَعُنِي ذَلِكَ فَقَالَ الرَّجُلُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِأُذُنَيَّ هَاتَيْنِ مَنْ نَصَبَ شَجَرَةً فَصَبَرَ عَلَى حِفْظِهَا وَالْقِيَامِ عَلَيْهَا حَتَّى تُثْمِرَ كَانَ لَهُ فِي كُلِّ شَيْءٍ يُصَابُ مِنْ ثَمَرَتِهَا صَدَقَةٌ عِنْدَ اللَّهِ عَزَّ وَجَلَّ فَقَالَ فَنَّجُ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْقَالَ فَنَّجُ فَأَنَا أَضْمَنُهَا قَالَ فَمِنْهَا جَوْزُ الدَّيْنَبَاذِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Daud bin Qais Ash-Shan'ani] berkata; telah menceritakan kepadaku [Abdullah bin Wahab] dari [Bapaknya] berkata; telah menceritakan kepadaku [Fannaj] berkata; Aku bekerja di Dainabadz dan mengobati, maka datanglah Ya'la bin Umayyah seorang 'Amir di Yaman bersama beberapa sahabat Nabi Shallallahu'alaihiwasallam. Lalu datanglah seorang laki-laki dari rombongan, tatkala aku berada di pekarangan mengatur sirkulasi air, laki-laki tersebut membawa kantong yang berisi buah kelapa lalu di duduk di tepian air, kemudian dia memecah kelapa tersebut dan memakannya, kemudian menunjuk kepada Fannaj seraya berkata; \"Wahai orang Persai, mendekatlah.\" Lalu aku pun mendekatinya, laki-laki itu berkata kepada Fannaj, \"Maukah engkau menjamin untukku untuk menanam kelapa di atas air?, maka Fannaj berkata kepadanya, \"Apa keuntungannya untukku?\" maka [laki-laki] tersebut berkata 'Saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda yang aku mendengarnya langsung dengan kedua telingaku, \"Barangsiapa menanam suatu pohon lalu dia bersabar untuk merawatnya sampai berbuah, maka segala sesuatu yang mengenai buahnya akan menjadi sebuah sedekah di sisi Allah\", maka Fannaj berkata; \"Apakah engkau mendengarnya langsung dari Rasulullah Shallallahu'alaihiwasallam?, dia pun menjawab, \"Benar\" Fannaj berkata; \"Aku akan berjanji untuk merawat semua tanaman dan kelapa tersebut\". (Fannaj Radliyallahu'anhu) berkata; di antaranya adalah kelapa Dainabadz."},"1169":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ طَارِقِ بْنِ عَلْقَمَةَ أَخْبَرَهُ عَنْ عَمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا جَاءَ مَكَانًا مِنْ دَارِ يَعْلَى نَسَبَهُ عُبَيْدُ اللَّهِ اسْتَقْبَلَ الْقِبْلَةَ فَدَعَاو قَالَ رَوْحٌ عَنْ أَبِيهِ و قَالَ ابْنُ بَكْرٍ عَنْ أُمْهِ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abu Yazid] sesungguhnya [Abdurrahman bin Thariq bin 'Alqamah] mengabarinya dari [pamannya] dari Nabi Shallallahu'alaihiwasallam, jika beliau mendatangi sebuah tempat dari Ya'la, 'Ubaidullah menasabkan pada arah kiblat lalu berdoa. [Rauh] berkata; dari [Bapaknya] dan [Ibnu Bakar] berkata; dari [Umhi]."},"1170":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاذٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ بِمِنًى وَنَزَّلَهُمْ مَنَازِلَهُمْ وَقَالَ لِيَنْزِلْ الْمُهَاجِرُونَ هَاهُنَا وَأَشَارَ إِلَى مَيْمَنَةِ الْقِبْلَةِ وَالْأَنْصَارُ هَاهُنَا وَأَشَارَ إِلَى مَيْسَرَةِ الْقِبْلَةِ ثُمَّ لِيَنْزِلْ النَّاسُ حَوْلَهُمْ قَالَ وَعَلَّمَهُمْ مَنَاسِكَهُمْ فَفُتِّحَتْ أَسْمَاعُ أَهْلِ مِنًى حَتَّى سَمِعُوهُ فِي مَنَازِلِهِمْ قَالَ فَسَمِعْتُهُ يَقُولُ ارْمُوا الْجَمْرَةَ بِمِثْلِ حَصَى الْخَذْفِقَالَ عَبْد اللَّهِ سَمِعْتُ مُصْعَبًا الزُّبَيْرِيَّ يَقُولُ جَاءَ أَبُو طَلْحَةَ الْقَاصُّ إِلَى مَالِكِ بْنِ أَنَسٍ فَقَالَ يَا أَبَا عَبْدِ اللَّهِ إِنَّ قَوْمًا قَدْ نَهَوْنِي أَنْ أَقُصَّ هَذَا الْحَدِيثَ صَلَّى اللَّهُ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَعَلَى مُحَمَّدٍ وَعَلَى أَهْلِ بَيْتِهِ وَعَلَى أَزْوَاجِهِ فَقَالَ مَالِكٌ حَدِّثْ بِهِ وَقُصَّ بِهِ وَقُولَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Humaid Al A'raj] dari [Muhammad bin Ibrahim At-Taimi] dari [Abdurrahman bin Mu'adz] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam] berkata; Nabi Shallallahu'alaihiwasallam berkhutbah pada orang-orang di Mina, lalu mereka kembali pada tempat singgah mereka, lalu beliau bersabda: \"Hendaknya Orang Muhajirin singgah di sini dan beliau menunjukkan ke arah kanan kiblat dan orang Anshar di sini, dan beliau menunjukkan arah kiri kiblat lalu orang-orang bertempat tinggal di sekitar mereka. (salah seorang sahabat radliyallahu'anhu) berkata; dan beliau mengajarkan tatacara ibadah mereka lalu penduduk Mina membuka pendengaran mereka sampai terdengar di tempat singgah mereka. (salah seorang sahabat radliyallahu'anhu) berkata; saya telah mendengar beliau bersabda: \"Lemparlah jumrah dengam kerikil yang kecil\". Abdullah berkata; saya telah mendengar Mush'ab Az-Zubairi berkata; Abu Thalhah orang yang punya kisah, datang kepada Malik bin Anas, lalu berkata; Wahai Abu Abdullah sesungguhnya ada suatu kaum yang mereka melarangku untuk menceritakan hadits ini, semoga Allah merahmati Ibrahim sesungguhnya Engkau Maha Terpuji lagi Maha Perkasa, dan atas Muhammad dan pada Ahli Baitnya, dan para istrinya, lalu Malik berkata; ceritakanlah hadits itu dan sampaikan perkataannya."},"1171":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا حُمَيْدُ بْنُ قَيْسٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاذٍ التَّيْمِيِّ قَالَ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdushshamad] berkata; telah menceritakan kepadaku [bapakku] berkata; telah menceritakan kepadaku [Humaid bin Qais] dari [Muhammad bin Ibrahim At-Taimi] dari [Abdurrahman bin Mu'adz At-Taimi] berkata; dia adalah salah seorang sahabat Nabi Shallallahu'alaihiwasallam, Rasulullah Shallallahu'alaihiwasallam berkhutbah lalu menyebutkan hadits."},"1172":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا الْأَشْجَعِيُّ عَنْ سُفْيَانَ عَنِ الْأَعْمَشِ عَنْ هِلَالِ بْنِ يِسَافٍ عَنْ رَجُلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ سَيَكُونُ قَوْمٌ لَهُمْ عَهْدٌ فَمَنْ قَتَلَ رَجُلًا مِنْهُمْ لَمْ يَرَحْ رَائِحَةَ الْجَنَّةِ وَإِنَّ رِيحَهَا لَيُوجَدُ مِنْ مَسِيرَةِ سَبْعِينَ عَامًا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Al Aysja'i] dari [Sufyan] dari [Al `a'masy] dari [Hilal bin Yisaf] dari [seorang laki-laki] dari Nabi Muhammad Shallallahu'alaihiwasallam, beliau bersabda: \"Akan datang suatu kaum yang mengadakan suatu perjanjian, maka barangsiapa yang membunuh salah seorang dari mereka, dia tidak akan dapat mencium bau surga, padahal baunya dapat dicium sejauh perjalanan tujuh puluh tahun.\""},"1173":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عَبْدِ الْحَمِيدِ بْنِ صَيْفِيٍّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَإِنَّ صُهَيْبًا قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ يَدَيْهِ تَمْرٌ وَخُبْزٌ فَقَالَ ادْنُ فَكُلْ قَالَ فَأَخَذَ يَأْكُلُ مِنْ التَّمْرِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بِعَيْنِكَ رَمَدًا فَقَالَ يَا رَسُولَ اللَّهِ إِنَّمَا آكُلُ مِنْ النَّاحِيَةِ الْأُخْرَى قَالَ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Abdul Hamid bin Shaifi] dari [Bapaknya] dari [kakeknya] berkata; sesungguhnya Shuhaib mendatangi Nabi Shallallahu'alaihiwasallam dan di hadapannya ada kurma dan roti. Lalu beliau bersabda: \"Dekatkanlah dan makanlah!\" (Shuhaib bin Sinan radliyallahu'anhu) berkata; lalu dia memakan kurmanya. Lalu Nabi Shallallahu'alaihiwasallam bersabda kepadanya, \"Di matamu ada sebuah penyakit\", lalu dia berkata; Wahai Rasulullah, saya akan makan dari arah yang lain. (Shuhaib bin Sinan radliyallahu'anhu) berkata; lalu Nabi Shallallahu'alaihiwasallam tersenyum."},"1174":{"ar":"قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ أَخْبَرَنِي سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ الْحَضْرَمِيِّ يَقُولُ أَخْبَرَنِي مَنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُإِنَّ مِنْ أُمَّتِي قَوْمًا يُعْطَوْنَ مِثْلَ أُجُورِ أَوَّلِهِمْ فَيُنْكِرُونَ الْمُنْكَرَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Al Habhab] berkata; telah mengabarkan kepadaku [Sufyan] dari ['Atha` bin As Sa`ib] berkata; saya telah mendengar [Abdurrahman bin Al Hadlrami] berkata; telah mengabarkan kepadaku [seseorang yang telah mendengar Nabi] Shallallahu'alaihiwasallam bersabda: \"Akan ada dari umatku suatu kaum yang mereka akan di beri seperti pahala orang yang pertama, lalu mereka mengingkari kemungkaran\"."},"1175":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ حَارِثَةَ بْنِ مُضَرِّبٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَصْحَابِهِ إِنَّ مِنْكُمْ رِجَالًا لَا أُعْطِيهِمْ شَيْئًا أَكِلُهُمْ مِنْهُمْ فُرَاتُ بْنُ حَيَّانَ قَالَ مِنْ بَنِي عِجْلٍ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Haritsah bin Mudlar] dari [beberapa sahabat Nabi Shallallahu'alaihiwasallam] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda kepada para sahabatnya, \"Diantara kalian ada beberapa laki-laki, saya tidak akan memberi mereka sesuatupun, saya mewakilkan kepada mereka. Di antara mereka Furat bin Hayyan\". (sebagian sahabat radliyallahu'anhum) berkata; dari Bani 'Ijl."},"1176":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ حَدَّثَنَا عِكْرِمَةُ قَالَ حَدَّثَنَا أَبُو زُمَيْلٍ سِمَاكٌ قَالَ حَدَّثَنِي رَجُلٌ مِنْ بَنِي هِلَالٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَصْلُحُ الصَّدَقَةُ لِغَنِيٍّ وَلَا لِذِي مِرَّةٍ سَوِيٍّ","id":"Telah menceritakan kepada kami [Abu Abdurrahman Abdullah bin Yazid] berkata; telah menceritakan kepada kami ['Ikrimah] berkata; telah menceritakan kepada kami [Abu Zumail, Simak] berkata; telah menceritakan kepadaku [seorang laki-laki dari Bani Hilal], berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak boleh zakat terhadap orang yang kaya ataupun kepada orang yang kuat.\""},"1177":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي بَكْرُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ أَنَّهُ حَدَّثَهُ رَجُلٌ خَدَمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِ سِنِينَ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قُرِّبَ إِلَيْهِ طَعَامُهُ يَقُولُ بِسْمِ اللَّهِ وَإِذَا فَرَغَ مِنْ طَعَامِهِ قَالَ اللَّهُمَّ أَطْعَمْتَ وَأَسْقَيْتَ وَأَغْنَيْتَ وَأَقْنَيْتَ وَهَدَيْتَ وَأَحْيَيْتَ فَلَكَ الْحَمْدُ عَلَى مَا أَعْطَيْتَ","id":"Telah menceritakan kepada kami [Abu Abdurrahman] berkata; telah menceritakan kepada kami [Sa'id bin Abu Ayyub] berkata; telah menceritakan kepadaku [Bakr bin 'Amr] dari [Abdullah bin Hubairah] dari [Abdurrahman bin Jubair] sesungguhnya dia menceritakannya [seseorang yang telah melayani] Rasulullah Shallallahu'alaihiwasallam selama delapan tahun, sesungguhnya dia mendengar Nabi Shallallahu'alaihiwasallam jika didekatkan kepada beliau makanannya membaca, BISMILLAH (Dengan menyebut nama Allah) dan jika telah selesai dari memakan, beliau membaca: ALLAHUMMA AT'AMTA WA ASQAITA WA AGHNAITA WA AQNAITA WA HADAITA WA AHYAITA FA LAKA Al HAMD 'ALA MA A'THAITA (Ya Allah, Engkau telah memberi makan, minum, kecukupan, keridlaan, petunjuk dan kehidupan. Bagi-Mulah pujian atas apa yang telah Engkau berikan)."},"1178":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ إِسْمَاعِيلَ أَبُو عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ مُنِيبٍ عَنْ عَمِّهِ قَالَ بَلَغَ رَجُلًا عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ سَتَرَ أَخَاهُ الْمُسْلِمَ فِي الدُّنْيَا سَتَرَهُ اللَّهُ يَوْمَ الْقِيَامَةِ فَرَحَلَ إِلَيْهِ وَهُوَ بِمِصْرَ فَسَأَلَهُ عَنْ الْحَدِيثِ قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَتَرَ أَخَاهُ الْمُسْلِمَ فِي الدُّنْيَا سَتَرَهُ اللَّهُ يَوْمَ الْقِيَامَةِ قَالَ وَأَنَا قَدْ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Mua`ammal bin Isma'il], Abu Abdurrahman berkata; telah menceritakan kepada kami [Hammad] berkata; telah menceritakan kepada kami [Abdul Malik bin 'Umair] dari [Munib] dari [pamannya] berkata; telah sampai berita kepada [seorang laki-laki dari salah seorang sahabat] Nabi Shallallahu'alaihiwasallam sesungguhnya dia menceritakan dari Nabi Shallallahu'alaihiwasallam, beliau bersabda: \"Barangsiapa yang menutupi aib saudaranya yang muslim di dunia, Allah akan menutupinya pada Hari Kiamat\", lalu dia berjalan di Mesir lalu dan bertanya tentang hadits, (sahabat radliyallahu'anhu itu menjawab) berkata; ya, saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menutupi saudaranya muslim di dunia niscaya Allah menutupi aibnya pada Hari Kiamat.\" Dia berkata dan saya mendengarnya dari Rasulullah Shallallahu'alaihiwasallam."},"1179":{"ar":"قَالَ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ أَنَّ جُنَادَةَ بْنَ أَبِي أُمَيَّةَ حَدَّثَهُأَنَّ رِجَالًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَعْضُهُمْ إِنَّ الْهِجْرَةَ قَدْ انْقَطَعَتْ فَاخْتَلَفُوا فِي ذَلِكَ قَالَ فَانْطَلَقْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أُنَاسًا يَقُولُونَ إِنَّ الْهِجْرَةَ قَدْ انْقَطَعَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْهِجْرَةَ لَا تَنْقَطِعُ مَا كَانَ الْجِهَادُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Laits] berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Abu Al Khair] sesungguhnya [Junadah bin Abu Umayyah] menceritakannya sesungguhnya seorang laki-laki dari sahabat Rasulullah Shallallahu'alaihiwasallam, sebagian berkata; sesungguhnya hijrah telah terputus lalu mereka berselisih dalam masalah itu. (Junadah bin Abu Umayyah radliyallahu'anhu) berkata; lalu saya menemui Rasulullah Shallallahu'alaihiwasallam, lalu saya berkata; Wahai Rasulullah, orang-orang mengatakan bahwa hijrah telah terputus. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Hijrah tidak terputus selama masih ada jihad.\""},"1180":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي عُقَيْلٌ عَنِ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَسُلَيْمَانَ بْنِ يَسَارٍ عَنْ إِنْسَانٍ مِنْ الْأَنْصَارِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ الْقَسَامَةَ كَانَتْ فِي الْجَاهِلِيَّةِ قَسَامَةَ الدَّمِ فَأَقَرَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَا كَانَتْ عَلَيْهِ فِي الْجَاهِلِيَّةِ وَقَضَى بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أُنَاسٍ مِنْ الْأَنْصَارِ مِنْ بَنِي حَارِثَةَ ادَّعُوهُ عَلَى الْيَهُودِ","id":"Telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepadaku [Laits] berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dan [Sulaiman bin Yasar] dari [salah seorang dari Anshar] dari sahabat Nabi Shallallahu'alaihiwasallam sesungguhnya Al Qasamah (bersumpahnya lima puluh orang laki-laki untuk membuktikan bahwa seseorang tidak terlibat tindak pembunuhan) pada masa Jahiliyah, yaitu qasamah darah, lalu Rasulullah Shallallahu'alaihiwasallam melestarikan hukum yang ada pada masa jahiliyyah tersebut, dan Rasulullah Shallallahu'alaihiwasallam memutuskan dengan hukum qasamah tersebut antara beberapa orang dari Anshar dari Bani Haritsah yang menuntutnya atas seorang Yahudi."},"1181":{"ar":"قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدٍ الْجُرَيْرِيِّ قَالَ سَمِعْتُ عُبَيْدَ بْنَ الْقَعْقَاعِ يُحَدِّثُ رَجُلًا مِنْ بَنِي حَنْظَلَةَ قَالَرَمَقَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَجَعَلَ يَقُولُ فِي صَلَاتِهِ اللَّهُمَّ اغْفِرْ لِي ذَنْبِي وَوَسِّعْ لِي فِي دَارِي وَبَارِكْ لِي فِيمَا رَزَقْتَنِي","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepada kami [Syu'bah] dari [Sa'id Al Jurairi] berkata; saya telah mendengar ['Ubaid bin Al Qa'qa'] menceritakan kepada seorang [laki-laki dari Bani Hanzhalah] berkata; ada seorang laki-laki yang memandang sepintas pada Nabi Shallallahu'alaihiwasallam saat beliau sedang shalat, beliau membaca dalam shalatnya: Ya Allah, ampunilah dosaku dan luaskanlah pada rumahku dan berilah berkah pada semua rizki yang Engkau berikan kepadaku\""},"1182":{"ar":"قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ قَالَ قُلْتُ لِجُنْدُبٍ إِنِّي قَدْ بَايَعْتُ هَؤُلَاءِ يَعْنِي ابْنَ الزُّبَيْرِ وَإِنَّهُمْ يُرِيدُونَ أَنْ أَخْرُجَ مَعَهُمْ إِلَى الشَّامِ فَقَالَ أَمْسِكْ فَقُلْتُ إِنَّهُمْ يَأْبَوْنَ فَقَالَ افْتَدِ بِمَالِكَ قَالَ قُلْتُ إِنَّهُمْ يَأْبَوْنَ إِلَّا أَنْ أَضْرِبَ مَعَهُمْ بِالسَّيْفِ فَقَالَ جُنْدُبٌ حَدَّثَنِي فُلَانٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجِيءُ الْمَقْتُولُ بِقَاتِلِهِ يَوْمَ الْقِيَامَةِ فَيَقُولُ يَا رَبِّ سَلْ هَذَا فِيمَ قَتَلَنِي قَالَ شُعْبَةُ فَأَحْسِبُهُ قَالَ فَيَقُولُ عَلَامَ قَتَلْتَهُ فَيَقُولُ قَتَلْتُهُ عَلَى مُلْكِ فُلَانٍ قَالَفَقَالَ جُنْدُبٌ فَاتَّقِهَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu 'Imran] berkata; saya berkata kepada Jundub, sesungguhnya saya telah berbaiat kepada mereka maksudnya kepada kelompok Ibnu Az Zubair, sehingga mereka menghendaki agar saya berangkat bersama mereka menuju Syam. Lalu Jundub berkata 'tahanlah', lalu saya berkata; 'mereka menolaknya', Jundub berkata; 'Tebuslah dengan hartamu.' (Abu 'Imran radliyallahu'anhu) berkata; mereka menolaknya kecuali jika saya mau berperang bersama mereka dengan membawa pedang. Lalu [Jundub], telah menceritakan kepadaku [Fulan], Rasulullah Shallallahu'alaihiwasallam pernah bersabda: \"Akan datang orang yang terbunuh pada Hari Kiamat dengan orang yang membunuhnya, lalu berkata; Wahai Rabb! Tanyakanlah kepada orang ini, dengan alasan apa dia membunuhku? Syu'bah berkata; saya yakin dia berkata; Dia berkata; atas dasar apa kau membunuhnya?, maka dia menjawab, saya membunuh untuk membela kerajaan (kekuasaan) si fulan. (Abu 'Imran radliyallahu'anhu) berkata; lalu Jundub berkata; maka takutlah terhadap pembunuhan karena dorongan seperti itu."},"1183":{"ar":"قَالَ حَدَّثَنَا أَبُو نُوحٍ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْكُبُ عَلَى رَأْسِهِ الْمَاءَ بِالسُّقْيَا إِمَّا مِنْ الْحَرِّ وَإِمَّا مِنْ الْعَطَشِ وَهُوَ صَائِمٌ ثُمَّ لَمْ يَزَلْ صَائِمًا حَتَّى أَتَى كَدِيدًا ثُمَّ دَعَا بِمَاءٍ فَأَفْطَرَ وَأَفْطَرَ النَّاسُ وَهُوَ عَامُ الْفَتْحِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nuh] berkata; telah mengabarkan kepada kami [Malik] dari [Sumai] dari [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] dari [seseorang sahabat Nabi Shallallahu'alaihiwasallam] berkata; saya telah melihat Nabi Shallallahu'alaihiwasallam menuangkan pada kepalanya dengan air dengan dengan bejana, entah karena panas atau karena haus padahal beliau sedang berpuasa, lalu beliau tetap berpuasa sampai beliau di Kadid, lalu beliau meminta air dan berbuka dan orang-orang berbuka pada saat tahun terjadinya Fathu Makkah."},"1184":{"ar":"قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ سُمَيٍّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَامَ فِي سَفَرٍ عَامَ الْفَتْحِ وَأَمَرَ أَصْحَابَهُ بِالْإِفْطَارِ وَقَالَ إِنَّكُمْ تَلْقَوْنَ عَدُوًّا لَكُمْ فَتَقَوَّوْا فَقِيلَ يَا رَسُولَ اللَّهِ إِنَّ النَّاسَ قَدْ صَامُوا لِصِيَامِكَ فَلَمَّا أَتَى الْكَدِيدَ أَفْطَرَ قَالَ الَّذِي حَدَّثَنِي فَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُبُّ الْمَاءَ عَلَى رَأْسِهِ مِنْ الْحَرِّ وَهُوَ صَائِمٌ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami ['Utsman bin 'Umar] berkata; telah mengabarkan kepada kami [Malik bin Anas] dari [Sumai] dari [Abu Bakar bin Abdurrahman bin Al Harits] dari [seorang sahabat Nabi Shallallahu'alaihiwasallam], Rasulullah Shallallahu'alaihiwasallam berpuasa dalam suatu perjalanan pada saat Fathu Makkah, dan beliau memerintahkan para sahabatnya untuk berbuka dan bersabda: \"Kalian akan menjumpai musuh kalian, maka perkuatlah fisik kalian\" Lalu ada yang bertanya 'Wahai Rasulullah, sebagian orang berpuasa karena anda berpuasa.' Tatkala sampai di Kadid beliau berbuka. Orang yang telah menceritakan kepadaku berkata; sungguh saya telah melihat Rasulullah Shallallahu'alaihiwasallam memercikkan air pada kepalanya karena panas dan beliau dalam keadaan puasa."},"1185":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ أَشْعَثَ قَالَ حَدَّثَنِي شَيْخٌ مِنْ بَنِي مَالِكِ بْنِ كِنَانَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسُوقِ ذِي الْمَجَازِ يَتَخَلَّلُهَا يَقُولُ يَا أَيُّهَا النَّاسُ قُولُوا لَا إِلَهَ إِلَّا اللَّهُ تُفْلِحُوا قَالَ وَأَبُو جَهْلٍ يَحْثِي عَلَيْهِ التُّرَابَ وَيَقُولُ يَا أَيُّهَا النَّاسُ لَا يَغُرَّنَّكُمْ هَذَا عَنْ دِينِكُمْ فَإِنَّمَا يُرِيدُ لِتَتْرُكُوا آلِهَتَكُمْ وَتَتْرُكُوا اللَّاتَ وَالْعُزَّى قَالَ وَمَا يَلْتَفِتُ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْنَا انْعَتْ لَنَا رَسُولَ اللَّهِ قَالَ بَيْنَ بُرْدَيْنِ أَحْمَرَيْنِ مَرْبُوعٌ كَثِيرُ اللَّحْمِ حَسَنُ الْوَجْهِ شَدِيدُ سَوَادِ الشَّعْرِ أَبْيَضُ شَدِيدُ الْبَيَاضِ سَابِغُ الشَّعْرِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Syaiban] dari [Asy'ats] berkata; telah menceritakan kepadaku [Syaikh dari Bani Malik bin Kinanah] berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam di pasar Dzil Majaz, beliau melewati sela-selanya. Beliau bersabda: \"Wahai manusia, katakanlah LAA ILAAHA ILLALLAAH (tidak ada tuhan selain Allah) maka kalian akan beruntung.\" (Syaikh dari Bani Malik bin Kinanah radliyallahu'anhu) berkata; Abu Jahal melemparkan tanah kepada beliau dan berkata; Wahai manusia jangan sampai orang ini menyesatkan kalian dari agama kalian. Dia hanya menginginkan agar kalian meninggalkan tuhan-tuhan kalian, kalian meninggalkan Lata dan Al Uzza. (Syaikh dari Bani Malik bin Kinanah radliyallahu'anhu) berkata; dan Rasulullah Shallallahu'alaihiwasallam tidak menoleh kepadanya. (Syaikh dari Bani Malik bin Kinanah radliyallahu'anhu) berkata; kami bertanya, berikan tanda-tanda Rasulullah Shallallahu'alaihiwasallam kepada kami! Dia menjawab, beliau memakai dua mantel yang berwarna, tinggi beliau sedang dan banyak dagingnya, wajahnya bagus, rambutnya sangat hitam, kulitnya putih sangat dan rambutnya lebat."},"1186":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ أَشْعَثَ عَنِ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ رَجُلٍ مِنْ قَوْمِهِ قَالَكَانَ يَقُولُ فِي خِلَافَةِ عُمَرَ بْنِ الْخَطَّابِ لَا يَمُوتُ عُثْمَانُ حَتَّى يُسْتَخْلَفَ قُلْنَا مِنْ أَيْنَ تَعْلَمُ ذَلِكَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رَأَيْتُ اللَّيْلَةَ فِي الْمَنَامِ كَأَنَّهُ ثَلَاثَةٌ مِنْ أَصْحَابِي وُزِنُوا فَوُزِنَ أَبُو بَكْرٍ فَوَزَنَ ثُمَّ وُزِنَ عُمَرُ فَوَزَنَ ثُمَّ وُزِنَ عُثْمَانُ فَنَقَصَ صَاحِبُنَا وَهُوَ صَالِحٌ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Syaiban] dari [Al Asy'ats] dari [Al Aswad bin Hilal] dari [seorang dari kaumnya] berkata; dia berkata pada masa ke khilafahan 'Umar Al Khattab, tidak akan mati 'Utsman sehingga dia diangkat menjadi seorang khilafah. Kami bertanya, 'Dari mana kamu mengetahui hal itu?. Dia menjawab, saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Tadi malam aku bermimpi seolah-olah tiga sahabatku ditimbang, Abu Bakar ditimbang dan timbangan begitu berat, 'Umar ditimbang dan timbangan begitu berat, kemudian 'Utsman namun sahabat kami menguranginya dan dia adalah orang yang shalih.\""},"1187":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ مُهَاجِرٍ أَبِي الْحَسَنِ عَنْ شَيْخٍ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَخَرَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَمَرَّ بِرَجُلٍ يَقْرَأُ قُلْ يَا أَيُّهَا الْكَافِرُونَ قَالَ أَمَّا هَذَا فَقَدْ بَرِئَ مِنْ الشِّرْكِ قَالَ وَإِذَا آخَرُ يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَا وَجَبَتْ لَهُ الْجَنَّةُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Al Mas'udi] dari [Muhajir Abu Al Hasan] dari [seorang yang sudah tua yang mendapatkan masa Nabi Shallallahu'alaihiwasallam] berkata; saya keluar bersama Nabi Shallallahu'alaihiwasallam dalam suatu perjalanan, lalu kami melewati seorang laki-laki yang sedang membaca, QUL YAA AYYUHAL KAAFIRUUN, maka beliau bersabda: \"dia telah terbebas dari syirik\", dan yang lainnya membaca QUL HUWA AllAHU AHAD, lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Dengan surat itu, wajib baginya mendapatkan surga.\""},"1188":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبِي وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ عَنْ حُمْرَانَ بْنِ أَعْيَنَ عَنْ أَبِي الطُّفَيْلِ عَنْ فُلَانِ بْنِ جَارِيَةَ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخَاكُمْ النَّجَاشِيَّ قَدْ مَاتَ فَصَلُّوا عَلَيْهِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku bapakku dan Abu Bakar bin Abu Syaibah telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan] dari [Humran bin A'yan] dari [Abu Ath-Thufail] dari [Fulan bin Jariyah Al Anshary] berkata; Rasulullah bersabda: \"Saudaramu An-Najasyi telah meninggal, maka shalatilah dia.\""},"1189":{"ar":"قَالَ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ قَالَ حَدَّثَنَا ابْنُ جَعْفَرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنِ ابْنَةِ كَرْدَمَةَ عَنْ أَبِيهَا أَنَّهُسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي نَذَرْتُ أَنْ أَنْحَرَ ثَلَاثَةً مِنْ إِبِلِي فَقَالَ إِنْ كَانَ عَلَى جَمْعٍ مِنْ جَمْعِ الْجَاهِلِيَّةِ أَوْ عَلَى عِيدٍ مِنْ أَعْيَادِ الْجَاهِلِيَّةِ أَوْ عَلَى وَثَنٍ فَلَا وَإِنْ كَانَ عَلَى غَيْرِ ذَلِكَ فَاقْضِ نَذْرَكَ قَالَ يَا رَسُولَ اللَّهِ إِنَّ عَلَى أُمِّ هَذِهِ الْجَارِيَةِ مَشْيًا أَفَأَمْشِي عَنْهَا قَالَ نَعَمْ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Bakar Al Hanafi] berkata; telah menceritakan kepada kami [Ibnu Ja'far] dari ['Amr bin Syua'ib] dari [anak perempuan Kardamah] dari [bapaknya] sesungguhnya bapaknya bertanya kepada Rasulullah Shallallahu'alaihiwasallam berkata; Aku bernadzar untuk menyembelih tiga ekor untaku, maka beliau bersabda: \"Jika nadzar dalam suatu perkumpulan Jahiliyyah ataupun hari raya dari hari raya orang Jahiliyyah ataupun untuk berhala, janganlah kamu melaksanakan nadzarmu, tetapi apabila untuk selain hAl hal tersebut penuhilah nadzarmu\" Dia bertanya, \"Wahai Rasulullah, ibu dari anak wanita ini meniatkan untuk berjalan, apakah saya harus berjalan untuknya?\", beliau menjawab, Ya."},"1190":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ التَّنُوخِيِّ قَالَ حَدَّثَنَا مَوْلًى لِيَزِيدَ بْنِ نِمْرَانَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ نِمْرَانَ قَالَلَقِيتُ رَجُلًا مُقْعَدًا شَوَّالًا فَسَأَلْتُهُ قَالَ مَرَرْتُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَتَانٍ أَوْ حِمَارٍ فَقَالَ قَطَعَ عَلَيْنَا صَلَاتَنَا قَطَعَ اللَّهُ أَثَرَهُ فَأُقْعِدَ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Sa'id bin Abdul Aziz At-Tanukhi] berkata; telah menceritakan kepada kami [budak milik Yazid bin Nimran] berkata; telah menceritakan kepadaku [Yazid bin Nimran] berkata; saya pernah bertemu [seseorang yang hanya bisa duduk di tempatnya], lalu saya bertanya kepadanya. Dia lantas menceritakan suatu peristiwa, 'Saya pernah lewat di depan Rasulullah Shallallahu'alaihiwasallam (ketika beliau shalat) dan saya saat itu menunggang keledai betina atau keledai-si perawi tidak ingat, lalu beliau bersabda: \"Dia telah memutus shalat kami semoga Allah memutus nama baiknya setelah meninggal, dan jadikanlah ia hanya bisa duduk.\""},"1191":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ يَعْنِي شَيْبَانَ عَنْ لَيْثٍ عَنْ شَهْرٍ قَالَ حَدَّثَنِي الْأَنْصَارِيُّ صَاحِبُ بُدْنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا بَعَثَهُ قَالَ رَجَعْتُ فَقُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ مَا تَأْمُرُنِي بِمَا عَطِبَ مِنْهَا قَالَ انْحَرْهَا ثُمَّ اصْبُغْ نَعْلَهَا فِي دَمِهَا ثُمَّ ضَعْهَا عَلَى صَفْحَتِهَا أَوْ عَلَى جَنْبِهَا وَلَا تَأْكُلْ مِنْهَا أَنْتَ وَلَا أَحَدٌ مِنْ أَهْلِ رُفْقَتِكَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] yaitu Syaiban dari [Laits] dari [Syahr] berkata; telah menceritakan kepadaku [Al Anshari] penggembala unta Nabi Shallallahu'alaihiwasallam, sesungguhnya Rasulullah Shallallahu'alaihiwasallam tatkala beliau mengutusnya, beliau berkata 'Engkau telah kembali?, saya menjawab, benar Wahai Rasulullah, apa yang anda perintahkan, dengan segala hal yang bisa merusaknya?. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Sembelihlah, lalu taruhlah sandalnya pada darahnya kemudian letakkanlah pada dua pipinya atau pada sampingnya dan janganlah kamu memakannya, baik kamu atau kenalan-kenalanmu.\""},"1192":{"ar":"حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ سُلَيْمَانَ بْنِ سُحَيْمٍ عَنْ أُمِّهِ ابْنَةِ أَبِي الْحَكَمِ الْغِفَارِيِّ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الرَّجُلَ لَيَدْنُو مِنْ الْجَنَّةِ حَتَّى يَكُونَ مَا بَيْنَهُ وَبَيْنَهَا قِيدُ ذِرَاعٍ فَيَتَكَلَّمُ بِالْكَلِمَةِ فَيَتَبَاعَدُ مِنْهَا أَبْعَدَ مِنْ صَنْعَاءَ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Muhammad bin Ishaq] dari [Sulaiman bin Suhaim] dari [Ibunya, anak perempuan Abu Al Hakam Al Ghifari] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sungguh ada seseorang laki-laki yang telah mendekati surga sampai jarak antara dia dengan surga tinggal seukuran satu dzira' (hasta), lalu dia mengucapkan sepatah kata yang bisa menjauhkannya dari surga melebihi jauhnya dari Shan'a."},"1193":{"ar":"قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَمْرِو بْنِ مُعَاذٍ الْأَشْهَلِيِّ عَنْ جَدَّتِهِ أَنَّها قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا نِسَاءَ الْمُؤْمِنَاتِ لَا تَحْقِرَنَّ إِحْدَاكُنَّ لِجَارَتِهَا وَلَوْ كُرَاعُ شَاةٍ مُحْرَقٌ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Rauh] berkata; telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Amr bin Mu'adz Al Asyhali] dari [neneknya] sesungguhnya dia berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wahai kaum wanita mukmin, janganlah seorang diantara kalian menyepelekan hadiah untuk tetangganya walau hanya dengan kaki kambing yang dimasak (dipanggang).\""},"1194":{"ar":"حَدَّثَنَا رَوْحٌ وَعَبْدُ الرَّزَّاقِ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي حَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ رَجُلٍ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الطَّوَافُ صَلَاةٌ فَإِذَا طُفْتُمْ فَأَقِلُّوا الْكَلَامَ وَلَمْ يَرْفَعْهُ ابْنُ بَكْرٍ","id":"Telah menceritakan kepada kami [Rauh] dan [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Hasan bin Muslim] dari [Thawus] dari [seseorang laki-laki yang mendapati Nabi Shallallahu'alaihiwasallam] sesungguhnya Nabi Shallallahu'alaihiwasallam bersabda: \"Thawaf itu layaknya shalat, maka jika kalian berthawaf sedikitkanlah bicara\" Dalam hal ini [Ibnu Bakar] tidak memarfukkannya."},"1195":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنِ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ بَنِي يَرْبُوعٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ وَهُوَ يُكَلِّمُ النَّاسَ يَقُولُ يَدُ الْمُعْطِي الْعُلْيَا أُمَّكَ وَأَبَاكَ وَأُخْتَكَ وَأَخَاكَ ثُمَّ أَدْنَاكَ فَأَدْنَاكَ قَالَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو ثَعْلَبَةَ الَّذِينَ أَصَابُوا فُلَانًا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا لَا تَجْنِي نَفْسٌ عَلَى أُخْرَى","id":"Telah menceritakan kepada kami [Yunus] berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Al Asy'ats bin Sulaim] dari [Bapaknya] dari [seorang laki-laki dari Bani Yarbu'] berkata; saya mendatangi Nabi Shallallahu'alaihiwasallam, lalu saya mendengarnya, beliau berbicara kepada orang-orang, beliau bersabda: \"Tangan orang yang memberi itu yang berada diatas, Dahulukan pemberian kepada ibumu, bapakmu dan saudara laki-lakimu, lalu yang terdekat, lalu yang terdekat\". (seorang laki-laki dari Bani Yarbu' Radliyallahu'anhu) berkata; lalu ada seorang laki-laki yang berkata; Wahai Rasulullah, Juga untuk Bani Tsa'labah yang telah bertindak kejahatan kepada si fulan?. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ketahuilah, bahwasanya seseorang terlarang bertindak aniaya kepada lainnya\"."},"1196":{"ar":"قَالَ حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنِ الْأَزْرَقِ بْنِ قَيْسٍ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَا يُحَاسَبُ بِهِ الْعَبْدُ صَلَاتُهُ فَإِنْ كَانَ أَتَمَّهَا كُتِبَتْ لَهُ تَامَّةً وَإِنْ لَمْ يَكُنْ أَتَمَّهَا قَالَ اللَّهُ عَزَّ وَجَلَّ انْظُرُوا هَلْ تَجِدُونَ لِعَبْدِي مِنْ تَطَوُّعٍ فَتُكْمِلُوا بِهَا فَرِيضَتَهُ ثُمَّ الزَّكَاةُ كَذَلِكَ ثُمَّ تُؤْخَذُ الْأَعْمَالُ عَلَى حَسَبِ ذَلِكَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Al Arzaq bin Qais] dari [Yahya bin Ya'mar] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Yang pertama kali dihisab dari seorang hamba adalah shalatnya, jika dia menyempurnakannya maka akan ditulis secara sempurna. Jika dia tidak menyempurnakannya, maka Allah Azza wa jalla berfirman: 'Lihatlah kalian, apakah kalian mendapatkan pada hamba-Ku amalan sunah sehingga menjadi sempurna kewajibannya?, lalu zakatnya demikian juga, semua amal akan diperiksa seperti itu.\""},"1197":{"ar":"قَالَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَاقَ عَنِ الْمُهَلَّبِ بْنِ أَبِي صُفْرَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أُرَاهُمْ اللَّيْلَةَ إِلَّا سَيُبَيِّتُونَكُمْ فَإِنْ فَعَلُوا فَشِعَارُكُمْ حم لَا يُنْصَرُونَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Aswad bin 'Amir] berkata; telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Al Muhallab bin Abu Shufrah] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Saya taksir mereka pasti akan menyerang kalian pada malam ini, jika mereka melakukannya maka sandi kalian adalah HAMIM, LA YUNSHARUN.\""},"1198":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا الْحَكَمُ بْنُ فُضَيْلٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي تَمِيمَةَ عَنْ رَجُلٍ مِنْ قَوْمِهِأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَتَاهُ رَجُلٌ فَقَالَ أَنْتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ أَنْتَ مُحَمَّدٌ فَقَالَ نَعَمْ قَالَ فَإِلَامَ تَدْعُو قَالَ أَدْعُو إِلَى اللَّهِ عَزَّ وَجَلَّ وَحْدَهُ مَنْ إِذَا كَانَ بِكَ ضُرٌّ فَدَعَوْتَهُ كَشَفَهُ عَنْكَ وَمَنْ إِذَا أَصَابَكَ عَامُ سَنَةٍ فَدَعَوْتَهُ أَنْبَتَ لَكَ وَمَنْ إِذَا كُنْتَ فِي أَرْضٍ قَفْرٍ فَأَضْلَلْتَ فَدَعَوْتَهُ رَدَّ عَلَيْكَ قَالَ فَأَسْلَمَ الرَّجُلُ ثُمَّ قَالَ أَوْصِنِي يَا رَسُولَ اللَّهِ قَالَ لَهُ لَا تَسُبَّنَّ شَيْئًا أَوْ قَالَ أَحَدًا شَكَّ الْحَكَمُ قَالَ فَمَا سَبَبْتُ بَعِيرًا وَلَا شَاةً مُنْذُ أَوْصَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تَزْهَدْ فِي الْمَعْرُوفِ وَلَوْ مُنْبَسِطٌ وَجْهُكَ إِلَى أَخِيكَ وَأَنْتَ تُكَلِّمُهُ وَأَفْرِغْ مِنْ دَلْوِكَ فِي إِنَاءِ الْمُسْتَسْقِي وَاتَّزِرْ إِلَى نِصْفِ السَّاقِ فَإِنْ أَبَيْتَ فَإِلَى الْكَعْبَيْنِ وَإِيَّاكَ وَإِسْبَالَ الْإِزَارِ فَإِنَّهَا مِنْ الْمَخِيلَةِ وَاللَّهُ تَبَارَكَ وَتَعَالَى لَا يُحِبُّ الْمَخِيلَةَ","id":"Telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Al Hakam bin Fudlail] dari [Khalid Al Hadza`] dari [Abu Tamimah] dari [seorang laki-laki dari kaumnya] sesungguhnya dia mendatangi Rasulullah Shallallahu'alaihiwasallam atau berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam didatangi oleh seorang laki-laki lalu bertanya, apakah kamu adalah Rasulullah Shallallahu'alaihiwasallam atau berkata; kamu adalah Muhammad?. Lalu beliau menjawab, Ya. Dia berkata; kepada apa kamu berseru? Beliau menjawab, saya menyeru kepada Allah Azza wa jalla Yang Maha Esa, jika kamu tertimpa bahaya lalu kamu meminta kepada-Nya maka Dia akan menghilangkannya. Dan jika ada tahun masa paceklik yang datang pada kalian lalu kamu meminta kepada-Nya maka Dia akan menumbuhkannya. Jika kamu berada pada tanah yang tandus, lalu kamu hilang, lalu meminta kepada-Nya maka Dia akan mengembalikanmu. (seorang laki-laki dari kaumnya radliyallahu'anhu) berkata; lalu orang itu masuk Islam, lalu berkata; 'Berilah wasiat kepadaku Wahai Rasulullah.' Beliau bersabda kepadanya, \"Janganlah kamu mencela sesuatu pun\". Atau berkata; \"Seorang pun.\" Al Hakam ragu. (seorang laki-laki radliyallahu'anhu) berkata; karenanya saya tidak pernah mencela unta maupun kambing sekalipun semenjak Rasulullah Shallallahu'alaihiwasallam memberi wasiat kepadaku. (Rasulullah juga berwasiat) Janganlah kamu menganggap remeh suatu kebaikan walaupun kamu hanya tersenyum kepada saudaramu ketika kamu sedang berbicara dengannya. Kosongkan embermu untuk kau isikan kepada bejana orang yang meminta air dan pakailah pakaian setengah betis. Jika kamu merasa berat maka sampai mata kaki. Hindarilah isbal (menurunkan pakaian sampai menutupi mata kaki) dalam pakaian sesungguhnya itu merupakan bagian dari kesombongan. Sedang Allah Tabaroka Wa Ta'ala tidak menyukai orang yang sombong.\""},"1199":{"ar":"قَالَ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ مُهَاجِرٍ الصَّائِغِ عَنْ رَجُلٍ لَمْ يُسَمِّهِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ سَمِعَ رَجُلًا يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ قُلْ يَا أَيُّهَا الْكَافِرُونَ قَالَ أَمَّا هَذَا فَقَدْ بَرِئَ مِنْ الشِّرْكِ وَسَمِعَ آخَرَ يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ فَقَالَ أَمَّا هَذَا فَقَدْ غُفِرَ لَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Al Aswad bin 'Amir] berkata; telah menceritakan kepada kami [Syarik] dari [Muhajir Ash-shaigh] dari [seorang yang tidak ada namanya dari kalangan sahabat] Nabi Shallallahu'alaihiwasallam sesungguhnya dia mendengar seorang laki-laki yaitu Nabi Shallallahu'alaihiwasallam membaca 'QUL YAA AYYUHAL KAAFIRUUN', beliau bersabda: \"Orang ini telah terbebas dari syirik\", dan telah mendengar yang lainnya membaca, 'QUL HUWAAllAHU AHAD', lalu (Nabi Shallallahu'alaihiwasallam) bersabda: \"Sedangkan orang ini, sungguh dia telah diampuni.\""},"1200":{"ar":"قَالَ حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي الزُّبَيْرِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَعْدًا أَوْ أَسْعَدَ بْنَ زُرَارَةَ فِي حَلْقِهِ مِنْ الذُّبْحَةِ وَقَالَ لَا أَدَعُ فِي نَفْسِي حَرَجًا مِنْ سَعْدٍ أَوْ أَسْعَدَ بْنِ زُرَارَةَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; tatkala [Hasan bin Musa] berkata; telah menceritakan kepada kami [Zuhair] dari [Abu Az Zubair] dari ['Amr bin Syu'aib] dari [Bapaknya] dari [sebagian sahabat Nabi Shallallahu'alaihiwasallam] berkata; Rasulullah Shallallahu'alaihiwasallam pernah mengobati seseorang dengan cara kay (metode pengobatan dengan cara mengunakan besi yang dipanaskan dan disundutkan ke organ yang sakit) kepada Saad atau As'ad bin Zurarah pada tenggorokannya karena luka dan bersabda: \"Saya anggap tidak masalah dari Saad atau As'ad bin Zurarah.\""},"1201":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ الْفَضْلِ بْنِ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَ سَمِعْتُ رِجَالًا يَتَحَدَّثُونَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا أُعْتِقَتْ الْأَمَةُ فَهِيَ بِالْخِيَارِ مَا لَمْ يَطَأْهَا إِنْ شَاءَتْ فَارَقَتْهُ وَإِنْ وَطِئَهَا فَلَا خِيَارَ لَهَا وَلَا تَسْتَطِيعُ فِرَاقَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Ishaq] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Ubaidullah bin Abu Ja'far] dari [Al Fadl bin 'Amr bin Umayyah] dari [Bapaknya] berkata; saya telah mendengar [beberapa orang yang mereka saling menceritakan] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda: \"Jika budak wanita dimerdekakan maka dia berhak melakukan pilihan (ikut majikan atau meninggalkannya) selama dia belum digauli, jika dia mau maka dia bisa meninggalkan majikannya. Sebaliknya jika telah digauli maka dia tidak boleh memilih dan dia tidak bisa meninggalkan tuannya\"."},"1202":{"ar":"قَالَ حَدَّثَنَا حَسَنٌ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي جَعْفَرٍ عَنِ الْفَضْلِ بْنِ الْحَسَنِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ قَالَ سَمِعْتُ رِجَالًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَحَدَّثُونَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُعْتِقَتْ الْأَمَةُ وَهِيَ تَحْتَ الْعَبْدِ فَأَمْرُهَا بِيَدِهَا فَإِنْ هِيَ أَقَرَّتْ حَتَّى يَطَأَهَا فَهِيَ امْرَأَتُهُ لَا تَسْتَطِيعُ فِرَاقَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hasan] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakan kepada kami ['Ubaidullah bin Abu Ja'far] dari [Al Fadl bin Al Hasan bin 'Amr bin Umayyah Adl-Dlamri] berkata; saya telah mendengar [beberapa orang sahabat Rasulullah Shallallahu'alaihiwasallam] yang menceritakan sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika seorang budak wanita dimerdekakan dan dia di bawah seorang budak laki-laki, maka urusannya berada di tangannya sehingga dia yang memutuskannya. Namun jika dia telah digauli, maka dia adalah istrinya dan dia tidak bisa meninggalkan (budak laki-laki tersebut) \"."},"1203":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ يَزِيدَ يَعْنِي ابْنَ جَابِرٍ عَنْ خَالِدِ بْنِ اللَّجْلَاجِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَائِشٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْهِمْ ذَاتَ غَدَاةٍ وَهُوَ طَيِّبُ النَّفْسِ مُسْفِرُ الْوَجْهِ أَوْ مُشْرِقُ الْوَجْهِ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّا نَرَاكَ طَيِّبَ النَّفْسِ مُسْفِرَ الْوَجْهِ أَوْ مُشْرِقَ الْوَجْهِ فَقَالَ وَمَا يَمْنَعُنِي وَأَتَانِي رَبِّي عَزَّ وَجَلَّ اللَّيْلَةَ فِي أَحْسَنِ صُورَةٍ قَالَ يَا مُحَمَّدُ قُلْتُ لَبَّيْكَ رَبِّي وَسَعْدَيْكَ قَالَ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قُلْتُ لَا أَدْرِي أَيْ رَبِّ قَالَ ذَلِكَ مَرَّتَيْنِ أَوْ ثَلَاثًا قَالَ فَوَضَعَ كَفَّيْهِ بَيْنَ كَتِفَيَّ فَوَجَدْتُ بَرْدَهَا بَيْنَ ثَدْيَيَّ حَتَّى تَجَلَّى لِي مَا فِي السَّمَوَاتِ وَمَا فِي الْأَرْضِ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَكَذَلِكَ نُرِي إِبْرَاهِيمَ مَلَكُوتَ السَّمَوَاتِ وَالْأَرْضِ وَلِيَكُونَ مِنْ الْمُوقِنِينَ }ثُمَّ قَالَ يَا مُحَمَّدُ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قَالَ قُلْتُ فِي الْكَفَّارَاتِ قَالَ وَمَا الْكَفَّارَاتُ قُلْتُ الْمَشْيُ عَلَى الْأَقْدَامِ إِلَى الْجَمَاعَاتِ وَالْجُلُوسُ فِي الْمَسْجِدِ خِلَافَ الصَّلَوَاتِ وَإِبْلَاغُ الْوُضُوءِ فِي الْمَكَارِهِ قَالَ مَنْ فَعَلَ ذَلِكَ عَاشَ بِخَيْرٍ وَمَاتَ بِخَيْرٍ وَكَانَ مِنْ خَطِيئَتِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُ وَمِنْ الدَّرَجَاتِ طِيبُ الْكَلَامِ وَبَذْلُ السَّلَامِ وَإِطْعَامُ الطَّعَامِ وَالصَّلَاةُ بِاللَّيْلِ وَالنَّاسُ نِيَامٌ قَالَ يَا مُحَمَّدُ إِذَا صَلَّيْتَ فَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ الطَّيِّبَاتِ وَتَرْكَ الْمُنْكَرَاتِ وَحُبَّ الْمَسَاكِينِ وَأَنْ تَتُوبَ عَلَيَّ وَإِذَا أَرَدْتَ فِتْنَةً فِي النَّاسِ فَتَوَفَّنِي غَيْرَ مَفْتُونٍ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Yazid bin Yazid] yaitu Ibnu Jabir dari [Khalid bin Al Lajlaj] dari [Abdurrahman bin 'A`isy] dari [beberapa sahabat Nabi Shallallahu'alaihiwasallam] sesungguhnya Rasulullah Shallallahu'alaihiwasallam keluar menemui mereka pada suatu pagi dalam keadaan yang sangat baik dan berseri-seri wajahnya, terang wajahnya, lalu bersabda: \"Tidak ada yang menghalangiku, padahal telah datang Rabku Azzawajalla tadi malam dengan wajah sangat mempesona.\" Dia (Allah Azza wa jalla) berkata; 'Wahai Muhammad', saya menjawab, 'Ya Wahai Rabku.' Dia bertanya, dalam masalah apa para Malaikat yang tinggi saling berselisih, saya menjawab, saya tidak tahu Wahai Rabku. Dia berkata seperti itu dua kali atau tiga kali. Lalu Dia (Rab Muhammad) meletakkan kedua telapak tangannya antara kedua pundakku, lalu saya merasakan dinginnya di antara kedua dadaku sehingga Dia menampakkan kepadaku apa yang ada di langit dan apa yang ada di bumi, lalu beliau membaca ayat ini, 'Dan Demikianlah kami perlihatkan kepada Ibrahim tanda-tanda keagungan (Kami yang terdapat) di langit dan bumi dan (Kami memperlihatkannya) agar dia termasuk orang yang yakin. lalu Dia berfirman, Wahai Muhammad, dalam masalah apa para Malaikat yang tinggi saling berselisih?, saya menjawab, dalam masalah kaffarat (penghapusan dosa-dosa). Apakah kafarat itu? Saya menjawab, berjalan kaki menuju jamaah shalat dan duduk di masjid untuk menanti shalat-shalat ditegakkan dan meratakan berwudlu saat-saat tidak suka. Beliau bersabda: \"Barangsiapa yang melakukan hal itu maka dia akan hidup dengan baik dan meninggal dalam keadaan baik dan keadaannya dengan kesalahannya sebagaimana hari dia dilahirkan oleh ibunya, dan yang termasuk mengangkat derajat adalah perkataan yang baik, menyebarkan salam, memberi makanan, shalat malam saat manusia dalam keadaan tidur.\" Dia berfirman, \"Wahai Muhammad, jika kamu shalat maka bacalah: Ya Allah, sesungguhnya saya meminta kepada-Mu kebaikan-kebaikan, meninggalkan kemungkaran, mencintai orang miskin dan kamu dalam keadaan bertaubat kepada-Ku, dan jika Engkau menghendaki fitnah pada manusia, tolong wafatkanlahku dalam keadaan tidak terkena fitnah."},"1204":{"ar":"قَالَ حَدَّثَنَا الزُّبَيْرِيُّ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ عَامِرٍ قَالَ حَدَّثَنِي مَنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَأَمَرَ بِرَجْمِ رَجُلٍ بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَلَمَّا وَجَدَ مَسَّ الْحِجَارَةِ خَرَجَ فَهَرَبَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا تَرَكْتُمُوهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Az Zubairi Muhammad bin Abdullah] berkata; telah menceritakan kepada kami ['Israil] dari [Simak] berkata; telah menceritakan kepadaku [Abdul Aziz bin Abdullah bin 'Amir] berkata; telah menceritakan kepadaku [seseorang yang telah mendengar Nabi Shallallahu'alaihiwasallam], beliau memerintahkan seorang laki-laki untuk dirajam di lokasi antara Makkah dan Madinah. Tatkala dia merasakan sentuhan batu dia pergi dan kabur, lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Kenapa kalian tidak membiarkannya?.\""},"1205":{"ar":"قَالَ حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ رَجُلٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَتَى جُعِلْتَ نَبِيًّا قَالَ وَآدَمُ بَيْنَ الرُّوحِ وَالْجَسَدِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Suraij bin An-Nu'man] berkata; telah menceritakan kepada kami [Hammad] dari [Khalad Al Hadza'] dari [Abdullah bin Syaqiq] dari [seorang laki-laki] berkata; saya berkata; \"Wahai Rasulullah, kapankah anda dijadikan Nabi?\" Beliau menjawab, \"Tatkala Adam masih berupa ruh dan jasadnya.\""},"1206":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا الْمُبَارَكُ قَالَ حَدَّثَنَا الْحَسَنُ أَنَّ شَيْخًا مِنْ بَنِي سَلِيطٍ أَخْبَرَهُ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُكَلِّمُهُ فِي سَبْيٍ أُصِيبَ لَنَا فِي الْجَاهِلِيَّةِ فَإِذَا هُوَ قَاعِدٌ وَعَلَيْهِ حَلْقَةٌ قَدْ أَطَافَتْ بِهِ وَهُوَ يُحَدِّثُ الْقَوْمَ عَلَيْهِ إِزَارُ قِطْرٍ لَهُ غَلِيظٌ قَالَ سَمِعْتُهُ يَقُولُ وَهُوَ يُشِيرُ بِإِصْبَعِهِ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يَخْذُلُهُ التَّقْوَى هَاهُنَا التَّقْوَى هَاهُنَا يَقُولُ أَيْ فِي الْقَلْبِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Al Mubarak] berkata; telah menceritakan kepada kami [Al Hasan] sesungguhnya [seorang yang sudah tua dari Bani Salith] mengabarinya berkata; saya menemui Nabi Shallallahu'alaihiwasallam, saya mengajak bicara beliau tentang tawanan perang dari kalangan anak-anak dan wanita yang kami dapatkan pada masa jahiliyah. Beliau saat itu sedang duduk dengan membawa lingkaran yang telah dilingkarkan dan beliau mengajak bicara orang-orang -Dan ketika itu beliau memakai sarung dari kain berjahit yang warna merahnya yang sangat tebal-(Orang tua bani Salith) itu berkata; saya mendengar (Rasulullah Shallallahu'alaihiwasallam) bersabda dan beliau memberi isyarat dengan jarinya, \"Seorang muslim itu saudara muslim lainnya, tidak boleh menganiayanya dan tidak boleh merendahkannya. Takwa itu letaknya di sini, takwa itu letaknya di sini.\" beliau mengatakannya yang maksudnya di hati."},"1207":{"ar":"قَالَ حَدَّثَنَا عُمَرُ بْنُ سَعْدٍ أَبُو دَاوُدَ الْحَفَرِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ قَالَ حَدَّثَنِي سَعْدُ بْنُ طَارِقٍ عَنْ بِلَالِ بْنِ يَحْيَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ أَخْبَرَنِي أَعْرَابِيٌّ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أَخَافُ عَلَى قُرَيْشٍ إِلَّا أَنْفُسَهَا قُلْتُ مَا لَهُمْ قَالَ أَشِحَّةٌ بَجَرَةٌ وَإِنْ طَالَ بِكَ عُمْرٌ لَتَنْظُرَنَّ إِلَيْهِمْ يَفْتِنُونَ النَّاسَ حَتَّى تَرَى النَّاسَ بَيْنَهُمْ كَالْغَنَمِ بَيْنَ الْحَوْضَيْنِ إِلَى هَذَا مَرَّةً وَإِلَى هَذَا مَرَّةً","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami ['Umar bin Sa'ad Abu Daud Al Hafari] berkata; telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Za`idah] berkata; telah menceritakan kepadaku [Sa'ad bin Thariq] dari [Bilal bin Yahya] dari ['Imran bin Husain] berkata; telah mengabarkan kepadaku [seorang Badui], sesungguhnya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada yang ditakutkan pada orang Quraisy kecuali diri mereka\". Saya bertanya, \"Apa yang terjadi pada mereka?\". Beliau menjawab, \"Mereka adalah orang yang sangat pelit, rakus dan sangat besar perutnya. Jika umurmu panjang, sungguh kamu akan dapat melihat mereka, mereka membuat fitnah pada manusia sehingga kamu melihat manusia antara mereka sebagaimana kambing yang berada di antara dua telaga. Terkadang ke sini sekali dan terkadang ke sana sekali.\" "},"1208":{"ar":"حَدَّثَنَا الزُّبَيْرِيُّ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ مَعْبَدِ بْنِ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَيْرٍ أَوْ عَمِيرَةَ قَالَ حَدَّثَنِي زَوْجُ ابْنَةِ أَبِي لَهَبٍ قَالَدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تَزَوَّجْتُ ابْنَةَ أَبِي لَهَبٍ فَقَالَ هَلْ مِنْ لَهْوٍ","id":"Telah menceritakan kepada kami [Az Zubairi] berkata; telah menceritakan kepada kami [Isra`il] dari [Simak] dari [Ma'bad bin Qais] dari [Abdullah bin 'Umair] atau 'Amirah berkata; telah menceritakan kepadaku [suami anak perempuan, Abu Lahab] berkata; Rasulullah Shallallahu'alaihiwasallam menemui kami ketika saya menikah dengan anak perempuan Abu lahab, lalu beliau bertanya, \"Bukankah hal ini hanyalah sia-sia belaka?.\""},"1209":{"ar":"قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا عَلِيٌّ عَنْ يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي حَيَّةُ التَّمِيمِيُّ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا شَيْءَ فِي الْهَامِ وَالْعَيْنُ حَقٌّ وَأَصْدَقُ الطِّيَرِ الْفَأْلُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami ['Ali] dari [Yahya] yaitu Ibnu Abu Katsir berkata; telah menceritakan kepadaku [Hayyah At-Tamimi] sesungguhnya [Bapaknya] mengabarinya, ia mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Anggapan ada Ham (keyakinan orang jahiliyah bahwa tulang mayat dapat berubah menjadi burung) adalah tidak ada kebenarannya sama sekali, dan 'ain (kedengkian yang timbul dari orang yang jahat) itu adalah benar dan tiyarah yang paling benar adalah Al fa'l (perkataan yang baik).\" "},"1210":{"ar":"قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا أَبَانُ وَعَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي جَعْفَرٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَبَيْنَمَا رَجُلٌ يُصَلِّي وَهُوَ مُسْبِلٌ إِزَارَهُ إِذْ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَتَوَضَّأْ قَالَ فَذَهَبَ فَتَوَضَّأَ ثُمَّ جَاءَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَتَوَضَّأْ قَالَ فَذَهَبَ فَتَوَضَّأَ ثُمَّ جَاءَ فَقَالَ مَا لَكَ يَا رَسُولَ اللَّهِ مَا لَكَ أَمَرْتَهُ يَتَوَضَّأُ ثُمَّ سَكَتَّ قَالَ إِنَّهُ كَانَ يُصَلِّي وَهُوَ مُسْبِلٌ إِزَارَهُ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يَقْبَلُ صَلَاةَ عَبْدٍ مُسْبِلٍ إِزَارَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yunus bin Muhammad] berkata; telah menceritakan kepada kami [Aban] dan [Abdushshomad] berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Ja'far] dari ['Atha` bin Yasar] dari [beberapa sahabat Nabi Shallallahu'alaihiwasallam] berkata; tatkala ada seorang yang shalat dalam keadaan isbal (memanjangkan kainnya sampai bawah mata kaki) pada sarungnya, Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya, \"Pergilah dan berwudlulah\". (beberapa sahabat radliyallahu'anhum) berkata; lalu orang itu pergi dan wudlu, lalu datang lagi. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya, \"Pergilah dan berwudlulah.\" (beberapa sahabat radliyallahu'anhum) berkata; lalu dia pergi dan berwudlku, kemudian datang. lalu (beberapa sahabat radliyallahu'anhum) bertanya, kenapa anda Wahai Rasulullah, kenapa anda memerintahkannya untuk berwudlu kemudian anda diam?. Beliau menjawab, \"Dia shalat sedangkan dia dalam keadaan musbil sarungnya, sesungguhnya Allah Azza wa jalla tidak menerima shalat seorang hamba yang sarungnya isbal.\" "},"1211":{"ar":"قَالَ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ النَّاقِدُ قَالَ حَدَّثَنَا عُبَيْدَةُ بْنُ حُمَيْدٍ الضَّبِّيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ ذِي الْغُرَّةِ قَالَعَرَضَ أَعْرَابِيٌّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِيرُ فَقَالَ يَا رَسُولَ اللَّهِ تُدْرِكُنَا الصَّلَاةُ وَنَحْنُ فِي أَعْطَانِ الْإِبِلِ أَفَنُصَلِّي فِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَالَ أَفَنَتَوَضَّأُ مِنْ لُحُومِهَا قَالَ نَعَمْ قَالَ أَفَنُصَلِّي فِي مَرَابِضِ الْغَنَمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ أَفَنَتَوَضَّأُ مِنْ لُحُومِهَا قَالَ لَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami Abdullah telah menceritakan kepada kami ['Amr bin Muhammad An-Naqid] berkata; telah menceritakan kepada kami ['Ubaidah bin Humaid Adl-Dlab'i] dari [Abdullah bin Abdullah] dari [Abdurrahman bin Abu Ya'la] dari [Dzil Ghurrah] berkata; seorang Badui datang kepada Rasulullah Shallallahu'alaihiwasallam yang ketika itu Rasulullah Shallallahu'alaihiwasallam sedang berjalan, lalu dia berkata; Wahai Rasulullah, terkadang waktu shalat datang saat kami di kandang unta, apakah kami boleh shalat di dalamnya? Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak.\" (orang Badui) berkata; apakah kami harus berwudlu karena dagingnya?. Beliau menjawab, ya. (orang Badui) berkata; bolehkah kami shalat di kandang kambing?, lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ya.\" (orang Badui) berkata; apakah kami harus berwudlu dari dagingnya?, maka beliau menjawab, tidak."},"1212":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ قَالَ حَدَّثَنَا أَبُو عُبَيْدَةَ يَعْنِي الْحَدَّادَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ عَنْ يَزِيدَ بْنِ أَبِي مَنْصُورٍ عَنْ ذِي اللِّحْيَةِ الْكِلَابِيِّ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَنَعْمَلُ فِي أَمْرٍ مُسْتَأْنَفٍ أَوْ أَمْرٍ قَدْ فُرِغَ مِنْهُ قَالَ لَا بَلْ فِي أَمْرٍ قَدْ فُرِغَ مِنْهُ قَالَ فَفِيمَ نَعْمَلُ إِذًا قَالَ اعْمَلُوا فَكُلٌّ مُيَسَّرٌ لِمَا خُلِقَ لَهُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Yahya bin Ma'in] berkata; telah menceritakan kepada kami [Abu 'Ubaidah] yaitu Al Haddad, berkata; telah menceritakan kepada kami [Abdul Aziz bin Muslim] dari [Yazid bin Abu Manshur] dari [Dzil Lihyah Al Kilabi] sesungguhnya dia berkata; Wahai Rasulullah, adakah kita beramal untuk urusan yang baru akan ditetapkan ataukah memang telah ditetapkan?. Beliau bersabda: \"Tidak, tapi untuk urusan yang telah ditetapkan\" lalu (Dzil Lihyah Al Kilabi radliyallahu'anhum) berkata; \"Kalau begitu untuk apa kita beramal?\" Beliau bersabda: \"Semuanya akan dimudahkan sesuai dengan apa yang dicipta baginya.\""},"1213":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو عَبْدِ اللَّهِ الْبَصْرِيُّ حَدَّثَنَا سَهْلُ بْنُ أَسْلَمَ الْعَدَوِيُّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي مَنْصُورٍ عَنْ ذِي اللِّحْيَةِ الْكِلَابِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَنَعْمَلُ فِي أَمْرٍ مُسْتَأْنَفٍ أَوْ فِي أَمْرٍ قَدْ فُرِغَ مِنْهُ قَالَ بَلْ فِي أَمْرٍ قَدْ فُرِغَ مِنْهُ قَالَ فَفِيمَ الْعَمَلُ فَقَالَ اعْمَلُوا فَكُلٌّ مُيَسَّرٌ لِمَا خُلِقَ لَهُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Abdullah Al Bashri] telah menceritakan kepada kami [Sahal bin Aslam Al 'Adawi] berkata; telah menceritakan kepada kami [Yazid bin Abu Manshur] dari [Dzil Lihyah Al Kilabi] berkata; saya berkata; Wahai Rasulullah, apakah kami beramal pada urusan yang tengah akan ditetapkan ataukah amalan yang telah ditetapkan?. Beliau bersabda: \"Pada urusan yang telah ditentukan\" lalu (Dzil Lihyah Al Kilabi radliyallahu'anhum) berkata; \"Kalau begitu untuk apa kita beramal?\" Beliau bersabda: \"Beramallah, semuanya akan dimudahkan sesuai dengan apa yang dicipta baginya.\""},"1214":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو صَالِحٍ الْحَكَمُ بْنُ مُوسَى قَالَ حَدَّثَنَا ضَمْرَةُ بْنُ رَبِيعَةَ عَنْ عُثْمَانَ بْنِ عَطَاءٍ عَنْ أَبِي عِمْرَانَ عَنْ ذِي الْأَصَابِعِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنْ ابْتُلِينَا بَعْدَكَ بِالْبَقَاءِ أَيْنَ تَأْمُرُنَا قَالَ عَلَيْكَ بِبَيْتِ الْمَقْدِسِ فَلَعَلَّهُ أَنْ يَنْشَأَ لَكَ ذُرِّيَّةٌ يَغْدُونَ إِلَى ذَلِكَ الْمَسْجِدِ وَيَرُوحُونَ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Shalih Al Hakam bin Musa] berkata; telah menceritakan kepada kami [Dlamrah bin Rabi'ah] dari ['Utsman bin 'Atha`] dari [Abu Imran] dari [Dzil Ashabi'] berkata; saya berkata; Wahai Rasulullah, jika kami diuji dengan panjang umur setelah anda, maka anda menyuruh Kemana?. Beliau bersabda: \"Pergilah ke Baitul Maqdis, semoga akan lahir darimu keturunan yang akan pergi ke masjid itu baik pagi maupun sore harinya\"."},"1215":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا عِيسَى بْنُ يُونُسَ قَالَ أَبِي أَخْبَرَنَا عَنْ أَبِيهِ عَنْ ذِي الْجَوْشَنِ الضِّبَابِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ أَنْ فَرَغَ مِنْ أَهْلِ بَدْرٍ بِابْنِ فَرَسٍ لِي يُقَالُ لَهَا الْقَرْحَاءُ فَقُلْتُ يَا مُحَمَّدُ إِنِّي قَدْ جِئْتُكَ بِابْنِ الْقَرْحَاءِ لِتَتَّخِذَهُ قَالَ لَا حَاجَةَ لِي فِيهِ وَإِنْ أَرَدْتَ أَنْ أَقِيضَكَ فِيهَا الْمُخْتَارَةَ مِنْ دُرُوعِ بَدْرٍ فَعَلْتُ فَقُلْتُ مَا كُنْتُ لِأَقِيضَهُ الْيَوْمَ بِعُدَّةٍ قَالَ لَا حَاجَةَ لِي فِيهِ ثُمَّ قَالَ يَا ذَا الْجَوْشَنِ أَلَا تُسْلِمُ فَتَكُونَ مِنْ أَوَّلِ أَهْلِ هَذَا الْأَمْرِ فَقُلْتُ لَا قَالَ لِمَ قُلْتُ إِنِّي رَأَيْتُ قَوْمَكَ وَلِعُوا بِكَ قَالَ فَكَيْفَ بَلَغَكَ عَنْ مَصَارِعِهِمْ بِبَدْرٍ قُلْتُ قَدْ بَلَغَنِي قَالَ فَإِنَّا نُهْدِي لَكَ قُلْتُ إِنْ تَغْلِبْ عَلَى الْكَعْبَةِ وَتَقْطُنْهَا قَالَ لَعَلَّكَ إِنْ عِشْتَ تَرَى ذَلِكَ ثُمَّ قَالَ يَا بِلَالُ خُذْ حَقِيبَةَ الرَّجُلِ فَزَوِّدْهُ مِنْ الْعَجْوَةِ فَلَمَّا أَدْبَرْتُ قَالَ أَمَا إِنَّهُ مِنْ خَيْرِ فُرْسَانِ بَنِي عَامِرٍ قَالَ فَوَاللَّهِ إِنِّي بِأَهْلِي بِالْغَوْرِ إِذْ أَقْبَلَ رَاكِبٌ فَقُلْتُ مَا فَعَلَ النَّاسُ قَالَ وَاللَّهِ قَدْ غَلَبَ مُحَمَّدٌ عَلَى الْكَعْبَةِ وَقَطَنَهَا فَقُلْتُ هَبِلَتْنِي أُمِّي وَلَوْ أُسْلِمُ يَوْمَئِذٍ ثُمَّ أَسْأَلُهُ الْحِيرَةَ لَأَقْطَعَنِيهَاحَدَّثَنَا شَيْبَانُ بْنُ أَبِي شَيْبَةَ أَبُو مُحَمَّدٍ قَالَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ عَنْ أَبِي إِسْحَاقَ الْهَمْدَانِيِّ قَالَ قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذُو الْجَوْشَنِ وَأَهْدَى لَهُ فَرَسًا وَهُوَ يَوْمَئِذٍ مُشْرِكٌ فَأَبَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقْبَلَهُ ثُمَّ قَالَ إِنْ شِئْتَ بِعْتَنِيهِ أَوْ هَلْ لَكَ أَنْ تَبِيعَنِيهِ بِالْمُتَخَيَّرَةِ مِنْ دُرُوعِ بَدْرٍ ثُمَّ قَالَ لَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ أَنْ تَكُونَ أَوَّلَ مَنْ يَدْخُلُ فِي هَذَا الْأَمْرِ فَقَالَ لَا فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَمْنَعُكَ مِنْ ذَلِكَ قَالَ رَأَيْتُ قَوْمَكَ قَدْ كَذَّبُوكَ وَأَخْرَجُوكَ وَقَاتَلُوكَ فَانْظُرْ مَا تَصْنَعُ فَإِنْ ظَهَرْتَ عَلَيْهِمْ آمَنْتُ بِكَ وَاتَّبَعْتُكَ وَإِنْ ظَهَرُوا عَلَيْكَ لَمْ أَتَّبِعْكَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا ذَا الْجَوْشَنِ لَعَلَّكَ إِنْ بَقِيتَ وَذَكَرَ الْحَدِيثَ نَحْوًا مِنْهُ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ ذِي الْجَوْشَنِ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ أَنْ فَرَغَ مِنْ بَدْرٍ بِابْنِ فَرَسٍ لِي يُقَالُ لَهَا الْقَرْحَاءُ فَقُلْتُ يَا مُحَمَّدُ وَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abu Shalih Al Hakam bin Musa] telah menceritakan kepada kami ['Isa bin Yunus] berkata;  telah mengabarkan kepada kami dari [Bapaknya] dari [Dzil Jausyan Adl-Dlababi], berkata; saya menemui Nabi Shallallahu'alaihiwasallam dengan anak penunggang kudaku yang bernama Al Qarha' setelah beliau selesai membereskan Ahli Badar, lalu saya berkata; Wahai Muhammad sesungguhnya saya datang untuk menemui kamu dengan anak (penunggang kuda) Al Qarha` ini agar anda bersedia mengambilnya. Beliau bersabda: \"Saya tidak berminat dengannya, namun jika kau mau, saya akan menggantikan anak penunggang kudamu dengan baju besi dari Badar yang sangat mahal\". Saya berkata; saya tidak akan menukarkannya hari ini dengan barang lain. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Saya tidak ada keperluan dengan anak itu\" lalu bersabda: \"Wahai Dzal Jausyan!, tidak sebaiknyakah engkau masuk Islam, lalu kamu menjadi menjadi orang yang pertama-tama dalam urusan agama ini?\". Saya berkata; tidak. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Kenapa?\" Saya menjawab, saya melihat kaummu telah tertipu denganmu. Beliau bersabda: \"Bagaimana kabar yang sampai padamu tentang lokasi-lokasi mereka terbunuh di Badar?.\" (Dzil Jausyan) berkata; ya, telah sampai berita itu kepadaku.Beliau bersabda: \"Jika kamu masuk Islam, kami memberimu hadiah\". Saya (Dzil Jausyan) berkata; \"Saya mau masuk Islam asalkan engkau bisa menguasai Makkah dan tinggal disana\". Beliau bersabda: \"Semoga jika kau masih hidup, kamu bisa menyaksikan hal itu\". Lalu beliau bersabda: \"Wahai Bilal, ambilah tas orang ini dan isilah dengan kurma Ajwah\". Tatkala saya hendak berangkat beliau bersabda: \"Sesungguhnya dia termasuk penunggang kuda terbaik di Bani 'Amir\". (Dzil Jausyan) berkata; demi Allah, ketika saya bersama dengan keluarga pada suatu tempat yang rendah, datanglah orang yang berkendaraan. Saya bertanya, apa yang telah dilakukan orang-orang? Dia menjawab, \"Demi Allah, Muhammad telah menguasai kakbah dan tinggal disana.\" Lalu saya (Dzil Jausyan) berkata; 'Uhh, aduhai seandainya saya masuk Islam saat itu dengan harapan nabi memberiku tanah Hirah (nama tempat). Telah menceritakan kepada kami [Syaiban bin Abu Syaibah Abu Muhammad] berkata; telah menceritakan kepada kami [Jarir] yaitu Ibnu Hazm dari [Abu Ishaq Al Hamdani] berkata; [Dzul Jausyan] menemui Nabi Shallallahu'alaihiwasallam dan memberihadiah seekor penunggang kuda. Pada saat itu dia masih dalam keadaan musyrik, lalu Rasulullah Shallallahu'alaihiwasallam menolaknya dengan bersabda: \"Jika kamu mau kamu juallah kepadaku\", atau \"Maukah kau menjualnya untukku dan kuganti dengan baju-baju besi dari Badar?. Kemudian beliau bersabda kepadanya tidak sebaiknyakah engkau menjadi orang pertama-tama memasuki agama ini? Dia menjawab, \"Menurutku, karena kaummu telah mendustakanmu dan mengusirmu serta memerangimu, lihatlah apa ang kau perbuat. Jika kamu bisa mengalahkan mereka saya akan beriman kepadamu dan saya akan mengikutimu. Jika mereka yang mengalahkanmu maka saya tidak akan mengikutimu\". Lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya, \"Wahai Dzal Jausyan, jika kamu masih hidup, \" lalu menyebutkan hadits yang sama dengan yang di atas. Telah menceritakan kepadaku [Abu Bakar bin Abu Syaibah] berkata; telah menceritakan kepada kami ['Isa bin Yunus] dari [Bapaknya] dari [kakeknya] dari [Dzil-Jausyan] berkata; saya menemui Nabi Shallallahu'alaihiwasallam setelah beliau selesai dari Perang Badar dengan membawa anak penunggang kuda milikku yag bernama Al Qarha`, lalu saya berkata; \"Wahai Muhammad, \" lalu dia menyebutkan hadis secara sempurna."},"1216":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مَنْصُورِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ عَنْ أُمِّ عُثْمَانَ ابْنَةِ سُفْيَانَ وَهِيَ أُمُّ بَنِي شَيْبَةَ الْأَكَابِرِ قَالَ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ وَقَدْ بَايَعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا شَيْبَةَ فَفَتَحَ فَلَمَّا دَخَلَ الْبَيْتَ وَرَجَعَ وَفَرَغَ وَرَجَعَ شَيْبَةُ إِذَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَجِبْ فَأَتَاهُ فَقَالَ إِنِّي رَأَيْتُ فِي الْبَيْتِ قَرْنًا فَغَيِّبْهُقَالَ مَنْصُورٌ فَحَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُسَافِعٍ عَنْ أُمِّي عَنْ أُمِّ عُثْمَانَ بِنْتِ سُفْيَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ فِي الْحَدِيثِ فَإِنَّهُ لَا يَنْبَغِي أَنْ يَكُونَ فِي الْبَيْتِ شَيْءٌ يُلْهِي الْمُصَلِّينَ","id":"Telah menceritakan kepada kami ['Ali bin Ishaq] berkata; telah mengabarkan kepada kami [Abdullah] berkata; telah mengabarkan kepada kami [Muhammad bin Abdurrahman] dari [Manshur bin Abdurrahman] dari [Ibunya] dari [Ummu 'Utsman, anak perempuan Sufyan] dia adalah Ummu Bani Syaibah yang paling tua, Muhammad bin Abdurrahman berkata; sesungguhnya dia (Ummu 'Utsman) telah berbaiat kepada Nabi Shallallahu'alaihiwasallam, sesungguhnya Nabi Shallallahu'alaihiwasallam memanggil Syaibah lalu beliau membukakan untuknya, tatkala dia memasuki rumah, lalu pulang dan telah selesai maka Syaibah kembali karena ada utusan Rasulullah Shallallahu'alaihiwasallam yang mengharap untuk menjawabnya, maka dia mendatangi beliau, lalu beliau bersabda: \"Saya melihat di dalam rumah ada suatu tanduk maka hilangkanlah.\" Manshur berkata; lalu telah menceritakan kepadaku [Abdullah bin Musafi'] dari [ibuku] dari [Ummu 'Utsman binti Sufyan] sesungguhnya Nabi Shallallahu'alaihiwasallam bersabda kepadanya dalam hadits, \"Sesungguhnya tidak layak di dalam rumah ada sesuatu yang sia-sia yang mengganggu orang yang shalat.\""},"1217":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ خَالِهِ مُسَافِعٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ أُمِّ مَنْصُورٍ قَالَتْ أَخْبَرَتْنِي امْرَأَةٌ مِنْ بَنِي سُلَيْمٍ وَلَدَتْ عَامَّةَ أَهْلِ دَارِنَاأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عُثْمَانَ بْنِ طَلْحَةَ وَقَالَ مَرَّةً إِنَّهَا سَأَلَتْ عُثْمَانَ بْنَ طَلْحَةَ لِمَ دَعَاكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي كُنْتُ رَأَيْتُ قَرْنَيْ الْكَبْشِ حِينَ دَخَلْتُ الْبَيْتَ فَنَسِيتُ أَنْ آمُرَكَ أَنْ تُخَمِّرَهُمَا فَخَمِّرْهُمَا فَإِنَّهُ لَا يَنْبَغِي أَنْ يَكُونَ فِي الْبَيْتِ شَيْءٌ يَشْغَلُ الْمُصَلِّيَقَالَ سُفْيَانُ لَمْ تَزَلْ قَرْنَا الْكَبْشِ فِي الْبَيْتِ حَتَّى احْتَرَقَ الْبَيْتُ فَاحْتَرَقَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Sufyan] berkata; telah menceritakan kepadaku [Manshur] dari [pamannya, Musafi'] dari [Shafiyyah binti Syaibah, Ummu Manshur] berkata; telah mengabarkan kepadaku [seorang perempuan dari Bani Sulaim] yang telah melahirkan seorang budak wanita pada salah satu kelurga kami, Rasulullah Shallallahu'alaihiwasallam mengutus kalian 'Utsman bin Thalhah, dan pernah berkata; sesungguhnya dia (seorang perempuan dari Bani Sulaim) bertanya kepada 'Utsman bin Thalhah, mengapa Nabi Shallallahu'alaihiwasallam memanggilmu. Dia menjawab, sesungguhnya saya melihat dua tanduk kambing ketika saya memasuki rumah, lalu saya lupa menyuruh kamu menutupinya, sesungguhnya tidak boleh di dalam rumah ada sesuatu yang bisa menyibukkan orang shalat. Sufyan berkata; maka dua tanduk tersebut tetap berada di rumah sampai rumah itu terbakar sehingga tanduk itu ikut terbakar."},"1218":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ صَفِيَّةَ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَى عَرَّافًا فَصَدَّقَهُ بِمَا يَقُولُ لَمْ يُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ يَوْمًا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] berkata; telah menceritakan kepadaku [Nafi'] dari [Shafiyah] dari [sebagian istri Nabi Shallallahu'alaihiwasallam] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa mendatangi dukun lalu membenarkan apa yang dikatakan, tidak diterima shalatnya selama empat puluh hari.\""},"1219":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ ذَكْوَانَ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدٍ عَنْ امْرَأَةٍ مِنْهُمْ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا آكُلُ بِشِمَالِي وَكُنْتُ امْرَأَةً عَسْرَاءَ فَضَرَبَ يَدِي فَسَقَطَتْ اللُّقْمَةُ فَقَالَ لَا تَأْكُلِي بِشِمَالِكِ وَقَدْ جَعَلَ اللَّهُ تَبَارَكَ وَتَعَالَى لَكِ يَمِينًا أَوْ قَالَ قَدْ أَطْلَقَ اللَّهُ عَزَّ وَجَلَّ لَكِ يَمِينَكِقَالَ فَتَحَوَّلَتْ شِمَالِي يَمِينًا فَمَا أَكَلْتُ بِهَا بَعْدُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Isma'il] yaitu Ibnu Ibrahim berkata; telah menceritakan kepada kami [Husain bin Dzakwan] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Abdullah bin Muhammad] dari [salah satu wanita mereka] berkata; Rasulullah Shallallahu'alaihiwasallam mendatangiku sedangkan aku makan dengan tangan kiri. Aku saat itu adalah perempuan yang berumur sekitar sepuluh tahunan, maka beliau memukul tanganku sehingga jatuhlah suapanku. Lalu beliau bersabda: \"Janganlah kamu makan dengan tangan kirimu, sedangkan Allah Tabaraka Wa Ta'ala telah menciptakan tangan kanan untukmu\", atau bersabda: \"Sungguh Allah Azza wa jalla telah menetapkan tangan kananmu\", Maka dia berkata; lalu aku mengubahnya dengan tangan kanan, dan aku selalu makan dengan tangan kanan tersebut setelahnya."},"1220":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِسْمَاعِيلَ بْنِ أُمَيَّةَ عَنْ مَوْلًى لَهُمْ يُقَالُ لَهُ مُزَاحِمُ بْنُ أَبِي مُزَاحِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ خَالِدِ بْنِ أَسِيدٍ عَنْ رَجُلٍ مِنْهُمْ مِنْ خُزَاعَةَ يُقَالُ لَهُ مُخَرِّشٌ أَوْ مُحَرِّشٌ لَمْ يَكُنْ سُفْيَانُ يُقِيمُ عَلَى اسْمِهِ وَرُبَّمَا قَالَ مُحَرِّسٌ وَلَمْ أَسْمَعْهُ أَنَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْجِعِرَّانَةِ لَيْلَةً فَاعْتَمَرَ ثُمَّ رَجَعَ وَأَصْبَحَ بِهَا كَبَائِتٍ فَنَظَرْتُ إِلَى ظَهْرِهِ كَأَنَّهُ سَبِيكَةُ فِضَّةٍ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Isma'il bin Umayyah] dari [budak mereka yang bernama Muzahim bin Abu Muzahim] dari [Abdul Aziz bin Abdullah bin Khalid bin Asid] dari [seorang laki-laki Bani Khuza'ah yang bernama Mukharrasy (si bisu) atau Muharrisy], Sufyan belum memberikan nama yang jelas, tetapi sepertinya dia adalah si muharris (si bisu) dan aku belum pernah mendengarnya, sesungguhnya Nabi Shallallahu'alaihiwasallam keluar dari Ji'ranah pada malam hari untuk berumrah kemudian pulang, dan pada waktu paginya seakan-akan bermalam, maka aku melihat punggungnya seakan-akan perak yang dilebur lalu dituang dalam cetakan."},"1221":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ رَجُلٍ مِنْ ثَقِيفٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ فَنَضَحَ فَرْجَهُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [seorang laki-laki Bani Tsaqif] dari bapaknya sesungguhnya Nabi Shallallahu'alaihiwasallam kencing lalu memercikkan air pada kemaluannya."},"1222":{"ar":"قَالَ حَدَّثَنَا حَفْصُ بنُ غِيَاثٍ قَالَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنِ الشَّعْبِيِّ عَنْ أَبِي جَبِيرَةَ بْنِ الضَّحَّاكِ الْأَنْصَارِيِّ عَنْ عُمُومَةٍ لَهُقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ أَحَدٌ مِنَّا إِلَّا لَهُ لَقَبٌ أَوْ لَقَبَانِ قَالَ فَكَانَ إِذَا دَعَا بِلَقَبِهِ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّ هَذَا يَكْرَهُ هَذَا قَالَ فَنَزَلَتْ{ وَلَا تَنَابَزُوا بِالْأَلْقَابِ }","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats] berkata; telah menceritakan kepada kami [Daud bin Abu Hind] dari [Asy Sya'bi] dari [Abu Jabirah bin Adl-Dlahak Al Anshari, Saudara jalur paman Al Anshary] dari [paman] Nabi Shallallahu'alaihiwasallam datang dan tidaklah seorangpun dari kami kecuali mempunyai satu atau dua nama panggilan. (Abu Jabirah bin Adl-Dlahak Al Anshari Radliyallahu'anhu) berkata; (Rasulullah Shallallahu'alaihiwasallam) apabila memanggil dengan laqabnya, kami berkata; \"Sesungguhnya nama panggilan ini dibenci\", lalu turunlah ayat, 'Janganlah kalian memperolok-olok dengan nama pangilan\""},"1223":{"ar":"قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي سُلَيْمَانَ شَيْخٌ صَالِحٌ حَسَنُ الْهَيْئَةِ مَدِينِيٌّ قَالَ حَدَّثَنَا مُعَاذُ بْنُ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ عَنْ أَبِيهِ عَنْ عَمِّهِ قَالَكُنَّا فِي مَجْلِسٍ فَطَلَعَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami [Abdullah bin Abu Sulaiman], seorang yang sudah tua dan sangat shalih, dan fisiknya baik, seseorang dari Madinah, berkata; telah menceritakan kepada kami [Mu'adz bin Abdullah bin khubaib] dari [Bapaknya] dari [pamannya] berkata; kami sedang berada pada suatu majlis, lalu Rasulullah Shallallahu'alaihiwasallam muncul kepada kami. Lalu, menyebutkannya."},"1224":{"ar":"قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا عَبَّادٌ يَعْنِي ابْنَ رَاشِدٍ عَنِ الْحَسَنِ عَنْ رَجُلٍ مِنْ بَنِي سَلِيطٍ أَنَّهُمَرَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَاعِدٌ عَلَى بَابِ مَسْجِدِهِ مُحْتَبٍ وَعَلَيْهِ ثَوْبٌ لَهُ قِطْرٌ لَيْسَ عَلَيْهِ ثَوْبٌ غَيْرَهُ وَهُوَ يَقُولُ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يَخْذُلُهُ ثُمَّ أَشَارَ بِيَدِهِ إِلَى صَدْرِهِ يَقُولُ التَّقْوَى هَاهُنَا التَّقْوَى هَاهُنَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami ['Abbad] yaitu Ibnu Rasyid dari [Al Hasan] dari seorang laki-laki dari Bani Salith sesungguhnya dia melewati Rasulullah Shallallahu'alaihiwasallam waktu itu beliau sedang duduk di depan masjidnya dalam keadaan duduk ihtiba' (posisi duduk dengan meletakkan kedua pahanya pada dadanya) dengan di atasnya ada pakaian yang ada jahitannya berwarna merah, tidak ada pakaian setelahnya, beliau bersabda: \"Seorang muslim adalah sauadara muslim yang lainnya, tidak boleh menganiayanya maupun merendahkannya\", lalu beliau menunjukkan dengan tangannya ke arah dadanya dan bersabda: \"Takwa itu letaknya di sini.\""},"1225":{"ar":"قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زَائِدَةُ قَالَ حَدَّثَنَا الرُّكَيْنُ بْنُ الرَّبِيعِ بْنِ عُمَيْلَةَ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ رَجُلٍ مِنْ الْأَنْصَارِعَنْ النَّبِيِّ قَالَ الْخَيْلُ ثَلَاثَةٌ فَرَسٌ يَرْبِطُهُ الرَّجُلُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَثَمَنُهُ أَجْرٌ وَرُكُوبُهُ أَجْرٌ وَعَارِيَتُهُ أَجْرٌ وَعَلَفُهُ أَجْرٌ وَفَرَسٌ يُغَالِقُ عَلَيْهِ الرَّجُلُ وَيُرَاهِنُ فَثَمَنُهُ وِزْرٌ وَعَلَفُهُ وِزْرٌ وَفَرَسٌ لِلْبِطْنَةِ فَعَسَى أَنْ يَكُونَ سَدَادًا مِنْ الْفَقْرِ إِنْ شَاءَ اللَّهُ تَعَالَى","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Mu'awiyah bin 'Amr] berkata; telah menceritakan kepada kami [Za`idah] berkata; telah menceritakan kepada kami [Ar Rukain bin Ar Rabi' bin 'Umailah] dari [Abu 'Amr Asy Syaibani] dari [seseorang dari Anshar] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Kuda itu ada tiga: Kuda yang diikat oleh seseorang di jalan Allah Azza wa jalla maka biaya untuk membelinya adalah pahala, menaikinya adalah pahala, orang yang meminjaminya ada pahala dan memberi makannya adalah pahala. Kuda yang di jadikan jaminan seseorang yang menggadaikan, maka harganya menjadi dosa dan memberi makannya juga dosa. Kuda untuk mencari nafkah, bisa jadi sebagai sesuatu untuk memenuhi kebutuhan dari kefakiran jika Allah Ta'ala menghendaki.\""},"1226":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ حُصَيْنِ بْنِ عُرْوَةَ قَالَ حَدَّثَتْنِي جَدَّتِي قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَلَوْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ يَقُودُكُمْ بِكِتَابِ اللَّهِ عَزَّ وَجَلَّ فَاسْمَعُوا لَهُ وَأَطِيعُوا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] berkata; telah menceritakan kepada kami [Yahya bin Husain bin 'Urwah] berkata; telah menceritakan kepadaku [nenekku] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika ada yang diangkat menjadi pimpinan pada kalian seorang budak, yang memimpin dengan kitab Allah Azza wa jalla maka dengarkanlah dan taatilah.\""},"1227":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ حُصَيْنٍ عَنْ جَدَّتِهِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَرْحَمُ اللَّهُ الْمُحَلِّقِينَ يَرْحَمُ اللَّهُ الْمُحَلِّقِينَ قَالُوا فِي الثَّالِثَةِ وَالْمُقَصِّرِينَ قَالَ وَالْمُقَصِّرِينَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Hushain] dari [neneknya] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Allah akan memberi rahmat orang yang telah mencukur habis rambutnya, Allah akan memberi rahmat orang yang telah mencukur habis rambutnya\" mereka berkata pada yang ketiga kalinya, \"Dan orang yang memendekkannya\" Beliau bersabda: \"Dan orang yang memendekkan rambutnya.\""},"1228":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورِ بْنِ حَيَّانَ الْأَسَدِيِّ عَنِ ابْنِ نَجَّادٍ عَنْ جَدَّتِهِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوا السَّائِلَ وَلَوْ بِظِلْفٍ مُحْتَرِقٍ أَوْ مُحْرَقٍ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur bin Hayyan Al Asadi] dari [Ibnu Najjad] dari [neneknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berilah orang yang meminta walaupun hanya dengan tulang kaki yang dibakar.\""},"1229":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ يَحْيَى بْنِ حُصَيْنٍ عَنْ أُمِّهِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فِي حَجَّةِ الْوَدَاعِ يَقُولُ يَا أَيُّهَا النَّاسُ اتَّقُوا اللَّهَ وَاسْمَعُوا وَأَطِيعُوا وَإِنْ أُمِّرَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ مُجَدَّعٌ مَا أَقَامَ فِيكُمْ كِتَابَ اللَّهِ عَزَّ وَجَلَّ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Yahya bin Hushain] dari [ibunya] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam berkhutbah pada Haji Wada', \"Wahai manusia, bertakwalah kepada Allah, dengarkanlah dan taatilah, walau yang memimpin kalian adalah seorang budak Ethopia yang botak, selama dia menegakkan kitab Allah Azza wa jalla\"."},"1230":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ جَدَّتِهِ عَنِ امْرَأَةٍ مِنْ نِسَائِهِمْ قَالَ وَقَدْ كَانَتْ صَلَّتْ الْقِبْلَتَيْنِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي اخْتَضِبِي تَتْرُكُ إِحْدَاكُنَّ الْخِضَابَ حَتَّى تَكُونَ يَدُهَا كَيَدِ الرَّجُلِقَالَتْ فَمَا تَرَكَتْ الْخِضَابَ حَتَّى لَقِيَتْ اللَّهَ عَزَّ وَجَلَّ وَإِنْ كَانَتْ لَتَخْتَضِبُ وَإِنَّهَا لَابْنَةُ ثَمَانِينَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Dlamrah bin Sa'id] dari [neneknya] dari [seorang wanita dari kalangan mereka] dia telah mengalami shalat dua arah kiblat bersama Rasulullah Shallallahu'alaihiwasallam, berkata; Rasulullah Shallallahu'alaihiwasallam menemuiku, lalu bersabda kepadaku, \"Warnailah kukumu, kenapa salah seorang dari kalian meninggalkan pacar sampai tangannya seperti tangan kaum laki-laki\". (seorang wanita dari kalangan kaumnya Dlamrah Radliyallahu'anha) berkata; lalu (wanita) tidak meninggalkan pewarna kuku sampai mereka bertemu Allah Azza wa jalla, ia tetap mewarnainya walau sudah berumur delapan puluh tahun."},"1231":{"ar":"قَالَ حَدَّثَنَا الْهَيْثَمُ بْنُ خَارِجَةَ قَالَ عَبْد اللَّهِ وَقَدْ سَمِعْتُهُ أَنَا مِنْ الْهَيْثَمِ قَالَ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ عَنِ ابْنِ حَرْمَلَةَ عَنْ أَبِي ثِفَالٍ الْمُرِّيِّ أَنَّهُ قَالَ سَمِعْتُ رَبَاحَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ حُوَيْطِبٍ يَقُولُ حَدَّثَتْنِي جَدَّتِي أَنَّها سَمِعَتْ أَبَاهَا يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا صَلَاةَ لِمَنْ لَا وُضُوءَ لَهُ وَلَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اللَّهَ تَعَالَى وَلَا يُؤْمِنُ بِاللَّهِ مَنْ لَمْ يُؤْمِنْ بِي وَلَا يُؤْمِنُ بِي مَنْ لَا يُحِبُّ الْأَنْصَارَقَالَ حَدَّثَنَا شَيْبَانُ قَالَ حَدَّثَنَا يَزِيدُ بْنُ عِيَاضٍ عَنْ أَبِي ثِفَالٍ بِهَذَا الْحَدِيثِ وَقَالَ سَمِعَتْ أَبَاهَا سَعِيدَ بْنَ زَيْدٍ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami Haitsam bin Kharijah Abdullah berkata; dan saya telah mendengarnya dari [Al Haitsam], berkata; telah menceritakan kepada kami [Hafs bin Maisarah] dari [Ibnu Harmalah] dari [Abu Tsifal Al Muri] sesungguhnya dia berkata; saya telah mendengar [Rabah bin Abdurrahman bin Huwaithib] berkata; telah menceritakan kepadaku [nenekku] sesungguhnya telah mendengar [bapaknya] berkata; saya telah mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak sah shalat bagi orang yang tidak berwudlu, dan tidak ada wudlu bagi orang yang tidak menyebut Allah Ta'ala. Tidak dikatakan beriman kepada Allah orang yang tidak beriman kepadaku dan tidak dikatakan beriman kepadaku jika dia tidak mencintai Anshar.\" (Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Syaiban] berkata; telah menceritakan kepada kami [Yazid bin Iyadl] dari [Abu Tsifal] dengan hadits ini dan berkata; saya telah mendengar bapaknya sesungguhnya berkata; [Sa'id bin Zaid]."},"1232":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا سَيَّارٌ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ الْقَسْرِيِّ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِجَدِّهِ يَزِيدَ بْنِ أَسَدٍ أَحِبَّ لِلنَّاسِ مَا تُحِبُّ لِنَفْسِكَ","id":"Abdullah berkata; telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Hutsaim] berkata; telah mengabarkan kepada kami [Sayyar] dari [Khalid bin Abdullah Al Qasri] dari [Bapaknya] sesungguhnya Nabi Shallallahu'alaihiwasallam bersabda kepada kakeknya, Yazid bin Asad, \"Cintalah kepada manusia sebagaimana kamu mencintai untuk dirimu.\""},"1233":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ قَالَ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ عَنْ يُونُسَ بْنِ أَبِي إِسْحَاقَ عَنْ إِسْمَاعِيلَ بْنِ أَوْسَطَ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ جَدِّهِ أَسَدِ بْنِ كُرْزٍسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمَرِيضُ تَحَاتُّ خَطَايَاهُ كَمَا يَتَحَاتُّ وَرَقُ الشَّجَرِ","id":"Abdullah berkata; telah menceritakan kepada kami ['Uqbah bin Mukram Al 'Ami] berkata; telah menceritakan kepada kami [Salm bin Qutaibah] dari [Yunus bin Abu Ishaq] dari [Isma'il bin Ausath] dari [Khalid bin Abdullah] dari [kakeknya, Asad bin Kurz] telah mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Orang yang sakit itu kesalahannya akan berjatuhan sebagaimana berjatuhannya daun dari pohon.\""},"1234":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرُّزِّيُّ أَبُو جَعْفَرٍ قَالَ حَدَّثَنَا رَوْحُ بْنُ عَطَاءٍ بْنِ أَبِي مَيْمُونَةَ قَالَ حَدَّثَنَا سَيَّارٌ أَنَّهُ سَمِعَ خَالِدَ بْنَ عَبْدِ اللَّهِ الْقَسْرِيَّ وَهُوَ يَخْطُبُ عَلَى الْمِنْبَرِ وَهُوَ يَقُولُ حَدَّثَنِي أَبِي عَنْ جَدِّي أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُحِبُّ الْجَنَّةَ قَالَ قُلْتُ نَعَمْ قَالَ فَأَحِبَّ لِأَخِيكَ مَا تُحِبُّ لِنَفْسِكَ","id":"Abdullah berkata; telah menceritakan kepadaku [Muhammad bin Abdullah Ar Ruzi, Abu Ja'far] berkata; telah menceritakan kepada kami [Rauh bin 'Atha` bin Abu Maimunah] berkata; telah menceritakan kepada kami [Sayyar] sesungguhnya telah mendengar [Khalid bin Abdullah Al Qasri] dia berkhutbah di atas mimbar, dia berkata; telah menceritakan kepadaku [bapakku] dari [kakekku] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apakah kalian menyukai surga\". Dia menjawab, ya. Beliau bersabda: \"Cintailah pada saudaramu sebagai kamu mencintai untuk diri kamu.\""},"1235":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنِي أَبُو الْحَسَنِ عُثْمَانُ بْنُ أَبِي شَيْبَةَ بِالْكُوفَةِ سَنَةَ ثَلَاثِينَ وَمِائَتَيْنِ وَيَعْقُوبُ الدَّوْرَقِيُّ قَالَا حَدَّثَنَا هُشَيْمُ بْنُ بَشِيرٍ قَالَ عُثْمَانُ بْنُ أَبِي شَيْبَةَ أَخْبَرَنَا سَيَّارٌ قَالَ سَمِعْتُ خَالِدَ بْنَ عَبْدِ اللَّهِ الْقَسْرِيَّ عَلَى الْمِنْبَرِ يَقُولُ حَدَّثَنِي أَبِي عَنْ جَدِّي يَزِيدَ بْنِ أَسَدٍقَالَ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا يَزِيدُ بْنَ أَسَدٍ أَحِبَّ لِلنَّاسِ مَا تُحِبُّ لِنَفْسِكَ","id":"Abdullah berkata; telah menceritakan kepadaku [Abu Al Hasan, 'Utsman bin Abu Syaibah] di Kufah pada tahun dua ratus tiga puluh dan [Ya'qub Ad-Dauraqi] berkata; telah menceritakan kepada kami [Husyaim bin Basyir] berkata; ['Utsman bin Abu Syaibah] berkata; telah mengabarkan kepada kami [Sayyar] berkata; saya telah mendengar [Khalid bin Abdullah Al Qari] di atas mimbar berkata; telah menceritakan kepadaku [bapakku] dari [kakekku, Yazid bin Asad] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku, \"Wahai Yazid bin Asad, Cintailah manusia sebagaimana kamu mencintai diri kamu sendiri.\""},"1236":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ وَهُوَ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ ثَابِتٍ الْعَبْدِيُّ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَأَنَّهُ أَهْدَى لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَحْمَ صَيْدٍ فَلَمْ يَقْبَلْهُ فَرَأَى ذَلِكَ فِي وَجْهِ الصَّعْبِ فَقَالَ إِنَّهُ لَمْ يَمْنَعْنَا أَنْ نَقْبَلَ مِنْكَ إِلَّا أَنَّا كُنَّا حُرُمًا","id":"Abdullah berkata; telah menceritakan kepada kami [Muhammad bin Abu Abu Bakar] yaitu Al Muqadami, berkata; telah menceritakan kepada kami [Muhammad bin Tsabit Al 'Abdi] berkata; telah menceritakan kepada kami ['Amr bin Dinar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu 'Abbas] dari [Ash-Sha'b bin Jatsamah] sesungguhnya dia memberi hadiah kepada Rasulullah Shallallahu'alaihiwasallam daging buruan namun beliau tidak menerimanya, lalu (Rasulullah Shallallahu'alaihiwasallam) melihat pancaran ketidaksukaan pada wajah Ash-Shab, lalu bersabda: \"Sebenarnya tidak ada yang menghalangi kami untuk menerima darimu, hanya karena kami dalam keadaan ihram.\""},"1237":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي أَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ قَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِالْأَبْوَاءِ أَوْ بِوَدَّانَ فَأَهْدَيْتُ لَهُ لَحْمَ حِمَارِ وَحْشٍ وَهُوَ مُحْرِمٌ فَرَدَّهُ عَلَيَّ فَلَمَّا رَأَى فِي وَجْهِي الْكَرَاهِيَةَ قَالَ لَيْسَ بِنَا رَدٌّ عَلَيْكَ وَلَكِنَّا حُرُمٌ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Abu Khaitsamah, Zuhair bin Harb] berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Ash-Sha'b bin Jatsamah] berkata; Rasulullah Shallallahu'alaihiwasallam melewatiku, waktu itu saya sedang berada di Abwa` atau Waddan, lalu saya memberi hadiah berupa daging keledai liar dan beliau dalam keadaan ihram namun beliau menolaknya. Tatkala beliau melihat ketidaksukaan pada wajahku, beliau bersabda: \"Kami tidak menolaknya hanya karena kami sedang dalam keadaan ihram.\""},"1238":{"ar":"قَالَوَسَمِعْتُهُ يَقُولُ لَا حِمَى إِلَّا لِلَّهِ وَلِرَسُولِهِ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, dari [Sha'bi bin Jatstsamah]; (Ash-Shab bin Jatsamah Radliyallahu'anhu) berkata; dan saya telah mendengarnya beliau bersabda: \"Tidak ada hima (batasan yang tidak boleh dilanggar seorang muslim) kecuali batasan yang ditetapkan oleh Allah dan Rasul-Nya."},"1239":{"ar":"قَالَوَسُئِلَ عَنْ أَهْلِ الدَّارِ مِنْ الْمُشْرِكِينَ يُبَيَّتُونَ فَيُصَابُ مِنْ نِسَائِهِمْ وَذَرَارِيِّهِمْ قَالَ هُمْ مِنْهُمْ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, dari [Sha'bi bin Jatstsamah]; (Ash-Shab bin Jatsamah Radliyallahu'anhu) berkata; beliau ditanya tentang orang yang sedang berada di perkampungan orang musyrik yang diserang pada malam harinya, lalu para wanita mereka ditawan, juga anak-anak mereka. Beliau mengatakan, \"Mereka adalah bagian dari diri mereka.\""},"1240":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنِي مُصْعَبٌ هُوَ الزُّبَيْرِيُّ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ عَبْدِ اللَّهِ بْنِ عَيَّاشٍ الْمَخْزُومِيُّ عَنِ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ اللَّيْثِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمَى النَّقِيعَ وَقَالَ لَا حِمَى إِلَّا لِلَّهِ وَلِرَسُولِهِ","id":"Abdullah berkata; telah menceritakan kepadaku [Mush'ab, Az Zubairi] berkata; telah menceritakan kepadaku [Abdul Aziz bin Muhammad] dari [Abdurrahman bin Al Harits bin Abdullah bin 'Ayyasy Al Makhzumi] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] dari [Abdullah bin 'Abbas] dari [Ash-Shab bin Jatsamah Al Laitsi] sesungguhnya Rasulullah Shallallahu'alaihiwasallam menjaga sumur yang banyak airnya dan bersabda: \"Tidak ada hima (batasan yang seharusnya tidak dilanggar oleh seorang muslim) kecuali batasan yang ditetapkan Allah dan Rasul-Nya\"."},"1241":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا مُصْعَبُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنِ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ اللَّيْثِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَهْدَى لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِمَارًا وَحْشِيًّا وَهُوَ بِالْأَبْوَاءِ أَوْ بِوَدَّانَ فَرَدَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فِي وَجْهِي فَقَالَ إِنَّا لَمْ نَرُدَّهُ عَلَيْكَ إِلَّا أَنَّا حُرُمٌ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami [Mus'ab bin Abdullah] berkata; telah menceritakan kepadaku [Malik bin Anas] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah bin Masud] dari [Abdullah bin Abbas] dari [Ash-Shab bin Jatsamah Al Laitsi] dari Nabi Shallallahu'alaihiwasallam, sesungguhnya dia pernah memberi hadiah kepada Rasulullah Shallallahu'alaihiwasallam keledai liar. Dia sedang berada di Abwa` atau Waddan, lalu Rasulullah Shallallahu'alaihiwasallam menolaknya. Tatkala Rasulullah Shallallahu'alaihiwasallam melihat ketidaksukaan pada wajahku, beliau bersabda: \"Kami tidak menolaknya, hanya karena kami sedang dalam keadaan ihram.\""},"1242":{"ar":"قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ سَمِعْتُ صَالِحَ بْنَ كَيْسَانَ يُحَدِّثُ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ بِوَدَّانَ إِذْ أَتَاهُ الصَّعْبُ بْنُ جَثَّامَةَ أَوْ رَجُلٌ بِبَعْضِ حِمَارِ وَحْشٍ فَرَدَّهُ عَلَيْهِ فَقَالَ إِنَّا حُرُمٌ لَا نَأْكُلُ الصَّيْدَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepadaku ['Ubaidullah bin 'Umar Al Qawariri] berkata; telah menceritakan kepada kami [Hammad bin Zaid] berkata; saya telah mendengar [Shalih bin Kaisan] menceritakan dari ['Ubaidullah bin Abdullah] dari [Abdullah bin Abbas] dari [Ash-Sha'b bin Jatsamah] sesungguhnya Rasulullah Shallallahu'alaihiwasallam tatkala sedang berada di Waddan, Ash-Shab bin Jatsamah menemuinya atau beberapa orang dengan membawa keledai liar, lalu (Rasulullah Shallallahu'alaihiwasallam) menolaknya. Lalu bersabda: \"Kami sedang berihram, kami tidak boleh makan hewan buruan.\""},"1243":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا حِمَى إِلَّا لِلَّهِ وَرَسُولِهِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami [Muhammad bin Abu Bakar] berkata; telah menceritakan kepada kami [Hammad bin Zaid] berkata; telah menceritakan kepada kami ['Amr bin Dinar] dari [Ibnu Abbas] dari [Ash-Sha'b bin Jatsamah] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \" Tidak ada hima (larangan yang harus dijauhi oleh seorang muslim) kecuali hima yang ditetapkan oleh Allah dan Rasul-Nya\"."},"1244":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ قَالَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَ قَالَأُوتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَدَّانَ بِحِمَارِ وَحْشٍ فَرَدَّهُ وَقَالَ إِنَّا حُرُمٌ لَا نَأْكُلُ الصَّيْدَ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Muhammad bin Abu Bakar] berkata; telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami ['Amr bin Dinar] dari [Ibnu Abbas] dari [Ash-Sha'b bin Jatsamah] berkata; Rasulullah Shallallahu'alaihiwasallam diberi keledai liar pada saat di Waddan, lalu beliau menolaknya dan bersabda: \"Kami sedang berihram, kami tidak boleh makan hewan buruan.\""},"1245":{"ar":"حَدَّثَنَا عَامِرُ بْنُ صَالِحٍ الزُّبَيْرِيُّ سَنَةَ ثَمَانِينَ وَمِائَةٍ قَالَ حَدَّثَنِي يُونُسُ بْنُ يَزِيدَ عَنِ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنِ ابْنِ عَبَّاسٍ عَنِ الصَّعْبِ بْنِ جَثَّامَةَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا حِمَى إِلَّا لِلَّهِ وَلِرَسُولِهِ","id":"Telah menceritakan kepada kami ['Amir bin Shalih Az Zubairi] tahun seratus delapan puluh, berkata; telah menceritakan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] dari [Ash-Sha'b bin Jatsamah] saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Tidak ada hima (larangan yang harus dijauhi oleh seorang muslim) kecuali hima yang ditetapkan oleh Allah dan Rasul-Nya.\""},"1246":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا أَبُو أَحْمَدَ الْهَيْثَمُ بْنُ خَارِجَةَ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي فَرْوَةَ عَنْ يُوسُفَ بْنِ سُلَيْمَانَ عَنْ جَدَّتِهِ مَيْمُونَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَنَّةَ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَدَأَ الْإِسْلَامُ غَرِيبًا ثُمَّ يَعُودُ غَرِيبًا كَمَا بَدَأَ فَطُوبَى لِلْغُرَبَاءِ قِيلَ يَا رَسُولَ اللَّهِ وَمَنْ الْغُرَبَاءُ قَالَ الَّذِينَ يُصْلِحُونَ إِذَا فَسَدَ النَّاسُ وَالَّذِي نَفْسِي بِيَدِهِ لَيُحَازَنَّ الْإِيمَانُ إِلَى الْمَدِينَةِ كَمَا يَحُوزُ السَّيْلُ وَالَّذِي نَفْسِي بِيَدِهِ لَيَأْرِزَنَّ الْإِسْلَامُ إِلَى مَا بَيْنَ الْمَسْجِدَيْنِ كَمَا تَأْرِزُ الْحَيَّةُ إِلَى جُحْرِهَا","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami [Abu Ahmad Al Haistami bin Kharijah] berkata; telah menceritakan kepada kami [Isma'il bin Ayyas] dari [Ishaq bin Abdullah bin Abu farwah] dari [Yusuf bin Sulaiman] dari [neneknya Maimunah] dari [Abdurrahman bin Sannah] sesungguhnya telah mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Islam datang dalam keadaan asing lalu akan kembali asing sebagaimana bermula, maka beruntunglah orang yang asing\". Ada yang bertanya, \"Wahai Rasulullah, siapakah orang yang asing itu?\" Beliau menjawab, \"Orang-orang yang berbuat baik jika manusia telah rusak. Demi jiwaku yang berada di tangan-Nya, sungguh iman itu akan masuk ke Madinah sebagaimana masuknya cairan. Demi Dzat yang jiwaku berada di tangan-Nya, sungguh Islam akan bersatu ke tempat antara dua masjid ini sebagaimana kembalinya ular ke lubangnya.\""},"1247":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُصْعَبُ بْنُ عَبْدِ اللَّهِ هُوَ الزُّبَيْرِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ فَائِدٍ مَوْلَى عَبَادِلَ قَالَ خَرَجْتُ مَعَ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ فَأَرْسَلَ إِبْرَاهِيمُ بْنُ عَبْدِ الرَّحْمَنِ إِلَى ابْنِ سَعْدٍ حَتَّى إِذَا كُنَّا بِالْعَرْجِ أَتَى ابْنُ سَعْدٍ وَسَعْدٌ هُوَ الَّذِي دَلَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى طَرِيقِ رَكُوبِهِ فَقَالَ إِبْرَاهِيمُ أَخْبِرْنِي مَا حَدَّثَكَ أَبُوكَ قَالَ ابْنُ سَعْدٍ حَدَّثَنِي أَبِيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهُمْ وَمَعَهُ أَبُو بَكْرٍ وَكَانَتْ لِأَبِي بَكْرٍ عِنْدَنَا بِنْتٌ مُسْتَرْضَعَةٌ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَادَ الِاخْتِصَارَ فِي الطَّرِيقِ إِلَى الْمَدِينَةِ فَقَالَ لَهُ سَعْدٌ هَذَا الْغَائِرُ مِنْ رَكُوبَةٍ وَبِهِ لِصَّانِ مِنْ أَسْلَمَ يُقَالُ لَهُمَا الْمُهَانَانِ فَإِنْ شِئْتَ أَخَذْنَا عَلَيْهِمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْ بِنَا عَلَيْهِمَا قَالَ سَعْدٌ فَخَرَجْنَا حَتَّى أَشْرَفْنَا إِذَا أَحَدُهُمَا يَقُولُ لِصَاحِبِهِ هَذَا الْيَمَانِي فَدَعَاهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَرَضَ عَلَيْهِمَا الْإِسْلَامَ فَأَسْلَمَا ثُمَّ سَأَلَهُمَا عَنْ أَسْمَائِهِمَا فَقَالَا نَحْنُ الْمُهَانَانِ فَقَالَ بَلْ أَنْتُمَا الْمُكْرَمَانِ وَأَمَرَهُمَا أَنْ يَقْدَمَا عَلَيْهِ الْمَدِينَةَ فَخَرَجْنَا حَتَّى أَتَيْنَا ظَاهِرَ قُبَاءَ فَتَلَقَّى بَنُو عَمْرِو بْنِ عَوْفٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ أَبُو أُمَامَةَ أَسْعَدُ بْنُ زُرَارَةَ فَقَالَ سَعْدُ بْنُ خَيْثَمَةَ إِنَّهُ أَصَابَ قَبْلِي يَا رَسُولَ اللَّهِ أَفَلَا أُخْبِرُهُ لَكَ ثُمَّ مَضَى حَتَّى إِذَا طَلَعَ عَلَى النَّخْلِ فَإِذَا الشَّرْبُ مَمْلُوءٌ فَالْتَفَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ يَا أَبَا بَكْرٍ هَذَا الْمَنْزِلُ رَأَيْتُنِي أَنْزِلُ عَلَى حِيَاضٍ كَحِيَاضِ بَنِي مُدْلِجٍ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Mus'ab bin Abdullah Az Zubairi] berkata; telah menceritakan kepadaku [bapakku] dari [Fa`id], budak Abadil, berkata; saya telah keluar bersama Ibrahim bin Abdurrahman bin Abdullah bin Abu Rabi'ah lalu Ibrahim bin Abdurrahman mengutus pada Ibnu Sa'd sampai kami di Al Araj, Ibnu Sa'd datang dan Sa'd yang menunjukkan pada Rasulullah Shallallahu'alaihiwasallam jalan kendaraannya. Ibrahim berkata; \"Kabarkanlah kepadaku apa yang telah bapakmu ceritakan\". [Ibnu Sa'd] berkata; telah menceritakan kepadaku [bapakku] sesungguhnya Rasulullah Shallallahu'alaihiwasallam mendatangi mereka bersama dengan Abu Bakar. Abu Bakar memiliki seorang anak perempuan sesusuan pada kami, dan Rasulullah Shallallahu'alaihiwasallam hendak meringkas perjalanannya ke Madinah. Lalu Sa'd berkata kepadanya, tanah yang rendah ini termasuk dari jalan yang biasa dilalui, di dalamnya ada dua pencuri dari Aslam yang bernama Al Muhanani (orang yang diremehkan) jika anda mau, maka kami akan menangkapnya. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tangkaplah keduanya.\" Sa'd berkata; \"Kami keluar sampai mendekatinya, ternyata salah seorang darinya berkata kepada temannya ini adalah orang Yaman, lalu Rasulullah Shallallahu'alaihiwasallam memanggil keduanya. Lantas keduanya ditawari Islam, mereka menerimanya. Lalu beliau menanyakan kepada keduanya tentang nama mereka. Mereka berdua berkata; \"Kami adalah Al Muhanani (orang yang sangat di remehkan) \" lalu beliau bersabda: \"Bahkan kalian adalah orang yang sangat dimuliakan\", lalu keduanya diperintahkan untuk datang ke Madinah. Lalu kami keluar sampai kami di Quba`, kami bertemu dengan Bani 'Amr bin 'Auf. Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Dimana Abu Umamah As'ad bin Zurarah?\" Lalu Sa'd bin Khaitsamah berkata; \"Sesungguhnya dia telah terkena musibah sebelumku Wahai Rasulullah, bukankah saya telah mengabari anda lalu telah berlalu\". Sampai dia muncul pada pohon kurma, ternyata tempat minumnya penuh, lalu Nabi Shallallahu'alaihiwasallam menoleh kepada Abu Bakar Radliyallahu'anhu, lalu bersabda: \"Wahai Abu Bakar, rumah ini, saya telah melihatnya dalam mimpiku, saya turun pada sebuah kolam seperti kolam Bani Mudlij.\""},"1248":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي سُرَيْجُ بْنُ يُونُسَ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ يَحْيَى بْنِ كَثِيرٍ الْكَاهِلِيِّ عَنْ مِسْوَرِ بْنِ يَزِيدَ الْأَسَدِيِّ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَرَكَ آيَةً فَقَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ تَرَكْتَ آيَةَ كَذَا وَكَذَا قَالَ فَهَلَّا ذَكَّرْتَنِيهَا","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Suraij bin Yunus] berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Yahya bin Katsir Al Kahili] dari [Miswar bin Yazid Al Asadi] berkata; Rasulullah Shallallahu'alaihiwasallam shalat dan meninggalkan satu ayat. Lalu ada seorang laki-laki yang berkata; Wahai Rasulullah, anda meninggalkan ayat ini dan ini. Beliau bersabda: Kenapa kamu tidak mengingatkanku padanya?.\""},"1249":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي سُرَيْجُ بْنُ يُونُسَ مِنْ كِتَابِهِ قَالَ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ يَعْنِي الْمُهَلَّبِيَّ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ أَبِي رَاشِدٍ مَوْلًى لِآلِ مُعَاوِيَةَ قَالَقَدِمْتُ الشَّامَ فَقِيلَ لِي فِي هَذِهِ الْكَنِيسَةِ رَسُولُ قَيْصَرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَدَخَلْنَا الْكَنِيسَةَ فَإِذَا أَنَا بِشَيْخٍ كَبِيرٍ فَقُلْتُ لَهُ أَنْتَ رَسُولُ قَيْصَرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ نَعَمْ قَالَ قُلْتُ حَدِّثْنِي عَنْ ذَلِكَ قَالَ إِنَّهُ لَمَّا غَزَا تَبُوكَ كَتَبَ إِلَى قَيْصَرَ كِتَابًا وَبَعَثَ بِهِ مَعَ رَجُلٍ يُقَالُ لَهُ دِحْيَةُ بْنُ خَلِيفَةَ فَلَمَّا قَرَأَ كِتَابَهُ وَضَعَهُ مَعَهُ عَلَى سَرِيرِهِ وَبَعَثَ إِلَى بَطَارِقَتِهِ وَرُءُوسِ أَصْحَابِهِ فَقَالَ إِنَّ هَذَا الرَّجُلَ قَدْ بَعَثَ إِلَيْكُمْ رَسُولًا وَكَتَبَ إِلَيْكُمْ كِتَابًا يُخَيِّرُكُمْ إِحْدَى ثَلَاثٍ إِمَّا أَنْ تَتَّبِعُوهُ عَلَى دِينِهِ أَوْ تُقِرُّوا لَهُ بِخَرَاجٍ يَجْرِي لَهُ عَلَيْكُمْ وَيُقِرَّكُمْ عَلَى هَيْئَتِكُمْ فِي بِلَادِكُمْ أَوْ أَنْ تُلْقُوا إِلَيْهِ بِالْحَرْبِ قَالَ فَنَخَرُوا نَخْرَةً حَتَّى خَرَجَ بَعْضُهُمْ مِنْ بَرَانِسِهِمْ وَقَالُوا لَا نَتَّبِعُهُ عَلَى دِينِهِ وَنَدَعُ دِينَنَا وَدِينَ آبَائِنَا وَلَا نُقِرُّ لَهُ بِخَرَاجٍ يَجْرِي لَهُ عَلَيْنَا وَلَكِنْ نُلْقِي إِلَيْهِ الْحَرْبَ فَقَالَ قَدْ كَانَ ذَاكَ وَلَكِنِّي كَرِهْتُ أَنْ أَفْتَاتَ دُونَكُمْ بِأَمْرٍ قَالَ عَبَّادٌ فَقُلْتُ لِابْنِ خُثَيْمٍ أَوَلَيْسَ قَدْ كَانَ قَارَبَ وَهَمَّ بِالْإِسْلَامِ فِيمَا بَلَغَنَا قَالَ بَلَى لَوْلَا أَنَّهُ رَأَى مِنْهُمْ قَالَ فَقَالَ ابْغُونِي رَجُلًا مِنْ الْعَرَبِ أَكْتُبْ مَعَهُ إِلَيْهِ جَوَابَ كِتَابِهِ قَالَ فَأَتَيْتُ وَأَنَا شَابٌّ فَانْطُلِقَ بِي إِلَيْهِ فَكَتَبَ جَوَابَهُ وَقَالَ لِي مَهْمَا نَسِيتَ مِنْ شَيْءٍ فَاحْفَظْ عَنِّي ثَلَاثَ خِلَالٍ انْظُرْ إِذَا هُوَ قَرَأَ كِتَابِي هَلْ يَذْكُرُ اللَّيْلَ وَالنَّهَارَ وَهَلْ يَذْكُرُ كِتَابَهُ إِلَيَّ وَانْظُرْ هَلْ تَرَى فِي ظَهْرِهِ عَلَمًا قَالَ فَأَقْبَلْتُ حَتَّى أَتَيْتُهُ وَهُوَ بِتَبُوكَ فِي حَلْقَةٍ مِنْ أَصْحَابِهِ مُحْتَبِينَ فَسَأَلْتُ فَأُخْبِرْتُ بِهِ فَدَفَعْتُ إِلَيْهِ الْكِتَابَ فَدَعَا مُعَاوِيَةَ فَقَرَأَ عَلَيْهِ الْكِتَابَ فَلَمَّا أَتَى عَلَى قَوْلِهِ دَعَوْتَنِي إِلَى جَنَّةٍ عَرْضُهَا السَّمَوَاتُ وَالْأَرْضُ فَأَيْنَ النَّارُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ اللَّيْلُ فَأَيْنَ النَّهَارُ قَالَ فَقَالَ إِنِّي قَدْ كَتَبْتُ إِلَى النَّجَاشِيِّ فَخَرَّقَهُ فَخَرَّقَهُ اللَّهُ مُخَرَّقَ الْمُلْكِ قَالَ عَبَّادٌ فَقُلْتُ لِابْنِ خُثَيْمٍ أَلَيْسَ قَدْ أَسْلَمَ النَّجَاشِيُّ وَنَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ إِلَى أَصْحَابِهِ فَصَلَّى عَلَيْهِ قَالَ بَلَى ذَاكَ فُلَانُ بْنُ فُلَانٍ وَهَذَا فُلَانُ بْنُ فُلَانٍ قَدْ ذَكَرَهُمْ ابْنُ خُثَيْمٍ جَمِيعًا وَنَسِيتُهُمَا وَكَتَبْتُ إِلَى كِسْرَى كِتَابًا فَمَزَّقَهُ فَمَزَّقَهُ اللَّهُ تَمْزِيقَ الْمُلْكِ وَكَتَبْتُ إِلَى قَيْصَرَ كِتَابًا فَأَجَابَنِي فِيهِ فَلَمْ تَزَلْ النَّاسُ يَخْشَوْنَ مِنْهُمْ بَأْسًا مَا كَانَ فِي الْعَيْشِ خَيْرٌ ثُمَّ قَالَ لِي مَنْ أَنْتَ قُلْتُ مِنْ تَنُوخٍ قَالَ يَا أَخَا تَنُوخٍ هَلْ لَكَ فِي الْإِسْلَامِ قُلْتُ لَا إِنِّي أَقْبَلْتُ مِنْ قِبَلِ قَوْمٍ وَأَنَا فِيهِمْ عَلَى دِينٍ وَلَسْتُ مُسْتَبْدِلًا بِدِينِهِمْ حَتَّى أَرْجِعَ إِلَيْهِمْ قَالَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ تَبَسَّمَ فَلَمَّا قَضَيْتُ حَاجَتِي قُمْتُ فَلَمَّا وَلَّيْتُ دَعَانِي فَقَالَ يَا أَخَا تَنُوخٍ هَلُمَّ فَامْضِ لِلَّذِي أُمِرْتَ بِهِ قَالَ وَكُنْتُ قَدْ نَسِيتُهَا فَاسْتَدَرْتُ مِنْ وَرَاءِ الْحَلْقَةِ وَيَلْقَى بُرْدَةً كَانَتْ عَلَيْهِ عَنْ ظَهْرِهِ فَرَأَيْتُ غُضْرُوفَ كَتِفِهِ مِثْلَ الْمِحْجَمِ الضَّخْمِحَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي أَبُو عَامِرٍ حَوْثَرَةُ بْنُ أَشْرَسَ إِمْلَاءً عَلَىَّ قَالَ أَخْبَرَنِي حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ أَبِي رَاشِدٍ قَالَ كَانَ رَسُولُ قَيْصَرَ جَارًا لِي زَمَنَ يَزِيدَ بْنِ مُعَاوِيَةَ فَقُلْتُ لَهُ أَخْبِرْنِي عَنْ كِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَيْصَرَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَ دِحْيَةَ الْكَلْبِيَّ إِلَى قَيْصَرَ وَكَتَبَ مَعَهُ إِلَيْهِ كِتَابًا فَذَكَرَ نَحْوَ حَدِيثِ عَبَّادِ بْنِ عَبَّادٍ وَحَدِيثُ عَبَّادٍ أَتَمُّ وَأَحْسَنُ اقْتِصَاصًا لِلْحَدِيثِ وَزَادَ قَالَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ دَعَاهُ إِلَى الْإِسْلَامِ فَأَبَى أَنْ يُسْلِمَ وَتَلَا هَذِهِ الْآيَةَ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ }ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ رَسُولُ قَوْمٍ وَإِنَّ لَكَ حَقًّا وَلَكِنْ جِئْتَنَا وَنَحْنُ مُرْمِلُونَ فَقَالَ عُثْمَانُ بْنُ عَفَّانَ أَنَا أَكْسُوهُ حُلَّةً صَفُورِيَّةً وَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ عَلَيَّ ضِيَافَتُهُ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Suraij bin Yunus] dari kitabnya, berkata; telah menceritakan kepada kami ['Abbad bin 'Abbad] yaitu Al Muhallabi, dari [Abdullah bin 'Utsman bin Khutsaim] dari [Sa'id bin Abu Rasyid] budak keluarga Mu'awiyah berkata; saya datang ke Syam, lalu ada diberitahukan kepadaku 'Dalam gereja itu ada seorang [utusan Kaisar] kepada Rasulullah Shallallahu'alaihiwasallam. (Sa'id bin Abu Rasyid Radliyallahu'anhu) berkata; lalu kami memasuki gereja tersebut, ternyata saya mendapati seorang yang sudah tua berbadan besar, lalu saya berkata kepadanya, \"Apakah kamu adalah utusan Kaisar kepada Rasulullah Shallallahu'alaihiwasallam?\" Maka dia menjawab, Ya. (Sa'id bin Abu Rasyid Radliyallahu'anhu) berkata; ceritakan kepadaku tentang hal itu! Dia berkata; tatkala terjadi Perang Tabuk, Rasulullah menulis surat kepada Kaisar, sebuah surat lalu dikirimkan bersama dengan seorang utusan yang bernama Dihyah bin Khalifah, tatkala (Kaisar) membaca surat beliau, dia meletakkannya di atas tempat tidurnya, lalu dia mengutus kepada para pendetanya dan para tokohnya dari kalangan sahabatnya, lalu berkata; \"Orang ini telah diutus kepada kalian, menulis kepada kalian sebuah surat, agar kalian memilih tiga hal: Pertama, kalian mengikutinya dan mengikuti agamanya, kedua, atau kalian menentukan pajak yang menjadi hak mereka dan menjadi kewajiban kalian dan menetapkan agar kalian tetap tinggal pada negeri kalian, ketiga, atau kalian memeranginya\". Lalu mereka murka dengan sangat sampai sebagian mereka melepaskan pakaiannya dan berkata; \"Kami tidak akan ikut dia dan agamanya, lalu kami meninggalkan agama kita dan agama nenek moyang kita, kami tidak mau membayar pajak kepada dia, tapi kita berperang saja melawan mereka\". Maka dia menjawab, \"Saya juga menghendaki hal itu, tapi saya sangat benci jika memberi fatwa pada orang selain kalian pada urusan ini.\" 'Abbad berkata; lalu saya berkata kepada Ibnu Khutsaim, \"Bukankah dia telah berusaha dan hendak masuk Islam, menurut kabar yang sampai kepada kami?\". Dia menjawab, \"Ya. seandainya saja dia tidak melihat kepada pendapat yang lainnya.\" Lalu (Kaisar) berkata; \"Carilah seorang laki-laki dari Arab, saya akan menuliskan kepadanya jawaban surat.\" (Sa'id bin Abu Rasyid Radliyallahu'anhu) berkata; lalu saya menemuinya waktu itu saya masih muda, lalu saya menuju ke tempatnya, dia menulis jawabannya. Dia berkata kepadaku, \"Walaupun kamu bisa lupa terhadap sesuatu, tapi ingatlah dariku tiga ciri: Lihatlah jika dia (Rasulullah Shallallahu'alaihiwasallam) membaca suratku, apakah dia menyebutkan malam dan siang, apakah dia menyebutkan suratnya kepadaku, dan lihatlah apakah pada punggungnya ada suatu tanda.\" (Sa'id bin Abu Rasyid Radliyallahu'anhu) berkata; Lalu saya pergi sehingga saya dapat menemui dia. Saat itu beliau sedang berada di Tabuk pada suatu halaqah dengan para sahabatnya dalam keadaan duduk bersila, lalu saya menanyakannya, lalu ada yang memberitahukannya, lalu saya serahkan surat kepadanya, beliau memanggil Mu'awiyah, untuk membacakannya surat tesebut. Tatkala sampai pada kalimat, 'Kamu menyerukan kepadaku untuk menuju surga yang luasnya seluas langit dan bumi, lalu di mana neraka'. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika datang malam, di manakah siang?\" lalu beliau bersabda: \"Sesungguhnya saya telah menulis surat kepada Najasyi, lalu dia membakarnya, maka Allah membakarnya sehingga binasalah kerajaannya\". 'Abbad berkata; lalu saya bertanya kepada Ibnu Khutsaim, bukankah Najasyi telah masuk Islam dan Rasulullah Shallallahu'alaihiwasallam telah mengumumkan kematiannya di Madinah kepada para sahabatnya, lalu beliau shalat atasnya. Dia menjawab, Ya, itu adalah Fulan bin Fulan, namun ini adalah Fulan bin Fulan. Ibnu Khutsaim menyebutkanya semuanya dan saya lupa, \"Lalu saya (Rasulullah Shallallahu'alaihiwasallam) menulis kepada Kisra sebuah surat, lalu dia merobeknya, maka Allah merobek-robek kerajaannya dengan sangat dahsat, lalu saya menulis kepada Kaisar sebuah surat lalu dia menjawabnya, maka orang-orang tetap takut dari mereka dengan bahayanya selama hidupnya ada kebaikan\", lalu beliau bertanya kepadaku, \"Siapa kamu?\" Saya menjawab, Saya berasal dari Tanukh. Lalu beliau bersabda: \"Wahai orang Tanukh, apakah kamu telah masuk Islam?\"saya menjawab, \"Tidak. Sesungguhnya saya datang dari suatu kaum saya yang sudah berada di dalamnya, mereka dalam suatu agama dan saya tidak akan mengganti agama mereka sampai saya kembali kepada mereka.\" (Sa'id bin Abu Rasyid RA) berkata; lalu Rasulullah Shallallahu'alaihiwasallam tertawa atau tersenyum. Tatkala saya telah menyelesaikan urusanku, lalu saya bangun. Tatkala saya sudah meninggalkan tempat itu, beliau memanggilku, lalu bersabda: \"Wahai orang Tanukh, dengarkanlah dulu lalu pergilah sesuai dengan apa yang diperintahkan kepadamu\" (Sa'id bin Abu Rasyid RA) berkata; \"Saya telah lupa, lalu saya melihat dari belakang lingkaran dan beliau memberikan kepadaku mantel yang sedang beliau pakai\". Lalu say adapat melihat tulang lunak ada keitakanya seperti sutu lingkaran yang agak besar.\" Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Abu 'Amir, Hautsarah bin Asyras], secara dikte kepadaku, berkata; telah mengabarkan kepadaku [Hammad bin Salamah bin Abdullah bin 'Utsman bin Khutsaim] dari [Sa'id bin Abu Rasyid] berkata; \"Utusan Kaisar adalah seorang tetanggaku pada masa Yazid bin Mu'awiyah, lalu saya berkata kepadanya, 'kabarkanlah kepadaku tentang surat Rasulullah Shallallahu'alaihiwasallam kepada Kaisar', lalu dia berkata; \"Sesungguhnya Rasulullah Shallallahu'alaihiwasallam mengutus Dihyah Al Kalbi kepada Kaisar dengan menjawab surat kepadanya\", lalu menyebutkan sama dengan hadits 'Abad bin 'Abad dan hadits 'Abad lebih lengkap dan lebih bagus kisahnya dengan tambahan, \"Lalu Rasulullah Shallallahu'alaihiwasallam tertawa ketika dia mengajaknya kepada Islam, lalu dia menolaknya. lalu beliau membaca ayat ini: Sesungguhnya kamu tidak akan dapat memberi petunjuk kepada orang yang kamu kasihi, tetapi Allah memberi petunjuk kepada orang yang dikehendaki-Nya Kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya kamu adalah utusan sebuah kaum, sesungguhnya ada pada dirimu hak, tapi kau datang kepada kami dan kami dalam keadaan kekurangan bekal kami. Lalu 'Utsman bin 'Affan berkata; \"Saya yang akan memberikannya perhiasan yang bagus\", ada seorang laki-laki dari Anshar berkata; \"Saya yang akan menyambutnya.\""},"1250":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ قَالَ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي زِيَادٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ كَثِيرٍ الدَّارِيُّ عَنْ مُجَاهِدٍ قَالَ حَدَّثَنَا شَيْخٌ أَدْرَكَ الْجَاهِلِيَّةَ وَنَحْنُ فِي غَزْوَةِ رُودِسَ يُقَالُ لَهُ ابْنُ عَبْسٍ قَالَكُنْتُ أَسُوقُ لِآلٍ لَنَا بَقَرَةً قَالَ فَسَمِعْتُ مِنْ جَوْفِهَا يَا آلَ ذَرِيحٍ قَوْلٌ فَصِيحٌ رَجُلٌ يَصِيحُ لَا إِلَهَ إِلَّا اللَّهُ قَالَ فَقَدِمْنَا مَكَّةَ فَوَجَدْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَرَجَ بِمَكَّةَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Bakar Al Bursani] berkata; telah mengabarkan kepada kami ['Ubaidullah bin Abu Ziyad] berkata; telah menceritakan kepadaku [Abdullah bin Katsir Ad-Dari] dari [Mujahid] berkata; telah menceritakan kepada kami seorang yang sudah tua yang mengalami masa Jahiliyyah, dan kami dalam Perang Rudis, yang bernama [Ibnu 'Abbas], berkata; saya sedang menggiring sapi milik keluarga kami. Dia berkata; lalu saya mendengar dari lubang tengahnya, \"Wahai Keluarga Dzuraih\" suara yang sangat lantang yaitu suara seorang yang menyerukan, LA ILAHA ILLA ALLAH (tidak ada tuhan selain Allah) \" (Ibnu Abs RA) berkata; tatkala kami sampai di Makkah, kami mendapatkan Nabi Shallallahu'alaihiwasallam telah keluar di dalamnya."},"1251":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنِي أَبُو مُوسَى الْعَنْزِيُّ قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنِي سَكَنُ بْنُ الْمُغِيرَةِ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ أَبِي هِشَامٍ عَنْ فَرْقَدٍ أَبِي طَلْحَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ خَبَّابٍ السُّلَمِيِّ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَثَّ عَلَى جَيْشِ الْعُسْرَةِ فَقَالَ عُثْمَانُ بْنُ عَفَّانَ عَلَيَّ مِائَةُ بَعِيرٍ بِأَحْلَاسِهَا وَأَقْتَابِهَا قَالَ ثُمَّ حَثَّ فَقَالَ عُثْمَانُ عَلَيَّ مِائَةٌ أُخْرَى بِأَحْلَاسِهَا وَأَقْتَابِهَا قَالَ ثُمَّ نَزَلَ مَرْقَاةً مِنْ الْمِنْبَرِ ثُمَّ حَثَّ فَقَالَ عُثْمَانُ بْنُ عَفَّانَ عَلَيَّ مِائَةٌ أُخْرَى بِأَحْلَاسِهَا وَأَقْتَابِهَا قَالَ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِيَدِهِ هَكَذَا يُحَرِّكُهَاوَأَخْرَجَ عَبْدُ الصَّمَدِ يَدَهُ كَالْمُتَعَجِّبِ مَا عَلَى عُثْمَانَ مَا عَمِلَ بَعْدَ هَذَا قَالَ عَبْد اللَّهِ حَدَّثَنِي أَبُو مُوسَى الْعَنَزِيُّ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا سَكَنُ بْنُ الْمُغِيرَةِ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ هِشَامٍ عَنْ أَبِي طَلْحَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ خَبَّابٍ السُّلَمِيِّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فَحَضَّ عَلَى جَيْشِ الْعُسْرَةِ فَذَكَرَهُ","id":"Abdullah berkata; telah menceritakan kepadaku [Abu Musa Al 'Anazi] berkata; telah menceritakan kepada kami [Abdushshomad bin Abdul Warits] berkata; telah menceritakan kepadaku [Sakan bin Al Mughirah] berkata; telah menceritakan kepadaku [Al Walid bin Abu Hisyam] dari [Farqad Abu Thalhah] dari [Abdurrahman bin Khabbab As-Sulami] berkata; Rasulullah Shallallahu'alaihiwasallam keluar lalu beliau menyemangati pada pasukan Perang 'Usrah. Lalu 'Utsman bin 'Affan berkata; saya akan memberikan seratus unta lengkap dengan perhiasan dan pelananya. (Abdurrahman bin Khabbab As-Sulami radliyallahu'anhu) berkata; lalu beliau menyemangati lagi, lalu 'Utsman berkata; saya tambah seratus lagi lengkap dengan perhiasan dan pelananya. (Abdurrahman bin Khabbab As-Sulami radliyallahu'anhu) berkata; lalu beliau turun dari satu tingkat tingkat dari mimbar, lalu menyemangati lagi. Lalu 'Utsman bin 'Affan berkata; saya tambah seratus lagi lengkap dengan perhiasan dan pelananya. (Abdurrahman bin Khabbab As-Sulami radliyallahu'anhu) berkata; lalu saya melihat Nabi Shallallahu'alaihiwasallam bersabda dengan tangannya, begini dengan mengerakkannya. Abdushshamad mengeluarkan tangannya layaknya orang yang kaget atas apa yang telah dilakukan 'Utsman dan apa yang telah dia lakukan setelahnya. Abdullah berkata; telah menceritakan kepadaku [Abu Musa Al 'Anazi] berkata; telah menceritakan kepada kami ['Utsman bin 'Umar] berkata; telah menceritakan kepada kami [Sakan bin Al Mugirah] berkata; telah menceritakan kepada kami [Al Walid bin Hisyam] dari [Abu Thalhah] dari [Abdurrahman bin Khabbab As-Sulami] berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam berkhutbah lalu memberi semangat pada pasukan Al 'Usrah, lalu menyebutkan hadits secara lengkap."},"1252":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي أَبُو مُوسَى الْعَنَزِيُّ مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنِ ابْنِ عَوْنٍ عَنْ كُلْثُومِ بْنِ جَبْرٍ قَالَكُنَّا بِوَاسِطِ الْقَصَبِ عِنْدَ عَبْدِ الْأَعْلَى بْنِ عَبْدِ اللَّهِ بْنِ عَامِرٍ قَالَ فَإِذَا عِنْدَهُ رَجُلٌ يُقَالُ لَهُ أَبُو الْغَادِيَةِ اسْتَسْقَى مَاءً فَأُتِيَ بِإِنَاءٍ مُفَضَّضٍ فَأَبَى أَنْ يَشْرَبَ وَذَكَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ هَذَا الْحَدِيثَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا أَوْ ضُلَّالًا شَكَّ ابْنُ أَبِي عَدِيٍّ يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ فَإِذَا رَجُلٌ يَسُبُّ فُلَانًا فَقُلْتُ وَاللَّهِ لَئِنْ أَمْكَنَنِي اللَّهُ مِنْكَ فِي كَتِيبَةٍ فَلَمَّا كَانَ يَوْمُ صِفِّينَ إِذَا أَنَا بِهِ وَعَلَيْهِ دِرْعٌ قَالَ فَفَطِنْتُ إِلَى الْفُرْجَةِ فِي جُرُبَّانِ الدِّرْعِ فَطَعَنْتُهُ فَقَتَلْتُهُ فَإِذَا هُوَ عَمَّارُ بْنُ يَاسِرٍ قَالَ قُلْتُ وَأَيَّ يَدٍ كَفَتَاهُ يَكْرَهُ أَنْ يَشْرَبَ فِي إِنَاءٍ مُفَضَّضٍ وَقَدْ قَتَلَ عَمَّارَ بْنَ يَاسِرٍ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Abu Musa Al 'Anazi, Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Ibnu 'Aun] dari [Kultsum bin Jabar] berkata; kami sedang berada pada tengah bambu, di sisi Abdul A'la bin Abdullah bin 'Amir, berkata; ternyata ada seorang laki-laki yang bernama [Abu Al Ghadiyah] yang sedang meminta air, lalu ia diberi bejana yang disepuh dengan perak, dia menolak untuk meminumnya, dan dia menyebutkan Nabi Shallallahu'alaihiwasallam, lalu menyebutkan hadits ini, \"Janganlah kalian kembali kufur setelahku\", atau dengan redaksi \" Jangan kalian kembali sesat sepeninggalkau\" Ibnu Abu 'Adi ragu kepastian redaksinya.\"Sebagian kalian memukul leher sebagian yang lain.\" Jika ada seorang laki-laki yang mencela fulan maka saya katakan, Demi Allah, semoga Allah memberi tempat darimu di dalam sebuah pasukan Perang. Maka tatkala Perang Shiffin, saya bersamanya dan dia membawa baju besi. (Abu Ghadiyah Radliyallahu'anhu) berkata; lalu saya ingatkan dia ke lubang dalam sarung pedang pada baju besinya, lalu saya tusuk dan saya bunuh ternyata dia adalah 'Ammar bin Yasir. (Abu Ghadiyah Radliyallahu'anhu) berkata; lalu saya berkata; tangan mana yang bisa mengantikannya, membenci untuk minum dalam bejana disepuh dengan perak padahal telah membunuh 'Ammar bin Yasir."},"1253":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا رَبِيعَةُ بْنُ كُلْثُومٍ قَالَ حَدَّثَنِي أَبِي عَنْ أَبِي غَادِيَةَ الْجُهَنِيِّ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْعَقَبَةِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ إِلَى أَنْ تَلْقَوْا رَبَّكُمْ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا أَلَا هَلْ بَلَّغْتُ قَالُوا نَعَمْ قَالَ اللَّهُمَّ هَلْ بَلَّغْتُحَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنِي رَبِيعَةُ قَالَ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ أَبَا غَادِيَةَ الْجُهَنِيَّ قَالَ بَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْعَقَبَةِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ دِمَاءَكُمْ فَذَكَرَ مِثْلَهُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdushshamad bin Abdul Warits] berkata; telah menceritakan kepada kami [Rabi'ah bin Kultsum] berkata; telah menceritakan kepadaku [bapakku] dari [Abu Ghaidah Al Juhani] berkata; Rasulullah Shallallahu'alaihiwasallam berkhutbah kepada kami pada peristiwa 'Aqabah, lalu bersabda: \"Wahai manusia, sesungguhnya darah dan harta kalian, atas kalian adalah haram sampai kalian menjumpai Rab kalian, sebagaimana keharaman hari kalian ini, pada negeri kalian ini, pada bulan kalian ini. Ketahuilah, bukankah saya sudah sampaikan?.\" Mereka menjawab, Ya. Beliau bersabda: \"Ya Allah, sudah saya sampaikan\". Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepadaku [Rabi'ah] berkata; telah menceritakan kepadaku [bapakku] berkata; saya telah mendengar [Abu Ghaifah Al Juhani] berkata; saya telah bebaiat kepada Rasulullah Shallallahu'alaihiwasallam pada Peristiwa 'Aqabah, lalu bersabda: \"Wahai manusia, sesungguhnya darah kalian, \" lalu menyebutkan hadits yang sama."},"1254":{"ar":"قَالَ حَدَّثَنِي الصَّلْتُ بْنُ مَسْعُودٍ الْجَحْدَرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ قَالَ سَمِعْتُ الْعَاصِ بْنَ عَمْرٍو الطُّفَاوِيَّ قَالَخَرَجَ أَبُو الْغَادِيَةِ وحَبِيبُ بْنُ الْحَارِثِ وَأُمُّ أَبِي الْعَالِيَةِ مُهَاجِرِينَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمُوا فَقَالَتْ الْمَرْأَةُ أَوْصِنِي يَا رَسُولَ اللَّهِ قَالَ إِيَّاكِ وَمَا يَسُوءُ الْأُذُنَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepadaku [As-Shalt bin Mas'ud Al Jahdari], berkata; telah menceritakan kepada kami [Muhammad bin Abdurrahman Ath-Thufawi] berkata; saya telah mendengar [Al Ash bin 'Amr Ath-Thufawi] berkata; Abu Al Ghadiyah, Habib bin Al Harits dan Umu Abu Al 'Aliyah keluar dalam rangka berhijrah kepada Rasulullah Shallallahu'alaihiwasallam lalu mereka masuk Islam. wanita itu berkata; \"Berilah aku wasiat Wahai Rasulullah, \" Beliau bersabda: \"Hindarilah kamu hAl hal yang mengganggu telinga.\""},"1255":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارٍ مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنِ الْأَعْمَشِ عَنْ يَعْقُوبَ بْنِ بَحِيرٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يَحْلِبُ فَقَالَ دَعْ دَاعِيَ اللَّبَنِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami [Muhammad bin Bakar] budak Bani Hasyim, berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Al A'masy] dari [Ya'qub bin Bahir] dari [Dlirar bin Al Azwar] sesungguhnya Nabi Shallallahu'alaihiwasallam melewatinya dan waktu itu dia sedang memeras, maka beliau bersabda: \"Sisakanlah untuk orang yang meminta susu\"."},"1256":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا أَبُو بَكْرِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ جَارُنَا قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ الْبَاهِلِيُّ الْأَثْرَمُ الْبَصْرِيُّ قَالَ حَدَّثَنَا سَلَّامُ بْنُ سُلَيْمَانَ الْقَارِئُ قَالَ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ أَبِي وَائِلٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ امْدُدْ يَدَكَ أُبَايِعْكَ عَلَى الْإِسْلَامِ قَالَ ضِرَارٌ ثُمَّ قُلْتُ تَرَكْتُ الْقِدَاحَ وَعَزْفَ الْقِيَانِوَالْخَمْرَ تَصْلِيَةً وَابْتِهَالَاوَكَرِّي الْمُحَبَّرَ فِي غَمْرَةٍوَحَمْلِي عَلَى الْمُشْرِكِينَ الْقِتَالَافَيَا رَبِّ لَا أُغْبَنَنْ صَفْقَتِيفَقَدْ بِعْتُ مَالِي وَأَهْلِي ابْتِدَالَافَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا غُبِنَتْ صَفْقَتُكَ يَا ضِرَارُ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami [Abu Bakar Muhammad bin Abdullah] salah seorang tetangga kami, berkata; telah menceritakan kepada kami [Muhammad bin Sa'id Al Bahili Al Atsram Al Bashri] berkata; telah menceritakan kepada kami [Sallam bin Sulaiman Al Qari`] berkata; telah menceritakan kepada kami ['Ashim bin Bahdalah] dari [Abu Wa`il] dari [Dlirar bin Al Azwar] berkata; saya menemui Rasulullah Shallallahu'alaihiwasallam lalu saya berkata; \"Bentangkanlah tangan anda, saya hendak berbaiat kepada anda atas Islam\" Dlirar berkata; \"Telah saya tinggalkan periuk minum-minuman dan nyanyian penyanyi, arak hibur-hiburan dan kesombongan, kembalikanlah mantel pertempuranku, bekalku untuk perang kepada orang musyrik, Wahai tuhanku, tidak akan hilang juAl beliku, saya telah menjual harta dan keluargaku sebagai gantinya\". Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak akan hilang jual belimu, Wahai Dlirar!\""},"1257":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ يَعْقُوبَ بْنِ بَحِيرٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِ قَالَبَعَثَنِي أَهْلِي بِلَقُوحٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنِي أَنْ أَحْلِبَهَا فَحَلَبْتُهَا فَقَالَ دَعْ دَاعِيَ اللَّبَنِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Muhammad bin Abdullah bin Numair] berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Al A'masy] dari [Ya'qub bin Bahir] dari [Dlirar bin Al Azwar] berkata; keluargaku mengutusku dengan membawa unta yang hampir melahirkan kepada Nabi Shallallahu'alaihiwasallam, lalu beliau menyuruhku untuk memerahnya. Saya memerahnya dan bersabda: \"Sisakanlah untuk orang yang meminta susu\"."},"1258":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبُو صَالِحٌ الْحَكَمُ بْنُ مُوسَى قَالَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنِ الْمُغِيرَةِ بْنِ سَعْدٍ عَنْ أَبِيهِ أَوْ عَنْ عَمِّهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَأَخَذْتُ بِزِمَامِ نَاقَتِهِ أَوْ بِخِطَامِهَا فَدَفَعْتُ عَنْهُ فَقَالَ دَعُوهُ فَأَرَبٌ مَا جَاءَ بِهِ فَقُلْتُ نَبِّئْنِي بِعَمَلٍ يُقَرِّبُنِي إِلَى الْجَنَّةِ وَيُبْعِدُنِي مِنْ النَّارِ قَالَ فَرَفَعَ رَأْسَهُ إِلَى السَّمَاءِ ثُمَّ قَالَ لَئِنْ كُنْتَ أَوْجَزْتَ فِي الْخُطْبَةِ لَقَدْ أَعْظَمْتَ أَوْ أَطْوَلْتَ تَعْبُدُ اللَّهَ لَا تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ وَتَحُجُّ الْبَيْتَ وَتَصُومُ رَمَضَانَ وَتَأْتِي إِلَى النَّاسِ مَا تُحِبُّ أَنْ يُؤْتُوهُ إِلَيْكَ وَمَا كَرِهْتَ لِنَفْسِكَ فَدَعْ النَّاسَ مِنْهُ خَلِّ عَنْ زِمَامِ النَّاقَةِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Abu shalih Al Hakam bin Musa] berkata; telah mengkhabarkan kepada kami [Isa bin Yunus] dari [Al A'masy] dari ['Amr bin Murrah] dari [Al Mughirah bin Saad] dari [Bapaknya] atau dari pamannya berkata; saya mendatangi Nabi Shallallahu'alaihiwasallam di Arafah lalu saya memegang tali kendali untanya atau ujung hidungnya, lalu saya menariknya. Lalu beliau bersabda: \"Biarkanlah, keperluan apa yang kau butuhkan?\" lalu saya berkata; \"Beritakanlah kepadaku tentang amalan yang bisa mendekatkan aku ke surga dan menjauhkanku dari neraka.\" Beliau mengangkat kepalanya ke langit kemudian bersabda: \"Kamu telah meringkas isi khutbah. Sungguh kau telah meminta hal yang sangat besar atau sesuatu yang panjang. Kamu beribadah kepada Allah dan janganlah kau menyekutukan-Nya dengan sesuatu pun, kamu menegakkan shalat dan membayar zakat. Melaksanakan haji dan berpuasa Ramadlan, memberi apa yang kamu sukai kepada orang-orang, sebagaimana mereka memberikannya kepadamu. Apa yang kamu benci jika ada pada dirimu maka tinggalkanlah. Lepaskan kendali untanya!\""},"1259":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي أَبُو مُوسَى الْعَنَزِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَثْمَةَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الشَّعْثَاءِ عَنْ يُونُسَ بْنِ شَدَّادٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ صَوْمِ أَيَّامِ التَّشْرِيقِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Abu Musa Al 'Anazi] berkata; telah menceritakan kepada kami [Muhammad bin 'Atsamah] berkata; telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] dari [Abu Qilabah] dari [Abu Asy Sya'tsa`] dari [Yunus bin Syaddad] sesungguhnya Rasulullah Shallallahu'alaihiwasallam melarang berpuasa pada Hari-Hari Tasyrik."},"1260":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مَعْدِيُّ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْثُ بْنُ مُطَيْرٍ عَنْ أَبِيهِ مُطَيْرٍ ومُطَيْرٌ حَاضِرٌ يُصَدِّقُهُ مَقَالَتَهُ قَالَكَيْفَ كُنْتُ أَخْبَرْتُكَ قَالَ يَا أَبَتَاهُ أَخْبَرْتَنِي أَنَّكَ لَقِيَكَ ذُو الْيَدَيْنِ بِذِي خُشُبٍ فَأَخْبَرَكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ إِحْدَى صَلَاتَيْ الْعَشِيِّ وَهِيَ الْعَصْرُ فَصَلَّى رَكْعَتَيْنِ وَخَرَجَ سَرَعَانُ النَّاسِ وَهُمْ يَقُولُونَ أَقَصُرَتْ الصَّلَاةُ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاتَّبَعَهُ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا وَهُمَا مُبْتَدٍ فَلَحِقَهُ ذُو الْيَدَيْنِ فَقَالَ يَا رَسُولَ اللَّهِ أَقَصُرَتْ الصَّلَاةُ أَقَصُرَتْ الصَّلَاةُ أَمْ نَسِيتَ فَقَالَ مَا قَصُرَتْ وَلَا نَسِيتُ ثُمَّ أَقْبَلَ عَلَى أَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ مَا يَقُولُ ذُو الْيَدَيْنِ فَقَالَا صَدَقَ يَا رَسُولَ اللَّهِ فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَابَ النَّاسُ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِقَالَ أَبُو سُلَيْمَانَ حَدَّثْتُ سِتَّ سِنِينَ أَوْ سَبْعَ سِنِينَ ثُمَّ سَلَّمَ وَشَكَكْتُ فِيهِ وَهُوَ أَكْثَرُ حِفْظِي","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Ma'di bin Sulaiman] berkata; telah menceritakan kepada kami [Syu'aits bin Muthair] dari [bapaknya, Muthair] Muthair datang membenarkannya pembicaraannaya. Berkata; bagaimana kamu saat mengabarkannya.\"Wahai bapak, anda telah mengabarkan kepadaku, sesungguhnya [Dzul Yadain] bertemu kamu di Dzil Khusub. Lalu dia mengabarkan sesungguhnya Rasulullah Shallallahu'alaihiwasallam shalat bersama mereka salah satu shalat siang, yaitu shalat asar dengan dua rekaat, lalu keluar menuju orang-orang. Mereka berkata; shalat telah diqasar. Lalu Rasulullah Shallallahu'alaihiwasallam berdiri dan Abu Bakar dan 'Umar radliyallahu'anhuma mengikuti di belakangnya, lalu Dzul Yadain mengikutinya dan berkata; \"Wahai Rasulullah, apakah shalat telah diqashar, apakah shalat telah diqashar atau karena anda lupa?.\" Lalu beliau bersabda: \"Saya tidak mengqasarnya tapi saya lupa, \" lalu beliau menemui Abu Bakar dan 'Umar Radliyallahu'anhuma lalu bertanya, \"Apa yang dikatakan Dzul Yadain?\". Mereka berdua menjawab, \"Benar, Wahai Rasulullah.\" Lalu Rasulullah Shallallahu'alaihiwasallam kembali dan orang-orang mengikutinya, lalu beliau shalat dua rekaat dan mengucapkan salam, lalu bersujud dua kali sujud sahwi.\" Abu Sulaiman berkata; saya telah menyampaikannya selama enam tahun atau tujuh tahun, \"Lalu salam\". Saya ragu di dalamnya, itu adakah hapalan terbanyakku."},"1261":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي نَصْرُ بْنُ عَلِيٍّ قَالَ أَخْبَرَنِي مَعْدِيُّ بْنُ سُلَيْمَانَ قَالَ أَتَيْتُ مُطَيْرًا لِأَسْأَلَهُ عَنْ حَدِيثِ ذِي الْيَدَيْنِ فَأَتَيْتُهُ فَسَأَلْتُهُ فَإِذَا هُوَ شَيْخٌ كَبِيرٌ لَا يُنْفِذُ الْحَدِيثَ مِنْ الْكِبَرِ فَقَالَ ابْنُهُ شُعَيْثٌ بَلَى يَا أَبَتِحَدَّثَتْنِي أَنَّ ذَا الْيَدَيْنِ لَقِيَكَ بِذِي خَشَبٍ فَحَدَّثَكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ إِحْدَى صَلَاتَيْ الْعَشِيِّ وَهِيَ الْعَصْرُ رَكْعَتَيْنِ ثُمَّ سَلَّمَ فَخَرَجَ سَرَعَانُ النَّاسِ فَقَالَ أَقَصُرَتْ الصَّلَاةُ وَفِي الْقَوْمِ أَبُو بَكْرٍ وَعُمَرُ فَقَالَ ذُو الْيَدَيْنِ أَقَصُرَتْ الصَّلَاةُ أَمْ نَسِيتَ قَالَ مَا قَصُرَتْ الصَّلَاةُ وَلَا نَسِيتُ ثُمَّ أَقْبَلَ عَلَى أَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ مَا يَقُولُ ذُو الْيَدَيْنِ فَقَالَا صَدَقَ يَا رَسُولَ اللَّهِ فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَابَ النَّاسُ وَصَلَّى بِهِمْ رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ بِهِمْ سَجْدَتَيْ السَّهْوِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Nasr bin Ali] berkata; telah mengabarkan kepadaku [Ma'di bin Sulaiman] berkata; saya telah mendatangi [Muthair] untuk menanyakannya tentang hadits Dzul Yadain lalu saya mendatanginya dan bertanya kepadanya, ternyata dia sudah sangat tua yang tidak lagi kuasa menyampaikan hadis karena sudah sangat tuanya. Lalu anaknya [Syu'aits] berkata; Wahai bapakku, dahulu engkau telah menceritakan kepadaku sesungguhnya [Dzil Yadain] telah bertemu denganmu di Dzil Khasyab lalu menceritakan kepadamu, sesungguhnya Rasulullah Shallallahu'alaihiwasallam shalat bersama mereka salah satu shalat siang yaitu shalat asar dua rekaat lalu salam, lalu keluar menuju ke orang-orang. Dia berkata; shalat telah diqashar dan di dalam kaum ada Abu Bakar dan 'Umar Radliyallahu'anhu. Lalu (Rasulullah Shallallahu'alaihiwasallam) bertanya tentang apa yang dikatakan oleh Dzul Yadain. Mereka berdua menjawab, \"Benar, Wahai Rasulullah, \" Lalu Rasulullah Shallallahu'alaihiwasallam kembali dan orang-orang mengikutinya lalu shalat dua rekaat dan mengucapkan salam, lalu bersujud bersama mereka dua kali sujud sahwi.\""},"1262":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبُو مَعْمَرٍ عَنْ ابْنِ أَبِي حَازِمٍ قَالَجَاءَ رَجُلٌ إِلَى عَلِيِّ بْنِ حُسَيْنٍ فَقَالَ مَا كَانَ مَنْزِلَةُ أَبِي بَكْرٍ وَعُمَرَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْزِلَتُهُمَا السَّاعَةَ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Abu Ma'mar] dari [Ibnu Abu Hazim] berkata; telah datang seorang laki-laki kepada ['Ali bin Husain] lalu bertanya, apakah kedudukan Abu Bakar dan 'Umar dari Nabi Shallallahu'alaihiwasallam?, maka dia menjawab, \"Kedudukan keduanya adalah bagaikan pentingnya waktu.\""},"1263":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ وَخَلَفُ بْنُ هِشَامٍ قَالَا حَدَّثَنَا عَامِرُ بْنُ أَبِي عَامِرٍ الْخَزَّازُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نَحَلَ وَالِدٌ وَلَدَهُ نُحْلًا أَفْضَلَ مِنْ أَدَبٍ حَسَنٍ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami ['Ubaidullah bin 'Umar Al Qawariri] dan [Khalaf bin Hisyam] berkata; telah menceritakan kepada kami ['Amr bin Abu 'Amr Al Khazari] dari [Ayyub bin Musa] dari [Bapaknya] dari [kakeknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang tua tidak bisa memberi pemberian kepada anaknya yang lebih utama daripada adab yang baik.\""},"1264":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ قَالَ عَمْرُو بْنُ يَحْيَى حَدَّثَنِي عَنْ يَحْيَى بْنِ عُمَارَةَ عَنْ جَدِّهِ أَبِي حَسَنٍ قَالَدَخَلْتُ الْأَسْوَاقَ وَقَالَ فَأَثَرْتُ وَقَالَ الْقَوَارِيرِيُّ مَرَّةً فَأَخَذْتُ دُبْسَتَيْنِ قَالَ وَأُمُّهُمَا تُرَشْرِشُ عَلَيْهِمَا وَأَنَا أُرِيدُ أَنْ آخُذَهُمَا قَالَ فَدَخَلَ عَلَيَّ أَبُو حَسَنٍ فَنَزَعَ مِتِّيخَةً قَالَ فَضَرَبَنِي بِهَا فَقَالَتْ لِي امْرَأَةٌ مِنَّا يُقَالُ لَهَا مَرْيَمُ لَقَدْ تَعِسْتَ مِنْ عَضُدِهِ وَمِنْ تَكْسِيرِ الْمِتِّيخَةِ فَقَالَ لِي أَلَمْ تَعْلَمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ مَا بَيْنَ لَابَتَيْ الْمَدِينَةِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami ['Ubaidullah bin 'Umar] telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad-Darawardi] ['Amr bin Yahya] berkata; telah menceritakan kepadaku dari [Yahya bin 'Umarah] dari [kakeknya Abu Hasan] berkata; saya memasuki pasar lalu saya saya meninggalkan, Al Qawariri berkata; lalu saya mengambil dua kuda. (Al Qawariri radliyallahu'anhu) berkata; induk keduanya menderuminya padahal saya hendak mengambilnya. (Al Qawariri radliyallahu'anhu) berkata; lalu Abu Hasan menemuiku dan mencabut dahan, lalu dia memukuliku dengan dahan itu, lalu ada seorang wanita yang berkata kepadaku yang bernama Maryam, \"Sungguh kamu telah rugi dari ototnya dan dari rusaknya dahan\". Lalu (Abu Hasan Radliyallahu'anhu) berkata kepadaku, \"Tidakkah kamu mengetahui sesungguhnya Rasulullah Shallallahu'alaihiwasallam mengharamkan apa yang ada antara dua gunung di Madinah?.\""},"1265":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو الْفَضْلِ الْمَرْوَزِيُّ قَالَ حَدَّثَنِي ابْنُ أَبِي أُوَيْسٍ قَالَ وَحَدَّثَنِي حُسَيْنُ بْنُ عَبْدِ اللَّهِ ابْنِ ضُمَيْرَةَ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ جَدِّهِ أَبِي حَسَنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَكْرَهُ نِكَاحَ السِّرِّ حَتَّى يُضْرَبَ بِدُفٍّ وَيُقَالَ أَتَيْنَاكُمْ أَتَيْنَاكُمْفَحَيُّونَا نُحَيِّيكُمْ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Al Fadl Al Marwazi] berkata; telah menceritakan kepadaku [Ibnu Abu Uwais] berkata; dan telah menceritakan kepadaku [Husain bin Abdullah bin Dlumairah] dari ['Amr bin Yahya Al Mazini] dari [kakeknya Abu Hasan] sesungguhnya Nabi Shallallahu'alaihiwasallam membenci pernikahan yang diselenggarakan secara sembunyi-sembunyi sehingga kendang dipukul, dan dilantunkan bait-bait lagu, \"Kami mendatangi kalian, kami mendatangi kalian, sambutlah kami dan kami akan menyambut kalian.\""},"1266":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ حَاتِمٍ الطَّوِيلُ وَكَانَ ثِقَةً رَجُلًا صَالِحًا قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ يَعْنِي الدَّرَاوَرْدِيَّ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ أَوْ عَمِّهِ قَالَكَانَتْ لِي جُمَّةٌ كُنْتُ إِذَا سَجَدْتُ رَفَعْتُهَا فَرَآنِي أَبُو حَسَنٍ الْمَازِنِيُّ فَقَالَ تَرْفَعُهَا لَا يُصِيبُهَا التُّرَابُ وَاللَّهِ لَأَحْلِقَنَّهَا فَحَلَقَهَا","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami [Ahmad bin Hatim Ath-Thawil] dia adalah orang yang tsiqah, seorang laki-laki yang shalih, berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad-Darawardi] dari ['Amr bin Yahya] dari [Bapaknya] atau [pamannya] berkata; saya memiliki rambut panjang hingga kedua pundakku, jika saya bersujud maka saya harus mengangkatnya, [Abu Hasan Al Mazini] melihatku lalu dia berkata; kalaulah kamu mengangkatnya niscaya tidak akan terkena tanah. Demi Allah, saya akan memotongnya. Lalu dia mencukurnya."},"1267":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي أَبُو مَالِكٍ الْحَنَفِيُّ كَثِيرُ بْنُ يَحْيَى بْنِ كَثِيرٍ الْبَصْرِيُّ قَالَ حَدَّثَنَا ثَابِتٌ أَبُو زَيْدٍ قَالَ حَدَّثَنَا هِلَالُ بْنُ خَبَّابٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ الْمَخْزُومِيِّ قَالَ حَدَّثَنِي عَرِيفٌ مِنْ عُرَفَاءِ قُرَيْشٍ عَنْ أَبِيهِسَمِعَهُ مِنْ فَلْقِ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ رَمَضَانَ وَشَوَّالَ وَالْأَرْبِعَاءَ وَالْخَمِيسَ دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Abu Malik Al Hanafi, Katsir bin Yahya bin Katsir Al Basri] berkata; telah menceritakan kepada kami [Tsabit Abu Zaid] berkata; telah menceritakan kepada kami [Hilal bin Khabbab] dari [Ikrimah Khalid Al Makhzumi] berkata; telah menceritakan kepadaku [orang yang punya pengetahuan dari kalangan Quraish] dari [Bapaknya] telah mendengar dari seseorang yang berada disisi Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang berpuasa Ramadan, Syawal, Rabu dan Kamis, maka akan masuk surga\"."},"1268":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي سُرَيْجُ بْنُ يُونُسَ مِنْ كِتَابِهِ قَالَ أَخْبَرَنَا أَبُو إِسْمَاعِيلَ الْمُؤَدِّبُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ عَائِذٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى نَاقَةٍ خَرْمَاءَ وَعَبْدٌ حَبَشِيٌّ مُمْسِكٌ بِخِطَامِهَاوَهَلَكَ قَيْسٌ أَيَّامَ الْمُخْتَارِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Suraij bin Yunus] dari kitabnya, berkata; telah mengabarkan kepada kami [Abu Isma'il Al Mu`addab] dari [Isma'il bin Abu Khalid] dari [Qais bin 'A`id] berkata; saya pernah melihat Rasulullah Shallallahu'alaihiwasallam berkhutbah di atas unta Kharma` dan seorang budak memegang tali kendali untanya. Dan Qais meninggal pada masa Al Mukhtar berkuasa. "},"1269":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا أَبُو مَعْشَرٍ الْبَرَاءُ قَالَ حَدَّثَنَا ابْنُ حَرْمَلَةَ عَنْ يَحْيَى بْنِ هِنْدِ بْنِ حَارِثَةَ عَنْ أَبِيهِ وَكَانَ مِنْ أَصْحَابِ الْحُدَيْبِيَةِ وَأَخُوهُ الَّذِي بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ قَوْمَهُ بِصِيَامِ يَوْمِ عَاشُورَاءَ وَهُوَ أَسْمَاءُ بْنُ حَارِثَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ فَقَالَ مُرْ قَوْمَكَ فَلْيَصُومُوا هَذَا الْيَوْمَ قَالَ أَرَأَيْتَ إِنْ وَجَدْتُهُمْ قَدْ طَعِمُوا قَالَ فَلْيُتِمُّوا بَقِيَّةَ يَوْمِهِمْ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Muhammad bin Abu Bakar Al Muqaddami] berkata; telah menceritakan kepada kami [Abu Ma'syar Al Bara`] berkata; telah menceritakan kepada kami [Ibnu Harmalah] dari [Yahya bin Hind bin Haritsah] dari [Bapaknya] salah seorang yang ikut Peristiwa Hudaibiyah, saudaranya adalah termasuk yang diutus Rasulullah Shallallahu'alaihiwasallam agar menyuruh kaumnya agar berpuasa hari Asy Syura` yaitu Asma` bin Haritsah sesungguhnya Rasulullah Shallallahu'alaihiwasallam mengutusnya dan bersabda: \"Perintahkan kaummu agar berpuasa pada hari ini.\" (Asma` bin Haritsah Radliyallahu'anhu) berkata; \"Bagaimana pendapat anda jika saya dapatkan mereka telah makan?\". Beliau bersabda: \"Sempurnakanlah sisa harinya\""},"1270":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا نَضْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَعَبْدُ الْأَعْلَى بْنُ حَمَّادٍ أَبُو يَحْيَى النَّرْسِيُّ قَالَا حَدَّثَنَا عَامِرُ بْنُ أَبِي عَامِرٍ الْخَزَّازُ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ مُوسَى عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نَحَلَ وَالِدٌ وَلَدًا أَفْضَلَ مِنْ أَدَبٍ حَسَنٍ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Nadlr bin 'Ali Al Jahdlami] dan [Abdul A'la bin Hammad, Abu Yahya An-Narsi] berkata; telah menceritakan kepada kami ['Amir bin Abu 'Amir Al Khazari] berkata; telah menceritakan kepada kami [Ayyub bin Musa] dari [Bapaknya] dari [kakeknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang tua tidak bisa memberi pemberian kepada anaknya yang lebih utama daripada adab yang baik.\""},"1271":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ ثَعْلَبَةَ بْنِ سَوَاءٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ قَالَ حَدَّثَنَا حُمْرَانُ بْنُ يَزِيدَ الْأَعْمَى عَنْ قَتَادَةَ عَنْ رَجُلٍ مِنْ بَنِي سَدُوسٍ عَنْ قُطْبَةَ بْنِ قَتَادَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُفْطِرُ إِذَا غَرَبَتْ الشَّمْسُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Tsa'labah bin Sawa`] berkata; telah menceritakan kepada kami [Muhammad bin Sawa`] berkata; telah menceritakan kepada kami [Humran bin Yazid yang buta] dari [Qatadah] dari [seorang laki-laki dari Bani Sundus] dari [Quthbah bin Qatadah] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam berbuka jika matahari telah tenggelam."},"1272":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ ثَعْلَبَةَ بْنِ سَوَاءٍ قَالَ حَدَّثَنِي ابْنُ سَوَاءٍ قَالَ حَدَّثَنِي حُمْرَانُ بْنُ يَزِيدَ عَنْ قَتَادَةَ عَنْ رَجُلٍ مِنْ بَنِي سَدُوسٍ عَنْ قُطْبَةَ بْنِ قَتَادَةَ قَالَبَايَعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ابْنَتِي الْحَوْصَلَةِوَكَانَ يُكَنَّى بِأَبِي الْحَوْصَلَةِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Muhammad bin Tsa'labah bin Sawa`] berkata; telah menceritakan kepadaku [Ibnu Sawa`] berkata; telah menceritakan kepadaku [Humran bin Yazid] dari [Qatadah] dari [seorang laki-laki dari Bani Sundus] dari [Quthbah bin Qatadah] berkata; saya telah berbaiat kepada Nabi Shallallahu'alaihiwasallam untuk dua anak perempuan Al Hushalah sehingga dia diberi julukan dengan Abu Al Haushalah."},"1273":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يُوسُفُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ الْخَطْمِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُقْبَةَ بْنِ الْفَاكِهِ عَنْ جَدِّهِ الْفَاكِهِ بْنِ سَعْدٍ وَكَانَتْ لَهُ صُحْبَةٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْتَسِلُ يَوْمَ الْجُمُعَةِ وَيَوْمَ عَرَفَةَ وَيَوْمَ الْفِطْرِ وَيَوْمَ النَّحْرِقَالَ وَكَانَ الْفَاكِهُ بْنُ سَعْدٍ يَأْمُرُ أَهْلَهُ بِالْغُسْلِ فِي هَذِهِ الْأَيَّامِ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Nasr bin Ali] berkata; telah menceritakan kepada kami [Yusuf bin Khalid] berkata; telah menceritakan kepada kami [Abu Ja'far Al Khathmi] dari [Abdurrahman bin 'Uqbah bin Al Faqih] dari [kakeknya, Al Faqih bin Saad] dia adalah salah seorang sahabat, sesungguhnya Rasulullah Shallallahu'alaihiwasallam mandi pada Hari Jumat, Hari Arafah, Idul Fitri dan Idul Adha. (Abdurrahman bin 'Uqbah bin Al Faqih Radliyallahu'anhu) berkata; Al Faqih bin Saad menyuruh keluarganya mandi pada hari-hari tersebut."},"1274":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَبُو مَعْمَرٍ الْهُذَلِيُّ حَدَّثَنَا سَعِيدُ بْنُ خُثَيْمٍ الْهِلَالِيُّ قَالَ حَدَّثَتْنِي جَدَّتِي أُمُّ أَبِي رَبِيعَةُ بِنْتُ عِيَاضٍ الْكِلَابِيَّةُ عَنْ جَدِّهَا عَبِيدَةَ بْنِ عَمْرٍو الْكِلَابِيِّ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَوَضَّأُ فَأَسْبَغَ الطُّهُورَوَكَانَتْ هِيَ إِذَا تَوَضَّأَتْ أَسْبَغَتْ الطُّهُورَ حَتَّى تَرْفَعَ الْخِمَارَ فَتَمْسَحَ رَأْسَهَا","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Isma'il bin Ibrahim, Abu Ma'mar Al Hudzali] telah menceritakan kepada kami [Sa'id bin Khustaim Al Hilali] berkata; telah menceritakan kepadaku [nenekku, Rabi'ah binti Iyadl Al Kilabiyah] dari [kakeknya, 'Abidah bin 'Amr Al Kilabi] berkata; saya melihat Nabi Shallallahu'alaihiwasallam beliau sedang berwudlu lalu menyempurnakan wudlunya. (Umu Abu Rabi'ah binti Iyadl Al Kilabiyah Radliyallahu'anhuma) jika berwudlu menyempurnakan wudlu sampai mengangkat kerudungnya dan mengusap kepalanya."},"1275":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي عُثْمَانُ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ خُثَيْمٍ الْهِلَالِيُّ قَالَ سَمِعْتُ جَدَّتِي رَبِيعَةَ ابْنَةَ عِيَاضٍ عَنْ جَدِّهَا عَبِيدَةَ بْنِ عَمْرٍو الْكِلَابِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَأَسْبَغَ الْوُضُوءَقَالَ وَكَانَتْ رَبِيعَةُ إِذَا تَوَضَّأَتْ أَسْبَغَتْ الْوُضُوءَ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku ['Utsman bin Muhammad bin Abu Syaibah] berkata; telah menceritakan kepada kami [Sa'id bin Khustaim Al Hilali] berkata; saya telah mendengar [nenekku, Rabi'ah binti Iyadl] dari [kakeknya 'Abidah bin 'Amr Al Kilabi] berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam berwudlu lalu menyempurnakan wudlunya. (Sa'id bin Khustaim Al Hilali Radliyallahu'anhu) berkata; Rabi'ah jika berwudlu maka dia menyempurnakan wudlunya."},"1276":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدٍ النَّاقِدُ قَالَ حَدَّثَنَا سَعِيدُ بْنُ خُثَيْمٍ الْهِلَالِيُّ قَالَ حَدَّثَتْنِي جَدَّتِي رَبِيعَةُ ابْنَةُ عِيَاضٍ الْكِلَابِيَّةُ عَنْ جَدِّهَا عَبِيدَةَ بْنِ عَمْرٍو الْكِلَابِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ فَأَسْبَغَ الطُّهُورَقَالَ وَكَانَتْ هِيَ يَعْنِي جَدَّتَهُ إِذَا أَخَذَتْ الطَّهُورَ أَسْبَغَتْ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku ['Amr bin Muhammad An-Naqid] berkata; telah menceritakan kepada kami [Sa'id bin Khustaim Al Hilali] berkata; telah menceritakan kepadaku [nenekku, Rabi'ah binti Iyadl Al Kilabiyah] dari [kakeknya, 'Abidah bin 'Amr Al Kilabi] berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam berwudlu lalu menyempurnakan wudlunya. (Sa'id bin Khustaim Al Hilali Radliyallahu'anhu) berkata; dia (Rabi'ah Radliyallahu'anhu) alias neneknya, jika berwudlu maka dia menyempurnakan wudlunya."},"1277":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ الْيَزَنِيِّ عَنْ مَالِكِ بْنِ هُبَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُؤْمِنٍ يَمُوتُ فَيُصَلِّي عَلَيْهِ أُمَّةٌ مِنْ الْمُسْلِمِينَ بَلَغُوا أَنْ يَكُونُوا ثَلَاثَةَ صُفُوفٍ إِلَّا غُفِرَ لَهُقَالَ فَكَانَ مَالِكُ بْنُ هُبَيْرَةَ يَتَحَرَّى إِذَا قَلَّ أَهْلُ جَنَازَةٍ أَنْ يَجْعَلَهُمْ ثَلَاثَةَ صُفُوفٍ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Hammad bin Zaid] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Martsad bin Abdullah Al Yazani] dari [Malik bin Hubarah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seorang mukmin yang meninggal lalu ada sekelompok orang yang menshalatinya sampai tiga shaf kecuali pasti dia diampuni.\" (Martsad bin Abdullah Al Yazani Radliyallahu'aanhu) berkata; jika keluarga jenazah sedikit, Malik bin Hubarah tetap menjaga agar bisa dijadikan tiga shaf."},"1278":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنِ الْمِقْدَادِ بْنِ الْأَسْوَدِ قَالَقَالَ لِي عَلِيٌّ سَلْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُلَاعِبُ امْرَأَتَهُ فَيَخْرُجُ مِنْهُ الْمَذْيُ مِنْ غَيْرِ مَاءِ الْحَيَاةِ قَالَ يَغْسِلُ فَرْجَهُ وَيَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid] berkata; telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Al Miqdad bin Al Aswad] berkata; \"'Ali berkata kepadaku tanyakan kepada Rasulullah Shallallahu'alaihiwasallam tentang seorang laki-laki yang mencumbui istrinya lalu keluar madzi bukan 'air kehidupan'(mani). Beliau bersabda: \"Hendaklah ia mencuci kemaluannya dan berwudlu untuk shalat\"."},"1279":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا إِسْرَائِيلُ بْنُ يُونُسَ بْنِ أَبِي إِسْحَاقَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَبْدِ الْأَعْلَى عَنْ جَدَّتِهِ عَنْ أَبِيهَا سُوَيْدِ بْنِ حَنْظَلَةَ قَالَخَرَجْنَا نُرِيدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَنَا وَائِلُ بْنُ حُجْرٍ فَأَخَذَهُ عَدُوٌّ لَهُ فَتَحَرَّجَ النَّاسُ أَنْ يَحْلِفُوا وَحَلَفْتُ أَنَّهُ أَخِي فَخَلَّى عَنْهُ فَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ أَنْتَ كُنْتَ أَبَرَّهُمْ وَأَصْدَقَهُمْ صَدَقْتَ الْمُسْلِمُ أَخُو الْمُسْلِمِحَدَّثَنَا الْوَلِيدُ بْنُ الْقَاسِمِ وأَسْوَدُ بْنُ عَامِرٍ قَالَا حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الْأَعْلَى عَنْ جَدَّتِهِ عَنْ أَبِيهَا سُوَيْدِ بْنِ حَنْظَلَةَ قَالَ خَرَجْنَا نُرِيدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Isra`il bin Yunus bin Abu Ishaq] berkata; telah menceritakan kepada kami [Ibrahim bin Abdu' A'la] dari [neneknya] dari [Bapaknya, Suwaid bin Hanzlalah] berkata; kami keluar untuk menemui Rasulullah Shallallahu'alaihiwasallam bersama dengan Wa`il bin Hujr lalu ada musuh yang menangkapnya. Orang-orang meminta dengan berulang-ulang agar bersumpah. Saya bersumpah bahwa dia adalah saudara laki-lakiku, lalu dia melepaskannya. Lalu kami mendatangi Rasulullah Shallallahu'alaihiwasallam, saya menyebutkan apa yang terjadi, lalu beliau bertanya, \"Kamu adalah orang terbaik dan orang terpercaya di antara mereka. Kamu benar, seorang muslim adalah saudara muslim lainnya. Telah menceritakan kepada kami [Al Walid bin Al Qasim] dan [Aswad bin 'Amir] berkata; telah menceritakan kepada kami [Isra`il] dari [Ibrahim bin Abdul A'la] dari [neneknya] dari [Bapaknya, Suwaid bin Hanzlalah] berkata; kami keluar untuk menemui Rasulullah Shallallahu'alaihiwasallam, lalu menyebutkan secara lengkap."},"1280":{"ar":"حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى قَالَ أَنَا الْحَارِثُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مُنِيرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ سَعْدِ بْنِ أَبِي ذُبَابٍ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمْتُ قُلْتُ يَا رَسُولَ اللَّهِ اجْعَلْ لِقَوْمِي مَا أَسْلَمُوا عَلَيْهِ مِنْ أَمْوَالِهِمْ فَفَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَعْمَلَنِي عَلَيْهِمْ ثُمَّ اسْتَعْمَلَنِي أَبُو بَكْرٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ ثُمَّ اسْتَعْمَلَنِي عُمَرُ مِنْ بَعْدِهِ","id":"Telah menceritakan kepada kami [Shafwan bin Isa] berkata; telah memberitakan kepada kami [Al Harits bin Abdurrahman] dari [Munir bin Abdullah] dari [Bapaknya] dari [Sa'd bin Abu Dzubab] berkata; saya menemui Rasulullah Shallallahu'alaihiwasallam lalu saya masuk Islam. Saya berkata; \"Wahai Rasulullah, berbuatlah sesuatu agar kaumku masuk Islam karena harta mereka.\" Lalu Rasulullah Shallallahu'alaihiwasallam melakukannya dan beliau mengangkatku menjadi pejabat atas mereka, lalu Abu Bakar Radliyallahu'anhu juga mengangkatku. Lalu 'Umar juga demikian pada setelahnya."},"1281":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنَا ابْنُ جُرَيْجٍ قَالَ أَنَا عَمْرُو بْنُ دِينَارٍ أَنَّهُ سَمِعَ طَاوُسًا يُخْبِرُ عَنِ ابْنِ عَبَّاسٍ عَنْ عُمَرَ رَضِيَ اللَّهُ تَعَالَى عَنْهُأَنَّهُ نَشَدَ قَضَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ فَجَاءَ حَمَلُ بْنُ مَالِكِ بْنِ النَّابِغَةِ فَقَالَ كُنْتُ بَيْنَ بَيْتَيْ امْرَأَتَيَّ فَضَرَبَتْ إِحْدَاهُمَا الْأُخْرَى بِمِسْطَحٍ فَقَتَلَتْهَا وَجَنِينَهَا فَقَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنِينِهَا بِغُرَّةٍ وَأَنْ تُقْتَلَ بِهَاقُلْتُ لِعَمْرٍو لَا أَخْبَرَنِي عَنْ أَبِيهِ بِكَذَا وَكَذَا قَالَ لَقَدْ شَكَّكْتَنِي","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah memberitakan kepada kami [Ibnu Juraij] berkata; telah memberitakan kepada kami ['Amr bin Dinar] sesungguhnya telah mendengar [Thawus] mengabari dari [Ibnu Abbas] dari ['Umar radliyallahu'anhuma] sesungguhnya dia melakukan ketentuan Rasulullah Shallallahu'alaihiwasallam pada masalah itu. Lalu [Hamal bin Malik bin Nabighah] datang, lalu berkata; saya berada di antara kedua rumah istriku, lalu salah satunya memukul yang lainnya dengan tongkat sehingga meninggal beserta janinnya. Lalu Nabi Shallallahu'alaihiwasallam memutuskan pada janinnya dengan uzzah (delapan belas diat atau setara dengan satu budak) lalu dia dibunuh. Saya (Ibnu Juraij Radliyallahu'anhu) berkata kepada 'Amr, tidak, dia telah mengabariku dari Bapaknya, demikian dan demikian. Dia berkata; kamu telah menjadikan saya ragu."},"1282":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا أَبُو خَالِدٍ هُدْبَةُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى قَالَ حَدَّثَنَا أَبُو جَمْرَةَ الضُّبَعِيُّ عَنْ أَبِي بَكْرٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى الْبَرْدَيْنِ دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepada kami [Abu Khalid Hudbah bin Khalid] berkata; telah menceritakan kepada kami [Hammam bin Yahya] berkata; telah menceritakan kepada kami [Abu Jamrah Adl-Dlab'i] dari [Abu Bakar] dari [Bapaknya] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang shalat shalat fajar dan shalat asar, akan masuk surga.\""},"1283":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَأَضْلَلْتُ بَعِيرًا لِي بِعَرَفَةَ فَذَهَبْتُ أَطْلُبُهُ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقِفٌ قُلْتُ إِنَّ هَذَا مِنْ الْحُمْسِ مَا شَأْنُهُ هَاهُنَا وَقَالَ سُفْيَانُ مَرَّةً عَنْ عَمْرٍو عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَ ذَهَبْتُ أَطْلُبُ بَعِيرًا لِي بِعَرَفَةَ فَوَجَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقِفًا قُلْتُ هَذَا مِنْ الْحُمْسِ مَا شَأْنُهُ هَاهُنَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] berkata; saya kehilangan kendaraanku di Arafah, lalu saya pergi untuk mencarinya. Ternyata Nabi Shallallahu'alaihiwasallam sedang berwukuf di sana, saya berkata; sesungguhnya ini termasuk tradisi yang dipegang teguh Al humus (orang Quraisy dinamai dengan hal itu karena sangat eratnya dalam memegang agama) ada apa di sini. [Sufyan] berkata; dari ['Amr] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] berkata; saya pergi untuk mencari unta kendaraanku di Arafah, lalu saya mendapatkan Rasulullah Shallallahu'alaihiwasallam berwukuf lalu saya berkata; ini adalah termasuk tradisi yang dipegang teguh Al humus, bagaimana keadaannya di sini?. "},"1284":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مِسْعَرٍ قَالَ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ رَجُلٍ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي التَّطَوُّعِ اللَّهُ أَكْبَرُ كَبِيرًا ثَلَاثَ مِرَارٍ وَالْحَمْدُ لِلَّهِ كَثِيرًا ثَلَاثَ مِرَارٍ وَسُبْحَانَ اللَّهِ بُكْرَةً وَأَصِيلًا ثَلَاثَ مِرَارٍ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الشَّيْطَانِ الرَّجِيمِ مِنْ هَمْزِهِ وَنَفْثِهِ وَنَفْخِهِ قُلْتُ يَا رَسُولَ اللَّهِ مَا هَمْزُهُ وَنَفْثُهُ وَنَفْخُهُ قَالَ أَمَّا هَمْزُهُ فَالْمُوتَةُ الَّتِي تَأْخُذُ ابْنَ آدَمَ وَأَمَّا نَفْخُهُ الْكِبْرُ وَنَفْثُهُ الشِّعْرُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Mis'ar] berkata; telah menceritakan kepadaku ['Amr bin Murrah] dari [seorang laki-laki] dari [Nafi' bin Jubair bin Muth'im] dari [Bapaknya] berkata; saya mendengar Nabi Shallallahu'alaihiwasallam membaca pada shalat sunnah, \"Allah Maha Besar\" tiga kali.\"Segala puji bagi Allah, pujian yang banyak\" tiga kali.\"Maha suci Allah pada pagi hari dan sore\" tiga kali.\"Ya Allah, sesungguhnya saya berlindung kepada-Mu dari setan yang terkutuk dari ganguannya (kegilaan yang bisa menimpa anak Adam), syairnya dan kesombongannya.\" Saya bertanya Wahai Rasulullah, apa yang dimaksud istilah hamz-nya, nafts-nya dan an-nafkh-nya? Beliau menjawab,, \"Hamznya maksudnya adalah keadaan gila atau ayan yang menimpa anak Adam, an-nafkh adalah kesombongannya dan nafts adalah syairnya yang jelek.\""},"1285":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ رَجُلٍ مِنْ عَنَزَةَ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُ أَكْبَرُ كَبِيرًا وَالْحَمْدُ لِلَّهِ كَثِيرًا وَسُبْحَانَ اللَّهِ بُكْرَةً وَأَصِيلًا اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الشَّيْطَانِ الرَّجِيمِ مِنْ هَمْزِهِ وَنَفْثِهِ وَنَفْخِهِ قَالَ قُلْتُ مَا هَمْزُهُ قَالَ فَذَكَرَ كَهَيْئَةِ الْمُوتَةِ يَعْنِي يَصْرَعُ قُلْتُ فَمَا نَفْخُهُ قَالَ الْكِبْرُ قُلْتُ فَمَا نَفْثُهُ قَالَ الشِّعْرُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Mis'ar] dari ['Amr bin Murrah] dari [seorang laki-laki dari 'Anazah] dari [Nafi' bin Jubair bin Muth'im] dari [Bapaknya] sesungguhnya Rasulullah Shallallahu'alaihiwasallam membaca, \"Allah Maha Besar. Segala puji bagi Allah, pujian yang banyak. Maha suci Allah pada pagi hari dan sore. Ya Allah, sesungguhnya saya berlindung kepada-Mu dari setan yang terkutuk dari ganguannya (kegilaan yang bisa menimpa anak Adam), syairnya dan kesombongannya.\" (Jubair bin Muth'im Radliyallahu'anhu) berkata; saya bertanya, apakah Hamznya itu? Beliau menyebutkan, seperti keadaan orang yang gila atau ayan. Saya bertanya, an-nafkh? Beliau menjawab, kesombongannya. Saya bertanya, nafts, maka beliau menjawab, syairnya yang jelek."},"1286":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنَا ابْنُ أَبِي ذِئْبٍ عَنِ الزُّهْرِيِّ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَزْهَرِ عَنْ جُبَيْرِ بْنِ مُطْعِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلْقُرَشِيِّ مِثْلَيْ قُوَّةِ الرَّجُلِ مِنْ غَيْرِ قُرَيْشٍفَقِيلَ لِلزُّهْرِيِّ مَا عَنَى بِذَلِكَ قَالَ نُبْلَ الرَّأْيِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yazid] berkata; telah memberitakan kepada kami [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Thalhah bin Abdullah bin 'Auf] dari [Abdurrahman bin Al Azhar] dari [Jubair bin Muth'im] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya orang Quraisy adalah keteladanan kekuatan bagi selain Quraisy.\" Ditanyakan kepada Az Zuhri, apa yang dimaksud dengan hal itu? Maka dia menjawab, kecerdasan dalam berpendapat."},"1287":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو قَالَ أَنَا ابْنُ جُرَيْجٍ قَالَ أَنَا أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ بَابَيْهِ عَنْ جُبَيْرِ بْنِ مُطْعِمٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ عَطَاءٍ هَذَا يَا بَنِي عَبْدِ مَنَافٍ وَيَا بَنِي عَبْدِ الْمُطَّلِبِ إِنْ كَانَ لَكُمْ مِنْ الْأَمْرِ شَيْءٌ فَلَأَعْرِفَنَّ مَا مَنَعْتُمْ أَحَدًا يَطُوفُ بِهَذَا الْبَيْتِ أَيَّ سَاعَةٍ مِنْ لَيْلٍ أَوْ نَهَارٍ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin 'Amr] berkata; telah memberitakan kepada kami [Ibnu Juraij] berkata; telah memberitakan kepada kami [Abu Az Zubair] sesungguhnya telah mendengar [Abdullah bin Babaih] dari [Jubair bin Muth'im] dari Nabi Shallallahu'alaihiwasallam, sebaik-baik pemberian adalah ini, Wahai Bani Abdu Manaf, Wahai Bani Abdul Muthalib. Jika kalian pada masalah ini ada sesuatu, maka pasti saya akan mengetahuinya. kalian tidak pernah melarang seseorangpun yang thawaf di ka'bah ini kapan saja baik malam ataupun siang."},"1288":{"ar":"قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ الْبُلْدَانِ شَرٌّ قَالَ فَقَالَ لَا أَدْرِي فَلَمَّا أَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام قَالَ يَا جِبْرِيلُ أَيُّ الْبُلْدَانِ شَرٌّ قَالَ لَا أَدْرِي حَتَّى أَسْأَلَ رَبِّي عَزَّ وَجَلَّ فَانْطَلَقَ جِبْرِيلُ عَلَيْهِ السَّلَام ثُمَّ مَكَثَ مَا شَاءَ اللَّهُ أَنْ يَمْكُثَ ثُمَّ جَاءَ فَقَالَ يَا مُحَمَّدُ إِنَّكَ سَأَلْتَنِي أَيُّ الْبُلْدَانِ شَرٌّ فَقُلْتُ لَا أَدْرِي وَإِنِّي سَأَلْتُ رَبِّي عَزَّ وَجَلَّ أَيُّ الْبُلْدَانِ شَرٌّ فَقَالَ أَسْوَاقُهَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah bin 'Aqil] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] sesungguhnya seorang laki-laki menemui Nabi Shallallahu'alaihiwasallam lalu bertanya, \"Wahai Rasulullah, bagian negeri mana yang paling jelek?\" (Muth'im radliyallahu'anhu) berkata; beliau menjawab, saya tidak tahu. Tatkala Jibril alaihissalam menemuinya, beliau bersabda: \"Wahai Jibril, bagian negeri mana yang paling jelek?\" dia menjawab, saya tidak tahu hingga saya akan menanyakan kepada Rabbku Azzawajalla. Lalu Jibril alaihissalam pergi dan menetap selama beberapa waktu lalu datang dan berkata; \"Wahai Muhammad, Sesungguhnya kamu menanyakan kepadaku tentang bagian negeri mana yang paling jelek?\" lalu saya menjawab, tidak tahu, lantas saya menanyakan kepada Rabbku Azzawajalla tentang hal itu, dan Dia (Allah Azzawajalla) menjawab lokasi paling jelek adalah pasar (tempat berjualan)."},"1289":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ وَعَفَّانُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ قَالَ مَنْ يَكْلَؤُنَا اللَّيْلَةَ لَا نَرْقُدُ عَنْ صَلَاةِ الْفَجْرِ فَقَالَ بِلَالٌ أَنَا فَاسْتَقْبَلَ مَطْلَعَ الشَّمْسِ فَضُرِبَ عَلَى آذَانِهِمْ فَمَا أَيْقَظَهُمْ إِلَّا حَرُّ الشَّمْسِ فَقَامُوا فَأَدَّوْهَا ثُمَّ تَوَضَّئُوا فَأَذَّنَ بِلَالٌ فَصَلَّوْا الرَّكْعَتَيْنِ ثُمَّ صَلَّوْا الْفَجْرَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdushshamad] dan ['Affan] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari ['Amr bin Dinar] dari [Nafi' bin Jubair bin Muth'im] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam dalam suatu perjalanan, lantas bersabda: \"Siapa yang akan menjaga kami pada malam ini sehingga kami tidak ketiduran dan ketinggalan shalat subuh?\" Lalu Bilal berkata; 'Saya.' Lalu dia bangun namun matahari telah terbit. Telinga-telinga mereka tidak mendengar suara apa-apa. Tidak ada yang membangunkan mereka kecuali panas sinar matahari, lalu mereka bangun, melaksanakan shalat. Mereka berwudlu, lalu Bilal melantunkan adzan, lalu mereka shalat dua rekaat lalu shalat fajar."},"1290":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ اللَّهُ عَزَّ وَجَلَّ كُلَّ لَيْلَةٍ إِلَى سَمَاءِ الدُّنْيَا فَيَقُولُ هَلْ مِنْ سَائِلٍ فَأُعْطِيَهُ هَلْ مِنْ مُسْتَغْفِرٍ فَأَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] berkata; telah menceritakan kepada kami ['Amr bin Dinar] dari [Nafi' bin Jubair bin Muth'im] dari [Bapaknya] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Allah Azzawajalla turun setiap malam ke langit dunia lalu berfirman, 'Adakah orang yang meminta lalu Aku memberinya, adakah orang yang meminta ampun lalu Aku mengampuninya?.\""},"1291":{"ar":"قَالَ حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ عَنْ جُبَيْرِ بْنِ مُطْعِمٍ قَالَتَذَاكَرْنَا غُسْلَ الْجَنَابَةِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَنَا فَآخُذُ مِلْءَ كَفِّي ثَلَاثًا فَأَصُبُّ عَلَى رَأْسِي ثُمَّ أُفِيضُ بَعْدُ عَلَى سَائِرِ جَسَدِي","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Hujain bin Al Mutsanna] berkata; telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Sulaiman bin Shurd] dari [Jubair bin Muth'im] berkata; kami saling memperbincangkan tentang mandi janabah di sisi Nabi Shallallahu'alaihiwasallam, lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Saya mengambil dua telapak tangan, tiga kali lalu saya siramkan pada kepalaku, kemudian saya tuangkan setelahnya pada semua tubuhku.\""},"1292":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَانْشَقَّ الْقَمَرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَارَ فِرْقَتَيْنِ فِرْقَةً عَلَى هَذَا الْجَبَلِ وَفِرْقَةً عَلَى هَذَا الْجَبَلِ فَقَالُوا سَحَرَنَا مُحَمَّدٌ فَقَالُوا إِنْ كَانَ سَحَرَنَا فَإِنَّهُ لَا يَسْتَطِيعُ أَنْ يَسْحَرَ النَّاسَ كُلَّهُمْ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Katsir] berkata; telah menceritakan kepada kami [Sulaiman bin Katsir] dari [Hushain bin Abdurrahman] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] berkata; Bulan terbelah pada masa Rasulullah Shallallahu'alaihiwasallam menjadi dua bagian, satu bagian di atas gunung ini dan satu bagian lagi pada gunung itu. Mereka berkata; \"Muhammad telah menyihir kita\". Mereka juga berkata; \"Jika dia telah menyihir kita, namun niscaya dia tidak akan bisa menyihir manusia semuanya.\""},"1293":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا سَعِيدُ بْنُ إِيَاسٍ الْجُرَيْرِيُّ عَنْ قَيْسِ بْنِ عَبَايَةَ عَنِ ابْنِ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ يَزِيدَ بْنِ عَبْدِ اللَّهِ قَالَسَمِعَنِي أَبِي وَأَنَا أَقُولُ{ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ }فَقَالَ أَيْ بُنَيَّ إِيَّاكَ قَالَ وَلَمْ أَرَ أَحَدًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَبْغَضَ إِلَيْهِ حَدَثًا فِي الْإِسْلَامِ مِنْهُ فَإِنِّي قَدْ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ أَبِي بَكْرٍ وَعُمَرَ وَمَعَ عُثْمَانَ فَلَمْ أَسْمَعْ أَحَدًا مِنْهُمْ يَقُولُهَا فَلَا تَقُلْهَا إِذَا أَنْتَ قَرَأْتَ فَقُلْ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Isma'il] berkata; telah menceritakan kepada kami [Sa'id bin Iyas Al Jurairi] dari [Qais bin Abayah] dari [Ibnu Abdullah bin Mughaffal, Yazid bin Abdullah] berkata; [bapakku] telah mendengarku membaca, BISMILLAHIRRAHMAANIRRAHIIM ketika shalat, Lalu dia berkata; \"Wahai anakku, jangan kau lakukan begitu, --dan saya tidak pernah melihat seorang pun dari kalangan sahabat Nabi Shallallahu'alaihiwasallam yang lebih marah terhadap bid'ah dalam Islam daripadanya--. Sesungguhnya saya pernah shalat bersama Rasulullah Shallallahu'alaihiwasallam, Abu Bakar, 'Umar dan 'Utsman, saya tidak pernah mendengar seorang pun dari mereka mengawalmulai shalat dengan bacaan itu (Bismillaahirrahmaanirrahiim), janganlah kau basmalah itu untuk mengawalmulai shalat. Jika kamu membacanya, maka bacalah, ALHAMDU LILLAHI RABBIL 'ALAMIN.\""},"1294":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنَا يُونُسُ عَنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنَّ الْكِلَابَ أُمَّةٌ مِنْ الْأُمَمِ لَأَمَرْتُ بِقَتْلِهَا فَاقْتُلُوا مِنْهَا الْأَسْوَدَ الْبَهِيمَ وَأَيُّمَا قَوْمٍ اتَّخَذُوا كَلْبًا لَيْسَ بِكَلْبِ حَرْثٍ أَوْ صَيْدٍ أَوْ مَاشِيَةٍ نَقَصُوا مِنْ أُجُورِهِمْ كُلَّ يَوْمٍ قِيرَاطًا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Isma'il] berkata; telah mengabarkan kepada kami [Yunus] dari Al [Hasan] dari [Abdullah bin Mughaffal] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Seandainya anjing bukanlah termasuk sekelompok mahluk dari mahluk yang ada, niscaya saya menyuruh untuk membunuhnya, bunuhlah yang berwarna hitam pekat. Siapa pun yang mengambil anjing bukan anjing yang untuk jaga atau berburu atau untuk ternaknya maka pahalanya akan berkurang setiap hari satu qirat.\" "},"1295":{"ar":"قَالَوَكُنَّا نُؤْمَرُ أَنْ نُصَلِّيَ فِي مَرَابِضِ الْغَنَمِ وَلَا نُصَلِّيَ فِي أَعْطَانِ الْإِبِلِ فَإِنَّهَا خُلِقَتْ مِنْ الشَّيَاطِينِ","id":"[Abdullah bin Mughaffal Radliyallahu'anhu] berkata; kami diperintahkan untuk shalat di kandang kambing dan tidak diperkenankan shalat pada kandang unta karena diciptakan dari setan."},"1296":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا كَهْمَ��ٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنِ ابْنِ مُغَفَّلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ لِمَنْ شَاءَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepada kami [Kahmas] berkata; telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Ibnu Mughaffal] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Setiap waktu antara dua adzan adalah ada shalat bagi siapa yang menghendakinya.\""},"1297":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَبَهْزٌ قَالَا حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ قَالَ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُغَفَّلٍقَالَ قَالَ دُلِّيَ جِرَابٌ مِنْ شَحْمٍ يَوْمَ خَيْبَرَ قَالَ فَالْتَزَمْتُهُ قُلْتُ لَا أُعْطِي أَحَدًا مِنْهُ شَيْئًا قَالَ فَالْتَفَتُّ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ قَالَ بَهْزٌ إِلَيَّ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dan [Bahz] berkata; telah menceritakan kepada kami [Sulaiman bin Al Mughirah] berkata; telah menceritakan kepada kami [Humaid bin Hilal] berkata; telah menceritakan kepada kami [Abdullah bin Mughaffal] berkata; diturunkan sebuah wadah berisi lemak para Perang Khaibar. (Abdullah bin Mughaffal radliyallahu'anhu) berkata; lalu saya menjaganya, lalu saya katakan saya tidak akan memberikannya sedikit pun kepada seorangpun. (Abdullah bin Mughaffal radliyallahu'anhu) berkata; lalu saya menoleh, ternyata Rasulullah Shallallahu'alaihiwasallam tersenyum. Bahz berkata kepadaku."},"1298":{"ar":"قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ سَمِعْتُ الْحَسَنَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّرَجُّلِ إِلَّا غِبًّا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata; saya telah mendengar [Al Hasan] dari [Abdullah bin Mughaffal Al Muzani], sesungguhnya Nabi Shallallahu'alaihiwasallam melarang seseorang menyisir rambut kecuali secara berkala."},"1299":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنِي كَهْمَسٌ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنِ ابْنِ مُغَفَّلٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَذْفِ وَقَالَ إِنَّهَا لَا يُنْكَأُ بِهَا عَدُوٌّ وَلَا يُصَادُ بِهَا صَيْدٌ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Kahmas] dari [Abdullah bin Buraidah] dari [Ibnu Mughaffal] berkata; Rasulullah Shallallahu'alaihiwasallam melarang pelemparan dengan menggunakan kerikil kecil dan bersabda: \"Yang demikian karena tidak bisa membunuh musuh dan tidak bisa melukai hewan buruan.\""},"1300":{"ar":"قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنِ فُضَيْلِ بْنِ زَيْدٍ الرَّقَاشِيِّ قَالَكُنَّا عِنْدَ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ فَتَذَاكَرْنَا الشَّرَابَ فَقَالَ الْخَمْرُ حَرَامٌ قُلْتُ لَهُ الْخَمْرُ حَرَامٌ فِي كِتَابِ اللَّهِ عَزَّ وَجَلَّ قَالَ إِيشْ تُرِيدُ تُرِيدُ مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِقَالَ قُلْتُ مَا الْحَنْتَمُ قَالَ كُلُّ خَضْرَاءَ وَبَيْضَاءَ قَالَ قُلْتُ مَا الْمُزَفَّتُ قَالَ كُلُّ مُقَيَّرٍ مِنْ زِقٍّ أَوْ غَيْرِهِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Yunus bin Muhammad] berkata; telah menceritakan kepada kami [Abdul Wahid] berkata; telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Fudlail bin Zaid Ar Raqasyi] berkata; kami sedang berada pada [Abdullah bin Mughaffal] lalu kami memperbincangkan tentang minuman. Lalu dia berkata 'Arak adalah haram', lalu saya bertanya kepadanya, 'Apakah arak haram dalam kitab Allah Azzawajalla?. Dia berkata; kamu mau tahu, kamu mau tahu, apa yang telah saya dengar dari Rasulullah Shallallahu'alaihiwasallam. Saya telah mendengar Rasulullah Shallallahu'alaihiwasallam melarang ad-duba`(bejana yang terbuat dari buah sejenis labu untuk mengoplos anggur), hantam (bejana yang terbuat dari tanah, rambut dan darah untuk mengoplos anggur) dan Al muzaffat. Saya bertanya, apakah hantam itu? Dia menjawab, semua yang berwarna hijau dan putih. Saya bertanya, apakah Al muzaffat)? Dia menjawab, semua bejana yang yang terukir dengan cat atau ter ataupun yang lainnya untuk mengoplos anggur."},"1301":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الْأَعْلَى قَالَا حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقْطَعُ الصَّلَاةَ الْمَرْأَةُ وَالْكَلْبُ وَالْحِمَارُ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdul `A'la] berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Abdullah bin Mughaffal] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Yang dapat memutus shalat adalah wanita, anjing dan keledai.\""},"1302":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا الْمُبَارَكُ عَنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَبِعَ جِنَازَةً حَتَّى يُصَلِّيَ عَلَيْهَا فَلَهُ قِيرَاطٌ وَمَنْ انْتَظَرَهَا حَتَّى يُفْرَغَ مِنْهَا فَلَهُ قِيرَاطَانِ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Al Mubarak] dari [Al Hasan] dari [Abdullah bin Mughaffal] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang mengiringi jenazah sampai dishalatinya, maka dia mendapatkan satu qirath dan barangsiapa yang menunggunya sampai selesai maka dia mendapatkan dua qirath.\""},"1303":{"ar":"قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنِي أُسَامَةُ بْنُ زَيْدٍ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَزْهَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُ النَّاسَ يَوْمَ حُنَيْنٍ يَسْأَلُ عَنْ مَنْزِلِ خَالِدِ بْنِ الْوَلِيدِ فَأُتِيَ بِسَكْرَانَ فَأَمَرَ مَنْ كَانَ مَعَهُ أَنْ يَضْرِبُوهُ بِمَا كَانَ فِي أَيْدِيهِمْ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] berkata; telah menceritakan kepadaku [Usamah bin Zaid] berkata; telah menceritakan kepadaku [Az Zuhri] dari [Abdurrahman bin Azhar] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam berada di tengah-tengah orang-orang pada Perang Hunain untuk mencari rumah Khalid bin Al Walid. Tiba-tiba dibawa ke hadapan beliau seorang pemabuk, dan beliau menyuruh para sahabat yang bersamanya untuk mencambuk dengan peralatan seadanya yang mereka bawa."},"1304":{"ar":"قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنِ الزُّهْرِيِّ أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ أَزْهَرَ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَاةَ يَوْمِ الْفَتْحِ وَأَنَا غُلَامٌ شَابٌّ يَتَخَلَّلُ النَّاسَ يَسْأَلُ عَنْ مَنْزِلِ خَالِدِ بْنِ الْوَلِيدِ فَأُتِيَ بِشَارِبٍ فَأَمَرَهُمْ فَضَرَبُوهُ بِمَا فِي أَيْدِيهِمْ فَمِنْهُمْ مَنْ ضَرَبَهُ بِعَصًا وَمِنْهُمْ مَنْ ضَرَبَهُ بِسَوْطٍ وَحَثَى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التُّرَابَ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami ['Utsman bin 'Umar] berkata; telah menceritakan kepada kami [Usamah Zaid] dari [Az Zuhri] sesungguhnya telah mendengar [Abdurrahman bin Al Azhar] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam pada saat Fathu Makkah, waktu itu masih sangat muda, beliau berada di tengah-tengah mereka untuk mencari rumah Khalid bin Al Walid. Tiba-tiba dibawa ke hadapan beliau seorang peminum, lalu beliau menyuruh agar dia di cambuk. Mereka mencambuknya dengan peralatan yang berada di tangan mereka. Diantara mereka ada yang mencambuk dengan tongkat, ada yang mencambuknya dengan cemeti sedangkan Rasulullah Shallallahu'alaihiwasallam mengambil tanah dengan kedua telapak tangannya."},"1305":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ قَالَ وَكَانَ عَبْدُ الرَّحْمَنِ بْنُ الْأَزْهَرِ يُحَدِّثُأَنَّ خَالِدَ بْنَ الْوَلِيدِ بْنِ الْمُغِيرَةِ جُرِحَ يَوْمَئِذٍ وَكَانَ عَلَى الْخَيْلِ خَيْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ الْأَزْهَرِ قَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَمَا هَزَمَ اللَّهُ الْكُفَّارَ وَرَجَعَ الْمُسْلِمُونَ إِلَى رِحَالِهِمْ يَمْشِي فِي الْمُسْلِمِينَ وَيَقُولُ مَنْ يَدُلُّ عَلَى رَحْلِ خَالِدِ بْنِ الْوَلِيدِ قَالَ فَمَشَيْتُ أَوْ قَالَ فَسَعَيْتُ بَيْنَ يَدَيْهِ وَأَنَا مُحْتَلِمٌ أَقُولُ مَنْ يَدُلُّ عَلَى رَحْلِ خَالِدٍ حَتَّى حَلَلْنَا عَلَى رَحْلِهِ فَإِذَا خَالِدُ بْنُ الْوَلِيدِ مُسْتَنِدٌ إِلَى مُؤْخِرَةِ رَحْلِهِ فَأَتَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى جُرْحِهِ قَالَ الزُّهْرِيُّ وَحَسِبْتُ أَنَّهُ قَالَ وَنَفَثَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَآخِرُ مُسْنَدِ الْمَكِّيِّينَ وَالْمَدَنِيِّينَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَضِيَ اللَّهُ تَعَالَى عَنْهُمْ","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Az Zuhri] berkata; dan [Abdurrahman bin Al Azhar] menceritakan sesungguhnya Khalid bin Al Walid bin Al Mughirah terluka pada hari itu, yaitu saat berada pada kuda Rasulullah Shallallahu'alaihiwasallam. Ibnu Al Azhar berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam setelah Allah mengalahkan orang-orang kafir dan kaum muslimin kembali pada kendaraan mereka, beliau berjalan di tengah-tengah kaum muslimin dan bersabda: \"Siapa yang mau menunjukkan kepada kendaraan Al Khalid bin Al Walid?.(Ibnu Al Azhar Radliyallahu'anhu) berkata; lalu saya berjalan, atau berkata; lalu saya bersegera ke hadapan beliau dan saat itu saya dalam keadaan habis mimpi basah. Saya berkata; siapa yang bisa menunjukkan kepadaku tentang kendaraan Khalid bin Al Walid, sampai kami mendapatkan pada kendaraannya, ternyata dia dalam keadaan bersandar pada kendaraannya lalu Rasulullah Shallallahu'alaihiwasallam menemuinya dan beliau melihat lukanya. [Az Zuhri] berkata; seingat saya dia berkata; lalu Rasulullah Shallallahu'alaihiwasallam memberi tiupan kepadanya."},"1306":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ وَحَدَّثَ ابْنُ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنِ ابْنِ عَبَّاسٍ أَنَّهُ أَخْبَرَهُ أَنَّ خَالِدَ بْنَ الْوَلِيدِ أَخْبَرَهُأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيْمُونَةَ بِنْتِ الْحَارِثِ وَهِيَ خَالَتُهُ فَقَدَّمَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَحْمَ ضَبٍّ جَاءَتْ بِهِ أُمُّ حُفَيْدٍ بِنْتُ الْحَارِثِ مِنْ نَجْدٍ وَكَانَتْ تَحْتَ رَجُلٍ مِنْ بَنِي جَعْفَرٍ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَأْكُلُ شَيْئًا حَتَّى يَعْلَمَ مَا هُوَ فَقَالَ بَعْضُ النِّسْوَةِ أَلَا تُخْبِرْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَأْكُلُ فَأَخْبَرْنَهُ أَنَّهُ لَحْمُ ضَبٍّ فَتَرَكَهُ فَقَالَ خَالِدٌ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَرَامٌ هُوَ قَالَ لَا وَلَكِنَّهُ طَعَامٌ لَيْسَ فِي قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ إِلَيَّ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُقَالَ ابْنُ شِهَابٍ وَحَدَّثَهُ الْأَصَمُّ يَع��نِي يَزِيدَ بْنَ الْأَصَمِّ عَنْ مَيْمُونَةَ وَكَانَ فِي حَجْرِهَا","id":"(Ahmad bin Hanbal radliyallahu'anhu) berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata; telah mengabarkan kepada kami [bapakku] dari [Shalih bin Kaisan] dan [Ibnu Syihab] menceritakan dari [Abu Umamah bin Sahal] dari [Ibnu 'Abbas] sesungguhnya dia mengabarinya, sesungguhnya [Khalid bin Walid] mengabarinya, pernah dia masuk ke dalam rumah Maimunah binti Al Harits bersama Rasulullah Shallallahu'alaihiwasallam. Dia adalah bibinya. Selanjutnya dia menyuguhkan daging biawak kepada Rasulullah Shallallahu'alaihiwasallam yang dibawa Ummu Hufaid binti Al Harits dari Najd, yang sebelumnya ditangkap oleh seorang laki-laki dari Bani ja'far. adalah Rasulullah Shallallahu'alaihiwasallam tidak pernah memakan sesuatu sehingga beliau mengetahui betul apa yang akan dimakan. Sebagian kaum wanita berkata; \"Kenapa kalian tidak mengabarkan kepada Rasulullah Shallallahu'alaihiwasallam, apa yang hendak beliau makan tersebut!\" Lalu saya berkata; \"Ini adalah biawak, \" Rasulullah Shallallahu'alaihiwasallam pun meninggalkannya. Saya Khalid berkata; \"Saya bertanya kepada Rasulullah Shallallahu'alaihiwasallam? apakah daging itu haram?. menjawab, \"Tidak, tapi saya tidak mendapatkannya di daerahku dan saya tidak menyukainya.\" Khalid berkata; \"Lalu saya mendekatinya, kemudian memakannya dan Rasulullah Shallallahu'alaihiwasallam melihatnya.\" [Ibnu Syihab] berkata; dan [Al Asham] yaitu Yazid bin Al Asham dari [Maimunah], biawak itu berada di rumahnya."},"1307":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مَالِكٌ عَنِ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ وَخَالِدِ بْنِ الْوَلِيدِأَنَّهُمَا دَخَلَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ مَيْمُونَةَ فَأُتِيَ بِضَبٍّ مَحْنُوذٍ فَأَهْوَى إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَعْضُ النِّسْوَةِ أَخْبِرُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يُرِيدُ أَنْ يَأْكُلَ فَقَالُوا هُوَ ضَبٌّ يَا رَسُولَ اللَّهِ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَقُلْتُ أَحَرَامٌ هُوَ يَا رَسُولَ اللَّهِ قَالَ لَا وَلَكِنْ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Umamah bin Sahal] dari [Abdullah bin 'Abbas] dan [Khalid bin Walid], keduanya bersama Rasulullah Shallallahu'alaihiwasallam memasuki rumah Maimunah lalu dihidangkan kepada mereka biawak yang sudah dibakar, dan Rasulullah Shallallahu'alaihiwasallam menyukainya. Lalu sebagian kaum wanita berkata; \"Tolong kabarkan kepada Rasulullah Shallallahu'alaihiwasallam, apa yang hendak beliau makan tersebut!.\" mereka berkata; \"Ini adalah biawak, Wahai Rasulullah, \" Rasulullah Shallallahu'alaihiwasallam lantas mengangkat tangannya. Saya bertanya, \"Apakah itu haram Wahai Rasulullah?\" beliau menjawab, \"Tidak, hanya saya tidak mendapatkannya pada daerahku dan saya tidak meyukainya.\" Khalid berkata; \"Lalu saya mendekatinya, kemudian memakannya sementara Rasulullah Shallallahu'alaihiwasallam melihatnya.\""},"1308":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْعَوَّامُ بْنُ حَوْشَبٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَلْقَمَةَ عَنْ خَالِدِ بْنِ الْوَلِيدِ قَالَكَانَ بَيْنِي وَبَيْنَ عَمَّارِ بْنِ يَاسِرٍ كَلَامٌ فَأَغْلَظْتُ لَهُ فِي الْقَوْلِ فَانْطَلَقَ عَمَّارٌ يَشْكُونِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ خَالِدٌ وَهُوَ يَشْكُوهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَجَعَلَ يُغْلِظُ لَهُ وَلَا يَزِيدُ إِلَّا غِلْظَةً وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاكِتٌ لَا يَتَكَلَّمُ فَبَكَى عَمَّارٌ وَقَالَ يَا رَسُولَ اللَّهِ أَلَا تَرَاهُ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ قَالَ مَنْ عَادَى عَمَّارًا عَادَاهُ اللَّهُ وَمَنْ أَبْغَضَ عَمَّارًا أَبْغَضَهُ اللَّهُقَالَ خَالِدٌ فَخَرَجْتُ فَمَا كَانَ شَيْءٌ أَحَبَّ إِلَيَّ مِنْ رِضَا عَمَّارٍ فَلَقِيتُهُ فَرَضِيَ قَالَ عَبْد اللَّهِ سَمِعْتُهُ مِنْ أَبِي مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Awwam bin Hautsab] dari [Sallamah bin Kuhail] dari ['Alqamah] dari [Khalid bin Al Walid] berkata; terjadi sebuah perdebatan antara aku dengan Amar bin Yasir sehingga saya sangat murka kepadanya. Dia juga mengadukanku kepada Nabi Shallallahu'alaihiwasallam lalu Khalid datang dan mengadukannya kepada Nabi Shallallahu'alaihiwasallam. (Khalid bin Al Walid Radliyallahu'anhu) berkata; dia bertambah marah dan Nabi Shallallahu'alaihiwasallam diam dan tidak mengucapkan sepatah kata pun, lalu 'Ammar menangis dan berkata; \"Wahai Rasulullah, bagaimana pendapatmu?\" Lalu Rasulullah Shallallahu'alaihiwasallam mengangkat kepalanya, bersabda: \"Barangsiapa memusuhi 'Ammar niscaya Allah memusuhinya. Barangsiapa membuat marah 'Ammar, Allah membuat dia marah\". Khalid berkata; saya keluar maka tidak ada yang lebih saya senangi selain kerelaan 'Ammar, lalu saya menemuinya dan dia meredlaiku. Abdullah berkata; saya mendengar dari bapakku dua kali."},"1309":{"ar":"حَدَّثَنَا عَتَّابٌ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ حَدَّثَنَا يُونُسُ عَنِ الزُّهْرِيِّ أَخْبَرَنِي أَبُو أُمَامَةَ بْنُ سَهْلِ بْنِ حُنَيْفٍ الْأَنْصَارِيُّ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ خَالِدَ بْنَ الْوَلِيدِ الَّذِي يُقَالُ لَهُ سَيْفُ اللَّهِ أَخْبَرَهُأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ وَخَالَةُ ابْنِ عَبَّاسٍ فَوَجَدَ عِنْدَهَا ضَبًّا مَحْنُوذًا قَدِمَتْ بِهِ أُخْتُهَا حُفَيْدَةُ بِنْتُ الْحَارِثِ مِنْ نَجْدٍ فَقَدَّمَتْ الضَّبَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ قَلَّمَا يُقَدِّمُ يَدَهُ لِطَعَامٍ حَتَّى يُحَدَّثَ بِهِ وَيُسَمَّى لَهُ فَأَهْوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ إِلَى الضَّبِّ فَقَالَتْ امْرَأَةٌ مِنْ النِّسْوَةِ الْحُضُورِ أَخْبِرْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَدَّمْتُنَّ إِلَيْهِ قُلْنَ هُوَ الضَّبُّ يَا رَسُولَ اللَّهِ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَنْ الضَّبِّ فَقَالَ خَالِدُ بْنُ الْوَلِيدِ أَحَرَامٌ الضَّبُّ يَا رَسُولَ اللَّهِ قَالَ لَا وَلَكِنْ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ إِلَيَّ فَلَمْ يَنْهَنِي","id":"Telah menceritakan kepada kami ['Attab] telah menceritakan kepada kami [Abdullah] yaitu Ibnu Al mubarak, telah menceritakan kepada kami [Yunus] dari [Az Zuhri] telah mengabarkan kepadaku [Abu Umamah bin Sahl bin Hunaif Al Anshari] sesungguhnya [Ibnu Abbas] mengabarinya, sesungguhnya [Khalid bin Al Walid] yang dijuluki dengan pedang Allah mengabarinya, pernah dia bersama Rasulullah Shallallahu'alaihiwasallam memasuki rumah Maimunah, salah seorang istri Nabi Shallallahu'alaihiwasallam, dia adalah bibinya dan bibi Ibnu Abbas. Lalu dia mendapatkan di sisinya biawak yang sudah disate, yang sate tersebut disuguhkan oleh saudara perempuannya, yaitu Hufaidah binti Al Harits dari Najd. Lalu dia menyuguhkan biawak kepada Rasulullah Shallallahu'alaihiwasallam dan sangat jarang beliau disajikan suatu makanan sampai beliau diberitahukan nama dan jenis makanan tersebut. Tiba-tiba beliau ingin menjulurkan tangannya kepada daging biawak tersebut. Kontan salah seorang wanita dari mereka datang dan berkata; 'Heih tolong kabarkan kepada Rasulullah Shallallahu'alaihiwasallam tentang apa yang kalian suguhkan kepada beliau.' kami berkata; \"Itu daging biawak Wahai Rasulullah?\" Rasulullah Shallallahu'alaihiwasallam bergegas mengangkat tangannya dari biawak tersebut. Lalu Khalid bin Al Walid bertanya, \"Apakah itu haram, Wahai Rasulullah?\" beliau bersabda: \"Tidak, tapi saya tidak mendapatkannya pada kaumku dan saya membencinya.\" Khalid berkata; \"Lalu saya mendekatkan kepadaku, saya memakannya dan Rasulullah Shallallahu'alaihiwasallam melihatku dan beliau tidak melarangku.\""},"1310":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ يَعْنِي الْأَبْرَشَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ سُلَيْمٍ أَبُو سَلَمَةَ عَنْ صَالِحٍ يَعْنِي ابْنَ يَحْيَى بْنِ الْمِقْدَامِ عَنْ جَدِّهِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَغَزَوْنَا مَعَ خَالِدِ بْنِ الْوَلِيدِ الصَّائِفَةَ فَقَرِمَ أَصْحَابُنَا إِلَى اللَّحْمِ فَسَأَلُونِي فَقَالُوا أَتَأْذَنُ لَنَا أَنْ نَذْبَحَ رَمْكَةً لَهُ فَدَفَعْتُهَا إِلَيْهِمْ فَحَبَلُوهَا ثُمَّ قُلْتُ مَك��انَكُمْ حَتَّى آتِيَ خَالِدًا فَأَسْأَلَهُ قَالَ فَأَتَيْتُهُ فَسَأَلْتُهُ فَقَالَ غَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ خَيْبَرَ فَأَسْرَعَ النَّاسُ فِي حَظَائِرِ يَهُودَ فَأَمَرَنِي أَنْ أُنَادِيَ الصَّلَاةُ جَامِعَةٌ وَلَا يَدْخُلُ الْجَنَّةَ إِلَّا مُسْلِمٌ ثُمَّ قَالَ أَيُّهَا النَّاسُ إِنَّكُمْ قَدْ أَسْرَعْتُمْ فِي حَظَائِرِ يَهُودَ أَلَا لَا تَحِلُّ أَمْوَالُ الْمُعَاهَدِينَ إِلَّا بِحَقِّهَا وَحَرَامٌ عَلَيْكُمْ لُحُومُ الْحُمُرِ الْأَهْلِيَّةِ وَخَيْلِهَا وَبِغَالِهَا وَكُلِّ ذِي نَابٍ مِنْ السِّبَاعِ وَكُلِّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdul Malik] telah menceritakan kepada kami [Muhammad bin Harb] yaitu Al Abrasy, berkata; telah menceritakan kepada kami [Sulaiman bin Sulaim Abu Salamah] dari [Shalih] yaitu Ibnu Yahya bin Al Miqdam dari [kakeknya, Al Miqdam bin Ma'di Kariba], berkata; kami berperang bersama [Khalid bin Al Walid] pada musim panas lalu sahabat kami kecanduan daging, lalu mereka meminta kepadaku. Mereka berkata; \"Apakah anda mengijinkan, jika kami menyembelih seekor unta yang lemah?\" Lalu saya menyerahkan kepada mereka dan mereka memerasnya lalu saya berkata; \"Tetaplah kalian berada pada tempat kalian, sampai saya mendatangi Khalid dan saya akan menanyakan.\" (Al Miqdam bin Ma'di Kariba Radliyallahu'anhu) berkata; lalu saya mendatanginya dan menanyakannnya. Dia berkata; kami berperang bersama Rasulullah Shallallahu'alaihiwasallam Perang Khaibar, lalu orang-orang bersegera dalam menyerang kandang-kandang ternak kaum Yahudi, lalu beliau menyuruhku untuk menyerukan: Tunaikanlah shalat berjama'ah, ketahuilah bahwa tidak bakalan masuk surga kecuali orang muslim, lalu bersabda: \"Wahai manusia, kalian telah bersegera dalam kandang-kandang milik orang Yahudi. Ketahuilah, sesungguhnya tidak halal harta orang yang berada dalam perjanjian kecuali sesuai haknya. Haram bagi kalian daging keledai jinak, kuda dan bighalnya, semua hewan bertaring dari hewan buas dan setiap burung yang berkuku tajam.\""},"1311":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنِي ثَوْرُ بْنُ يَزِيدَ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ خَالِدِ بْنِ الْوَلِيدِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ لُحُومِ الْخَيْلِ وَالْبِغَالِ وَالْحَمِيرِ","id":"Telah menceritakan kepada kami [Yazid bin Abdu Rabbihi] telah menceritakan kepada kami [Baqiyyah bin Al Walid] telah menceritakan kepadaku [Tsaur bin Yazid] dari [Shalih bin Yahya bin Al Miqdam bin Ma'di Karib] dari [Bapaknya] dari [kakeknya] dari [Khalid bin Al Walid] berkata; Rasulullah Shallallahu'alaihiwasallam melarang memakan daging kuda, bighal (keturunan campuran antara kuda dengan keledai) dan keledai."},"1312":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ الْخَوْلَانِيُّ حَدَّثَنَا أَبُو سَلَمَةَ الْحِمْصِيُّ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ عَنِ ابْنِ الْمِقْدَامِ عَنْ جَدِّهِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَغَزَوْتُ مَعَ خَالِدِ بْنِ الْوَلِيدِ الصَّائِفَةَ فَقَرِمَ أَصْحَابِي إِلَى اللَّحْمِ فَقَالُوا أَتَأْذَنُ لَنَا أَنْ نَذْبَحَ رَمْكَةً لَهُ قَالَ فَحَبَلُوهَا فَقُلْتُ مَكَانَكُمْ حَتَّى آتِيَ خَالِدَ بْنَ الْوَلِيدِ فَأَسْأَلَهُ عَنْ ذَلِكَ فَأَتَيْتُهُ فَأَخْبَرْتُهُ خَبَرَ أَصْحَابِي فَقَالَ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ خَيْبَرَ فَأَسْرَعَ النَّاسُ فِي حَظَائِرِ يَهُودَ فَقَالَ يَا خَالِدُ نَادِ فِي النَّاسِ أَنَّ الصَّلَاةَ جَامِعَةٌ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مُسْلِمٌ فَفَعَلْتُ فَقَامَ فِي النَّاسِ فَقَالَ يَا أَيُّهَا النَّاسُ مَا بَالُكُمْ أَسْرَعْتُمْ فِي حَظَائِرِ يَهُودَ أَلَا لَا تَحِلُّ أَمْوَالُ الْمُعَاهَدِينَ إِلَّا بِحَقِّهَا وَحَرَامٌ عَلَيْكُمْ حُمُرُ الْأَهْلِيَّةِ وَالْإِنْسِيَّةِ وَخَيْلُهَا وَبِغَالُهَا وَكُلُّ ذِي نَابٍ مِنْ السِّبَاعِ وَكُلُّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ","id":"Telah menceritakan kepada kami [Ali bin Bahr] telah menceritakan kepada kami [Muhammad bin Harb Al Khaulani] telah menceritakan kepada kami [Abu Salamah Al Himshi] dari [Shalih bin Yahya bin Al Miqdam] dari [Ibnu Al Miqdam] dari [kakeknya Al Miqdam bin Ma'di Kariba], berkata; kami berperang bersama [Khalid bin Al Walid] pada musim panas lalu sahabat kami kecanduan daging, lalu mereka berkata; \"Apakah kamu mengijinkan kepada kami, jika kami menyembelih seekor unta yang lemah?\" (Al Miqdam bin Ma'di Kariba Radliyallahu'anhu) berkata; kontan mereka memerasnya, saya berkata; \"Tetaplah kalian berada pada tempat kalian, sampai saya mendatangi Khalid dan saya akan menanyakan tentang hal itu.\" lalu saya mengabari tentang keadaan para sahabatku, lalu (Khalid bin Al Walid Radliyallahu'anhu) berkata; \"Saya berperang bersama Rasulullah Shallallahu'alaihiwasallam Perang Khaibar, lalu orang-orang bersegera dalam menyerang kandang-kandang milik orang Yahudi, \" lalu beliau menyuruhku, \"Wahai Khalid, serukanlah kepada orang-orang: 'Tunaikanlah shalat dengan berjama'ah, dan tidak akan masuk surga kecuali orang muslim\", lalu hal itu saya lakukan. Lantas beliau berdiri ditengah orang-orang dan bersabda: Wahai manusia, bagaimana kalian bisa terburu-buru dalam menyerang kandang-kandang milik orang Yahudi?. Ketahuilah, sesungguhnya tidak halal harta orang yang berada dalam perjanjian kecuali sesuai haknya. Haram bagi kalian daging keledai jinak, kuda dan bighalnya, semua hewan yang bertaring dari hewan buas dan setiap burung yang berkuku tajam.\""},"1313":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنِ أَبِي نَجِيحٍ عَنْ خَالِدِ بْنِ حَكِيمِ بْنِ حِزَامٍ قَالَتَنَاوَلَ أَبُو عُبَيْدَةَ رَجُلًا بِشَيْءٍ فَنَهَاهُ خَالِدُ بْنُ الْوَلِيدِ فَقَالَ أَغْضَبْتَ الْأَمِيرَ فَأَتَاهُ فَقَالَ إِنِّي لَمْ أُرِدْ أَنْ أُغْضِبَكَ وَلَكِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَشَدَّ النَّاسِ عَذَابًا يَوْمَ الْقِيَامَةِ أَشَدُّ النَّاسِ عَذَابًا لِلنَّاسِ فِي الدُّنْيَا","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amr bin Dinar] dari [Abu Najih] dari [Khalid bin Hakim bin Hizam] berkata; Abu 'Ubaidah memberi hukuman kepada seorang laki-laki dengan suatu hal, lalu [Khalid bin Walid] melarangnya, lalu (Abu 'Ubaidah) berkata; 'Apakah kamu memancing emosi seorang pemimpin?, lalu dia (Khalid bin Al Walid radliyallahu'anhu) menemuinya dan berkata; \"Saya tidak bermaksud menjadikan kamu marah hanya saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Orang yang paling keras siksanya pada Hari Kiamat adalah orang yang paling keras menyiksa orang ketika dia berada di di dunia'.\""},"1314":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ عَزْرَةَ بْنِ قَيْسٍ عَنْ خَالِدِ بنِ الْوَلِيدِ قَالَكَتَبَ إِلَيَّ أَمِيرُ الْمُؤْمِنِينَ حِينَ أَلْقَى الشَّامَ بَوَانِيَةً بَثْنِيَةً وَعَسَلًا وَشَكَّ عَفَّانُ مَرَّةً قَالَ حِينَ أَلْقَى الشَّامَ كَذَا وَكَذَا فَأَمَرَنِي أَنْ أَسِيرَ إِلَى الْهِنْدِ وَالْهِنْدُ فِي أَنْفُسِنَا يَوْمَئِذٍ الْبَصْرَةُ قَالَ وَأَنَا لِذَلِكَ كَارِهٌ قَالَ فَقَامَ رَجُلٌ فَقَالَ لِي يَا أَبَا سُلَيْمَانَ اتَّقِ اللَّهَ فَإِنَّ الْفِتَنَ قَدْ ظَهَرَتْ قَالَ فَقَالَ وَابْنُ الْخَطَّابِ حَيٌّ إِنَّمَا تَكُونُ بَعْدَهُ وَالنَّاسُ بِذِي بِلِّيَانَ وَذِي بِلِّيَانَ بِمَكَانِ كَذَا وَكَذَا فَيَنْظُرُ الرَّجُلُ فَيَتَفَكَّرُ هَلْ يَجِدُ مَكَانًا لَمْ يَنْزِلْ بِهِ مِثْلُ مَا نَزَلَ بِمَكَانِهِ الَّذِي هُوَ فِيهِ مِنْ الْفِتْنَةِ وَالشَّرِّ فَلَا يَجِدُهُ قَالَ وَتِلْكَ الْأَيَّامُ الَّتِي ذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ يَدَيْ السَّاعَةِ أَيَّامُ الْهَرْجِ فَنَعُوذُ بِاللَّهِ أَنْ تُدْرِكَنَا وَإِيَّاكُمْ تِلْكَ الْأَيَّامُ","id":"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Abu Awanah] dari ['Ashim] dari [Abu Wail] dari ['Azrah bin Qais] dari [Khalid bin Al Walid] berkata; Amirul mukminin berkirim surat kepadaku ketika negeri Syam mendatangkan produksi-produksi pertaniannya, alias dimasa-masa kesuburannya, atau saat menghasilkan produksi madunya, -- ['Affan] ragu kepastian redaksinya hingga terkadang dia berkata; 'Ketika Syam menghasilkan ini dan itu--, lalu dia (Amirul Mukmin) menyuruhku untuk pergi menuju India, sedang India yang dimaksud menurut kami saat itu adalah Basrah. (Khalid bin Al Walid radliyallahu'anhu) berkata; padahal saya sangat membenci negeri itu. Lalu ada seorang laki-laki berkata kepadaku, \"Wahai Abu Sulaiman, bertakwalah kepada Allah. Fitnah-fitnah telah muncul\". (Khalid bin Al Walid radliyallahu'anhu) berkata; lalu dia berkata; sedangkan Ibnu Al Khattab saat itu masih hidup, dan hal itu terjadi setelahnya. Sedang orang-orang berada pada Dzil Baliyyan, dan Dzil Baliyan adalah di tempat ini dan itu. Lalu ada seorang laki-laki mengamati-amati dan berfikir, apakah dia mendapatkan suatu tempat yang dia singgahi pada saat adanya fitnah dan kejelekan namun tidak juga ia mendapatkannya?. (Khalid bin Al Walid radliyallahu'anhu) berkata; \"Itu adalah hari-hari yang telah disebutkan Rasulullah Shallallahu'alaihiwasallam tentang tanda-tanda Hari Kiamat yaitu hari pembunuhan, lalu kami berlindung kepada Allah jika kami sampai mendapatinya dan jangan sampai kalian menjumpai hari itu\"."},"1315":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ يُحَدِّثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنِ الْأَشْتَرِ قَالَكَانَ بَيْنَ عَمَّارٍ وَبَيْنَ خَالِدِ بْنِ الْوَلِيدِ كَلَامٌ فَشَكَاهُ عَمَّارٌ إِلَى رَسُولِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ مَنْ يُعَادِ عَمَّارًا يُعَادِهِ اللَّهُ عَزَّ وَجَلَّ وَمَنْ يُبْغِضْهُ يُبْغِضْهُ اللَّهُ عَزَّ وَجَلَّ وَمَنْ يَسُبَّهُ يَسُبَّهُ اللَّهُ عَزَّ وَجَلَّفَقَالَ سَلَمَةُ هَذَا أَوْ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] berkata; saya telah mendengar [Muhammad bin Abdurrahman] menceritakan dari [Abdurrahman bin Yazid] dari [Al Asytar] berkata; antara Amar dan Khalid bin Al Walid pernah terjadi sebuah perdebatan. Lalu 'Ammar mengadukannya kepada Rasulullah Shallallahu'alaihiwasallam, dan beliau bersabda: \"Barangsiapa memusuhi 'Ammar, niscaya Allah Azzawajalla memusuhinya. Barangsiapa membuat marah 'Ammar, Allah Azzawajalla akan membuat dia marah. Barangsiapa yang mencelanya niscaya Allah Azzawajalla akan mencelanya\". Lalu Salamah berkata; demikian atau semisalnya."},"1316":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ بْنُ عَمْرٍو قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ وَخَالِدِ بْنِ الْوَلِيدِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُخَمِّسْ السَّلَبَ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan bin 'Amr] berkata; telah menceritakan kepadaku [Abdurrahman bin Jubair bin Nufair] dari [Bapaknya] dari [Auf bin Malik Al Asyja'i] dan [Khalid bin Al Walid] sesungguhnya Nabi Shallallahu'alaihiwasallam tidak menjadikan perhiasan dan harta orang yang terbunuh bagian dari khumus. "},"1317":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَاسْتَعْمَلَ عُمَرُ بْنُ الْخَطَّابِ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ عَلَى الشَّامِ وَعَزَلَ خَالِدَ بْنَ الْوَلِيدِ قَالَ فَقَالَ خَالِدُ بْنُ الْوَلِيدِ بُعِثَ عَلَيْكُمْ أَمِينُ هَذِهِ الْأُمَّةِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَمِينُ هَذِهِ الْأُمَّةِ أَبُو عُبَيْدةَ بْنُ الْجَرَّاحِ قَالَ أَبُو عُبَيْدَةَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَالِدٌ سَيْفٌ مِنْ سُيُوفِ اللَّهِ عَزَّ وَجَلَّ وَنِعْمَ فَتَى الْعَشِيرَةِ","id":"Telah menceritakan kepada kami [Husain bin 'Ali Al Ja'fi] dari [Za`idah] dari [Abdul Malik bin 'Umair] berkata; 'Umar bin Khattab pernah mengangkat Abu 'Ubaidah Ibnu Jarah untuk menjadi pejabat di Syam dan menghentikan [Khalid bin Al Walid]. (Abdul Malik bin 'Umair Radliyallahu'anhu) berkata; lalu Khalid bin Al Walid berkata; \"Telah diutus kepada kalian orang kepercayaan umat ini. Saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Orang kepercayaan umat ini adalah Abu 'Ubaidah Ibnu Jarrah'.\" [Abu 'Ubaidah] berkata; \"Saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Khalid adalah salah satu pedang daripada pedang-pedang Allah Azzawajalla dan sebaik-baik pemuda sebuah kaum.\""},"1318":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا حَرِيزٌ عَنْ يَزِيدَ بْنِ صُلَيْحٍ عَنْ ذِي مِخْمَرٍ وَكَانَ رَجُلًا مِنْ الْحَبَشَةِ يَخْدُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكُنَّا مَعَهُ فِي سَفَرٍ فَأَسْرَعَ السَّيْرَ حِينَ انْصَرَفَ وَكَانَ يَفْعَلُ ذَلِكَ لِقِلَّةِ الزَّادِ فَقَالَ لَهُ قَائِلٌ يَا رَسُولَ اللَّهِ قَدْ انْقَطَعَ النَّاسُ وَرَاءَكَ فَحَبَسَ وَحَبَسَ النَّاسُ مَعَهُ حَتَّى تَكَامَلُوا إِلَيْهِ فَقَالَ لَهُمْ هَلْ لَكُمْ أَنْ نَهْجَعَ هَجْعَةً أَوْ قَالَ لَهُ قَائِلٌ فَنَزَلَ وَنَزَلُوا فَقَالَ مَنْ يَكْلَؤُنَا اللَّيْلَةَ فَقُلْتُ أَنَا جَعَلَنِي اللَّهُ فِدَاءَكَ فَأَعْطَانِي خِطَامَ نَاقَتِهِ فَقَالَ هَاكَ لَا تَكُونُنَّ لُكَعَ قَالَ فَأَخَذْتُ بِخِطَامِ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِخِطَامِ نَاقَتِي فَتَنَحَّيْتُ غَيْرَ بَعِيدٍ فَخَلَّيْتُ سَبِيلَهُمَا يَرْعَيَانِ فَإِنِّي كَذَاكَ أَنْظُرُ إِلَيْهِمَا حَتَّى أَخَذَنِي النَّوْمُ فَلَمْ أَشْعُرْ بِشَيْءٍ حَتَّى وَجَدْتُ حَرَّ الشَّمْسِ عَلَى وَجْهِي فَاسْتَيْقَظْتُ فَنَظَرْتُ يَمِينًا وَشِمَالًا فَإِذَا أَنَا بِالرَّاحِلَتَيْنِ مِنِّي غَيْرُ بَعِيدٍ فَأَخَذْتُ بِخِطَامِ نَاقَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِخِطَامِ نَاقَتِي فَأَتَيْتُ أَدْنَى الْقَوْمِ فَأَيْقَظْتُهُ فَقُلْتُ لَهُ أَصَلَّيْتُمْ قَالَ لَا فَأَيْقَظَ النَّاسُ بَعْضُهُمْ بَعْضًا حَتَّى اسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا بِلَالُ هَلْ لِي فِي الْمِيضَأَةِ يَعْنِي الْإِدَاوَةَ قَالَ نَعَمْ جَعَلَنِي اللَّهُ فِدَاءَكَ فَأَتَاهُ بِوَضُوءٍ فَتَوَضَّأَ لَمْ يَلُتَّ مِنْهُ التُّرَابَ فَأَمَرَ بِلَالًا فَأَذَّنَ ثُمَّ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الرَّكْعَتَيْنِ قَبْلَ الصُّبْحِ وَهُوَ غَيْرُ عَجِلٍ ثُمَّ أَمَرَهُ فَأَقَامَ الصَّلَاةَ فَصَلَّى وَهُوَ غَيْرُ عَجِلٍ فَقَالَ لَهُ قَائِلٌ يَا نَبِيَّ اللَّهِ أَفْرَطْنَا قَالَ لَا قَبَضَ اللَّهُ عَزَّ وَجَلَّ أَرْوَاحَنَا وَقَدْ رَدَّهَا إِلَيْنَا وَقَدْ صَلَّيْنَا","id":"Telah menceritakan kepada kami [Abu Nadlr] telah menceritakan kepada kami [Hariz] dari [Yazid bin Shulaih] dari [Dzi Mihmar], dia adalah seorang laki-laki dari Habasyah yang pernah melayani Nabi Shallallahu'alaihiwasallam. Dia berkata; \"Pernah kami bersama beliau dalam suatu perjalanan, beliau berjalan dengan cepat ketika melakukan perjalanan karena sedikitnya bekal. Lalu ada seseorang yang menegur 'Wahai Rasulullah, orang-orang telah tertinggal jauh di belakang anda' Karena teguran ini beliau menghentikan perjalanannya dan beliau ajak orang-orang menghentikan perjalanannya hingga jumlah sahabat lengkap.\" Beliau bertanya kepada mereka, \"Tidak sebaiknyakah kalian tidur malam sebentar?\" --Atau sepertinya ada seseorang yang berkata kepada beliau \"lantas beliau singgah dan mereka pun ikut singgah\", lalu beliau bertanya, \"Siapa yang hendak menjaga kami pada malam ini?\", Saya berkata; \"Saya, semoga Allah menjadikanku sebagai tebusan anda, \" lalu beliau memberikan kendali untanya kepadaku lalu bersabda: \"Ini dan janganlah kau menjadi orang yang bodoh\". (Dzi Mihmar Al Habasyi Radliyallahu'anhu) berkata; lalu saya mengambil kendali untanya dengan kendali untaku lalu saya menyingkir ke arah yang tidak terlalu jauh, lalu saya lepaskan kedua unta itu dalam keadaan bebas, dan saya terus mengawasi-awasi keduanya sampai saya ketiduran, sehingga saya bisa merasakan panasnya matahari pada wajahku, lalu saya bangun dan saya menoleh ke kanan, ke kiri ternyata saya berada di antara kedua kendaraanku yang jaraknya tidak terlalu jauh dariku. Saya mengambil unta Nabi Shallallahu'alaihiwasallam dengan untaku lalu saya datangi manusia yang terdekat denganku. Orang itu kubangunkan dan saya bertanya, \"Apakah kamu telah shalat?\" dia menjawab, \"Belum, \" lalu orang-orang saling membangunkan satu dengan yang lainnya. Sampai Nabi Shallallahu'alaihiwasallam terbangun lalu bersabda: \"Wahai Bilal, apakah ada air untuk wudlu?\" Dia menjawab, 'Iya', semoga Allah menjadikanku sebagai tawananmu, \" lalu dibawa kepada beliau air wudlu, lalu beliau berwudlu dengan tidak mencampurnya dengan tanah. Lalu beliau memerintahkan Bilal dan langsung mengumandangkan adzan, lalu Nabi Shallallahu'alaihiwasallam berdiri dan shalat dua rekaat sebelum subuh dengan tidak terburu-buru. Bilal disuruhnya mengumandangkan iqamat shalat dengan tergesa-gesa, lalu ada seorang yang berkata; \"Wahai Nabiyullah, apakah kita berarti telah menyepelekan shalat?\" Beliau menjawab, \"Tidak, karena Allah Azzawajalla telah mengambil ruh kita, dan Dialah yang akan mengembalikannya lagi, dan kita telah melakukan shalat.\""},"1319":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ ذِي مِخْمَرٍ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتُصَالِحُكُمْ الرُّومُ صُلْحًا آمِنًا ثُمَّ تَغْزُونَ وَهُمْ عَدُوًّا فَتُنْصَرُونَ وَتَسْلَمُونَ وَتَغْنَمُونَ ثُمَّ تَنْصُرُونَ الرُّومَ حَتَّى تَنْزِلُوا بِمَرْجٍ ذِي تُلُولٍ فَيَرْفَعُ رَجُلٌ مِنْ النَّصْرَانِيَّةِ صَلِيبًا فَيَقُولُ غَلَبَ الصَّلِيبُ فَيَغْضَبُ رَجُلٌ مِنْ الْمُسْلِمِينَ فَيَقُومُ إِلَيْهِ فَيَدُقُّهُ فَعِنْدَ ذَلِكَ يَغْدِرُ الرُّومُ وَيَجْمَعُونَ لِلْمَلْحَمَةِ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Al Auza'i] dari [Hassan bin 'Athiyyah] dari [Khalid bin Ma'dan] dari [Dzi Mikhmar, salah seorang sahabat Nabi Shallallahu'alaihiwasallam] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang Romawi akan membuat perjanjian kepada kalian dengan suatu perjanjian damai lalu kalian berperang sedangkan mereka adalah musuh, lalu kalian diberi pertolongan dan kalian selamat dan mendapatkan rampasan. Lalu kalian bisa mengalahkan bangsa Romawi sampai kalian di tempat yang sangat subur dan luas yaitu di Dzi Tulul, lalu ada seorang Nasrani yang mengangkat salib lalu berkata; 'Salib telah menang'. Lalu ada seorang muslim yang marah, lalu dia berdiri dan memukulnya, maka saat itu orang Romawi berkhianat dan mereka berkumpul untuk menghadapi perang besAr besaran'."},"1320":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ هُوَ الْقُرْقُسَائِيُّ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ ذِي مِخْمَرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُصَالِحُونَ الرُّومَ صُلْحًا آمِنًا وَتَغْزُونَ أَنْتُمْ وَهُمْ عَدُوًّا مِنْ وَرَائِهِمْ فَتَسْلَمُونَ وَتَغْنَمُونَ ثُمَّ تَنْزِلُونَ بِمَرْجٍ ذِي تُلُولٍ فَيَقُومُ إِلَيْهِ رَجُلٌ مِنْ الرُّومِ فَيَرْفَعُ الصَّلِيبَ وَيَقُولُ أَلَا غَلَبَ الصَّلِيبُ فَيَقُومُ إِلَيْهِ رَجُلٌ مِنْ الْمُسْلِمِينَ فَيَقْتُلُهُ فَعِنْدَ ذَلِكَ تَغْدِرُ الرُّومُ وَتَكُونُ الْمَلَاحِمُ فَيَجْتَمِعُونَ إِلَيْكُمْ فَيَأْتُونَكُمْ فِي ثَمَانِينَ غَايَةً مَعَ كُلِّ غَايَةٍ عَشْرَةُ آلَافٍ","id":"Telah menceritakan kepada kami [Muhammad bin Mu'sab] yaitu Al Qurqusa`i telah menceritakan kepada kami [Al Auza'i] dari [Hassan bin 'Athiyyah] dari [Khalid bin Ma'dan] dari [Jabir bin Nufair] dari [Dzi Mikhmar] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Kalian akan membuat perjanjian damai kepada Orang Romawi, kalian berperang sedangkan kalian dan mereka adalah sama-sama musuh, ada musuh dari belakang mereka. Lalu kalian selamat dan mendapatkan rampasan. Lalu kalian tinggal di tempat yang sangat subur dan luas di Dzi Tulul, lalu ada seorang Romawi yang berdiri dan mengangkat salib lalu berkata; 'Ketahuilah salib telah menang'. Lalu ada seorang muslim yang berdiri dan membunuhnya. Maka saat itu orang Romawi berkhianat dan terjadilah pembunuhan yang sangat dahsyat dan mereka berkumpul untuk menyerang kalian. Mereka mendatangi kalian dalam delapan puluh bendera dan di setiap bendera ada sepuluh ribu orang.\""},"1321":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا حَرِيزٌ يَعْنِي ابْنَ عُثْمَانَ الرَّحَبِيَّ قَالَ حَدَّثَنَا رَاشِدُ بْنُ سَعْدٍ الْمَقْرَائِيُّ عَنْ أَبِي حَيٍّ عَنْ ذِي مِخْمَرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ هَذَا الْأَمْرُ فِي حِمْيَرَ فَنَزَعَهُ اللَّهُ عَزَّ وَجَلَّ مِنْهُمْ فَجَعَلَهُ فِي قُرَيْشٍوَ سَ يَ عُ و دُ إِ لَ يْ هِ مْ وَكَذَا كَانَ فِي كِتَابِ أَبِي مُقَطَّعًا وَحَيْثُ حَدَّثَنَا بِهِ تَكَلَّمَ عَلَى الِاسْتِوَاءِ","id":"Telah menceritakan kepada kami [Abdul Qudus Abu Al Mughirah] berkata; telah menceritakan kepada kami [Hariz] yaitu Ibnu 'Utsman Ar Rahabi, berkata; telah menceritakan kepada kami [Rasyid bin Sa'd bin Al Maqra`i] dari [Abu Hay] dari [Dzi Mihmar] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \" Urusan kepemimpinan ini akan berada di Himyar, lantas Allah Azzawajalla mencabutnya dari mereka, lalu memindahkannya kepada orang Quraisy: WA SA YA 'U DU `I LAI HIM (selanjutnya akan kembali kepada mereka) \" demikian yang tertulis dalam kitab bapakku, redaksi s e l a n j u t n y a dalam keadaan terputus-putus, sebagaimana dia telah menceritakan kepada kami, sama ketika dia membacanya."},"1322":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ قَالَ حَدَّثَنِي مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ قَالَ حَدَّثَنِي أَبُو نَعَامَةَ السَّعْدِيُّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَخَرَجَ مُعَاوِيَةُ عَلَى حَلْقَةٍ فِي الْمَسْجِدِ فَقَالَ مَا أَجْلَسَكُمْ قَالُوا جَلَسْنَا نَذْكُرُ اللَّهَ عَزَّ وَجَلَّ قَالَ آللَّهِ مَا أَجْلَسَكُمْ إِلَّا ذَاكَ قَالُوا آللَّهِ مَا أَجْلَسَنَا إِلَّا ذَاكَ قَالَ أَمَا إِنِّي لَمْ أَسْتَحْلِفْكُمْ تُهْمَةً لَكُمْ وَمَا كَانَ أَحَدٌ بِمَنْزِلَتِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَلَّ عَنْهُ حَدِيثًا مِنِّي وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَى حَلْقَةٍ مِنْ أَصْحَابِهِ فَقَالَ مَا أَجْلَسَكُمْ قَالُوا جَلَسْنَا نَذْكُرُ اللَّهَ عَزَّ وَجَلَّ وَنَحْمَدُهُ عَلَى مَا هَدَانَا لِلْإِسْلَامِ وَمَنَّ عَلَيْنَا بِكَ قَالَ آللَّهِ مَا أَجْلَسَكُمْ إِلَّا ذَلِكَ قَالُوا آللَّهِ مَا أَجْلَسَنَا إِلَّا ذَلِكَ قَالَ أَمَا إِنِّي لَمْ أَسْتَحْلِفْكُمْ تُهْمَةً لَكُمْ وَإِنَّهُ أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام فَأَخْبَرَنِي أَنَّ اللَّهَ عَزَّ وَجَلَّ يُبَاهِي بِكُمْ الْمَلَائِكَةَ","id":"Telah menceritakan kepada kami ['Ali bin Bahr] berkata; telah menceritakan kepadaku [Marhum bin Abdul Aziz] berkata; telah menceritakan kepadaku [Abu Na'amah As-Sa'di] dari [Abu 'Utsman An-Nahdi] dari [Abu Sa'id Al Hudri] berkata; [Mu'awiyah] keluar dari sebuah halaqah di dalam masjid, lalu bertanya, \"Apakah yang membuat kalian duduk?.\" Mereka menjawab, \"Demi Allah, Kami duduk untuk mengingat Allah Azzawajalla.\" Dia bertanya, \"Apakah hanya itu sebab kalian duduk?\" Mereka menjawab, \"Ya.\" Mu'awiyah berkata; \"Maaf, saya meminta kalian bersumpah bukan karena saya ragu terhadap kalian, dan bukan pula karena kedudukanku disisi Rasulullah Shallallahu'alaihiwasallam lantas selainku lebih sedikit hadisnya daripadaku. Ketahuilah, sesungguhnya Rasulullah Shallallahu'alaihiwasallam pernah mendatangi sebuah halaqah sahabatnya, Lalu bertanya, \"Apakah yang membuat kalian duduk?\" mereka menjawab, \"Kami duduk untuk berdzikir kepada Allah Azzawajalla dan kami memuji-Nya karena petunjuk-Nya kepada Islam dan Dia telah mengaruniai kami dengan engkau.\" Beliau bersabda: Demi Allah, tidakkah kalian duduk selain karena dorongan itu?\" Mereka menjawab, \"Demi Allah, kami tidak melakukannya kecuali karena hal itu.\" Beliau bersabda: \"Ketahuilah bahwasanya saya meminta sumpah kalian bukan karena saya ragu terhadap kalian hanya Jibril Alaihissalam pernah datang kepadaku, lalu mengabariku sesungguhnya Allah Azzawajalla membanggakan kalian di hadapan para Malaikat karena perkumpulan kalian.\""},"1323":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنِي سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ مَعْبَدٍ الْجُهَنِيِّ قَالَكَانَ مُعَاوِيَةُ قَلَّمَا يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا وَيَقُولُ هَؤُلَاءِ الْكَلِمَاتِ قَلَّمَا يَدَعُهُنَّ أَوْ يُحَدِّثُ بِهِنَّ فِي الْجُمَعِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهُّ فِي الدِّينِ وَإِنَّ هَذَا الْمَالَ حُلْوٌ خَضِرٌ فَمَنْ يَأْخُذْهُ بِحَقِّهِ يُبَارَكْ لَهُ فِيهِ وَإِيَّاكُمْ وَالتَّمَادُحَ فَإِنَّهُ الذَّبْحُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Syu'bah] berkata; telah memberitakan kepadaku [Sa'ad bin Ibrahim] dari [Ma'bad Al Juhani] berkata; [Mu'awiyah] jarang menceritakan sesuatu dari Rasulullah Shallallahu'alaihiwasallam. Dan hanya beberapa kalimat berikut ini yang jarang ditinggalkannya atau kerap diceritakannya dalam perkumpulan orang, yaitu dari Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang Allah kehendaki kebaikan, niscaya Allah akan pahamkan dalam masalah agama. Harta ini sangat manis dan hijau (menyenangkan) siapa yang mengambilnya sesuai dengan haknya maka ia dapatkan berkah darinya. Janganlah kalian saling memuji karena hal itu sama halnya penyembelihan.\""},"1324":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ ابْنِ عَجْلَانَ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ حَبَّانَ عَنِ ابْنِ مُحَيْرِيزٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُبَادِرُونِي بِرُكُوعٍ وَلَا بِسُجُودٍ فَإِنَّهُ مَهْمَا أَسْبِقْكُمْ بِهِ إِذَا رَكَعْتُ تُدْرِكُونِي إِذَا رَفَعْتُ وَمَهْمَا أَسْبِقْكُمْ بِهِ إِذَا سَجَدْتُ تُدْرِكُونِي إِذَا رَفَعْتُ إِنِّي قَدْ بَدَّنْتُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Ajlan] berkata; telah mengabarkan kepadaku [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz] dari [Mu'awiyah bin Abu Sufyan] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Janganlah kalian mendahuluiku dalam rukuk dan sujud. Sebab segala ruku' yang terlebih dahulu saya lakukan sebelum kalian, kalian bisa menyusulku saat saya mengangkat rukuk. Dan segala sujud yang kulakukan sebelum kalian, bisa kalian susul ketika saya mengangkat sujud. Sesungguhnya saya telah tua.\""},"1325":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ قَالَقَالَ مُعَاوِيَةُ عَلَى الْمِنْبَرِ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهُّ فِي الدِّينِ سَمِعْتُ هَؤُلَاءِ الْكَلِمَاتِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى هَذَا الْمِنْبَرِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Usamah bin Zaid] dari [Muhammad bin Ka'Abu Bakar Al Qurazhi] berkata; [Mu'awiyah] berkata; di atas mimbar, \"Ya Allah, tidak ada yang menghalangi terhadap yang Kau beri dan tidak ada yang memberi terhadap yang Kau halangi. Tidak berguna kekayaan dan kemuliaan itu bagi pemiliknya (selain iman dan amal shalihnya), hanya dari-Mu segala kekayaan dan kemuliaan. Barangsiapa yang Allah kehendaki kebaikan kepadanya, niscaya Allah pahamkan urusan agamanya\". Saya mendengar kalimat-kalimat itu dari Rasulullah Shallallahu'alaihiwasallam dari atas mimbar."},"1326":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُجَمِّعُ بْنُ يَحْيَى عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ مُعَاوِيَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَشَهَّدُ مَعَ الْمُؤَذِّنِينَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Mujamma' bin Yahya] dari [Abu Umamah bin Sahal] dari [Mu'awiyah] sesungguhnya Nabi Shallallahu'alaihiwasallam pernah bersyahadat bersama para muadzin."},"1327":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَبَهْزٌ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ جَبَلَةَ بْنِ عَطِيَّةَ عَنِ ابْنِ مُحَيْرِيزٍ قَالَ بَهْزٌ عَبْدُ اللَّهِ بْنُ مُحَيْرِيزٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ اللَّهُ عَزَّ وَجَلَّ بِعَبْدٍ خَيْرًا يُفَقِّهُّ فِي الدِّينِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Bahz] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Jabalah bin 'Athiyyah] dengan [Ibnu Muhairiz]. [Bahz], [Abdullah bin Muhairiz] berkata; dari [Mu'awiyah bin Abu Sufyan] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika Allah Azzawajalla menghendaki pada seorang hamba itu dalam kebaikan, niscaya Allah pahamkan dia dalam urusan agamanya.\""},"1328":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ مَيْمُونٍ الْقَنَّادِ عَنْ أَبِي قِلَابَةَ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ رُكُوبِ النِّمَارِ وَعَنْ لُبْسِ الذَّهَبِ إِلَّا مُقَطَّعًا","id":"Telah menceritakan kepada kami [Isma'il] berkata; telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Maimun Al Qannad] dari [Abu Qilabah] dari [Mu'awiyah bin Abu Sufyan] sesungguhnya Rasulullah Shallallahu'alaihiwasallam melarang memakai kain yang terbuat dari macan tutul dan memakai emas kecuali yang sudah dalam keadaan potongan (dalam ukuran yang dimaafkan dalam syariat karena sangat sedikitnya misalnya dalam hiasan pedang atau kalung atau cincin bagi para wanita)."},"1329":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا حَبِيبُ بْنُ الشَّهِيدِ عَنْ أَبِي مِجْلَزٍأَنَّ مُعَاوِيَةَ دَخَلَ بَيْتًا فِيهِ ابْنُ عَامِرٍ وَابْنُ الزُّبَيْرِ فَقَامَ ابْنُ عَامِرٍ وَجَلَسَ ابْنُ الزُّبَيْرِ فَقَالَ لَهُ مُعَاوِيَةُ اجْلِسْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَرَّهُ أَنْ يَمْثُلَ لَهُ الْعِبَادُ قِيَامًا فَلْيَتَبَوَّأْ بَيْتًا فِي النَّارِ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Habib bin Asy Syahid] dari [Abu Mijlaz] sesungguhnya [Mu'awiyah] pernah memasuki suatu rumah yang di rumah itu Ibnu 'Amir dan Ibnu Az Zubair sedang berdiam, lalu Ibnu 'Amir berdiri dan Ibnu Az Zubair tetap duduk. lalu Mu'awiyah berkata kepadanya, \"Duduklah, sesungguhnya saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Barangsiapa yang dia senang jika ada seorang hamba berdiri karenanya maka bersiaplah menempati rumahnya di neraka.\""},"1330":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ مَعْبَدٍ الْجُهَنِيِّ قَالَكَانَ مُعَاوِيَةُ قَلَّمَا يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَانَ قَلَّمَا يَكَادُ أَنْ يَدَعَ يَوْمَ الْجُمُعَةِ هَؤُلَاءِ الْكَلِمَاتِ أَنْ يُحَدِّثَ بِهِنَّ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهُّ فِي الدِّينِ وَإِنَّ هَذَا الْمَالَ حُلْوٌ خَضِرٌ فَمَنْ يَأْخُذْهُ بِحَقِّهِ يُبَارَكْ لَهُ فِيهِ وَإِيَّاكُمْ وَالتَّمَادُحَ فَإِنَّهُ الذَّبْحُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dan [Hajjaj] berkata; telah mengabarkan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Ma'bad Al Juhani] berkata; [Mu'awiyah] jarang menceritakan dari Nabi Shallallahu'alaihiwasallam. (Ma'bad Al Juhani Radliyallahu'anhu) berkata; pada Hari Jumat bisa dikatakan sangat jarang dia meninggalkan kalimat-kalimat yang didengarnya dari Rasulullah Shallallahu'alaihiwasallam, beliau bersabda: \"Barangsiapa yang Allah kehendaki kebaikan padanya, niscaya Allah akan pahamkan urusan agamanya. Sesungguhnya harta ini sangat manis dan hijau (menyenangkan) siapa yang mengambilnya sesuai dengan haknya maka akan mendapatkan berkah. Janganlah kalian saling memuji karena hal itu ibarat penyembelihan.\""},"1331":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا حَرِيزٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَوْفٍ الْجُرَشِيِّ عَنْ مُعَاوِيَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمُصُّ لِسَانَهُ أَوْ قَالَ شَفَتَهُ يَعْنِي الْحَسَنَ بْنَ عَلِيٍّ صَلَوَاتُ اللَّهِ عَلَيْهِ وَإِنَّهُ لَنْ يُعَذَّبَ لِسَانٌ أَوْ شَفَتَانِ مَصَّهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Hariz] dari [Abdurrahman bin Abu Auf Al Jarasyi] dari [Mu'awiyah] berkata; saya pernah melihat Rasulullah Shallallahu'alaihiwasallam mengisap lidah atau mulut Al Hasan bin 'Ali dan sesungguhnya tidak akan disiksa lidah atau mulut yang telah dihisap oleh Rasulullah Shallallahu'alaihiwasallam."},"1332":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ تَمِيمٍ الدَّارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الدِّينَ النَّصِيحَةُ إِنَّمَا الدِّينُ النَّصِيحَةُ قَالُوا لِمَنْ يَا رَسُولَ اللَّهِ قَالَ لِلَّهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Suhail bin Abu Shalih] dari ['Atha` bin Yazid Al Laitsi] dari [Tamim Ad-Dari] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Agama itu kebaktian diri, hanyasanya agama itu adalah kebaktian diri.\" Mereka bertanya, \"Kebaktian diri kepada siapa Rasulullah?\" beliau menjawab, \"Bagi Allah, kitab-Nya, rasul-Nya, para pemimpin kaum muslimin dan mereka secara umum.\""},"1333":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ تَمِيمٍ الدَّارِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الدِّينُ النَّصِيحَةُ قِيلَ لِمَنْ قَالَ لِلَّهِ وَلِرَسُولِهِ وَلِكِتَابِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْحَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ فَذَكَرَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ إِنَّمَا الدِّينُ النَّصِيحَةُ ثَلَاثًا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] berkata; telah bercerita kepadaku [Suhail bin Abu Shalih] dari ['Atha` bin Yazid] dari [Tamim Ad-Dari] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Hanyasanya agama itu kebaktian diri.\" Ada yang bertanya, \"Bagi siapa?\" beliau menjawab, \"Bagi Allah, Rasul-Nya, kitab-Nya, para pemimpin kaum muslimin dan mereka secara umum.\" Telah menceritakan kepada kami [Abdurrazzaq] dari [Sufyan] dari [Suhail bin Abu Shalih] lalu dia menyebutkan sama dengan yang di atas kecuali dengan redaksi, \"Hanyasanya agama itu adalah kebaktian diri, \" ia ucapkan tiga kali."},"1334":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ يُوسُفَ الْأَزْرَقُ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَوْهَبٍ يُحَدِّثُ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ عَنْ تَمِيمٍ الدَّارِيِّ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُسْلِمُ عَلَى يَدَيْ الرَّجُلِ فَقَالَ هُوَ أَوْلَى النَّاسِ بِمَحْيَاهُ وَمَمَاتِهِ","id":"Telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] berkata; telah bercerita kepadaku [Abdul Aziz bin 'Umar bin Abdul Aziz] berkata; saya telah mendengar [Abdullah bin Mauhab] menceritakan kepada ['Umar bin Abdul Aziz] dari [Tamim Ad-Dari] berkata; Rasulullah Shallallahu'alaihiwasallam pernah ditanya tentang seorang laki-laki yang masuk Islam melalui perantaraan orang lain, beliau bersabda: \"Dia lebih berhak terhadap nasib hidup dan matinya.\""},"1335":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ تَمِيمٍ الدَّارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ��َالَ إِنَّ الدِّينَ النَّصِيحَةُ إِنَّ الدِّينَ النَّصِيحَةُ إِنَّ الدِّينَ النَّصِيحَةُ قَالُوا لِمَنْ يَا رَسُولَ اللَّهِ قَالَ لِلَّهِ وَلِكِتَابِهِ وَلِنَبِيِّهِ وَلِأَئِمَّةِ الْمُؤْمِنِينَ وَعَامَّتِهِمْقَالَ أَبُو عَبْد الرَّحْمَنِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ حَدَّثَنَا سُفْيَانُ قَالَ قُلْتُ لِسُهَيْلِ بْنِ أَبِي صَالِحٍ فِي حَدِيثٍ حَدَّثَنَاهُ عَمْرُو بْنُ دِينَارٍ عَنِ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِيهِ فَقَالَ سُهَيْلٌ سَمِعْتُهُ مِنْ الَّذِي سَمِعَهُ مِنْهُ أَبِي سَمِعْتُ عَطَاءَ بْنَ يَزِيدَ اللَّيْثِيَّ يُحَدِّثُ عَنْ تَمِيمٍ الدَّارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ حَدِيثِ أَبِي عَنْ ابْنِ عُيَيْنَةَ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Suhail bin Abu Shalih] dari ['Atha` bin Yazid Al Laitsi] dari [Tamim Ad-Dari] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Agama itu adalah kebaktian diri, sesungguhnya agama itu adalah kebaktian diri, agama itu adalah kebaktian diri nasehat.\" Mereka bertanya, \"Bagi siapa, Wahai Rasulullah?\" beliau menjawab, \"Bagi Allah, kitab-Nya, Nabi-Nya, para pemimpin kaum muslimin dan mereka secara umum.\" Abu Abdurrahman berkata; telah menceritakan kepada kami [Muhammad bin 'Abbad] telah menceritakan kepada kami [Sufyan] berkata; saya berkata kepada [Suhail bin Abu Shalih] pada suatu hadis, yang telah ['Amr bin Dinar] menceritakannya, dari [Al Qa'qa' bin Hakim] dari [Bapaknya] lalu [Suhail] berkata; saya telah mendengar dari orang yang bapakku juga mendengar darinya, saya mendengar ['Atha` bin Yazid Al Laitsi] menceritakan dari [Tamim Ad-Dari] dari Nabi Shallallahu'alaihiwasallam sebagaimana hadis bapakku dari Ibnu 'Uyainah"},"1336":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ قَالَ سَمِعْتُ تَمِيمًا الدَّارِيَّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا السُّنَّةُ فِي الرَّجُلِ مِنْ أَهْلِ الْكِتَابِ يُسْلِمُ عَلَى يَدَيْ رَجُلٍ مِنْ الْمُسْلِمِينَ قَالَ هُوَ أَوْلَى النَّاسِ بِمَحْيَاهُ وَمَمَاتِهِ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah bercerita kepadaku [Abdul Aziz bin 'Umar bin Abdul Aziz] dari [Abdullah bin Mauhab] berkata; saya telah mendengar [Tamim Ad-Dari] berkata; \"Saya berkata; 'Wahai Rasulullah, bagaimana menurut sunnah tentang seorang ahli Kitab yang masuk Islam melalui perantaraan salah seorang kaum muslimin', \" beliau bersabda: \"Dia lebih berhak menentukan nasib hidup dan kematiannya.\""},"1337":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنِ الْأَزْرَقِ بْنِ قَيْسٍ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَا يُحَاسَبُ بِهِ الْعَبْدُ يَوْمَ الْقِيَامَةِ صَلَاتُهُ فَإِنْ كَانَ أَتَمَّهَا كُتِبَتْ لَهُ تَامَّةً وَإِنْ لَمْ يَكُنْ أَتَمَّهَا قَالَ اللَّهُ عَزَّ وَجَلَّ انْظُرُوا هَلْ تَجِدُونَ لِعَبْدِي مِنْ تَطَوُّعٍ فَتُكْمِلُونَ بِهَا فَرِيضَتَهُ ثُمَّ الزَّكَاةُ كَذَلِكَ ثُمَّ تُؤْخَذُ الْأَعْمَالُ عَلَى حِسَابِ ذَلِكَحَدَّثَنَا حَسَنٌ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنِ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنَا حَسَنٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ تَمِيمٍ الدَّارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Musa] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Al Arzaq bin Qais] dari [Yahya bin Ya'mar] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Yang pertama kali dihisab dari seorang hamba pada Hari Kiamat adalah shalatnya. Jika dia mendirikannya secara sempurna, maka ditulis secara sempurna. Jika tidak, Allah Azzawajalla berfirman: 'Lihatlah kalian, apakah kalian mendapatkan amalan sunnah pada hamba-Ku sehingga bisa menyempurnakan shalat wajibnya?. Lalu zakatnya juga akan dihitung seperti ini, lalu semua amalnya juga akan dihisab dengan cara seperti ini?.\" Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Hammad] dari [Humaid] dari [Al Hasan] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana diatas. Telah menceritakan kepada kami [Hasan] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Daud bin Abu Hind] dari [Zurarah bin Aufa] dari [Tamim Ad-Dari] dari Nabi Shallallahu'alaihiwasallam, sama dengan hadis di atas."},"1338":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى يَعْنِي الطَّبَّاعَ قَالَ حَدَّثَنِي لَيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي الْخَلِيلُ بْنُ مُرَّةَ عَنِ الْأَزْهَرِ بْنِ عَبْدِ اللَّهِ عَنْ تَمِيمٍ الدَّارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَاحِدًا أَحَدًا صَمَدًا لَمْ يَتَّخِذْ صَاحِبَةً وَلَا وَلَدًا وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ عَشْرَ مَرَّاتٍ كُتِبَتْ لَهُ أَرْبَعُونَ أَلْفَ حَسَنَةٍ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] yaitu Ath-Thaba', berkata; telah bercerita kepadaku [Laits bin Sa'd] berkata; telah bercerita kepadaku [Al Khalil bin Murrah] dari [Al Azhar bin Abdullah] dari [Tamim Ad-Dari] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa mengatakan: 'Tidak ada illah selain Allah Yang Maha Tunggal, yang menjadi tempat bergantung, yang tidak mengambil istri atau pun anak dan tidak ada satu pun yang semisAl Nya' sebanyak sepuluh kali maka akan ditulis baginya empat puluh ribu kebaikan.\""},"1339":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنِ الْحَسَنِ عَنْ رَجُلٍ عَنْ أَبِي هُرَيْرَةَ وَدَاوُدَ عَنْ زُرَارَةَ عَنْ تَمِيمٍ الدَّارِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوَّلُ مَا يُحَاسَبُ بِهِ الْعَبْدُ يَوْمَ الْقِيَامَةِ الصَّلَاةُ فَإِنْ كَانَ أَكْمَلَهَا كُتِبَتْ لَهُ كَامِلَةً وَإِنْ لَمْ يَكُنْ أَكْمَلَهَا قَالَ لِلْمَلَائِكَةِ انْظُرُوا هَلْ تَجِدُونَ لِعَبْدِي مِنْ تَطَوُّعٍ فَأَكْمِلُوا بِهَا مَا ضَيَّعَ مِنْ فَرِيضَةٍ ثُمَّ الزَّكَاةُ ثُمَّ تُؤْخَذُ الْأَعْمَالُ عَلَى حَسَبِ ذَلِكَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Al Hasan] dari [seorang laki-laki] dari [Abu Hurairah] dan [Daud] dari [Zurarah] dari [Tamim Ad-Dari] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Yang pertama kali dihisab dari amalan seorang hamba pada Hari Kiamat adalah shalat. Jika dia melengkapinya, maka akan ditulis secara lengkap. Jika dia tidak melengkapinya, (Allah Azzawajalla) berfirman kepada para Malaikat: 'Lihatlah, apakah kalian mendapatkan amalan sunnah dari hamba-Ku? lengkapilah kewajiban yang kurang dipenuhinya dengan shalat sunnahnya! '. Lalu zakatnya juga dihitung seperti ini, lantas semua amalnya juga.\""},"1340":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ قَالَ حَدَّثَنِي شُرَحْبِيلُ بْنُ مُسْلِمٍ الْخَوْلَانِيُّأَنَّ رَوْحَ بْنَ زِنْبَاعٍ زَارَ تَمِيمًا الدَّارِيَّ فَوَجَدَهُ يُنَقِّي شَعِيرًا لِفَرَسِهِ قَالَ وَحَوْلَهُ أَهْلُهُ فَقَالَ لَهُ رَوْحٌ أَمَا كَانَ فِي هَؤُلَاءِ مَنْ يَكْفِيكَ قَالَ تَمِيمٌ بَلَى وَلَكِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ امْرِئٍ مُسْلِمٍ يُنَقِّي لِفَرَسِهِ شَعِيرًا ثُمَّ يُعَلِّقُهُ عَلَيْهِ إِلَّا كُتِبَ لَهُ بِكُلِّ حَبَّةٍ حَسَنَةٌحَدَّثَنَا الْهَيْثَمُ بْنُ خَارِجَةَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ شُرَحْبِيلَ بْنِ مُسْلِمٍ فَذَكَرَ مِثْلَ هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu Mughirah] berkata; telah menceritakan kepada kami [Isma'il bin 'Ayyasy] berkata; telah bercerita kepadaku [Syurahbil bin muslim Al Khaulani] sesungguhnya [Rauh bin Zinba'] mengujungi [Tamim Ad-Dari] maka dia mendapatinya sedang membersihkan rambut kudanya dan sekitarnya ada keluarganya, lalu [Rauh] berkata kepadanya, \"Tidaklah hal itu cukup bagi kalian?.\" [Tamim] berkata; Ya. tapi saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seorang muslim yang membersihkan rambut kudanya lalu mengikatnya kecuali akan ditulis baginya pada setiap helai satu kebaikan.\" Telah menceritakan kepada kami [Al Hutsaim bin Kharijah] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Syurahbil bin muslim] lalu menyebutkan sebagaimana hadis itu."},"1341":{"ar":"أَمْلَاهُ عَلَيْنَا مِنْ النَّوَادِرِ قَالَ كَتَبَ إِلَيَّ أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ قَالَ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ عَنْ زَيْدِ بْنِ وَاقِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ تَمِيمٍ الدَّارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ بِمِائَةِ آيَةٍ فِي لَيْلَةٍ كُتِبَ لَهُ قُنُوتُ لَيْلَةٍ","id":"Dia (Ahmad bin Hanbal Radliyallahu'anhu) telah membacakannya pada kami dari kitab Nawadir-nya berkata; [Abu Taubah Ar Rabi' bin Nafi'] menulis kepadaku, berkata; telah menceritakan kepada kami [Al Hutsaim bin Humaid] dari [Zaid bin Waqid] dari [Sulaiman bin Musa] dari [Katsir bin Murrah] dari [Tamim Ad-Dari] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang membaca seratus ayat pada satu malam maka akan ditulis baginya sebagaimana berdiri semalam.\""},"1342":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنِ ابْنِ الْمُنْكَدِرِ عَنْ أَبِي أَيُّوبَ عَنْ مَسْلَمَةَ بْنِ مُخَلَّدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَتَرَ مُسْلِمًا فِي الدُّنْيَا سَتَرَهُ اللَّهُ عَزَّ وَجَلَّ فِي الدُّنْيَا وَالْآخِرَةِ وَمَنْ نَجَّى مَكْرُوبًا فَكَّ اللَّهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ الْقِيَامَةِ وَمَنْ كَانَ فِي حَاجَةِ أَخِيهِ كَانَ اللَّهُ عَزَّ وَجَلَّ فِي حَاجَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Bakar] telah Mengabarkan kepada kami [Ibnu Juraij] dari [Ibnu Munkadir] dari [Abu Ayyub] dari [Maslamah bin Mukhallid] sesungguhnya Nabi Shallallahu'alaihiwasallam berkata; \"Barangsiapa yang menutupi seorang muslim di dunia niscaya Allah Azzawajalla akan menutupinya di di dunia dan akhirat. Barangsiapa yang menyelamatkan orang yang sedang susah dan sangat payah niscaya Allah melepaskan darinya satu kesusahan dari kesusahan Hari Kiamat. Barangsiapa yang membantu memenuhi kebutuhan saudaranya maka Allah Azzawajalla akan memenuhi kebutuhannya.\""},"1343":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ قَرَأْتُ عَلَى أَبِي هَذَا الْحَدِيثَ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ وَابْنُ أَبِي عَدِيٍّ عَنِ ابْنِ عَوْنٍ عَنْ مَكْحُولٍأَنَّ عُقْبَةَ قَالَ ابْنُ أَبِي عَدِيٍّ أَتَى مَسْلَمَةَ بْنَ مُخَلَّدٍ بِمِصْرَ وَكَانَ بَيْنَهُ وَبَيْنَ الْبَوَّابِ شَيْءٌ فَسَمِعَ صَوْتَهُ فَأَذِنَ لَهُ فَقَالَ إِنِّي لَمْ آتِكَ زَائِرًا وَلَكِنِّي جِئْتُكَ لِحَاجَةٍ أَتَذْكُرُ يَوْمَ قَالَ عَبَّادٌ فِي حَدِيثِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَلِمَ مِنْ أَخِيهِ سَيِّئَةً فَسَتَرَهَا سَتَرَهُ اللَّهُ عَزَّ وَجَلَّ بِهَا يَوْمَ الْقِيَامَةِ فَقَالَ نَعَمْ فَقَالَ لِهَذَا جِئْتُ قَالَ ابْنُ أَبِي عَدِيٍّ فِي حَدِيثِهِ رَكِبَ عُقْبَةُ بْنُ عَامِرٍ إِلَى مَسْلَمَةَ بْنِ مُخَلَّدٍ وَهُوَ أَمِيرٌ عَلَى مِصْرَ","id":"Telah menceritakan kepada kami Abdullah berkata; saya membacakan di hadapan bapakku hadis ini, telah menceritakan kepada kami ['Abbad bin 'Abbad] dari [Ibnu Abu 'Adi] dari [Ibnu 'Aun] dari [Makhul] sesungguhnya 'Uqbah berkata; Ibnu Abu 'Adi menemui [Maslamah bin Mukhallid] di Mesir, dan antara dia dengan penjaga ada pembatas, lalu dia mendengar suaranya, maka dia diijinkan lalu berkata; sesungguhnya saya tidak mendatangimu dalam rangka mengunjungi tapi saya mendatangimu karena ada suatu keperluan, \"Apakah kau ingat pada hari 'Abbad berkata dalam hadis nya, Rasulullah Shallallahu'alaihiwasallam bersabda: 'Barangsiapa yang mengetahui dari saudaranya suatu kejelekan lalu dia menutupinya, niscaya Allah Azzawajalla akan menutupinya pada Hari Kiamat'.\"Maka dia menjawab, \"Ya.\" (Ibnu Abu 'Adi RH) berkata; \"Karena hal itulah saya datang.\" [Ibnu Abu 'Adi] berkata; dalam hadis nya, \"'Uqbah bin 'Amir menuju Maslamah bin Mukhallid, waktu itu adalah seorang Amir di Mesir."},"1344":{"ar":"قَالَ حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ حَدَّثَنَا بِهِ عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ غَسَّلَ وَاغْتَسَلَ وَغَدَا وَابْتَكَرَ فَدَنَا وَأَنْصَتَ وَلَمْ يَلْغُ كَانَ لَهُ بِكُلِّ خُطْوَةٍ كَأَجْرِ سَنَةٍ صِيَامِهَا وَقِيَامِهَا","id":"[Husain bin 'Ali Al Ju'fi] berkata; telah menceritakan kepada kami dengan hadis ini, [Abdurrahman bin Yazid bin Jabir] dari [Abu Al Asy'ats Ash-Shan'ani] dari ['Aus bin 'Aus] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang berwudlu, mandi dan pergi ketika masih pagi lalu dia duduk mendekat dan diam dan dia tidak mengucapkan kalimat yang tidak ada manfaatnya maka setiap langkahnya (dicatat) sebagaimana pahala satu tahun baik puasanya maupun shalatnya.\""},"1345":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنِ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍ الثَّقَفِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ غَسَّلَ وَاغْتَسَلَ يَوْمَ الْجُمُعَةِ وَبَكَّرَ وَابْتَكَرَ وَمَشَى وَلَمْ يَرْكَبْ فَدَنَا مِنْ الْإِمَامِ وَاسْتَمَعَ وَلَمْ يَلْغُ كَانَ لَهُ بِكُلِّ خُطْوَةٍ أَجْرُ سَنَةٍ صِيَامِهَا وَقِيَامِهَاحَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنِ الْأَوْزَاعِيِّ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ حَدَّثَنَا أَبُو الْأَشْعَثِ الصَّنْعَانِيُّ قَالَ حَدَّثَنِي ابْنُ أَوْسٍ الثَّقَفِيُّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ إِلَّا أَنَّهُ قَالَ ثُمَّ غَدَا وَابْتَكَرَ","id":"Telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Ibnu Mubarak] dari [Al Auza'i] dari [Hassan bin 'Athiyyah] dari [Abu Al Asy'ats Ash-Shan'ani] dari ['Aus bin 'Aus Al Tsaqafi] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang berwudlu, mandi dan pergi ketika masih pagi lalu dia berjalan dan tidak berkendaraan, lalu dia duduk mendekati imam dan mendengarkannya, dia tidak mengucapkan kalimat yang tidak ada manfaatnya maka setiap langkahnya (dicatat) sebagaimana pahala satu tahun baik puasanya maupun shalatnya.\" Telah menceritakan kepada kami ['Ali bin Ishaq] berkata; telah menceritakan kepada kami [Ibnu Mubarak] dari [Al Auza'i] telah bercerita kepadaku [Hassan bin 'Athiyyah] telah menceritakan kepada kami [Abu Al Asy'ats Ash-Shan'ani] berkata; telah bercerita kepadaku [Ibnu 'Aus Al Tsaqafi] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam, lalu dia menyebutkan secara makna kecuali tambahan perkataan, \"Lalu dia pergi pada waktu masih pagi.\""},"1346":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا أَرْطَاةُ يَعْنِي ابْنَ الْمُنْذِرِ حَدَّثَنَا ضَمْرَةُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا سَلَمَةُ بْنُ نُفَيْلٍ السَّكُونِيُّ قَالَكُنَّا جُلُوسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ قَالَ لَهُ قَائِلٌ يَا رَسُولَ اللَّهِ هَلْ أُتِيتَ بِطَعَامٍ مِنْ السَّمَاءِ قَالَ نَعَمْ قَالَ وَبِمَاذَا قَالَ بِمِسْخَنَةٍ قَالُوا فَهَلْ كَانَ فِيهَا فَضْلٌ عَنْكَ قَالَ نَعَمْ قَالَ فَمَا فُعِلَ بِهِ قَالَ رُفِعَ وَهُوَ يُوحَى إِلَيَّ أَنِّي مَكْفُوتٌ غَيْرُ لَابِثٍ فِيكُمْ وَلَسْتُمْ لَابِثِينَ بَعْدِي إِلَّا قَلِيلًا بَلْ تَلْبَثُونَ حَتَّى تَقُولُوا مَتَى وَسَتَأْتُونَ أَفْنَادًا يُفْنِي بَعْضُكُمْ بَعْضًا وَبَيْنَ يَدَيْ السَّاعَةِ مُوتَانٌ شَدِيدٌ وَبَعْدَهُ سَنَوَاتُ الزَّلَازِلِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Arthah] yaitu Ibnu Al Mundzir, telah menceritakan kepada kami [Dlamrah bin Habib] berkata; telah menceritakan kepada kami [Salamah bin Nufail As-Sakuni] berkata; \"Kami sedang duduk di sisi Rasulullah Shallallahu'alaihiwasallam, lalu ada seorangh laki-laki yang berkata; 'Wahai Rasulullah, apakah anda diberikan makanan dari Langit?\" beliau menjawab, \"Ya.\" dia bertanya, \"Dengan apa?\" beliau menjawab, \"Dengan piring\" mereka berkata; \"Apakah itu juga termasuk kelebihan bagi anda\". Beliau menjawab, \"Ya\". Dia berkata; \"Lantas mengapa ember itu diangkat?\" Beliau menjawab, \"Ember itu diangkat, maknanya telah diwahyukan kepadaku bahwa suatu hari nanti saya pasti mati dan tidak bisa tinggal selamanya bersama kalian, Dan kalian juga tidak akan tinggal setelahku kecuali hanya sebentar. Bahkan kalian akan tinggal sampai kalian mengatakan sampai kapan kita, sampai kapan kita?. Kalian akan mendatangi kelompok yang terpecah-pecah yang satu sama lainnya saling memusnahkan. Sebelum terjadinya hari Kiamat akan ada banyak kematian yang dahsyat dan setelahnya akan terjadi keguncangan beberapa tahun.\""},"1347":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ إِبْرَاهِيمَ بْنِ سُلَيْمَانَ عَنِ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجُرَشِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ أَنَّ سَلَمَةَ بْنَ نُفَيْلٍ أَخْبَرَهُمْأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي سَئِمْتُ الْخَيْلَ وَأَلْقَيْتُ السِّلَاحَ وَوَضَعَتْ الْحَرْبُ أَوْزَارَهَا قُلْتُ لَا قِتَالَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآنَ جَاءَ الْقِتَالُ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي ظَاهِرِينَ عَلَى النَّاسِ يَرْفَعُ اللَّهُ قُلُوبَ أَقْوَامٍ فَيُقَاتِلُونَهُمْ وَيَرْزُقُهُمْ اللَّهُ مِنْهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ عَزَّ وَجَلَّ وَهُمْ عَلَى ذَلِكَ أَلَا إِنَّ عُقْرَ دَارِ الْمُؤْمِنِينَ الشَّامُ وَالْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Al Hakim bin Nafi'] berkata; telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Ibrahim bin Sulaiman] dari [Al Walid bin Abdurrahman Al Jurasyi] dari [Jubair bin Nufair] sesungguhnya [Salamah bin Nufail] mengabari mereka sesungguhnya dia mendatangi Nabi Shallallahu'alaihiwasallam lalu berkata; \"Saya telah bosan dengan kuda dan senjata telah saya buang. Peperangan telah terhenti dan saya katakan sudah tidak ada perang.\" Kontan Nabi Shallallahu'alaihiwasallam bersabda kepadanya, \"Sekarang telah datang peperangan, akan ada dari sekelompok orang dari umatku, mereka selalu menghadapi manusia yang menghalanginya, Allah akan mengangkat hati kaum (membutakan hatinya), lalu (kaum-kaum itu) memerangi mereka dan Allah memberi rizqi kepada mereka melalui kaum yang dibutakan hatinya itu sampai datang keputusan Allah Azzawajalla dan mereka tetap dalam keadaan seperti itu. Ketahuilah, sesungguhnya benteng pertahanan orang mukmin adalah Syam, dan kuda terdapat pada ubun-ubun mereka kebaikan sampai Hari Kiamat.\""},"1348":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ وَجَدْتُ فِي كِتَابِ أَبِي بِخَطِّ يَدِهِ قَالَ كَتَبَ إِلَيَّ أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ وَكَانَ فِي كِتَابِهِ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ عَنْ زَيْدِ بْنِ وَاقِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ يَزِيدَ بْنِ الْأَخْنَسِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنَافُسَ بَيْنَكُمْ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ أَعْطَاهُ اللَّهُ عَزَّ وَجَلَّ الْقُرْآنَ فَهُوَ يَقُومُ بِهِ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ وَيَتَّبِعُ مَا فِيهِ فَيَقُولُ رَجُلٌ لَوْ أَنَّ اللَّهَ تَعَالَى أَعْطَانِي مِثْلَ مَا أَعْطَى فُلَانًا فَأَقُومَ بِهِ كَمَا يَقُومُ بِهِ وَرَجُلٌ أَعْطَاهُ اللَّهُ مَالًا فَهُوَ يُنْفِقُ وَيَتَصَدَّقُ فَيَقُولُ رَجُلٌ لَوْ أَنَّ اللَّهَ أَعْطَانِي مِثْلَ مَا أَعْطَى فُلَانًا فَأَتَصَدَّقَ بِهِ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَرَأَيْتُكَ النَّجْدَةَ تَكُونُ فِي الرَّجُلِ وَسَقَطَ بَاقِي الْحَدِيثِ","id":"Telah menceritakan kepada kami Abdullah berkata; saya telah mendapatkan kitab bapakku dengan tulisan dia sendiri, berkata; [Abu Taubah Ar Rabi' bin Nafi'] dan tertulis dalam kitabnya, telah menceritakan kepada kami [Al Hutsaim bin Humaid] dari [Zaid bin Waqid] dari [Sulaiman bin Musa] dari [Katsir bin Murrah] dari [Yazid bin Al Akhnas] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada perlombaan diantara kalian kecuali dalam dua hal: Pertama, seorang laki-laki yang Allah Azzawajalla berikan kepadanya Al qur'an lalu dia menegakkan hokum-hukumnya pada malam dan siangnya dan mengikuti isinya, lalu ada seorang laki-laki yang berkata; 'seandainya Allah Ta'ala memberiku sebagaimana yang telah diberikan kepada si 'A' maka akan saya lakukan sebagaimana yang dikerjakannya'. Dan kedua, seorang laki-laki yang Allah Azzawajalla berikan kepadanya harta, lalu dia menginfakkan dan menyedekahkannya, lalu ada seorang laki-laki yang berkata; 'seandainya Allah memberiku sebagaimana yang telah diberikan kepada si 'B', saya akan menyedekahkannya.\" Lalu ada seorang laki-laki yang berkata; \"Wahai Rasulullah, bagaimana pendapat baginda tentang keberanian yang dimiliki seorang laki-laki?, \" lalu sisa hadis nya hilang."},"1349":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ يُوسُفَ بْنِ سَيْفٍ عَنْ غُضَيْفِ بْنِ الْحَارِثِ أَوْ الْحَارِثِ بْنِ غُضَيْفٍِ قَالَمَا نَسِيتُ مِنْ الْأَشْيَاءِ مَا نَسِيتُ أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا يَمِينَهُ عَلَى شِمَالِهِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Hammad bin Khalid] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Yusuf bin Saif] dari [Ghudlaif Al Harits] atau Al Harits bin Ghudlaif berkata; \"Ada beberapa hal yang tidak pernah saya lupakan, sebagaimana kelupaan saya kepada lainnya, sesungguhnya saya melihat Rasulullah Shallallahu'alaihiwasallam meletakkan tangan kanannya pada tangan kirinya dalam shalat.\""},"1350":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍ حَدَّثَنَا مُعَاوِيَةُ عَنْ يُونُسَ بْنِ سَيْفٍ عَنِ الْحَارِثِ بْنِ غُضَيْفٍ أَوْ غُضَيْفِ بْنِ الْحَارِثِ قَالَمَا نَسِيتُ مِنْ الْأَشْيَاءِ لَمْ أَنْسَ أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا يَمِينَهُ عَلَى شِمَالِهِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Mu'awiyah] dari [Yunus bin Saif] dari [Al Harits bin Ghudlaif] atau Ghudlaif Al Harits berkata; \"Beberapa hal yang tidak pernah saya lupakan, sungguh saya tak pernah melupakannya. Sesungguhnya saya melihat Rasulullah Shallallahu'alaihiwasallam meletakkan tangan kanannya pada tangan kirinya dalam shalat.\""},"1351":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ حَدَّثَنِي الْمَشْيَخَةُأَنَّهُمْ حَضَرُوا غُضَيْفَ بْنَ الْحَارِثِ الثُّمَالِيَّ حِينَ اشْتَدَّ سَوْقُهُ فَقَالَ هَلْ مِنْكُمْ أَحَدٌ يَقْرَأُ يس قَالَ فَقَرَأَهَا صَالِحُ بْنُ شُرَيْحٍ السَّكُونِيُّ فَلَمَّا بَلَغَ أَرْبَعِينَ مِنْهَا قُبِضَ قَالَ فَكَانَ الْمَشْيَخَةُ يَقُولُونَ إِذَا قُرِئَتْ عِنْدَ الْمَيِّتِ خُفِّفَ عَنْهُ بِهَاقَالَ صَفْوَانُ وَقَرَأَهَا عِيسَى بْنُ الْمُعْتَمِرِ عِنْدَ ابْنِ مَعْبَدٍ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan] telah bercerita kepadaku [beberapa orang syaikh], mereka menghadiri Ghudlaif Al Harits Ats-Tsumali tatkala kekuatan fisiknya telah melemah, lalu berkata; \"Maukah salah seorang di antara kalian membacakan surat YASIN?\" \"Lalu Shalih bin Syuraih As-Sakuni membacanya, tatkala sampai pada ayat yang ke empat puluh, Ghudlaif Alharits Ats-Tsumali wafat.\" (Shahwan radliyallahu'anhu) berkata; \"Beberapa syaikh tadi berkata; 'Jika hal itu dibacakan di sisi mayit, maka akan diringankannya.\" Shahwan berkata; 'Isa bin Al Mu'tamir membacakan di sisi Ma'bad."},"1352":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ حَبِيبِ بْنِ عُبَيْدٍ الرَّحَبِيِّ عَنْ غُضَيْفِ بْنِ الْحَا��ِثِ الثُّمَالِيِّ قَالَبَعَثَ إِلَيَّ عَبْدُ الْمَلِكِ بْنُ مَرْوَانَ فَقَالَ يَا أَبَا أَسْمَاءَ إِنَّا قَدْ أَجْمَعْنَا النَّاسَ عَلَى أَمْرَيْنِ قَالَ وَمَا هُمَا قَالَ رَفْعُ الْأَيْدِي عَلَى الْمَنَابِرِ يَوْمَ الْجُمُعَةِ وَالْقَصَصُ بَعْدَ الصُّبْحِ وَالْعَصْرِ فَقَالَ أَمَا إِنَّهُمَا أَمْثَلُ بِدْعَتِكُمْ عِنْدِي وَلَسْتُ مُجِيبَكَ إِلَى شَيْءٍ مِنْهُمَا قَالَ لِمَ قَالَ لِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَحْدَثَ قَوْمٌ بِدْعَةً إِلَّا رُفِعَ مِثْلُهَا مِنْ السُّنَّةِ فَتَمَسُّكٌ بِسُنَّةٍ خَيْرٌ مِنْ إِحْدَاثِ بِدْعَةٍ","id":"Telah menceritakan kepada kami [Suraij bin An-Nu'man] berkata; telah menceritakan kepada kami [Baqiyyah] dari [Abu Bakar bin Abdullah] dari [Habib bin 'Ubaid Ar Rahabi] dari [Ghudlaif Al Harits] berkata; Abdul Malik bin Marwan mengutus kepadaku lalu berkata; \"Wahai Abu Asma`, sesungguhnya kami telah mengumpulkan orang-orang atas dua hal, \" (Ghudlaif Al Harits radliyallahu'anhu) berkata; \"Apa dua hal itu?\" Dia menjawab, \"Mengangkat tangan di atas mimbar pada Hari Jumat dan membaca kisah setelah subuh dan asar.\" Maka (Ghudlaif Al Harits radliyallahu'anhu) berkata; \"Sesungguhnya keduanya adalah contoh bid'ah kalian menurutku, saya tidak melaksanakannya.\" Dia bertanya, \"Kenapa?\" (Ghudlaif Al Harits radliyallahu'anhu) menjawab, \"Karena Nabi Shallallahu'alaihiwasallam bersabda: 'Tidaklah sebuah kaum melakukan sebuah bid'ah kecuali pasti akan ada sunnah yang hilang. Berpegang teguh dengan sunah adalah lebih baik daripada melakukan hal yang bid'ah.\""},"1353":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا حَرِيزٌ قَالَ حَدَّثَنَا شُرَحْبِيلُ ابْنُ شُفْعَةَ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُقَالُ لِلْوِلْدَانِ يَوْمَ الْقِيَام��ةِ ادْخُلُوا الْجَنَّةَ قَالَ فَيَقُولُونَ يَا رَبِّ حَتَّى يَدْخُلَ آبَاؤُنَا وَأُمَّهَاتُنَا قَالَ فَيَأْتُونَ قَالَ فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ مَا لِي أَرَاهُمْ مُحْبَنْطِئِينَ ادْخُلُوا الْجَنَّةَ قَالَ فَيَقُولُونَ يَا رَبِّ آبَاؤُنَا وَأُمَّهَاتُنَا قَالَ فَيَقُولُ ادْخُلُوا الْجَنَّةَ أَنْتُمْ وَآبَاؤُكُمْ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Hariz] berkata; telah menceritakan kepada kami [Syurahbil Ibnu Syuf'ah] dari [beberapa sahabat Nabi Shallallahu'alaihiwasallam] sesungguhnya telah mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Pada Hari Kiamat nanti anak-anak kecil memperoleh panggilan, 'Masuklah kalian ke dalam surga', \" beliau bersabda: \"mereka berkata lagi, 'Wahai Rabku, (kami akan berdiam disini) sampai bapak-bapak dan ibu-ibu kami memasukinya' Bapak dan ibu mereka pun datang.\" Lalu beliau bersabda: \"Lantas Allah Azzawajalla berfirman, 'Kenapa saya lihat mereka tidak juga segera memasukinya, masuklah kalian ke surga!\", beliau bersabda: \"mereka berkata lagi, 'Wahai Rabku, bapak-bapak dan ibu-ibu kami? '\", beliau bersabda: \"Lalu (Allah Azzawajalla) berfirman, 'masuklah kalian dan bapak-bapak kalian'.\""},"1354":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ الرَّحَبِيُّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَامِرٍ الْأَلْهَانِيَّ قَالَدَخَلَ الْمَسْجِدَ حَابِسُ بْنُ سَعْدٍ الطَّائِيُّ مِنْ السَّحَرِ وَقَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَى النَّاسَ يُصَلُّونَ فِي مُقَدَّمِ الْمَسْجِدِ فَقَالَ مُرَاءُونَ وَرَبِّ الْكَعْبَةِ أَرْعِبُوهُمْ فَمَنْ أَرْعَبَهُمْ فَقَدْ أَطَاعَ اللَّهَ وَرَسُولَهُ فَأَتَاهُمْ النَّاسُ فَأَخْرَجُوهُمْ قَالَ فَقَالَ إِنَّ الْمَلَائِكَةَ يُصَلُّونَ مِنْ السَّحَرِ فِي مُقَدَّمِ الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Hariz bin 'Utsman Ar Rahabi] berkata; saya mendengar [Abdullah bin 'Amir Al Hani] berkata; [Habis bin Sa'd Ath-Tha`i] masuk ke masjid pada waktu sahur dan kebetulan ia temui Nabi Shallallahu'alaihiwasallam. Lalu nabi melihat orang-orang shalat di serambi masjid, lalu berkata; \"Mereka adalah orang-orang yang riya', demi Rabb Ka'bah, ancamlah mereka. Barangsiapa yang mengancam mereka maka dia taat kepada Allah dan Rasul-Nya.\" Lalu orang-orang mendatangi mereka dan mengusir mereka. (Abdullah bin 'Amir Al Hani Radliyallahu'anhu) berkata; lalu (Ruwaifi' bin Tsabit Al Anshari radliyallahu'anhu) berkata; \"Sesungguhnya para Malaikat shalat pada waktu malam menjelang subuh (waktu sahur) pada bagian serambi masjid.\""},"1355":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ عَنْ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ رَبِيعَةَ بْنِ لَقِيطٍ عَنْ عَبْدِ اللَّهِ بْنِ حَوَالَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَجَا مِنْ ثَلَاثٍ فَقَدْ نَجَا ثَلَاثَ مَرَّاتٍ مَوْتِي وَالدَّجَّالُ وَقَتْلُ خَلِيفَةٍ مُصْطَبِرٍ بِالْحَقِّ مُعْطِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] dari [Yahya bin Ayyub] berkata; telah bercerita kepadaku [Yazid bin Abu Habib] dari [Rabi'ah bin Laqith] dari [Abdullah bin Hawalah] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang selamat dari tiga hal, maka dia telah selamat tiga kali: wafatku, Dajjal dan pembunuhan seorang khalifah yang sabar mempertahankan kebenaran, dan khalifah itu telah memasrahkan kebenaran agar dituntaskan.'"},"1356":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حِمْيَرٍ الْحِمْصِيُّ قَالَ حَدَّثَنَا ثَابِتُ بْنُ عَجْلَانَ قَالَ سَمِعْتُ أَبَا كَثِيرٍ الْمُحَارِبِيَّ يَقُولُ سَمِعْتُ خَرَشَةَ بْنَ الْحُرِّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتَكُونُ مِنْ بَعْدِي فِتْنَةٌ النَّائِمُ فِيهَا خَيْرٌ مِنْ الْيَقْظَانِ وَالْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ السَّاعِي فَمَنْ أَتَتْ عَلَيْهِ فَلْيَمْشِ بِسَيْفِهِ إِلَى صَفَاةٍ فَلْيَضْرِبْهُ حَتَّى يَنْكَسِرَ ثُمَّ لِيَضْطَجِعَ لَهَا حَتَّى تَنْجَلِيَ عَمَّا انْجَلَيَتْ","id":"Telah menceritakan kepada kami [Ali bin Bahr] berkata; telah menceritakan kepada kami [Muhammad bin Himyar Al Himsyi] berkata; telah menceritakan kepada kami [Tsabit bin Ajlan] berkata; saya telah mendengar [Abu Katsir Al Muharibi] berkata; saya telah mendengar [Kharasyah bin Al Hur] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Akan ada fitnah setelahku, orang yang tidur ketika itu lebih baik dari pada orang yang terjaga. Orang yang duduk lebih baik daripada orang yang berdiri. Orang yang berdiri lebih baik daripada orang yang berjalan. Jika dia didatangi, maka berjalanlah dengan pedangnya menuju ke batu yang licin dan bantinglah pedangnya di batu sampai patah, lalu berbaringlah menghadap batu itu sampai fitnah itu tampak.\""},"1357":{"ar":"حَدَّثَنَا مُوسَى بْنُ دَاوُدَ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُحَمَّدِ بْنِ يَزِيدَ أَنَّ عَبْدَ اللَّهِ بْنَ عَوْفٍ حَدَّثَهُ أَنَّ أَبَا جُمُعَةَ حَبِيبَ بْنِ سِبَاعٍ وَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْأَحْزَابِ صَلَّى الْمَغْرِبَ فَلَمَّا فَرَغَ قَالَ هَلْ عَلِمَ أَحَدٌ مِنْكُمْ أَنِّي صَلَّيْتُ الْعَصْرَ قَالُوا يَا رَسُولَ اللَّهِ مَا صَلَّيْتَهَا فَأَمَرَ الْمُؤَذِّنَ فَأَقَامَ الصَّلَاةَ فَصَلَّى الْعَصْرَ ثُمَّ أَعَادَ الْمَغْرِبَ","id":"Telah menceritakan kepada kami [Musa bin Daud] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Muhammad bin Yazid] sesungguhnya [Abdullah bin Auf] menceritakannya, sesungguhnya [Abu Jumu'ah, Habib bin Siba'] dia bertemu Nabi Shallallahu'alaihiwasallam, Nabi Shallallahu'alaihiwasallam pada Perang Ahzab shalat maghrib, tatkala selesai beliau bersabda: \"Mungkin salah seorang dari kalian tahu jika saya tadi sudah shalat asar?.\" Mereka berkata; \"Wahai Rasulullah, anda belum melaksanakan shalat ashar!, \" lalu beliau menyuruh muadzin, lalu ditegakkan shalat. Beliau shalat ashar lalu mengulangi maghrib.\" "},"1358":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي أَسِيدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي صَالِحٌ أَبُو مُحَمَّدٍ قَالَ حَدَّثَنِي أَبُو جُمُعَةَقَالَ تَغَدَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَنَا أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ قَالَ فَقَالَ يَا رَسُولَ اللَّهِ هَلْ أَحَدٌ خَيْرٌ مِنَّا أَسْلَمْنَا مَعَكَ وَجَاهَدْنَا مَعَكَ قَالَ نَعَمْ قَوْمٌ يَكُونُونَ مِنْ بَعْدِكُمْ يُؤْمِنُونَ بِي وَلَمْ يَرَوْنِي","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Al Auza'i] berkata; telah bercerita kepadaku [Asid bin Abdurrahman] berkata; telah bercerita kepadaku [Shalih Abu Muhammad] berkata; telah bercerita kepadaku [Abu Jumu'ah] berkata; kami keluar pada awal siang bersama Rasulullah Shallallahu'alaihiwasallam dan bersama beliau Abu Ubaidah bin Al Jarrah. (Abu Jumu'ah radliyallahu'anhu) berkata; lalu (Abu Ubaidah bin Al Jarrah radliyallahu'anhu) berkata; \"Wahai Rasulullah, apakah ada seseorang yang lebih baik dari kami, kami masuk Islam dan berjihad bersama anda?.\" Beliau bersabda: \"Ya, yaitu suatu kaum yang ada setelah kalian mereka beriman kepadaku padahal mereka belum pernah melihatku.\""},"1359":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي أَسِيدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ خَالِدِ بْنِ دُرَيْكٍ عَنْ أَبِي مُحَيْرِيزٍ قَالَقُلْتُ لِأَبِي جُمُعَةَ رَجُلٍ مِنْ الصَّحَابَةِ حَدِّثْنَا حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ أُحَدِّثُكُمْ حَدِيثًا جَيِّدًا تَغَدَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَنَا أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ فَقَالَ يَا رَسُولَ اللَّهِ أَحَدٌ خَيْرٌ مِنَّا أَسْلَمْنَا مَعَكَ وَجَاهَدْنَا مَعَكَ قَالَ نَعَمْ قَوْمٌ يَكُونُونَ مِنْ بَعْدِكُمْ يُؤْمِنُونَ بِي وَلَمْ يَرَوْنِي","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Al Auza'i] berkata; telah bercerita kepadaku [Asid bin Abdurrahman] dari [Khalid bin Duraik] dari [Abu Muhairiz] berkata; saya berkata; kepada [Abu Jumu'ah] seorang sahabat, \"Ceritakan kepada kami suatu hadis, yang telah kau dengar dari Rasulullah Shallallahu'alaihiwasallam.\" dia berkata; \"Ya. saya akan menceritakan kepada kalian satu hadis yang bagus, kami keluar pada awal siang bersama Rasulullah Shallallahu'alaihiwasallam dan bersama kami juga Abu Ubaidah bin Al Jarrah. (Abu Jumu'ah radliyallahu'anhu) berkata; lalu (Abu Ubaidah bin Al Jarrah radliyallahu'anhu) berkata; \"Wahai Rasulullah, apakah ada seseorang yang lebih baik dari kami, kami masuk Islam dan berjihad bersama anda?.\" Beliau bersabda: \"Ya, yaitu suatu kaum yang ada setelah kalian mereka beriman kepadaku padahal mereka belum pernah melihatku.\""},"1360":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ سَمِعْتُ الْأَوْزَاعِيَّ قَالَ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ قَالَ سَمِعْتُ وَاثِلَةَ بْنَ الْأَسْقَعِ يَقُولُخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَزْعُمُونَ أَنِّي آخِرِكُمْ وَفَاةً أَلَا إِنِّي مِنْ أَوَّلِكُمْ وَفَاةً وَتَتْبَعُونِي أَفْنَادًا يُهْلِكُ بَعْضُكُمْ بَعْضًا","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; saya mendengar [Al Auza'i] berkata; telah bercerita kepadaku [Rabi'ah bin Yazid] berkata; saya mendengar [Watsilah bin Al Asqa'] berkata; Rasulullah Shallallahu'alaihiwasallam datang menemui kami lalu bersabda: \"Apakah kalian beranggapan bahwa saya adalah orang yang terakhir wafat di antara kalian?. Ketahuilah bahwa saya adalah orang pertama-tama wafat dan akan ada beberapa kelompok yang mengikutiku, mereka itu saling menghancurkan satu sama lainnya.\""},"1361":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا هِشَامُ بْنُ الْغَازِ قَالَ حَدَّثَنِي أَبُو النَّضْرِ قَالَدَعَانِي وَاثِلَةُ بْنُ الْأَسْقَعِ وَقَدْ ذَهَبَ بَصَرُهُ فَقَالَ يَا خَبَّابُ قُدْنِي إِلَى يَزِيدَ بْنِ الْأَسْوَدِ الْجُرَشِيِّ فَذَكَرَ الْحَدِيثَ فَقَالَ أَبْشِرْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَنْ اللَّهِ عَزَّ وَجَلَّ أَنَا عِنْدَ ظَنِّ عَبْدِي بِي فَلْيَظُنَّ بِي مَا شَاءَ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Hisyam bin Al Ghaz] berkata; telah bercerita kepadaku [Abu Nadlr] berkata; [Watsilah bin Al Asqa'] memanggilku dan waktu itu telah buta, lalu berkata; \"Wahai, Khabbab? Bawalah saya pada Yazid bin Al Aswad Al Jurasyi\", lalu dia menyebutkan hadis lalu berkata; \"Berilah kabar gembira, sesungguhnya saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda dari Allah Azzawajalla, \"Saya berada pada persangkaan hamba-Ku, maka berprasangkalah dengan-Ku sekehendaknya.\""},"1362":{"ar":"حَدَّثَنَا عِصَامُ بْنُ خَالِدٍ وَأَبُو الْمُغِيرَةِ قَالَا حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ قَالَ سَمِعْتُ عَبْدَ الْوَاحِدِ بْنَ عَبْدِ اللَّهِ النَّصْرِيَّ قَالَ سَمِعْتُ وَاثِلَةَ بْنَ الْأَسْقَعِ يَقُولُقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَعْظَمِ الْفِرَى أَنْ يُدْعَى الرَّجُلُ إِلَى غَيْرِ أَبِيهِ أَوْ يُرِيَ عَيْنَيْهِ فِي الْمَنَامِ مَا لَمْ تَرَيَا أَوْ يَقُولَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَمْ يَقُلْ","id":"Telah menceritakan kepada kami ['Isham bin Khalid] dan [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Hariz bin 'Utsman] berkata; saya telah mendengar [Abdul Wahid bin Abdullah An-Nasri] berkata; saya mendengar [Watsilah bin Al Asqa'] berkata; Nabiyullah Shallallahu'alaihiwasallam bersabda: \" Yang termasuk kedustaan yang paling besar adalah: seorang laki-laki yang menasabkan dirinya kepada selain bapaknya, mengatakan dirinya bermimpi padahal tidak, dan berkata mengatasnamakan Rasulullah Shallallahu'alaihiwasallam suatu hal yang beliau tidak mengatakannya.\""},"1363":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ الْخَوْلَانِيُّ قَالَ حَدَّثَنِي عُمَرُ بْنُ رُؤْبَةَ قَالَ سَمِعْتُ عَبْدَ الْوَاحِدِ النَّصْرِيَّ يَقُولُ سَمِعْتُ وَاثِلَةَ بْنَ الْأَسْقَعِ يَذْكُرُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَرْأَةُ تَحُوزُ ثَلَاثَةَ مَوَارِيثَ عَتِيقَهَا وَلَقِيطَهَا وَالْوَلَدَ الَّذِي لَاعَنَتْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Yazid bin Abdu Rabbihi] berkata; telah menceritakan kepada kami [Muhammad bin Harb Al Khalani] berkata; telah bercerita kepadaku ['Umar bin Ru`yah] berkata; saya mendengar [Abdul Wahid An-Nashri] berkata; saya mendengar [Watsilah bin Al Asqa'] menyebutkan, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wanita itu mendapatkan tiga warisan: dari orang yang dia merdekakan, dari barang temuannya dan dari anak yang dirinya terkena li'an karena anak itu.\" "},"1364":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ أَخْبَرَنَا عِمْرَانُ الْقَطَّانُ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ الْهُذَلِيِّ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُعْطِيتُ مَكَانَ التَّوْرَاةِ السَّبْعَ وَأُعْطِيتُ مَكَانَ الزَّبُورِ الْمَئِينَ وَأُعْطِيتُ مَكَانَ الْإِنْجِيلِ الْمَثَانِيَ وَفُضِّلْتُ بِالْمُفَصَّلِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud, Abu Daud Ath-Thayalisi] berkata; telah Mengabarkan kepada kami ['Imran bin Al Qathan] dari [Qatadah] dari [Abu Al Malih Al Hudzali] dari [Watsilah bin Al Asqa'] sesungguhnya Nabi Shallallahu'alaihiwasallam bersabda: \"Saya diberi ganti dari Taurat dengan as-saba' (tujuh surat dalam Al qur'an yang panjang-panjang). Saya diberi ganti dari Zabur dengan Al ma`in (surat yang jumlah ayatnya sekitar seratus). Saya diberi ganti dari Injil dengan Al matsani (yaitu surat yang terulang-ulang membacanya dalam setiap rekaat shalat) dan saya diberi tambahan dengan Al mufashal (surat yang dimulai dari QAF sampai akhir surat).\""},"1365":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَجْلَانَ قَالَ سَمِعْتُ النَّضْرَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ يَقُولُ سَمِعْتُ وَاثِلَةَ بْنَ الْأَسْقَعِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْظَمُ الْفِرَى مَنْ يُقَوِّلُنِي مَا لَمْ أَقُلْ وَمَنْ أَرَى عَيْنَيْهِ فِي الْمَنَامِ مَا لَمْ تَرَيَا وَمَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] berkata; telah menceritakan kepada kami [Sa'id] yaitu Ibnu Abu Ayyub berkata; telah bercerita kepadaku [Muhammad bin Ajlan] berkata; saya telah mendengar [Nadlr bin Abdurrahman bin Abdullah] berkata; saya telah mendengar [Watsilah bin Al Asqa'] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Yang termasuk kedustaan yang paling besar adalah: Orang yang mengada-ada perkataan atas namaku apa yang tidak saya katakan, seseorang yang mengaku-ngaku bermimpi padahal tidak, Orang yang menasabkan diri kepada selain bapaknya.\""},"1366":{"ar":"حَدَّثَنَا عَارِمُ بْنُ الْفَضْلِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ إِبْرَاهِيمَ بْنِ أَبِي عَبْلَةَ عَنِ الْغَرِيفِ بْنِ عَيَّاشٍ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَرٌ مِنْ بَنِي سُلَيْمٍ فَقَالُوا إِنَّ صَاحِبًا لَنَا أَوْجَبَ قَالَ فَلْيُعْتِقْ رَقَبَةً يَفْدِي اللَّهُ بِكُلِّ عُضْوٍ مِنْهَا عُضْوًا مِنْهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami ['Arim bin Al Fadl] berkata; telah menceritakan kepada kami [Abdullah bin Mubarak] dari [Ibrahim bin Abu 'Ablah] dari [Al Gharif bin 'Ayyasy] dari [Watsilah bin Al Asqa'] berkata; ada beberapa orang dari Bani Sulaim yang mendatangi Nabi Shallallahu'alaihiwasallam lalu berkata; \"Salah seorang sahabat kami telah memastikan dirinya masuk neraka karena membunuh.\" Beliau bersabda: \" Hendaklah dia membebaskan seorang budak, karena Allah dengan tiap-tiap anggota badan budak tersebut akan menebus tiap anggota badannya dari neraka.\""},"1367":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي أَبُو عَمَّارٍ شَدَّادٌ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ اصْطَفَى كِنَانَةَ مِنْ بَنِي إِسْمَاعِيلَ وَاصْطَفَى مِنْ بَنِي كِنَانَةَ قُرَيْشًا وَاصْطَفَى مِنْ قُرَيْشٍ بَنِي هَاشِمٍ وَاصْطَفَانِي مِنْ بَنِي هَاشِمٍ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Al Auza'i] berkata; telah bercerita kepadaku [Abu 'Ammar Syaddad] dari [Watsilah bin Al Asqa'] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah telah memilih Kinanah dari Bani Isma'il dan telah memilih Bani Kinanah dengan Quraisy. Telah memilih Quraisy, dengan Bani Hasyim dan telah memilihku dari Bani Hasyim.\""},"1368":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ شَدَّادٍ أَبِي عَمَّارٍ قَالَدَخَلْتُ عَلَى وَاثِلَةَ بْنِ الْأَسْقَعِ وَعِنْدَهُ قَوْمٌ فَذَكَرُوا عَلِيًّا فَلَمَّا قَامُوا قَالَ لِي أَلَا أُخْبِرُكَ بِمَا رَأَيْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ بَلَى قَالَ أَتَيْتُ فَاطِمَةَ رَضِيَ اللَّهُ تَعَالَى عَنْهَا أَسْأَلُهَا عَنْ عَلِيٍّ قَالَتْ تَوَجَّهَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسْتُ أَنْتَظِرُهُ حَتَّى جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ عَلِيٌّ وَحَسَنٌ وَحُسَيْنٌ رَضِيَ اللَّهُ تَعَالَى عَنْهُمْ آخِذٌ كُلَّ وَاحِدٍ مِنْهُمَا بِيَدِهِ حَتَّى دَخَلَ فَأَدْنَى عَلِيًّا وَفَاطِمَةَ فَأَجْلَسَهُمَا بَيْنَ يَدَيْهِ وَأَجْلَسَ حَسَنًا وَحُسَيْنًا كُلَّ وَاحِدٍ مِنْهُمَا عَلَى فَخِذِهِ ثُمَّ لَفَّ عَلَيْهِمْ ثَوْبَهُ أَوْ قَالَ كِسَاءً ثُمَّ تَلَا هَذِهِ الْآيَةَ{ إِنَّمَا يُرِيدُ اللَّهُ لِيُذْهِبَ عَنْكُمْ الرِّجْسَ أَهْلَ الْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيرًا }وَقَالَ اللَّهُمَّ هَؤُلَاءِ أَهْلُ بَيْتِي وَأَهْلُ بَيْتِي أَحَقُّ","id":"Telah menceritakan kepada kami [Muhammad bin Mus'ab] berkata; telah menceritakan kepada kami [Al Auza'i] dari [Syaddad Abu 'Ammar] berkata; saya menemui [Watsilah bin Al Asqa'] saat itu di sisinya ada suatu kaum, lalu mereka menyebutkan Ali. Tatkala mereka berdiri, dia berkata kepadaku, \"Maukah saya beritahukan dengan apa yang telah saya lihat dari Rasulullah Shallallahu'alaihiwasallam?\" saya menjawab, Ya. (Watsilah bin Al Asqa' Radliyallahu'anhu) berkata; \"Saya mendatangi Fathimah Radliyallahu'anha, saya bertanya tentang Ali.\" Maka dia menjawab, \"Dia sedang menuju ke Rasulullah Shallallahu'alaihiwasallam lalu saya duduk dan menunggunya sampai Rasulullah Shallallahu'alaihiwasallam datang bersama Ali, Hasan dan Husain 'alaihimussalam, \" masing-masing beliau gandeng tangannya sampai masuk lalu Ali mendekati Fatimah dan Rasul mendudukkan hasan dan Husain di hadapan beliau. Dia mendudukkan Hasan dan Husain pada lutut beliau lalu beliau melipat pakaiannya pada mereka, \" atau berkata; \"Kain.\" Lalu beliau membaca ayat, \"Sesungguhnya Allah bermaksud hendak menghilangkan dosa dari kamu, Hai ahlul bait dan membersihkan kamu sebersih-bersihnya.\" dan bersabda: \"Ya Allah, mereka adalah Ahli Baitku, dan Ahli Baitku-lah yang paling berhak.\""},"1369":{"ar":"حَدَّثَنَا زِيَادُ بْنُ الرَّبِيعِ قَالَ حَدَّثَنَا عَبَّادُ بْنُ كَثِيرٍ الشَّامِيُّ مِنْ أَهْلِ فِلَسْطِينَ عَنِ امْرَأَةٍ مِنْهُمْ يُقَالُ لَهَا فَسِيلَةُ أَنَّهَا قَالَتْ سَمِعْتُ أَبِي يَقُولُسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَمِنَ الْعَصَبِيَّةِ أَنْ يُحِبَّ الرَّجُلُ قَوْمَهُ قَالَ لَا وَلَكِنْ مِنْ الْعَصَبِيَّةِ أَنْ يَنْصُرَ الرَّجُلُ قَوْمَهُ عَلَى الظُّلْمِقَالَ أَبُو عَبْد الرَّحْمَنِ سَمِعْتُ مَنْ يَذْكُرُ مِنْ أَهْلِ الْعِلْمِ أَنَّ أَبَاهَا يَعْنِي فَسِيلَةَ وَاثِلَةُ بْنُ الْأَسْقَعِ وَرَأَيْتُ أَبِي جَعَلَ هَذَا الْحَدِيثَ فِي آخِرِ أَحَادِيثِ وَاثِلَةَ فَظَنَنْتُ أَنَّهُ أَلْحَقَهُ فِي حَدِيثِ وَاثِلَةَ","id":"Telah menceritakan kepada kami [Ziyad bin Rabi'] berkata; telah menceritakan kepada kami ['Abbad bin Katsir Asy Syami] dari seorang penduduk Palestina dari salah seorang dari mereka, yang bernama [Fasilah] sesungguhnya dia berkata; saya telah mendengar [bapakku] berkata; saya telah bertanya kepada Rasulullah Shallallahu'alaihiwasallam, lalu saya berkata; \"Wahai Rasulullah, apakah termasuk dari fanatik golonngan, jika seseorang menyukai kaumnya?\" Beliau bersabda: \"Tidak, tapi yang termasuk fanatik adalah seorang laki-laki menolong kaumnya padahal dia melakukan penganiayaan.\" Abu Abdurrahman berkata; saya mendengar dari seorang yang menyebutkannya, dia termasuk dari ahli ilmu, sesungguhnya Bapaknya yaitu Fasilah, Watsilah bin Al Asqa', saya telah melihat bapakku menjadikan hadis ini pada akhir hadis Watsilah, lalu saya mengira, sesungguhnya dia menyertakan pada hadis Watsilah."},"1370":{"ar":"حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي مَرْزُوقٍ مَوْلَى تُجِيبَ وَتُجِيبُ بَطْنٌ مِنْ كِنْدَةَ عَنْ رُوَيْفِعِ بْنِ ثَابِتٍ الْأَنْصَارِيِّ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ افْتَتَحَ حُنَيْنًا فَقَامَ فِينَا خَطِيبًا فَقَالَ لَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْقِيَ مَاءَهُ زَرْعَ غَيْرِهِ وَلَا أَنْ يَبْتَاعَ مَغْنَمًا حَتَّى يُقْسَمَ وَلَا أَنْ يَلْبَسَ ثَوْبًا مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَخْلَقَهُ رَدَّهُ فِيهِ وَلَا يَرْكَبَ دَابَّةً مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَعْجَفَهَا رَدَّهَا فِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Za`idah] berkata; telah bercerita kepadaku [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Abu Marzuq] budak Tujib, yaitu daerah tengah dari Kindah, dari [Ruwaifi' bin Tsabit Al Anshari] berkata; saya bersama Nabi Shallallahu'alaihiwasallam ketika sedang menyerang Hunain, lalu beliau berdiri di tengah-tengah kami berkhutbah, bersabda: \"Tidak halal bagi seseorang yang beriman kepada Allah dan Hari Akhir mengalirkan airnya pada sawah orang lain, juga menjual ghanimah sampai dibagi atau memakai pakaian dari fa'i (harta kaum muslimin yang dirampas dari musuhnya tanpa adanya Perang) hingga jika telah usang lantas dia kembalikan, juga tidak halal menaiki kendaraan dari fa'i kaum muslimin sampai jika dia kendaraan itu telah melemah, lantas dia kembalikan.\" "},"1371":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا بَكْرُ بْنُ سَوَادَةَ عَنْ زِيَادِ بْنِ نُعَيْمٍ عَنْ وَفَاءٍ الْحَضْرَمِيِّ عَنْ رُوَيْفِعِ بْنِ ثَابِتٍ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى عَلَى مُحَمَّدٍ وَقَالَ اللَّهُمَّ أَنْزِلْهُ الْمَقْعَدَ الْمُقَرَّبَ عِنْدَكَ يَوْمَ الْقِيَامَةِ وَجَبَتْ لَهُ شَفَاعَتِي","id":"Telah menceritakan kepada kami [Hasan bin Musa] telah menceritakan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakan kepada kami [Bakr bin Sawadah] dari [Ziyad bin Nua'im] dari [Wafa' Al Hadlrami] dari [Ruwaifi' bin Tsabit Al Anshari] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang bershalawat atas Muhammad dan berkata; 'Ya Allah, turunkanlah dia pada tempat yang dekat di sisi-Mu pada Hari Kiamat' maka wajib baginya mendapat syafaatku.\""},"1372":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنِ الْحَارِثِ بْنِ يَزِيدَ عَنْ حَنَشٍ الصَّنْعَانِيِّ عَنْ رُوَيْفِعِ بْنِ ثَابِتٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِأَحَدٍ وَقَالَ قُتَيْبَةُ لِرَجُلٍ أَنْ يَسْقِيَ مَاءَهُ وَلَدَ غَيْرِهِ وَلَا يَقَعُ عَلَى أَمَةٍ حَتَّى تَحِيضَ أَوْ يَبِينَ حَمْلُهَا","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata; telah Mengabarkan kepada kami [Ibnu Lahi'ah] dan [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Al Harits bin Yazid] dari [Hanasy Ash-Shan'ani] dari [Ruwaifi' bin Tsabit] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak halal bagi seorangpun, \" Qutaibah berkata dengan redaksi 'Bagi seorang laki-laki', yaitu mengalirkan airnya pada anak orang lain, dan tidak menggauli atas budak sampai dia haid atau jelas kehamilannya.\" "},"1373":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنِ الْحَارِثِ بْنِ يَزِيدَ عَنْ حَنَشٍ الصَّنْعَانِيِّ عَنْ رُوَيْفِعِ بْنِ ثَابِتٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُوطَأَ الْأَمَةُ حَتَّى تَحِيضَ وَعَنْ الْحَبَالَى حَتَّى يَضَعْنَ مَا فِي بُطُونِهِنَّ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah Mengabarkan kepada kami [Ibnu Lahi'ah] dari [Al Harits bin Yazid] dari [Hanasy Ash-Shan'ani] dari [Ruwaifi' bin Tsabit] berkata; Rasulullah Shallallahu'alaihiwasallam melarang menggauli budak sampai dia haid dan dari orang yang sedang hamil sampai dia melahirkan isi perutnya.\""},"1374":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ مِنْ كِتَابِهِ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ عَنْ شِيَيْمِ بْنِ بَيْتَانَ عَنْ أَبِي سَالِمٍ عَنْ شَيْبَانَ بْنِ أُمَيَّةَ عَنْ رُوَيْفِعِ بْنِ ثَابِتٍ الْأَنْصَارِيِّ أَنَّهُغَزَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَكَانَ أَحَدُنَا يَأْخُذُ النَّاقَةَ عَلَى النِّصْفِ مِمَّا يَغْنَمُ حَتَّى أَنَّ لِأَحَدِنَا الْقِدْحَ وَلِلْآخَرِ النَّصْلَ وَالرِّيشَ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] dari kitabnya, berkata; telah Mengabarkan kepada kami [Ibnu Lahi'ah] dari ['Ayyasy bin 'Abbas] dari [Syiyaim bin Baitan] dari [Abu Salim] dari [Syaiban bin Umayyah] dari [Ruwaifi' bin Tsabit Al Anshari], dia pernah berperang bersama Rasulullah Shallallahu'alaihiwasallam, (Kata Ruwaifi') dan salah seorang dari kami sedang ada yang mengambil unta lantas dibagi separoh, sampai ada salah seorang dari kami yang hanya mendapat kayu busur, sedang lainnya mendapat anak panah dan lainnya lagi mendapat bulu anak panahnya.\""},"1375":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاَقَ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ عَنْ شِيَيْمِ بْنِ بَيْتَانَ قَالَكَانَ مَسْلَمَةُ بْنُ مُخَلَّدٍ عَلَى أَسْفَلِ الْأَرْضِ قَالَ فَاسْتَعْمَلَ رُوَيْفِعَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ فَسِرْنَا مَعَهُ مِنْ شَرِيكٍ إِلَى كَوْمِ عَلْقَامَ أَوْ مِنْ كَوْمِ عَلْقَامَ إِلَى شَرِيكٍ قَالَ فَقَالَ رُوَيْفِعُ بْنُ ثَابِتٍ كُنَّا نَغْزُو عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَأْخُذُ أَحَدُنَا جَمَلَ أَخِيهِ عَلَى أَنَّ لَهُ النِّصْفَ مِمَّا يَغْنَمُ قَالَ حَتَّى أَنَّ أَحَدَنَا لَيَصِيرُ لَهُ الْقِدْحُ وَلِلْآخَرِ النَّصْلُ وَالرِّيشُ قَالَ فَقَالَ رُوَيْفِعُ بْنُ ثَابِتٍ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رُوَيْفِعُ لَعَلَّ الْحَيَاةَ سَتَطُولُ بِكَ فَأَخْبِرْ النَّاسَ أَنَّهُ مَنْ عَقَدَ لِحْيَتَهُ أَوْ تَقَلَّدَ وَتَرًا أَوْ اسْتَنْجَى بِرَجِيعِ دَابَّةٍ أَوْ عَظْمٍ فَقَدْ بَرِئَ مِمَّا أَنْزَلَ اللَّهُ عَلَى مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Ayyasy bin 'Abbas] dari [Syiyaim bin Baitan] berkata; Maslamah bin Mukhallad berada pada dataran rendah, berkata; lalu dia mengangkat [Ruwaifi' bin Tsabit Al Anshari] sebagai pimpinan. Kami melakukan perjalanan bersamanya dari Syarik ke Kaum 'Alqam atau dari Kaum 'Alqam ke Syarik. Ruwaifi' bin Tsabit Al Anshari berkata; \"Kami pernah berperang pada masa Nabi Shallallahu'alaihiwasallam sehingga salah seorang dari kami mengambil unta saudaranya padahal bagian untuknya hanyalah setengah dari rampasan itu.\" (Ruwaifi' bin Tsabit Al Anshari radliyallahu'anhu) berkata; \"Sampai ada pada salah seorang dari kami memiliki busur dan yang lainnya memiliki anak panah dan tali busur.\" (Maslamah bin Mukhallad radliyallahu'anhu) berkata; lalu Ruwaifi' bin Tsabit berkata; Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku, \"Wahai Ruwaifi', sepertinya hidupmu akan panjang, maka tolong kabarkanlah kepada orang-orang, bahwa barangsiapa mengikat jenggotnya atau dia menggantungkan tali pada lehernya dalam jumlah ganjil, atau dia bersuci dengan kotoran tunggangan atau tulang, berarti dia telah berlepas diri dari wahyu yang Allah turunkan kepada Muhammad Shallallahu'alaihiwasallam.\""},"1376":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى الْأَشْيَبُ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا عَيَّاشُ بْنُ عَبَّاسٍ عَنْ شِيَيْمِ بْنِ بَيْتَانَ قَالَ حَدَّثَنَا رُوَيْفِعُ بْنُ ثَابِتٍ قَالَكَانَ أَحَدُنَا فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُ جَمَلَ أَخِيهِ عَلَى أَنْ يُعْطِيَهُ النِّصْفَ مِمَّا يَغْنَمُ وَلَهُ النِّصْفُ حَتَّى أَنَّ أَحَدَنَا لَيَطِيرُ لَهُ النَّصْلُ وَالرِّيشُ وَالْآخَرَ الْقِدْحُ ثُمَّ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رُوَيْفِعُ لَعَلَّ الْحَيَاةَ سَتَطُولُ بِكَ فَأَخْبِرْ النَّاسَ أَنَّهُ مَنْ عَقَدَ لِحْيَتَهُ أَوْ تَقَلَّدَ وَتَرًا أَوْ اسْتَنْجَى بِرَجِيعِ دَابَّةٍ أَوْ عَظْمٍ فَإِنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُ بَرِيءٌ","id":"Telah menceritakan kepada kami [Hasan bin Musa Al Asyyab] berkata; telah Mengabarkan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakan kepada kami ['Ayyasy bin 'Abbas] dari [Syiyaim bin Baitan] berkata; telah menceritakan kepada kami [Ruwaifi' bin Tsabit Al Anshari] berkata; salah seorang dari kami pada masa Rasulullah Shallallahu'alaihiwasallam mengambil unta milik saudaranya dengan memberinya setengah dari bagian rampasannya, dan haknya adalah setengahnya. Sampai salah seorang dari kami hanya mendapat anak panah, bulu dan yang lainnya mendapatkan panah saja. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku, \"Wahai Ruwaifi', sepertinya hidupmu panjang, maka tolong kabarkanlah kepada orang-orang, barangsiapa yang memintal jenggotnya atau dia mengalungkan tali pada lehernya dalam jumlah yang ganjil atau dia bersuci dengan kotoran tunggangan atau tulang, sesungguhnya Muhammad Shallallahu'alaihiwasallam berlepas diri darinya.\""},"1377":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي مَرْزُوقٍ مَوْلَى تُجِيبَ عَنْ حَنَشٍ الصَّنْعَانِيِّ قَالَغَزَوْنَا مَعَ رُوَيْفِعِ بْنِ ثَابِتٍ الْأَنْصَارِيِّ قَرْيَةً مِنْ قُرَى الْمَغْرِبِ يُقَالُ لَهَا جَرَبَّةُ فَقَامَ فِينَا خَطِيبًا فَقَالَ أَيُّهَا النَّاسُ إِنِّي لَا أَقُولُ فِيكُمْ إِلَّا مَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَامَ فِينَا يَوْمَ حُنَيْنٍ فَقَالَ لَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْقِيَ مَاءَهُ زَرْعَ غَيْرِهِ يَعْنِي إِتْيَانَ الْحَبَالَى مِنْ السَّبَايَا وَأَنْ يُصِيبَ امْرَأَةً ثَيِّبًا مِنْ السَّبْيِ حَتَّى يَسْتَبْرِئَهَا يَعْنِي إِذَا اشْتَرَاهَا وَأَنْ يَبِيعَ مَغْنَمًا حَتَّى يُقْسَمَ وَأَنْ يَرْكَبَ دَابَّةً مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَعْجَفَهَا رَدَّهَا فِيهِ وَأَنْ يَلْبَسَ ثَوْبًا مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَخْلَقَهُ رَدَّهُ فِيهِ","id":"Telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; telah bercerita kepadaku [Yazid bin Abu Habib] dari [Abu Marzuq] mantan budak Tujib, dari [Hanasy Ash-Shana'ani] berkata; kami berperang bersama [Ruwaifi' bin Tsabit Al Anshari] di suatu desa di negara Maroko yang bernama Jarabbah, lalu dia berdiri di tengah-tengah kami berkhutbah, lalu berkata; \"Wahai orang-orang, saya tidak mengatakan kepada kalian kecuali apa yang saya dengar dari Rasulullah Shallallahu'alaihiwasallam bersabda: saat itu beliau berdiri di tengah-tengah kami pada Perang Hunain, \"Tidak halal bagi seseorang yang beriman kepada Allah dan Hari Akhir, ia mengalirkan airnya pada sawah orang lain' maksudnya mensetubuhi wanita hamil dari tawanan Perang, terlarang seseorang mensetubuhi wanita menjanda dari tawanan sampai dia tahu betul ketidakhamilannya maksudnya jika dia membeli tawanan itu, juga terlarang menjual ghanimah sampai dibagi, atau menaiki kendaraan dari fa'i kaum muslimin sampai jika dia hewan tunggangan itu telah melemah, dia mengembalikannya, dan memakai pakaian dari fa'i (harta kaum muslimin yang dirampas dari musuhnya tanpa adanya Perang) hingga jika telah menjadi usang, dia mengembalikannya.\""},"1378":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنِ الْحَارِثِ بْنِ يَزِيدَ قَالَ حَدَّثَنِي حَنَشٌ قَالَكُنَّا مَعَ رُوَيْفِعِ بْنِ ثَابِتٍ غَزْوَةَ جَرَبَّةَ فَقَسَمَهَا عَلَيْنَا وَقَالَ لَنَا رُوَيْفِعٌ مَنْ أَصَابَ مِنْ هَذَا السَّبْيِ فَلَا يَطَؤُهَا حَتَّى تَحِيضَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِرَجُلٍ أَنْ يَسْقِيَ مَاءَهُ وَلَدَ غَيْرِهِ","id":"Telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Al Harits bin Yazid] berkata; telah bercerita kepadaku [Hanasy] berkata; kami sedang bersama [Ruwaifi' bin Tsabit] pada Perang Jarabbah lalu dia membagi kepada kami, lalu dia bertanya kepada kami, \"Barangsiapa yang mendapatkan tawanan, maka janganlah dia menggaulinya sampai tawanan itu haid. Sesungguhnya saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Tiada halal bagi seorang laki-laki menumpahkan airnya pada anak orang lain'.\" "},"1379":{"ar":"حَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ قَالَ حَدَّثَنَا الْمُفَضَّلُ قَالَ حَدَّثَنِي عَيَّاشُ بْنُ عَبَّاسٍ أَنَّ شِيَيْمَ بْنَ بَيْتَانَ أَخْبَرَهُ أَنَّهُ سَمِعَ شَيْبَانَ الْقِتْبَانِيَّ يَقُولُاسْتَخْلَفَ مَسْلَمَةُ بْنُ مُخَلَّدٍ رُوَيْفِعَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ عَلَى أَسْفَلِ الْأَرْضِ قَالَ فَسِرْنَا مَعَهُ قَالَ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رُوَيْفِعُ لَعَلَّ الْحَيَاةَ سَتَطُولُ بِكَ بَعْدِي فَأَخْبِرْ النَّاسَ أَنَّهُ مَنْ عَقَدَ لِحْيَتَهُ أَوْ تَقَلَّدَ وَتَرًا أَوْ اسْتَنْجَى بِرَجِيعِ دَابَّةٍ أَوْ بِ��َظْمٍ فَإِنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَرِيءٌ مِنْهُ","id":"Telah menceritakan kepada kami [Yahya bin Ghailan] berkata; telah menceritakan kepada kami [Al Mufadldlal] berkata; telah bercerita kepadaku ['Ayyasy bin 'Abbas] sesungguhnya [Syiyaim bin Baitan] mengabarinya, sesungguhnya telah mendengar [Syaiban Al Qityani] berkata; Maslamah bin Mukhallid mengangkat [Ruwaifi' bin Tsabit Al Anshari] sebagai pimpinan di dataran rendah lalu dia berkata; \"Kami mengadakan perjalanan bersamanya.\" (Ruwaifi' bin Tsabit Al Anshari radliyallahu'anhu) berkata; Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku, \"Wahai Ruwaifi', sepertinya hidupmu akan panjang setelahku, maka tolong kabarkan kepada orang-orang, sesungguhnya barangsiapa yang memintal jenggotnya atau dia mengalungkan pada lehernya sebuah tali dengan jumlah ganjil atau dia bersuci dengan kotoran hewan tunggangan atau tulang, sesungguhnya Muhammad Shallallahu'alaihiwasallam telah berlepas diri darinya.\""},"1380":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا حَرِيزٌ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَامِرٍ الْأَلْهَانِيَّ قَالَدَخَلَ الْمَسْجِدَ حَابِسُ بْنُ سَعْدٍ الطَّائِيُّ مِنْ السَّحَرِ وَقَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَى النَّاسَ يُصَلُّونَ فِي مُقَدَّمِ الْمَسْجِدِ فَقَالَ مُرَاءُونَ وَرَبِّ الْكَعْبَةِ أَرْعِبُوهُمْ فَمَنْ أَرْعَبَهُمْ فَقَدْ أَطَاعَ اللَّهَ وَرَسُولَهُ قَالَ فَأَتَاهُمْ النَّاسُ فَأَخْرَجُوهُمْ قَالَ فَقَالَ إِنَّ الْمَلَائِكَةَ تُصَلِّي مِنْ السَّحَرِ فِي مُقَدَّمِ الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Hariz] berkata; saya mendengar [Abdullah bin 'Amir Al Hani] berkata; [Habis bin Sa'd Ath-Tha`i] masuk masjid pada waktu malam sebelum subuh, dan dia telah menemukan Nabi Shallallahu'alaihiwasallam di masjid itu. Nabi melihat orang-orang shalat di bagian serambi masjid, lalu beliau bersabda: \"Mereka adalah orang yang riya', demi Rab Ka'bah, ancamlah mereka. Barangsiapa yang mengancam mereka, berarti dia mentaati Allah dan Rasul-Nya.\" lalu orang-orang mendatangi mereka dan mengusir mereka. (Abdullah bin 'Amir Al Hani Radliyallahu'anhu) berkata; lalu (Ruwaifi' bin Tsabit Al Anshari radliyallahu'anhu) berkata; \"Sesungguhnya para Malaikat shalat pada waktu malam menjelang subuh pada bagian serambi masjid.\""},"1381":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ رَبِيعَةَ بْنِ لَقِيطٍ عَنْ عَبْدِ اللَّهِ بْنِ حَوَالَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَجَا مِنْ ثَلَاثٍ فَقَدْ نَجَا ثَلَاثَ مَرَّاتٍ مَوْتِي وَالدَّجَّالِ وَقَتْلِ خَلِيفَةٍ مُصْطَبِرٍ بِالْحَقِّ مُعْطِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah Mengabarkan kepadaku [Yahya bin Ayyub] berkata; telah bercerita kepadaku [Yazid bin Abu Habib] dari [Rabi'ah bin Laqith] dari [Abdullah bin Hawalah] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang selamat dari tiga hal, maka dia telah selamat tiga kali: wafatku, Dajjal dan pembunuhan seorang khalifah yang sabar mempertahankan kebenaran, sedang khalifah itu telah memasrahkan kebenaran agar dituntaskan."},"1382":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنِ ابْنِ حَوَالَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَالِسٌ فِي ظِلِّ دَوْمَةٍ وَعِنْدَهُ كَاتِبٌ لَهُ يُمْلِي عَلَيْهِ فَقَالَ أَلَا أَكْتُبُكَ يَا ابْنَ حَوَالَةَ قُلْتُ لَا أَدْرِي مَا خَارَ اللَّهُ لِي وَرَسُولُهُ فَأَعْرَضَ عَنِّي وَقَالَ إِسْمَاعِيلُ مَرَّةً فِي الْأُولَى نَكْتُبُكَ يَا ابْنَ حَوَالَةَ قُلْتُ لَا أَدْرِي فِيمَ يَا رَسُولَ اللَّهِ فَأَعْرَضَ عَنِّي فَأَكَبَّ عَلَى كَاتِبِهِ يُمْلِي عَلَيْهِ ثُمَّ قَالَ أَنَكْتُبُكَ يَا ابْنَ حَوَالَةَ قُلْتُ لَا أَدْرِي مَا خَارَ اللَّهُ لِي وَرَسُولُهُ فَأَعْرَضَ عَنِّي فَأَكَبَّ عَلَى كَاتِبِهِ يُمْلِي عَلَيْهِ قَالَ فَنَظَرْتُ فَإِذَا فِي الْكِتَابِ عُمَرُ فَقُلْتُ إِنَّ عُمَرَ لَا يُكْتَبُ إِلَّا فِي خَيْرٍ ثُمَّ قَالَ أَنَكْتُبُكَ يَا ابْنَ حَوَالَةَ قُلْتُ نَعَمْ فَقَالَ يَا ابْنَ حَوَالَةَ كَيْفَ تَفْعَلُ فِي فِتْنَةٍ تَخْرُجُ فِي أَطْرَافِ الْأَرْضِ كَأَنَّهَا صَيَاصِي بَقَرٍ قُلْتُ لَا أَدْرِي مَا خَارَ اللَّهُ لِي وَرَسُولُهُ قَالَ وَكَيْفَ تَفْعَلُ فِي أُخْرَى تَخْرُجُ بَعْدَهَا كَأَنَّ الْأُولَى فِيهَا انْتِفَاجَةُ أَرْنَبٍ قُلْتُ لَا أَدْرِي مَا خَارَ اللَّهُ لِي وَرَسُولُهُ قَالَ اتَّبِعُوا هَذَا قَالَ وَرَجُلٌ مُقَفٍّ حِينَئِذٍ قَالَ فَانْطَلَقْتُ فَسَعَيْتُ وَأَخَذْتُ بِمَنْكِبَيْهِ فَأَقْبَلْتُ بِوَجْهِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ هَذَا قَالَ نَعَمْ قَالَ وَإِذَا هُوَ عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ تَعَالَى عَنْهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Al Jurairi] dari [Abdullah bin Syaqiq] dari [Ibnu Hawalah] berkata; saya telah mendatangi Rasulullah Shallallahu'alaihiwasallam saat itu beliau sedang duduk di bawah pohon yang besar dan disamping beliau ada seorang penulis yang membacakan di hadapan beliau. Lalu dia (penulis Rasulullah Shallallahu'alaihiwasallam) berkata; \"Maukah saya tulis kamu, Wahai Ibnu Hawalah?.\" Saya menjawab, \"Saya tidak tahu. Apa yang Allah dan Rasul-Nya pilihkan untukku?, \" lalu dia berpaling dariku. [Isma'il] berkata pertama kami, \"Kami akan menulismu, Wahai Ibnu Hawalah, \" lalu saya berkata; \"Saya tidak tahu saya harus menulis apa, Wahai Rasulullah?, \" lalu beliau berpaling dariku, beliau merendahkan kepalanya pada penulisnya dan mendiktekannya, lalu bersabda: \"Maukah saya menulismu, Wahai Ibnu Hawalah?.\" Saya menjawab, \"Saya tidak tahu. Apa yang Allah dan Rasul-Nya pilihkan untukku, \" lalu beliau berpaling dariku dan merendahkan kepalanya pada penulisnya dan mendiktekannya (Ibnu Hawalah radliyallahu'anhu) berkata; lalu saya melihatnya, ternyata di dalam tulisan ada 'Umar, lalu saya berkata; \"Umar tidak ditulis kecuali dalam kebaikan, \" lalu beliau bersabda: \"Apakah kami menulismu, Wahai Ibnu Hawalah?.\" Saya menjawab, Ya. lalu beliau bertanya, \"Apa yang akan kau lakukan jika ada fitnah yang keluar dari ujung bumi seperti tanduk sapi?.\" Saya menjawab, \"Saya tidak tahu, Allah dan Rasul-Nya tidak memilihku.\" Beliau bertanya, \"Apa yang akan kau lakukan pada fitnah yang lain yang keluar setelahnya, fitnah yang pertama seolah-olah lompatan kelinci?.\" Saya menjawab, \"Saya tidak tahu, Allah dan Rasul-Nya tidak memilihku.\" Beliau bersabda: \"Ikutlah kalian ini\", waktu itu ada seorang laki-laki yang sedang meninggalkan mereka. (Ibnu Hawalah radliyallahu'anhu) berkata; \"Saya berangkat dan saya mengejarnya lalu saya memegang kedua pundaknya, lalu saya arahkan wajahnya kepada Rasulullah Shallallahu'alaihiwasallam, lalu saya bertanya, 'Apakah ini? '\" beliau menjawab, Ya. (Ibnu Hawalah radliyallahu'anhu) berkata; \"Ternyata dia adalah 'Utsman bin 'Affan Radliyallahu'anhu.\""},"1383":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ وَيَزِيدُ بْنُ عَبْدِ رَبِّهِ قَالَا حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنِي بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي قُتَيْلَةَ عَنِ ابْنِ حَوَالَةَ أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيَصِيرُ الْأَمْرُ إِلَى أَنْ تَكُونَ جُنُودٌ مُجَنَّدَةٌ جُنْدٌ بِالشَّامِ وَجُنْدٌ بِالْيَمَنِ وَجُنْدٌ بِالْعِرَاقِ فَقَالَ ابْنُ حَوَالَةَ خِرْ لِي يَا رَسُولَ اللَّهِ إِنْ أَدْرَكْتُ ذَاكَ قَالَ عَلَيْكَ بِالشَّامِ فَإِنَّهُ خِيرَةُ اللَّهِ مِنْ أَرْضِهِ يَجْتَبِي إِلَيْهِ خِيرَتَهُ مِنْ عِبَادِهِ فَإِنْ أَبَيْتُمْ فَعَلَيْكُمْ بِيَمَنِكُمْ وَاسْقُوا مِنْ غُدُرِكُمْ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ تَوَكَّلَ لِي بِالشَّامِ وَأَهْلِهِ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] dan [Yazid bin Abdurabbihi] berkata; telah menceritakan kepada kami [Baqiyyah] berkata; telah bercerita kepadaku [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] dari [Abu Qutailah] dari [Ibnu Hawalah] sesungguhnya dia berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Saat itu akan terjadi tentara-tentara yang berkelompok-kelompok. Tentara yang berada di Syam, Tentara yang berada di Yaman, dan Tentara yang berada di Iraq.\" Ibnu Hawalah berkata; \"Pilihkan untukku, Wahai Rasulullah, jika saya menjumpai hal itu!.\" Beliau bersabda: \"Bergabunglah di Syam, karena di sana ada hamba-hamba Allah yang terpilih. Jika kalian tidak bisa, maka pergilah ke Yaman. Berilah air dari kolam kalian, sesungguhnya Allah Azzawajalla telah menyerahkan Syam dan penduduknya kepadaku.\""},"1384":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ رَبِيعَةَ بْنِ لَقِيطٍ عَنْ عَبْدِ اللَّهِ بْنِ حَوَالَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَجَا مِنْ ثَلَاثٍ فَقَدْ نَجَا ثَلَاثَ مَرَّاتٍ مَوْتِي وَالدَّجَّالِ وَقَتْلِ خَلِيفَةٍ مُصْطَبِرٍ بِالْحَقِّ مُعْطِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah Mengabarkan kepadaku [Yahya bin Ayyub] berkata; telah bercerita kepadaku [Yazid bin Abu Habib] dari [Rabi'ah bin Laqith] dari [Abdullah bin Hawalah] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa selamat dari tiga hal, dia selamat tiga kali: wafatku, Dajjal dan pembunuhan seorang khalifah yang sabar mempertahankan kebenaran dan khalifah itu telah memasrahkan kebenaran agar dituntaskan.\""},"1385":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ الْقَيْسِيُّ قَالَ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ قَالَ حَدَّثَنِي بَشْرُ بْنُ عَاصِمٍ اللَّيْثِيُّ عَنْ عُقْبَةَ بْنِ مَالِكٍ وَكَانَ مِنْ رَهْطِهِ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً فَسَلَّحْتُ رَجُلًا سَيْفًا قَالَ فَلَمَّا رَجَعَ قَالَ مَا رَأَيْتُ مِثْلَ مَا لَامَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعَجَزْتُمْ إِذْ بَعَثْتُ رَجُلًا فَلَمْ يَمْضِ لِأَمْرِي أَنْ تَجْعَلُوا مَكَانَهُ مَنْ يَمْضِي لِأَمْرِي","id":"Telah menceritakan kepada kami [Abdushshamad] telah menceritakan kepada kami [Sulaiman bin Al Mughirah Al Qaisi] berkata; telah menceritakan kepada kami [Humaid bin Hilal] berkata; telah bercerita kepadaku [Bisyr bin 'Ashim Al Laitsi] dari [Uqbah bin Malik] dia termasuk dari rombongannnya, berkata; Rasulullah Shallallahu'alaihiwasallam mengutus sebuah satuan Perang lalu saya menyerungkan satu pedang pada seorang laki-laki. (Uqbah bin Malik Radliyallahu'anhu) berkata; Tatkala dia kembali, dia berkata; \"Saya tidak pernah melihat sebagaimana Rasulullah Shallallahu'alaihiwasallam mencela kami, beliau bersabda: 'Apakah kalian telah lemah jika saya mengutus seorang laki-laki dan dia belum selesai melakukannya lalu kalian mengantikan tempatnya pada orang yang akan menyelesaikan urusanku.\""},"1386":{"ar":"حَدَّثَنَا هَاشِمٌ قَالَ حَدَّثَنَا سُلَيْمَانُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ بِشْرِ بْنِ عَاصِمٍ قَالَ حَدَّثَنَا عُقْبَةُ بْنُ مَالِكٍ اللَّيْثِيُّ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ إِذْ قَالَ الْقَائِلُ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا قَالَ الَّذِي قَالَ إِلَّا تَعَوُّذًا مِنْ الْقَتْلِ فَذَكَرَ قِصَّتَهُ فَأَقْبَلَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُعْرَفُ الْمَسَاءَةُ فِي وَجْهِهِ ثُمَّ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَبَى عَلَيَّ مَنْ قَتَلَ مُؤْمِنًا قَالَهَا ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Hisyam] berkata; telah menceritakan kepada kami [Sulaiman] dari [Humaid bin Hilal] dari [Bisyr bin 'Ashim] berkata; telah menceritakan kepada kami ['Uqbah bin Malik Al Laitsi] berkata; tatkala Rasulullah Shallallahu'alaihiwasallam sedang berkhutbah, ada seorang yang berkata; \"Wahai Rasulullah, demi Allah, bagaimana jika ada orang yang mengucapkan syahadat hanya sebagai alat untuk menghindari pembunuhan?\" lalu dia menyebutkan kisahnya. Rasulullah Shallallahu'alaihiwasallam mendatanginya dan kelihatan muram pada wajahnya lalu bersabda: \"Allah Azzawajalla melalui perantaraanku menolak siapa saja yang membunuh seorang mukmin, \" beliau mengatakannya sebanyak tiga kali."},"1387":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ حُمَيْدِ بْنِ هِلَالٍ قَالَ جَمَعَ بَيْنِي وَبَيْنَ بِشْرِ بْنِ عَاصِمٍ رَجُلٌ فَحَدَّثَنِي عَنْ عُقْبَةَ بْنِ مَالِكٍأَنَّ سَرِيَّةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَشُوا أَهْلَ مَاءٍ صُبْحًا فَبَرَزَ رَجُلٌ مِنْ أَهْلِ الْمَاءِ فَحَمَلَ عَلَيْهِ رَجُلٌ مِنْ الْمُسْلِمِينَ فَقَالَ إِنِّي مُسْلِمٌ فَقَتَلَهُ فَلَمَّا قَدِمُوا أَخْبَرُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَمَا بَالُ الْمُسْلِمِ يَقْتُلُ الرَّجُلَ وَهُوَ يَقُولُ إِنِّي مُسْلِمٌ فَقَالَ الرَّجُلُ إِنَّمَا قَالَهَا مُتَعَوِّذًا فَصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجْهَهُ وَمَدَّ يَدَهُ الْيُمْنَى فَقَالَ أَبَى اللَّهُ عَلَيَّ مَنْ قَتَلَ مُسْلِمًا ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Hammad] yaitu Ibnu Salamah, dari [Yunus bin 'Ubaid] dari [Humaid bin Hilal] berkata; ada seorang laki-laki yang mempertemukanku dengan [Bisyr bin 'Ashim], lalu dia bercerita kepadaku, dari ['Uqbah bin Malik] sesungguhnya utusan Perang Rasulullah Shallallahu'alaihiwasallam mengerubungi 'pemiliki air' pada waktu pagi lalu ada seorang laki-laki dari 'pemilik air' yang menyerang. lalu ada seorang kaum muslimin yang menangkapnya, lalu (laki-laki itu) berkata; \"Sesungguhnya saya adalah seorang muslim, \" lalu dia membunuhnya. Tatkala mereka tiba, mereka mengabari Nabi Shallallahu'alaihiwasallam perihal itu, lalu Rasulullah Shallallahu'alaihiwasallam bangkit berkhutbah, memuji Allah lalu bersabda: \"Amma ba'du. Bagaimana ada seorang muslim yang membunuh seorang laki-laki yang mengatakan 'Sesungguhnya saya adalah seorang muslim'.\" Lalu (laki-laki muslim) itu berkata; \"Dia mengatakannya hanya sebagai alat perlindungan saja untuk menghindari pembunuhan, \" lalu Rasulullah Shallallahu'alaihiwasallam memalingkan wajahnya dan mengangkat tangan kanannya lalu bersabda: \"Melalui perantaraanku, Allah menolak siapa yang membunuh seorang muslim, \" beliau mengucapkannya sebanyak tiga kali."},"1388":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حِمْيَرٍ الْحِمْصِيُّ قَالَ حَدَّثَنَا ثَابِتُ بْنُ عَجْلَانَ قَالَ سَمِعْتُ أَبَا كَثِيرٍ الْمُحَارِبِيَّ يَقُولُ سَمِعْتُ خَرَشَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتَكُونُ مِنْ بَعْدِي فِتْنَةٌ النَّائِمُ فِيهَا خَيْرٌ مِنْ الْيَقْظَانِ وَالْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ السَّاعِي فَمَنْ أَتَتْ عَلَيْهِ فَلْيَمْشِ بِسَيْفِهِ إِلَى صَفَاةٍ فَلْيَضْرِبْهُ بِهَا حَتَّى يَنْكَسِرَ ثُمَّ لِيَضْجَعْ لَهَا حَتَّى تَنْجَلِيَ عَمَّا انْجَلَتْ","id":"Telah menceritakan kepada kami [Ali bin Bahr] berkata; telah menceritakan kepada kami [Muhammad bin Himyar Al Himsyi] berkata; telah menceritakan kepada kami [Tsabit bin Ajlan] berkata; saya telah mendengar [Abu Katsir Al Muharibi] berkata; saya mendengar [Kharasyah] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Akan ada fitnah setelahku, orang yang tidur ketika itu lebih baik dari pada orang yang terjaga. Orang yang duduk lebih baik daripada orang yang berdiri. Orang yang berdiri lebih baik daripada orang yang berjalan. Siapa saja yang menemui fitnah itu, berjalanlah dengan pedangnya menuju ke batu yang licin, dan bantinglah pedangnya sampai pecah, lalu berbaringlah menghadap batu itu sampai fitnah itu tampak.\""},"1389":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الرُّؤَاسِيُّ حَدَّثَنَا زُهَيْرٌ عَنْ دَاوُدَ بْنِ عَبْدِ اللَّهِ الْأَوْدِيِّ عَنْ حُمَيْدٍ الْحِمْيَرِيِّ قَالَلَقِيتُ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَحِبَهُ مِثْلَ مَا صَحِبَهُ أَبُو هُرَيْرَةَ فَمَا زَادَنِي عَلَى ثَلَاثِ كَلِمَاتٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْتَسِلُ الرَّجُلُ مِنْ فَضْلِ امْرَأَتِهِ وَلَا تَغْتَسِلُ بِفَضْلِهِ وَلَا يَبُولُ فِي مُغْتَسَلِهِ وَلَا يَمْتَشِطُ فِي كُلِّ يَوْمٍ","id":"Telah menceritakan kepada kami [Humaid bin Abdurrahman Ar Ru`asi] telah menceritakan kepada kami [Zuhair] dari [Daud bin Abdullah Al Audi] dari [Humaid Al Himyari] berkata; saya bertemu dengan [seorang laki-laki dari sahabat Nabi Shallallahu'alaihiwasallam] yang bersahabat sebagaimana Abu Hurairah bersahabat dengan beliau. Dia tidak menambahkan padaku lebih dari tiga kalimat, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah seorang laki-laki mandi dengan air sisa dari istrinya, dan janganlah seorang istri mandi dengan sisa air suaminya. Janganlah kamu kencing pada tempat mandinya, dan janganlah menyisir setiap hari.\""},"1390":{"ar":"حَدَّثَنَا يُونُسُ وَعَفَّانُ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ دَاوُدَ بْنِ عَبْدِ اللَّهِ الْأَوْدِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيِّ قَالَلَقِيتُ رَجُلًا قَدْ صَحِبَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَ سِنِينَ كَمَا صَحِبَهُ أَبُو هُرَيْرَةَ أَرْبَعَ سِنِينَ قَالَ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَمْتَشِطَ أَحَدُنَا كُلَّ يَوْمٍ وَأَنْ يَبُولَ فِي مُغْتَسَلِهِ وَأَنْ تَغْتَسِلَ الْمَرْأَةُ بِفَضْلِ الرَّجُلِ وَأَنْ يَغْتَسِلَ الرَّجُلُ بِفَضْلِ الْمَرْأَةِ وَلْيَغْتَرِفُوا جَمِيعًا","id":"Telah menceritakan kepada kami [Yunus] dan ['Affan] berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Daud bin Abdullah Al Audi] dari [Humaid bin Abdurrahman Al Himyari] berkata; saya bertemu dengan [seorang laki-laki yang pernah bertemu Nabi Shallallahu'alaihiwasallam] selama empat tahun sebagaimana Abu Hurairah bersahabat dengan beliau. Dia berkata; Rasulullah Shallallahu'alaihiwasallam melarang kami bersisir setiap hari, kencing pada tempat mandinya, seorang wanita mandi dengan air sisa dari laki-laki, dan seorang laki-laki yang mandi dengan sisa air dari wanita dan keduanya saling menciduknya."},"1391":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِسْحَاقَ هُوُ ابْنُ سُوَيْدٍ عَنْ أَبِي حَبِيبَةَ عَنْ ذَلِكَ الرَّجُلِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِي حَاجَةٌ فَرَأَى عَلَيَّ خَلُوقًا فَقَالَ اذْهَبْ فَاغْسِلْهُ فَغَسَلْتُهُ ثُمَّ عُدْتُ إِلَيْهِ فَقَالَ اذْهَبْ فَاغْسِلْهُ فَذَهَبْتُ فَوَقَعْتُ فِي بِئْرٍ فَأَخَذْتُ مِشْقَةً فَجَعَلْتُ أَتَتَبَّعُهُ ثُمَّ عُدْتُ إِلَيْهِ فَقَالَ حَاجَتُكَ","id":"Telah menceritakan kepada kami [Muhammad] yaitu Ibnu Ja'far, telah menceritakan kepada kami [Syu'bah] dari [Ishaq] yaitu Ibnu Suwaid, dari [Abu Habibah] dari [seorang laki-laki] berkata; saya menemui Nabi Shallallahu'alaihiwasallam pada saat itu saya memiliki keperluan, lalu beliau melihatku dalam keadaan memakai wangi-wangian yang berwarna kuning, lalu beliau bersabda: \"Pergilah dan cucilah, \" saya pun mencucinya. Saya kembali kepada beliau, dan beliau bersabda: \"Pergilah dan cucilah, \" saya pun pergi. Saya datang ke sumur, saya mengambil sepotong kain, saya mengunakannya. Saya kembali, lalu beliau bersabda: \"Apa keperluanmu.\""},"1392":{"ar":"حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ قَالَ حَدَّثَنِي شَدَّادُ بْنُ عَبْدِ اللَّهِ وَكَانَ قَدْ أَدْرَكَ نَفَرًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَبِي أُمَامَةَ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي مِمَّا عَلَّمَكَ اللَّهُ عَزَّ وَجَلَّ قَالَ إِذَا صَلَّيْتَ الصُّبْحَ فَأَقْصِرْ عَنْ الصَّلَاةِ حَتَّى تَطْلُعَ الشَّمْسُ فَإِذَا طَلَعَتْ فَلَا تُصَلِّ حَتَّى تَرْتَفِعَ فَإِنَّهَا تَطْلُعُ حِينَ تَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَحِينَئِذٍ يَسْجُدُ لَهَا الْكُفَّارُ فَإِذَا ارْتَفَعَتْ قِيدَ رُمْحٍ أَوْ رُمْحَيْنِ فَصَلِّ فَإِنَّ الصَّلَاةَ مَشْهُودَةٌ مَحْضُورَةٌ حَتَّى يَعْنِي يَسْتَقِلَّ الرُّمْحُ بِالظِّلِّ ثُمَّ أَقْصِرْ عَنْ الصَّلَاةِ فَإِنَّهَا حِينَئِذٍ تُسْجَرُ جَهَنَّمُ فَإِذَا أَفَاءَ الْفَيْءُ فَصَلِّ فَإِنَّ الصَّلَاةَ مَشْهُودَةٌ مَحْضُورَةٌ حَتَّى تُصَلِّيَ الْعَصْرَ فَإِذَا صَلَّيْتَ الْعَصْرَ فَأَقْصِرْ عَنْ الصَّلَاةِ حَتَّى تَغْرُبَ الشَّمْسُ فَإِنَّهَا تَغْرُبُ بَيْنَ قَرْنَيْ شَيْطَانٍ فَحِينَئِذٍ يَسْجُدُ لَهَا الْكُفَّارُ","id":"Telah menceritakan kepada kami [Ghundar] berkata; telah menceritakan kepada kami [Ikrimah bin 'Ammar] berkata; telah bercerita kepadaku [Syaddad bin Abdullah] dia bertemu beberapa sahabat Nabi Shallallahu'alaihiwasallam, dari [Abu Umamah] dari ['Amr bin 'Abasah] berkata; saya berkata; \"Wahai Rasulullah, ajarilah saya dari apa yang Allah Azzawajalla ajarkan kepadamu.\" Beliau bersabda: \"Jika kamu selesai shalat subuh, maka tahanlah sampai matahari terbit. Jika telah terbit, janganlah kamu shalat sampai meninggi, sesungguhnya matahari terbit ketika dua tanduk setan muncul. Saat itu orang-orang kafir sedang bersujud padanya. Jika matahari telah naik seukuran tombak atau dua tombak, maka shalatlah, sesungguhnya shalat saat itu disaksikan dan dihadiri malaikat, sampai tombak dan bayangannya sama. Lalu tahanlah shalat setelahnya, karena pada saat itu Jahanam sedang dinyalakan. Jika telah ada bayangannya maka shalatlah, sesungguhnya shalat saat itu disaksikan dan dihadiri malaikat, sampai kamu shalat asar. Jika kamu telah shalat asar, maka janganlah shalat sampai matahari terbenam. Sesungguhnya matahari itu terbenam diantara dua tanduk setan, yang pada saat itu orang-orang kafir sedang sujud kepadanya.\""},"1393":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ يَحْيَى بْنِ أَبِي عَمْرٍو السَّيْبَانِيِّ عَنْ أَبِي سَلَّامٍ الدِّمَشْقِيِّ وَعَمْرِو بْنِ عَبْدِ اللَّهِ أَنَّهُمَا سَمِعَا أَبَا أُمَامَةَ الْبَاهِلِيَّ يُحَدِّثُ عَنْ حَدِيثِ عَمْرِو بْنِ عَبَسَةَ السُّلَمِيِّ قَالَرَغِبْتُ عَنْ آلِهَةِ قَوْمِي فِي الْجَاهِلِيَّةِ فَذَكَرَ الْحَدِيثَ قَالَ فَسَأَلْتُ عَنْهُ فَوَجَدْتُهُ مُسْتَخْفِيًا بِشَأْنِهِ فَتَلَطَّفْتُ لَهُ حَتَّى دَخَلْتُ عَلَيْهِ فَسَلَّمْتُ عَلَيْهِ فَقُلْتُ لَهُ مَا أَنْتَ فَقَالَ نَبِيٌّ فَقُلْتُ وَمَا النَّبِيُّ فَقَالَ رَسُولُ اللَّهِ فَقُلْتُ وَمَنْ أَرْسَلَكَ قَالَ اللَّهُ عَزَّ وَجَلَّ قُلْتُ بِمَاذَا أَرْسَلَكَ فَقَالَ بِأَنْ تُوصَلَ الْأَرْحَامُ وَتُحْقَنَ الدِّمَاءُ وَتُؤَمَّنَ السُّبُلُ وَتُكَسَّرَ الْأَوْثَانُ وَيُعْبَدَ اللَّهُ وَحْدَهُ لَا يُشْرَكُ بِهِ شَيْءٌ قُلْتُ نِعْمَ مَا أَرْسَلَكَ بِهِ وَأُشْهِدُكَ أَنِّي قَدْ آمَنْتُ بِكَ وَصَدَّقْتُكَ أَفَأَمْكُثُ مَعَكَ أَمْ مَا تَرَى فَقَالَ قَدْ تَرَى كَرَاهَةَ النَّاسِ لِمَا جِئْتُ بِهِ فَامْكُثْ فِي أَهْلِكَ فَإِذَا سَمِعْتُمْ بِي قَدْ خَرَجْتُ مَخْرَجِي فَأْتِنِي فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata; Telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Yahya bin Abu 'Amr As-Syaibani] dari [Abu Sallam Ad-Dimasyqi] dan ['Amr bin Abdullah] sesungguhnya keduanya telah mendengar [Abu Umamah Al Bahili] menceritakan dari hadits ['Amr bin 'Abasah As-Sulami] berkata; \"Saya sangat membenci tuhan-tuhan kaumku pada Masa Jahiliyyah, \" lalu dia menyebutkan haditsnya. ('Amr bin 'Abasah As-Sulami radliyallahu'anhu) berkata; lalu saya bertanya tentang keberadaan nabi, dan saya pun mendapatkan nabi dalam keadaan menyembunyikan diri dari keramaian orang. Saya berusaha menemuinya dengan cara menyamar hingga saya bisa menemuinya, saya ucapkan salam kepadanya, lalu saya bertanya, \"Siapakah kamu.\" Beliau menjawab, \"Nabi.\" Saya ('Amr bin 'Abasah As-Sulami radliyallahu'anhu) berkata; \"Apakah nabi itu?\" lalu beliau menjawab, \"Rasulullah.\" saya bertanya, \"Siapakah yang mengutus kamu?.\" Beliau menjawab, \"Allah Azzawajalla.\" Saya bertanya, \"Dengan apa?\" beliau menjawab, \"Agar kamu menyambung silaturrahim, melindungi darah, mengamankan jalan, berhala dihancurkan, Allah semata yang disembah dan tidak ada sekutu bagi-Nya sesuatupun.\" Saya berkata; \"Sangat bagus risalah yang karenanya kau diutus. Saya bersaksi sesungguhnya saya beriman kepadamu, dan saya mempercayaimu, apakah saya harus tinggal bersamamu atau bagaimana pendapatmu?\" Maka beliau bersabda: \"Kamu telah melihat kebencian orang-orang atas apa yang saya bawa, maka tinggallah di keluargamu. Jika suatu hari nanti kamu mendengarku dan saya telah keluar dari tempat persembunyianku, datangilah saya, \" lalu dia menyebutkan hadits secara lengkap."},"1394":{"ar":"حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ حَدَّثَنَا السَّرِيُّ بْنُ يَحْيَى عَنْ كَثِيرِ بْنِ زِيَادٍ قَالَ قَالَ ابْنُ عَبَسَةَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَضْمَضَ وَاسْتَنْشَقَ فِي رَمَضَانَ","id":"Telah menceritakan kepada kami ['Attab bin Ziyad] berkata; Telah menceritakan kepada kami [Abdullah] Telah menceritakan kepada kami [As-Sari bin Yahya] dari [Katsir bin Ziyad] berkata; [Ibnu 'Abasah] berkata; \"Saya pernah melihat Rasulullah Shallallahu'alaihiwasallam berkumur dan memasukkan air ke dalam hidung pada bulan Ramadlan.\""},"1395":{"ar":"حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا يَعْلَى بْنُ عَطَاءٍ عَنْ يَزِيدَ بْنِ طَلْقٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ أَسْلَمَ يَعْنِي مَعَكَ فَقَالَ حُرٌّ وَعَبْدٌ يَعْنِي أَبَا بَكْرٍ وَبِلَالًا فَقُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي مِمَّا تَعْلَمُ وَأَجْهَلُ هَلْ مِنْ السَّاعَاتِ سَاعَةٌ أَفْضَلُ مِنْ الْأُخْرَى قَالَ جَوْفُ اللَّيْلِ الْآخِرُ أَفْضَلُ فَإِنَّهَا مَشْهُودَةٌ مُتَقَبَّلَةٌ حَتَّى تُصَلِّيَ الْفَجْرَ ثُمَّ انْهَهُ حَتَّى تَطْلُعَ الشَّمْسُ مَا دَامَتْ كَالْحَجَفَةِ حَتَّى تَنْتَشِرَ فَإِنَّهَا تَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَيَسْجُدُ لَهَا الْكُفَّارُ ثُمَّ تُصَلِّي فَإِنَّهَا مَشْهُودَةٌ مُتَقَبَّلَةٌ حَتَّى يَسْتَوِيَ الْعَمُودُ عَلَى ظِلِّهِ ثُمَّ انْهَهُ فَإِنَّهَا سَاعَةٌ تُسْجَرُ فِيهَا الْجَحِيمُ فَإِذَا زَالَتْ فَصَلِّ فَإِنَّهَا مَشْهُودَةٌ مُتَقَبَّلَةٌ حَتَّى تُصَلِّيَ الْعَصْرَ ثُمَّ انْهَهُ حَتَّى تَغْرُبَ الشَّمْسُ فَإِنَّهَا تَغْرُبُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَيَسْجُدُ لَهَا الْكُفَّارُوَكَانَ عَمْرُو بْنُ عَبَسَةَ يَقُولُ أَنَا رُبُعُ الْإِسْلَامِ وَكَانَ عَبْدُ الرَّحْمَنِ يُصَلِّي بَعْدَ الْعَصْرِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Bahz] berkata; Telah menceritakan kepada kami [Hammad bin Salamah] Telah menceritakan kepada kami [Ya'la bin 'Atha`] dari [Yazid bin Thalq] dari [Abdurrahman bin Al Bailamani] dari ['Amr bin 'Abasah] berkata; saya telah mendatangi Rasulullah Shallallahu'alaihiwasallam lalu saya berkata; \"Wahai Rasulullah, siapa yang telah masuk Islam bersama kamu?\" Beliau menjawab, \"Orang merdeka dan budak, yaitu Abu Bakar dan Bilal.\" Lalu saya berkata; \"Wahai Rasulullah, ajarilah aku, apa yang kamu ketahui dan saya tidak mengetahuinya, apakah pada waktu itu ada satu waktu yang lebih utama dari yang lainnya?\" Beliau bersabda: \"Pertengahan malam yang terakhir itu adalah yang paling utama, karena pada saat itu disaksikan malaikat dan dikabulkan sampai kamu shalat fajar. Kemudian tinggalkanlah sampai matahari terbit, sebagaimana tameng, sampai dia tersebar, karena saat itu sedang terbit diantara dua tanduk setan dan orang-orang kafir sedang bersujud kepadanya, lalu shalatlah karena disaksikan dan dikabulkan sampai keadaan tiang sama dengan bayangannya, lalu tinggalkanlah, karena pada saat itu neraka Jahim sedang dinyalakan. Jika telah bergeser, shalatlah, sesungguhnya shalat ketika itu disaksikan malaikat dan dikabulkan sampai kamu shalat ashar, lalu janganlah kau lakukan sampai matahari tenggelam, sesungguhnya saat itu sedang berada pada dua tanduk setan dan orang-orang kafir sujud kepadanya.\" 'Amr bin 'Abasah berkata; saya adalah rubu' Islam (seperempat) dan Abdurrahman shalat setelah asar dua rekaat."},"1396":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ حَدَّثَنَا حَرِيزٌ عَنْ سُلَيْمٍ يَعْنِي ابْنَ عَامِرٍ أَنَّ شُرَحْبِيلَ بْنَ السِّمْطِ قَالَ لِعَمْرِو بْنِ عَبَسَةَ حَدِّثْنَا حَدِيثًا لَيْسَ فِيهِ تَزَيُّدٌ وَلَا نِسْيَانٌ قَالَ عَمْرٌوسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَعْتَقَ رَقَبَةً مُسْلِمَةً كَانَتْ فِكَاكَهُ مِنْ النَّارِ عُضْوًا بِعُضْوٍ وَمَنْ شَابَ شَيْبَةً فِي سَبِيلِ اللَّهِ كَانَتْ لَهُ نُورًا يَوْمَ الْقِيَامَةِ وَمَنْ رَمَى بِسَهْمٍ فَبَلَغَ فَأَصَابَ أَوْ أَخْطَأَ كَانَ كَمَنْ أَعْتَقَ رَقَبَةً مِنْ وَلَدِ إِسْمَاعِيلَ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] Telah menceritakan kepada kami [Hariz] dari [Sulaim] yaitu Ibnu 'Amr, sesungguhnya [Syurahbil Al Samth] berkata; kepada ['Amr bin 'Abasah] Telah menceritakan kepada kami dengan suatu hadits yang di dalamnya tidak ada tambahan atau hal yang dilupakan. 'Amr berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa membebaskan seorang budak muslim, maka dari setiap anggota tubuh budak itu akan membebaskannya dari neraka. Barangsiapa yang beruban di jalan Allah, maka dia akan mendapatkan cahaya pada Hari Kiamat. Barangsiapa yang melempar dengan satu panah lalu sampai dan tepat sasarannya atau meleset, maka sebagaimana orang yang membebaskan budak dari anak Isma'il.\""},"1397":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي ابْنَ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي أُمَامَةَ قَالَأَتَيْنَاهُ فَإِذَا هُوَ جَالِسٌ يَتَغَلَّ فِي جَوْفِ الْمَسْجِدِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ الْمُسْلِمُ ذَهَبَ الْإِثْمُ مِنْ سَمْعِهِ وَبَصَرِهِ وَيَدَيْهِ وَرِجْلَيْهِقَالَ فَجَاءَ أَبُو ظَبْيَةَ وَهُوَ يُحَدِّثُنَا فَقَالَ مَا حَدَّثَكُمْ فَذَكَرْنَا لَهُ الَّذِي حَدَّثَنَا قَالَ فَقَالَ أَجَلْ سَمِعْتُ عَمْرَو بْنَ عَبَسَةَ ذَكَرَهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَادَ فِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ رَجُلٍ يَبِيتُ عَلَى طُهْرٍ ثُمَّ يَتَعَارَّ مِنْ اللَّيْلِ فَيَذْكُرُ وَيَسْأَلُ اللَّهَ عَزَّ وَجَلَّ خَيْرًا مِنْ خَيْرِ الدُّنْيَا وَالْآخِرَةِ إِلَّا آتَاهُ اللَّهُ عَزَّ وَجَلَّ إِيَّاهُ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] berkata; Telah menceritakan kepada kami [Abu Bakar] yaitu Ibnu 'Ayyasy, dari ['Ashim] dari [Syahr bin Hausyab] dari [Abu Umamah] berkata; kami mendatangi beliau, ternyata beliau pada saat itu sedang duduk beribadah di tengah masjid. (Abu Umamah Radliyallahu'anhu) berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika seorang muslim berwudlu, niscaya dosa akan hilang dari pendengarannya, penglihatannya, kedua tangannya dan kedua kakinya.\" Lalu [Abu Zhabiyah] datang dan dia menceritakan kepada kami, lalu berkata; 'Apa yang telah dia sampaikan kepada kalian? ', lalu kami sampaikan apa yang telah disampaikan kepada kami.\"Lalu dia berkata; 'ya. Saya telah mendengar ['Amr bin 'Abasah] menyebutkannya, dari Rasulullah Shallallahu'alaihiwasallam dan menambahkan di dalamnya, berkata Rasulullah Shallallahu'alaihiwasallam bersabda: 'Tidaklah seorang laki-laki yang bermalam dalam keadaan suci, lalu dia bangun dari malamnya, lalu dia berdzikir dan meminta kepada Allah Azzawajalla kebaikan dari kebaikan dunia dan akhirat, kecuali Allah Azzawajalla memberikan kepadanya.\""},"1398":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَهْرَامَ قَالَ سَمِعْتُ شَهْرَ بْنَ حَوْشَبٍ قَالَ حَدَّثَنِي أَبُو ظَبْيَةَ قَالَ قَالَ عَمْرُو بْنُ عَبَسَةَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا رَجُلٍ مُسْلِمٍ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَبَلَغَ مُخْطِئًا أَوْ مُصِيبًا فَلَهُ مِنْ الْأَجْرِ كَرَقَبَةٍ أَعْتَقَهَا مِنْ وَلَدِ إِسْمَاعِيلَ","id":"Telah menceritakan kepada kami [Rauh] berkata; Telah menceritakan kepada kami [Abdul Hamid bin Bahran] berkata; saya telah mendengar [Syahr bin Hausyab] berkata; Telah menceritakan kepadaku [Abu Zhabyah] berkata; ['Amr bin 'Abasah] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Muslim siapa saja yang melempar dengan satu panah di jalan Allah Azzawajalla, lalu mengenai sasarannya atau meleset, maka baginya pahala sebagaimana dia membebaskan budak dari anak Isma'il.\""},"1399":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ يَعْنِي ابْنَ جَعْفَرٍ قَالَ حَدَّثَنِي الْأَسْوَدُ بْنُ الْعَلَاءِ عَنْ حُوَىٍّ مَوْلَى سُلَيْمَانَ بْنِ عَبْدِ الْمَلِكِ عَنْ رَجُلٍ أَرْسَلَ إِلَيْهِ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ وَهُوَ أَمِيرُ الْمُؤْمِنِينَ قَالَ كَيْفَ الْحَدِيثُ الَّذِي حَدَّثْتَنِي عَنْ الصُّنَابِحِيِّ قَالَ أَخْبَرَنِي الصُّنَابِحِيُّأَنَّهُ لَقِيَ عَمْرَو بْنَ عَبَسَةَ فَقَالَ هَلْ مِنْ حَدِيثٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا زِيَادَةَ فِيهِ وَلَا نُقْصَانَ قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَعْتَقَ رَقَبَةً أَعْتَقَ اللَّهُ بِكُلِّ عُضْوٍ مِنْهَا عُضْوًا مِنْهُ مِنْ النَّارِ وَمَنْ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ بَلَغَ أَوْ قَصَّرَ كَانَ عِدْلَ رَقَبَةٍ وَمَنْ شَابَ شَيْبَةً فِي سَبِيلِ اللَّهِ كَانَ لَهُ نُورًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Bakar] Telah menceritakan kepada kami [Abdul Hamid] yaitu Ibnu Ja'far, berkata; Telah menceritakan kepadaku [Al Aswad bin Al 'Ala'] dari [Huwai] budak Sulaiman bin Abdul Malik, dari [seorang laki-laki] yang diutus oleh 'Umar bin Abdul Aziz yaitu Amirul Mukminin, berkata; bagaimana hadits yang kamu Telah menceritakan kepadaku, dari [Ash-Shunabihi] berkata; telah mengabarkan kepadaku Ash-Shunabihi sesungguhnya dia bertemu ['Amr bin 'Abasah] lalu dia berkata; apakah ada hadits dari Rasulullah Shallallahu'alaihiwasallam yang di dalamnya tidak ada tambahan atau hal yang dikurangi. Maka dia menjawab, ya, saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa membebaskan seorang budak, niscaya Allah akan membebaskan anggota tubuhnya dari neraka lantaran setiap anggota tubuh budak yang dimerdekakannya. Barangsiapa yang melempar dengan satu panah di jalan Allah, lalu mengenai sasarannya atau meleset, menyamai membebaskan budak. Barangsiapa yang beruban satu uban saja di jalan Allah, dia mendapatkan cahaya pada Hari Kiamat.\""},"1400":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَابْنُ جَعْفَرٍ الْمَعْنَى قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْفَيْضِ قَالَ عَبْدُ الرَّحْمَنِ فِي حَدِيثِهِ سَمِعْتُ سُلَيْمَ بْنَ عَامِرٍ يَقُولُكَانَ بَيْنَ مُعَاوِيَةَ وَبَيْنَ الرُّومِ عَهْدٌ وَكَانَ يَسِيرُ نَحْوَ بِلَادِهِمْ حَتَّى يَنْقَضِيَ الْعَهْدُ فَيَغْزُوَهُمْ فَجَعَلَ رَجُلٌ عَلَى دَابَّةٍ يَقُولُ وَفَاءٌ لَا غَدْرٌ وَفَاءٌ لَا غَدْرٌ فَإِذَا هُوَ عَمْرُو بْنُ عَبَسَةَ فَسَأَلْتُهُ عَنْ ذَلِكَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ بَيْنَهُ وَبَيْنَ قَوْمٍ عَهْدٌ فَلَا يَحِلَّ عُقْدَةً وَلَا يَشُدَّهَا حَتَّى يَمْضِيَ أَمَدُهَا أَوْ يَنْبِذَ إِلَيْهِمْ عَلَى سَوَاءٍ فَرَجَعَ مُعَاوِيَةُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Ibnu Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Al faidl] Abdurrahman berkata dalam hadisnya, saya mendengar [Sulaim bin 'Amir] berkata; telah terjadi perjanjian antara Mu'awiyah dan orang Romawi. Lalu (Mu'awiyah radliyallahu'anhu) berjalan menuju ke Romawi. Hingga saat perjanjian telah selesai, ia menyerbu mereka. Lalu ada seorang laki-laki yang menaiki kendaraannya dan berkata; \"Penuhilah janji, jangan ada ada khianat. Penuhilah janji, jangan ada khianat.\" Ternyata orang itu adalah ['Amru bin 'Abasah]. Lalu saya menanyakan hal itu, dan dia berkata; \"Saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Barangsiapa yang mengikat perjanjian dengan suatu kaum, ia tidak boleh melepasnya, atau menarik janjinya sampai perjanjian itu habis atau keduanya sama-sama membatalkannya.\" Lalu Mu'awiyah Radliyallahu'anhu kembali."},"1401":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ مَا الْإِسْلَ��مُ قَالَ أَنْ يُسْلِمَ قَلْبُكَ لِلَّهِ عَزَّ وَجَلَّ وَأَنْ يَسْلَمَ الْمُسْلِمُونَ مِنْ لِسَانِكَ وَيَدِكَ قَالَ فَأَيُّ الْإِسْلَامِ أَفْضَلُ قَالَ الْإِيمَانُ قَالَ وَمَا الْإِيمَانُ قَالَ تُؤْمِنُ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَالْبَعْثِ بَعْدَ الْمَوْتِ قَالَ فَأَيُّ الْإِيمَانِ أَفْضَلُ قَالَ الْهِجْرَةُ قَالَ فَمَا الْهِجْرَةُ قَالَ تَهْجُرُ السُّوءَ قَالَ فَأَيُّ الْهِجْرَةِ أَفْضَلُ قَالَ الْجِهَادُ قَالَ وَمَا الْجِهَادُ قَالَ أَنْ تُقَاتِلَ الْكُفَّارَ إِذَا لَقِيتَهُمْ قَالَ فَأَيُّ الْجِهَادِ أَفْضَلُ قَالَ مَنْ عُقِرَ جَوَادُهُ وَأُهْرِيقَ دَمُهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ عَمَلَانِ هُمَا أَفْضَلُ الْأَعْمَالِ إِلَّا مَنْ عَمِلَ بِمِثْلِهِمَا حَجَّةٌ مَبْرُورَةٌ أَوْ عُمْرَةٌ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Abu Qilabah] dari ['Amr bin 'Abasah] berkata; ada seorang laki-laki berkata; \"Wahai Rasulullah, apa maksud Islam?\" beliau menjawab, \"Kamu menyerahkan hatimu kepada Allah Azzawajalla dan orang muslim selamat dari lidah dan tanganmu.\" Dia bertanya, \"Islam manakah yang paling utama?\" Beliau menjawab, \"Iman.\" Dia bertanya, \"Apa maksud iman?\" Beliau bersabda: \"Kamu beriman kepada Allah, para Malaikat-Nya, Kitab-Kitab-Nya, Rasul-Rasul-Nya dan kebangkitan setelah mati.\" Dia bertanya lagi, \"Iman apa yang paling utama?\" beliau bersabda: \"Hijrah.\" dia bertanya, \"Apa maksud hijrah itu?\" beliau bersabda: \"Kamu meninggalkan kejelekan.\" Dia bertanya, \"Hijrah apa yang paling utama?.\" Beliau menjawab, \"Jihad.\" Dia bertanya, \"Apakah jihad itu?\" beliau bersabda: \"Kamu memerangi orang kafir jika kamu menemui mereka.\" dia bertanya, \"Jihad apa yang paling utama?\" beliau menjawab, \"Barangsiapa yang kudanya disembelih dan darahnya ditumpahkan.\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ada dua amalan yang kedua amalan itu adalah paling utama kecuali orang itu melakukan amalan semisal, haji mabrur atau umrah.\""},"1402":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ وَيَعْلَى وَيَزِيدُ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ لَا تَتَّخِذُوا بُيُوتَكُمْ قُبُورًا صَلُّوا فِيهَا","id":"Telah menceritakan kepada kami [Ibnu Numair] dan [Ya'la] dan [Yazid] berkata; Telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] dari [Zaid bin Khalid Al Juhani] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Janganlah kalian menjadikan rumah kalian sebagai kuburan. Shalatlah kalian di rumah.\""},"1403":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى ح وَيَزِيدُ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى عَنِ ابْنِ أَبِي عَمْرَةَ عَنْ أَبِي عَمْرَةَ أَنَّهُ سَمِعَ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ قَالَ يَزِيدُ أَنَّ أَبَا عَمْرَةَ مَوْلَى زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُ سَمِعَ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّيُحَدِّثُ أَنَّ رَجُلًا مِنْ الْمُسْلِمِينَ تُوُفِّيَ بِخَيْبَرَ وَأَنَّهُ ذُكِرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَلُّوا عَلَى صَاحِبِكُمْ قَالَ فَتَغَيَّرَتْ وُجُوهُ الْقَوْمِ لِذَلِكَ فَلَمَّا رَأَى الَّذِي بِهِمْ قَالَ إِنَّ صَاحِبَكُمْ غَلَّ فِي سَبِيلِ اللَّهِ فَفَتَّشْنَا مَتَاعَهُ فَوَجَدْنَا فِيهِ خَرَزًا مِنْ خَرَزِ الْيَهُودِ مَا يُسَاوِي دِرْهَمَيْنِ","id":"Telah menceritakan kepada kami [Ibnu Numair] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya] -lewat jalur periwayatan lain --dan [Yazid] berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Yahya] dari [Ibnu Abu 'Amrah] dari [Abu Amrah] sesungguhnya telah mendengar [Zaid bin Khalid Al Juhani] Yazid berkata; sesungguhnya [Abu 'Amrah] budak Zaid bin Khalid Al Juhani, telah mendengar [Zaid bin Khalid Al Juhani] menceritakan sesungguhnya ada seorang laki-laki dari kalangan kaum muslimin wafat di Khaibar, lalu disebutkan pada Rasulullah Shallallahu'alaihiwasallam lalu beliau bersabda: \"Shalatlah kalian atas saudara kalian.\" (Zaid bin Khalid Al Juhani Radliyallahu'anhu) berkata; \"Lalu wajah orang-orang berubah karena hal itu.\" Tatkala (Rasulullah Shallallahu'alaihiwasallam) melihat mereka bersabda: \"Sahabat kalian ini telah mengambil rampasan sebelum dibagi di jalan Allah.\" Lalu kami memeriksanya pada perbekalannya lalu kami mendapatkan permata Yahudi yang setara dengan dua dirham.\""},"1404":{"ar":"حَدَّثَنَا يَعْلَى وَمُحَمَّدٌ ابْنَا عُبَيْدٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنْ أَشُقَّ وَقَالَ مُحَمَّدٌ لَوْلَا أَنْ يُشَقَّ عَلَى أُمَّتِي لَأَخَّرْتُ صَلَاةَ الْعِشَاءِ إِلَى ثُلُثِ اللَّيْلِ وَلَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah menceritakan kepada kami [Ya'la] dan [Muhammad] anak laki-laki 'Ubaid berkata; Telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin Abdurrahman] dari [Zaid bin Khalid Al Juhani] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Seandainya tidak karena memberatkan.\" Muhammad berkata dengan redaksi, \"Seandainya tidak memberatkan umatku, niscaya saya akan mengakhirkan shalat isya' sampai sepertiga malam dan saya memerintahkan mereka untuk bersiwak setiap shalat.\""},"1405":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَلَعَنَ رَجُلٌ دِيكًا صَاحَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلْعَنْهُ فَإِنَّهُ يَدْعُو إِلَى الصَّلَاةِحَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ زَيْدِ بْنِ خَالِدٍ قَالَ صَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ بِالْحُدَيْبِيَةِ فِي أَثَرِ سَمَاءٍ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Shalih bin Kaisan] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Zaid bin Khalid Al Juhani] berkata; Ada seorang laki-laki yang melaknat ayam jago yang berkokok di samping Nabi Shallallahu'alaihiwasallam. lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Janganlah kamu melaknatnya, sebab jago itu memanggil untuk shalat.\" Telah menceritakan kepada kami [Abdurrazzaq] Telah menceritakan kepada kami [Ma'mar] dari [Shalih bin Kaisan] dari ['Ubaidullah bin Abdullah] dari [Zaid bin Khalid] berkata; Nabi Shallallahu'alaihiwasallam shalat subuh bersama kami di Hudaibiyah setelah hujan, lalu menyebutkan hadi secara lengkap."},"1406":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَابْنُ بَكْرٍ قَالَا أَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْأَعْمَى يُخْبِرُ عَنْ رَجُلٍ يُقَالُ لَهُ السَّائِبُ مَوْلَى الْفَارِسِيِّينَ وَقَالَ ابْنُ بَكْرٍ مَوْلًى لِفَارِسَ وَقَالَ حَجَّاجٌ مَوْلَى الْفَارِسِيِّ عَنْ زَيْدِ بْنِ خَالِدٍأَنَّهُ رَآهُ عُمَرُ بْنُ الْخَطَّابِ وَهُوَ خَلِيفَةٌ رَكَعَ بَعْدَ الْعَصْرِ رَكْعَتَيْنِ فَمَشَى إِلَيْهِ فَضَرَبَهُ بِالدِّرَّةِ وَهُوَ يُصَلِّي كَمَا هُوَ فَلَمَّا انْصَرَفَ قَالَ زَيْدٌ يَا أَمِيرَ الْمُؤْمِنِينَ فَوَاللَّهِ لَا أَدَعُهُمَا أَبَدًا بَعْدَ أَنْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهِمَاقَالَ فَجَلَسَ إِلَيْهِ عُمَرُ وَقَالَ يَا زَيْدُ بْنَ خَالِدٍ لَوْلَا أَنِّي أَخْشَى أَنْ يَتَّخِذَهَا النَّاسُ سُلَّمًا إِلَى الصَّلَاةِ حَتَّى اللَّيْلِ لَمْ أَضْرِبْ فِيهِمَا","id":"Telah menceritakan kepada kami [Abdurrazzaq] dan [Ibnu Bakar] berkata; telah memberitakan kepada kami [Ibnu Juraij] berkata; saya telah mendengar [Abu Sa'id Al A'ma] mengabarkan dari [seorang laki-laki] yang bernama As-Sa`ib, budak orang-orang Persi. [Ibnu Bakar] berkata; budak orang Persi dan [Hajjaj] berkata; budak salah seorang Persi, dari [Zaid bin Khalid], 'Umar bin Al Khattab sang khalifah melihat dia shalat dua rekaat setelah ashar, khalifah kontan mendatanginya dan memukulnya dengan tongkat, dan tetap shalat saja tanpa mempedulikannya. Setelah selesai, Zaid berkata; \"Wahai Amirul Mukminin, demi Allah saya tidak akan meninggalkannya selamanya setelah saya melihat Rasulullah Shallallahu'alaihiwasallam melakukannya.\" (Zaid bin Khalid Al Juhani Radliyallahu'anhu) berkata; lalu 'Umar mendatanginya. Lalu dia berkata; \"Wahai Zaid bin Khalid, seandainya saya tidak takut orang-orang mengambil sebagai sarana shalat sampai malam, maka saya tidak memukul karenanya.\""},"1407":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا فَزَنَى بِامْرَأَتِهِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي الرَّجْمَ فَافْتَدَيْتُ مِنْهُ بِوَلِيدَةٍ وَبِمِائَةِ شَاةٍ ثُمَّ أَخْبَرَنِي أَهْلُ الْعِلْمِ أَنَّ عَلَى ابْنِي جَلْدَ مِائَةٍ وَتَغْرِيبَ عَامٍ وَأَنَّ عَلَى امْرَأَةِ هَذَا الرَّجْمَ حَسِبْتُ أَنَّهُ قَالَ فَاقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ أَمَّا الْغَنَمُ وَالْوَلِيدَةُ فَرَدٌّ عَلَيْكَ وَأَمَّا ابْنُكَ فَعَلَيْهِ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ ثُمَّ قَالَ لِرَجُلٍ مِنْ أَسْلَمَ يُقَالُ لَهُ أُنَيْسٌ قُمْ يَا أُنَيْسُ فَاسْأَلْ امْرَأَةَ هَذَا فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Abu Hurairah] dan [Zaid bin Khalid Al Juhani], ada seorang laki-laki mendatangi Nabi Shallallahu'alaihiwasallam lalu berkata; \"Anak saya adalah disewa orang ini, lalu dia berzina dengan istrinya, lantas mereka mengabariku bahwa anakku harus di rajam. Lalu saya menebusnya dengan seorang budak wanita dan seratus kambing, lalu ahli ilmu mengabarkan kepadaku bahwa anak saya harus dicambuk seratus kali dan diasingkan selama satu tahun sedang sang wanita tersebut dirajam, \" saya (Zaid bin Khalid Al Juhani Radliyallahu'anhu) menyangka dia berkata; \"Putuskanlah dengan kitabullah!\" Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, saya akan memutuskan kepada kalian berdua dengan kitab Allah. Kambing dan budak wanita itu dikembalikan kepadamu, sedang anakmu dicambuk seratus kali dan diasingkan selama satu tahun, \" lalu dikatakan kepada seorang dari Bani Aslam yang bernama Unais, \"Bangunlah Wahai Unais, dan tanyalah wanita itu, jika dia mengakuinya maka rajamlah.\""},"1408":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَقَدْ غَزَا وَمَنْ خَلَفَهُ فَقَدْ غَزَا","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amr] berkata; Telah menceritakan kepada kami [Ibnu Wahb] dari ['Amr bin Al Harits] dari [Bukair bin Al Asysaj] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa memberi bekal kepada orang yang hendak berperang di jalan Allah Azzawajalla maka dia telah berperang, dan barangsiapa membiarkan seseorang untuk berangkat perang, dan ia menggantikan posisinya untuk menuntaskan keperluan rumahtangganya berarti dia telah berperang.\""},"1409":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى أَنْبَأَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عُثْمَانَ عَنْ أَبِي عَمْرَةَ الْأَنْصَارِيِّ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ إِنْ شَاءَ اللَّهُ قَالَ إِسْحَاقُ قَالَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِ الشُّهَدَاءِ الَّذِي يَأْتِي بِالشَّهَادَةِ قَبْلَ أَنْ يُسْأَلَهَا","id":"Telah menceritakan kepada kami [Ishaq bin Isa] telah memberitakan kepada kami [Malik] dari [Abdullah bin Abu Bakar] dari [Bapaknya] dari [Abdullah bin 'Amr bin 'Utsman] dari [Abu Amrah Al Anshari] dari [Zaid bin Khalid Al Juhani] jika Allah menghendaki, Ishaq berkata; sesungguhnya Nabi Shallallahu'alaihiwasallam bersabda: \"Maukah saya kabarkan tentang sebaik-baik saksi?. Yaitu orang yang memberikan kesaksian sebelum diminta untuk untuk bersaksi.\""},"1410":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ وَزَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ وَشَبْلًا قَالَ سُفْيَانُ قَالَ بَعْضُ النَّاسِ ابْنَ مَعْبَدٍ وَالَّذِي حَفِظْتُ شِبْلًا قَالُواكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ رَجُلٌ فَقَالَ أَنْشُدُكَ اللَّهَ إِلَّا قَضَيْتَ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَامَ خَصْمُهُ وَكَانَ أَفْقَهَ مِنْهُ فَقَالَ صَدَقَ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ عَزَّ وَجَلَّ وَأْذَنْ لِي فَأَتَكَلَّمَ قَالَ قُلْ قَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا وَإِنَّهُ زَنَى بِامْرَأَتِهِ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَخَادِمٍ ثُمَّ سَأَلْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي جَلْدَ مِائَةٍ وَتَغْرِيبَ عَامٍ وَعَلَى امْرَأَةِ هَذَا الرَّجْمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ عَزَّ وَجَلَّ الْمِائَةُ شَاةٍ وَالْخَادِمُ رَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَاغْدُ يَا أُنَيْسُ رَجُلٌ مِنْ أَسْلَمَ عَلَى امْرَأَةِ هَذَا فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا فَغَدَا عَلَيْهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abdullah] sesungguhnya telah mendengar dari [Abu Hurairah] [Zaid bin Khalid Al Juhani] dan [Syabl] Sufyan berkata; sebagian manusia berkata; Ibnu Ma'bad, dan yang saya hafal adalah Syibl, mereka berkata; \"Kami sedang bersama Rasulullah Shallallahu'alaihiwasallam lalu ada seorang laki-laki yang berdiri lalu berkata; 'demi Allah saya meminta anda untuk memutuskan kepada kami dengan kitab Allah'.\" Lalu lawannya berdiri dan dia lebih faqih darinya, lalu berkata; \"Benar. Putuskanlah kepada kami dengan kitab Allah Azzawajalla dan ijinkanlah untuk saya ungkapkan.\" Beliau bersabda: \"Katakanlah!\" (Zaid bin Khalid Al Juhani Radliyallahu'anhu) berkata; \"Anak saya sedang disewa orang ini, lalu anakku berzina dengan istrinya, lalu aku pun menebusnya dengan seratus kambing dan seorang pelayan, lalu saya bertanya beberapa orang dari kalangan ahli ilmu, mengabarkan kepadaku bahwa anak saya harus dicambuk seratus kali dan diasingkan selama satu tahun dan wanita tersebut dirajam, \" lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sungguh saya akan memutuskan kepada kalian berdua dengan kitab Allah Azzawajalla. Seratus kambing dan pelayan itu akan dikembalikan kepadamu. Anakmu akan dicambuk seratus kali dan diasingkan selama satu tahun. Pergilah Wahai Unais, -seorang laki-laki dari Aslam-dan tanyalah wanita itu, jika dia mengakuinya maka rajamlah.\" Lalu dia menemuinya lalu wanita itu mengakuinya lalu (Unais RA) merajamnya."},"1411":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ وَشَبْلٍ قَالُواسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْأَمَةِ تَزْنِي قَبْلَ أَنْ تُحْصَنَ قَالَ اجْلِدُوهَا فَإِنْ عَادَتْ فَاجْلِدُوهَا فَإِنْ عَادَتْ فَاجْلِدُوهَا فَإِنْ عَادَتْ فَبِيعُوهَا وَلَوْ بِضَفِيرٍ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Abu Hurairah] [Zaid bin Khalid] dan [Syabl] mereka bersabda: \" Nabi Shallallahu'alaihiwasallam ditanya tentang seorang budak wanita yang berzina sebelum haid. Beliau bersabda: \"Cambukklah dia, jika dia mengulanginya, cambuklah. Jika dia mengulanginya, maka cambukalah. jika dia mengulanginya maka juallah walau dengan rambut yang dianyam.\""},"1412":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي إِسْمَاعِيلُ بْنُ رَجَاءٍ قَالَ سَمِعْتُ أَوْسَ بْنَ ضَمْعَجٍ قَالَ سَمِعْتُ أَبَا مَسْعُودٍ الْأَنْصَارِيَّ الْبَدْرِيَّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَؤُمُّ الْقَوْمَ أَقْرَؤُهُمْ لِكِتَابِ اللَّهِ تَعَالَى وَأَقْدَمُهُمْ قِرَاءَةً فَإِنْ كَانَتْ قِرَاءَتُهُمْ سَوَاءً فَلْيَؤُمَّهُمْ أَقْدَمُهُمْ هِجْرَةً فَإِنْ كَانَ هِجْرَتُهُمْ سَوَاءً فَلْيَؤُمَّهُمْ أَكْبَرُهُمْ سِنًّا وَلَا يُؤَمُّ الرَّجُلُ فِي أَهْلِهِ وَلَا فِي سُلْطَانِهِ وَلَا يُجْلَسُ عَلَى تَكْرِمَتِهِ فِي بَيْتِهِ إِلَّا أَنْ يَأْذَنَ لَكَ أَوْ إِلَّا بِإِذْنِهِ","id":"Telah menceritakan kepada kami ['Affan] berkata; Telah menceritakan kepada kami [Syu'bah] berkata; telah mengabarkan kepadaku [Isma'il bin Raja'] berkata; saya telah mendengar [Aus bin Dlam'aj] berkata; saya telah mendengar [Abu Mas'ud Al Anshari Al Badari] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Orang yang menjadi imam suatu kaum adalah orang yang menguasai dalam membaca kitab Allah Ta'ala, dan orang yang lebih mula-mula membacanya. Jika bacaannya sama, maka setelahnya adalah yang lebih dulu hijrah. Jika hijrahnya bersamaan adalah lebih tua. Janganlah seorang laki-laki menjadi imam dalam keluarga orang lain atau di wilayah yang menjadi wewenangnya dan janganlah duduk pada tikar di suatu rumah kecuali jika diijinkan, \" atau \"kecuali dengan seijinnya.\""},"1413":{"ar":"حَدَّثَنَا يَزِيدُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ إِنِّي لَأَتَأَخَّرُ فِي صَلَاةِ الْغَدَاةِ مَخَافَةَ فُلَانٍ يَعْنِي إِمَامَهُمْ قَالَ فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ غَضَبًا فِي مَوْعِظَةٍ مِنْهُ يَوْمَئِذٍ فَقَالَ أَيُّهَا النَّاسُ إِنَّ مِنْكُمْ مُنَفِّرِينَ فَأَيُّكُمْ مَا صَلَّى بِالنَّاسِ فَلْيُخَفِّفْ فَإِنَّ فِيهِمْ الضَّعِيفَ وَالْكَبِيرَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Yazid] Telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abu Mas'ud] berkata; telah datang seorang laki-laki kepada Rasulullah Shallallahu'alaihiwasallam lalu berkata; \"Wahai Rasulullah, demi Allah, sesungguhnya saya akan memperlambat shalat subuh karena saya khawatir kepada seseorang, \" yaitu imam mereka (yang biasanya shalat terlalu panjang). (Abu Mas'ud Radliyallahu'anhu) berkata; \" Dan saya tidak pernah melihat Rasulullah Shallallahu'alaihiwasallam lebih marah saat memberi nasehatnya daripada ketika itu.\" Lalu bersabda: \"Wahai manusia, sesungguhnya diantara kalian ada orang yang membuat orang kabur. Siapa saja diantara kalian yang memimpin shalat orang-orang maka ringankanlah, karena di dalamnya ada orang yang lemah, orang yang telah tua dan orang yang punya keperluan.\""},"1414":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ وَمُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا إِسْمَاعِيلُ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَأَشَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ نَحْوَ الْيَمَنِ فَقَالَ الْإِيمَانُ هَاهُنَا قَالَ أَلَا وَإِنَّ الْقَسْوَةَ وَغِلَظَ الْقُلُوبِ فِي الْفَدَّادِينَ أَصْحَابِ الْإِبِلِ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ فِي رَبِيعَةَ وَمُضَرَ قَالَ مُحَمَّدٌ عِنْدَ أُصُولِ أَذْنَابِ الْإِبِلِ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Isma'il bin Abu Khalid] dan [Muhammad bin 'Ubaid] Telah menceritakan kepada kami [Isma'il] dari [Qais bin Abu Hazim] dari [Abu Mas'ud Al Anshari] berkata; Rasulullah Shallallahu'alaihiwasallam memberi isyarat dengan tangannnya ke arah Yaman lalu bersabda: \"Iman itu di sini, ketahuilah sesungguhnya kefasikan dan kekerasan hati terjadi di orang-orang yang keras suarannya pemilik unta-unta, yaitu ditempat tanduk setan muncul, di Rabi'ah dan Mudlar.\" Muhammad berkata; \"Di pangkal ekor unta-unta.\""},"1415":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا شَرِيكٌ عَنْ عَاصِمٍ عَنِ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ عَلْقَمَةَ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ الْآيَتَيْنِ مِنْ آخِرِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","id":"Telah menceritakan kepada kami [Yahya bin Adam] Telah menceritakan kepada kami [Syarik] dari ['Ashim] dari [Musayyab bin Rafi'] dari ['Alqomah] dari [Abu Mas'ud] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang membaca dua ayat dari akhir surat Al Baqarah pada waktu malam maka itu telah cukup (untuk melindunginya dari kejahatan yang dibenci).\""},"1416":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبٍ يَعْنِي ابْنَ أَبِي ثَابِتٍ عَنْ عُبَيْدِ اللَّهِ بْنِ الْقَاسِمِ أَوْ الْقَاسِمِ بْنِ عُبَيْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي مَسْعُودٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ هَذَا الْأَمْرَ فِيكُمْ وَإِنَّكُمْ وُلَاتُهُ وَلَنْ يَزَالَ فِيكُمْ حَتَّى تُحْدِثُوا أَعْمَالًا فَإِذَا فَعَلْتُمْ ذَلِكَ بَعَثَ اللَّهُ عَزَّ وَجَلَّ عَلَيْكُمْ شَرَّ خَلْقِهِ فَيَلْتَحِيكُمْ كَمَا يُلْتَحَى الْقَضِيبُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Habib] yaitu Ibnu Abu Dzi`b dari ['Ubaidullah bin Al Qasim] atau Al Qasim bin 'Ubaidullah bin Utbah dari [Abu Mas'ud] berkata; Rasulullah Shallallahu'alaihiwasallam berkhutbah lalu bersabda: \"Sesungguhnya urusan ini berada pada kalian dan kalian adalah walinya. Dan akan tetap berada pada kalian sehingga kalian melakukan amalan yang baru. Jika kalian melakukan hal itu, niscaya Allah Azzawajalla mengutus mahluq-Nya yang paling jelek, lalu dia menguliti kalian sebagaimana kayu yang dikuliti.\""},"1417":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا اللَّيْثُ يَعْنِي ابْنَ سَعْدٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ أَنَّ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا مَسْعُودٍ عُقْبَةَ بْنَ عَمْرٍو قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] berkata; Telah menceritakan kepada kami [Laits] yaitu Ibnu Sa'ad berkata; Telah menceritakan kepadaku [Ibnu Syihab] sesungguhnya [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] mengabarinya sesungguhnya telah mendengar [Abu Mas'ud, Uqbah bin 'Amr] berkata; Rasulullah Shallallahu'alaihiwasallam melarang hasil penjualan anjing, penghasilan orang yang berzina dan upah dukun."},"1418":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ وَحَدَّثَنِي فِي الصَّلَاةِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا الْمَرْءُ الْمُسْلِمُ صَلَّى عَلَيْهِ فِي صَلَاتِهِ مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيُّ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَبْدِ رَبِّهِ الْأَنْصَارِيِّ أَخِي بَلْحَارِثِ بْنِ الْخَزْرَجِ عَنْ أَبِي مَسْعُودٍ عُقْبَةَ بْنِ عَمْرٍو قَالَأَقْبَلَ رَجُلٌ حَتَّى جَلَسَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ عِنْدَهُ فَقَالَ يَا رَسُولَ اللَّهِ أَمَّا السَّلَامُ عَلَيْكَ فَقَدْ عَرَفْنَاهُ فَكَيْفَ نُصَلِّي عَلَيْكَ إِذَا نَحْنُ صَلَّيْنَا فِي صَلَاتِنَا صَلَّى اللَّهُ عَلَيْكَ قَالَ فَصَمَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَحْبَبْنَا أَنَّ الرَّجُلَ لَمْ يَسْأَلْهُ فَقَالَ إِذَا أَنْتُمْ صَلَّيْتُمْ عَلَيَّ فَقُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ النَّبِيِّ الْأُمِّيِّ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَآلِ إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ النَّبِيِّ الْأُمِّيِّ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; dan Telah menceritakan kepadaku tentang shalawat atas Rasulullah Shallallahu'alaihiwasallam jika ada seorag muslim bershalawat tatkala dalam shalatnya, [Muhammad bin Ibrahim bin Al Harits At-Taimi] dari [Muhammad bin Abdullah bin Zaid bin Abdu Rabbihi Al Anshari] saudara Balharits bin Al Khajraj, dari [Abu Mas'ud, Uqbah bin 'Amr Al Anshari] berkata; ada seorang laki-laki yang datang sehingga dia duduk di depan Rasulullah Shallallahu'alaihiwasallam, dan kami pada saat sedang berada di samping beliau. Lalu orang itu berkata; \"Wahai Rasulullah, berkenaan ucapan salam terhadap anda kami telah mengetahuinya, lalu bagaimana kami harus mengucapkan shalawat atas anda saat kami shalat?.\" (Abu Mas'ud, Uqbah bin 'Amr Al Anshari Radliyallahu'anhu) berkata; \"Lalu Rasulullah Shallallahu'alaihiwasallam diam sampai kami berandai-andai jika si laki-laki tadi tidak menanyakannya.\" Lalu beliau bersabda: \"Jika kalian hendak mengucapkan salawat atasku, maka bacalah: ALLAHUMMA SHALLI 'ALA MUHAMMAD AN-NABIYIL UMI WA 'ALA ALI MUHAMMAD. KAMA SHALLAITA 'ALA IBRAHIM DAN KELUARGA IBRAHIM. WA BARIK 'ALA MUHAMMAD WA 'ALA ALI MUHAMMAD AN-NABIYIL UMI KAMA BARAKTA 'ALA IBRAHIM WA 'ALA ALI IBRAHIM FIL 'ALAMIN INNAKA HAMIDUN MAJID (ya Allah, berilah rahmat kepada Muhammad, Nabi yang tidak bisa membaca dan menulis dan keluarganya. Dan berilah berkah kepada Muhammad Nabi yang tidak bisa membaca dan menulis, sebagaimana Engkau telah memberi berkah kepada Ibrahim dan keluarganya. Sesungguhnya engkau Maha Terpuji dan Maha Agung), "},"1419":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ عُمَارَةَ بْنَ عُمَيْرٍ التَّيْمِيَّ يُحَدِّثُ عَنْ أَبِي مَعْمَرٍ الْأَزْدِيِّ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُجْزِئُ صَلَاةٌ لِرَجُلٍ أَوْ لِأَحَدٍ لَا يُقِيمُ ظَهْرَهُ فِي الرُّكُوعِ وَالسُّجُودِ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] berkata; saya telah mendengar [Umarah bin Umair At-Taimi] menceritakan dari [Abu Ma'mar Al Azdi] dari [Abu Mas'ud] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak sah shalat seorang laki-laki yang tidak meluruskan punggungnya dalam rukuk maupun sujud.\""},"1420":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ حَدَّثَنَا عَبْدُ اللَّهِ وَهُوَ ابْنُ الْمُبَارَكِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقِيلَ لَهُ مَا سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي زَعَمُوا قَالَ بِئْسَ مَطِيَّةُ الرَّجُلِ","id":"Telah menceritakan kepada kami [Ali bin Ishaq] Telah menceritakan kepada kami [Abdullah] yaitu Ibnu Mubarak berkata; Telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Qilabah] dari [Abu Mas'ud Al Anshari] berkata; ada yang bertanya kepadanya, \"Apa yang telah kau dengar dari Rasulullah Shallallahu'alaihiwasallam tentang perkataan 'ZA'AMU'. Beliau bersabda: \"Sejelek-jelek cara bagi seseorang.\" (maksudnya adalah yaitu orang yang banyak meriwayatkan hadits yang dia tidak tahu kesahihannya sehingga tidak aman dari kedustaan, atau kebiasaan yang paling jelek dari seseorang adalah menggunakan kalimat ZA'AMU, sebagai sarana untuk menyampaikan maksudnya lalu dia menyampaikan sebagai taklid saja Za'amu maknanya adalah mereka beranggapan) "},"1421":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ قَالَ حَدَّثَنَا سَالِمٌ الْبَرَّادُ قَالَ وَكَانَ عِنْدِي أَوْثَقَ مِنْ نَفْسِي قَالَقَالَ لَنَا أَبُو مَسْعُودٍ الْبَدْرِيُّ أَلَا أُصَلِّي لَكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَبَّرَ فَرَكَعَ فَوَضَعَ كَفَّيْهِ عَلَى رُكْبَتَيْهِ وَفُصِلَتْ أَصَابِعُهُ عَلَى سَاقَيْهِ وَجَافَى عَنْ إِبْطَيْهِ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَاسْتَوَى قَائِمًا حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ كَبَّرَ وَسَجَدَ وَجَافَى عَنْ إِبْطَيْهِ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ رَفَعَ رَأْسَهُ فَاسْتَوَى جَالِسًا حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ سَجَدَ الثَّانِيَةَ فَصَلَّى بِنَا أَرْبَعَ رَكَعَاتٍ هَكَذَا ثُمَّ قَالَ هَكَذَا كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammam] Telah menceritakan kepada kami ['Atha` bin As-Sa`ib] berkata; Telah menceritakan kepada kami [Salim Al Barad] berkata; dan menurutku dia adalah lebih tsiqah dari padaku, berkata; [Abu Mas'ud Al Badari] berkata kepada kami, \"Maukah saya berikan contoh shalat Rasulullah Shallallahu'alaihiwasallam kepada kalian?\" (Salim Al Barad Radliyallahu'anhu) berkata; \"Lalu dia bertakbir, rukuk, meletakkan kedua telapak tanganya pada lututnya dengan memisah jarinya pada betisnya dan merenggangkan kedua ketiaknya sampai semua telah menetap lalu membaca, 'SAMI'A 'ALLAHU LIMAN HAMIDAH', lalu beliau berdiri dengan lurus sampai semuanya telah menetap pada tempatnya lalu bertakbir dan bersujud dengan merenggangkan kedua ketiaknya sampai semuanya tetap pada tempatnya, lalu mengangkat kepalanya sehingga duduk dengan tetap pada tempatnya, lalu sujud untuk kedua kalinya, lalu dia shalat bersama kami empat rekaat, demikian lalu berkata; demikianlah shalat Rasulullah Shallallahu'alaihiwasallam\" atau berkata; \"demikianlah yang telah saya lihat Rasulullah Shallallahu'alaihiwasallam shalat.\""},"1422":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ بُشَيْرِ بْنِ كَعْبٍ عَنْ شَدَّادِ بْنِ أَوْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيِّدُ الِاسْتِغْفَارِ أَنْ يَقُولَ الْعَبْدُ اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ خَلَقْتَنِي وَأَنَا عَبْدُكَ وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ أَبُوءُ لَكَ بِالنِّعْمَةِ وَأَبُوءُ لَكَ بِذَنْبِي فَاغْفِرْ لِي إِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ قَالَ إِنْ قَالَهَا بَعْدَمَا يُصْبِحُ مُوقِنًا بِهَا ثُمَّ مَاتَ كَانَ مِنْ أَهْلِ الْجَنَّةِ وَإِنْ قَالَهَا بَعْدَمَا يُمْسِي مُوقِنًا بِهَا ثُمَّ مَاتَ كَانَ مِنْ أَهْلِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Husain Al Mu'allim] berkata; telah menceritakan kepadaku [Abdullah bin Buraidah] dari [Busyair bin Ka'ab] dari [Syaddad bin Aus] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Sayidul istighfar adalah seorang hamba berkata 'Ya Allah engkau adalah Rabku, tidak ada ilah kecuali Engkau. Enngkau telah menciptakannku dan saya adalah hamba-Mu. Saya berada pada perjanjian-Mu dan ancaman-Mu semampu saya. Saya menetapi kepada-Mu dengan nikmat yang ada dan saya mengadu kepada-Mu dengan dosaku. Ampunilah aku, sesungguhnya tidak ada yang mengampuni dosa kecuali Engkau. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Jika dia mengatakannya pada waktu pagi hari dalam keadaan yakin dengan-Nya, lalu dia mati maka dia termasuk dari penduduk surga. Jika dia membacanya pada waktu sore dalam keadaan yakin, lalu dia mati maka dia termasuk dari penduduk surga.\""},"1423":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍأَنَّهُ مَرَّ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْفَتْحِ عَلَى رَجُلٍ يَحْتَجِمُ بِالْبَقِيعِ لِثَمَانِ عَشْرَةَ خَلَتْ مِنْ رَمَضَانَ وَهُوَ آخِذٌ بِيَدِي فَقَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Syaddad bin Aus] sesungguhnya dia bersama Rasulullah Shallallahu'alaihiwasallam pada Fath Makkah melewati seorang yang sedang berbekam di Baqi' tanggal delapan belas bulan Ramadlan dan beliau mengambil kedua tanganku lalu bersabda: \"Orang yang berbekam dan yang dibekam berarti telah batal puasanya.\""},"1424":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ قَالَكَانَ شَدَّادُ بْنُ أَوْسٍ فِي سَفَرٍ فَنَزَلَ مَنْزِلًا فَقَالَ لِغُلَامِهِ ائْتِنَا بِالشَّفْرَةِ نَعْبَثْ بِهَا فَأَنْكَرْتُ عَلَيْهِ فَقَالَ مَا تَكَلَّمْتُ بِكَلِمَةٍ مُنْذُ أَسْلَمْتُ إِلَّا وَأَنَا أَخْطِمُهَا وَأَزُمُّهَا إِلَّا كَلِمَتِي هَذِهِ فَلَا تَحْفَظُوهَا عَلَيَّ وَاحْفَظُوا مِنِّي مَا أَقُولُ لَكُمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا كَنَزَ النَّاسُ الذَّهَبَ وَالْفِضَّةَ فَاكْنِزُوا هَؤُلَاءِ الْكَلِمَاتِ اللَّهُمَّ إِنِّي أَسْأَلُكَ الثَّبَاتَ فِي الْأَمْرِ وَالْعَزِيمَةَ عَلَى الرُّشْدِ وَأَسْأَلُكَ شُكْرَ نِعْمَتِكَ وَأَسْأَلُكَ حُسْنَ عِبَادَتِكَ وَأَسْأَلُكَ قَلْبًا سَلِيمًا وَأَسْأَلُكَ لِسَانًا صَادِقًا وَأَسْأَلُكَ مِنْ خَيْرِ مَا تَعْلَمُ وَأَعُوذُ بِكَ مِنْ شَرِّ مَا تَعْلَمُ وَأَسْتَغْفِرُكَ لِمَا تَعْلَمُ إِنَّكَ أَنْتَ عَلَّامُ الْغُيُوبِ","id":"Telah menceritakan kepada kami [Rauh] berkata; telah menceritakan kepada kami [Al Auza'i] dari [Hassan bin Athiyyah] berkata; [Syaddad bin Aus] berada dalam sebuah perjalanan lalu dia singggah pada sebuah tempat, lalu dia berkata kepada pelayannya, \"Datangkan kepada kami pisau yang akan saya kirimkanlah, \" lalu saya (Hassan bin Athiyyah) mengingkarinya. Dia berkata; \"Tidaklah saya mengucapkan perkataan dengan satu kalimat sejak saya masuk Islam kecuali saya menutupnya dan memakaianya sebagai hukum, dan saya pimpin, kecuali dua kalimat ini, maka janganlah kamu menghafalnya atasku tapi dan jagalah dariku apa yang saya katakan kepada kalian, saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika manusia telah menyimpan emas dan perak maka simpankah kalimat-kalimat ini; Ya Allah, sesungguhnya saya meminta ketetapan dalam perintah dan niat atas petunjuk. Saya meminta kepada-Mu atas syukur pada nikmatmu. Saya meminta kepada-Mu kebagusan ibadah kepada-Mu. Saya meminta kepada-Mu hati yang bersih. Saya meminta kepada-Mu lidah yang benar. Saya meminta kepada-Mu dari kebaikan yang Engkau ketahui. Saya berlindung kepada-Mu dari kejahatan apa yang Engkau ketahui. Saya meminta ampun kepada-Mu atas apa yang Engkau tahu. Sesungguhnya Engkau adalah yang mengetahui hAl hal yang ghaib."},"1425":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ مَعْمَرٌ أَخْبَرَنِي أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ شَدَّادِ بْنِ أَوْسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ زَوَى لِي الْأَرْضَ حَتَّى رَأَيْتُ مَشَارِقَهَا وَمَغَارِبَهَا وَإِنَّ مُلْكَ أُمَّتِي سَيَبْلُغُ مَا زُوِيَ لِي مِنْهَا وَإِنِّي أُعْطِيتُ الْكَنْزَيْنِ الْأَبْيَضَ وَالْأَحْمَرَ وَإِنِّي سَأَلْتُ رَبِّي عَزَّ وَجَلَّ لَا يُهْلِكُ أُمَّتِي بِسَنَةٍ بِعَامَّةٍ وَأَنْ لَا يُسَلِّطَ عَلَيْهِمْ عَدُوًّا فَيُهْلِكَهُمْ بِعَامَّةٍ وَأَنْ لَا يُلْبِسَهُمْ شِيَعًا وَلَا يُذِيقَ بَعْضَهُمْ بَأْسَ بَعْضٍ وَقَالَ يَا مُحَمَّدُ إِنِّي إِذَا قَضَيْتُ قَضَاءً فَإِنَّهُ لَا يُرَدُّ وَإِنِّي قَدْ أَعْطَيْتُكَ لِأُمَّتِكَ أَنْ لَا أُهْلِكَهُمْ بِسَنَةٍ بِعَامَّةٍ وَلَا أُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِمَّنْ سِوَاهُمْ فَيُهْلِكُوهُمْ بِعَامَّةٍ حَتَّى يَكُونَ بَعْضُهُمْ يُهْلِكُ بَعْضًا وَبَعْضُهُمْ يَقْتُلُ بَعْضًا وَبَعْضُهُمْ يَسْبِي بَعْضًا","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; [Ma'mar] telah mengabarkan kepadaku [Ayyub] dari [Abu Qilabah] dari [Abu Al Asy'asts As-Shan'ani] dari [Abu Asma` Ar Rahabi] dari [Syaddad bin Aus] sesungguhnya Nabi Shallallahu'alaihiwasallam bersabda: \" Allah Azzawajalla telah mendekatkan bumi kepadaku sehingga saya bisa melihat timurnya dan baratnya. Sesungguhnya kerajaan umatku akan sampai pada apa yang ditampakkan kepadaku. Sesungguhnya saya telah diberi dua simpanan di bumi, yang putih dan warna merah. Sesungguhnya saya meminta pada Rabku AzzaWaJalla agar tidak membinasakan umatku dengan kelaparan yang merata, agar umatku tidak dikalahkan musuh sehingga mereka hancur, Agar Allah tidak menjadikan mereka terpecah belah sehingga satau sama lainnya merasakan keganasan kepada sebagian yang lain. (Allah Azzawajalla) berfirman, 'Wahai Muhammad, sesungguhnya Aku jika telah memutuskan suatu putusan, maka tidak akan bisa ditolak. Sesungguhnya Aku telah memberikan kepadamu untuk umatmu, Aku tidak akan menghancurkan mereka dengan kelaparan yang panjang, Aku tidak akan menguasakan musuh atas mereka sehingga menghancurkan mereka secara merata, hingga justru sebagian mereka menghancurkan sebagian yang lain (terjadi konflik internal muslimin) dan sebagian mereka membunuh yang lainnya. Sebagian menawan sebagian yang lain.\""},"1426":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَحَفِظْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اثْنَتَيْنِ أَنَّهُ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَي��ءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ ثُمَّ لِيُرِحْ ذَبِيحَتَهُ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah bercerita kepada kami [Ma'mar] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Syaddad bin Aus] berkata; \"Saya telah menghafal dari Rasulullah Shallallahu'alaihiwasallam dua hal, beliau bersabda: 'Allah Azzawajalla telah menetapkan kebaikan atas setiap sesuatu', jika kalian membunuh maka perbaguslah cara membunuhnya dan jika kalian menyembelih maka perbaguslah cara menyembelihnya, tajamkanlah pisaunya dan buatlah hewan sembelihan tidak merasakan kesakitan.\""},"1427":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ أَبِي أَسْمَاءَ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Abu Asma`] dari [Syaddad bin Aus] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang yang membekam dan dibekam telah batal puasanya.\""},"1428":{"ar":"حَدَّثَنَا هَيْثَمُ بْنُ خَارِجَةَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ رَاشِدِ بْنِ دَاوُدَ الصَّنْعَانِيِّ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّأَنَّهُ رَاحَ إِلَى مَسْجِدِ دِمَشْقَ وَهَجَّرَ بِالرَّوَاحِ فَلَقِيَ شَدَّادَ بْنَ أَوْسٍ وَالصُّنَابِحِيُّ مَعَهُ فَقُلْتُ أَيْنَ تُرِيدَانِ يَرْحَمُكُمَا اللَّهُ قَالَا نُرِيدُ هَاهُنَا إِلَى أَخٍ لَنَا مَرِيضٍ نَعُودُهُ فَانْطَلَقْتُ مَعَهُمَا حَتَّى دَخَلَا عَلَى ذَلِكَ الرَّجُلِ فَقَالَا لَهُ كَيْفَ أَصْبَحْتَ قَالَ أَصْبَحْتُ بِنِعْمَةٍ فَقَالَ لَهُ شَدَّادٌ أَبْشِرْ بِكَفَّارَاتِ السَّيِّئَاتِ وَحَطِّ الْخَطَايَا فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَقُولُ إِنِّي إِذَا ابْتَلَيْتُ عَبْدًا مِنْ عِبَادِي مُؤْمِنًا فَحَمِدَنِي عَلَى مَا ابْتَلَيْتُهُ فَإِنَّهُ يَقُومُ مِنْ مَضْجَعِهِ ذَلِكَ كَيَوْمِ وَلَدَتْهُ أُمُّهُ مِنْ الْخَطَايَا وَيَقُولُ الرَّبُّ عَزَّ وَجَلَّ أَنَا قَيَّدْتُ عَبْدِي وَابْتَلَيْتُهُ وَأَجْرُوا لَهُ كَمَا كُنْتُمْ تُجْرُونَ لَهُ وَهُوَ صَحِيحٌ","id":"Telah menceritakan kepada kami [Husyaim bin Kharijah] telah menceritakan kepada kami [Isma'il bin 'Ayasy] dari [Rasyid bin Daud As-Shan'ani] dari [Abu Al Asy'ats As-Shan'ani] sesungguhnya dia berangkat ke Masjid Damaskus pada tengah hari dalam berjalan. lalu dia bertemu dengan [Syaddad bin Aus] dan As-Shunabihi bersamanya, lalu saya (Syaddad bin Aus Radliyallahu'anhu) bertanya, \"Kemana kalian hendak pergi, semoga Allah merahmati kalian.\" Mereka berdua menjawab, \"Kami hendak kesini, karena saudara sakit, kami hendak menjenguknya, \" saya berangkat bersama mereka berdua sampai kami bertemu dengan orang itu.\" Lalu mereka berdua berkata kepadanya, \"Bagaimana kabarmu pagi ini?\" dia menjawab, \"Saya pagi ini dalam keadaan nikmat.\" Lalu Syadad berkata kepadanya, \"Berilah kabar gembira dengan pelebur kejelekkan dan penghapus kesalahan. Sesungguhnya saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Allah Azzawajalla berfirman, Aku jika menguji seorang hamba dari hamba-Ku yang beriman, lalu dia memuji-Ku atas apa yang Aku timpakan kepadanya, sesungguhnya dia bangun dari tempat tidurnya sebagaimana dia saat dari ibunya, dari kesalahan.\" Rabb AzzaWaJalla berfirman, \"Aku telah menahan hamba-Ku (dari amal shalih), maka berilah dia ganjaran sebagaimana kalian memberinya ganjaran dikala dia sehat.\""},"1429":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنِي عَبْدُ الْوَاحِدِ بْنُ زَيْدٍ أَخْبَرَنَا عُبَادَةُ بْنُ نُسَيٍّ عَنْ شَدَّادِ بْنِ أَوْسٍأَنَّهُ بَكَى فَقِيلَ لَهُ مَا يُبْكِيكَ قَالَ شَيْئًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهُ فَذَكَرْتُهُ فَأَبْكَانِي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَتَخَوَّفُ عَلَى أُمَّتِي الشِّرْكَ وَالشَّهْوَةَ الْخَفِيَّةَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَتُشْرِكُ أُمَّتُكَ مِنْ بَعْدِكَ قَالَ نَعَمْ أَمَا إِنَّهُمْ لَا يَعْبُدُونَ شَمْسًا وَلَا قَمَرًا وَلَا حَجَرًا وَلَا وَثَنًا وَلَكِنْ يُرَاءُونَ بِأَعْمَالِهِمْ وَالشَّهْوَةُ الْخَفِيَّةُ أَنْ يُصْبِحَ أَحَدُهُمْ صَائِمًا فَتَعْرِضُ لَهُ شَهْوَةٌ مِنْ شَهَوَاتِهِ فَيَتْرُكُ صَوْمَهُ","id":"Telah menceritakan kepada kami [Zaid bin Al Habhab] berkata; telah menceritakan kepadaku [Abdul Wahid bin Zaid] telah menceritakan kepada kami ['Ubadah bin Nusa] dari [Syaddad bin Aus] sesungguhnya dia menangis, lalu ditanyakan kepadanya, \"Apa yang membuat anda menangis?\" lalu dia menjawab, \"Saya sangat takut kepada umatku tertimpa kesyirikan dan syahwat yang tersembunyi.\" (Syaddad bin Aus Radliyallahu'anhu) berkata; saya berkata; \"Wahai Rasulullah, apakah umatmu akan melakukan kesyirikan setelah anda?.\" Beliau menjawab, \"Ya, namun mereka tidak menyembah matahari, bulan, batu atau berhala tapi mereka melakukan riya' dengan amalan-amalan mereka dan syahwat yang tersembunyi. Pagi hari dalam keadaan puasa lalu ada syahwat yang datang hingga dia meninggalkan puasanya.\""},"1430":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَبُو الْيَمَانِ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ رَاشِدِ بْنِ دَاوُدَ عَنْ يَعْلَى بْنِ شَدَّادٍ قَالَ حَدَّثَنِي أَبِي شَدَّادُ بْنُ أَوْسٍ وَعُبَادَةُ بْنُ الصَّامِتِ حَاضِرٌ يُصَدِّقُهُ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ فِيكُمْ غَرِيبٌ يَعْنِي أَهْلَ الْكِتَابِ فَقُلْنَا لَا يَا رَسُولَ اللَّهِ فَأَمَرَ بِغَلْقِ الْبَابِ وَقَالَ ارْفَعُوا أَيْدِيَكُمْ وَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَرَفَعْنَا أَيْدِيَنَا سَاعَةً ثُمَّ وَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ ثُمَّ قَالَ الْحَمْدُ لِلَّهِ اللَّهُمَّ بَعَثْتَنِي بِهَذِهِ الْكَلِمَةِ وَأَمَرْتَنِي بِهَا وَوَعَدْتَنِي عَلَيْهَا الْجَنَّةَ وَإِنَّكَ لَا تُخْلِفُ الْمِيعَادَ ثُمَّ قَالَ أَبْشِرُوا فَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ غَفَرَ لَكُمْ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi' Abu Al Yaman] berkata; telah menceritakan kepada kami [Isma'il bin 'Ayasy] dari [Rasyid bin Daud] dari [Ya'la bin Syadad] berkata; telah menceritakan kepadaku [Abu syadad bin Aus] dan ['Ubadah bin Shamit] datang membenarkannya berkata; kami bersama Rasulullah Shallallahu'alaihiwasallam lalu beliau bertanya, \"Apakah diantara kalian ada orang yang asing yaitu Ahli Kitab?\". Lalu kami menjawab, \"Tidak Wahai Rasulullah, \" lalu beliau menyuruh untuk menutup pintu dan bersabda: \"Angkatlah tangan kalian dan katakanlah, tidak ada tuhan selain Allah, \" lalu kami mengangkat tangan kami beberapa saat lalu Rasulullah Shallallahu'alaihiwasallam meletakkan tangan beliau lalu bersabda: \"Segala Puji bagi Allah, Ya Allah, Engkau telah mengutus kami dengan kalimat ini dan Engkau telah memerintahkanya dengannya dan Engkau telah menjanjikan kepada kami dengan syurga. Sesungguhnya Engkau tidak akan menyelisihi janji, \" lalu (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Berilah kabar gembira, sesungguhnya Allah Azzawajalla telah mengampuni kalian.\""},"1431":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ قَالَ أَخْبَرَنَا أَبُو بَكْرِ بْنُ أَبِي مَرْيَمَ عَنْ ضَمْرَةَ بْنِ حَبِيبٍ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَيِّسُ مَنْ دَانَ نَفْسَهُ وَعَمِلَ لِمَا بَعْدَ الْمَوْتِ وَالْعَاجِزُ مَنْ أَتْبَعَ نَفْسَهُ هَوَاهَا وَتَمَنَّى عَلَى اللَّهِ","id":"Telah menceritakan kepada kami [Ali bin Ishaq] berkata; telah mengabarkan kepada kami [Abdullah] yaitu Ibnu Mubarak berkata; telah mengabarkan kepada kami [Abu Bakar bin Abu Maryam] dari [Dlamrah bin Habib] dari [Syaddad bin Aus] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang yang cerdas adalah orang yang menghitung-hitung dirinya dan beramal untuk setelah kematian, sebaliknya orang yang lemah adalah orang yang mengikuti jiwanya dengan hawa nafsunya dan berangan-angan kepada Allah.\""},"1432":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ صَالِحٍ عَنْ ضَمْرَةَ بْنِ حَبِيبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو السُّلَمِيِّ أَنَّهُ سَمِعَ الْعِرْبَاضَ بْنَ سَارِيَةَ قَالَوَعَظَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْعِظَةً ذَرَفَتْ مِنْهَا الْعُيُونُ وَوَجِلَتْ مِنْهَا الْقُلُوبُ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّ هَذِهِ لَمَوْعِظَةُ مُوَدِّعٍ فَمَاذَا تَعْهَدُ إِلَيْنَا قَالَ قَدْ تَرَكْتُكُمْ عَلَى الْبَيْضَاءِ لَيْلُهَا كَنَهَارِهَا لَا يَزِيغُ عَنْهَا بَعْدِي إِلَّا هَالِكٌ وَمَنْ يَعِشْ مِنْكُمْ فَسَيَرَى اخْتِلَافًا كَثِيرًا فَعَلَيْكُمْ بِمَا عَرَفْتُمْ مِنْ سُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الرَّاشِدِينَ الْمَهْدِيِّينَ وَعَلَيْكُمْ بِالطَّاعَةِ وَإِنْ عَبْدًا حَبَشِيًّا عَضُّوا عَلَيْهَا بِالنَّوَاجِذِ فَإِنَّمَا الْمُؤْمِنُ كَالْجَمَلِ الْأَنِفِ حَيْثُمَا انْقِيدَ انْقَادَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Mu'awiyah] yaitu Ibnu Shalih dari [Dlamrah bin Habib] dari [Abdurrahman bin 'Amr As-Sulami] sesungguhnya telah mendengar [Al 'Irbadl bin Sariyah] berkata; Rasulullah Shallallahu'alaihiwasallam memberi nasehat kepada kami dengan nasehat yang menyebabkan mata bercucuran dan hati menjadi tergetar. Kami bertanya, \"Wahai Rasulullah, sesungguhnya ini adalah nasehat perpisahan, apa yang anda janjikan kepada kami?\". Beliau bersabda: \"Sungguh saya telah meninggalkan kalian dalam keadaan yang sangat jelas, malamnya sebagaimana siangnya. Tidak akan menyeleweng setelahku kecuali dia akan binasa. Barangsiapa yang hidup di antara kalian akan melihat perselisihan yang banyak. Maka berpeganglah dengan apa yang kalian ketahui dari sunnahku dan sunnah Khulafa' Rasyidin yang mendapat petunjuk. Kalian harus taat, walau terhadap hamba dari Habasyah, gigitlah dengan gigi geraham. Hanyasanya seorang mukmin itu laksana unta yang penurut, kemana dituntun dia akan nurut.\""},"1433":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ صَالِحٍ عَنْ يُونُسَ بْنِ سَيْفٍ عَنِ الْحَارِثِ بْنِ زِيَادٍ عَنْ أَبِي رُهْمٍ عَنْ عِرْبَاضِ بْنِ سَارِيَةَ قَالَدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى السَّحُورِ فِي رَمَضَانَ فَقَالَ هَلُمَّ إِلَى هَذَا الْغِذَاءِ الْمُبَارَكِ","id":"Telah menceritakan kepada kami [Hammad bin khlaid Al Khayyath] telah menceritakan kepada kami [Mu'awiyah] yaitu Ibnu Shalih, dari [Yunus bin Saif] dari [Al Harits bin Ziyad] dari [Abu Ruhm] dari [Al 'Irbadl bin Sariyah] berkata; Rasulullah Shallallahu'alaihiwasallam memanggilku untuk sahur pada Ramadlan lalu beliau bersabda: \"Marilah kita menikmati makanan yang berbarakah ini.\""},"1434":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ حَدَّثَنَا خَالِدُ بْنُ مَعْدَانَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو السُّلَمِيُّ وَحُجْرُ بْنُ حُجْرٍ قَالَاأَتَيْنَا الْعِرْبَاضَ بْنَ سَارِيَةَ وَهُوَ مِمَّنْ نَزَلَ فِيهِ{ وَلَا عَلَى الَّذِينَ إِذَا مَا أَتَوْكَ لِتَحْمِلَهُمْ قُلْتَ لَا أَجِدُ مَا أَحْمِلُكُمْ عَلَيْهِ }فَسَلَّمْنَا وَقُلْنَا أَتَيْنَاكَ زَائِرِينَ وَعَائِدِينَ وَمُقْتَبِسِينَ فَقَالَ عِرْبَاضٌ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ ذَاتَ يَوْمٍ ثُمَّ أَقْبَلَ عَلَيْنَا فَوَعَظَنَا مَوْعِظَةً بَلِيغَةً ذَرَفَتْ مِنْهَا الْعُيُونُ وَوَجِلَتْ مِنْهَا الْقُلُوبُ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ كَأَنَّ هَذِهِ مَوْعِظَةُ مُوَدِّعٍ فَمَاذَا تَعْهَدُ إِلَيْنَا فَقَالَ أُوصِيكُمْ بِتَقْوَى اللَّهِ وَالسَّمْعِ وَالطَّاعَةِ وَإِنْ كَانَ عَبْدًا حَبَشِيًّا فَإِنَّهُ مَنْ يَعِشْ مِنْكُمْ بَعْدِي فَسَيَرَى اخْتِلَافًا كَثِيرًا فَعَلَيْكُمْ بِسُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الرَّاشِدِينَ الْمَهْدِيِّينَ فَتَمَسَّكُوا بِهَا وَعَضُّوا عَلَيْهَا بِالنَّوَاجِذِ وَإِيَّاكُمْ وَمُحْدَثَاتِ الْأُمُورِ فَإِنَّ كُلَّ مُحْدَثَةٍ بِدْعَةٌ وَكُلَّ بِدْعَةٍ ضَلَالَةٌحَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنِ ابْنِ أَبِي بِلَالٍ عَنْ عِرْبَاضِ بْنِ سَارِيَةَ أَنَّهُ حَدَّثَهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَظَهُمْ يَوْمًا بَعْدَ صَلَاةِ الْغَدَاةِ فَذَكَرَهُ حَدَّثَنَا إِسْمَاعِيلُ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي بِلَالٍ عَنِ الْعِرْبَاضِ بْنِ سَارِيَةَ أَنَّهُ حَدَّثَهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَظَهُمْ يَوْمًا بَعْدَ صَلَاةِ الْغَدَاةِ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Tsaur bin Yazid] telah menceritakan kepada kami [Khalid bin Ma'dan] berkata; telah menceritakan kepada kami [Abdurrahman bin 'Amr As-Sulami] dan [Hujr bin Hujr] berkata; kami mendatangi [Al 'Irbadl bin Sariyah] dia adalah termasuk orang yang menyebabkan turunnya ayat, 'Dan tiada (pula) berdosa atas orang-orang yang apabila mereka datang kepadamu, supaya kamu memberi mereka kendaraan, lalu kamu berkata: \"Aku tidak memperoleh kendaraan untuk membawamu \" Lalu kami mengucapkan salam dan kami katakan, \"Kami mendatangi anda, dalam rangka mengunjungi, kembali dan mencari ilmu. lalu 'Irbadl berkata; \"Rasulullah Shallallahu'alaihiwasallam shalat subuh bersama kami pada suatu hari, lalu beliau menemui kami dan memberi nasehat yang sangat mengena, yang menyebabkan mata bercucuran dan hati menjadi tergetar. Lalu ada seseorang yang bertanya, \"Wahai Rasulullah, sepertinya ini adalah nasehat perpisahan, maka apa yang anda wasiatkan kepada kami\". Beliau bersabda: \"Saya wasiatkan kalian untuk bertakwa kepada Allah, mendengar dan taat walau kepada budak dari Habasyah. Sungguh siapa yang hidup di antara kalian setelahku akan melihat perselisihan yang banyak. Berpeganglah dengan sunahku dan sunnah Khulafa' Rasyidin yang mendapat petunjuk. Berpegang teguhlah dan gigitlah dengan gigi geraham. Hindarilah kalian hAl hal yang baru, sesungguhnya setiap hal yang baru adalah bid'ah dan setiap bid'ah ada sesat. Telah menceritakan kepada kami [Haiwah bin Syuraih] telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepadaku [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] dari [Ibnu Abu bilal] dari [Al 'Irbadl bin Sariyah], ia menceritakan kepada mereka sesungguhnya Rasulullah Shallallahu'alaihiwasallam telah memberi nasehat kepada mereka pada suatu hari setelah shalat subuh, lalu dia sebutkan. Telah menceritakan kepada kami [Isma'il] dari [Hisyam Ad-Dustuwa'i] dari [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim bin Al Harits] dari [Khalid bin Ma'dan] dari [Abu Bilal] dari [Al 'Irbadl bin Sariyah], dia menceritakan kepada mereka sesungguhnya Rasulullah Shallallahu'alaihiwasallam memberi nasehat kepada mereka pada suatu hari setelah shalat subuh, lalu dia menyebutkanya secara lengkap."},"1435":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنِ الْعِرْبَاضِ بْنِ سَارِيَةَ أَنَّهُ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَغْفِرُ لِلصَّفِّ الْمُقَدَّمِ ثَلَاثَ مِرَارٍ وَلِلثَّانِي مَرَّةً","id":"Telah menceritakan kepada kami [Isma'il] dari [Hisyam Ad-Dustuwa'i] dari [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim bin Al Harits] dari [Khalid bin Ma'dan] dari [Al 'Irbadl bin Sariyah] sesungguhnya dia menceritakan kepada mereka, Rasulullah Shallallahu'alaihiwasallam memintakan ampunan untuk shaf yang paling depan tiga kali dan untuk shaf yang kedua sekali."},"1436":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ سَعِيدِ بْنِ هَانِئٍ قَالَ سَمِعْتُ الْعِرْبَاضَ بْنَ سَارِيَةَ قَالَبِعْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَكْرًا فَأَتَيْتُهُ أَتَقَاضَاهُ فَقُلْتُ يَا رَسُولَ اللَّهِ اقْضِنِي ثَمَنَ بَكْرِي فَقَالَ أَجَلْ لَا أَقْضِيكَهَا إِلَّا لُجَيْنِيَّةً قَالَ فَقَضَانِي فَأَحْسَنَ قَضَائِي قَالَ وَجَاءَهُ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ اقْضِنِي بَكْرِي فَأَعْطَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ جَمَلًا قَدْ أَسَنَّ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا خَيْرٌ مِنْ بَكْرِي قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خَيْرَ الْقَوْمِ خَيْرُهُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Sa'id bin Hani`] berkata; saya telah mendengar [Al 'Irbadl bin Sariyah] berkata; saya menjual unta muda kepada Nabi Shallallahu'alaihiwasallam, saya mendatanginya untuk meminta dibayar, saya berkata; \"Wahai Rasulullah, bayarkanlah ongkos unta mudaku. Lalu beliau bersabda: \"Ya. Saya tidak akan membayarkanya kecuali dengan perak.\" Beliau pun membayarnya dengan baik\" \"Lalu datang seorang Badui berkata; 'Wahai Rasulullah, bayarkanlah unta mudaku', lalu Rasulullah Shallallahu'alaihiwasallam memberinya pada hari itu dengan satu unta yang besar. Lalu dia berkata; 'Wahai Rasulullah, ini lebih baik daripada unta mudaku'.\" \"Rasulullah Shallallahu'alaihiwasallam kontan bersabda: 'Sebaik-baik kaum adalah yang tebaik dalam menunaikan pembayarannya'.\""},"1437":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ يَعْنِي ابْنَ صَالِحٍ عَنْ يُونُسَ بْنِ سَيْفٍ عَنِ الْحَارِثِ بْنِ زِيَادٍ عَنْ أَبِي رُهْمٍ عَنِ الْعِرْبَاضِ بْنِ سَارِيَةَ السُّلَمِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَدْعُونَا إِلَى السَّحُورِ فِي شَهْرِ رَمَضَانَ هَلُمُّوا إِلَى الْغِذَاءِ الْمُبَارَكِ ثُمَّ سَمِعْتُهُ يَقُولُ اللَّهُمَّ عَلِّمْ مُعَاوِيَةَ الْكِتَابَ وَالْحِسَابَ وَقِهِ الْعَذَابَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Mu'awiyah] yaitu Ibnu Shalih, dari [Yunus bin Saif] dari [Al Harits bin Ziyad] dari [Abu Ruhm] dari [Al 'Irbadl bin Sariyah As-Sulami] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam memanggil kami untuk sahur pada bulan Ramadlan, \"Marilah kalian menikmati makanan yang berbarakah ini.\" Saya mendengar beliau membaca, \"Ya Allah, ajarilah Mu'awiyah kitabullah, ilmu hisab dan jagalah dia dari siksaan.\""},"1438":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا وَهْبُ بْنُ خَالِدٍ الْحِمْصِيُّ حَدَّثَتْنِي أُمُّ حَبِيبَةَ بِنْتُ الْعِرْبَاضِ قَالَتْ حَدَّثَنِي أَبِيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ يَوْمَ خَيْبَرَ كُلَّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ وَلُحُومَ الْحُمُرِ الْأَهْلِيَّةِ وَالْخَلِيسَةَ وَالْمُجَثَّمَةَ وَأَنْ تُوطَأَ السَّبَايَا حَتَّى يَضَعْنَ مَا فِي بُطُونِهِنَّ","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Wahb bin Khalid Al Himshi] telah menceritakan kepadaku [Umu Habibah binti Al 'Irbadl] berkata; telah menceritakan kepadaku [bapakku] sesungguhnya Rasulullah Shallallahu'alaihiwasallam pada Perang Khaibar mengharamkan semua burung yang memiliki cakar, keledai jinak, khalisah (binatang yang mati karena mulut hewan buas sebelum sempat disembelih), hewan yang mati karena dijadikan sasaran lemparan dan menggauli tawanan sampai mereka melahirkan.\""},"1439":{"ar":"حَدَّثَنَا أَبُو جَعْفَرٍ وَهُوَ مُحَمَّدُ بْنُ جَعْفَرٍ الْمَدَائِنِيُّ أَخْبَرَنِي عَبَّادُ بْنُ الْعَوَّامِ عَنْ سُفْيَانَ بْنِ الْحُسَيْنِ عَنْ خَالِدِ بْنِ زَيْدٍ عَنِ الْعِرْبَاضِ بْنِ سَارِيَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الرَّجُلَ إِذَا سَقَى امْرَأَتَهُ مِنْ الْمَاءِ أُجِرَقَالَ فَأَتَيْتُهَا فَسَقَيْتُهَا وَحَدَّثْتُهَا بِمَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Ja'far] yaitu Muhammad bin Ja'far Al Mada`ini, telah mengabarkan kepadaku ['Abbad bin Al 'Awwam] dari [Sufyan bin Al Husain] dari [Khalid bin Zaid] dari [Al 'Irbadl bin Sariyah] berkata; saya telah mendengar bersabda: \"Sesungguhnya seorang laki-laki, jika dia memberi minum istrinya dengan air, maka akan mendapatkan pahala, \" (Al 'Irbadl bin Sariyah radliyallahu'anhu) berkata; \"Lalu saya memberinya minum dan saya sampaikan dengan apa yang telah saya dengar dari Rasulullah Shallallahu'alaihiwasallam. "},"1440":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ خَالِدِ بْنِ مَعْدَانَ حَدَّثَهُ أَنَّ جُبَيْرَ بْنَ نُفَيْرٍ حَدَّثَهُ أَنَّ الْعِرْبَاضَ حَدَّثَهُ وَكَانَ الْعِرْبَاضُ بْنُ سَارِيَةَ مِنْ أَصْحَابِ الصُّفَّةِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الصَّفِّ الْمُقَدَّمِ ثَلَاثًا وَعَلَى الثَّانِي وَاحِدَةً","id":"Telah menceritakan kepada kami [Husain bin Musa] berkata; telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Muhammad bin Ibrahim] dari [Khalid bin Ma'dan] menceritakannya, sesungguhnya [Jubair bin Nufair] menceritakannya sesungguhnya [Al 'Irbadl] menceritakannya, dan Al 'Irbadl bin Sariyah termasuk ahli suffah, berkata; Rasulullah Shallallahu'alaihiwasallam memintakan rahmat untuk shaf yang paling depan tiga kali dan untuk yang kedua satu kali."},"1441":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنِ الْعِرْبَاضِ بْنِ سَارِيَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُصَلِّي عَلَى الصَّفِّ الْأَوَّلِ ثَلَاثًا وَعَلَى الَّذِي يَلِيهِ وَاحِدَةً","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] telah menceritakan kepada kami [Baqiyyah bin Al Walid] telah menceritakan kepada kami [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari [Al 'Irbadl bin Sariyah] dari Rasulullah Shallallahu'alaihiwasallam memintakan rahmat untuk shaf yang paling depan tiga kali dan untuk yang berikutnya satu kali."},"1442":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ حَدَّثَنَا عَلِيُّ بْنُ مُدْرِكٍ عَنْ أَبِي عَامِرٍ الْأَشْعَرِيِّ قَالَكَانَ رَجُلٌ قُتِلَ مِنْهُمْ بِأَوْطَاسٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا عَامِرٍ أَلَا غَيَّرْتَ فَتَلَا هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَيْنَ ذَهَبْتُمْ إِنَّمَا هِيَ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا يَضُرُّكُمْ مَنْ ضَلَّ مِنْ الْكُفَّارِ إِذَا اهْتَدَيْتُمْ","id":"Telah menceritakan kepada kami [Abdushshamad bin Abdul Warits] berkata; telah menceritakan kepada kami [Malik bin Mighwal] telah menceritakan kepada kami [Ali bin Mudrik] dari [Abu 'Amir Al Asy'ari] berkata; ada seorang laki-laki dari mereka yang terbunuh di Authas, lalu Nabi Shallallahu'alaihiwasallam bersabda kepadanya, \"Wahai Abu 'Amir, tidakkah engkau cemburu??, \" lalu (Abu 'Amir Al Asy'ari Radliyalllahu'anhu) membaca ayat ini, 'Hai orang-orang yang beriman, jagalah dirimu; tiadalah orang yang sesat itu akan memberi mudharat kepadamu apabila kamu telah mendapat petunjuk' lalu Rasulullah Shallallahu'alaihiwasallam marah dan bersabda: \"Bagaimana pendapatmu ini?, yang benar adalah: 'Wahai orang-orang yang beriman, tidak akan membahayakan kalian orang yang sesat dari orang kafir, jika kalian telah mendapatkan petunjuk. "},"1443":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَلَاذٍ يُحَدِّثُ عَنْ نُمَيْرِ بْنِ أَوْسٍ عَنْ مَالِكِ بْنِ مَسْرُوحٍ عَنْ عَامِرِ بْنِ أَبِي عَامِرٍ الْأَشْعَرِيِّ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الْحَيُّ الْأُسْدُ وَالْأَشْعَرِيُّونَ لَا يَفِرُّونَ فِي الْقِتَالِ وَلَا يَغُلُّونَ هُمْ مِنِّي وَأَنَا مِنْهُمْقَالَ عَامِرٌ فَحَدَّثْتُ بِهِ مُعَاوِيَةَ فَقَالَ لَيْسَ هَكَذَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنَّهُ قَالَ هُمْ مِنِّي وَإِلَيَّ فَقَالَ لَيْسَ هَكَذَا حَدَّثَنِي أَبِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنَّهُ قَالَ هُمْ مِنِّي وَأَنَا مِنْهُمْ قَالَ فَأَنْتَ إِذًا أَعْلَمُ بِحَدِيثِ أَبِيكَ قَالَ عَبْد اللَّهِ هَذَا مِنْ أَجْوَدِ الْحَدِيثِ مَا رَوَاهُ إِلَّا جَرِيرٌ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] berkata; telah menceritakan kepada kami [bapakku] berkata; saya mendengar [Abdullah bin Maladz] menceritakan dari [Numair bin Aus] dari [Malik bin Masruh] dari ['Amir bin Abu 'Amir Al Asy'ari] dari [Bapaknya] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Sebaik-baik golongan adalah Usud dan Asy'ari, mereka tidak kabur dalam peperangan, tidak berbuat ghulul (khianat yaitu mengambil harta rampasan sebelum dibagi), mereka adalah dariku dan saya adalah dari mereka. ['Amir] berkata; lalu saya ceritakan pada [Mu'awiyah]. lalu dia berkata; \"Tidak demikian yang disabdakan Rasulullah Shallallahu'alaihiwasallam, tapi yang benar adalah beliau bersabda: \"Mereka adalah dariku dan akan kembali kepadaku, \" lalu ('Amir Radliyallahu'anhu) berkata; \"Tidak begitu yang diceritakan bapakku dari Nabi Shallallahu'alaihiwasallam tapi bersabda: 'mereka adalah dariku dan saya adalah dari mereka.\" (Mu'awiyah Radliyallahu'anhu) berkata; \"Kamu lebih tahu dengan hadis bapakmu.\" Abdullah berkata; ini adalah hadis yang paling baik yang diriwayatkan kecuali Jarir."},"1444":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي حُسَيْنٍ حَدَّثَنَا شَهْرُ بْنُ حَوْشَبٍ عَنْ عَامِرٍ أَوْ أَبِي عَامِرٍ أَوْ أَبِي مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ جَالِسٌ فِي مَجْلِسٍ فِيهِ أَصْحَابُهُ جَاءَهُ جِبْرِيلُ عَلَيْهِ السَّلَام فِي غَيْرِ صُورَتِهِ يَحْسِبُهُ رَجُلًا مِنْ الْمُسْلِمِينَ فَسَلَّمَ عَلَيْهِ فَرَدَّ عَلَيْهِ السَّلَامَ ثُمَّ وَضَعَ جِبْرِيلُ يَدَهُ عَلَى رُكْبَتَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَهُ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ فَقَالَ أَنْ تُسْلِمَ وَجْهَكَ لِلَّهِ وَأَنْ تَشْهَدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ أَسْلَمْتُ قَالَ نَعَمْ ثُمَّ قَالَ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَالْمَلَائِكَةِ وَالْكِتَابِ وَالنَّبِيِّينَ وَالْمَوْتِ وَالْحَيَاةِ بَعْدَ الْمَوْتِ وَالْجَنَّةِ وَالنَّارِ وَالْحِسَابِ وَالْمِيزَانِ وَالْقَدَرِ كُلِّهِ خَيْرِهِ وَشَرِّهِ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ آمَنْتُ قَالَ نَعَمْ ثُمَّ قَالَ مَا الْإِحْسَانُ يَا رَسُولَ اللَّهِ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ كُنْتَ لَا تَرَاهُ فَهُوَ يَرَاكَ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ أَحْسَنْتُ قَالَ نَعَمْ وَنَسْمَعُ رَجْعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ وَلَا يُرَى الَّذِي يُكَلِّمُهُ وَلَا يُسْمَعُ كَلَامُهُ قَالَ فَمَتَى السَّاعَةُ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَانَ اللَّهِ خَمْسٌ مِنْ الْغَيْبِ لَا يَعْلَمُهَا إِلَّا اللَّهُ عَزَّ وَجَلَّ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }فَقَالَ السَّائِلُ يَا رَسُولَ اللَّهِ إِنْ شِئْتَ حَدَّثْتُكَ بِعَلَامَتَيْنِ تَكُونَانِ قَبْلَهَا فَقَالَ حَدِّثْنِي فَقَالَ إِذَا رَأَيْتَ الْأَمَةَ تَلِدُ رَبَّهَا وَيَطُولُ أَهْلُ الْبُنْيَانِ بِالْبُنْيَانِ وَعَادَ الْعَالَةُ الْحُفَاةُ رُءُوسَ النَّاسِ قَالَ وَمَنْ أُولَئِكَ يَا رَسُولَ اللَّهِ قَالَ الْعَرِيبُ قَالَ ثُمَّ وَلَّى فَلَمَّا لَمْ نَرَ طَرِيقَهُ بَعْدُ قَالَ سُبْحَانَ اللَّهِ ثَلَاثًا هَذَا جِبْرِيلُ جَاءَ لِيُعَلِّمَ النَّاسَ دِينَهُمْ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا جَاءَنِي قَطُّ إِلَّا وَأَنَا أَعْرِفُهُ إِلَّا أَنْ تَكُونَ هَذِهِ الْمَرَّةُحَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ قَالَ حَدَّثَنِي شَهْرُ بْنُ حَوْشَبٍ عَنِ ابْنِ عَبَّاسٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَصْنَافِ النِّسَاءِ وَذَكَرَ الْحَدِيثَ وَذَكَرَ مُلْصِقًا بِهِ قَالَ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَجْلِسًا فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَجَلَسَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ وَقَالَ فِيهِ إِنْ شِئْتَ حَدَّثْتُكَ بِمَعَالِمَ لَهَا دُونَ ذَلِكَ قَالَ أَجَلْ يَا رَسُولَ اللَّهِ فَحَدِّثْنِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتَ الْأَمَةَ وَلَدَتْ رَبَّتَهَا فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syua'ib] berkata; telah menceritakan kepada kami [Abdullah bin Abu Husain] telah menceritakan kepada kami [Syahr bin Hausyab] dari ['Amir] atau [Abu 'Amir] atau [Abu Malik], Nabi Shallallahu'alaihiwasallam tatkala duduk pada sebuah majlis yang dihadiri para sahabatnya, Jibril 'alaihissalam datang bukan dengan bentuk aslinya yang dikira seseorang laki-laki dari kaum muslimin, lalu dia mengucapkan salam kepada beliau. Beliau pun menjawabnya, Jibril tangannya diletakkan pada kedua lutut Nabi Shallallahu'alaihiwasallam, lalu bertanya kepadanya, \"Wahai Rasulullah, apakah Islam itu?\" Beliau menjawab, \"Kamu menyerahkan wajahmu kepada Allah dan bersaksi bahwa tidak ada tuhan selain Allah dan Muhammad adalah hamba-Nya dan Rasul-Nya, Kamu menegakkan shalat, membayar zakat. (Jibril alaihissalam) berkata; \"Jika saya telah melakukan hal itu, saya telah masuk Islam\" beliau menjawab, \"Ya, \" lalu dia bertanya, \"Apakah iman itu?\" beliau menjawab, \"Kamu beriman kepada Allah, Hari Akhir, para Malaikat, Kitab-Kitab, para Nabi, kematian dan kehidupan setelah kematian, surga, neraka, perhitungan, timbangan dan semua taqdir baik buruk maupun yang jelek. (Jibril alaihissalam) berkata; \"Jika saya melakukan hal itu, maka saya telah beriman.\" Beliau menjawab, \"Ya.\" lalu dia bertanya, \"Apakah ihsan itu? Wahai Rasulullah\" beliau menjawab, \"Kamu menyembah kepada Allah seolah-olah kamu melihat-Nya, jika kamu tidak bisa demikian maka Dia adalah melihatmu.\" (Jibril 'alaihissalam) berkata; \"Jika saya melakukan hal itu, maka saya telah melakukan ihsan.\"Beliau menjawab, \"Ya.\" Dan kami mendengar jawaban Rasulullah Shallallahu'alaihiwasallam kepadanya dan tidak terlihat yang mengajaknya bicara, dan tidak terdengar suaranya. (Jibril alaihissalam) berkata; \"Kapankah Hari Kiamat itu? Wahai Rasulullah, \" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Maha Suci Allah, lima hal ghaib yang tidak ada yang mengetahuinya kecuali Allah Azzawajalla. Allah sajalah yang mengetahui ilmu Hari Kiamat, menurunkan hujan, mengetahui apa yang ada di rahim, dan tidaklah jiwa mengetahui apa yang akan terjadi besok harinya. Tidak juga jiwa mengetahui dimana dia akan meninggal. Sesungguhnya Allah Maha Mengetahui lagi Maha Tahu.\" Lalu orang yang bertanya berkata; \"Wahai Rasulullah, Jika kamu mau, saya akan menceritakannya dengan dua tanda yang akan terjadi sebelumnya, \" lalu beliau bersabda: \"Ceritakan kepadaku!\" dia menjawab, \"Jika kamu melihat seorang budak melahirkan tuannya, lalu orang-orang sudah banyak yang meninggikan bangunannya, dan ada orang yang miskin dan tidak bersepatu menjadi pemimpin manusia, \" ('Amir, Abu 'Amir atau Abu Malik radliyallahu'anhum) berkata; \"Siapakah orang itu Wahai Rasulullah,?\" lalu dia pergi, tatkala kami tidak melihatnya, beliau bersabda: \"Maha Suci Allah, \" tiga kali, \"Itu adalah Jibril 'alaihissalam telah datang untuk mengajarkan orang-orang agama mereka. Demi Dzat yang jiwa Muhammad berada di tangan-Nya, tidaklah dia datang kepadaku kecuali saya pasti mengetahuinya kecuali tadi.\" Telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Abdul Hamid] berkata; telah menceritakan kepadaku [Syhar bin Hausyab] dari [Ibnu 'Abbas] berkata; Rasulullah Shallallahu'alaihiwasallam pernah dilarang sekian macam wanita yang tidak boleh dinikahi, lalu menyebutkan hadis secara lengkap dan beliau sebutkan bahwa lutut jibril menempel pada lutut Rasulullah Shallallahu'alaihiwasallam (katanya selanjutnya), \"Rasulullah Shallallahu'alaihiwasallam duduk pada suatu majlis lalu Jibril alaihissalam datang, dia duduk di hadapan Rasulullah Shallallahu'alaihiwasallam, dan ia sebutkan hadis secara lengkap dan didalamnya ada tambahan, \"Jika kamu mau, saya akan menceritakannya dengan tanda-tanda kiamat selain hal itu. (Jibril alaihissalam) berkata; \"Ya. Wahai Rasulullah, ceritakanlah.\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika kamu melihat budak yang melahirkan tuannya, lalu menyebutkan hadis secara lengkap.\""},"1445":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو خَلَفٍ مُوسَى بْنُ خَلَفٍ كَانَ يُعَدُّ فِي الْبُدَلَاءِ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ زَيْدِ بْنِ سَلَّامٍ عَنْ جَدِّهِ مَمْطُورٍ عَنِ الْحَارِثِ الْأَشْعَرِيِّأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَمَرَ يَحْيَى بْنَ زَكَرِيَّا عَلَيْهِمَا السَّلَام بِخَمْسِ كَلِمَاتٍ أَنْ يَعْمَلَ بِهِنَّ وَأَنْ يَأْمُرَ بَنِي إِسْرَائِيلَ أَنْ يَعْمَلُوا بِهِنَّ وَكَادَ أَنْ يُبْطِئَ فَقَالَ لَهُ عِيسَى إِنَّكَ قَدْ أُمِرْتَ بِخَمْسِ كَلِمَاتٍ أَنْ تَعْمَلَ بِهِنَّ وَتَأْمُرَ بَنِي إِسْرَائِيلَ أَنْ يَعْمَلُوا بِهِنَّ فَإِمَّا أَنْ تُبَلِّغَهُنَّ وَإِمَّا أَنْ أُبَلِّغَهُنَّ فَقَالَ يَا أَخِي إِنِّي أَخْشَى إِنْ سَبَقْتَنِي أَنْ أُعَذَّبَ أَوْ يُخْسَفَ بِي قَالَ فَجَمَعَ يَحْيَى بَنِي إِسْرَائِيلَ فِي بَيْتِ الْمَقْدِسِ حَتَّى امْتَلَأَ الْمَسْجِدُ فَقُعِدَ عَلَى الشُّرَفِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَمَرَنِي بِخَمْسِ كَلِمَاتٍ أَنْ أَعْمَلَ بِهِنَّ وَآمُرَكُمْ أَنْ تَعْمَلُوا بِهِنَّ أَوَّلُهُنَّ أَنْ تَعْبُدُوا اللَّهَ لَا تُشْرِكُوا بِهِ شَيْئًا فَإِنَّ مَثَلَ ذَلِكَ مَثَلُ رَجُلٍ اشْتَرَى عَبْدًا مِنْ خَالِصِ مَالِهِ بِوَرِقٍ أَوْ ذَهَبٍ فَجَعَلَ يَعْمَلُ وَيُؤَدِّي غَلَّتَهُ إِلَى غَيْرِ سَيِّدِهِ فَأَيُّكُمْ سَرَّهُ أَنْ يَكُونَ عَبْدُهُ كَذَلِكَ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ خَلَقَكُمْ وَرَزَقَكُمْ فَاعْبُدُوهُ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَآمُرُكُمْ بِالصَّلَاةِ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ يَنْصِبُ وَجْهَهُ لِوَجْهِ عَبْدِهِ مَا لَمْ يَلْتَفِتْ فَإِذَا صَلَّيْتُمْ فَلَا تَلْتَفِتُوا وَآمُرُكُمْ بِالصِّيَامِ فَإِنَّ مَثَلَ ذَلِكَ كَمَثَلِ رَجُلٍ مَعَهُ صُرَّةٌ مِنْ مِسْكٍ فِي عِصَابَةٍ كُلُّهُمْ يَجِدُ رِيحَ الْمِسْكِ وَإِنَّ خُلُوفَ فَمِ الصَّائِمِ عِنْدَ اللَّهِ أَطْيَبُ مِنْ رِيحِ الْمِسْكِ وَآمُرُكُمْ بِالصَّدَقَةِ فَإِنَّ مَثَلَ ذَلِكَ كَمَثَلِ رَجُلٍ أَسَرَهُ الْعَدُوُّ فَشَدُّوا يَدَيْهِ إِلَى عُنُقِهِ وَقَدَّمُوهُ لِيَضْرِبُوا عُنُقَهُ فَقَالَ هَلْ لَكُمْ أَنْ أَفْتَدِيَ نَفْسِي مِنْكُمْ فَجَعَلَ يَفْتَدِي نَفْسَهُ مِنْهُمْ بِالْقَلِيلِ وَالْكَثِيرِ حَتَّى فَكَّ نَفْسَهُ وَآمُرُكُمْ بِذِكْرِ اللَّهِ عَزَّ وَجَلَّ كَثِيرًا وَإِنَّ مَثَلَ ذَلِكَ كَمَثَلِ رَجُلٍ طَلَبَهُ الْعَدُوُّ سِرَاعًا فِي أَثَرِهِ فَأَتَى ��ِصْنًا حَصِينًا فَتَحَصَّنَ فِيهِ وَإِنَّ الْعَبْدَ أَحْصَنُ مَا يَكُونُ مِنْ الشَّيْطَانِ إِذَا كَانَ فِي ذِكْرِ اللَّهِ عَزَّ وَجَلَّ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا آمُرُكُمْ بِخَمْسٍ اللَّهُ أَمَرَنِي بِهِنَّ بِالْجَمَاعَةِ وَالسَّمْعِ وَالطَّاعَةِ وَالْهِجْرَةِ وَالْجِهَادِ فِي سَبِيلِ اللَّهِ فَإِنَّهُ مَنْ خَرَجَ مِنْ الْجَمَاعَةِ قِيدَ شِبْرٍ فَقَدْ خَلَعَ رِبْقَةَ الْإِسْلَامِ مِنْ عُنُقِهِ إِلَّا أَنْ يَرْجِعَ وَمَنْ دَعَا بِدَعْوَى الْجَاهِلِيَّةِ فَهُوَ مِنْ جُثَاءِ جَهَنَّمَ قَالُوا يَا رَسُولَ اللَّهِ وَإِنْ صَامَ وَإِنْ صَلَّى قَالَ وَإِنْ صَامَ وَإِنْ صَلَّى وَزَعَمَ أَنَّهُ مُسْلِمٌ فَادْعُوا الْمُسْلِمِينَ بِأَسْمَائِهِمْ بِمَا سَمَّاهُمْ اللَّهُ عَزَّ وَجَلَّ الْمُسْلِمِينَ الْمُؤْمِنِينَ عِبَادَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abu Khalaf, Musa bin Khalaf] yang dianggap di Al Budala`, telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Zaid bin Sallam] dari [kakeknya Mamthur] dari [Al Harits Al Asy'ari] sesungguhnya Nabi Shallallahu'alaihiwasallam bersabda: \" Allah Azzawajalla memerintahkan Yahya bin Zakariya 'alaihissalam dengan lima kalimat agar diamalkan, dan memerintahkan Bani Isra`il agar mereka mengamalkannya. Namun Yahya hampir saja memperlambatnya. Lalu 'Isa berkata kepadanya, 'Sesungguhnya kamu kamu diperintahkan dengan lima kalimat, agar kamu mengamalkannya, juga kamu perintahkan kepada Bani Isra`il mengamalkannya. Sekarang kamu yang menyampaikan, atau saya yang menyampaikannya.' Lalu dia berkata; 'Wahai saudaraku, sesungguhnya saya takut jika kamu mendahuluiku niscaya saya akan disiksa atau ditenggelamkan'.\" (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"lalu Yahya mengumpulkan Bani Isra`il di Baitul Maqdis, sampai masjid itu menjadi penuh, dia duduk pada tempat imam, memuji Allah dan berkata; 'Allah Azzawajalla telah memerintahkan kepadaku agar mengamalkan lima hal dan agar kalian juga mengamalkannya. Yang pertama adalah: kalian menyembah Allah dan tidak menyekutukan-Nya dengan sesuatupun. Permisalan hal itu adalah sebagaimana seseorang yang membeli seorang budak dari hartanya dengan sejumlah uang atau dari emas, sialnya budak itu bekerja dan mengerjakan pekerjaanya kepada selain tuannya, maka siapa yang merasa senang dengan hal itu?. Sesungguhnya Allah Azzawajalla telah menciptakan kalian, memberi rizki kepada kalian, sembahlah Dia dan janganlah kalian menyekutukan dengan sesuatupun. Saya perintahkan kepada kalian untuk shalat. Sesungguhnya Allah Azzawajalla menghadapkan wajah-Nya kepada wajah hamba-Nya, selama dia tidak menoleh. Jika kalian shalat, janganlah kalian menoleh. Saya perintahkan kepada kalian untuk berpuasa, permisalah hal itu adalah sebagaimana seseorang yang membawa sebotol minyak wangi pada sekelompok orang semunya merasakan bau wangi tersebut. Bau harum mulut orang yang sedang berpuasa di sisi Allah itu lebih harum daripada bau kasturi. Saya perintahkan kepada kalian untuk bersedekah. Sesungguhnya permisalan hal itu adalah seseorang yang ditawan musuh, lalu dia mengikatnya kedua tangannya pada lehernya, dan diletakkan di hadapannya untuk dibunuh. Lalu dia mengajukan penawaran, 'Apakah kalian mau jika saya menebus diri saya dari kalian? ' Lalu dia menebus dirinya dengan sesuatu yang sedikit dan yang banyak sehingga dirinya bisa bebas. Saya perintahkan kepada kalian untuk berdzikir kepada Allah Azzawajalla yang banyak. Permisalan hal itu adalah sebagaimana seseorang yang musuhnya mengejarnya dengan cepat lalu dia mendapatkan benteng yang kokoh, dijadikannya benteng itu untuk tempat berlindung. Sesungguhnya seorang hamba akan lebih dapat terjaga dari setan jika dia dalam keadaan berdzikir kepada Allah Azzawajalla.\" (Al Harits Al Asy'ari Radliyallahu'anhu) berkata; lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Saya perintahkan kalian dengan lima hal yang Allah telah perintahkan kepadaku: jama'ah, mendengar, taat, hijrah dan jihad di jalan Allah. Barangsiapa yang keluar dari jama'ah satu jengkal, maka dia telah melepaskan perjanjian Islam dari lehernya sampai dia kembali. Barangsiapa yang memanggil dengan panggilan jahiliyyah, maka dia termasuk bangkai Jahannam.\" Mereka berkata; \"Wahai Rasulullah, walaupun dia berpuasa dan shalat?.\" Beliau bersabda: \"Walaupun dia berpuasa dan shalat dan beranggapan bahwa dirinya adalah seorang muslim. Panggillah kaum muslimin dengan nama-nama yang Allah Azzawajalla menamakan mereka yaitu 'muslimin dan mukminin dan hamba Allah Azzawajalla'.\""},"1446":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا ثَوْرٌ يَعْنِي ابْنَ يَزِيدَ قَالَ حَدَّثَنِي حَبِيبُ بْنُ عُبَيْدٍ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ أَبِي كَرِيمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَحَبَّ أَحَدُكُمْ أَخَاهُ فَلْيُعْلِمْهُ أَنَّهُ يُحْبِبْهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepada kami [Tsaur] yaitu Ibnu Yazid berkata; telah menceritakan kepadaku [Habib bin 'Ubaid] dari [Al Miqdam bin Ma'di Karib, Abu Karimah] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian menyukai saudaranya maka beritahukanlah jika dirinya menyukainya.\""},"1447":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي مَنْصُورٌ عَنِ الشَّعْبِيِّ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ أَبِي كَرِيمَةَ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْلَةُ الضَّيْفِ وَاجِبَةٌ عَلَى كُلِّ مُسْلِمٍ فَإِنْ أَصْبَحَ بِفِنَائِهِ مَحْرُومًا كَانَ دَيْنًا لَهُ عَلَيْهِ إِنْ شَاءَ اقْتَضَاهُ وَإِنْ شَاءَ تَرَكَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Manshur] dari [Asy-Sya'bi] dari [Al Miqdam bin Ma'di Karib, Abu Karimah] sesungguhnya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tamu yang datang malam hari wajib dilayani oleh setiap muslim. Jika pagi harinya berada diterasnya dan belum dipersilahkan, maka menjadi hutang bagi orang tersebut, jika mau, si tamu boleh menuntutnya atau meninggalkannya.\""},"1448":{"ar":"حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ الْبَكَّائِيُّ قَالَ حَدَّثَنَا مَنْصُورٌ عَنْ عَامِرٍ عَنْ أَبِي كَرِيمَةَ رَجُلٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةُ الضَّيْفِ وَاجِبَةٌ عَلَى كُلِّ مُسْلِمٍ فَإِنْ أَصْبَحَ بِفِنَائِهِ مَحْرُومًا كَانَ دَيْنًا لَهُ عَلَيْهِ إِنْ شَاءَ اقْتَضَاهُ وَإِنْ شَاءَ تَرَكَهُ","id":"Telah menceritakan kepada kami [Ziyad bin Abdullah Al Buka`i] berkata; telah menceritakan kepada kami [Manshur] dari ['Amir] dari [Abu Karimah] seorang laki-laki dari sahabat Rasulullah Shallallahu'alaihiwasallam berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tamu yang datang malam hari wajib dilayani oleh setiap muslim. Jika pagi harinya berada diterasnya dan belum dipersilahkan, maka menjadi hutang bagi orang tersebut, jika mau, si tamu boleh menuntutnya atau meninggalkannya.\""},"1449":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ بُدَيْلٍ عَنْ عَلِيِّ بْنِ أَبِي طَلْحَةَ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ أَبِي عَامِرٍ الْهَوْزَنِيِّ عَنِ الْمِقْدَامِ أَبِي كَرِيمَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ تَرَكَ كَلًّا فَإِلَى اللَّهِ وَرَسُولِهِ وَرُبَّمَا قَالَ فَإِلَيْنَا وَمَنْ تَرَكَ مَالًا فَلِوَارِثِهِ وَالْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُ وَأَنَا وَارِثُ مَنْ لَا وَارِثَ لَهُ أَرِثُهُ وَأَعْقِلُ عَنْهُحَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شُعْبَةُ فَذَكَرَهُ وَقَالَ عَنِ الْمِقْدَامِ مِنْ كِنْدَةَ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Budail] dari [Ali bin Abu Thalhah] dari [Rasyid bin Sa'ad] dari [Abu 'Amir Al Hauzani] dari [Al Miqdam, Abu Karimah] dari Rasulullah Shallallahu'alaihiwasallam sesungguhnya beliau bersabda: \"Barangsiapa yang meninggalgalkan tanggungan (anak atau hutang) adalah menjadi tanggungan Allah dan Rasul-Nya, \" atau sepertinya berkata; \"Maka kembalinya kepada kami, Barangsiapa yang meninggalkan harta maka itu untuk ahli warisnya. Paman dari ibu adalah ahli waris jika tidak ada ahlu waris yang lainnya. Saya adalah penjamin bagi yang tidak ada ahli warisnya, saya mewarisinya dan menanggung semua tanggungannya.\" Telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepada kami [Syu'bah] lalu menyebutkanya dan berkata; dari [Al Miqdam] dari Kindah, dia adalah salah seorang sahabat Nabi Shallallahu'alaihiwasallam, dari Nabi Shallallahu'alaihiwasallam semisalnya."},"1450":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنِ ابْنِ الْمُبَارَكِ عَنْ ثَوْرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِيلُوا طَعَامَكُمْ يُبَارَكْ لَكُمْ فِيهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Ibnu Mubarak] dari [Tsaur] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'di Karib] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Takarlah makanan kalian, niscaya Allah akan memberkati.\""},"1451":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَطْعَمْتَ نَفْسَكَ فَهُوَ لَكَ صَدَقَةٌ وَمَا أَطْعَمْتَ وَلَدَكَ فَهُوَ لَكَ صَدَقَةٌ وَمَا أَطْعَمْتَ زَوْجَكَ فَهُوَ لَكَ صَدَقَةٌ وَمَا أَطْعَمْتَ خَادِمَكَ فَهُوَ لَكَ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Abu 'Abbas] berkata; telah menceritakan kepada kami [Baqiyyah] berkata; telah menceritakan kepada kami [Bahir bin Sa'id] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'di Karib] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika kamu memberi makan pada diri kamu, maka itu menjadi sedekah bagimu, jika kamu memberi makan pada anakmu maka itu menjadi sedekah bagimu, jika kamu memberi makan pada istrimu maka itu menjadi sedekah bagimu, jika kamu memberi makan pada pelayanmu maka itu menjadi sedekah bagimu.\""},"1452":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ أَرْطَاةَ بْنِ الْمُنْذِرِ عَنْ بَعْضِ أَشْيَاخِ الْجُنْدِ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ لَطْمِ خُدُودِ الدَّوَابِّ وَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ جَعَلَ لَكُمْ عِصِيًّا وَسِيَاطًا","id":"Telah menceritakan kepada kami [Suraij bin Nu'man] telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Arthah bin Al Munzdir] dari [beberapa syaikh Al Jundi] dari [Al Miqdam bin Ma'di Karib] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam melarang menampar pipi hewan tunggangan dan bersabda: \"Allah Azzawajalla telah menjadikan untuk kalian tongkat dan cemeti.\""},"1453":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ حَدَّثَنَا خَالِدُ بْنُ مَعْدَانَ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أَكَلَ أَحَدٌ مِنْكُمْ طَعَامًا أَحَبَّ إِلَى اللَّهِ عَزَّ وَجَلَّ مِنْ عَمَلِ يَدَيْهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Abu 'Abbas] telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepada kami [Bahir bin Sa'ad] telah menceritakan kepada kami [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'di Karib] sesungguhnya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah salah seorang dari kalian bisa menyantap makanan yang lebih dicintai oleh Allah Azzawajalla daripada santapan yang dihasilkan dari usaha kedua tangannya.\""},"1454":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُوصِيكُمْ بِالْأَقْرَبِ فَالْأَقْرَبِ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepadaku [Bahir bin Sa'ad] dari [Khalid Ma'dan] dari [Al Miqdam bin Ma'di Karib] sesungguhnya ia mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah Azzawajalla mewasiatkan kepada kalian untuk mendahulukan kebaikan kepada kerabat yang paling dekat, dan selanjutnya, dan selanjutnya.\""},"1455":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ وَأَحْمَدُ بْنُ عَبْدِ الْمَلِكِ قَالَا حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَرِيرِ وَالذَّهَبِ وَعَنْ مَيَاثِرِ النُّمُورِ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] dan [Ahmad bin Abdul Malik] berkata; telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepadaku [Bahir bin Sa'ad] dari [Khalid bin Miqdam] dari [Al Miqdam bin Ma'di Karib] berkata; Rasulullah Shallallahu'alaihiwasallam melarang sutra, emas dan kain penutup yang terbuat dari kulit harimau."},"1456":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا حَرِيزٌ قَالَ سَمِعْتُ سَعْدَ بْنَ مَرْثَدٍ الرَّحَبِيَّ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ حَوْشَبٍ يُحَدِّثُ عَنْ ثَوْبَانَ بْنِ شَهْرٍ قَالَ سَمِعْتُ كُرَيْبَ بْنَ أَبْرَهَةَ وَهُوَ جَالِسٌ مَعَ عَبْدِ الْمَلِكِ بِدَيْرِ الْمُرَّانِ وَذَكَرُوا الْكِبْرَ فَقَالَ كُرَيْبٌ سَمِعْتُ أَبَا رَيْحَانَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ لَا يَدْخُلُ شَيْءٌ مِنْ الْكِبْرِ الْجَنَّةَ قَالَ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ إِنِّي أُحِبُّ أَنْ أَتَجَمَّلَ بِسَبْقِ سَوْطِي وَشِسْعِ نَعْلِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ ذَلِكَ لَيْسَ بِالْكِبْرِ إِنَّ اللَّهَ عَزَّ وَجَلَّ جَمِيلٌ يُحِبُّ الْجَمَالَ إِنَّمَا الْكِبْرُ مَنْ سَفِهَ الْحَقَّ وَغَمَصَ النَّاسَ بِعَيْنَيْهِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Hariz] berkata; saya telah mendengar [Sa'ad bin Martsad Ar-Rahabi] berkata; saya telah mendengar [Abdurrahman bin Hautsab] menceritakan dari [Tsauban bin Syahr] berkata; saya mendengar [Kuraib bin Abrahah] dia duduk bersama Abdul Malik di Dair Al Murrah mereka menyebutkan tentang 'sombong lalu Kuraib berkata; saya mendengar [Abu Raihanah] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kesombongan walaupun sedikit tidak akan masuk surga, \" (Abu Raihanah Radliyallahu'anhu) berkata; lalu ada seseorang yang berkata; \"Wahai Rasulullah, sesungguhnya saya senang berhias diri dengan cemeti yang pernah dihadiahkan kepadaku dan tali-temali sandalku.\" Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Kalau yang itu bukan termasuk kesombongan. Sesungguhnya Allah Azzawajalla indah menyukai keindahan. Sesungguhnya kesombongan itu siapa yang tidak mau tahu terhadap kebenaran dan meremehkan manusia dengan kedua matanya.\""},"1457":{"ar":"حَدَّثَنَا عِصَامُ بْنُ خَالِدٍ حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ عَنْ سَعْدِ بْنِ مَرْثَدٍ الرَّحَبِيِّ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ حَوْشَبٍ يُحَدِّثُ عَنْ ثَوْبَانَ بْنِ شَهْرٍ الْأَشْعَرِيِّ قَالَ سَمِعْتُ كُرَيْبَ بْنَ أَبْرَهَةَ وَهُوَ جَالِسٌ مَعَ عَبْدِ الْمَلِكِ عَلَى سَرِيرِهِ بِدَيْرِ الْمُرَّانِ وَذَكَرَ الْكِبْرَ فَقَالَ كُرَيْبٌ سَمِعْتُ أَبَا رَيْحَانَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَدْخُلُ شَيْءٌ مِنْ الْكِبْرِ الْجَنَّةَ فَقَالَ قَائِلٌ يَا نَبِيَّ اللَّهِ إِنِّي أُحِبُّ أَنْ أَتَجَمَّلَ بِحَبْلَانِ سَوْطِي وَشِسْعِ نَعْلِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ ذَلِكَ لَيْسَ بِالْكِبْرِ إِنَّ اللَّهَ عَزَّ وَجَلَّ جَمِيلٌ يُحِبُّ الْجَمَالَ إِنَّمَا الْكِبْرُ مَنْ سَفِهَ الْحَقَّ وَغَمَصَ النَّاسَ بِعَيْنَيْهِ يَعْنِي بِالْحَبْلَانِ سَيْرَ السَّوْطِ وَشِسْعَ النَّعْلِ","id":"Telah menceritakan kepada kami ['Isham bin Khalid] telah menceritakan kepada kami [Hariz bin 'Utsman] dari [Sa'ad bin Martsad Ar-Rahabi] berkata; saya telah mendengar [Abdurrahman bin Hautsab] menceritakan dari [Tsauban bin Syahr Al Asy'ari] berkata; saya telah mendengar [Kuraib bin Abrahah] dia duduk bersama Abdul Malik di atas tempat tidurnya di Dair Al Murrah, dia menyebutkan tentang 'sombong' lalu Kuraib berkata; saya mendengar [Abu Raihanah] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sedikit saja dari kesombongan tidak akan masuk surga, \" (Abu Raihanah Rasulullah) berkata; lalu ada seseorang yang berkata; \"Wahai Nabiyullah, saya senang berdandan dengan dua tali cemetiku dan tali sandalku.\" Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Itu bukan termasuk kesombongan, sesungguhnya Allah Azzawajalla Maha indah dan menyukai keindahan. Sesungguhnya kesombongan itu siapa saja yang tidak mau tahu terhadap kebenaran dan meremehkan manusia dengan kedua matanya.\" Redaksi hablan maksudnya tali cemeti dan tali sandal."},"1458":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا لَيْثٌ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْحُصَيْنِ الْحِمْيَرِيِّ عَنْ أَبِي رَيْحَانَةَ أَنَّهُ قَالَبَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْوَشْرِ وَالْوَشْمِ وَالنَّتْفِ وَالْمُشَاغَرَةِ وَالْمُكَامَعَةِ وَالْوِصَالِ وَالْمُلَامَسَةِ","id":"Telah menceritakan kepada kami [Hajjaj bin Muhammad] telah menceritakan kepada kami [Laits] telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Abu Al Hushain Al Himyari] dari [Abu Raihanah] sesungguhnya dia berkata; telah sampai berita kepada kami sesungguhnya Rasulullah Shallallahu'alaihiwasallam melarang mengikir gigi, mentato, mencukur alis, nikah syighar (nikah yang disertakan dengan nikah lain tanpa adanya mahar), tidur dua orang dalam satu selimut, puasa wishal (puasa tanpa disertai dengan berbuka) dan memaksa membeli jika barang telah disentuhnya."},"1459":{"ar":"حَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ حَدَّثَنِي عَيَّاشُ بْنُ عَبَّاسٍ عَنْ أَبِي الْحُصَيْنِ الْهَيْثَمِ بْنِ شُفَيٍّ أَنَّهُ سَمِعَهُ يَقُولُخَرَجْتُ أَنَا وَصَاحِبٌ لِي يُسَمَّى أَبَا عَامِرٍ رَجُلٌ مِنْ الْمَعَافِرِ لِيُصَلِّيَ بِإِيلِيَاءَ وَكَانَ قَاصُّهُمْ رَجُلًا مِنْ الْأَزْدِ يُقَالُ لَهُ أَبُو رَيْحَانَةَ مِنْ الصَّحَابَةِ قَالَ أَبُو الْحُصَيْنِ فَسَبَقَنِي صَاحِبِي إِلَى الْمَسْجِدِ ثُمَّ أَدْرَكْتُهُ فَجَلَسْتُ إِلَى جَنْبِهِ فَسَأَلَنِي هَلْ أَدْرَكْتَ قَصَصَ أَبِي رَيْحَانَةَ فَقُلْتُ لَا فَقَالَ سَمِعْتُهُ يَقُولُ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَشْرَةٍ عَنْ الْوَشْرِ وَالْوَشْمِ وَالنَّتْفِ وَعَنْ مُكَامَعَةِ الرَّجُلِ الرَّجُلَ بِغَيْرِ شِعَارٍ وَعَنْ مُكَامَعَةِ الْمَرْأَةِ الْمَرْأَةَ بِغَيْرِ شِعَارٍ وَأَنْ يَجْعَلَ الرَّجُلُ فِي أَسْفَلِ ثِيَابِهِ حَرِيرًا مِثْلَ الْأَعْلَامِ وَأَنْ يَجْعَلَ عَلَى مَنْكِبَيْهِ مِثْلَ الْأَعَاجِمِ وَعَنْ النُّهْبَى وَرُكُوبِ النُّمُورِ وَلَبُوسِ الْخَاتَمِ إِلَّا لِذِي سُلْطَانٍ","id":"Telah menceritakan kepada kami [Yahya bin Ghailan] telah menceritakan kepada kami [Al Mufadlal bin Fadlalah] telah menceritakan kepadaku ['Ayyas bin 'Abbas] dari [Abu Al Hushain Al Haitsam bin Syufai] sesungguhnya telah mendengarnya, berkata; saya bersama sahabatku yang bernama [Abu 'Amir] keluar seseorang dari Ma'afir untuk shalat di 'Iliya', dia adalah seorang ahli kisah, seseorang dari Azd yang bernama [Abu Raihanah] dari kalangan sahabat, Abu Hushain berkata; \"Lalu sahabat saya mendahuluiku, ke masjid, saya pun menemuinya, lalu saya duduk di sampingnya, dan dia bertanya kepadaku, \"Apakah kamu mendapatkan kisah Abu Raihanah?\" saya menjawab, \"Tidak.\" Lalu dia berkata; saya mendengarnya berkata; \"Rasulullah Shallallahu'alaihiwasallam melarang mengikir gigi, mentato, mencukur alis, seorang laki-laki yang tidur dengan laki-laki lainnya tanpa dengan pakaian. Seorang wanita yang tidur dengan wanita lainnya dalam satu selimut. Seorang laki-laki yang menjadikan bagian bawah pakaiannya dari sutra sebagaimana orang terkenal atau dia menaruhkannya pada kedua pundaknya sebagaimana orang asing, merampok dan menaiki kendaraan yang terbuat dari kulit macan dan memakai cincin kecuali penguasa.\""},"1460":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ الْحِمْيَرِيِّ عَنْ أَبِي حُصَيْنٍ الْحَجْرِيِّ عَنْ عَامِرٍ الْحَجْرِيِّ عَنْ أَبِي رَيْحَانَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَرِهَ عَشْرَ خِصَالٍ الْوَشْرَ وَالنَّتْفَ وَالْوَشْمَ وَمُكَامَعَةَ الرَّجُلِ الرَّجُلَ وَالْمَرْأَةِ الْمَرْأَةَ لَيْسَ بَيْنَهُمَا ثَوْبٌ وَالنُّهْبَةَ وَرُكُوبَ النُّمُورِ وَاتِّخَاذَ الدِّيبَاجِ هَاهُنَا وَهَاهُنَا أَسْفَلَ فِي الثِّيَابِ وَفِي الْمَنَاكِبِ وَالْخَاتَمَ إِلَّا لِذِي سُلْطَانٍ","id":"Telah menceritakan kepada kami [Zaid bin Al Habhab] telah menceritakan kepadaku [Yahya bin Ayyub] dari ['Ayyasy bin 'Abbas Al Himyari] dari [Abu Hushain Al Hajri] dari ['Amir Al Hajri] dari [Abu Raihanah] dari Nabi Shallallahu'alaihiwasallam, sesungguhnya Rasulullah Shallallahu'alaihiwasallam membenci sepuluh hal: mengikir gigi, mencukur alis, mentato, seorang laki-laki yang tidur dengan laki-laki lainnya dalam, seorang wanita dengan wanita lainnya tanpa pakaian. Merampok, menaiki kendaraan yang ada kulit macannya, menjadikan sutra di sini dan di sini, pada bagian bawah pakaian dan juga pada pundaknya dan memakai stempel kecuali penguasa.\""},"1461":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى الْأَشْيَبُ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا عَيَّاشُ بْنُ عَبَّاسٍ قَالَ حَدَّثَنِي أَبُو الْحُصَيْنِ عَنْ أَبِي رَيْحَانَةَ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْخَاتَمِ إِلَّا لِذِي سُلْطَانٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Musa Al Asyyab] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakan kepada kami ['Ayyasy bin 'Abbas] berkata; telah menceritakan kepadaku [Abu Al Hushain] dari [Abu Raihanah] sahabat Nabi Shallallahu'alaihiwasallam, Rasulullah Shallallahu'alaihiwasallam melarang cincin kecuali bagi penguasa."},"1462":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ حُمَيْدٍ الْكِنْدِيِّ عَنْ عُبَادَةَ بْنِ نُسَىٍّ عَنْ أَبِي رَيْحَانَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ انْتَسَبَ إِلَى تِسْعَةِ آبَاءٍ كُفَّارٍ يُرِيدُ بِهِمْ عِزًّا وَكَرَمًا فَهُوَ عَاشِرُهُمْ فِي النَّارِ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Humaid Al Kindi] dari ['Ubadah bin Nusay] dari [Abu Raihanah] sesungguhnya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menisbahkan kepada sembilan bapak yang kafir karena menghendaki kegagahan dan kemuliaan maka dia adalah orang yang ke sepuluh di neraka."},"1463":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ سُمَيْرٍ الرُّعَيْنِيَّ يَقُولُ سَمِعْتُ أَبَا عَامِرٍ التُّجِيبِيَّ قَالَ أَبِي وَقَالَ غَيْرُهُ الْجَنَبِيَّ يَعْنِي غَيْرَ زَيْدٍ أَبُو عَلِيٍّ الْجَنَبِيُّ يَقُولُ سَمِعْتُ أَبَا رَيْحَانَةَ يَقُولُكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَأَتَيْنَا ذَاتَ لَيْلَةٍ إِلَى شَرَفٍ فَبِتْنَا عَلَيْهِ فَأَصَابَنَا بَرْدٌ شَدِيدٌ حَتَّى رَأَيْتُ مَنْ يَحْفِرُ فِي الْأَرْضِ حُفْرَةً يَدْخُلُ فِيهَا يُلْقِي عَلَيْهِ الْحَجَفَةَ يَعْنِي التُّرْسَ فَلَمَّا رَأَى ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ النَّاسِ نَادَى مَنْ يَحْرُسُنَا فِي هَذِهِ اللَّيْلَةِ وَأَدْعُو لَهُ بِدُعَاءٍ يَكُونُ فِيهِ فَضْلٌ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ أَنَا يَا رَسُولَ اللَّهِ فَقَالَ ادْنُهْ فَدَنَا فَقَالَ مَنْ أَنْتَ فَتَسَمَّى لَهُ الْأَنْصَارِيُّ فَفَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالدُّعَاءِ فَأَكْثَرَ مِنْهُ قَالَ أَبُو رَيْحَانَةَ فَلَمَّا سَمِعْتُ مَا دَعَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَنَا رَجُلٌ آخَرُ فَقَالَ ادْنُهْ فَدَنَوْتُ فَقَالَ مَنْ أَنْتَ قَالَ فَقُلْتُ أَنَا أَبُو رَيْحَانَةَ فَدَعَا بِدُعَاءٍ هُوَ دُونَ مَا دَعَا لِلْأَنْصَارِيِّ ثُمَّ قَالَ حُرِّمَتْ النَّارُ عَلَى عَيْنٍ دَمَعَتْ أَوْ بَكَتْ مِنْ خَشْيَةِ اللَّهِ وَحُرِّمَتْ النَّارُ عَلَى عَيْنٍ سَهِرَتْ فِي سَبِيلِ اللَّهِ أَوْ قَالَ حُرِّمَتْ النَّارُ عَلَى عَيْنٍ أُخْرَى ثَالِثَةٍ لَمْ يَسْمَعْهَا مُحَمَّدُ بْنُ سُمَيْرٍوَقَالَ غَيْرُهُ يَعْنِي غَيْرَ زَيْدٍ أَبُو عَلِيٍّ الْجَنَبِيُّ","id":"Telah menceritakan kepada kami [Zaid bin Al Habhab] berkata; telah menceritakan kepadaku [Abdurrahman bin Syuraikh] berkata; saya telah mendengar [Muhammad bin Sumair Ar-Ru'aini] berkata; saya telah mendengar [Abu 'Amir At-Tujibi] bapakku berkata; dan yang lainnya berkata; Al Janabi yaitu selain Zaid Abu Ali yaitu Al Janabi berkata; saya telah mendengar [Abu Raihanah] berkata; \"Kami bersama Rasulullah Shallallahu'alaihiwasallam dalam suatu peperangan, pada suatu malam kami mendatangi ke suatu tempat yang agak tinggi, lalu kami bermalam disitu. Kami merasakan kedinginan yang sangat, sampai saya melihat ada orang yang menggali lobang pada tanah lalu dia jadikan untuk berdiam diri, dan dia letakkan hajfah atau tamengnya diatas lubang itu.\" Tatkala Rasulullah Shallallahu'alaihiwasallam melihat hal itu, beliau memanggil, \"Siapa yang hendak menjaga kami pada malam itu, dan saya akan mendoakannya dengan doa yang berisikan keutamaan!, lalu ada seorang laki-laki anshar berkata; \"Saya Wahai Rasulullah.\" lalu beliau bersabda: \"Siapakah kamu\", lalu orang Anshar itu menyebutkan namanya, Rasulullah Shallallahu'alaihiwasallam membuka dengan do'a, dengan banyak doa. Abu Raihanah berkata; \"Tatkala saya mendengar doa yang dipanjatkan Rasulullah Shallallahu'alaihiwasallam, saya berkata; 'Saya akan ikut.\" Beliau bersabda: \"Mendekatlan, \" Saya pun mendekat, beliau bertanya, \"Siapakah kamu?\". Dia berkata; \"Saya Abu Raihanah, \" lalu beliau berdoa dengan doa yang lain dengan doa kepada orang Anshar. Beliau bersabda: \"Diharamkan neraka atas mata yang menetes atau menangis karena takut kepada takut Allah dan diharamkan neraka atas mata yang berjaga di jalan Allah, \" atau berkata; \"Atau diharamkan pada neraka atas mata lain (yang disebut nabi pada kali ketiga) yang tidak didengar Muhammad bin Sumair dan yang lainnya berkata; yaitu selain Zaid Abu Ali Al Janabi."},"1464":{"ar":"حَدَّثَنَا عَتَّابٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ قَالَ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ أَخْبَرَنِي عَيَّاشُ بْنُ عَبَّاسٍ الْقِتْبَانِيُّ عَنْ أَبِي الْحُصَيْنِ الْحَجْرِيِّ أَنَّهُ أَخْبَرَهُأَنَّهُ وَصَاحِبًا لَهُ يَلْزَمَانِ أَبَا رَيْحَانَةَ يَتَعَلَّمَانِ مِنْهُ خَيْرًا قَالَ فَحَضَرَ صَاحِبِي يَوْمًا وَلَمْ أَحْضُرْ فَأَخْبَرَنِي صَاحِبِي أَنَّهُ سَمِعَ أَبَا رَيْحَانَةَ يَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ عَشْرَةً الْوَشْرَ وَالْوَشْمَ وَالنَّتْفَ وَمُكَامَعَةَ الرَّجُلِ الرَّجُلَ لَيْسَ بَيْنَهُمَا ثَوْبٌ وَمُكَامَعَةَ الْمَرْأَةِ بِالْمَرْأَةِ لَيْسَ بَيْنَهُمَا ثَوْبٌ وَخَطَّيْ حَرِيرٍ عَلَى أَسْفَلِ الثَّوْبِ وَخَطَّيْ حَرِيرٍ عَلَى الْعَاتِقَيْنِ وَالنَّمِرَ يَعْنِي جِلْدَةَ النَّمِرِ وَالنُّهْبَةَ وَالْخَاتَمَ إِلَّا لِذِي سُلْطَانٍ","id":"Tel ah menceritakan kepada kami ['Attab] berkata; telah menceritakan kepada kami [Abdullah] yaitu Ibnu Mubarak berkata; telah menceritakan kepada kami [Haiwah bin Syuraikh] telah mengabarkan kepadaku [Ayyas bin 'Abbas Al Qitbani] dari [Abu Al Hushain Al Hajri] sesungguhnya dia mengabarinya, sesungguhnya dia dan sahabatnya, menemui Abu Raihanah untuk belajar kebaikan. (Abu Raihanah Radliyallahu'anhu) berkata; \"Lalu sahabatku datang pada suatu hari, dan saya belum datang.\" Lalu [sahabatku] mengabarkanku, ia mendengar [Abu Raihanah] berkata; \"Rasulullah Shallallahu'alaihiwasallam mengharamkan sepuluh hal: mengikir gigi, mentato, mencukur alis, seorang laki-laki yang tidur dengan laki-laki lainnya tanpa selimut, seorang wanita dengan wanita lainnya tanpa pakaian. Menutup bagian bawah pakaian dengan sutra atau meletakkan sutera itu pada dua pundaknya, menggunakan kulit harimau, merampok dan memakai cincin kecuali penguasa.\""},"1465":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ سَمِعْتُ ابْنَ جَابِرٍ يَقُولُ حَدَّثَنِي بُسْرُ بْنُ عُبَيْدِ اللَّهِ الْحَضْرَمِيُّ أَنَّهُ سَمِعَ وَاثِلَةَ بْنَ الْأَسْقَعِ صَاحَبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حَدَّثَنِي أَبُو مَرْثَدٍ الْغَنَوِيُّسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُصَلُّوا إِلَى الْقُبُورِ وَلَا تَجْلِسُوا عَلَيْهَا","id":"Telah menceritakan kepada kami [Al Walid bin Muslim] berkata; saya mendengar [Ibnu Jabir] berkata; telah menceritakan kepadaku [Busr bin 'Ubaidullah Al Hadrami], ia mendengar [Watsilah bin Al Asqa'] sahabat Rasulullah Shallallahu'alaihiwasallam berkata; telah menceritakan kepadaku [Abu Martsad Al Ghanawi] mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah shalat ke arah kubur dan janganlah kalian duduk di atasnya.\""},"1466":{"ar":"حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ قَالَ أَبِي و حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ وَقَالَ حَدَّثَنَا بُسْرُ بْنُ عُبَيْدِ اللَّهِ قَالَ عَلِيٌّ حَدَّثَنَا بُسْرُ بْنُ عُبَيْدِ اللَّهِ قَالَ سَمِعْتُ أَبَا إِدْرِيسَ يَقُولُ سَمِعْتُ وَاثِلَةَ بْنَ الْأَسْقَعِ يَقُولُ سَمِعْتُ أَبَا مَرْثَدٍ الْغَنَوِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَجْلِسُوا عَلَى الْقُبُورِ وَلَا تُصَلُّوا عَلَيْهَا","id":"Telah menceritakan kepada kami ['Attab bin Ziyad] berkata; telah menceritakan kepada kami [Abdullah] yaitu Ibnu Al Mubarak, bapakku berkata; dan telah menceritakan kepada kami [Ali bin Ishaq] berkata; telah menceritakan kepada kami [Abdullah] berkata; telah menceritakan kepada kami [Abdurrahman bin Yazid bin Jabir] dan berkata; telah menceritakan kepada kami [Busr bin 'Ubaidullah] [Ali] berkata; telah menceritakan kepada kami [Busr bin 'Ubaid] berkata; saya telah mendengar [Abu Idris] berkata; saya telah mendengar [Watsilah bin Al Asqa'] berkata; saya telah mendengar [Abu Martsad Al Ghanawi] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah kalian duduk di atas kubur dan janganlah kalian shalat ke arahnya.\""},"1467":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ وَيَزِيدُ بْنُ عَبْدِ رَبِّهِ قَالَا حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنِي بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ حَدَّثَنَا جُبَيْرُ بْنُ نُفَيْرٍ أَنَّ عُمَرَ الْجُمَعِيَّ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَرَادَ اللَّهُ بِعَبْدٍ خَيْرًا اسْتَعْمَلَهُ قَبْلَ مَوْتِهِ فَسَأَلَهُ رَجُلٌ مِنْ الْقَوْمِ مَا اسْتَعْمَلَهُ قَالَ يَهْدِيهِ اللَّهُ عَزَّ وَجَلَّ إِلَى الْعَمَلِ الصَّالِحِ قَبْلَ مَوْتِهِ ثُمَّ يَقْبِضُهُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] dan [Yazid bin Abdu Rabbihi] berkata; telah menceritakan kepada kami [Baqiyyah bin Al Walid] telah menceritakan kepadaku [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] telah menceritakan kepada kami [Jubair bin Nufair] sesungguhnya ['Umar Al Juma'i] menceritakannya, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika Allah menghendaki kebaikan pada seorang hamba, niscaya Allah menjadikannya sebagai pemimpin sebelum meninggalnya, \" lalu ada seorang laki-laki dari kaumnya yang bertanya, 'Apa yang dimaksud dengan menjadikannya pemimpin? ', dia berkata; \"Allah Azzawajalla menunjukinya kepada amal shalih sebelum matinya lalu dia meninggal dalam keadaan demikian.\""},"1468":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدّ��ثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّهُ أَخْبَرَهُ بَعْضُ مَنْ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَيْبَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ مِمَّنْ مَعَهُ إِنَّ هَذَا لَمِنْ أَهْلِ النَّارِ فَلَمَّا حَضَرَ الْقِتَالُ قَاتَلَ الرَّجُلُ أَشَدَّ الْقِتَالِ حَتَّى كَثُرَتْ بِهِ الْجِرَاحُ فَأَتَاهُ رِجَالٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ أَرَأَيْتَ الرَّجُلَ الَّذِي ذَكَرْتَ أَنَّهُ مِنْ أَهْلِ النَّارِ فَقَدْ وَاللَّهِ قَاتَلَ فِي سَبِيلِ اللَّهِ أَشَدَّ الْقِتَالِ وَكَثُرَتْ بِهِ الْجِرَاحُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ مِنْ أَهْلِ النَّارِ وَكَادَ بَعْضُ النَّاسِ أَنْ يَرْتَابَ فَبَيْنَمَا هُمْ عَلَى ذَلِكَ وَجَدَ الرَّجُلُ أَلَمَ الْجِرَاحِ فَأَهْوَى بِيَدِهِ الرَّجُلُ إِلَى كِنَانَتِهِ فَانْتَزَعَ مِنْهَا سَهْمًا فَانْتَحَرَ بِهِ فَاشْتَدَّ رَجُلٌ مِنْ الْمُسْلِمِينَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ قَدْ صَدَّقَ اللَّهُ حَدِيثَكَ قَدْ انْتَحَرَ فُلَانٌ فَقَتَلَ نَفْسَهُ","id":"Telah mengabarkan kepada kami [Ya'qub] berkata; telah menceritakan kepada kami [bapakku] dari [Shalih bin Kaisan] [Ibnu Syihab] berkata; telah menceritakan kepadaku [Abdurrahman bin Abdullah bin Ka'ab bin Malik] sesungguhnya dia mengabarinya [sebagian yang menyaksikan Nabi Shallallahu'alaihiwasallam] di Khaibar, Rasulullah Shallallahu'alaihiwasallam bersabda kepada seorang laki-laki yang bersamanya, \"Orang ini termasuk dari penduduk neraka. Tatkala datang pertempuran yang sangat dahsyat, orang itu berperang dengan sangat gigihnya sampai banyak lukanya, lalu beberapa sahabat Nabi Shallallahu'alaihiwasallam mendatanginya.\" Mereka katakan, \"Wahai Rasulullah, bagaimana anda mengatakan bahwa orang yang anda sebutkan adalah dari penduduk neraka, demi Allah dia telah berperang di jalan Allah dengan perang yang dahsyat dan banyak sekali lukanya.\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Dia termasuk penduduk neraka, dan sebagian orang ragu, tatkala mereka dalam keadaan demikian, lalu seorang laki-laki itu merasakan sakitnya, lalu laki-laki itu mengulurkan tangannya ke tempat panahnya dari kulit, dia mencabut panah dari kulit itu, dan dia membunuh dirinya sendiri. Beberapa orang kaum muslimin kontan mendatangi Rasulullah Shallallahu'alaihiwasallam dan berkata; \"Wahai Nabiyullah, Allah telah membenarkan perkataan anda. Fulan telah membunuh dirinya sendiri.\""},"1469":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُمَارَةَ بْنِ رُوَيْبَةَ الثَّقَفِيِّ قَالَرَأَى بِشْرَ بْنَ مَرْوَانَ رَافِعًا يَدَيْهِ يَوْمَ الْجُمُعَةِ فَقَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ وَمَا يَقُولُ إِلَّا هَكَذَا وَأَشَارَ بِإِصْبَعِهِ السَّبَّابَةِ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Sufyan] dari [Hushain bin Abdurrahman] dari ['Umarah bin Ruwaibah Ats-Tsaqafi] berkata; Bisr bin Marwan melihat mengangkat kedua tangannya pada hari Jumat, lalu dia berkata; \"Saya melihat Rasulullah Shallallahu'alaihiwasallam di atas mimbar pada hari Jumat dan tidak membaca kecuali demikian dengan mengisyaratkan jarinya telunjuknya."},"1470":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عِمَارَةَ بْنِ رُوَيْبَةَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ سُفْيَانُ مَرَّةً سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَنْ يَلِجَ النَّارَ أَحَدٌ صَلَّى قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَاقِيلَ لِسُفْيَانَ مِمَّنْ سَمِعَهُ قَالَ مِنْ عُمَارَةَ بْنِ رُوَيْبَةَ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdul Malik bin 'Umair] dari ['Imarah bin Ruwai'bah] saya telah mendengar Rasulullah Shallallahu'alaihiwasallam dan [Sufyan] berkata; mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak akan masuk neraka orang yang shalat sebelum terbitnya matahari dan sebelum terbenamnya, \" ditanyakan kepada Sufyan dari mana dia mendengarnya? Ia menjawab, dari 'Umarah bin Ruwai'bah."},"1471":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حُصَيْنٍأَنَّ بِشْرَ بْنَ مَرْوَانَ رَفَعَ يَدَيْهِ يَوْمَ الْجُمُعَةِ عَلَى الْمِنْبَرِ فَقَالَ عُمَارَةُ بْنُ رُوَيْبَةَ مَا زَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى هَذَا وَأَشَارَ بِإِصْبَعِهِ السَّبَّابَةِ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Hushain] sesungguhnya Bisr bin Marwan mengangkat kedua tangannya pada hari Jumat di atas mimbar lalu ['Umarah bin Ruwai'bah] tidaklah Rasulullah Shallallahu'alaihiwasallam menambahi hal ini dan dia memberi isyarat dengan jari telunjuknya."},"1472":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ قَالَ وَحَدَّثَنَا أَبُو الْوَلِيدِ هِشَامٌ وَعَفَّانُ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ قَالَ عَفَّانُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنِ ابْنِ عِمَارَةَ بْنِ رُوَيْبَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَلِجُ النَّارَ مَنْ صَلَّى قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا وَعِنْدَهُ رَجُلٌ قَالَ عَفَّانُ مِنْ أَهْلِ الْبَصْرَةِ فَقَالَ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ نَعَمْ أَشْهَدُ بِهِ عَلَيْهِ قَالَ وَأَنَا أَشْهَدُ لَقَدْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهُ فِي الْمَكَانِ الَّذِي سَمِعْتَهُ مِنْهُ قَالَ عَفَّانُ فِيهِحَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا شَيْبَانُ عَنْ عَبْدِ الْمَلِكِ عَنِ ابْنِ عُمَارَةَ بْنِ رُوَيْبَةَ الثَّقَفِيِّ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَلِجُ النَّارَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] berkata; dan telah menceritakan kepada kami [Abu Al Walid, Hisyam] dan ['Affan] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abdul Malik] ['Affan] berkata; telah menceritakan kepada kami [Abdul Malik bin 'Umair] dari [Ibnu 'Imarah bin Ruwaibah] dari [Bapaknya] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak masuk neraka orang yang shalat sebelum terbit matahari dan sebelum terbenamnya dan di sisinya ada seorang laki-laki.\" 'Affan berkata; dari penduduk Basrah. Lalu (Ibnu 'Imarah bin Ruwaibah Radliyallahu'anhu) berkata; \"Apakah kamu mendengar hal ini dari Rasulullah Shallallahu'alaihiwasallam?\" dia menjawab, \"Ya. Saya menyaksikannya.\" Lalu (Ibnu 'Imarah bin Ruwaibah Radliyallahu'anhu) berkata; \"Saya menyaksikan, sungguh saya mendengar Nabi Shallallahu'alaihiwasallam bersabda di tempat yang kamu mendengarnya dari beliau.\" ['Affan] berkata di dalamanya, telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Syaiban] dari [Abdul Malik] dari [Ibnu 'Umarah bin Ruwaibah Ats-Tsaqafi] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak masuk neraka, \" lalu menyebutkan semisalnya."},"1473":{"ar":"حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا زُهَيْرٌ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ السُّلَمِيِّ قَالَكُنْتُ إِلَى جَنْبِ عِمَارَةَ بْنِ رُوَيْبَةَ وَبِشْرٌ يَخْطُبُنَا فَلَمَّا دَعَا رَفَعَ يَدَيْهِ فَقَالَ عِمَارَةُ يَعْنِي قَبَّحَ اللَّهُ هَاتَيْنِ الْيَدَيْنِ أَوْ هَاتَيْنِ الْيُدِيَّتَيْنِ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ إِذَا دَعَا يَقُولُ هَكَذَا وَرَفَعَ السَّبَّابَةَ وَحْدَهَا","id":"Telah menceritakan kepada kami [Musa bin Daud] telah menceritakan kepada kami [Zuhair] dari [Hushain bin Abdurrahman As-Sulami] berkata; saya berada di samping ['Imarah bin Ruwaibah] dan Bisyr berkhutbah kepada kami, tatkala berdoa, dia mengangkat kedua tangannya, lalu Imarah berkata; \"Semoga Allah menjelekkan kedua tangan itu, saya telah melihat Rasulullah Shallallahu'alaihiwasallam berkhutbah, jika berdo'a hanya mengangkat jari telunjuknya satu saja.\""},"1474":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنَا لَيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي عُقَيْلٌ عَنِ ابْنِ شِهَابٍ عَنِ ابْنِ أَبِي نَمْلَةَ أَنَّ أَبَا نَمْلَةَ الْأَنْصَارِيَّ أَخْبَرَهُ أَنَّهُبَيْنَمَا هُوَ جَالِسٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهُ رَجُلٌ مِنْ الْيَهُودِ فَقَالَ يَا مُحَمَّدُ هَلْ تَتَكَلَّمُ هَذِهِ الْجَنَازَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَعْلَمُ قَالَ الْيَهُودِيُّ أَنَا أَشْهَدُ أَنَّهَا تَتَكَلَّمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَدَّثَكُمْ أَهْلُ الْكِتَابِ فَلَا تُصَدِّقُوهُمْ وَلَا تُكَذِّبُوهُمْ وَقُولُوا آمَنَّا بِاللَّهِ وَكُتُبِهِ وَرُسُلِهِ فَإِنْ كَانَ حَقًّا لَمْ تُكَذِّبُوهُمْ وَإِنْ كَانَ بَاطِلًا لَمْ تُصَدِّقُوهُمْحَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا يُونُسُ عَنِ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ أَبِي نَمْلَةَ أَنَّ أَبَاهُ حَدَّثَهُ قَالَ بَيْنَمَا أَنَا جَالِسٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهُ رَجُلٌ مِنْ الْيَهُودِ فَذَكَرَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ وَكِتَابِهِ وَرُسُلِهِ","id":"Telah menceritakan kepada kami [Hajjaj] berkata; telah mengabarkan kepada kami [Laits bin Sa'ad] berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] dari [Ibnu Abu Namlah Al Anshari] [Abu Namlah Al Anshari] mengabarinya, sesungguhnya tatkala dia duduk di samping Rasulullah Shallallahu'alaihiwasallam, datanglah seorang laki-laki dari Yahudi, lalu berkata; \"Wahai Muhammad, apakah jenazah ini bisa berbicara?\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Allah yang lebih tahu, \" orang Yahudi berkata; \"Saya bersaksi, sesungguhnya itu berbicara, \" Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika ada Ahli Kitab yang menceritakan kepada kalian, janganah kalian benarkan mereka, juga kalian dustakan mereka. Katakanlah, 'kami beriman kepada Allah, kitab-kitab-Nya dan para rasul-Nya. Jika memang itu benar, maka kalian tidak mendustakannya. Jika memang batil maka kalian tidak membenarkannya mereka.\" Telah menceritakan kepada kami ['Utsman bin 'Umar] berkata; telah menceritakan kepada kami [Yunus] dari [Az-Zuhri] berkata; telah mengabarkan kepadaku [Ibnu Abu Namlah] sesungguhnya [Bapaknya] menceritakannya berkata; tatkala saya sedang duduk bersama Rasulullah Shallallahu'alaihiwasallam, ada seorang laki-laki Yahudi yang datang, lalu menyebutkan hadits yang sama dengan yang di atas. Kecuali dengan perbedaan dalam lafadz, \"Pada Kitab-Nya dan Rasul-Nya.\""},"1475":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ الْمَلِكِ أَبِي جَعْفَرٍ عَنْ أَبِي نَضْرَةَ عَنْ سَعْدِ بْنِ الْأَطْوَلِ قَالَمَاتَ أَخِي وَتَرَكَ ثَلَاثَ مِائَةِ دِينَارٍ وَتَرَكَ وَلَدًا صِغَارًا فَأَرَدْتُ أَنْ أُنْفِقَ عَلَيْهِمْ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخَاكَ مَحْبُوسٌ بِدَيْنِهِ فَاذْهَبْ فَاقْضِ عَنْهُ قَالَ فَذَهَبْتُ فَقَضَيْتُ عَنْهُ ثُمَّ جِئْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ قَدْ قَضَيْتُ عَنْهُ وَلَمْ يَبْقَ إِلَّا امْرَأَةً تَدَّعِي دِينَارَيْنِ وَلَيْسَتْ لَهَا بَيِّنَةٌ قَالَ أَعْطِهَا فَإِنَّهَا صَادِقَةٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abdul Malik Abu Ja'far] dari [Abu Nadlrah] dari [Sa'ad bin Al Athwal] berkata; saudara laki-lakiku meninggal, ia meninggalkan hutang tiga ratus dinar dan seorang anak kecil. Saya pun berkehendak menginfakkan harta untuk mereka. lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku, \"Saudara kamu tertahan karena hutangnya, pergilah dan bayarlah!\" (Sa'ad bin Al Athwal Radliyallahu'anha) berkata; \"Saya pun pergi untuk membayarnya, saya kembali dan berkata; 'Wahai Rasulullah, saya telah memenuhinya dan tidak tersisa kecuali seorang wanita yang mengakui dengan dua dinar namun dia tidak mempunyai bukti.\" Beliau bersabda: \"Berikanlah sesungguhnya dia adalah jujur.\""},"1476":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ مَرَّتَيْنِ قَالَ حَدَّثَنَا أَبُو الزَّعْرَاءِ عَمْرُو بْنُ عَمْرٍو عَنْ عَمِّهِ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَعَّدَ فِيَّ النَّظَرَ وَصَوَّبَ وَقَالَ أَرَبُّ إِبِلٍ أَنْتَ أَوْ رَبُّ غَنَمٍ قَالَ مِنْ كُلٍّ قَدْ آتَانِي اللَّهُ فَأَكْثَرَ وَأَطْيَبَ قَالَ فَتُنْتِجُهَا وَافِيَةً أَعْيُنُهَا وَآذَانُهَا فَتَجْدَعُ هَذِهِ فَتَقُولُ صَرْمَاءَ ثُمَّ تَكَلَّمَ سُفْيَانُ بِكَلِمَةٍ لَمْ أَفْهَمْهَا وَتَقُولُ بَحِيرَةَ اللَّهِ فَسَاعِدُ اللَّهِ أَشَدُّ وَمُوسَاهُ أَحَدُّ وَلَوْ شَاءَ أَنْ يَأْتِيَكَ بِهَا صَرْمَاءَ أَتَاكَ قُلْتُ إِلَى مَا تَدْعُو قَالَ إِلَى اللَّهِ وَإِلَى الرَّحِمِ قُلْتُ يَأْتِينِي الرَّجُلُ مِنْ بَنِي عَمِّي فَأَحْلِفُ أَنْ لَا أُعْطِيَهُ ثُمَّ أُعْطِيهِ قَالَ فَكَفِّرْ عَنْ يَمِينِكَ وَأْتِ الَّذِي هُوَ خَيْرٌ أَرَأَيْتَ لَوْ كَانَ لَكَ عَبْدَانِ أَحَدُهُمَا يُطِيعُكَ وَلَا يَخُونُكَ وَلَا يَكْذِبُكَ وَالْآخَرُ يَخُونُكَ وَيَكْذِبُكَ قَالَ قُلْتُ لَا بَلْ الَّذِي لَا يَخُونُنِي وَلَا يَكْذِبُنِي وَيَصْدُقُنِي الْحَدِيثَ أَحَبُّ إِلَيَّ قَالَ كَذَاكُمْ أَنْتُمْ عِنْدَ رَبِّكُمْ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dua kali berkata; telah menceritakan kepada kami [Abu Za'ra`, 'Amr bin 'Amr] dari [pamannya, Abu Al Ahwash] dari [Bapaknya] berkata; saya mendatangi Nabi Shallallahu'alaihiwasallam lalu beliau mempertajam penglihatannya dan membenarkannya dan bersabda: \"Betulkah kamu si pemilik unta, atau si pemilik kambing?.\" Dia menjawab, \"Dari kedua hal itu, Allah telah memberiku dengan jumlah yang banyak dan bagus.\" Beliau bersabda: \"Bukankah kambing itu menghasilkan keturunan atau anak dengan mata dan telinga yang sempurna (lengkap) lantas engkau memotong telinganya dan kamu mengatakan telinga itu putus sendiri?, Lalu Sufyan mengucapkan suatu ucapan yang tidak bisa saya pahami dan berkata; \"Duhai malang telinga yang dipotong, padahal hasta Allah dan gunting Allah adalah lebih tajam. Seandainya Allah berkehendak, niscaya Dia akan mendatangkan kepada kalian dalam keadaan terpotong telinganya.\" Saya (Ayah Abul ahwash Radliyallahu'anhu) berkata; \"Kepada siapa anda menyeru?.\" Beliau menjawab, \"Kepada Allah dan menyambung silaturrahim, \" saya berkata; \"Telah datang seorang dari Bani pamanku lalu saya bersumpah untuk tidak memberikan kepadanya lalu saya memberikannya, \" Beliau bersabda: \"Bayarlah kafarat sumpahmu dan lakukan mana yang baik. Bagaimana pendapatmu, jika kamu memiliki dua budak yang satunya menaatimu, tidak berkhianat, tidak mendustakan, sedangkan yang lainnya berkhianat dan berdusta kepadamu?.\" (Ayah Abul ahwash radliyallahu'anhu) berkata; \"Tentu yang tidak berkhianat dan tidak berdusta denganku itu lebih saya sukai.\" Beliau bersabda: \"Demikiah juga kalian di sisi Rab Azzawajalla.\""},"1477":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيَّ شَمْلَةٌ أَوْ شَمْلَتَانِ فَقَالَ لِي هَلْ لَكَ مِنْ مَالٍ قُلْتُ نَعَمْ قَدْ آتَانِي اللَّهُ عَزَّ وَجَلَّ مِنْ كُلِّ مَالِهِ مِنْ خَيْلِهِ وَإِبِلِهِ وَغَنَمِهِ وَرَقِيقِهِ فَقَالَ فَإِذَا آتَاكَ اللَّهُ مَالًا فَلْيَرَ عَلَيْكَ نِعْمَتَهُ فَرُحْتُ إِلَيْهِ فِي حُلَّةٍحَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ فَذَكَرَهُ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فَغَدَوْتُ إِلَيْهِ فِي حُلَّةٍ حَمْرَاءَ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Syarik bin Abdullah] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Bapaknya] berkata; saya menemui Rasulullah Shallallahu'alaihiwasallam dan saya membawa satu pakaian atau dua pakaian, lalu beliau bersabda: \"Apakah kamu memiliki harta?, \" maka saya menjawab, \"Ya, Sesungguhnya Allah Azzawajalla telah memberikan semua harta-Nya, dari kuda-Nya, unta-Nya, kambing-Nya dan budak-Nya\" Telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Syarik] lalu dia menyebutkan dengan sanadnya secara maknanya. (Aswad bin Amir Radliyallahu'anhu) berkata; \"Lalu saya berangkat pada waktu pagi dengan berpakaian warna merah.\""},"1478":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ مَالِكٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ الرَّجُلُ أَمُرُّ بِهِ فَلَا يُضَيِّفُنِي وَلَا يَقْرِينِي فَيَمُرُّ بِي فَأَجْزِيهِ قَالَ لَا بَلْ اقْرِهِ قَالَ فَرَآنِي رَثَّ الْهَيْئَةِ فَقَالَ هَلْ لَكَ مِنْ مَالٍ فَقُلْتُ قَدْ أَعْطَانِي اللَّهُ عَزَّ وَجَلَّ مِنْ كُلِّ الْمَالِ مِنْ الْإِبِلِ وَالْغَنَمِ قَالَ فَلْيُرَ أَثَرُ نِعْمَةِ اللَّهِ عَلَيْكَ","id":"Telah menceritakan kepada kami [Abu Ahmad] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Bapaknya, Malik] berkata; saya berkata; \"Wahai Rasulullah, ada seorang laki-laki yang saya melewatinya namun mereka tidak menyambutku, dan mereka tidak menghormatiku, dan tidak menghormatiku namun saya menghormatinya.\" Beliau bersabda: \"Sambutlah dan hormatilah, \" (Malik bin Nadlah Radliyallahu'anhu) berkata; \"Lalu beliau melihatku dalam penampilanku yang jelek, beliau bertanya, 'Apakah kamu memiliki harta? ' lalu saya menjawab, 'Sungguh Allah Azzawajalla telah memberikan harta dari harta unta dan kambing.\" Beliau bersabda: \"Maka pertontonkanlah bekas nikmat Allah yang dikurniakan kepada kamu.\""},"1479":{"ar":"حَدَّثَنَا عُبَيْدَةُ قَالَ حَدَّثَنِي أَبُو الزَّعْرَاءِ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ مَالِكِ بْنِ نَضْلَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَيْدِي ثَلَاثَةٌ فَيَدُ اللَّهِ الْعُلْيَا وَيَدُ الْمُعْطِي الَّتِي تَلِيهَا وَيَدُ السَّائِلِ السُّفْلَى فَأَعْطِيَنَّ الْفَضْلَ وَلَا تَعْجَزْ عَنْ نَفْسِكَ","id":"Telah menceritakan kepada kami ['Ubaidah] berkata; telah menceritakan kepadaku [Abu Az-Za'ra`] dari [Abu Al Ahwash] dari [Bapaknya, Malik bin Nadllah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tanngan itu ada tiga: tangan Allah, yang paling tinggi, tangan orang yang memberi, yaitu setelahnya dan tangan orang yang meminta, yang paling rendah. Maka berikanlah kelebihan dan janganlah merasa lemah dari diri kamu.\""},"1480":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ عَنْ يَزِيدَ بْنِ شَيْبَانَ قَالَأَتَانَا ابْنُ مِرْبَعٍ الْأَنْصَارِيُّ وَنَحْنُ فِي مَكَانٍ مِنْ الْمَوْقِفِ بَعِيدٍ فَقَالَ إِنِّي رَسُولُ رَسُولِ اللَّهِ إِلَيْكُمْ يَقُولُ كُونُوا عَلَى مَشَاعِرِكُمْ هَذِهِ فَإِنَّكُمْ عَلَى إِرْثٍ مِنْ إِرْثِ إِبْرَاهِيمَ لِمَكَانٍ تَبَاعَدَهُ عَمْرٌو","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amr] yaitu Ibnu Dinar, dari ['Amr bin Abdullah bin Shafwan] dari [Yazid bin Syaiban] berkata; [Ibnu Mirba' Al Anshari] datang kepada kami dan saat itu kami sedang berada pada tempat yang jauh, lalu berkata; \"Saya adalah utusan Rasulullah Shallallahu'alaihiwasallam kepada kalian (beliau bersabda) \"Tetaplah kalian pada tata cara ibadah kalian ini, sesungguhnya kalian berada pada salah satu warisan dari warisan Ibrahim pada suatu tempat yang dijauhi oleh 'Amru."},"1481":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَهُ أَنَّ عَمْرَو بْنَ عَوْفٍ وَهُوَ حَلِيفُ بَنِي عَامِرِ بْنِ لُؤَيٍّ وَكَانَ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ إِلَى الْبَحْرَيْنِ يَأْتِي بِجِزْيَتِهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ صَالَحَ أَهْلَ الْبَحْرَيْنِ وَأَمَّرَ عَلَيْهِمْ الْعَلَاءَ بْنَ الْحَضْرَمِيِّ فَقَدِمَ أَبُو عُبَيْدَةَ بِمَالٍ مِنْ الْبَحْرَيْنِ فَسَمِعَتْ الْأَنْصَارُ بِقُدُومِهِ فَوَافَتْ صَلَاةَ الْفَجْرِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْفَجْرِ انْصَرَفَ فَتَعَرَّضُوا لَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَآهُمْ فَقَالَ أَظُنُّكُمْ قَدْ سَمِعْتُمْ أَنَّ أَبَا عُبَيْدَةَ قَدْ جَاءَ وَجَاءَ بِشَيْءٍ قَالُوا أَجَلْ يَا رَسُولَ اللَّهِ قَالَ فَأَبْشِرُوا وَأَمِّلُوا مَا يَسُرُّكُمْ فَوَاللَّهِ مَا الْفَقْرَ أَخْشَى عَلَيْكُمْ وَلَكِنِّي أَخْشَى أَنْ تُبْسَطَ الدُّنْيَا عَلَيْكُمْ كَمَا بُسِطَتْ عَلَى مَنْ كَانَ قَبْلَكُمْ فَتَنَافَسُوهَا كَمَا تَنَافَسُوهَا وَتُلْهِيكُمْ كَمَا أَلْهَتْهُمْحَدَّثَنَا سَعْدٌ حَدَّثَنِي أَبِي عَنْ صَالِحٍ عَنِ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَهُ أَنَّ عَمْرَو بْنَ عَوْفٍ وَهُوَ حَلِيفُ بَنِي عَامِرِ بْنِ لُؤَيٍّ وَكَانَ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا عُبَيْدَةَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepada kami [Bapakku] dari [Shalih] [Ibnu Syihab] berkata; telah mengabarkan kepadaku [Urwah bin Az-Zubair] sesungguhnya [Al Miswar bin Makhramah] mengabarinya, sesungguhnya ['Amr bin Auf] yaitu wakil Bani 'Amir bin Luhay, dia ikut dalam Perang Badar bersama Rasulullah Shallallahu'alaihiwasallam mengabarinya, Rasulullah Shallallahu'alaihiwasallam mengutus Abu 'Ubaidah bin Al Jarah ke Bahrain untuk membawa jizyahnya. Rasulullah Shallallahu'alaihiwasallam mengadakan perjanjian damai dengan penduduk Bahrain dan yang menjadi pemimpin mereka ada Al 'Ala` bin Al Hadlrami. Lantas Abu 'Ubaidah datang dengan membawa harta dari Bahrain. Orang-orang Anshar mendengar kedatangannya, waktu itu bertepatan dengan waktu shalat fajar Rasulullah Shallallahu'alaihiwasallam. Tatkala Rasulullah Shallallahu'alaihiwasallam selesai dari shalat subuh, mereka bubar dan menemuinya, lalu Rasulullah Shallallahu'alaihiwasallam tersenyum. Lalu beliau bersabda: \"Saya yakin kalian telah mendengar Abu 'Ubaidah datang dengan membawa sesuatu.\" Mereka berkata; \"Ya Wahai Rasulullah, \" Beliau bersabda: \"Bergembiralah, dan bersenang-senanglah dengan apa yang menyenangkan kalian. Demi Allah, tidaklah kemiskinan yang saya takutkan pada kalian, tapi saya takut jika dibentangkan pada kalian dunia sebagaimana telah dibentangkan pada orang sebelum kalian. Mereka kalian saling berlomba-lomba sebagaimana mereka berlomba-lomba. Kalian lalai, sebagaimana mereka lalai.\" Telah menceritakan kepada kami [Sa'ad] telah menceritakan kepadaku [bapakku] dari [Shalih] dari [Ibnu Syihab] berkata; telah mengabarkan kepadaku ['Urwah bin Az-Zubair] Sesungguhnya [Al Miswar bin Makhramah] mengabarinya, sesungguhnya ['Amr bin Auf] yaitu wakil Bani 'Amir bin Lu`y, dia ikut Perang Badar bersama Rasulullah Shallallahu'alaihiwasallam mengabarinya sesungguhnya Rasulullah Shallallahu'alaihiwasallam mengutus Abu 'Ubaidah, lalu menyebutkan hadits saya dengan yang di atas."},"1482":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ أَخْبَرَنِي أَبُو الْمِنْهَالِ سَمِعَ إِيَاسَ بْنَ عَبْدٍ الْمُزَنِيَّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَلَا تَبِيعُوا الْمَاءَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْمَاءِ لَا يَدْرِي عَمْرٌو أَيَّ مَاءٍ هُوَ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amr] berkata; telah mengabarkan kepadaku [Abu Al Minhal] telah mendengar [Iyas bin Abd Al Muzani] salah seorang sahabat Nabi Shallallahu'alaihiwasallam berkata; \"Janganlah kalian menjual air, karena saya mendengar Rasulullah Shallallahu'alaihiwasallam melarang menjual air.\" 'Amru tidak tahu maksudnya air apakah itu."},"1483":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ مُزَيْنَةَ أَنَّهُقَالَتْ لَهُ أُمُّهُ أَلَا تَنْطَلِقُ فَتَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا يَسْأَلُهُ النَّاسُ فَانْطَلَقْتُ أَسْأَلُهُ فَوَجَدْتُهُ قَائِمًا يَخْطُبُ وَهُوَ يَقُولُ مَنْ اسْتَعَفَّ أَعَفَّهُ اللَّهُ وَمَنْ اسْتَغْنَى أَغْنَاهُ اللَّهُ وَمَنْ سَأَلَ النَّاسَ وَلَهُ عِدْلُ خَمْسِ أَوَاقٍ فَقَدْ سَأَلَ إِلْحَافًا فَقُلْتُ بَيْنِي وَبَيْنَ نَفْسِي لَنَاقَةٌ لَهُ هِيَ خَيْرٌ مِنْ خَمْسِ أَوَاقٍ وَلِغُلَامِهِ نَاقَةٌ أُخْرَى هِيَ خَيْرٌ مِنْ خَمْسِ أَوَاقٍ فَرَجَعْتُ وَلَمْ أَسْأَلْهُ","id":"Telah menceritakan kepada kami [Abu Bakar Al Hanafi] berkata; telah menceritakan kepada kami [Abdul Hamid] dari [Bapaknya] dari [seorang laki-laki dari Muzainah] sesungguhnya ibunya berkata kepadanya \"Maukah kamu pergi menuju Rasulullah Shallallahu'alaihiwasallam dan meminta kepada beliau sebagaimana orang-orang meminta beliau?, \" Saya pun pergi meminta sesuatu kepada beliau. Saya dapatkan beliau sedang berdiri berkhutbah dengan bersabda: \"Barangsiapa yang menahan dari berbuat yang haram dan meminta kepada manusia, niscaya Allah akan menjaganya. Barangsiapa yang merasa cukup, niscaya Allah akan mencukupkannya. Barangsiapa yang meminta pada manusia dan dia memiliki harta setara dengan lima uqiyah (empat puluh dirham perak) maka dia telah meminta dengan mendesak, \" lalu saya berkata; \"Saya mempunyai satu unta yang lebih baik daripada lima uqiyah, dan pelayanku juga mempunyai unta yang lain yang lebih baik daripada lima uqiyah, lalu saya pulang dan tidak meminta sesuatupun.\""},"1484":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ قَالَ سَمِعْتُ ابْنَ شِهَابٍ يُحَدِّثُ أَنَّ أَبَا أُمَامَةَ بْنَ سَهْلِ بْنِ حُنَيْفٍ أَخْبَرَهُ عَنْ أَبِي أُمَامَةَ أَسْعَدَ بْنِ زُرَارَةَ وَكَانَ أَحَدَ النُّقَبَاءِ يَوْمَ الْعَقَبَةِأَنَّهُ أَخَذَتْهُ الشَّوْكَةُ فَجَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَقَالَ بِئْسَ الْمَيِّتُ لَيَهُودُ مَرَّتَيْنِ سَيَقُولُونَ لَوْلَا دَفَعَ عَنْ صَاحِبِهِ وَلَا أَمْلِكُ لَهُ ضَرًّا وَلَا نَفْعًا وَلَأَتَمَحَّلَنَّ لَهُ فَأَمَرَ بِهِ وَكُوِيَ بِخَطَّيْنِ فَوْقَ رَأْسِهِ فَمَاتَ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Zam'ah bin Shalih] berkata; saya telah mendengar [Ibnu Syihab] menceritakan sesungguhnya [Abu Umamah bin Sahl bin Hunaif] mengabarinya, dari [Abu Umamah, As'ad bin Zurarah] dia adalah salah seorang pemimpin suku pada peristiwa Aqabah. Dia terluka oleh suatu senjata, Rasulullah Shallallahu'alaihiwasallam pun datang menjenguknya. Beliau bersabda: \"Sejelek-jelek mayat adalah orang Yahudi, \" beliau mengucapkan ucapannya dua kali, dan sungguh mereka akan memberi komentar, 'Duhai mengapa dia tidak membela sahabatnya, padahal saya tidak bisa mendatangkan bahaya dan manfaat padanya', Sungguh saya akan berusaha untuk menyembuhkannya\". Lalu beliau menyuruh untuk diobati dengan kay (metode pengobatan dengan sundutan besi panas) pada dua bagian atas kepalanya, hanya dia lantas meninggal."},"1485":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ حَدَّثَنَا الْمَسْعُودِيُّ قَالَ حَدَّثَنِي أَبُو عَمْرَةَ عَنْ أَبِيهِ قَالَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ أَرْبَعَةُ نَفَرٍ وَمَعَنَا فَرَسٌ فَأَعْطَى كُلَّ إِنْسَانٍ مِنَّا سَهْمًا وَأَعْطَى الْفَرَسَ سَهْمَيْنِ","id":"Telah menceritakan kepada kami [Abu Abdurrahman bin Al Muqri`] telah menceritakan kepada kami [Al Mas'udi] berkata; telah menceritakan kepadaku [Abu 'Amrah] dari [Bapaknya] berkata; \"Kami mendatangi Rasulullah Shallallahu'alaihiwasallam, jumlah kami saat itu empat orang pejalan kaki dan seorang prajurit penunggang kuda, maka beliau memberi masing-masing dari kami satu bagian untuk pejlan kaki dan untuk prajurit penunggang kuda dengan dua bagian.\""},"1486":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي جَعْفَرٍ قَالَ سَمِعْتُ عُمَارَةَ بْنَ خُزَيْمَةَ يُحَدِّثُ عَنْ عُثْمَانَ بْنِ حُنَيْفٍأَنَّ رَجُلًا ضَرِيرَ الْبَصَرِ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ادْعُ اللَّهَ أَنْ يُعَافِيَنِي قَالَ إِنْ شِئْتَ دَعَوْتُ لَكَ وَإِنْ شِئْتَ أَخَّرْتُ ذَاكَ فَهُوَ خَيْرٌ فَقَالَ ادْعُهُ فَأَمَرَهُ أَنْ يَتَوَضَّأَ فَيُحْسِنَ وُضُوءَهُ فَيُصَلِّيَ رَكْعَتَيْنِ وَيَدْعُوَ بِهَذَا الدُّعَاءِ اللَّهُمَّ إِنِّي أَسْأَلُكَ وَأَتَوَجَّهُ إِلَيْكَ بِنَبِيِّكَ مُحَمَّدٍ نَبِيِّ الرَّحْمَةِ يَا مُحَمَّدُ إِنِّي تَوَجَّهْتُ بِكَ إِلَى رَبِّي فِي حَاجَتِي هَذِهِ فَتَقْضِي لِي اللَّهُمَّ شَفِّعْهُ فِيَّ","id":"Telah menceritakan kepada kami ['Utsman bin 'Umar] telah mengabarkan kepada kami [Syu'bah] dari [Abu Ja'far] berkata; saya telah mendengar ['Umarah bin Huzaimah] menceritakan dari ['Utsman bin Hunaif], ada seorang buta mendatangi Nabi Shallallahu'alaihiwasallam lalu berkata; \"Berdo'alah kepada Allah agar menyembuhkanku.\" Beliau bersabda: \"Jika kamu mau, saya akan mendo'akan untukmu dan jika kamu mau saya akan menangguhkan doaku dan itu lebih baik bagimu.\" Lalu orang itu berkata; \"Berdo'alah, \" lalu beliau menyuruh agar orang itu berwudlu dengan baik lalu shalat dua rekaat. Lalu berdo'a dengan do'a: \"Ya Allah, sesungguhnya saya meminta kepada-Mu, saya menghadapkan kepada-Mu dengan nabi-Mu, Muhammad, nabi Yang Maha Penyayang, Wahai Muhammad, sesungguhnya saya bertawajjuh dengan perantaraanmu kepada Rabku pada kebutuhanku ini, maka putuskanlah kepadaku. Ya Allah, sembuhkanlah bagiku.\""},"1487":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي جَعْفَرٍ الْمَدِينِيِّ قَالَ سَمِعْتُ عُمَارَةَ بْنَ خُزَيْمَةَ بْنِ ثَابِتٍ يُحَدِّثُ عَنْ عُثْمَانَ بْنِ حُنَيْفٍأَنَّ رَجُلًا ضَرِيرًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ ادْعُ اللَّهَ أَنْ يُعَافِيَنِي فَقَالَ إِنْ شِئْتَ أَخَّرْتُ ذَلِكَ فَهُوَ أَفْضَلُ لِآخِرَتِكَ وَإِنْ شِئْتَ دَعَوْتُ لَكَ قَالَ لَا بَلْ ادْعُ اللَّهَ لِي فَأَمَرَهُ أَنْ يَتَوَضَّأَ وَأَنْ يُصَلِّيَ رَكْعَتَيْنِ وَأَنْ يَدْعُوَ بِهَذَا الدُّعَاءِ اللَّهُمَّ إِنِّي أَسْأَلُكَ وَأَتَوَجَّهُ إِلَيْكَ بِنَبِيِّكَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيِّ الرَّحْمَةِ يَا مُحَمَّدُ إِنِّي أَتَوَجَّهُ بِكَ إِلَى رَبِّي فِي حَاجَتِي هَذِهِ فَتَقْضِي وَتُشَفِّعُنِي فِيهِ وَتُشَفِّعُهُ فِيَّ قَالَ فَكَانَ يَقُولُ هَذَا مِرَارًا ثُمَّ قَالَ بَعْدُ أَحْسِبُ أَنَّ فِيهَا أَنْ تُشَفِّعَنِي فِيهِ قَالَ فَفَعَلَ الرَّجُلُ فَبَرَأَحَدَّثَنَا مُؤَمَّلٌ قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ الْخَطْمِيُّ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ بْنِ ثَابِتٍ عَنْ عُثْمَانَ بْنِ حُنَيْفٍ أَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ ذَهَبَ بَصَرُهُ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Rouh] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ja'far Al Madini] berkata; saya mendengar ['Umarah bin Huzaimah bin Tsabit] menceritakan dari ['Utsman bin Hunaif], Ada seorang buta mendatangi Nabi Shallallahu'alaihiwasallam lalu berkata; \"Wahai Nabiyullah, berdo'alah kepada Allah agar menyembuhkanku.\" Beliau bersabda: \"Jika kamu berkenan, saya akan menangguhkan doaku dan itu lebih utama bagi akhiratmu. Dan jika kamu berkenan, saya akan mendoakan untukmu\" Lalu orang itu berkata; \"Tidak, tapi do'alah untukku, \" lalu beliau menyuruh agar orang itu berwudlu lalu shalat dua rekaat. Lalu berdo'a dengan do'a: \"Ya Allah, sesungguhnya saya meminta kepada-Mu, saya bertawajjuh kepada-Mu dengan perantaraan nabi-Mu, Muhammad Shallallahu'alaihiwasallam, nabi Yang Maha Penyayang, Wahai Muhammad, sesungguhnya saya telah mengarahkan denganmu kepada Rabku pada kebutuhanku ini, dan kamu meminatkan kesembuhan untukku.\" ('Utsman bin Hunaif Radliyallahu'anhu) berkata; \"Lalu orang itu membaca itu terus, \" Di kemudian hari orang itu mengatakan, \"Seingatku ketika itu ada kalimat 'dengan harapan engkau bisa menolongku melalui doamu', \" ('Utsman bin Hunaif Radliyallahu'anhu) berkata; \"Lalu laki-laki itu melakukannya dan sembuh.\" Telah menceritakan kepada kami [Mu`ammal] berkata; telah menceritakan kepada kami [Hammad] yaitu Ibnu Salamah berkata; telah menceritakan kepada kami [Abu Ja'far Al khathmi] dari ['Umarah bin Huzaimah bin Tsabit] dari ['Utsman bin Hunaif], ada seorang laki-laki mendatangi Nabi Shallallahu'alaihiwasallam, dia seorang buta. Lalu menyebutkan hadits secara lengkap."},"1488":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا الْحَارِثُ بْنُ يَزِيدَ عَنِ الْبَرَاءِ بْنِ عُثْمَانَ الْأَنْصَارِيِّ عَنْ هَانِئِ بْنِ مُعَاوِيَةَ الصَّدَفِيِّ حَدَّثَهُ قَالَحَجَجْتُ زَمَانَ عُثْمَانَ بْنِ عَفَّانَ فَجَلَسْتُ فِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا رَجُلٌ يُحَدِّثُهُمْ قَالَ كُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَأَقْبَلَ رَجُلٌ فَصَلَّى فِي هَذَا الْعَمُودِ فَعَجَّلَ قَبْلَ أَنْ يُتِمَّ صَلَاتَهُ ثُمَّ خَرَجَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا لَوْ مَاتَ لَمَاتَ وَلَيْسَ مِنْ الدِّينِ عَلَى شَيْءٍ إِنَّ الرَّجُلَ لَيُخَفِّفُ صَلَاتَهُ وَيُتِمُّهَا قَالَ فَسَأَلْتُ عَنْ الرَّجُلِ مَنْ هُوَ فَقِيلَ عُثْمَانُ بْنُ حُنَيْفٍ الْأَنْصَارِيُّ","id":"Telah menceritakan kepada kami [Hasan bin Musa] Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Al Harits bin Yazid] dari [Bara` bin Utsman Al Anshari] dari [Hani` bin Mu'awiyah Ash Shadafi] bahwa ia menceritakan kepadanya, dia berkata, \"Saya pernah menunaikan haji pada zaman Utsman bin Affan, lalu saya duduk di Masjid Nabi shallallahu 'alaihi wasallam, lalu ada seorang laki-laki sedang menceritakan (hadits) kepada mereka. Ia berkata, \"Pada suatu hari kami berada di sisi Rasulullah shallallahu 'alaihi wasallam, lalu datanglah seorang laki-laki dan shalat di tiang ini dengan tergesa-gesa sebelum menyempurnakan shalatnya, lalu ia pun keluar. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, sekiranya orang ini meninggal, maka ia tidak akan mempunyai bagian dari agama ini sedikitpun. Sesungguhnya seorang laki-laki hendaklah meringankan shalatnya dan juga menyempurnakan (pelaksanaannya).\" Hani` bin Mu'awiyah berkata, \"Lalu saya bertanya prihal laki-laki itu, tentang siapakah ia sebenarnya. Maka dikatakanlah bahwa dia adalah [Utsman bin Hunaif Al Anshari].\""},"1489":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيُّ وَعَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Ya'qub] dia berkata, Telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] dia berkata; telah menceritakan kepadaku [Ja'far bin Umayyah Adl Dlamrui] dan dari [Abu Salamah bin Abdurrahman] dari [Ja'far bin Amru bin Umayyah] dari [bapaknya] dia berkata, \"Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam mengusap kedua khufnya.\""},"1490":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ وَالْخِمَارِ","id":"Telah menceritakan kepada kami [Muhammad bin Mus'ab] dia berkata, Telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Ja'far bin Amruu bin Umayyah Adl Dlamrui] dari [Bapaknya] dia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam mengusap kedua khuf dan Khimar (sejenis imamah penutup kepala).\""},"1491":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى وَحُسَيْنُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ جَعْفَرَ بْنَ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيَّ أَخْبَرَهُ أَنَّ أَبَاهُ أَخْبَرَهُ ��َنَّهُرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Hasan bin Musa] dan [Husain bin Muhammad] keduanya berkata, Telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] bahwa [Ja'far bin Amru bin Umayyah Adl Dlamri] dia mengabarkan kepadanya, bahwa [Bapaknya] mengabarkan kepadanya, Bahwasanya ia pernah melihat Rasulullah shallallahu 'alaihi wasallam mengusap kedua khuf.\""},"1492":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَلِيٌّ يَعْنِي ابْنَ مُبَارَكٍ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ أَخْبَرَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ أَنَّهُرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Abu Amir] telah menceritakan kepada kami [Ali] -yakni Ibnul Mubarak- dari [Yahya] dari [Ibnu Salamah] dia berkata, telah mengabarkan kepadaku [Ja'far bin Amruu bin Umayyah] dari [Bapaknya] bahwasanya ia pernah melihat Rasulullah shallallahu 'alaihi wasallam mengusap kedua khuf.\""},"1493":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا فُلَيْحٌ عَنِ الزُّهْرِيِّ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ أَنَّهُرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ عُضْوًا ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abu Amir] Telah menceritakan kepada kami [Fulaih] dari [Zuhri] dia berkata, telah menceritakan kepadaku [Ja'far bin Amru bin Umayyah] dari [bapaknya], bahwa dia pernah melihat Nabi shallallahu 'alaihi wasallam makan 'Udwan kemudian shalat dengan tidak berwudlu.\" "},"1494":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ أَنَّ أَبَاهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَزُّ مِنْ كَتِفِ شَاةٍ فَدُعِيَ إِلَى الصَّلَاةِ فَطَرَحَ السِّكِّينَ وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Shalih] dari [Ibnu Syihab] telah menceritakan kepadaku [Ja'far bin Amru bin Umayyah] bahwa [Bapaknya] berkata, \"Saya melihat Rasulullah sedang memotong pundak kambing lalu beliau diajak untuk menunaikan shalat, maka beliau pun menanggalkan pisaunya (untuk memenuhi panggilan shalat) dengan tanpa berwudlu.\""},"1495":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ شِهَابٍ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ يَحْتَزُّ مِنْ كَتِفِ شَاةٍ ثُمَّ دُعِيَ إِلَى الصَّلَاةِ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Ya'qub] ia berkata, telah menceritakan kepada kami [bapakku], dari [Ibnu Syihab] dari [Ja'far bin Amru bin Umayyah] dari [Bapaknya] dia berkata, \"Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam makan dan memotong pundak kambing, kemudian beliau diseru untuk menunaikan shalat, maka beliau pun shalat sedang beliau tidak berwudlu.\""},"1496":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِيُّ حَدَّثَنَا حَيْوَةُ أَخْبَرَنِي عَيَّاشُ بْنُ عَبَّاسٍ أَنَّ كُلَيْبَ بْنَ صُبَيْحٍ حَدَّثَهُ أَنَّ الزِّبْرِقَانَ حَدَّثَهُ عَنْ عَمِّهِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فَنَامَ عَنْ صَلَاةِ الصُّبْحِ حَتَّى طَلَعَتْ الشَّمْسُ لَمْ يَسْتَيْقِظُوا وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَأَ بِالرَّكْعَتَيْنِ فَرَكَعَهُمَا ثُمَّ أَقَامَ الصَّلَاةَ فَصَلَّى","id":"Telah menceritakan kepada kami [Abu Abdirrahman Al Muqri] telah menceritakan kepada kami [Haiwah] telah mengabarkan kepadaku [Ayyas bin Abbas] bahwa [Kulaib bin Shubaih] menceritakan kepadanya, bahwa [Az Zibriqan] menceritakan kepadanya, dari pamannya [Amru bin Umayyah Adl Dlamri] dia berkata, \"Kami pernah ikut bersama Rasulullah shallallahu 'alaihi wasallam dalam sebagian safarnya. Kemudian beliau ketiduran sehingga tidak melaksanakan shalat subuh, dan mereka belum bangun meskipun matahari telah terbit. Maka Rasulullah memulai shalat dua rakaat, kemudian iqamah dikumandangkan dan beliau pun shalat.\""},"1497":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ أَبِي شَيْبَةَ بِالْكُوفَةِ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ إِبْرَاهِيمَ بْنِ إِسْمَاعِيلَ قَالَ أَخْبَرَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ وَحْدَهُ عَيْنًا إِلَى قُرَيْشٍ قَالَ جِئْتُ إِلَى خَشَبَةِ خُبَيْبٍ وَأَنَا أَتَخَوَّفُ الْعُيُونَ فَرَقِيتُ فِيهَا فَحَلَلْتُ خُبَيْبًا فَوَقَعَ إِلَى الْأَرْضِ فَانْتَبَذْتُ غَيْرَ بَعِيدٍ ثُمَّ الْتَفَتُّ فَلَمْ أَرَ خُبَيْبًا وَلَكَأَنَّمَا ابْتَلَعَتْهُ الْأَرْضُ فَلَمْ يُرَ لِخُبَيْبٍ أَثَرٌ حَتَّى السَّاعَةِقَالَ أَبُو عَبْد الرَّحْمَنِ وَقَالَ ابْنُ أَبِي شَيْبَةَ لَنَا فِيهِ عَنْ الزُّهْرِيِّ وَأَمَّا أَبِي فَحَدَّثَنَا عَنْهُ لَمْ يَذْكُرْ الزُّهْرِيَّ وَحَدَّثَنَاهُ ابْنُ أَبِي شَيْبَةَ بِالْكُوفَةِ فَجَعَلَهُ لَنَا عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Abu Syaibah], dan ia katakan 'Saya mendengarnya dari [Abdullah bin Abu Syaibah] di Kufah', dia berkata, telah menceritakan kepada kami [Ja'far bin Aun] dari [Ibrahim bin Isma'il] dia berkata, telah mengabarkan kepadaku [Ja'far bin Amru bin Umayyah] dari [Bapaknya] bahwasanya Rasulullah shallallahu 'alaihi wasallam mengutusnya seorang diri sebagai mata-mata kepada orang-orang Quraisy. Ia berkata, \"Saya mendatangi batang kayu (tempat Khubaib digantung) dengan penuh khawatir jika diketahui mata-mata Quraisy. Kemudian aku menaiki batang kayu itu dan melepaskan Khubaib hingga tubuh Khubaib jatuh ke tanah. Kemudian aku menyingkir tidak jauh dari tempat itu, saat menoleh aku tidak mendapati Khubaib berada di tempatnya lagi, seakan-akan ia ditelan oleh bumi dan bekasnya pun tidak terlihat lagi.\" Abdurrahman berkata; Ibnu Abu Syaibah menyebutkan kepada kami yang di dalamnya disebutkan dari Az Zuhri. Dan adapun bapakku, ia menceritakan kepada kami tanpa menyebutkan nama Az Zuhri. Dan [Ibnu Abu Syaibah] menceritakannya kepada kami di Kufah, dan ia menyandarkannya dari [Az Zuhri]."},"1498":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا أَبُو كَثِيرٍ مَوْلَى اللَّيْثِيِّينَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ جَحْشٍأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَاذَا لِي إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ قَالَ الْجَنَّةُ فَلَمَّا وَلَّى قَالَ إِلَّا الدَّيْنُ سَارَّنِي بِهِ جِبْرِيلُ عَلَيْهِ السَّلَام آنِفًا","id":"Telah menceritakan kepada kami [Muhammad bin Bisyr] dia berkata, telah menceritakan kepada kami [Muhammad bin Amru] dia berkata, telah menceritakan kepada kami [Abu Katsir] mantan budak Al Laitsiyyin, dari [Muhammad bin Abdullah bin Jahsy], bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, apakah ganjaran untukku jika aku dibunuh di jalan Allah?\" Beliau menjawab, \"Surga.\" Kemudian ketika beliau berpaling, beliau bersabda: \"Kecuali utang, tadi Jibril 'Alaihis Salam telah memberitahukannya kepadaku.\""},"1499":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي كَثِيرٍ مَوْلَى الْهِلَالِيِّينَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ جَحْشٍ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَاذَا لِي إِنْ قَاتَلْتُ فِي سَبِيلِ اللَّهِ حَتَّى أُقْتَلَ قَالَ الْجَنَّةُ قَالَ فَلَمَّا وَلَّى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الدَّيْنُ سَارَّنِي بِهِ جِبْرِيلُ عَلَيْهِ السَّلَام آنِفًا","id":"Telah menceritakan kepada kami [Khalaf bin Walid] telah menceritakan kepada kami [Abbad bin Abbad] telah menceritakan kepada kami [Muhammad bin Amru] dari [Abu Katsir] mantan budak Al Hilaliyyin, dari [Muhammad bin Jahsy] dari [Bapaknya] ia berkata, \"Seorang laki-laki datang menghadap Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, ganjaran apa yang akan saya dapatkan jika saya berperang di jalan Allah sampai saya terbunuh?\" beliau menjawab: \"Surga.\" Perawi berkata, \"Setelah berpaling, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kecuali utang, tadi Jibril 'Alaihis Salam telah memberitahukannya kepadaku.\""},"1500":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ يَعْنِي ابْنَ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعْظَمُ الْغُلُولِ عِنْدَ اللَّهِ عَزَّ وَجَلَّ ذِرَاعٌ مِنْ الْأَرْضِ تَجِدُونَ الرَّجُلَيْنِ جَارَيْنِ فِي الْأَرْضِ أَوْ فِي الدَّارِ فَيَقْتَطِعُ أَحَدُهُمَا مِنْ حَظِّ صَاحِبِهِ ذِرَاعًا فَإِذَا اقْتَطَعَهُ طُوِّقَهُ مِنْ سَبْعِ أَرَضِينَ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abdul Malik bin Amru] dia berkata, telah menceritakan kepada kami [Zuhair] -yakni Ibnu Muhammad- dari [Abdullah] -yakni Ibnu Muhammad bin Aqil- dari [Atha bin Yasar] dari [Abu Malik Al Asyja'i] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya pengkhianatan yang paling besar di sisi Allah (adalah berkenaan dengan) satu hasta dari tanah. Dimana kalian mendapati dua orang laki-laki yang saling bertangga (berdampingan) tanah atau tempat tinggal, lalu salah seorang di antara keduanya mengambil satu hasta dari bagian temannya, dan jika ia benar-benar mengambilnya, maka akan dihipitkan kepadanya tujuh lapis bumi hingga hari kiamat.\""}};
